/**
 * Tests for gates/engine.ts
 */

import { describe, expect, it } from "vitest";
import {
  computeOverallStatus,
  countChanges,
  formatGateResults,
  getAddedLines,
  getBuiltinRules,
  getChangedFiles,
  getRuleByName,
  runGates,
} from "../../../src/mcp-tools/bazdmeg/core-logic/engine.js";
import { buildDiff } from "../__test-utils__/fixtures.js";
import type { GateResult, RuleContext } from "../../../src/mcp-tools/bazdmeg/core-logic/types.js";

function makeContext(overrides: Partial<RuleContext> = {}): RuleContext {
  return {
    diff: "",
    files: [],
    additions: 0,
    deletions: 0,
    prTitle: "Test PR",
    prBody: "This is a test PR with enough description to pass the quality gate check.",
    claudeMdRules: [],
    ...overrides,
  };
}

describe("getAddedLines", () => {
  it("extracts lines starting with +", () => {
    const diff = "+added line\n-removed line\n+another added\n+++header";
    expect(getAddedLines(diff)).toEqual(["+added line", "+another added"]);
  });

  it("returns empty for no additions", () => {
    expect(getAddedLines("-only removals\n---header")).toEqual([]);
  });
});

describe("getChangedFiles", () => {
  it("extracts file paths from diff headers", () => {
    const diff = buildDiff([
      { path: "src/index.ts", added: ["const x = 1;"] },
      { path: "src/util.ts", added: ["export function foo() {}"] },
    ]);
    const files = getChangedFiles(diff);
    expect(files).toContain("src/index.ts");
    expect(files).toContain("src/util.ts");
  });
});

describe("countChanges", () => {
  it("counts additions and deletions", () => {
    const diff = "+new line 1\n+new line 2\n-old line 1\n+++header\n---header";
    expect(countChanges(diff)).toEqual({ additions: 2, deletions: 1 });
  });
});

describe("getBuiltinRules", () => {
  it("returns 6 rules", () => {
    expect(getBuiltinRules()).toHaveLength(6);
  });

  it("includes workspace scope compliance gate", () => {
    const names = getBuiltinRules().map((r) => r.name);
    expect(names).toContain("Workspace Scope Compliance");
  });
});

describe("getRuleByName", () => {
  it("finds a rule by name", () => {
    const rule = getRuleByName("Change Size");
    expect(rule).toBeDefined();
    expect(rule?.name).toBe("Change Size");
  });

  it("returns undefined for unknown rule", () => {
    expect(getRuleByName("NonExistent")).toBeUndefined();
  });
});

describe("Unit Tests Present gate", () => {
  const rule = getRuleByName("Unit Tests Present")!;

  it("GREEN when test files included", () => {
    const result = rule.check(makeContext({ files: ["src/index.ts", "src/index.test.ts"] }));
    expect(result.status).toBe("GREEN");
  });

  it("GREEN when no code files changed", () => {
    const result = rule.check(makeContext({ files: ["README.md", "package.json"] }));
    expect(result.status).toBe("GREEN");
  });

  it("RED when code changed without tests", () => {
    const result = rule.check(makeContext({ files: ["src/index.ts"] }));
    expect(result.status).toBe("RED");
  });
});

describe("TypeScript Strict Compliance gate", () => {
  const rule = getRuleByName("TypeScript Strict Compliance")!;

  it("GREEN for clean code", () => {
    const diff = "+const x: string = 'hello';";
    const result = rule.check(makeContext({ diff }));
    expect(result.status).toBe("GREEN");
  });

  it("RED for `any` type", () => {
    const diff = "+function foo(x: any) {}";
    const result = rule.check(makeContext({ diff }));
    expect(result.status).toBe("RED");
  });

  it("RED for eslint-disable", () => {
    const diff = "+// eslint-disable-next-line no-console";
    const result = rule.check(makeContext({ diff }));
    expect(result.status).toBe("RED");
  });

  it("RED for ts-ignore", () => {
    const diff = "+// @ts-ignore";
    const result = rule.check(makeContext({ diff }));
    expect(result.status).toBe("RED");
  });
});

describe("PR Description Quality gate", () => {
  const rule = getRuleByName("PR Description Quality")!;

  it("GREEN for substantive description", () => {
    const result = rule.check(
      makeContext({
        prBody:
          "This PR implements the new authentication flow using OAuth2. It replaces the legacy session-based auth with JWT tokens.",
      }),
    );
    expect(result.status).toBe("GREEN");
  });

  it("YELLOW for brief description", () => {
    const result = rule.check(makeContext({ prBody: "Fix the auth bug that was found" }));
    expect(result.status).toBe("YELLOW");
  });

  it("RED for missing description", () => {
    const result = rule.check(makeContext({ prBody: null }));
    expect(result.status).toBe("RED");
  });

  it("RED for very short description", () => {
    const result = rule.check(makeContext({ prBody: "fix" }));
    expect(result.status).toBe("RED");
  });
});

describe("Security Patterns gate", () => {
  const rule = getRuleByName("Security Patterns")!;

  it("GREEN for clean code", () => {
    const diff = "+const config = loadConfig();";
    const result = rule.check(makeContext({ diff }));
    expect(result.status).toBe("GREEN");
  });

  it("RED for hardcoded API key", () => {
    const diff = "+const api_key = 'sk-1234567890abcdef';";
    const result = rule.check(makeContext({ diff }));
    expect(result.status).toBe("RED");
  });

  it("RED for innerHTML", () => {
    const diff = "+element.innerHTML = userInput;";
    const result = rule.check(makeContext({ diff }));
    expect(result.status).toBe("RED");
  });
});

describe("Change Size gate", () => {
  const rule = getRuleByName("Change Size")!;

  it("GREEN for small changes", () => {
    const result = rule.check(makeContext({ additions: 50, deletions: 20 }));
    expect(result.status).toBe("GREEN");
  });

  it("YELLOW for medium changes", () => {
    const result = rule.check(makeContext({ additions: 400, deletions: 200 }));
    expect(result.status).toBe("YELLOW");
  });

  it("RED for large changes", () => {
    const result = rule.check(makeContext({ additions: 800, deletions: 300 }));
    expect(result.status).toBe("RED");
  });
});

describe("Workspace Scope Compliance gate", () => {
  const rule = getRuleByName("Workspace Scope Compliance")!;

  it("GREEN when no restrictions", () => {
    const result = rule.check(makeContext({ files: ["any/file.ts"] }));
    expect(result.status).toBe("GREEN");
  });

  it("GREEN when all files in scope", () => {
    const result = rule.check(
      makeContext({
        files: ["packages/chess-engine/src/index.ts"],
        allowedPaths: ["packages/chess-engine/"],
      }),
    );
    expect(result.status).toBe("GREEN");
  });

  it("RED when files outside scope", () => {
    const result = rule.check(
      makeContext({
        files: ["packages/chess-engine/src/index.ts", "packages/spike-review/src/types.ts"],
        allowedPaths: ["packages/chess-engine/"],
      }),
    );
    expect(result.status).toBe("RED");
  });
});

describe("runGates", () => {
  it("runs all rules and returns results", () => {
    const rules = getBuiltinRules();
    const results = runGates(rules, makeContext());
    expect(results).toHaveLength(6);
    for (const r of results) {
      expect(r).toHaveProperty("name");
      expect(r).toHaveProperty("status");
      expect(r).toHaveProperty("detail");
    }
  });
});

describe("computeOverallStatus", () => {
  it("RED if any RED", () => {
    const gates: GateResult[] = [
      { name: "A", status: "GREEN", detail: "" },
      { name: "B", status: "RED", detail: "" },
    ];
    expect(computeOverallStatus(gates)).toBe("RED");
  });

  it("YELLOW if any YELLOW (no RED)", () => {
    const gates: GateResult[] = [
      { name: "A", status: "GREEN", detail: "" },
      { name: "B", status: "YELLOW", detail: "" },
    ];
    expect(computeOverallStatus(gates)).toBe("YELLOW");
  });

  it("GREEN if all GREEN", () => {
    const gates: GateResult[] = [
      { name: "A", status: "GREEN", detail: "" },
      { name: "B", status: "GREEN", detail: "" },
    ];
    expect(computeOverallStatus(gates)).toBe("GREEN");
  });
});

describe("formatGateResults", () => {
  it("produces markdown table", () => {
    const gates: GateResult[] = [
      {
        name: "Test Gate",
        status: "GREEN",
        detail: "All good",
      },
    ];
    const text = formatGateResults(gates);
    expect(text).toContain("BAZDMEG Quality Gates");
    expect(text).toContain("Test Gate");
    expect(text).toContain("All good");
    expect(text).toContain("Overall: GREEN");
    expect(text).toContain("All quality gates passing");
  });

  it("formats reports with RED status correctly", () => {
    const gates: GateResult[] = [{ name: "Tests", status: "RED", detail: "Missing" }];
    const output = formatGateResults(gates);
    expect(output).toContain("Overall: RED");
    expect(output).toContain("Issues must be addressed");
  });

  it("formats reports with YELLOW status correctly", () => {
    const gates: GateResult[] = [{ name: "Size", status: "YELLOW", detail: "Large" }];
    const output = formatGateResults(gates);
    expect(output).toContain("Overall: YELLOW");
    expect(output).toContain("Minor concerns noted");
  });
});

describe("Diff parsing edge cases", () => {
  it("getChangedFiles handles non-git diff headers", () => {
    const diff = "+++ b/src/only-plus.ts\n+ new line";
    const files = getChangedFiles(diff);
    expect(files).toEqual(["src/only-plus.ts"]);
  });

  it("detects @ts-nocheck and various security patterns", () => {
    const diff = [
      "+// @ts-nocheck",
      "+const password = '123';",
      "+const token = 'test-fake-value';",
    ].join("\n");
    const ctx = makeContext({ diff });
    const rules = getBuiltinRules();

    const complianceRule = rules.find((r) => r.name === "TypeScript Strict Compliance")!;
    expect(complianceRule.check(ctx).status).toBe("RED");
    expect(complianceRule.check(ctx).detail).toContain("@ts-nocheck");

    const securityRule = rules.find((r) => r.name === "Security Patterns")!;
    const res = securityRule.check(ctx);
    expect(res.status).toBe("RED");
    expect(res.detail).toContain("Hardcoded password");
    expect(res.detail).toContain("Potential secret/token");
  });
});

describe("Workspace scope edge cases", () => {
  it("Workspace Scope Compliance uses ellipsis for many files", () => {
    const ctx = makeContext({
      files: ["a.ts", "b.ts", "c.ts", "d.ts", "e.ts"],
      allowedPaths: ["src/"],
    });
    const rule = getBuiltinRules().find((r) => r.name === "Workspace Scope Compliance")!;
    const res = rule.check(ctx);
    expect(res.status).toBe("RED");
    expect(res.detail).toContain("...");
  });
});

/**
 * Tests for the root manifest.ts module
 *
 * Covers: readManifest, getManifestPackage, clearManifestCache,
 * topologicalSort, and the YAML parser functions.
 */

import { afterEach, beforeEach, describe, expect, it } from "vitest";
import { mkdtemp, rm, writeFile } from "node:fs/promises";
import { join } from "node:path";
import { tmpdir } from "node:os";
import {
  clearManifestCache,
  getManifestPackage,
  readManifest,
  topologicalSort,
} from "../../src/mcp-tools/bazdmeg/node-sys/manifest.js";

// Helper to create a temp directory with a packages.yaml file
async function createTempManifest(
  yamlContent: string,
): Promise<{ root: string; cleanup: () => Promise<void> }> {
  const root = await mkdtemp(join(tmpdir(), "bazdmeg-manifest-test-"));
  await writeFile(join(root, "packages.yaml"), yamlContent, "utf-8");
  return {
    root,
    cleanup: () => rm(root, { recursive: true, force: true }),
  };
}

const BASIC_MANIFEST_YAML = `
defaults:
  scope: "@spike-land-ai"
  registry: npm.pkg.github.com
  license: MIT
  type: module

packages:
  shared:
    kind: library
    version: 1.0.0
    description: Shared utilities
    entry: src/index.ts

  chess-engine:
    kind: library
    version: 1.2.0
    description: Chess ELO engine
    entry: src/index.ts
    deps:
      - shared

  spike-cli:
    kind: cli
    version: 2.0.0
    description: CLI tool
    entry: src/index.ts
    deps:
      - shared
      - chess-engine

  spike-edge:
    kind: worker
    version: 1.0.0
    description: Edge worker
    entry: src/index.ts
    worker:
      name: spike-edge
      compatibility_date: "2024-01-01"
      compatibility_flags:
        - nodejs_compat
      kv_namespaces:
        - binding: KV
          id: abc123
      d1_databases:
        - binding: DB
          database_name: mydb
          database_id: db456
      r2_buckets:
        - binding: BUCKET
          bucket_name: files
      durable_objects:
        - name: ROOM
          class_name: ChatRoom
          sqlite: true
      routes:
        - pattern: "api.example.com/*"
          custom_domain: true
          zone_name: example.com
      rules:
        - type: Text
          globs:
            - "**/*.txt"
      assets:
        directory: ./dist
        not_found_handling: single-page-application
      site:
        bucket: ./public
`;

describe("readManifest", () => {
  let cleanup: () => Promise<void>;
  let root: string;

  beforeEach(() => {
    clearManifestCache();
  });

  afterEach(async () => {
    clearManifestCache();
    if (cleanup) await cleanup();
  });

  it("reads and parses a basic manifest", async () => {
    const tmp = await createTempManifest(BASIC_MANIFEST_YAML);
    root = tmp.root;
    cleanup = tmp.cleanup;

    const manifest = await readManifest(root);
    expect(manifest.defaults.scope).toBe("@spike-land-ai");
    expect(manifest.defaults.registry).toBe("npm.pkg.github.com");
    expect(manifest.defaults.license).toBe("MIT");
    expect(manifest.defaults.type).toBe("module");
  });

  it("parses packages correctly", async () => {
    const tmp = await createTempManifest(BASIC_MANIFEST_YAML);
    root = tmp.root;
    cleanup = tmp.cleanup;

    const manifest = await readManifest(root);
    expect(manifest.packages["shared"]).toBeDefined();
    expect(manifest.packages["chess-engine"]).toBeDefined();
    expect(manifest.packages["chess-engine"]?.deps).toContain("shared");
  });

  it("parses worker config with all fields", async () => {
    const tmp = await createTempManifest(BASIC_MANIFEST_YAML);
    root = tmp.root;
    cleanup = tmp.cleanup;

    const manifest = await readManifest(root);
    const worker = manifest.packages["spike-edge"]?.worker!;
    expect(worker.name).toBe("spike-edge");
    expect(worker.compatibility_date).toBe("2024-01-01");
    expect(worker.compatibility_flags).toContain("nodejs_compat");
    expect(worker.kv_namespaces).toBeDefined();
    expect(worker.kv_namespaces?.[0]?.binding).toBe("KV");
    expect(worker.d1_databases).toBeDefined();
    expect(worker.d1_databases?.[0]?.binding).toBe("DB");
    expect(worker.r2_buckets).toBeDefined();
    expect(worker.r2_buckets?.[0]?.binding).toBe("BUCKET");
    expect(worker.durable_objects).toBeDefined();
    expect(worker.durable_objects?.[0]?.name).toBe("ROOM");
    expect(worker.durable_objects?.[0]?.sqlite).toBe(true);
    expect(worker.routes).toBeDefined();
    expect(worker.routes?.[0]?.pattern).toBe("api.example.com/*");
    expect(worker.routes?.[0]?.custom_domain).toBe(true);
    expect(worker.routes?.[0]?.zone_name).toBe("example.com");
    expect(worker.rules).toBeDefined();
    expect(worker.assets).toBeDefined();
    expect(worker.assets?.directory).toBe("./dist");
    expect(worker.assets?.not_found_handling).toBe("single-page-application");
    expect(worker.site).toBeDefined();
    expect(worker.site?.bucket).toBe("./public");
  });

  it("parses inline arrays used by worker manifest fields", async () => {
    const tmp = await createTempManifest(`
defaults:
  scope: "@spike-land-ai"
  registry: https://npm.pkg.github.com
  license: MIT
  type: module

packages:
  spike-edge:
    kind: worker
    version: 1.0.0
    description: Edge worker
    entry: index.ts
    worker:
      name: spike-edge
      compatibility_date: "2026-03-01"
      compatibility_flags: [nodejs_compat, trace_events]
      migrations:
        - tag: v1
          new_classes: [RateLimiter, AnotherClass]
`);
    root = tmp.root;
    cleanup = tmp.cleanup;

    const manifest = await readManifest(root);
    const worker = manifest.packages["spike-edge"]?.worker!;
    expect(worker.compatibility_flags).toEqual(["nodejs_compat", "trace_events"]);
    expect(worker.migrations?.[0]?.new_classes).toEqual(["RateLimiter", "AnotherClass"]);
  });

  it("caches the manifest on second call", async () => {
    const tmp = await createTempManifest(BASIC_MANIFEST_YAML);
    root = tmp.root;
    cleanup = tmp.cleanup;

    const manifest1 = await readManifest(root);
    const manifest2 = await readManifest(root);
    // Should be the same object reference (cached)
    expect(manifest1).toBe(manifest2);
  });

  it("throws when packages.yaml is missing required keys", async () => {
    const tmp = await createTempManifest(`
invalid:
  key: value
`);
    root = tmp.root;
    cleanup = tmp.cleanup;

    await expect(readManifest(root)).rejects.toThrow("Invalid packages.yaml");
  });

  it("throws when packages.yaml file does not exist", async () => {
    const tmpRoot = await mkdtemp(join(tmpdir(), "bazdmeg-no-manifest-"));
    const tmpCleanup = () => rm(tmpRoot, { recursive: true, force: true });
    try {
      await expect(readManifest(tmpRoot)).rejects.toThrow();
    } finally {
      await tmpCleanup();
    }
  });

  it("uses process.cwd() when no root is provided", async () => {
    // This test just verifies the function can be called without args (may throw if no manifest in cwd)
    try {
      await readManifest();
    } catch {
      // Expected if no packages.yaml in cwd
    }
    // No assertion needed - just verifying it doesn't crash in an unexpected way
    expect(true).toBe(true);
  });
});

describe("clearManifestCache", () => {
  let cleanup: () => Promise<void>;
  let root: string;

  afterEach(async () => {
    clearManifestCache();
    if (cleanup) await cleanup();
  });

  it("clears cache so next read re-reads the file", async () => {
    const tmp = await createTempManifest(BASIC_MANIFEST_YAML);
    root = tmp.root;
    cleanup = tmp.cleanup;

    const manifest1 = await readManifest(root);
    clearManifestCache();
    const manifest2 = await readManifest(root);
    // After clearing cache, should be a new object
    expect(manifest1).not.toBe(manifest2);
    // But same data
    expect(manifest1.defaults.scope).toBe(manifest2.defaults.scope);
  });
});

describe("getManifestPackage", () => {
  let cleanup: () => Promise<void>;
  let root: string;

  beforeEach(() => {
    clearManifestCache();
  });

  afterEach(async () => {
    clearManifestCache();
    if (cleanup) await cleanup();
  });

  it("returns a package by name", async () => {
    const tmp = await createTempManifest(BASIC_MANIFEST_YAML);
    root = tmp.root;
    cleanup = tmp.cleanup;

    const pkg = await getManifestPackage("chess-engine", root);
    expect(pkg).toBeDefined();
    expect(pkg?.kind).toBe("library");
    expect(pkg?.version).toBe("1.2.0");
  });

  it("returns null for non-existent package", async () => {
    const tmp = await createTempManifest(BASIC_MANIFEST_YAML);
    root = tmp.root;
    cleanup = tmp.cleanup;

    const pkg = await getManifestPackage("nonexistent", root);
    expect(pkg).toBeNull();
  });

  it("returns shared package with no deps", async () => {
    const tmp = await createTempManifest(BASIC_MANIFEST_YAML);
    root = tmp.root;
    cleanup = tmp.cleanup;

    const pkg = await getManifestPackage("shared", root);
    expect(pkg).toBeDefined();
    expect(pkg?.deps).toBeUndefined();
  });
});

describe("topologicalSort", () => {
  it("sorts packages with no deps correctly", () => {
    const packages = {
      a: { kind: "library", version: "1.0.0", description: "A", entry: "src/index.ts" },
      b: { kind: "library", version: "1.0.0", description: "B", entry: "src/index.ts" },
    };
    const order = topologicalSort(packages);
    expect(order).toContain("a");
    expect(order).toContain("b");
    expect(order).toHaveLength(2);
  });

  it("sorts packages respecting dependencies", () => {
    const packages = {
      "chess-engine": {
        kind: "library",
        version: "1.0.0",
        description: "Chess",
        entry: "src/index.ts",
        deps: ["shared"],
      },
      shared: {
        kind: "library",
        version: "1.0.0",
        description: "Shared",
        entry: "src/index.ts",
      },
    };
    const order = topologicalSort(packages);
    const sharedIdx = order.indexOf("shared");
    const chessIdx = order.indexOf("chess-engine");
    expect(sharedIdx).toBeLessThan(chessIdx);
  });

  it("sorts a chain of 3 packages in correct build order", () => {
    const packages = {
      c: {
        kind: "library",
        version: "1.0.0",
        description: "C",
        entry: "src/index.ts",
        deps: ["b"],
      },
      b: {
        kind: "library",
        version: "1.0.0",
        description: "B",
        entry: "src/index.ts",
        deps: ["a"],
      },
      a: { kind: "library", version: "1.0.0", description: "A", entry: "src/index.ts" },
    };
    const order = topologicalSort(packages);
    expect(order.indexOf("a")).toBeLessThan(order.indexOf("b"));
    expect(order.indexOf("b")).toBeLessThan(order.indexOf("c"));
  });

  it("throws on circular dependencies", () => {
    const packages = {
      a: {
        kind: "library",
        version: "1.0.0",
        description: "A",
        entry: "src/index.ts",
        deps: ["b"],
      },
      b: {
        kind: "library",
        version: "1.0.0",
        description: "B",
        entry: "src/index.ts",
        deps: ["a"],
      },
    };
    expect(() => topologicalSort(packages)).toThrow("Circular dependency");
  });

  it("handles packages with external deps (not in manifest)", () => {
    const packages = {
      "chess-engine": {
        kind: "library",
        version: "1.0.0",
        description: "Chess",
        entry: "src/index.ts",
        deps: ["external-not-in-manifest"],
      },
    };
    // Should not throw — external deps are skipped
    const order = topologicalSort(packages);
    expect(order).toContain("chess-engine");
  });

  it("returns empty array for empty packages", () => {
    const order = topologicalSort({});
    expect(order).toEqual([]);
  });

  it("handles packages where deps is undefined", () => {
    const packages = {
      a: { kind: "library", version: "1.0.0", description: "A", entry: "src/index.ts" },
    };
    const order = topologicalSort(packages);
    expect(order).toEqual(["a"]);
  });
});

describe("YAML parser edge cases", () => {
  let cleanup: () => Promise<void>;
  let root: string;

  beforeEach(() => {
    clearManifestCache();
  });

  afterEach(async () => {
    clearManifestCache();
    if (cleanup) await cleanup();
  });

  it("handles boolean values in YAML", async () => {
    const yaml = `
defaults:
  scope: "@spike-land-ai"
  registry: npm.pkg.github.com
  license: MIT
  type: module

packages:
  test-pkg:
    kind: worker
    version: 1.0.0
    description: Test
    entry: src/index.ts
    private: true
    vite: false
`;
    const tmp = await createTempManifest(yaml);
    root = tmp.root;
    cleanup = tmp.cleanup;

    const manifest = await readManifest(root);
    expect(manifest.packages["test-pkg"]?.private).toBe(true);
    expect(manifest.packages["test-pkg"]?.vite).toBe(false);
  });

  it("handles null/empty values in YAML", async () => {
    const yaml = `
defaults:
  scope: "@spike-land-ai"
  registry: npm.pkg.github.com
  license: MIT
  type: module

packages:
  test-pkg:
    kind: library
    version: 1.0.0
    description: Test
    entry: src/index.ts
    bin: null
