    processor = new CodeProcessor("test-code-space");
    mockAbortController = new AbortController();

    baseSession = {
      code: "const x = 1;",
      transpiled: "transpiled:const x = 1;",
      html: "<div>test</div>",
      css: ".test { color: blue; }",
