    // Mock document methods for iframe handling
    vi.spyOn(document, "createElement").mockImplementation((tagName) => {
      if (tagName === "iframe") {
        const iframe = {
          srcdoc: "",
          title: "",
          className: "",
          style: { display: "" },
          contentWindow: null,
        } as unknown as HTMLIFrameElement;
        return iframe;
      }
      return document.createElement(tagName);
