describe("esbuild_wasm_mcp tools", () => {
  it("build tool provides defaults for bundle and write", async () => {
    const server = new MockMcpServer();
    registerBuildTool(server as unknown as McpServer);

    const handler = server.tools.get("esbuild_wasm_build");
    expect(handler).toBeDefined();

    mockEsbuild.build.mockResolvedValue({
      outputFiles: [{ path: "out.js", text: "console.log('test')" }],
      warnings: [],
      errors: [],
    });

    await handler!({
      entryPoints: ["in.js"],
    });

    expect(mockEsbuild.build).toHaveBeenCalledWith(
      expect.objectContaining({
        entryPoints: ["in.js"],
        bundle: true,
        write: false,
      }),
    );
  });

  it("context tool provides defaults for bundle and write", async () => {
    const server = new MockMcpServer();
    registerContextTool(server as unknown as McpServer);

    const handler = server.tools.get("esbuild_wasm_context");
    expect(handler).toBeDefined();

    const mockCtx = {
      rebuild: vi.fn().mockResolvedValue({
        outputFiles: [{ path: "out.js", text: "console.log('test')" }],
        warnings: [],
        errors: [],
      }),
      dispose: vi.fn().mockResolvedValue(undefined),
    };
    mockEsbuild.context.mockResolvedValue(mockCtx);

    await handler!({
      entryPoints: ["in.js"],
    });

    expect(mockEsbuild.context).toHaveBeenCalledWith(
      expect.objectContaining({
        entryPoints: ["in.js"],
        bundle: true,
        write: false,
      }),
    );
    expect(mockCtx.rebuild).toHaveBeenCalled();
    expect(mockCtx.dispose).toHaveBeenCalled();
  });

  it("build tool handles metafile and mangleCache", async () => {
    const server = new MockMcpServer();
    registerBuildTool(server as unknown as McpServer);
    const handler = server.tools.get("esbuild_wasm_build");

    mockEsbuild.build.mockResolvedValue({
      outputFiles: [],
      warnings: [],
      errors: [],
      metafile: { inputs: {}, outputs: {} },
      mangleCache: { a: "b" },
    });

    const result = (await handler!({ entryPoints: ["in.js"] })) as {
      content: { text: string }[];
    };
    const parsed = JSON.parse(result.content[0]?.text);
    expect(parsed.metafile).toBeDefined();
    expect(parsed.mangleCache).toBeDefined();
  });

  it("build tool handles errors", async () => {
    const server = new MockMcpServer();
    registerBuildTool(server as unknown as McpServer);
    const handler = server.tools.get("esbuild_wasm_build");

    mockEsbuild.build.mockRejectedValue(new Error("Build failed"));
    const result = (await handler!({ entryPoints: ["in.js"] })) as {
      isError: boolean;
    };
    expect(result.isError).toBe(true);
  });

  it("build tool handles missing outputFiles", async () => {
    const server = new MockMcpServer();
    registerBuildTool(server as unknown as McpServer);
    const handler = server.tools.get("esbuild_wasm_build");

    mockEsbuild.build.mockResolvedValue({
      warnings: [],
      errors: [],
      // outputFiles missing
    });

    const result = (await handler!({ entryPoints: ["in.js"] })) as {
      content: { text: string }[];
    };
    const parsed = JSON.parse(result.content[0].text);
    expect(parsed.outputFiles).toEqual([]);
  });

  it("build tool handles reserveProps", async () => {
    const server = new MockMcpServer();
    registerBuildTool(server as unknown as McpServer);
    const handler = server.tools.get("esbuild_wasm_build");

    mockEsbuild.build.mockResolvedValue({
      outputFiles: [],
      warnings: [],
      errors: [],
    });

    await handler!({
      entryPoints: ["in.js"],
      reserveProps: "^myProp$",
    });

    expect(mockEsbuild.build).toHaveBeenCalledWith(
      expect.objectContaining({
        reserveProps: expect.any(RegExp),
      }),
    );
  });
});

import { beforeEach, describe, expect, it, vi } from "vitest";
import { registerContextTool } from "../../../src/mcp-tools/esbuild-wasm/lazy-imports/context.js";
import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";

const mockContext = vi.hoisted(() => vi.fn());
const mockRebuild = vi.hoisted(() => vi.fn());
const mockDispose = vi.hoisted(() => vi.fn());

vi.mock("esbuild-wasm", () => ({
  context: mockContext,
  version: "0.27.4",
  initialize: vi.fn().mockResolvedValue(undefined),
}));

class MockMcpServer {
  tools = new Map<string, (args: Record<string, unknown>) => Promise<unknown>>();

  tool(
    name: string,
    _description: string,
    _schema: Record<string, unknown>,
    handler: (args: Record<string, unknown>) => Promise<unknown>,
  ) {
    this.tools.set(name, handler);
  }
}

function makeServer() {
  const server = new MockMcpServer();
  registerContextTool(server as unknown as McpServer);
  const handler = server.tools.get("esbuild_wasm_context")!;
  return { server, handler };
}

describe("context tool", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it("registers esbuild_wasm_context tool", () => {
    const { server } = makeServer();
    expect(server.tools.has("esbuild_wasm_context")).toBe(true);
  });

  it("successfully creates context, rebuilds and disposes", async () => {
    const { handler } = makeServer();
    mockRebuild.mockResolvedValue({
      outputFiles: [{ path: "out.js", text: "code" }],
      warnings: [],
      errors: [],
    });
    mockContext.mockResolvedValue({
      rebuild: mockRebuild,
      dispose: mockDispose,
    });

    const result = (await handler({ entryPoints: ["in.js"] })) as {
      content: { text: string }[];
      isError?: boolean;
    };

    expect(mockContext).toHaveBeenCalled();
    expect(mockRebuild).toHaveBeenCalled();
    expect(mockDispose).toHaveBeenCalled();
    expect(result.isError).toBeUndefined();
    expect(result.content[0].text).toContain("out.js");
  });

  it("handles context creation failure", async () => {
    const { handler } = makeServer();
    mockContext.mockRejectedValue(new Error("context fail"));

    const result = (await handler({ entryPoints: ["in.js"] })) as {
      content: { text: string }[];
      isError?: boolean;
    };

    expect(result.isError).toBe(true);
    expect(result.content[0].text).toContain("context fail");
  });

  it("handles rebuild failure", async () => {
    const { handler } = makeServer();
    mockRebuild.mockRejectedValue(new Error("rebuild fail"));
    mockContext.mockResolvedValue({
      rebuild: mockRebuild,
      dispose: mockDispose,
    });

    const result = (await handler({ entryPoints: ["in.js"] })) as {
      content: { text: string }[];
      isError?: boolean;
    };

    expect(result.isError).toBe(true);
    expect(result.content[0].text).toContain("rebuild fail");
    expect(mockDispose).toHaveBeenCalled();
  });

  it("handles missing outputFiles and present mangleCache", async () => {
    const { handler } = makeServer();
    mockRebuild.mockResolvedValue({
      warnings: [],
      errors: [],
      mangleCache: { foo: "bar" },
      // outputFiles missing
    });
    mockContext.mockResolvedValue({
      rebuild: mockRebuild,
      dispose: mockDispose,
    });

    const result = (await handler({ entryPoints: ["in.js"] })) as {
      content: { text: string }[];
      isError?: boolean;
    };
    const parsed = JSON.parse(result.content[0].text);
    expect(parsed.outputFiles).toEqual([]);
    expect(parsed.mangleCache).toEqual({ foo: "bar" });
  });
});

import { describe, expect, it, vi } from "vitest";
import { registerFormatMessagesTool } from "../../../src/mcp-tools/esbuild-wasm/lazy-imports/format-messages.js";
import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";

const mockEsbuild = vi.hoisted(() => ({
  formatMessages: vi.fn(),
}));

vi.mock("../../../src/mcp-tools/esbuild-wasm/node-sys/wasm-api.js", () => ({
  getEsbuildWasm: vi.fn().mockResolvedValue(mockEsbuild),
}));

class MockMcpServer {
  tools = new Map<string, (args: Record<string, unknown>) => Promise<unknown>>();

  tool(
    name: string,
    _description: string,
    _schema: Record<string, unknown>,
    handler: (args: Record<string, unknown>) => Promise<unknown>,
  ) {
    this.tools.set(name, handler);
  }
