  } as unknown as D1Database;
}

function createMockEnv(overrides: Partial<Env> = {}): Env {
  return {
    R2: {} as unknown as R2Bucket,
    SPA_ASSETS: {} as unknown as R2Bucket,
    DB: createMockD1(),
    LIMITERS: {} as unknown as DurableObjectNamespace,
