/**
 * Form Filler
 *
 * Manages loading a FormTemplate, prefilling it from a user profile, validating
 * individual fields, and tracking overall completion state.
 *
 * COMPASS principle: this module NEVER fabricates required document content.
 * It only maps known user profile data onto form fields and flags what is still
 * missing.
 */

import type { FilledForm, FormField, FormTemplate, ValidationResult } from "../types.js";

// ---------------------------------------------------------------------------
// User profile shape — the data COMPASS holds about a user
// ---------------------------------------------------------------------------

/**
 * A flat bag of well-known profile keys.  Only the keys defined here are used
 * for prefill; all other profile data is ignored.
 */
export interface UserProfile {
  readonly givenName?: string;
  readonly familyName?: string;
  readonly dateOfBirth?: string; // ISO 8601 date, e.g. "1990-04-15"
  readonly email?: string;
  readonly phone?: string;
  readonly addressLine1?: string;
  readonly addressLine2?: string;
  readonly city?: string;
  readonly stateOrProvince?: string;
  readonly postalCode?: string;
  readonly country?: string;
  readonly nationalIdNumber?: string;
  readonly passportNumber?: string;
}

// ---------------------------------------------------------------------------
// FormFiller class
// ---------------------------------------------------------------------------

export class FormFiller {
  private template: FormTemplate | null = null;
  private values: Map<string, unknown> = new Map();

  // -------------------------------------------------------------------------
  // Template management
  // -------------------------------------------------------------------------

  /**
   * Load a form template.  Clears any previously stored values so the filler
   * always operates on a single template at a time.
   */
  loadTemplate(template: FormTemplate): void {
    this.template = template;
    this.values = new Map();
  }

  // -------------------------------------------------------------------------
  // Prefill
  // -------------------------------------------------------------------------

  /**
   * Attempt to map well-known profile fields onto the loaded template's fields.
   *
   * Matching is heuristic: it checks whether a field's `id` or `label`
   * contains a known profile-key synonym.  Only fields that have a non-empty
   * match are written; required fields with no match remain blank so the caller
   * can clearly see what still needs human input.
   *
   * @throws if no template has been loaded yet.
   */
  prefillFromProfile(userProfile: UserProfile): FilledForm {
    this.requireTemplate();

    for (const field of this.template!.fields) {
      const value = this.resolveProfileValue(field, userProfile);
      if (value !== undefined) {
        this.values.set(field.id, value);
      }
    }

    return this.buildFilledForm();
  }

  // -------------------------------------------------------------------------
  // Field operations
  // -------------------------------------------------------------------------

  /**
   * Set a single field value and return its validation result.
   * The value is stored even when validation fails so the UI can show the
   * error inline rather than discarding user input.
   */
  setField(fieldId: string, value: unknown): ValidationResult {
    this.requireTemplate();
    const field = this.findField(fieldId);
    if (!field) {
      return { valid: false, errorMessage: `Unknown field "${fieldId}".` };
    }
    this.values.set(fieldId, value);
    return this.validateField(fieldId, value);
  }

  /**
   * Validate a value against a field's rules without storing it.
   *
   * Returns `{valid: true}` immediately when the field is optional and the
   * value is empty so callers do not need to special-case optional fields.
   */
  validateField(fieldId: string, value: unknown): ValidationResult {
    this.requireTemplate();
    const field = this.findField(fieldId);
    if (!field) {
      return { valid: false, errorMessage: `Unknown field "${fieldId}".` };
    }

    const isEmpty = value === undefined || value === null || value === "";

    if (isEmpty) {
      if (field.required) {
        return {
          valid: false,
          errorMessage: `"${field.label}" is required.`,
        };
      }
      return { valid: true };
    }

    return validateAgainstRules(field, value);
  }

  /**
   * Return a plain-language help string for a given field.
   * Falls back to the field's own `helpText` when available, otherwise
   * generates a generic description from the field metadata.
   */
  getFieldHelp(fieldId: string): string {
    this.requireTemplate();
    const field = this.findField(fieldId);
    if (!field) {
      return `No help available for field "${fieldId}".`;
    }
    if (field.helpText) {
      return field.helpText;
    }
    return generateGenericHelp(field);
  }

  // -------------------------------------------------------------------------
  // Completion status
  // -------------------------------------------------------------------------

  /**
   * Compute how complete the form currently is.
   *
   * @returns An object with:
   *   - `percentage` — 0–100 integer based on required fields answered.
   *   - `missingFields` — IDs of required fields that are still blank.
   *   - `filledForm` — Current FilledForm snapshot.
   */
  getCompletionStatus(form?: FilledForm): {
    percentage: number;
    missingFields: string[];
    filledForm: FilledForm;
  } {
    this.requireTemplate();

    // If a FilledForm snapshot was passed in, use its values; otherwise use
    // the internal mutable map.
    const source: ReadonlyMap<string, unknown> = form ? form.values : this.values;

    const requiredFields = this.template!.fields.filter((f) => f.required);
    const missingFields = requiredFields
      .filter((f) => {
        const v = source.get(f.id);
        return v === undefined || v === null || v === "";
      })
      .map((f) => f.id);

    const answered = requiredFields.length - missingFields.length;
    const percentage =
      requiredFields.length === 0 ? 100 : Math.round((answered / requiredFields.length) * 100);

    const filledForm: FilledForm = {
      templateId: this.template!.id,
      values: source,
      completionPercentage: percentage,
      missingFields,
    };

    return { percentage, missingFields, filledForm };
  }

  // -------------------------------------------------------------------------
  // Private helpers
  // -------------------------------------------------------------------------

  private requireTemplate(): void {
    if (!this.template) {
      throw new Error("No template loaded. Call loadTemplate() before using FormFiller.");
    }
  }

  private findField(fieldId: string): FormField | undefined {
    return this.template!.fields.find((f) => f.id === fieldId);
  }

  private buildFilledForm(): FilledForm {
    const { percentage, missingFields } = this.getCompletionStatus();
    return {
      templateId: this.template!.id,
      values: new Map(this.values),
      completionPercentage: percentage,
      missingFields,
    };
  }

  /**
   * Heuristic profile-to-field resolution.
   *
   * The combined needle is `"${field.id} ${field.label}".toLowerCase()`.
   * Each synonym group maps to a profile value; the first match wins.
   */
  private resolveProfileValue(field: FormField, profile: UserProfile): unknown {
    const needle = `${field.id} ${field.label}`.toLowerCase();

    const matchers: Array<{ keywords: string[]; value: unknown }> = [
      {
        keywords: ["givenname", "given_name", "first name", "firstname", "given"],
        value: profile.givenName,
      },
      {
        keywords: ["familyname", "family_name", "last name", "lastname", "surname"],
        value: profile.familyName,
      },
      {
        keywords: ["dob", "date of birth", "dateofbirth", "birth_date", "birthdate"],
        value: profile.dateOfBirth,
      },
      {
        keywords: ["email", "e-mail", "emailaddress"],
        value: profile.email,
      },
      {
        keywords: ["phone", "telephone", "mobile", "cell"],
        value: profile.phone,
      },
      {
        keywords: ["address1", "addressline1", "street address", "address line 1"],
        value: profile.addressLine1,
      },
      {
        keywords: ["address2", "addressline2", "address line 2", "apt", "suite"],
        value: profile.addressLine2,
      },
      {
        keywords: ["city", "town", "municipality"],
        value: profile.city,
      },
      {
        keywords: ["state", "province", "region", "county"],
        value: profile.stateOrProvince,
      },
      {
        keywords: ["postalcode", "postal_code", "zip", "postcode"],
        value: profile.postalCode,
      },
      {
        keywords: ["country", "nation"],
        value: profile.country,
      },
      {
        keywords: ["nationalid", "national_id", "national id", "ssn", "sin", "nino"],
        value: profile.nationalIdNumber,
      },
      {
        keywords: ["passport", "passportnumber", "passport_number"],
        value: profile.passportNumber,
      },
    ];

    for (const { keywords, value } of matchers) {
      if (value !== undefined && value !== "" && keywords.some((kw) => needle.includes(kw))) {
        return value;
      }
    }

    return undefined;
  }
}

// ---------------------------------------------------------------------------
// Standalone validation helper (also exported for direct use)
// ---------------------------------------------------------------------------

/**
 * Validate `value` against the rules declared on `field`.
 * Does NOT check for required-ness; that is the caller's responsibility.
 */
export function validateAgainstRules(field: FormField, value: unknown): ValidationResult {
  // Type-level coercions
  if (field.type === "number") {
    const num = Number(value);
    if (Number.isNaN(num)) {
      return {
        valid: false,
        errorMessage: `"${field.label}" must be a number.`,
      };
    }
    if (field.validation?.min !== undefined && num < field.validation.min) {
      return {
        valid: false,
        errorMessage:
          field.validation.message || `"${field.label}" must be at least ${field.validation.min}.`,
      };
    }
    if (field.validation?.max !== undefined && num > field.validation.max) {
      return {
        valid: false,
        errorMessage:
          field.validation.message || `"${field.label}" must be at most ${field.validation.max}.`,
      };
    }
    return { valid: true };
  }

  if (field.type === "date") {
    const d = new Date(String(value));
    if (isNaN(d.getTime())) {
      return {
        valid: false,
        errorMessage: `"${field.label}" must be a valid date.`,
      };
    }
    return { valid: true };
  }

  if (field.type === "select") {
    const options = field.options ?? [];
    if (!options.includes(String(value))) {
      return {
        valid: false,
        errorMessage: `"${field.label}" must be one of: ${options.join(", ")}.`,
      };
    }
    return { valid: true };
  }

  if (field.type === "text" || field.type === "signature") {
    const str = String(value);
    if (field.validation?.min !== undefined && str.length < field.validation.min) {
      return {
        valid: false,
        errorMessage:
          field.validation.message ||
          `"${field.label}" must be at least ${field.validation.min} characters.`,
      };
    }
    if (field.validation?.max !== undefined && str.length > field.validation.max) {
      return {
        valid: false,
        errorMessage:
          field.validation.message ||
          `"${field.label}" must be at most ${field.validation.max} characters.`,
      };
    }
    if (field.validation?.pattern) {
      const re = new RegExp(field.validation.pattern);
      if (!re.test(str)) {
        return {
          valid: false,
          errorMessage:
            field.validation.message || `"${field.label}" does not match the required format.`,
        };
      }
    }
    return { valid: true };
  }

  // checkbox — any truthy/falsy is valid
  return { valid: true };
}

// ---------------------------------------------------------------------------
// Generic help text generator
// ---------------------------------------------------------------------------

function generateGenericHelp(field: FormField): string {
  const typeDescriptions: Record<string, string> = {
    text: "Enter text",
    date: "Enter a date in YYYY-MM-DD format",
    number: "Enter a numeric value",
    checkbox: "Check this box if the statement applies to you",
    select: `Choose one of the available options`,
    signature: "Type your full legal name as a signature",
  };

  const base = typeDescriptions[field.type] ?? "Complete this field";
  const requiredNote = field.required ? " (required)" : " (optional)";

  const rangeNote = field.validation
    ? (() => {
        if (field.type === "number" || field.type === "text") {
          const parts: string[] = [];
          if (field.validation.min !== undefined) parts.push(`minimum ${field.validation.min}`);
          if (field.validation.max !== undefined) parts.push(`maximum ${field.validation.max}`);
          return parts.length ? `. Allowed range: ${parts.join(", ")}` : "";
        }
        return "";
      })()
    : "";

  const optionsNote =
    field.type === "select" && field.options?.length
      ? `. Options: ${field.options.join(", ")}`
      : "";

  return `${base}${requiredNote} for "${field.label}"${rangeNote}${optionsNote}.`;
}

/**
 * Plain Language Module
 *
 * Converts form metadata and legal boilerplate into plain, accessible
 * explanations.  All functions are pure — no I/O, no AI calls, no fabrication
 * of factual content.  They rephrase structure and labels; they do not
 * interpret legal meaning.
 */

import type { FormField, FormTemplate } from "../types.js";

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Produce a single plain-language sentence explaining what a form field
 * is asking for and what a valid answer looks like.
 */
export function explainField(field: FormField): string {
  const requiredTag = field.required ? "Required" : "Optional";
  const typeGuide = typeGuideFor(field);
  const help = field.helpText ? ` ${field.helpText}` : "";
  const validationNote = validationNoteFor(field);

  return `[${requiredTag}] ${field.label}: ${typeGuide}${validationNote}${help}`.trim();
}

/**
 * Return a step-by-step overview of what a form is about and what the user
 * will need to provide.  Each string in the array is a self-contained
 * paragraph intended to be displayed as a numbered list.
 */
export function explainForm(template: FormTemplate): string[] {
  const steps: string[] = [
    `This is the "${template.name}" form for ${template.jurisdiction}.`,
    `It has ${template.fields.length} field${template.fields.length === 1 ? "" : "s"}: ` +
      `${countRequired(template)} required and ` +
      `${template.fields.length - countRequired(template)} optional.`,
  ];

  // Group fields by type so the user knows what kinds of answers to prepare.
  const typeGroups = groupByType(template.fields);
  for (const [type, fields] of Object.entries(typeGroups)) {
    if (fields.length === 0) continue;
    const names = fields.map((f) => `"${f.label}"`).join(", ");
    steps.push(`${typeLabel(type)}: ${names}.`);
  }

  // Surface any fields that have options so the user can prepare.
  const selectFields = template.fields.filter((f) => f.type === "select" && f.options?.length);
  if (selectFields.length > 0) {
    for (const f of selectFields) {
      steps.push(`For "${f.label}", you will choose from: ${f.options!.join(", ")}.`);
    }
  }

  // Include the official instructions if they are non-trivial.
  if (template.instructions.trim().length > 0) {
    steps.push(`Official instructions: ${template.instructions.trim()}`);
  }

  return steps;
}

/**
 * Attempt to rephrase a block of legal or bureaucratic text in plain English.
 *
 * This is a pattern-based stub.  It applies a series of string replacements
 * for the most common legalese phrases.  A production system would integrate
 * an LLM call here, but COMPASS keeps this module free of external dependencies
 * and never fabricates meaning it cannot derive from the input text.
 */
export function translateLegalese(text: string): string {
  let result = text;

  for (const [pattern, replacement] of LEGALESE_MAP) {
    result = result.replace(pattern, replacement);
  }

  // Collapse multiple spaces that substitutions may create.
  result = result.replace(/  +/g, " ").trim();

  return result;
}

// ---------------------------------------------------------------------------
// Internal helpers
// ---------------------------------------------------------------------------

function typeGuideFor(field: FormField): string {
  switch (field.type) {
    case "text":
      return "Enter text.";
    case "date":
      return "Enter a date (format: YYYY-MM-DD, e.g. 1990-04-15).";
    case "number":
      return "Enter a number.";
    case "checkbox":
      return "Tick this box if the statement applies to you.";
    case "select":
      return field.options?.length
        ? `Choose one of: ${field.options.join(", ")}.`
        : "Choose from the available options.";
    case "signature":
      return "Type your full legal name exactly as it appears on your ID.";
  }
}

function validationNoteFor(field: FormField): string {
  const v = field.validation;
  if (!v) return "";

  const parts: string[] = [];

  if (field.type === "text" || field.type === "signature") {
    if (v.min !== undefined) parts.push(`at least ${v.min} characters`);
    if (v.max !== undefined) parts.push(`at most ${v.max} characters`);
    if (v.pattern) parts.push(`must match the format: ${v.pattern}`);
  } else if (field.type === "number") {
    if (v.min !== undefined) parts.push(`minimum value: ${v.min}`);
    if (v.max !== undefined) parts.push(`maximum value: ${v.max}`);
  }

  if (parts.length === 0) return "";
  return ` (${parts.join("; ")})`;
}

function countRequired(template: FormTemplate): number {
  return template.fields.filter((f) => f.required).length;
}

function groupByType(fields: readonly FormField[]): Record<string, FormField[]> {
  const groups: Record<string, FormField[]> = {};
  for (const field of fields) {
    if (!groups[field.type]) groups[field.type] = [];
    groups[field.type]!.push(field);
  }
  return groups;
}

function typeLabel(type: string): string {
  const labels: Record<string, string> = {
    text: "Text fields to fill in",
    date: "Date fields",
    number: "Numeric fields",
    checkbox: "Checkboxes to tick",
    select: "Drop-down selections",
    signature: "Signature fields",
  };
  return labels[type] ?? `"${type}" fields`;
}

// ---------------------------------------------------------------------------
// Legalese replacement map
// ---------------------------------------------------------------------------
// Each entry is [RegExp, replacement string].  Order matters — more specific
// phrases should appear before more general ones.
// ---------------------------------------------------------------------------

const LEGALESE_MAP: Array<[RegExp, string]> = [
  // Clauses
  [/\bnotwithstanding\b/gi, "even though"],
  [/\bwherein\b/gi, "where"],
  [/\bhereinafter\b/gi, "from here on called"],
  [/\bhereinbefore\b/gi, "mentioned earlier"],
  [/\bthereof\b/gi, "of that"],
  [/\btherein\b/gi, "in that"],
  [/\bthereto\b/gi, "to that"],
  [/\bhereunder\b/gi, "under this"],
  [/\bhereunto\b/gi, "to this"],
  [/\bwhereas\b/gi, "given that"],
  [/\bwherefore\b/gi, "for this reason"],
  [/\binter alia\b/gi, "among other things"],
  [/\bmutatis mutandis\b/gi, "with necessary changes applied"],
  [/\bpari passu\b/gi, "equally and proportionally"],
  [/\bpro rata\b/gi, "proportionally"],
  [/\bin lieu of\b/gi, "instead of"],
  [/\bin accordance with\b/gi, "following"],
  [/\bpursuant to\b/gi, "under"],
  [/\bwith respect to\b/gi, "about"],
  [/\bwith regard to\b/gi, "about"],
  [/\bin connection with\b/gi, "related to"],
  [/\bshall be deemed\b/gi, "will be considered"],
  [/\bshall\b/gi, "must"],
  [/\bmay not\b/gi, "cannot"],
  [/\bprior to\b/gi, "before"],
  [/\bsubsequent to\b/gi, "after"],
  [/\bin the event that\b/gi, "if"],
  [/\bat such time as\b/gi, "when"],
  [/\bfor the purposes of\b/gi, "for"],
  [/\bwith the exception of\b/gi, "except for"],
  [/\bsave and except\b/gi, "except"],
  [/\bany and all\b/gi, "all"],
  [/\beach and every\b/gi, "every"],
  [/\bnull and void\b/gi, "invalid"],
  [/\bcease and desist\b/gi, "stop"],
  [/\btrue and correct\b/gi, "accurate"],
  [/\bfull and complete\b/gi, "complete"],
  [/\bforce and effect\b/gi, "effect"],
  [/\bterm and condition/gi, "condition"],
  [/\brepresentations and warranties\b/gi, "promises"],
  [/\bindemnify and hold harmless\b/gi, "protect from liability"],
  [/\bexecute and deliver\b/gi, "sign and provide"],
  [/\bcovenants and agrees\b/gi, "agrees"],
  [/\bauthorise[sd]?\b/gi, "allow"],
  [/\bforthwith\b/gi, "immediately"],
  [/\bhitherto\b/gi, "until now"],
  [/\bheretofore\b/gi, "up until now"],
  [/\baforesaid\b/gi, "previously mentioned"],
];

/**
 * COMPASS Eligibility Engine — Rules Engine Tests
 *
 * Covers:
 *   - Every Operator variant
 *   - Field resolution (top-level, dot-path, custom:)
 *   - Program evaluation (fully eligible, partially eligible, ineligible)
 *   - matchScore calculation
 *   - findEligiblePrograms ordering
 *   - explainDecision output structure
 *   - Edge cases: empty rules, missing fields, zero values, large inputs
 */

import { describe, expect, it } from "vitest";
import { ProfileBuilder } from "../core-logic/profile-builder.js";
import { RulesEngine } from "../core-logic/rules-engine.js";
import { CitizenshipStatus, EmploymentStatus, Operator } from "../types.js";
import type { EligibilityRule, Program, UserProfile } from "../types.js";

// ---------------------------------------------------------------------------
// Shared test fixtures
// ---------------------------------------------------------------------------

const engine = new RulesEngine();

function buildBaseProfile(): UserProfile {
  return new ProfileBuilder()
    .setAge(35)
    .setIncome(3_000_000) // $30,000/yr in cents
    .setLocation({ countryCode: "US", regionCode: "CA" })
    .setFamilySize(3)
    .setEmploymentStatus(EmploymentStatus.unemployed)
    .setCitizenshipStatus(CitizenshipStatus.citizen)
    .addLanguage("en")
    .build();
}

function makeProgram(id: string, rules: EligibilityRule[]): Program {
  return {
    id,
    name: `Program ${id}`,
    jurisdiction: "US",
    rules,
    benefits: [
      {
        type: "monetary",
        description: "Monthly payment",
        estimatedAnnualValueCents: 12_000_00,
      },
    ],
    requiredDocuments: ["ID", "Proof of income"],
  };
}

// ---------------------------------------------------------------------------
// 1. evaluateRule — each operator
// ---------------------------------------------------------------------------

describe("RulesEngine.evaluateRule", () => {
  const profile = buildBaseProfile();

  describe("Operator.eq", () => {
    it("passes when field equals value", () => {
      const rule: EligibilityRule = {
        field: "age",
        operator: Operator.eq,
        value: 35,
      };
      expect(engine.evaluateRule(profile, rule)).toBe(true);
    });

    it("fails when field does not equal value", () => {
      const rule: EligibilityRule = {
        field: "age",
        operator: Operator.eq,
        value: 40,
      };
      expect(engine.evaluateRule(profile, rule)).toBe(false);
    });

    it("works on string fields", () => {
      const rule: EligibilityRule = {
        field: "employmentStatus",
        operator: Operator.eq,
        value: EmploymentStatus.unemployed,
      };
      expect(engine.evaluateRule(profile, rule)).toBe(true);
    });
  });

  describe("Operator.neq", () => {
    it("passes when field differs from value", () => {
      const rule: EligibilityRule = {
        field: "age",
        operator: Operator.neq,
        value: 40,
      };
      expect(engine.evaluateRule(profile, rule)).toBe(true);
    });

    it("fails when field equals value", () => {
      const rule: EligibilityRule = {
        field: "age",
        operator: Operator.neq,
        value: 35,
      };
      expect(engine.evaluateRule(profile, rule)).toBe(false);
    });
  });

  describe("Operator.gt / lt / gte / lte", () => {
    it("gt: passes when field > value", () => {
      expect(engine.evaluateRule(profile, { field: "age", operator: Operator.gt, value: 30 })).toBe(
        true,
      );
    });
    it("gt: fails when field === value", () => {
      expect(engine.evaluateRule(profile, { field: "age", operator: Operator.gt, value: 35 })).toBe(
        false,
      );
    });
    it("lt: passes when field < value", () => {
      expect(engine.evaluateRule(profile, { field: "age", operator: Operator.lt, value: 40 })).toBe(
        true,
      );
    });
    it("lt: fails when field > value", () => {
      expect(engine.evaluateRule(profile, { field: "age", operator: Operator.lt, value: 30 })).toBe(
        false,
      );
    });
    it("gte: passes when field === value (boundary)", () => {
      expect(
        engine.evaluateRule(profile, { field: "age", operator: Operator.gte, value: 35 }),
      ).toBe(true);
    });
    it("lte: passes when field === value (boundary)", () => {
      expect(
        engine.evaluateRule(profile, { field: "age", operator: Operator.lte, value: 35 }),
      ).toBe(true);
    });
    it("lte: fails when field > value", () => {
      expect(
        engine.evaluateRule(profile, { field: "age", operator: Operator.lte, value: 30 }),
      ).toBe(false);
    });
  });

  describe("Operator.in / notIn", () => {
    it("in: passes when value is in the array", () => {
      const rule: EligibilityRule = {
        field: "citizenshipStatus",
        operator: Operator.in,
        value: [CitizenshipStatus.citizen, CitizenshipStatus.permanentResident],
      };
      expect(engine.evaluateRule(profile, rule)).toBe(true);
    });

    it("in: fails when value is not in the array", () => {
      const rule: EligibilityRule = {
        field: "citizenshipStatus",
        operator: Operator.in,
        value: [CitizenshipStatus.refugee, CitizenshipStatus.temporaryVisa],
      };
      expect(engine.evaluateRule(profile, rule)).toBe(false);
    });

    it("notIn: passes when value is absent from array", () => {
      const rule: EligibilityRule = {
        field: "employmentStatus",
        operator: Operator.notIn,
        value: [EmploymentStatus.employed, EmploymentStatus.selfEmployed],
      };
      expect(engine.evaluateRule(profile, rule)).toBe(true);
    });

    it("notIn: fails when value is in the array", () => {
      const rule: EligibilityRule = {
        field: "employmentStatus",
        operator: Operator.notIn,
        value: [EmploymentStatus.unemployed],
      };
      expect(engine.evaluateRule(profile, rule)).toBe(false);
    });

    it("in: works with numeric values", () => {
      const rule: EligibilityRule = {
        field: "familySize",
        operator: Operator.in,
        value: [1, 2, 3, 4],
      };
      expect(engine.evaluateRule(profile, rule)).toBe(true);
    });
  });

  describe("Operator.contains", () => {
    it("passes when string field contains substring", () => {
      // employmentStatus = "unemployed", contains "employ"
      const rule: EligibilityRule = {
        field: "employmentStatus",
        operator: Operator.contains,
        value: "employ",
      };
      expect(engine.evaluateRule(profile, rule)).toBe(true);
    });

    it("fails when string field does not contain substring", () => {
      const rule: EligibilityRule = {
        field: "employmentStatus",
        operator: Operator.contains,
        value: "retired",
      };
      expect(engine.evaluateRule(profile, rule)).toBe(false);
    });

    it("passes when languages array contains the tag", () => {
      const rule: EligibilityRule = {
        field: "languages",
        operator: Operator.contains,
        value: "en",
      };
      expect(engine.evaluateRule(profile, rule)).toBe(true);
    });

    it("fails when languages array does not contain tag", () => {
      const rule: EligibilityRule = {
        field: "languages",
        operator: Operator.contains,
        value: "fr",
      };
      expect(engine.evaluateRule(profile, rule)).toBe(false);
    });
  });

  describe("Operator.exists", () => {
    it("passes for a field that is present", () => {
      const rule: EligibilityRule = {
        field: "age",
        operator: Operator.exists,
      };
      expect(engine.evaluateRule(profile, rule)).toBe(true);
    });

    it("passes for a custom field that exists", () => {
      const p = ProfileBuilder.from(profile).setCustomField("test.flag", true).build();
      const rule: EligibilityRule = {
        field: "custom:test.flag",
        operator: Operator.exists,
      };
      expect(engine.evaluateRule(p, rule)).toBe(true);
    });

    it("fails for a custom field that does not exist", () => {
      const rule: EligibilityRule = {
        field: "custom:nonexistent",
        operator: Operator.exists,
      };
      expect(engine.evaluateRule(profile, rule)).toBe(false);
    });

    it("fails for an unknown top-level field", () => {
      const rule: EligibilityRule = {
        field: "unknownField",
        operator: Operator.exists,
      };
      expect(engine.evaluateRule(profile, rule)).toBe(false);
    });
  });

  describe("Dot-path field resolution", () => {
    it("resolves location.countryCode correctly", () => {
      const rule: EligibilityRule = {
        field: "location.countryCode",
        operator: Operator.eq,
        value: "US",
      };
      expect(engine.evaluateRule(profile, rule)).toBe(true);
    });

    it("resolves location.regionCode correctly", () => {
      const rule: EligibilityRule = {
        field: "location.regionCode",
        operator: Operator.eq,
        value: "CA",
      };
      expect(engine.evaluateRule(profile, rule)).toBe(true);
    });

    it("fails when location.regionCode does not match", () => {
      const rule: EligibilityRule = {
        field: "location.regionCode",
        operator: Operator.eq,
        value: "TX",
      };
      expect(engine.evaluateRule(profile, rule)).toBe(false);
    });

    it("resolves location.postalCode (exists check) returns false when absent", () => {
      const rule: EligibilityRule = {
        field: "location.postalCode",
        operator: Operator.exists,
      };
      // Base profile has no postalCode
      expect(engine.evaluateRule(profile, rule)).toBe(false);
    });
  });

  describe("Custom field resolution", () => {
    it("resolves string custom field with eq", () => {
      const p = ProfileBuilder.from(profile)
        .setCustomField("us.snap.householdType", "renter")
        .build();
      const rule: EligibilityRule = {
        field: "custom:us.snap.householdType",
        operator: Operator.eq,
        value: "renter",
      };
      expect(engine.evaluateRule(p, rule)).toBe(true);
    });

    it("resolves numeric custom field with gte", () => {
      const p = ProfileBuilder.from(profile).setCustomField("us.snap.assetsCents", 500_000).build();
      const rule: EligibilityRule = {
        field: "custom:us.snap.assetsCents",
        operator: Operator.lte,
        value: 600_000,
      };
      expect(engine.evaluateRule(p, rule)).toBe(true);
    });
  });

  describe("Disability array with contains operator", () => {
    it("passes when disabilities contains the given code", () => {
      const p = ProfileBuilder.from(profile)
        .addDisability({ code: "M54.5", description: "Low back pain", certified: true })
        .build();
      const rule: EligibilityRule = {
        field: "disabilities",
        operator: Operator.contains,
        value: "M54.5",
      };
      expect(engine.evaluateRule(p, rule)).toBe(true);
    });

    it("fails when disabilities does not contain the code", () => {
      const rule: EligibilityRule = {
        field: "disabilities",
        operator: Operator.contains,
        value: "G35",
      };
      expect(engine.evaluateRule(profile, rule)).toBe(false);
    });
  });

  describe("Edge cases", () => {
    it("returns false for gt with missing field", () => {
      const rule: EligibilityRule = {
        field: "unknownNumericField",
        operator: Operator.gt,
        value: 0,
      };
      expect(engine.evaluateRule(profile, rule)).toBe(false);
    });

    it("eq with no value returns false", () => {
      const rule: EligibilityRule = {
        field: "age",
        operator: Operator.eq,
        // value intentionally omitted
      };
      expect(engine.evaluateRule(profile, rule)).toBe(false);
    });

    it("age zero passes gte 0", () => {
      const p = new ProfileBuilder()
        .setAge(0)
        .setIncome(0)
        .setLocation({ countryCode: "US" })
        .setFamilySize(1)
        .setEmploymentStatus(EmploymentStatus.notInLaborForce)
        .setCitizenshipStatus(CitizenshipStatus.citizen)
        .build();
      const rule: EligibilityRule = { field: "age", operator: Operator.gte, value: 0 };
      expect(engine.evaluateRule(p, rule)).toBe(true);
    });

    it("income zero passes lte 5000000", () => {
      const p = new ProfileBuilder()
        .setAge(25)
        .setIncome(0)
        .setLocation({ countryCode: "US" })
        .setFamilySize(1)
        .setEmploymentStatus(EmploymentStatus.unemployed)
        .setCitizenshipStatus(CitizenshipStatus.citizen)
        .build();
      const rule: EligibilityRule = {
        field: "incomeAnnualCents",
        operator: Operator.lte,
        value: 5_000_000,
      };
      expect(engine.evaluateRule(p, rule)).toBe(true);
    });
  });
});

