// ---------------------------------------------------------------------------
// Stage-to-right index entry
// ---------------------------------------------------------------------------

interface StageEntry {
  processId: string;
  stageId: string;
  rightIds: string[];
  warnings: string[];
}

// ---------------------------------------------------------------------------
// RightsDatabase
// ---------------------------------------------------------------------------

/**
 * In-process store for rights, indexed for fast lookup.
 *
 * Typical usage:
 *   const db = new RightsDatabase();
 *   db.addRight({ id: "example", ... });
 *   const stageRights = db.getRightsForStage("asylum-DE", "initial-registration");
 */
export class RightsDatabase {
  /** Primary store keyed by right.id */
  private readonly rights = new Map<string, Right>();

  /** Domain→right ids, per jurisdiction */
  private readonly domainIndex = new Map<string, Map<string, Set<string>>>();

  /** Process+stage→entry */
  private readonly stageIndex = new Map<string, StageEntry>();

  // -------------------------------------------------------------------------
  // Mutation
  // -------------------------------------------------------------------------

  /**
   * Add or replace a right in the database.
   * Calling addRight with an existing id overwrites the previous value.
   */
  addRight(right: Right): void {
    this.rights.set(right.id, right);
    this.indexByDomain(right);
  }

  /**
   * Register which rights are relevant at a particular process stage.
   * This is separate from addRight so that the same right can appear across
   * many stages without duplication.
   *
   * @param processId  Top-level process identifier, e.g. "asylum-DE"
   * @param stageId    Stage within that process, e.g. "initial-registration"
   * @param rightIds   Rights that are active at this stage
   * @param warnings   Urgent plain-language warnings for this stage
   */
  registerStageRights(
    processId: string,
    stageId: string,
    rightIds: string[],
    warnings: string[] = [],
  ): void {
    const key = this.stageKey(processId, stageId);
    this.stageIndex.set(key, { processId, stageId, rightIds, warnings });
  }

  // -------------------------------------------------------------------------
  // Query
  // -------------------------------------------------------------------------

  /**
   * Return the rights and warnings for a specific process stage.
   * Rights registered for this stage but not found in the database are
   * silently dropped (allows partial loading of rights data).
   */
  getRightsForStage(processId: string, stageId: string): ProcessStageRights {
    const key = this.stageKey(processId, stageId);
    const entry = this.stageIndex.get(key);

    if (entry === undefined) {
      return { stageId, rights: [], warnings: [] };
    }

    const rights = entry.rightIds.flatMap((id) => {
      const right = this.rights.get(id);
      return right !== undefined ? [right] : [];
    });

    return {
      stageId,
      rights,
      warnings: [...entry.warnings],
    };
  }

  /**
   * Return all rights for a given domain within a jurisdiction.
   * Supranational rights (e.g. EU, ECHR, "*") are included when the
   * queried jurisdiction falls within their scope.
   */
  getRightsByDomain(domain: RightsDomain, jurisdiction: string): Right[] {
    const results: Right[] = [];

    for (const right of this.rights.values()) {
      if (right.domain === domain && jurisdictionMatches(right.jurisdiction, jurisdiction)) {
        results.push(right);
      }
    }

    return results;
  }

  /**
   * Full-text search over right title, description, and applicableTo fields.
   * Optionally filtered to a jurisdiction.
   *
   * Results are ranked: title matches first, then description matches,
   * then applicableTo matches.
   */
  searchRights(query: string, jurisdiction?: string): Right[] {
    const normQuery = normalise(query);
    if (normQuery.length === 0) return [];

    const titleMatches: Right[] = [];
    const descriptionMatches: Right[] = [];
    const applicableToMatches: Right[] = [];
    const seenIds = new Set<string>();

    for (const right of this.rights.values()) {
      if (jurisdiction !== undefined && !jurisdictionMatches(right.jurisdiction, jurisdiction)) {
        continue;
      }

      if (seenIds.has(right.id)) continue;

      const titleNorm = normalise(right.title);
      const descNorm = normalise(right.description);
      const appToNorm = right.applicableTo.map(normalise).join(" ");

      if (titleNorm.includes(normQuery)) {
        titleMatches.push(right);
        seenIds.add(right.id);
      } else if (descNorm.includes(normQuery)) {
        descriptionMatches.push(right);
        seenIds.add(right.id);
      } else if (appToNorm.includes(normQuery)) {
        applicableToMatches.push(right);
        seenIds.add(right.id);
      }
    }

    return [...titleMatches, ...descriptionMatches, ...applicableToMatches];
  }

  /**
   * Return a right by its exact id, or undefined if not found.
   */
  getRight(id: string): Right | undefined {
    return this.rights.get(id);
  }

  /**
   * Return all rights currently in the database.
   */
  getAllRights(): Right[] {
    return Array.from(this.rights.values());
  }

  // -------------------------------------------------------------------------
  // Private helpers
  // -------------------------------------------------------------------------

  private indexByDomain(right: Right): void {
    if (!this.domainIndex.has(right.domain)) {
      this.domainIndex.set(right.domain, new Map());
    }
    const domainMap = this.domainIndex.get(right.domain)!;

    const jk = right.jurisdiction.toUpperCase();
    if (!domainMap.has(jk)) {
      domainMap.set(jk, new Set());
    }
    domainMap.get(jk)!.add(right.id);
  }

  private stageKey(processId: string, stageId: string): string {
    return `${processId}::${stageId}`;
  }
}

/**
 * In-memory StorageAdapter — for testing and development.
 *
 * Provides a simple Map-backed implementation of all storage interfaces.
 * No persistence — data lives only in process memory.
 */

import type {
  BlobAdapter,
  KVAdapter,
  QueryResult,
  Row,
  SQLAdapter,
  StorageAdapter,
} from "./types-block-sdk.js";

/** Simple in-memory KV store */
function createMemoryKV(): KVAdapter {
  const store = new Map<string, unknown>();

  return {
    async get<T = unknown>(key: string): Promise<T | null> {
      const value = store.get(key);
      return (value ?? null) as T | null;
    },
    async put<T = unknown>(key: string, value: T): Promise<void> {
      store.set(key, value);
    },
    async delete(key: string): Promise<boolean> {
      return store.delete(key);
    },
    async list(prefix?: string): Promise<Array<{ key: string; value: unknown }>> {
      const entries: Array<{ key: string; value: unknown }> = [];
      for (const [key, value] of store) {
        if (!prefix || key.startsWith(prefix)) {
          entries.push({ key, value });
        }
      }
      return entries;
    },
  };
}

/**
 * Simple in-memory SQL store backed by a Map of tables.
 *
 * Supports basic INSERT INTO, SELECT, UPDATE, DELETE statements.
 * Not a full SQL engine — covers the patterns used by defineBlock() schemas.
 */
function createMemorySQL(): SQLAdapter {
  const tables = new Map<string, Row[]>();

  function getTable(name: string): Row[] {
    if (!tables.has(name)) {
      tables.set(name, []);
    }
    return tables.get(name)!;
  }

  function executeOne<T extends Row>(query: string, params?: unknown[]): QueryResult<T> {
    const trimmed = query.trim();

    // CREATE TABLE — just ensure table exists
    const createMatch = trimmed.match(/^CREATE\s+TABLE\s+(?:IF\s+NOT\s+EXISTS\s+)?(\w+)/i);
    if (createMatch) {
      const tableName = createMatch[1]!;
      getTable(tableName);
      return { rows: [] as T[], rowsAffected: 0 };
    }

    // INSERT INTO table (cols) VALUES (?)
    const insertMatch = trimmed.match(
      /^INSERT\s+INTO\s+(\w+)\s*\(([^)]+)\)\s*VALUES\s*\(([^)]+)\)/i,
    );
    if (insertMatch) {
      const tableName = insertMatch[1]!;
      const cols = insertMatch[2]!.split(",").map((c) => c.trim());
      const table = getTable(tableName);
      const row: Row = {};
      for (let i = 0; i < cols.length; i++) {
        row[cols[i]!] = params?.[i] ?? null;
      }
      table.push(row);
      return { rows: [row] as T[], rowsAffected: 1 };
    }

    // SELECT * FROM table WHERE col = ? AND col2 = ?
    const selectMatch = trimmed.match(/^SELECT\s+\*\s+FROM\s+(\w+)(?:\s+WHERE\s+(.+))?/i);
    if (selectMatch) {
      const tableName = selectMatch[1]!;
      const table = getTable(tableName);
      if (!selectMatch[2]) {
        return { rows: [...table] as T[], rowsAffected: 0 };
      }
      const conditions = selectMatch[2].split(/\s+AND\s+/i).map((c) => c.trim());
      const filtered = table.filter((row) => {
        let paramIdx = 0;
        return conditions.every((cond) => {
          const [col] = cond.split(/\s*=\s*/);
          const value = params?.[paramIdx++];
          return row[col!.trim()] === value;
        });
      });
      return { rows: filtered as T[], rowsAffected: 0 };
    }

    // UPDATE table SET col = ? WHERE col2 = ? AND col3 = ?
    const updateMatch = trimmed.match(/^UPDATE\s+(\w+)\s+SET\s+(.+?)\s+WHERE\s+(.+)/i);
    if (updateMatch) {
      const tableName = updateMatch[1]!;
      const setClauses = updateMatch[2]!.split(",").map((s) => s.trim());
      const whereClauses = updateMatch[3]!.split(/\s+AND\s+/i).map((w) => w.trim());
      const table = getTable(tableName);

      const setColCount = setClauses.length;
      let rowsAffected = 0;

      for (const row of table) {
        let whereIdx = setColCount;
        const matches = whereClauses.every((cond) => {
          const [col] = cond.split(/\s*=\s*/);
          return row[col!.trim()] === params?.[whereIdx++];
        });
        if (matches) {
          for (let i = 0; i < setClauses.length; i++) {
            const [col] = setClauses[i]!.split(/\s*=\s*/);
            row[col!.trim()] = params?.[i] ?? null;
          }
          rowsAffected++;
        }
      }

      return { rows: [] as T[], rowsAffected };
    }

    // DELETE FROM table WHERE col = ?
    const deleteMatch = trimmed.match(/^DELETE\s+FROM\s+(\w+)(?:\s+WHERE\s+(.+))?/i);
    if (deleteMatch) {
      const tableName = deleteMatch[1]!;
      const table = getTable(tableName);
      if (!deleteMatch[2]) {
        const count = table.length;
        tables.set(tableName, []);
        return { rows: [] as T[], rowsAffected: count };
      }
      const conditions = deleteMatch[2].split(/\s+AND\s+/i).map((c) => c.trim());
      const before = table.length;
      const remaining = table.filter((row) => {
        let paramIdx = 0;
        return !conditions.every((cond) => {
          const [col] = cond.split(/\s*=\s*/);
          return row[col!.trim()] === params?.[paramIdx++];
        });
      });
      tables.set(tableName, remaining);
      return { rows: [] as T[], rowsAffected: before - remaining.length };
    }

    // DROP TABLE
    const dropMatch = trimmed.match(/^DROP\s+TABLE\s+(?:IF\s+EXISTS\s+)?(\w+)/i);
    if (dropMatch) {
      tables.delete(dropMatch[1]!);
      return { rows: [] as T[], rowsAffected: 0 };
    }

    throw new Error(`Unsupported SQL statement: ${trimmed.slice(0, 80)}`);
  }

  return {
    async execute<T extends Row>(query: string, params?: unknown[]): Promise<QueryResult<T>> {
      return executeOne<T>(query, params);
    },
    async batch(queries: Array<{ query: string; params?: unknown[] }>): Promise<QueryResult[]> {
      return queries.map((q) => executeOne(q.query, q.params));
    },
  };
}

/** Simple in-memory blob store */
function createMemoryBlobs(): BlobAdapter {
  const store = new Map<string, ArrayBuffer>();

  return {
    async put(key: string, data: ArrayBuffer | Uint8Array | ReadableStream): Promise<void> {
      if (data instanceof ArrayBuffer) {
        store.set(key, data);
      } else if (data instanceof Uint8Array) {
        store.set(
          key,
          (data.buffer as ArrayBuffer).slice(data.byteOffset, data.byteOffset + data.byteLength),
        );
      } else {
        // ReadableStream — collect chunks
        const reader = (data as ReadableStream).getReader();
        const chunks: Uint8Array[] = [];
        let done = false;
        while (!done) {
          const result = await reader.read();
          done = result.done;
          if (result.value) chunks.push(result.value as Uint8Array);
        }
        const total = chunks.reduce((n, c) => n + c.byteLength, 0);
        const buf = new Uint8Array(total);
        let offset = 0;
        for (const chunk of chunks) {
          buf.set(chunk, offset);
          offset += chunk.byteLength;
        }
        store.set(key, buf.buffer);
      }
    },
    async get(key: string): Promise<ArrayBuffer | null> {
      return store.get(key) ?? null;
    },
    async delete(key: string): Promise<boolean> {
      return store.delete(key);
    },
    async list(prefix?: string): Promise<string[]> {
      const keys: string[] = [];
      for (const key of store.keys()) {
        if (!prefix || key.startsWith(prefix)) keys.push(key);
      }
      return keys;
    },
  };
}

/** Create an in-memory StorageAdapter for testing */
export function createMemoryAdapter(): StorageAdapter {
  return {
    kv: createMemoryKV(),
    sql: createMemorySQL(),
    blobs: createMemoryBlobs(),
  };
}

/**
 * IndexedDB StorageAdapter — Browser target.
 *
 * Provides KV via IDB object stores and SQL via sql.js (in-memory SQLite).
 * IDB is the durable persistence layer; sql.js provides full SQL query support.
 * Blob storage uses IDB with large value support.
 */

import type { Database } from "sql.js";

import type {
  BlobAdapter,
  KVAdapter,
  QueryResult,
  Row,
  SQLAdapter,
  StorageAdapter,
} from "../core-logic/types-block-sdk.js";
import { getSqlJs } from "./sql-js-loader.js";

/** Options for the IndexedDB adapter */
export interface IDBAdapterOptions {
  /** Database name (defaults to "block-store") */
  dbName?: string;
  /** Database version (defaults to 1) */
  version?: number;
  /** Table names to create as object stores */
  tables?: string[];
}

function openDB(name: string, version: number, tables: string[]): Promise<IDBDatabase> {
  return new Promise((resolve, reject) => {
    const request = indexedDB.open(name, version);
    request.onupgradeneeded = () => {
      const db = request.result;
      // Create KV store
      if (!db.objectStoreNames.contains("__kv__")) {
        db.createObjectStore("__kv__");
      }
      // Create blob store
      if (!db.objectStoreNames.contains("__blobs__")) {
        db.createObjectStore("__blobs__");
      }
      // Create table stores
      for (const table of tables) {
        if (!db.objectStoreNames.contains(table)) {
          db.createObjectStore(table, { keyPath: "id" });
        }
      }
    };
    request.onsuccess = () => resolve(request.result);
    request.onerror = () => reject(request.error);
  });
}

function createIDBKV(dbPromise: Promise<IDBDatabase>): KVAdapter {
  async function tx(mode: IDBTransactionMode): Promise<IDBObjectStore> {
    const db = await dbPromise;
    return db.transaction("__kv__", mode).objectStore("__kv__");
  }

  function req<T>(request: IDBRequest<T>): Promise<T> {
    return new Promise((resolve, reject) => {
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
  }

  return {
    async get<T = unknown>(key: string): Promise<T | null> {
      const store = await tx("readonly");
      const result = await req(store.get(key));
      return (result ?? null) as T | null;
    },
    async put<T = unknown>(key: string, value: T): Promise<void> {
      const store = await tx("readwrite");
      await req(store.put(value, key));
    },
    async delete(key: string): Promise<boolean> {
      const store = await tx("readwrite");
      await req(store.delete(key));
      return true;
    },
    async list(prefix?: string): Promise<Array<{ key: string; value: unknown }>> {
      const store = await tx("readonly");
      const entries: Array<{ key: string; value: unknown }> = [];
      return new Promise((resolve, reject) => {
        const cursor = store.openCursor();
        cursor.onsuccess = () => {
          const result = cursor.result;
          if (!result) {
            resolve(entries);
            return;
          }
          const key = String(result.key);
          if (!prefix || key.startsWith(prefix)) {
            entries.push({ key, value: result.value });
          }
          result.continue();
        };
        cursor.onerror = () => reject(cursor.error);
      });
    },
  };
}

/**
 * SQL adapter using sql.js (in-memory SQLite) with IDB persistence.
 *
 * - IDB is the durable storage layer (source of truth across page loads)
 * - sql.js provides full SQL query support (ORDER BY, LIMIT, JOIN, OR, etc.)
 * - On first execute(), sql.js WASM is lazy-loaded and hydrated from IDB
 * - Writes go to both sql.js and IDB; reads query sql.js only
 */
function createIDBSQL(dbPromise: Promise<IDBDatabase>): SQLAdapter {
  let sqliteDb: Database | null = null;
  let initPromise: Promise<void> | null = null;

  function idbReq<T>(request: IDBRequest<T>): Promise<T> {
    return new Promise((resolve, reject) => {
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
  }

  async function getStore(table: string, mode: IDBTransactionMode): Promise<IDBObjectStore> {
    const db = await dbPromise;
    return db.transaction(table, mode).objectStore(table);
  }

  function getAllRows(store: IDBObjectStore): Promise<Row[]> {
    return new Promise((resolve, reject) => {
      const request = store.getAll();
      request.onsuccess = () => resolve(request.result as Row[]);
      request.onerror = () => reject(request.error);
    });
  }

  async function ensureInitialized(): Promise<Database> {
    if (sqliteDb) return sqliteDb;
    if (!initPromise) {
      initPromise = (async () => {
        const SQL = await getSqlJs();
        sqliteDb = new SQL.Database();

        // Hydrate from IDB: for each object store (table), load rows into SQLite
        const idb = await dbPromise;
        const storeNames = Array.from(idb.objectStoreNames).filter(
          (name) => name !== "__kv__" && name !== "__blobs__",
        );

        for (const storeName of storeNames) {
          const store = idb.transaction(storeName, "readonly").objectStore(storeName);
          const rows = await getAllRows(store);
          if (rows.length === 0) continue;

          // Infer schema from first row
          const cols = Object.keys(rows[0]!);
          const colDefs = cols.map((c) => `"${c}" TEXT`).join(", ");
          sqliteDb!.run(`CREATE TABLE IF NOT EXISTS "${storeName}" (${colDefs})`);

          // Insert all rows
          const placeholders = cols.map(() => "?").join(", ");
          const colNames = cols.map((c) => `"${c}"`).join(", ");
          const stmt = sqliteDb!.prepare(
            `INSERT INTO "${storeName}" (${colNames}) VALUES (${placeholders})`,
          );
          for (const row of rows) {
            stmt.run(cols.map((c) => row[c] as string | number | null));
          }
          stmt.free();
        }
      })();
    }
    await initPromise;
    return sqliteDb!;
  }

  /** Determine the operation type from a SQL statement */
  function getOperation(
    sql: string,
  ): "create" | "insert" | "select" | "update" | "delete" | "other" {
    const trimmed = sql.trim().toUpperCase();
    if (trimmed.startsWith("CREATE")) return "create";
    if (trimmed.startsWith("INSERT")) return "insert";
    if (trimmed.startsWith("SELECT")) return "select";
    if (trimmed.startsWith("UPDATE")) return "update";
    if (trimmed.startsWith("DELETE")) return "delete";
    return "other";
  }

  /** Extract table name from a SQL statement */
  function extractTableName(sql: string): string | null {
    const match = sql.match(
      /(?:INSERT\s+INTO|UPDATE|DELETE\s+FROM|CREATE\s+TABLE(?:\s+IF\s+NOT\s+EXISTS)?)\s+"?(\w+)"?/i,
    );
    return match?.[1] ?? null;
  }

  async function syncInsertToIDB(table: string, db: Database, _params: unknown[]): Promise<void> {
    // Get the last inserted row by rowid
    const result = db.exec(`SELECT * FROM "${table}" WHERE rowid = last_insert_rowid()`);
    if (result.length > 0 && result[0]!.values.length > 0) {
      const cols = result[0]!.columns;
      const vals = result[0]!.values[0]!;
      const row: Row = {};
      for (let i = 0; i < cols.length; i++) {
        row[cols[i]!] = vals[i];
      }
      // Only write to IDB if row has an id (IDB store uses keyPath: "id")
      if (row["id"] !== undefined) {
        const store = await getStore(table, "readwrite");
        await idbReq(store.put(row));
      }
    }
  }

  async function syncDeleteToIDB(table: string, sql: string, params: unknown[]): Promise<void> {
    // For simple WHERE id = ? deletes
    const whereMatch = sql.match(/WHERE\s+"?id"?\s*=\s*\?/i);
    if (whereMatch && params.length > 0) {
      const store = await getStore(table, "readwrite");
      await idbReq(store.delete(params[params.length - 1] as IDBValidKey));
      return;
    }
    // For DELETE without WHERE (clear all), clear the store
    if (!/WHERE/i.test(sql)) {
      const store = await getStore(table, "readwrite");
      await idbReq(store.clear());
    }
  }

  async function syncUpdateToIDB(
    table: string,
    db: Database,
    sql: string,
    params: unknown[],
  ): Promise<void> {
    // Re-read updated rows from SQLite and sync to IDB
    // Extract WHERE clause to find which rows were updated
    const whereMatch = sql.match(/WHERE\s+(.+)$/i);
    if (!whereMatch) return;

    // Count SET params to know where WHERE params start
    const setMatch = sql.match(/SET\s+(.+?)\s+WHERE/i);
    if (!setMatch) return;
    const setCount = setMatch[1]!.split(",").length;
    const whereParams = params.slice(setCount);

    const selectSql = `SELECT * FROM "${table}" WHERE ${whereMatch[1]}`;
    const result = db.exec(selectSql, whereParams as (string | number | null)[]);
    if (result.length > 0) {
      for (const vals of result[0]!.values) {
        const row: Row = {};
        for (let i = 0; i < result[0]!.columns.length; i++) {
          row[result[0]!.columns[i]!] = vals[i];
        }
        if (row["id"] !== undefined) {
          const store = await getStore(table, "readwrite");
          await idbReq(store.put(row));
        }
      }
    }
  }

  async function executeOne<T extends Row>(
    query: string,
    params?: unknown[],
  ): Promise<QueryResult<T>> {
    const db = await ensureInitialized();
    const op = getOperation(query);
    const sqlParams = (params ?? []) as (string | number | null)[];

    if (op === "create") {
      // Run CREATE TABLE on sql.js (IDB tables created during DB open)
      db.run(query);
      return { rows: [] as T[], rowsAffected: 0 };
    }

    if (op === "select") {
      const result = db.exec(query, sqlParams);
      if (result.length === 0) {
        return { rows: [] as T[], rowsAffected: 0 };
      }
      const cols = result[0]!.columns;
      const rows = result[0]!.values.map((vals) => {
        const row: Row = {};
        for (let i = 0; i < cols.length; i++) {
          row[cols[i]!] = vals[i];
        }
        return row as T;
      });
      return { rows, rowsAffected: 0 };
    }

    // Write operations: execute on sql.js, then sync to IDB
    db.run(query, sqlParams);
    const rowsAffected = db.getRowsModified();
    const table = extractTableName(query);

    if (table) {
      if (op === "insert") {
        await syncInsertToIDB(table, db, params ?? []);
      } else if (op === "delete") {
        await syncDeleteToIDB(table, query, params ?? []);
      } else if (op === "update") {
        await syncUpdateToIDB(table, db, query, params ?? []);
      }
    }

    return { rows: [] as T[], rowsAffected };
  }

  return {
    async execute<T extends Row>(query: string, params?: unknown[]): Promise<QueryResult<T>> {
      return executeOne<T>(query, params);
    },
    async batch(queries: Array<{ query: string; params?: unknown[] }>): Promise<QueryResult[]> {
      await ensureInitialized();
      const results: QueryResult[] = [];
      for (const q of queries) {
        results.push(await executeOne(q.query, q.params));
      }
      return results;
    },
  };
}

function createIDBBlobs(dbPromise: Promise<IDBDatabase>): BlobAdapter {
  function req<T>(request: IDBRequest<T>): Promise<T> {
    return new Promise((resolve, reject) => {
      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
  }

  return {
    async put(key: string, data: ArrayBuffer | Uint8Array | ReadableStream): Promise<void> {
      const db = await dbPromise;
      const store = db.transaction("__blobs__", "readwrite").objectStore("__blobs__");
      let buffer: ArrayBuffer;
      if (data instanceof ArrayBuffer) {
        buffer = data;
      } else if (data instanceof Uint8Array) {
        buffer = (data.buffer as ArrayBuffer).slice(
          data.byteOffset,
          data.byteOffset + data.byteLength,
        );
      } else {
        const reader = (data as ReadableStream).getReader();
        const chunks: Uint8Array[] = [];
        let done = false;
        while (!done) {
          const result = await reader.read();
          done = result.done;
          if (result.value) chunks.push(result.value as Uint8Array);
        }
        const total = chunks.reduce((n, c) => n + c.byteLength, 0);
        const buf = new Uint8Array(total);
        let offset = 0;
        for (const chunk of chunks) {
          buf.set(chunk, offset);
          offset += chunk.byteLength;
        }
        buffer = buf.buffer;
      }
      await req(store.put(buffer, key));
    },
    async get(key: string): Promise<ArrayBuffer | null> {
      const db = await dbPromise;
      const store = db.transaction("__blobs__", "readonly").objectStore("__blobs__");
      const result = await req(store.get(key));
      return (result as ArrayBuffer) ?? null;
    },
    async delete(key: string): Promise<boolean> {
      const db = await dbPromise;
      const store = db.transaction("__blobs__", "readwrite").objectStore("__blobs__");
      await req(store.delete(key));
      return true;
    },
    async list(prefix?: string): Promise<string[]> {
      const db = await dbPromise;
      const store = db.transaction("__blobs__", "readonly").objectStore("__blobs__");
      return new Promise((resolve, reject) => {
        const keys: string[] = [];
        const cursor = store.openCursor();
        cursor.onsuccess = () => {
          const result = cursor.result;
          if (!result) {
            resolve(keys);
            return;
          }
          const key = String(result.key);
          if (!prefix || key.startsWith(prefix)) keys.push(key);
          result.continue();
        };
        cursor.onerror = () => reject(cursor.error);
      });
    },
  };
}

/** Create a StorageAdapter backed by IndexedDB */
export function idbAdapter(options?: IDBAdapterOptions): StorageAdapter {
  const dbName = options?.dbName ?? "block-store";
  const version = options?.version ?? 1;
  const tables = options?.tables ?? [];

  const dbPromise = openDB(dbName, version, tables);

  return {
    kv: createIDBKV(dbPromise),
    sql: createIDBSQL(dbPromise),
    blobs: createIDBBlobs(dbPromise),
  };
}

/**
 * defineBlock() — the core abstraction for full-stack blocks.
 *
 * A block packages storage schema, business logic (procedures), UI components,
 * and MCP tool definitions into a single composable unit that can deploy to
 * CF Workers, run in the browser, or execute in Node.js.
 */

import type { BuiltTool, CallToolResult, Procedure } from "@spike-land-ai/shared/tool-builder";
import { createProcedure, middleware } from "@spike-land-ai/shared/tool-builder";
import type { SchemaDef, TableDef } from "../core-logic/types.js";
import { schemaToSQL } from "../core-logic/types.js";
import type { StorageAdapter } from "../core-logic/types-block-sdk.js";

/** Base constraint for BuiltTool that avoids handler contravariance issues */
type AnyBuiltTool = BuiltTool<never, CallToolResult>;

// ─── Block Context ─────────────────────────────────────────────────────────

/** Context available to all block procedures */
export interface BlockContext {
  [key: string]: unknown;
  /** The storage adapter (D1, IDB, or memory) */
  storage: StorageAdapter;
  /** Current user ID (injected by auth middleware) */
  userId: string;
  /** Generate a unique ID */
  nanoid: (length?: number) => string;
}

/** Context builder passed to the `procedures` factory */
export interface BlockProcedureContext {
  /** Base procedure with BlockContext injected */
  procedure: Procedure<BlockContext>;
}

// ─── Block Definition Types ────────────────────────────────────────────────

/** Component map — React components provided by the block */
export type BlockComponents = Record<string, unknown>;

/** Block definition input (what the user writes) */
export interface BlockDefinition<
  TStorage extends Record<string, TableDef>,
  TProcedures extends Record<string, AnyBuiltTool>,
  TComponents extends BlockComponents,
> {
  /** Block name (kebab-case identifier) */
  name: string;
  /** Semantic version */
  version: string;
  /** Storage schema — tables the block needs */
  storage: TStorage;
  /** Business logic — procedures with middleware chains */
  procedures: (ctx: BlockProcedureContext) => TProcedures;
  /** React components — UI layer */
  components?: TComponents;
  /** MCP tool configuration — "auto" derives from procedures, or explicit override */
  tools?: "auto" | string[];
}

/** Resolved block — the output of defineBlock() */
export interface Block<
  _TStorage extends Record<string, TableDef>,
  TProcedures extends Record<string, AnyBuiltTool>,
  TComponents extends BlockComponents,
> {
  /** Block name */
  name: string;
  /** Semantic version */
  version: string;
  /** Storage schema */
  schema: SchemaDef;
  /** SQL statements to initialize storage */
  migrations: string[];
  /** Build procedures with a specific storage adapter and user context */
  createProcedures: (storage: StorageAdapter, userId: string) => TProcedures;
  /** React components */
  components: TComponents;
  /** Tool names that should be registered as MCP tools */
  toolNames: string[];
  /** Initialize storage (run migrations) */
  initialize: (storage: StorageAdapter) => Promise<void>;
  /** Get all tools as BuiltTool[] for MCP registration */
  getTools: (storage: StorageAdapter, userId: string) => BuiltTool[];
}

// ─── Simple nanoid implementation ──────────────────────────────────────────

const ALPHABET = "0123456789abcdefghijklmnopqrstuvwxyz";

function nanoid(length = 21): string {
  const bytes = new Uint8Array(length);
  crypto.getRandomValues(bytes);
  let id = "";
  for (let i = 0; i < length; i++) {
    id += ALPHABET[bytes[i]! % ALPHABET.length];
  }
  return id;
}

// ─── defineBlock ───────────────────────────────────────────────────────────

/**
 * Define a full-stack block.
 *
 * @example
 * ```ts
 * const myBlock = defineBlock({
 *   name: "task-queue",
 *   version: "1.0.0",
 *   storage: {
 *     tasks: defineTable("tasks", {
 *       id: t.string().primaryKey(),
 *       title: t.string(),
 *       status: t.enum(["pending", "claimed", "done"]),
 *     }),
 *   },
 *   procedures: (ctx) => ({
 *     createTask: ctx.procedure
 *       .tool("create_task", "Create a new task", { title: z.string() })
 *       .handler(async ({ input, ctx }) => {
 *         // ...
 *       }),
 *   }),
 *   tools: "auto",
 * });
 * ```
 */
export function defineBlock<
  TStorage extends Record<string, TableDef>,
  TProcedures extends Record<string, AnyBuiltTool>,
  TComponents extends BlockComponents = Record<string, never>,
>(
  definition: BlockDefinition<TStorage, TProcedures, TComponents>,
): Block<TStorage, TProcedures, TComponents> {
  // Build the schema from table definitions
  const schema: SchemaDef = {};
  for (const [key, tableDef] of Object.entries(definition.storage)) {
    schema[key] = tableDef;
  }

  // Generate SQL migrations
  const migrations = schemaToSQL(schema);

  // Create the procedure factory
  function createProcedures(storage: StorageAdapter, userId: string): TProcedures {
    const blockCtx: BlockContext = { storage, userId, nanoid };

    // Create a base procedure with BlockContext injected via middleware
    const withBlockContext = middleware<Record<string, unknown>, BlockContext>(
      async ({ ctx, next }) => next({ ...ctx, ...blockCtx }),
    );
    const procedure = createProcedure().use(withBlockContext) as unknown as Procedure<BlockContext>;

    // The user's procedure factory receives the context builder
    return definition.procedures({ procedure });
  }

  // Determine which procedures are MCP tools
  const toolNames: string[] = [];
  if (definition.tools === "auto") {
    // Probe with a dummy to discover tool names
    // We create procedures with a no-op storage to introspect names
    const dummyStorage: StorageAdapter = {
      kv: {
        /* v8 ignore next */ get: async (): Promise<null> => null,
        /* v8 ignore next */ put: async (): Promise<void> => {},
        /* v8 ignore next */ delete: async (): Promise<boolean> => false,
        /* v8 ignore next */ list: async (): Promise<[]> => [],
      },
      sql: {
        /* v8 ignore next */ execute: async (): Promise<{ rows: []; rowsAffected: 0 }> => ({
          rows: [],
          rowsAffected: 0,
        }),
        /* v8 ignore next */ batch: async (): Promise<[]> => [],
      },
    };
    const procs = createProcedures(dummyStorage, "__introspect__");
    for (const [, tool] of Object.entries(procs)) {
      if (tool && typeof tool === "object" && "name" in tool && "handler" in tool) {
        toolNames.push(tool.name);
      }
    }
  } else if (Array.isArray(definition.tools)) {
    toolNames.push(...definition.tools);
  }

  return {
    name: definition.name,
    version: definition.version,
    schema,
    migrations,
    createProcedures,
    components: (definition.components ?? {}) as TComponents,
    toolNames,

    async initialize(storage: StorageAdapter): Promise<void> {
      for (const sql of migrations) {
        await storage.sql.execute(sql);
      }
    },

    getTools(storage: StorageAdapter, userId: string): BuiltTool[] {
      const procs = createProcedures(storage, userId);
      const tools: BuiltTool[] = [];
      for (const [, tool] of Object.entries(procs)) {
        if (
          tool &&
          typeof tool === "object" &&
          "name" in tool &&
          "handler" in tool &&
          toolNames.includes(tool.name)
        ) {
          tools.push(tool as BuiltTool);
        }
      }
      return tools;
    },
  };
}

"use client";

import { AnimatePresence, motion } from "framer-motion";
import { useEffect, useMemo, useRef, useState } from "react";
import { useInViewProgress } from "../ui/useInViewProgress";

// ─── Types ─────────────────────────────────────────────────────────────────

type Point = { x: number; y: number };

type BranchDef = {
  id: string;
  from: Point;
  to: Point;
  generation: number;
  survives: boolean;
  fitness: number;
  delayFraction: number;
};

type ParticleDef = {
  id: string;
  startX: number;
  startY: number;
  endX: number;
  endY: number;
  branchId: string;
};

// ─── Tree builder ─────────────────────────────────────────────────────────

function buildTree(maxGenerations: number): BranchDef[] {
  const branches: BranchDef[] = [];

  const root: Point = { x: 400, y: 500 };
  const gen0End: Point = { x: 400, y: 340 };
  branches.push({
    id: "g0-trunk",
    from: root,
    to: gen0End,
    generation: 0,
    survives: true,
    fitness: 88,
    delayFraction: 0,
  });

  if (maxGenerations < 1) return branches;

  const gen1: Array<{ to: Point; survives: boolean; fitness: number; delay: number }> = [
    { to: { x: 250, y: 200 }, survives: true, fitness: 74, delay: 0.02 },
    { to: { x: 560, y: 210 }, survives: false, fitness: 31, delay: 0.04 },
  ];
  gen1.forEach((n, i) => {
    branches.push({
      id: `g1-${i}`,
      from: gen0End,
      to: n.to,
      generation: 1,
      survives: n.survives,
      fitness: n.fitness,
      delayFraction: 0.18 + n.delay,
    });
  });

  if (maxGenerations < 2) return branches;

  const g1Survivor = gen1[0]!.to;
  const gen2: Array<{ to: Point; survives: boolean; fitness: number; delay: number }> = [
    { to: { x: 160, y: 90 }, survives: true, fitness: 91, delay: 0.01 },
    { to: { x: 340, y: 110 }, survives: false, fitness: 22, delay: 0.03 },
  ];
  gen2.forEach((n, i) => {
    branches.push({
      id: `g2-${i}`,
      from: g1Survivor,
      to: n.to,
      generation: 2,
      survives: n.survives,
      fitness: n.fitness,
      delayFraction: 0.42 + n.delay,
    });
  });

  const g1Failed = gen1[1]!.to;
  branches.push({
    id: "g2-fail-a",
    from: g1Failed,
    to: { x: 500, y: 110 },
    generation: 2,
    survives: false,
    fitness: 18,
    delayFraction: 0.44,
  });
  branches.push({
    id: "g2-fail-b",
    from: g1Failed,
    to: { x: 630, y: 120 },
    generation: 2,
    survives: false,
    fitness: 11,
    delayFraction: 0.47,
  });

  if (maxGenerations < 3) return branches;

  const g2Survivor = gen2[0]!.to;
  const gen3: Array<{ to: Point; survives: boolean; fitness: number; delay: number }> = [
    { to: { x: 90, y: 20 }, survives: true, fitness: 97, delay: 0.01 },
    { to: { x: 200, y: 15 }, survives: false, fitness: 43, delay: 0.02 },
    { to: { x: 130, y: 5 }, survives: false, fitness: 29, delay: 0.035 },
  ];
  gen3.forEach((n, i) => {
    branches.push({
      id: `g3-${i}`,
      from: g2Survivor,
      to: n.to,
      generation: 3,
      survives: n.survives,
      fitness: n.fitness,
      delayFraction: 0.65 + n.delay,
    });
  });

  return branches;
}

function buildParticles(branches: BranchDef[]): ParticleDef[] {
  const kbX = 400;
  const kbY = 530;
  const particles: ParticleDef[] = [];
  branches
    .filter((b) => !b.survives)
    .forEach((b, bi) => {
      for (let i = 0; i < 3; i++) {
        const offsetX = (i - 1) * 20 + (bi % 2 === 0 ? 5 : -5);
        particles.push({
          id: `particle-${b.id}-${i}`,
          startX: b.to.x + offsetX,
          startY: b.to.y,
          endX: kbX + (i - 1) * 30,
          endY: kbY,
          branchId: b.id,
        });
      }
    });
  return particles;
}

// ─── SVG helpers ───────────────────────────────────────────────────────────

function cubicPath(from: Point, to: Point): string {
  const midY = (from.y + to.y) / 2;
  return `M ${from.x} ${from.y} C ${from.x} ${midY}, ${to.x} ${midY}, ${to.x} ${to.y}`;
}

function approxLength(from: Point, to: Point): number {
  const dx = to.x - from.x;
  const dy = to.y - from.y;
  return Math.sqrt(dx * dx + dy * dy) * 1.2;
}

// ─── Color constants ────────────────────────────────────────────────────────

const C_SURVIVE = "#22c55e";
const C_FAIL = "#ef4444";
const C_TRUNK = "#3b82f6";
const C_PARTICLE = "#10b981";
const PRUNE_FRACTION = 0.12;

// ─── AnimatedBranch ─────────────────────────────────────────────────────────

type AnimatedBranchProps = {
  branch: BranchDef;
  globalProgress: number;
  glowFilterId: string;
  strongGlowFilterId: string;
};

function AnimatedBranch({
  branch,
  globalProgress,
  glowFilterId,
  strongGlowFilterId,
}: AnimatedBranchProps) {
  const pathD = cubicPath(branch.from, branch.to);
  const pathLen = approxLength(branch.from, branch.to);
  const branchDuration = 0.15;
  const drawProgress = Math.max(
    0,
    Math.min(1, (globalProgress - branch.delayFraction) / branchDuration),
  );
  if (drawProgress <= 0) return null;

  const pruneStart = branch.delayFraction + PRUNE_FRACTION;
  const pruneProgress = branch.survives
    ? 0
    : Math.max(0, Math.min(1, (globalProgress - pruneStart) / 0.08));
  const opacity = branch.survives ? 1 : Math.max(0.08, 1 - pruneProgress);
  const strokeColor = branch.generation === 0 ? C_TRUNK : branch.survives ? C_SURVIVE : C_FAIL;
  const strokeWidth = branch.generation === 0 ? 5 : branch.generation === 1 ? 3.5 : 2.5;
  const dashLen = pathLen * drawProgress;
  const dashArray = `${dashLen} ${pathLen}`;
  const glitchX = pruneProgress > 0.3 ? Math.sin(pruneProgress * 30) * 3 : 0;
  const glitchY = pruneProgress > 0.3 ? Math.cos(pruneProgress * 25) * 2 : 0;
  const pulseOffset = -(globalProgress * 600) % (pathLen + 50);

  return (
    <g transform={`translate(${glitchX}, ${glitchY})`} style={{ opacity }}>
      <path
        d={pathD}
        fill="none"
        stroke={strokeColor}
        strokeWidth={strokeWidth + 4}
        strokeLinecap="round"
        strokeDasharray={dashArray}
        opacity={0.2}
        filter={`url(#${glowFilterId})`}
      />
      <path
        d={pathD}
        fill="none"
        stroke={strokeColor}
        strokeWidth={strokeWidth}
        strokeLinecap="round"
        strokeDasharray={dashArray}
      />
      {branch.survives && drawProgress > 0.7 && (
        <path
          d={pathD}
          fill="none"
          stroke="white"
          strokeWidth={1.5}
          strokeLinecap="round"
          strokeDasharray={`8 ${pathLen}`}
          strokeDashoffset={pulseOffset}
          opacity={0.65}
          filter={`url(#${strongGlowFilterId})`}
        />
      )}
      {drawProgress > 0.85 && (
        <circle
          cx={branch.to.x}
          cy={branch.to.y}
          r={branch.generation === 0 ? 5 : 4}
          fill={strokeColor}
          opacity={opacity}
          filter={`url(#${glowFilterId})`}
        />
      )}
    </g>
  );
}

// ─── FitnessLabel ────────────────────────────────────────────────────────────

type FitnessLabelProps = {
  branch: BranchDef;
  globalProgress: number;
};

function FitnessLabel({ branch, globalProgress }: FitnessLabelProps) {
  if (branch.generation === 0) return null;
  const showAt = branch.delayFraction + 0.12;
  const labelProgress = Math.max(0, Math.min(1, (globalProgress - showAt) / 0.06));
  if (labelProgress <= 0) return null;

  const pruneStart = branch.delayFraction + PRUNE_FRACTION;
  const pruneProgress = branch.survives
    ? 0
    : Math.max(0, Math.min(1, (globalProgress - pruneStart) / 0.08));
  const opacity = Math.max(0, labelProgress * (1 - pruneProgress * 0.8));
  const color = branch.survives ? C_SURVIVE : C_FAIL;
  const isRight = branch.to.x > 400;
  const labelX = branch.to.x + (isRight ? 12 : -12);

  return (
    <g opacity={opacity}>
      <rect
        x={isRight ? labelX : labelX - 58}
        y={branch.to.y - 10}
        width={58}
        height={18}
        rx={3}
        fill={`${color}15`}
        stroke={`${color}40`}
        strokeWidth={0.5}
      />
      <text
        x={isRight ? labelX + 4 : labelX - 4}
        y={branch.to.y + 2}
        textAnchor={isRight ? "start" : "end"}
        fill={color}
        fontSize={9}
        fontFamily="JetBrains Mono, monospace"
        fontWeight="bold"
        letterSpacing={1}
      >
        {`FIT:${branch.fitness}`}
      </text>
    </g>
  );
}

// ─── LearningParticle ────────────────────────────────────────────────────────

type LearningParticleProps = {
  particle: ParticleDef;
  globalProgress: number;
  branchDelayFraction: number;
  strongGlowFilterId: string;
};

function LearningParticle({
  particle,
  globalProgress,
  branchDelayFraction,
  strongGlowFilterId,
}: LearningParticleProps) {
  const startAt = branchDelayFraction + PRUNE_FRACTION + 0.02;
  const particleProgress = Math.max(0, Math.min(1, (globalProgress - startAt) / 0.15));
  if (particleProgress <= 0 || particleProgress >= 1) return null;

  const eased = particleProgress * particleProgress;
  const px = particle.startX + (particle.endX - particle.startX) * particleProgress;
  const py = particle.startY + (particle.endY - particle.startY) * eased;

  return (
    <g transform={`translate(${px}, ${py})`} opacity={1 - particleProgress * 0.3}>
      <rect
        x="-4"
        y="-4"
        width="8"
        height="8"
        rx="2"
        fill={C_PARTICLE}
        filter={`url(#${strongGlowFilterId})`}
      />
      <text
        y="-8"
        fill={C_PARTICLE}
        fontSize={8}
        textAnchor="middle"
        opacity={0.85}
        fontFamily="JetBrains Mono, monospace"
      >
        {"\u0394"}
      </text>
    </g>
  );
}

