function getClientId(): string {
  const key = "spike_client_id";
  try {
    let id = localStorage.getItem(key);
    if (!id) {
      id = crypto.randomUUID();
      localStorage.setItem(key, id);
    }
    return id;
  } catch {
    // SSR or private-browsing fallback — ephemeral ID
    return crypto.randomUUID();
  }
}

