/**
 * Browser Session Manager
 *
 * Thin facade over a BrowserAdapter. Manages tabs, idle timeout, and
 * accessibility snapshots. Defaults to PlaywrightAdapter for Node.js CLI.
 */

import type { AccessibilityNode, BrowserConfig } from "./types.js";
import type { BrowserAdapter, BrowserPage } from "./adapter.js";
import { PlaywrightAdapter, setupPageListeners } from "../testing/adapter-playwright.js";
import type { TabEntry } from "../testing/adapter-playwright.js";

export type { TabEntry };

export interface BrowserTab {
  index: number;
  url: string;
  title: string;
}

const IDLE_TIMEOUT_MS = 5 * 60 * 1000; // 5 minutes

let adapter: BrowserAdapter & { setConfig?: (c: Partial<BrowserConfig>) => void } =
  new PlaywrightAdapter();
let idleTimer: ReturnType<typeof setTimeout> | null = null;

const tabs = new Map<number, TabEntry>();
let activeTabIndex = 0;
let nextTabIndex = 0;

/**
 * Replace the default adapter (for Workers/Puppeteer mode).
 */
export function setAdapter(newAdapter: BrowserAdapter): void {
  adapter = newAdapter;
}

/**
 * Override browser launch options before first call.
 */
export function setBrowserConfig(config: BrowserConfig): void {
  if (adapter.setConfig) {
    adapter.setConfig(config);
  }
}

function resetIdleTimer(): void {
  if (idleTimer) clearTimeout(idleTimer);
  idleTimer = setTimeout(() => {
    void cleanup();
  }, IDLE_TIMEOUT_MS);
}

async function ensureBrowser(): Promise<BrowserAdapter> {
  if (adapter.isConnected()) {
    resetIdleTimer();
    return adapter;
  }
  await adapter.launch();
  resetIdleTimer();
  return adapter;
}

export async function getOrCreateTab(index?: number): Promise<{
  page: BrowserPage;
  entry: TabEntry;
  index: number;
}> {
  await ensureBrowser();

  if (index !== undefined && tabs.has(index)) {
    activeTabIndex = index;
    const entry = tabs.get(index)!;
    return { page: entry.page, entry, index };
  }

  const page = await adapter.newPage();
  const tabIndex = nextTabIndex++;
  const entry: TabEntry = {
    page,
    consoleMessages: [],
    networkRequests: [],
  };
  setupPageListeners(page, entry);
  tabs.set(tabIndex, entry);
  activeTabIndex = tabIndex;
  return { page, entry, index: tabIndex };
}

export function getActiveTab(): {
  page: BrowserPage;
  entry: TabEntry;
  index: number;
} | null {
  const entry = tabs.get(activeTabIndex);
  if (!entry || entry.page.isClosed()) return null;
  resetIdleTimer();
  return { page: entry.page, entry, index: activeTabIndex };
}

export async function listTabs(): Promise<BrowserTab[]> {
  const result: BrowserTab[] = [];
  for (const [index, entry] of tabs) {
    if (entry.page.isClosed()) {
      tabs.delete(index);
      continue;
    }
    result.push({
      index,
      url: entry.page.url(),
      title: await entry.page.title(),
    });
  }
  return result;
}

export async function closeTab(index: number): Promise<boolean> {
  const entry = tabs.get(index);
  if (!entry) return false;
  if (!entry.page.isClosed()) {
    await entry.page.close();
  }
  tabs.delete(index);
  if (activeTabIndex === index) {
    const remaining = [...tabs.keys()];
    activeTabIndex = remaining.length > 0 ? remaining[0]! : 0;
  }
  return true;
}

export async function cleanup(): Promise<void> {
  if (idleTimer) {
    clearTimeout(idleTimer);
    idleTimer = null;
  }
  for (const [index, entry] of tabs) {
    if (!entry.page.isClosed()) {
      await entry.page.close();
    }
    tabs.delete(index);
  }
  await adapter.close();
  nextTabIndex = 0;
  activeTabIndex = 0;
}

/**
 * Get the accessibility tree snapshot for the active tab's page.
 */
export async function getPageSnapshot(): Promise<{
  tree: AccessibilityNode | null;
  title: string;
  url: string;
  page: BrowserPage;
} | null> {
  const tab = getActiveTab();
  if (!tab) return null;
  const { page } = tab;

  const tree = await page.getAccessibilityTree();
  const title = await page.title();
  const url = page.url();
  return { tree, title, url, page };
}

import type { ExtractedLink, LinkValidationResult, ParsedGitHubUrl } from "./types.js";

const GITHUB_URL_RE =
  /github\.com\/([^/]+)\/([^/]+?)(?:\.git)?(?:\/(blob|tree)\/([^/]+)\/(.+))?(?:[?#].*)?$/;
const RAW_GH_RE = /raw\.githubusercontent\.com\/([^/]+)\/([^/]+)\/([^/]+)\/(.+)$/;
const SHIELDS_WORKFLOW_RE =
  /img\.shields\.io\/github\/actions\/workflow\/status\/([^/]+)\/([^/]+)\/([^?]+)/;

export function parseGitHubUrl(url: string): ParsedGitHubUrl | null {
  // Try raw.githubusercontent.com first
  const rawMatch = RAW_GH_RE.exec(url);
  if (rawMatch) {
    return {
      org: rawMatch[1]!,
      repo: rawMatch[2]!,
      type: "raw",
      branch: rawMatch[3],
      path: rawMatch[4],
      url,
    };
  }

  const match = GITHUB_URL_RE.exec(url);
  if (!match) return null;

  const [, org, repo, pathType, branch, path] = match;
  if (!org || !repo) return null;

  let type: ParsedGitHubUrl["type"] = "repo";
  if (pathType === "blob") type = "file";
  else if (pathType === "tree") type = "tree";

  return { org, repo, type, branch, path, url } as ParsedGitHubUrl;
}

export function parseShieldsBadge(url: string): ParsedGitHubUrl | null {
  const match = SHIELDS_WORKFLOW_RE.exec(url);
  if (!match) return null;

  return {
    org: match[1]!,
    repo: match[2]!,
    type: "badge",
    workflow: match[3],
    url,
  };
}

export interface GitHubValidatorOptions {
  token?: string;
  timeout?: number;
}

class GitHubRateLimiter {
  private remaining = 60;
  private resetAt = 0;

  async checkAndWait(): Promise<void> {
    if (this.remaining <= 1 && Date.now() < this.resetAt) {
      const waitMs = this.resetAt - Date.now() + 100;
      if (waitMs > 0 && waitMs < 60_000) {
        await new Promise((r) => setTimeout(r, waitMs));
      }
    }
  }

  update(headers: Headers): void {
    const remaining = headers.get("X-RateLimit-Remaining");
    const reset = headers.get("X-RateLimit-Reset");
    if (remaining !== null) this.remaining = parseInt(remaining, 10);
    if (reset !== null) this.resetAt = parseInt(reset, 10) * 1000;
  }
}

const rateLimiter = new GitHubRateLimiter();

export async function validateGitHubUrl(
  link: ExtractedLink,
  parsed: ParsedGitHubUrl,
  options: GitHubValidatorOptions = {},
): Promise<LinkValidationResult> {
  const start = Date.now();
  const { token, timeout = 10_000 } = options;

  // Resolve token from options or environment
  const authToken =
    token ??
    (typeof process !== "undefined"
      ? (process.env["GITHUB_TOKEN"] ?? process.env["GH_TOKEN"])
      : undefined);

  const headers: Record<string, string> = {
    Accept: "application/vnd.github.v3+json",
    "User-Agent": "spike-land-ai-link-checker/1.0",
  };
  if (authToken) {
    headers["Authorization"] = `Bearer ${authToken}`;
  }

  await rateLimiter.checkAndWait();

  const controller = new AbortController();
  const timer = setTimeout(() => controller.abort(), timeout);

  try {
    let apiUrl: string;

    switch (parsed.type) {
      case "repo":
        apiUrl = `https://api.github.com/repos/${parsed.org}/${parsed.repo}`;
        break;
      case "file":
      case "tree": {
        const ref = parsed.branch ? `?ref=${parsed.branch}` : "";
        apiUrl = `https://api.github.com/repos/${parsed.org}/${parsed.repo}/contents/${parsed.path ?? ""}${ref}`;
        break;
      }
      case "raw": {
        // For raw URLs, just do a HEAD request directly
        const response = await fetch(parsed.url, {
          method: "HEAD",
          signal: controller.signal,
          headers: { "User-Agent": "spike-land-ai-link-checker/1.0" },
        });
        clearTimeout(timer);
        return {
          link,
          status: response.ok ? "ok" : "broken",
          httpStatus: response.status,
          reason: response.ok ? "Raw file exists" : `HTTP ${response.status}`,
          durationMs: Date.now() - start,
        };
      }
      case "badge": {
        if (parsed.workflow) {
          apiUrl = `https://api.github.com/repos/${parsed.org}/${parsed.repo}/actions/workflows/${parsed.workflow}`;
        } else {
          apiUrl = `https://api.github.com/repos/${parsed.org}/${parsed.repo}`;
        }
        break;
      }
      default:
        apiUrl = `https://api.github.com/repos/${parsed.org}/${parsed.repo}`;
    }

    const response = await fetch(apiUrl, {
      method: "GET",
      signal: controller.signal,
      headers,
    });

    clearTimeout(timer);
    rateLimiter.update(response.headers);

    if (response.ok) {
      return {
        link,
        status: "ok",
        httpStatus: response.status,
        reason: "GitHub resource exists",
        durationMs: Date.now() - start,
      };
    }

    if (response.status === 404) {
      return {
        link,
        status: "broken",
        httpStatus: 404,
        reason: `GitHub ${parsed.type} not found: ${parsed.org}/${parsed.repo}${parsed.path ? `/${parsed.path}` : ""}`,
        durationMs: Date.now() - start,
      };
    }

    if (response.status === 403) {
      return {
        link,
        status: "warning",
        httpStatus: 403,
        reason: "GitHub resource is private or rate-limited",
        durationMs: Date.now() - start,
      };
    }

    return {
      link,
      status: "error",
      httpStatus: response.status,
      reason: `GitHub API returned ${response.status}`,
      durationMs: Date.now() - start,
    };
  } catch (err: unknown) {
    clearTimeout(timer);
    const message = err instanceof Error ? err.message : String(err);
    return {
      link,
      status: "error",
      reason: `GitHub validation error: ${message}`,
      durationMs: Date.now() - start,
    };
  }
}

import type { ExtractedLink, LinkCategory } from "./types.js";

// Regex patterns
const INLINE_LINK_RE = /\[([^\]]*)\]\(([^)]+)\)/g;
const REFERENCE_LINK_RE = /^\s*\[([^\]]+)\]:\s+(.+)$/;
const HTML_HREF_RE = /<a\s+[^>]*href="([^"]+)"[^>]*>/gi;
const HTML_SRC_RE = /<img\s+[^>]*src="([^"]+)"[^>]*>/gi;
const HEADING_RE = /^(#{1,6})\s+(.+)$/;

const SKIP_PROTOCOLS = new Set(["mailto:", "tel:", "data:", "javascript:", "ftp:"]);
const SKIP_DOMAINS = new Set(["example.com", "localhost", "127.0.0.1", "0.0.0.0"]);

export function extractLinks(source: string, _filePath: string): ExtractedLink[] {
  const links: ExtractedLink[] = [];
  const lines = source.split("\n");
  let inCodeBlock = false;
  let inComment = false;

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i]!;
    const lineNum = i + 1;

    // Track code block state
    if (line.trimStart().startsWith("```")) {
      inCodeBlock = !inCodeBlock;
      continue;
    }

    // Track HTML comment state (simplified - handles single-line and multi-line)
    if (!inCodeBlock) {
      if (line.includes("<!--") && !line.includes("-->")) {
        inComment = true;
        continue;
      }
      if (inComment && line.includes("-->")) {
        inComment = false;
        continue;
      }
      // Single-line comment: skip whole line if it's entirely a comment
      if (line.includes("<!--") && line.includes("-->")) {
        if (line.trim().startsWith("<!--") && line.trim().endsWith("-->")) {
          continue;
        }
      }
    }

    if (inCodeBlock) continue;

    // Inline links: [text](target)
    let match: RegExpExecArray | null;
    INLINE_LINK_RE.lastIndex = 0;
    while ((match = INLINE_LINK_RE.exec(line)) !== null) {
      const text = match[1]!;
      const target = match[2]!.trim();
      links.push({
        target,
        text,
        line: lineNum,
        column: match.index + 1,
        category: categorizeLink(target),
        inCodeBlock: false,
        inComment,
      });
    }

    // Reference-style links: [label]: url
    const refMatch = REFERENCE_LINK_RE.exec(line);
    if (refMatch) {
      const text = refMatch[1]!;
      const target = refMatch[2]!.trim();
      links.push({
        target,
        text,
        line: lineNum,
        column: 1,
        category: categorizeLink(target),
        inCodeBlock: false,
        inComment,
      });
    }

    // HTML <a href="..."> tags
    HTML_HREF_RE.lastIndex = 0;
    while ((match = HTML_HREF_RE.exec(line)) !== null) {
      const target = match[1]!;
      links.push({
        target,
        text: "",
        line: lineNum,
        column: match.index + 1,
        category: categorizeLink(target),
        inCodeBlock: false,
        inComment,
      });
    }

    // HTML <img src="..."> tags
    HTML_SRC_RE.lastIndex = 0;
    while ((match = HTML_SRC_RE.exec(line)) !== null) {
      const target = match[1]!;
      links.push({
        target,
        text: "",
        line: lineNum,
        column: match.index + 1,
        category: categorizeLink(target),
        inCodeBlock: false,
        inComment,
      });
    }
  }

  return links;
}

export function categorizeLink(target: string): LinkCategory {
  // Skip protocols
  for (const proto of SKIP_PROTOCOLS) {
    if (target.startsWith(proto)) return "skipped";
  }

  // Skip known non-real domains
  try {
    const url = new URL(target);
    if (SKIP_DOMAINS.has(url.hostname)) return "skipped";
  } catch {
    // Not a valid URL, could be a relative path
  }

  // GitHub URLs
  if (target.includes("github.com/")) {
    if (target.includes("/blob/")) return "github_file";
    if (target.includes("/tree/")) return "github_tree";
    // Just org/repo pattern
    const ghMatch = target.match(/github\.com\/([^/]+)\/([^/]+)/);
    if (ghMatch) return "github_repo";
  }

  if (target.includes("raw.githubusercontent.com/")) return "github_raw";

  if (target.includes("img.shields.io/github/")) return "github_badge";

  // Anchor-only
  if (target.startsWith("#")) return "anchor";

  // External URLs
  if (target.startsWith("http://") || target.startsWith("https://")) return "external_url";

  // Relative file with anchor
  if (target.includes("#") && !target.startsWith("#")) return "file_with_anchor";

  // Relative file
  return "relative_file";
}

export function slugifyHeading(heading: string): string {
  return heading
    .toLowerCase()
    .replace(/<[^>]+>/g, "") // strip HTML
    .replace(/[^\w\s-]/g, "") // strip special chars except hyphens
    .replace(/\s+/g, "-") // spaces to hyphens
    .replace(/-+/g, "-") // collapse multiple hyphens
    .replace(/^-|-$/g, ""); // trim leading/trailing hyphens
}

export function extractHeadings(source: string): string[] {
  const headings: string[] = [];
  const lines = source.split("\n");
  let inCodeBlock = false;

  for (const line of lines) {
    if (line.trimStart().startsWith("```")) {
      inCodeBlock = !inCodeBlock;
      continue;
    }
    if (inCodeBlock) continue;

    const match = HEADING_RE.exec(line);
    if (match) {
      headings.push(slugifyHeading(match[2]!));
    }
  }

  return headings;
}

/**
 * Narration Engine
 *
 * Converts Playwright's accessibility tree into screen-reader-style text.
 * Interactive elements and headings get ref numbers for agent interaction.
 */

import type { AccessibilityNode, NarratedElement, NarrationResult } from "./types.js";

/** Roles that get a ref number (interactive + headings) */
const INTERACTIVE_ROLES = new Set([
  "link",
  "button",
  "textbox",
  "checkbox",
  "radio",
  "combobox",
  "slider",
  "spinbutton",
  "switch",
  "tab",
  "menuitem",
  "menuitemcheckbox",
  "menuitemradio",
  "option",
  "treeitem",
  "heading",
  "searchbox",
]);

/** Roles that are structural landmarks (no ref) */
const LANDMARK_ROLES = new Set([
  "banner",
  "navigation",
  "main",
  "complementary",
  "contentinfo",
  "form",
  "region",
  "search",
]);

/** Roles to skip entirely (decorative / structural noise) */
const SKIP_ROLES = new Set(["none", "presentation", "generic"]);

interface NarrationState {
  nextRef: number;
  elements: NarratedElement[];
  refMap: Map<number, AccessibilityNode>;
}

function getStates(node: AccessibilityNode): string[] {
  const states: string[] = [];
  if (node.checked === true) states.push("checked");
  if (node.checked === "mixed") states.push("mixed");
  if (node.disabled) states.push("disabled");
  if (node.expanded === true) states.push("expanded");
  if (node.expanded === false) states.push("collapsed");
  if (node.selected) states.push("selected");
  if (node.pressed === true) states.push("pressed");
  if (node.pressed === "mixed") states.push("mixed pressed");
  return states;
}

function formatElement(node: AccessibilityNode, ref: number | undefined, depth: number): string {
  const indent = "  ".repeat(depth);
  const parts: string[] = [];

  // Role with optional level (for headings)
  let roleStr = node.role;
  if (node.level !== undefined) {
    roleStr += ` level ${node.level}`;
  }

  // Ref
  if (ref !== undefined) {
    roleStr += ` ref=${ref}`;
  }

  parts.push(`${indent}[${roleStr}]`);

  // Name
  if (node.name) {
    parts.push(`"${node.name}"`);
  }

  // States
  const states = getStates(node);
  if (states.length > 0) {
    parts.push(`(${states.join(", ")})`);
  }

  // Value
  if (node.value !== undefined && node.value !== "") {
    parts.push(`- value: "${node.value}"`);
  }

  return parts.join(" ");
}

function shouldAssignRef(role: string): boolean {
  return INTERACTIVE_ROLES.has(role);
}

function isLandmark(role: string): boolean {
  return LANDMARK_ROLES.has(role);
}

function shouldSkip(node: AccessibilityNode): boolean {
  return SKIP_ROLES.has(node.role);
}

function narrateNode(
  node: AccessibilityNode,
  state: NarrationState,
  depth: number,
  lines: string[],
): void {
  if (shouldSkip(node)) {
    // Still process children — skip the wrapper
    for (const child of node.children ?? []) {
      narrateNode(child, state, depth, lines);
    }
    return;
  }

  if (isLandmark(node.role)) {
    const label = node.name ? `${node.role} landmark "${node.name}"` : `${node.role} landmark`;
    lines.push(`${"  ".repeat(depth)}[${label}]`);
    for (const child of node.children ?? []) {
      narrateNode(child, state, depth + 1, lines);
    }
    return;
  }

  if (shouldAssignRef(node.role)) {
    const ref = state.nextRef++;
    state.refMap.set(ref, node);
    state.elements.push({
      ref,
      role: node.role,
      ...(node.name !== undefined ? { name: node.name } : {}),
      ...(node.value !== undefined ? { value: node.value } : {}),
      states: getStates(node),
      ...(node.level !== undefined ? { level: node.level } : {}),
      depth,
    });
    lines.push(formatElement(node, ref, depth));
    // Don't recurse into children for interactive elements — their text is in name
    return;
  }

  // Static text or group
  if (node.role === "text" || node.role === "StaticText") {
    if (node.name) {
      lines.push(`${"  ".repeat(depth)}[text] "${node.name}"`);
      state.elements.push({
        role: "text",
        name: node.name,
        states: [],
        depth,
      });
    }
    return;
  }

  // For other roles (list, listitem, group, etc.) — show if named, then recurse
  if (node.name && node.role !== "WebArea" && node.role !== "RootWebArea") {
    lines.push(`${"  ".repeat(depth)}[${node.role}] "${node.name}"`);
  }

  for (const child of node.children ?? []) {
    narrateNode(child, state, depth, lines);
  }
}

/**
 * Convert an accessibility tree into narrated text.
 */
export function narrate(tree: AccessibilityNode, title: string, url: string): NarrationResult {
  const state: NarrationState = {
    nextRef: 1,
    elements: [],
    refMap: new Map(),
  };

  const lines: string[] = [];
  lines.push(`[Page: "${title}" - ${url}]`);

  for (const child of tree.children ?? []) {
    narrateNode(child, state, 0, lines);
  }

  return {
    title,
    url,
    text: lines.join("\n"),
    elements: state.elements,
    refCount: state.nextRef - 1,
  };
}

/**
 * Narrate only elements within a specific landmark.
 */
export function narrateSection(
  tree: AccessibilityNode,
  landmarkName: string,
  title: string,
  url: string,
): NarrationResult {
  const landmark = findLandmark(tree, landmarkName);
  if (!landmark) {
    return {
      title,
      url,
      text: `[Page: "${title}" - ${url}]\n[No "${landmarkName}" landmark found]`,
      elements: [],
      refCount: 0,
    };
  }

  const state: NarrationState = {
    nextRef: 1,
    elements: [],
    refMap: new Map(),
  };

  const lines: string[] = [];
  lines.push(`[Page: "${title}" - ${url}]`);

  const label = landmark.name
    ? `${landmark.role} landmark "${landmark.name}"`
    : `${landmark.role} landmark`;
  lines.push(`[${label}]`);

  for (const child of landmark.children ?? []) {
    narrateNode(child, state, 1, lines);
  }

  return {
    title,
    url,
    text: lines.join("\n"),
    elements: state.elements,
    refCount: state.nextRef - 1,
  };
}

function findLandmark(node: AccessibilityNode, name: string): AccessibilityNode | null {
  const normalizedName = name.toLowerCase();
  if (LANDMARK_ROLES.has(node.role) && node.role.toLowerCase() === normalizedName) {
    return node;
  }
  for (const child of node.children ?? []) {
    const found = findLandmark(child, name);
    if (found) return found;
  }
  return null;
}

// ─── Compact Narration ───────────────────────────────────────────────────────

const LANDMARK_SHORT: Record<string, string> = {
  banner: "banner",
  navigation: "nav",
  main: "main",
  complementary: "aside",
  contentinfo: "footer",
  form: "form",
  region: "region",
  search: "search",
};

const HEADING_SHORT: Record<number, string> = {
  1: "h1",
  2: "h2",
  3: "h3",
  4: "h4",
  5: "h5",
  6: "h6",
};

function truncate(s: string, max: number): string {
  return s.length > max ? s.slice(0, max - 1) + "\u2026" : s;
}

function shortUrl(url: string): string {
  return url.replace(/^https?:\/\//, "");
}

function compactStates(node: AccessibilityNode): string {
  const parts: string[] = [];
  if (node.checked === true) parts.push("checked");
  if (node.checked === "mixed") parts.push("mixed");
  if (node.disabled) parts.push("disabled");
  if (node.expanded === true) parts.push("expanded");
  if (node.expanded === false) parts.push("collapsed");
  if (node.selected) parts.push("selected");
  if (node.pressed === true) parts.push("pressed");
  if (node.pressed === "mixed") parts.push("mixed-pressed");
  return parts.length > 0 ? ` (${parts.join(",")})` : "";
}

function compactInteractive(node: AccessibilityNode, ref: number): string {
  const name = node.name ? ` ${truncate(node.name, 40)}` : "";
  const val = node.value !== undefined && node.value !== "" ? `="${truncate(node.value, 30)}"` : "";
  const states = compactStates(node);
  return `${name}${val}${states} ref=${ref}`;
}

function narrateCompactNode(
  node: AccessibilityNode,
  state: NarrationState,
  depth: number,
  lines: string[],
  siblings: AccessibilityNode[],
  siblingIndex: number,
): void {
  if (shouldSkip(node)) {
    for (const child of node.children ?? []) {
      narrateCompactNode(
        child,
        state,
        depth,
        lines,
        node.children ?? [],
        (node.children ?? []).indexOf(child),
      );
    }
    return;
  }

  const indent = "  ".repeat(depth);

  if (isLandmark(node.role)) {
    const short = LANDMARK_SHORT[node.role] ?? node.role;
    const label = node.name ? `${short} "${truncate(node.name, 30)}"` : short;
    lines.push(`${indent}[${label}]`);
    const children = node.children ?? [];
    for (let i = 0; i < children.length; i++) {
      narrateCompactNode(children[i]!, state, depth + 1, lines, children, i);
    }
    return;
  }

  if (shouldAssignRef(node.role)) {
    const ref = state.nextRef++;
    state.refMap.set(ref, node);
    state.elements.push({
      ref,
      role: node.role,
      ...(node.name !== undefined ? { name: node.name } : {}),
      ...(node.value !== undefined ? { value: node.value } : {}),
      states: getStates(node),
      ...(node.level !== undefined ? { level: node.level } : {}),
      depth,
    });

    // Collapse consecutive interactive siblings on the same line
    const isGroupable =
      node.role !== "heading" &&
      node.role !== "textbox" &&
      node.role !== "searchbox" &&
      node.role !== "combobox" &&
      node.role !== "slider" &&
      node.role !== "spinbutton";

    if (isGroupable && siblingIndex > 0) {
      const prev = siblings[siblingIndex - 1];
      if (
        prev &&
        shouldAssignRef(prev.role) &&
        prev.role !== "heading" &&
        prev.role !== "textbox" &&
        prev.role !== "searchbox"
      ) {
        // Append to previous line with pipe separator
        const lastLine = lines[lines.length - 1];
        if (lastLine && !lastLine.endsWith("]")) {
          lines[lines.length - 1] = `${lastLine} | ${node.role}${compactInteractive(node, ref)}`;
          return;
        }
      }
    }

    const role =
      node.role === "heading"
        ? `[${HEADING_SHORT[node.level ?? 1] ?? `h${node.level}`}]`
        : `[${node.role}]`;
    lines.push(`${indent}${role}${compactInteractive(node, ref)}`);
    return;
  }

  // Static text
  if (node.role === "text" || node.role === "StaticText") {
    if (node.name) {
      lines.push(`${indent}[text] ${truncate(node.name, 80)}`);
    }
    return;
  }

  // Other roles — recurse
  if (node.name && node.role !== "WebArea" && node.role !== "RootWebArea") {
    lines.push(`${indent}[${node.role}] ${truncate(node.name, 60)}`);
  }

  const children = node.children ?? [];
  for (let i = 0; i < children.length; i++) {
    narrateCompactNode(children[i]!, state, depth, lines, children, i);
  }
}

/**
 * Compact narration for token-efficient AI consumption.
 * ~40-60% smaller than full narration.
 */
export function narrateCompact(
  tree: AccessibilityNode,
  title: string,
  url: string,
): NarrationResult {
  const state: NarrationState = {
    nextRef: 1,
    elements: [],
    refMap: new Map(),
  };

  const lines: string[] = [];
  lines.push(`[Page "${title}" ${shortUrl(url)}]`);

  const children = tree.children ?? [];
  for (let i = 0; i < children.length; i++) {
    narrateCompactNode(children[i]!, state, 0, lines, children, i);
  }

  return {
    title,
    url,
    text: lines.join("\n"),
    elements: state.elements,
    refCount: state.nextRef - 1,
  };
}

/**
 * Compact narration of a single landmark section.
 */
export function narrateCompactSection(
  tree: AccessibilityNode,
  landmarkName: string,
  title: string,
  url: string,
): NarrationResult {
  const landmark = findLandmark(tree, landmarkName);
  if (!landmark) {
    return {
      title,
      url,
      text: `[Page "${title}" ${shortUrl(url)}]\n[No "${landmarkName}" found]`,
      elements: [],
      refCount: 0,
    };
  }

  const state: NarrationState = {
    nextRef: 1,
    elements: [],
    refMap: new Map(),
  };

  const lines: string[] = [];
  lines.push(`[Page "${title}" ${shortUrl(url)}]`);

  const short = LANDMARK_SHORT[landmark.role] ?? landmark.role;
  const label = landmark.name ? `${short} "${truncate(landmark.name, 30)}"` : short;
  lines.push(`[${label}]`);

  const children = landmark.children ?? [];
  for (let i = 0; i < children.length; i++) {
    narrateCompactNode(children[i]!, state, 1, lines, children, i);
  }

  return {
    title,
    url,
    text: lines.join("\n"),
    elements: state.elements,
    refCount: state.nextRef - 1,
  };
}

/**
 * Find an accessibility node by its ref number.
 * Rebuilds the ref map by re-walking the tree.
 */
export function findElementByRef(tree: AccessibilityNode, ref: number): AccessibilityNode | null {
  const state: NarrationState = {
    nextRef: 1,
    elements: [],
    refMap: new Map(),
  };
  const lines: string[] = [];
  for (const child of tree.children ?? []) {
    narrateNode(child, state, 0, lines);
  }
  return state.refMap.get(ref) ?? null;
}

/**
 * Puppeteer Browser Adapter (Cloudflare Workers Browser Rendering API)
 *
 * Implements BrowserAdapter using @cloudflare/puppeteer for CF Workers deployment.
 */

import type { AccessibilityNode } from "../core-logic/types.js";
import type { BrowserAdapter, BrowserPage, CdpAxNode } from "../core-logic/adapter.js";
import { rebuildTree } from "../core-logic/adapter.js";

// ─── Puppeteer type aliases (runtime import from @cloudflare/puppeteer) ──────

type PuppeteerBrowser = {
  newPage(): Promise<PuppeteerPage>;
  close(): Promise<void>;
  isConnected(): boolean;
};

type PuppeteerPage = {
  goto(url: string, opts?: { waitUntil?: string | string[] }): Promise<unknown>;
  title(): Promise<string>;
  url(): string;
  screenshot(opts?: {
    fullPage?: boolean;
    encoding?: "base64" | "binary";
    type?: "png" | "jpeg" | "webp";
  }): Promise<string | Buffer>;
  evaluate<T>(fn: string | ((...args: unknown[]) => T), ...args: unknown[]): Promise<T>;
  setViewport(vp: { width: number; height: number }): Promise<void>;
  close(): Promise<void>;
  isClosed(): boolean;
  keyboard: { press(key: string): Promise<void>; type(text: string): Promise<void> };
  mouse: { wheel(opts: { deltaX: number; deltaY: number }): Promise<void> };
  viewport(): { width: number; height: number } | null;
  $(selector: string): Promise<PuppeteerElementHandle | null>;
  $$(selector: string): Promise<PuppeteerElementHandle[]>;
  createCDPSession(): Promise<{
    send(method: string, params?: Record<string, unknown>): Promise<{ nodes?: CdpAxNode[] }>;
  }>;
};

type PuppeteerElementHandle = {
  click(): Promise<void>;
  type(text: string): Promise<void>;
  evaluate<T>(fn: (el: unknown) => T): Promise<T>;
  select(...values: string[]): Promise<string[]>;
};

// ─── PuppeteerPage wraps raw page to implement BrowserPage ───────────────────

class PuppeteerPageWrapper implements BrowserPage {
  private _page: PuppeteerPage;
  keyboard: BrowserPage["keyboard"];
  mouse: BrowserPage["mouse"];

  constructor(page: PuppeteerPage) {
    this._page = page;
    this.keyboard = page.keyboard;
    // Puppeteer mouse.wheel takes an object, normalize to (deltaX, deltaY)
    this.mouse = {
      wheel: (deltaX: number, deltaY: number) => page.mouse.wheel({ deltaX, deltaY }),
    };
  }

  goto(url: string, opts?: { waitUntil?: string }) {
    return this._page.goto(url, opts);
  }
  title() {
    return this._page.title();
  }
  url() {
    return this._page.url();
  }
  screenshot(opts?: { fullPage?: boolean; encoding?: "base64" | "binary"; type?: "png" | "jpeg" }) {
    return this._page.screenshot(opts);
  }
  evaluate(fn: string | ((...args: unknown[]) => unknown)) {
    return this._page.evaluate(fn as string | (() => unknown));
  }
  async setViewportSize(size: { width: number; height: number }) {
    await this._page.setViewport(size);
  }
  close() {
    return this._page.close();
  }
  isClosed() {
    return this._page.isClosed();
  }
  viewportSize() {
    return this._page.viewport();
  }

  getByRole(role: string, opts?: { name?: string | RegExp }) {
    const page = this._page;
    // Puppeteer uses ARIA selectors: aria/Name[role="role"]
    const ariaSelector = buildAriaSelector(role, opts?.name);

    return {
      async click() {
        const el = await page.$(ariaSelector);
        if (!el) throw new Error(`No element found for role="${role}" name="${opts?.name}"`);
        await el.click();
      },
      async fill(text: string) {
        const el = await page.$(ariaSelector);
        if (!el) throw new Error(`No element found for role="${role}" name="${opts?.name}"`);
        // Clear existing value then type
        await el.evaluate((input: unknown) => {
          const inp = input as HTMLInputElement;
          inp.value = "";
          inp.dispatchEvent(new Event("input", { bubbles: true }));
        });
        await el.type(text);
      },
      async clear() {
        const el = await page.$(ariaSelector);
        if (!el) throw new Error(`No element found for role="${role}" name="${opts?.name}"`);
        await el.evaluate((input: unknown) => {
          const inp = input as HTMLInputElement;
          inp.value = "";
          inp.dispatchEvent(new Event("input", { bubbles: true }));
        });
      },
      async selectOption(value: string): Promise<string[]> {
        const el = await page.$(ariaSelector);
        if (!el) throw new Error(`No element found for role="${role}" name="${opts?.name}"`);
        return el.select(value);
      },
    };
  }

  async getAccessibilityTree(): Promise<AccessibilityNode | null> {
    try {
      const client = await this._page.createCDPSession();
      const result = await client.send("Accessibility.getFullAXTree");
      if (result?.nodes) {
        return rebuildTree(result.nodes);
      }
    } catch (err) {
      throw new Error(
        `Failed to get accessibility tree via CDP: ${err instanceof Error ? err.message : String(err)}`,
      );
    }
    return null;
  }
}

function buildAriaSelector(role: string, name?: string | RegExp): string {
  if (name) {
    const nameStr = name instanceof RegExp ? name.source : name;
    return `aria/${nameStr}[role="${role}"]`;
  }
  return `[role="${role}"]`;
}

// ─── PuppeteerAdapter implements BrowserAdapter ──────────────────────────────

export class PuppeteerAdapter implements BrowserAdapter {
  private _browserBinding: Fetcher;
  private _browser: PuppeteerBrowser | null = null;

  constructor(browserBinding: Fetcher) {
    this._browserBinding = browserBinding;
  }

  async launch(): Promise<void> {
    if (this._browser?.isConnected()) return;
    const puppeteer = await import("@cloudflare/puppeteer" as string);
    this._browser = (await (puppeteer.default ?? puppeteer).launch(
      this._browserBinding,
    )) as unknown as PuppeteerBrowser;
  }

  async newPage(): Promise<BrowserPage> {
    if (!this._browser) await this.launch();
    const rawPage = await this._browser!.newPage();
    return new PuppeteerPageWrapper(rawPage);
  }

  isConnected(): boolean {
    return this._browser?.isConnected() ?? false;
  }

  async close(): Promise<void> {
    if (this._browser) {
      await this._browser.close();
      this._browser = null;
    }
  }
}

/**
 * Browser Session Durable Object
 *
 * Manages a browser session per client on Cloudflare Workers.
 * Uses the Browser Rendering API via PuppeteerAdapter.
 * 90-second alarm for auto-cleanup (under CF's 2-min limit).
 */

import { DurableObject } from "cloudflare:workers";
import type { Env } from "../core-logic/env.js";
import type { BrowserPage } from "../core-logic/adapter.js";
import { PuppeteerAdapter } from "./adapter-puppeteer.js";
import {
  narrate,
  narrateCompact,
  narrateCompactSection,
  narrateSection,
  findElementByRef,
} from "../core-logic/narrate.js";
import type { AccessibilityNode } from "../core-logic/types.js";

interface TabState {
  page: BrowserPage;
  index: number;
}

export class BrowserSessionDO extends DurableObject<Env> {
  private adapter: PuppeteerAdapter | null = null;
  private tabs = new Map<number, TabState>();
  private activeTabIndex = 0;
  private nextTabIndex = 0;

  private getAdapter(): PuppeteerAdapter {
    if (!this.adapter) {
      this.adapter = new PuppeteerAdapter(this.env.BROWSER);
    }
    return this.adapter;
  }

  private async resetAlarm(): Promise<void> {
    await this.ctx.storage.setAlarm(Date.now() + 90_000);
  }

  override async alarm(): Promise<void> {
    await this.snapshotAndClose();
  }

  private async snapshotAndClose(): Promise<void> {
    for (const [, t] of this.tabs) {
      if (!t.page.isClosed()) await t.page.close();
    }
    this.tabs.clear();

    if (this.adapter) {
      await this.adapter.close();
      this.adapter = null;
    }
    this.nextTabIndex = 0;
    this.activeTabIndex = 0;
  }

  private async ensureTab(index?: number): Promise<TabState> {
    const adapter = this.getAdapter();

    if (index !== undefined && this.tabs.has(index)) {
      this.activeTabIndex = index;
      return this.tabs.get(index)!;
    }

    await adapter.launch();
    const page = await adapter.newPage();
    const tabIndex = this.nextTabIndex++;
    const tab: TabState = { page, index: tabIndex };
    this.tabs.set(tabIndex, tab);
    this.activeTabIndex = tabIndex;
    await this.resetAlarm();
    return tab;
  }

  private getActiveTab(): TabState | null {
    const tab = this.tabs.get(this.activeTabIndex);
    if (!tab || tab.page.isClosed()) return null;
    return tab;
  }

  private async getSnapshot(): Promise<{
    tree: AccessibilityNode | null;
    title: string;
    url: string;
    page: BrowserPage;
  } | null> {
    const tab = this.getActiveTab();
    if (!tab) return null;
    const tree = await tab.page.getAccessibilityTree();
    const title = await tab.page.title();
    const url = tab.page.url();
    return { tree, title, url, page: tab.page };
  }

  // ─── RPC Methods (called from worker-entry via DO stub) ──────────────────

  async navigate(url: string, waitUntil: string = "load", tabIndex?: number): Promise<string> {
    const tab = await this.ensureTab(tabIndex);
    await tab.page.goto(url, { waitUntil });
    return this.readPage("compact");
  }

  async readPage(
    detail: "compact" | "full" | "landmark" = "compact",
    landmark?: string,
  ): Promise<string> {
    await this.resetAlarm();
    const snapshot = await this.getSnapshot();
    if (!snapshot) return "No active browser tab. Use web_navigate first.";
    if (!snapshot.tree) return `[Page: "${snapshot.title}" - ${snapshot.url}]\n[Empty page]`;

    if (landmark) {
      const fn = detail === "full" ? narrateSection : narrateCompactSection;
      return fn(snapshot.tree, landmark, snapshot.title, snapshot.url).text;
    }
    const fn = detail === "full" ? narrate : narrateCompact;
    return fn(snapshot.tree, snapshot.title, snapshot.url).text;
  }

  async click(ref?: number, role?: string, name?: string): Promise<string> {
    await this.resetAlarm();
    const snapshot = await this.getSnapshot();
    if (!snapshot?.tree) return "No active browser tab.";

    if (ref !== undefined) {
      const node = findElementByRef(snapshot.tree, ref);
      if (!node) return `No element with ref=${ref}.`;
      const locator = snapshot.page.getByRole(
        node.role,
        node.name !== undefined ? { name: node.name } : undefined,
      );
      await locator.click();
    } else if (role) {
      const opts = name ? { name } : undefined;
      await snapshot.page.getByRole(role, opts).click();
    } else {
      return "Provide ref or role.";
    }
    return this.readPage("compact");
  }

  async type(text: string, ref?: number, name?: string, clear: boolean = true): Promise<string> {
    await this.resetAlarm();
    const snapshot = await this.getSnapshot();
    if (!snapshot?.tree) return "No active browser tab.";

    let role = "textbox";
    let targetName = name;
    if (ref !== undefined) {
      const node = findElementByRef(snapshot.tree, ref);
      if (!node) return `No element with ref=${ref}.`;
      role = node.role;
      targetName = node.name;
    }

    const locator = snapshot.page.getByRole(role, targetName ? { name: targetName } : undefined);
    if (clear) await locator.clear();
    await locator.fill(text);
    return this.readPage("compact");
  }

  async select(option: string, ref?: number, name?: string): Promise<string> {
    await this.resetAlarm();
    const snapshot = await this.getSnapshot();
    if (!snapshot?.tree) return "No active browser tab.";

    let role = "combobox";
    let targetName = name;
    if (ref !== undefined) {
      const node = findElementByRef(snapshot.tree, ref);
      if (!node) return `No element with ref=${ref}.`;
      role = node.role;
      targetName = node.name;
    }

    await snapshot.page
      .getByRole(role, targetName ? { name: targetName } : undefined)
      .selectOption(option);
    return this.readPage("compact");
  }

  async press(key: string): Promise<string> {
    await this.resetAlarm();
    const tab = this.getActiveTab();
    if (!tab) return "No active browser tab.";
    await tab.page.keyboard.press(key);
    return this.readPage("compact");
  }

  async scroll(direction: "up" | "down" = "down", amount: number = 1): Promise<string> {
    await this.resetAlarm();
    const tab = this.getActiveTab();
    if (!tab) return "No active browser tab.";
    const vp = tab.page.viewportSize();
    const height = vp?.height ?? 720;
    const delta = height * amount * (direction === "up" ? -1 : 1);
    await tab.page.mouse.wheel(0, delta);
    return this.readPage("compact");
  }

  async screenshot(fullPage: boolean = false): Promise<string> {
    await this.resetAlarm();
    const tab = this.getActiveTab();
    if (!tab) return "";
    return String(await tab.page.screenshot({ fullPage, encoding: "base64", type: "png" }));
  }

  async listTabs(): Promise<Array<{ index: number; url: string; title: string }>> {
    const result: Array<{ index: number; url: string; title: string }> = [];
    for (const [index, tab] of this.tabs) {
      if (tab.page.isClosed()) {
        this.tabs.delete(index);
        continue;
      }
      result.push({ index, url: tab.page.url(), title: await tab.page.title() });
    }
    return result;
  }

  async closeTab(index: number): Promise<boolean> {
    const tab = this.tabs.get(index);
    if (!tab) return false;
    if (!tab.page.isClosed()) await tab.page.close();
    this.tabs.delete(index);
    if (this.activeTabIndex === index) {
      const remaining = [...this.tabs.keys()];
      this.activeTabIndex = remaining.length > 0 ? remaining[0]! : 0;
    }
    return true;
  }
}

import express from "express";
import cors from "cors";
import { SSEServerTransport } from "@modelcontextprotocol/sdk/server/sse.js";
import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";

// Keep track of active transports to route messages
const transports = new Map<string, SSEServerTransport>();
const LOCAL_BROWSER_ORIGIN_PATTERN =
  /^https?:\/\/(?:localhost|127\.0\.0\.1|local\.spike\.land)(:\d+)?$/i;

export function isAllowedQaStudioOrigin(origin: string | undefined) {
  return (
    origin === undefined ||
    origin === "https://spike.land" ||
    LOCAL_BROWSER_ORIGIN_PATTERN.test(origin)
  );
}

export function startHttpServer(server: McpServer, port: number, host: string) {
  const app = express();

  app.use(
    cors({
      origin(origin, callback) {
        callback(null, isAllowedQaStudioOrigin(origin));
      },
      credentials: true,
      exposedHeaders: ["mcp-session-id"],
    }),
  );

  // Parse JSON bodies for POST requests (except SSE which has its own format)
  app.use(express.json());

  app.get("/mcp", async (_req, res) => {
    const transport = new SSEServerTransport("/mcp/messages", res);
    const sessionId = transport.sessionId;
    transports.set(sessionId, transport);

    res.setHeader("mcp-session-id", sessionId);

    // When the transport is closed, clean it up
    transport.onclose = () => {
      transports.delete(sessionId);
    };

    await server.connect(transport);
  });

  app.post("/mcp/messages", async (req, res) => {
    const sessionId = req.query["sessionId"] as string;
    if (!sessionId) {
      res.status(400).send("Missing sessionId query parameter");
      return;
    }

    const transport = transports.get(sessionId);
    if (!transport) {
      res.status(404).send("Session not found");
      return;
    }

    try {
      // Pass req.body as parsedBody since express.json() already consumed the stream
      await transport.handlePostMessage(req, res, req.body as Record<string, unknown>);
    } catch {
      if (!res.headersSent) {
        res.status(500).send("Error processing message");
      }
    }
  });

  app.delete("/mcp", (req, res) => {
    const sessionId = req.query["sessionId"] as string;
    if (sessionId) {
      const transport = transports.get(sessionId);
      if (transport) {
        transport.close();
        transports.delete(sessionId);
      }
    }
    res.status(200).send("Session cleaned up");
  });

  app.listen(port, host);
}

/**
 * Playwright Browser Adapter
 *
 * Implements BrowserAdapter using Playwright for Node.js CLI usage.
 */

import type { AccessibilityNode } from "../core-logic/types.js";
import type { BrowserAdapter, BrowserPage, CdpAxNode } from "../core-logic/adapter.js";
import { rebuildTree } from "../core-logic/adapter.js";

// ─── Playwright type aliases (never import Playwright types directly) ────────

type PwBrowser = {
  newPage(): Promise<PwPage>;
  close(): Promise<void>;
  isConnected(): boolean;
};

type PwPage = {
  goto(url: string, opts?: { waitUntil?: string }): Promise<unknown>;
  title(): Promise<string>;
  url(): string;
  screenshot(opts?: {
    fullPage?: boolean;
    encoding?: "base64" | "binary";
    type?: "png" | "jpeg";
  }): Promise<string | Buffer>;
  evaluate(fn: string | ((...args: unknown[]) => unknown)): Promise<unknown>;
  setViewportSize(size: { width: number; height: number }): Promise<void>;
  close(): Promise<void>;
  isClosed(): boolean;
  on(event: string, handler: (...args: unknown[]) => void): void;
  keyboard: { press(key: string): Promise<void>; type(text: string): Promise<void> };
  getByRole(
    role: string,
    opts?: { name?: string | RegExp },
  ): {
    click(): Promise<void>;
    fill(text: string): Promise<void>;
    clear(): Promise<void>;
    selectOption(value: string): Promise<string[]>;
  };
  mouse: { wheel(deltaX: number, deltaY: number): Promise<void> };
  viewportSize(): { width: number; height: number } | null;
  context(): {
    newCDPSession(page: PwPage): Promise<{
      send(method: string): Promise<{ nodes?: CdpAxNode[] }>;
    }>;
  };
};

interface ConsoleMessage {
  type(): string;
  text(): string;
  location(): { url: string; lineNumber: number };
}

interface PageRequest {
  url(): string;
  method(): string;
  resourceType(): string;
  response(): Promise<{
    status(): number;
    headers(): Record<string, string>;
  } | null>;
}

export interface BrowserConfig {
  headless?: boolean;
  slowMo?: number;
}

export interface TabEntry {
  page: BrowserPage;
  consoleMessages: Array<{ type: string; text: string; url: string; line: number }>;
  networkRequests: Array<{
    url: string;
    method: string;
    resourceType: string;
    status: number;
    contentLength: string;
  }>;
}

// ─── PlaywrightPage wraps PwPage to implement BrowserPage ────────────────────

class PlaywrightPageWrapper implements BrowserPage {
  private _page: PwPage;
  keyboard: BrowserPage["keyboard"];
  mouse: BrowserPage["mouse"];

  constructor(page: PwPage) {
    this._page = page;
    this.keyboard = page.keyboard;
    this.mouse = page.mouse;
  }

  goto(url: string, opts?: { waitUntil?: string }) {
    return this._page.goto(url, opts);
  }
  title() {
    return this._page.title();
  }
  url() {
    return this._page.url();
  }
  screenshot(opts?: { fullPage?: boolean; encoding?: "base64" | "binary"; type?: "png" | "jpeg" }) {
    return this._page.screenshot(opts);
  }
  evaluate(fn: string | ((...args: unknown[]) => unknown)) {
    return this._page.evaluate(fn);
  }
  setViewportSize(size: { width: number; height: number }) {
    return this._page.setViewportSize(size);
  }
  close() {
    return this._page.close();
  }
  isClosed() {
    return this._page.isClosed();
  }
  getByRole(role: string, opts?: { name?: string | RegExp }) {
    return this._page.getByRole(role, opts);
  }
  viewportSize() {
    return this._page.viewportSize();
  }

  async getAccessibilityTree(): Promise<AccessibilityNode | null> {
    try {
      const client = await this._page.context().newCDPSession(this._page);
      const result = await client.send("Accessibility.getFullAXTree");
      if (result?.nodes) {
        return rebuildTree(result.nodes);
      }
    } catch (err) {
      throw new Error(
        `Failed to get accessibility tree via CDP: ${err instanceof Error ? err.message : String(err)}`,
      );
    }
    return null;
  }

  /** Access underlying Playwright page for event listeners */
  get rawPage(): PwPage {
    return this._page;
  }
}

// ─── PlaywrightAdapter implements BrowserAdapter ─────────────────────────────

export class PlaywrightAdapter implements BrowserAdapter {
  private _config: BrowserConfig;
  private _browser: PwBrowser | null = null;
  private _launchPromise: Promise<PwBrowser> | null = null;

  constructor(config: BrowserConfig = { headless: true }) {
    this._config = config;
  }

  setConfig(config: Partial<BrowserConfig>): void {
    this._config = { ...this._config, ...config };
  }

  async launch(): Promise<void> {
    if (this._browser && this._browser.isConnected()) return;
    if (this._launchPromise) {
      await this._launchPromise;
      return;
    }

    this._launchPromise = (async () => {
      const pw = await import("playwright");
      const b = await pw.chromium.launch({
        headless: this._config.headless ?? true,
        ...(this._config.slowMo !== undefined ? { slowMo: this._config.slowMo } : {}),
      });
      this._browser = b as unknown as PwBrowser;
      return this._browser;
    })();

    try {
      await this._launchPromise;
    } finally {
      this._launchPromise = null;
    }
  }

  async newPage(): Promise<BrowserPage> {
    await this.launch();
    const rawPage = await this._browser!.newPage();
    return new PlaywrightPageWrapper(rawPage);
  }

  isConnected(): boolean {
    return this._browser?.isConnected() ?? false;
  }

  async close(): Promise<void> {
    if (this._browser) {
      await this._browser.close();
      this._browser = null;
    }
  }
}

/**
 * Set up console and network event listeners on a Playwright page wrapper.
 * Only works with PlaywrightPageWrapper (has rawPage).
 */
export function setupPageListeners(page: BrowserPage, entry: TabEntry): void {
  const wrapper = page as PlaywrightPageWrapper;
  if (!wrapper.rawPage) return;

  const raw = wrapper.rawPage as unknown as {
    on(event: string, handler: (...args: unknown[]) => void): void;
  };

  raw.on("console", (msg: unknown) => {
    const m = msg as ConsoleMessage;
    const loc = m.location();
    entry.consoleMessages.push({
      type: m.type(),
      text: m.text(),
      url: loc.url,
      line: loc.lineNumber,
    });
  });

  raw.on("requestfinished", (req: unknown) => {
    const r = req as PageRequest;
    void r.response().then((res) => {
      entry.networkRequests.push({
        url: r.url(),
        method: r.method(),
        resourceType: r.resourceType(),
        status: res?.status() ?? 0,
        contentLength: res?.headers()["content-length"] ?? "0",
      });
    });
  });
}

// Event Delegation - Attach listeners at root container, walk fiber tree to dispatch

import { createSyntheticEvent } from "./SyntheticEvent.js";
import {
  getAllNativeEvents,
  getReactNamesForNativeEvent,
  isNonBubblingEvent,
} from "./EventRegistry.js";
import { HostComponent } from "../../reconciler/ReactWorkTags.js";

// We store the fiber on DOM nodes via this property
const FIBER_KEY = "__reactFiber$";
const PROPS_KEY = "__reactProps$";

// Internal fiber type - minimal interface needed for event dispatch
interface MinimalFiber {
  tag: number;
  stateNode: unknown;
  return: MinimalFiber | null;
  memoizedProps: Record<string, unknown> | null;
}

export function setFiberOnNode(node: Node, fiber: unknown): void {
  (node as unknown as Record<string, unknown>)[FIBER_KEY] = fiber;
}

export function setPropsOnNode(node: Node, props: Record<string, unknown>): void {
  (node as unknown as Record<string, unknown>)[PROPS_KEY] = props;
}

function getFiberFromNode(node: Node): MinimalFiber | null {
  return ((node as unknown as Record<string, unknown>)[FIBER_KEY] as MinimalFiber) || null;
}

function getPropsFromNode(node: Node): Record<string, unknown> | null {
  return (
    ((node as unknown as Record<string, unknown>)[PROPS_KEY] as Record<string, unknown>) || null
  );
}

// Collect all React event listeners along the fiber path (from target to root)
interface DispatchListener {
  fiber: MinimalFiber;
  handler: (event: unknown) => void;
  currentTarget: EventTarget;
}

function collectListeners(
  targetFiber: MinimalFiber | null,
  reactName: string,
  isCapture: boolean,
): DispatchListener[] {
  const listeners: DispatchListener[] = [];
  let fiber = targetFiber;

  while (fiber !== null) {
    // Only HostComponent fibers (tag=5) have DOM nodes with event props
    if (fiber.tag === HostComponent && fiber.stateNode) {
      const props = getPropsFromNode(fiber.stateNode as Node) || fiber.memoizedProps;
      if (props) {
        const propName = isCapture ? reactName + "Capture" : reactName;
        const handler = props[propName];
        if (typeof handler === "function") {
          listeners.push({
            fiber,
            handler: handler as (event: unknown) => void,
            currentTarget: fiber.stateNode as EventTarget,
          });
        }
      }
    }
    fiber = fiber.return;
  }

  return listeners;
}

function dispatchEvent(nativeEventName: string, nativeEvent: Event, _container: Element): void {
  const target = nativeEvent.target || nativeEvent.srcElement;
  if (!target) return;

  // Find the fiber for the target node
  let targetNode: Node | null = target as Node;
  let targetFiber: MinimalFiber | null = null;

  // Walk up from event target to find a node with a fiber
  while (targetNode !== null) {
    targetFiber = getFiberFromNode(targetNode);
    if (targetFiber !== null) break;
    targetNode = targetNode.parentNode;
  }

  // Get React event names for this native event
  const reactNames = getReactNamesForNativeEvent(nativeEventName);

  for (const reactName of reactNames) {
    const syntheticEvent = createSyntheticEvent(reactName, nativeEvent, target);

    // Capture phase - dispatch from root to target
    const captureListeners = collectListeners(targetFiber, reactName, true);
    for (let i = captureListeners.length - 1; i >= 0; i--) {
      if (syntheticEvent.isPropagationStopped()) break;
      const listener = captureListeners[i]!;
      syntheticEvent.currentTarget = listener.currentTarget;
      listener.handler(syntheticEvent);
    }

    // Bubble phase - dispatch from target to root
    if (!syntheticEvent.isPropagationStopped()) {
      const bubbleListeners = collectListeners(targetFiber, reactName, false);
      for (let i = 0; i < bubbleListeners.length; i++) {
        if (syntheticEvent.isPropagationStopped()) break;
        const listener = bubbleListeners[i]!;
        syntheticEvent.currentTarget = listener.currentTarget;
        listener.handler(syntheticEvent);
      }
    }

    syntheticEvent.currentTarget = null;
  }
}

const listeningContainers = new WeakSet<Element>();

export function listenToAllSupportedEvents(container: Element): void {
  if (listeningContainers.has(container)) return;
  listeningContainers.add(container);

  const allNativeEvents = getAllNativeEvents();

  for (const nativeEventName of allNativeEvents) {
    const useCapture = isNonBubblingEvent(nativeEventName);

    container.addEventListener(
      nativeEventName,
      (nativeEvent: Event) => {
        dispatchEvent(nativeEventName, nativeEvent, container);
      },
      useCapture,
    );

    // Also listen in capture phase for bubbling events
    if (!useCapture) {
      container.addEventListener(
        nativeEventName,
        (nativeEvent: Event) => {
          dispatchEvent(nativeEventName, nativeEvent, container);
        },
        true,
      );
    }
  }
}

// Main-thread DOM applier.
// Receives MutationBatch messages from the worker, creates real DOM nodes,
// and forwards captured user events back to the worker.

import { CAPTURED_EVENTS } from "../events.js";
import type { TransferrableEventData } from "../events.js";
import { MutationType } from "./protocol.js";
import type { EventMessage, Mutation, MutationBatchMessage } from "./protocol.js";
import { serializeEvent } from "./event-serializer.js";

export class MainThreadApplier {
  private worker: Worker;
  private container: HTMLElement;
  private nodeMap = new Map<number, Node>();
  private reverseMap = new WeakMap<Node, number>();
  private eventAbortController = new AbortController();

  constructor(container: HTMLElement, workerBlobUrl: string) {
    this.container = container;
    // Pre-register the container as node 0
    this.nodeMap.set(0, container);
    this.reverseMap.set(container, 0);

    this.worker = new Worker(workerBlobUrl, { type: "module" });
    this.worker.onmessage = (ev: MessageEvent<MutationBatchMessage>) => {
      if (ev.data.kind === "mutations") {
        for (const mut of ev.data.mutations) {
          this.applyMutation(mut);
        }
      }
    };

    this.setupEventCapture();
  }

  private applyMutation(mut: Mutation): void {
    switch (mut.type) {
      case MutationType.CREATE_ELEMENT: {
        const el = document.createElement(mut.tagName!);
        this.register(mut.targetId, el);
        break;
      }
      case MutationType.CREATE_ELEMENT_NS: {
        const el = document.createElementNS(mut.namespace!, mut.tagName!);
        this.register(mut.targetId, el);
        break;
      }
      case MutationType.CREATE_TEXT: {
        const text = document.createTextNode(mut.value ?? "");
        this.register(mut.targetId, text);
        break;
      }
      case MutationType.APPEND_CHILD: {
        const parent = this.nodeMap.get(mut.parentId!);
        const child = this.nodeMap.get(mut.targetId);
        if (parent && child) parent.appendChild(child);
        break;
      }
      case MutationType.INSERT_BEFORE: {
        const parent = this.nodeMap.get(mut.parentId!);
        const child = this.nodeMap.get(mut.targetId);
        const ref = this.nodeMap.get(mut.refId!);
        if (parent && child) parent.insertBefore(child, ref ?? null);
        break;
      }
      case MutationType.REMOVE_CHILD: {
        const parent = this.nodeMap.get(mut.parentId!);
        const child = this.nodeMap.get(mut.targetId);
        if (parent && child && child.parentNode === parent) {
          parent.removeChild(child);
        }
        break;
      }
      case MutationType.SET_ATTRIBUTE: {
        const el = this.nodeMap.get(mut.targetId);
        if (el && el instanceof Element) {
          el.setAttribute(mut.name!, mut.value!);
        }
        break;
      }
      case MutationType.REMOVE_ATTRIBUTE: {
        const el = this.nodeMap.get(mut.targetId);
        if (el && el instanceof Element) {
          el.removeAttribute(mut.name!);
        }
        break;
      }
      case MutationType.SET_STYLE: {
        const el = this.nodeMap.get(mut.targetId);
        if (el && el instanceof HTMLElement) {
          el.style.setProperty(mut.name!, mut.value!);
        }
        break;
      }
      case MutationType.SET_TEXT: {
        const node = this.nodeMap.get(mut.targetId);
        if (node && node instanceof Text) {
          node.data = mut.value ?? "";
        }
        break;
      }
      case MutationType.SET_TEXT_CONTENT: {
        const node = this.nodeMap.get(mut.targetId);
        if (node) {
          node.textContent = mut.value ?? "";
        }
        break;
      }
    }
  }

  private register(id: number, node: Node): void {
    this.nodeMap.set(id, node);
    this.reverseMap.set(node, id);
  }

  private setupEventCapture(): void {
    const signal = this.eventAbortController.signal;

    for (const eventName of CAPTURED_EVENTS) {
      this.container.addEventListener(
        eventName,
        (nativeEvent: Event) => {
          const target = nativeEvent.target as Node | null;
          const targetId = target ? (this.reverseMap.get(target) ?? 0) : 0;

          const data: TransferrableEventData = serializeEvent(nativeEvent, targetId);
          const msg: EventMessage = { kind: "event", event: data };
          this.worker.postMessage(msg);
        },
        { capture: true, signal },
      );
    }
  }

  destroy(): void {
    this.worker.terminate();
    this.eventAbortController.abort();
    this.nodeMap.clear();
  }
}

// Worker-side virtual DOM implementation.
// Creates lightweight WorkerElement / WorkerText nodes that record mutations
// and flush them to the main thread via postMessage in a microtask batch.

import type {
  WorkerDocument,
  WorkerElement,
  WorkerNode,
  WorkerText,
} from "../../host-config/WorkerDOMHostConfig.js";
import { MutationType } from "./protocol.js";
import type { Mutation, MutationBatchMessage } from "./protocol.js";

// ---- Global state ----

let nextNodeId = 1; // 0 is reserved for the container
export const nodeMap = new Map<number, WorkerNodeImpl>();

// ---- Mutation collector ----

export class MutationCollector {
  private queue: Mutation[] = [];
  private scheduled = false;

  record(mutation: Mutation): void {
    this.queue.push(mutation);
    if (!this.scheduled) {
      this.scheduled = true;
      queueMicrotask(() => this.flush());
    }
  }

  private flush(): void {
    this.scheduled = false;
    if (this.queue.length === 0) return;

    const batch: MutationBatchMessage = {
      kind: "mutations",
      mutations: this.queue,
    };
    this.queue = [];

    (self as unknown as { postMessage(msg: MutationBatchMessage): void }).postMessage(batch);
  }
}

// Shared collector instance
const collector = new MutationCollector();

// ---- WorkerNode base ----

export class WorkerNodeImpl implements WorkerNode {
  readonly __nodeId: number;
  parentNode: WorkerNode | null = null;
  private _children: WorkerNodeImpl[] = [];

  constructor(id?: number) {
    this.__nodeId = id ?? nextNodeId++;
    nodeMap.set(this.__nodeId, this);
  }

  get childNodes(): ArrayLike<WorkerNode> {
    return this._children;
  }

  get textContent(): string | null {
    return this._children.map((c) => c.textContent ?? "").join("");
  }

  set textContent(value: string | null) {
    // Remove all children
    while (this._children.length > 0) {
      this.removeChild(this._children[this._children.length - 1]!);
    }
    collector.record({
      type: MutationType.SET_TEXT_CONTENT,
      targetId: this.__nodeId,
      value: value ?? "",
    });
  }

  appendChild(child: WorkerNode): void {
    const impl = child as WorkerNodeImpl;
    // Remove from old parent if needed
    if (impl.parentNode) {
      (impl.parentNode as WorkerNodeImpl).removeChildInternal(impl);
    }
    this._children.push(impl);
    impl.parentNode = this;
    collector.record({
      type: MutationType.APPEND_CHILD,
      targetId: impl.__nodeId,
      parentId: this.__nodeId,
    });
  }

  insertBefore(child: WorkerNode, before: WorkerNode): void {
    const impl = child as WorkerNodeImpl;
    const beforeImpl = before as WorkerNodeImpl;
    if (impl.parentNode) {
      (impl.parentNode as WorkerNodeImpl).removeChildInternal(impl);
    }
    const idx = this._children.indexOf(beforeImpl);
    if (idx === -1) {
      this._children.push(impl);
    } else {
      this._children.splice(idx, 0, impl);
    }
    impl.parentNode = this;
    collector.record({
      type: MutationType.INSERT_BEFORE,
      targetId: impl.__nodeId,
      parentId: this.__nodeId,
      refId: beforeImpl.__nodeId,
    });
  }

  removeChild(child: WorkerNode): void {
    const impl = child as WorkerNodeImpl;
    this.removeChildInternal(impl);
    collector.record({
      type: MutationType.REMOVE_CHILD,
      targetId: impl.__nodeId,
      parentId: this.__nodeId,
    });
  }

  /** Internal removal without recording a mutation (used when moving nodes). */
  private removeChildInternal(child: WorkerNodeImpl): void {
    const idx = this._children.indexOf(child);
    if (idx !== -1) {
      this._children.splice(idx, 1);
    }
    child.parentNode = null;
  }
}

// ---- WorkerElement ----

export class WorkerElementImpl extends WorkerNodeImpl implements WorkerElement {
  readonly tagName: string;
  readonly namespaceURI: string | null;
  readonly style: Record<string, string>;

  constructor(tagName: string, namespaceURI: string | null = null) {
    super();
    this.tagName = tagName.toUpperCase();
    this.namespaceURI = namespaceURI;

    // Style proxy that records SET_STYLE mutations
    const nodeId = this.__nodeId;
    const backing: Record<string, string> = {};
    this.style = new Proxy(backing, {
      set(_target, prop: string, value: string) {
        _target[prop] = value;
        collector.record({
          type: MutationType.SET_STYLE,
          targetId: nodeId,
          name: prop,
          value: String(value),
        });
        return true;
      },
      get(target, prop: string) {
        return target[prop] ?? "";
      },
    });
  }

  setAttribute(name: string, value: string): void {
    collector.record({
      type: MutationType.SET_ATTRIBUTE,
      targetId: this.__nodeId,
      name,
      value,
    });
  }

  removeAttribute(name: string): void {
    collector.record({
      type: MutationType.REMOVE_ATTRIBUTE,
      targetId: this.__nodeId,
      name,
    });
  }
}

// ---- WorkerText ----

export class WorkerTextImpl extends WorkerNodeImpl implements WorkerText {
  private _data: string;

  constructor(text: string) {
    super();
    this._data = text;
  }

  get data(): string {
    return this._data;
  }

  set data(value: string) {
    this._data = value;
    collector.record({
      type: MutationType.SET_TEXT,
      targetId: this.__nodeId,
      value,
    });
  }

  get nodeValue(): string | null {
    return this._data;
  }

  set nodeValue(value: string | null) {
    this.data = value ?? "";
  }

  override get textContent(): string | null {
    return this._data;
  }

  override set textContent(value: string | null) {
    this.data = value ?? "";
  }
}

// ---- WorkerDocument ----

export class WorkerDocumentImpl implements WorkerDocument {
  createElement(type: string): WorkerElement {
    const el = new WorkerElementImpl(type);
    collector.record({
      type: MutationType.CREATE_ELEMENT,
      targetId: el.__nodeId,
      tagName: type,
    });
    return el;
  }

  createElementNS(namespace: string, type: string): WorkerElement {
    const el = new WorkerElementImpl(type, namespace);
    collector.record({
      type: MutationType.CREATE_ELEMENT_NS,
      targetId: el.__nodeId,
      tagName: type,
      namespace,
    });
    return el;
  }

  createTextNode(text: string): WorkerText {
    const node = new WorkerTextImpl(text);
    collector.record({
      type: MutationType.CREATE_TEXT,
      targetId: node.__nodeId,
      value: text,
    });
    return node;
  }
}

// Pre-register a container root node with id 0 so the main-thread applier
// and worker agree on the container identity.
export function createContainerNode(): WorkerElementImpl {
  const container = new WorkerElementImpl("DIV");
  // Override the auto-generated id — constructor already called super()
  // so we re-register under id 0.
  nodeMap.delete(container.__nodeId);
  Object.defineProperty(container, "__nodeId", { value: 0 });
  nodeMap.set(0, container);
  return container;
}

// BeginWork - Render phase down-traversal
// Processes each fiber and returns the next child to work on

import type { Fiber } from "./ReactFiberTypes.js";
import type { Lanes } from "./ReactFiberLane.js";
import type { ComponentClass, ComponentInstance, ReactContext } from "../react/ReactTypes.js";
import {
  ClassComponent,
  ContextProvider,
  ForwardRef,
  Fragment,
  FunctionComponent,
  HostComponent,
  HostRoot,
  HostText,
  LazyComponent,
  MemoComponent,
  SimpleMemoComponent,
  SuspenseComponent,
} from "./ReactWorkTags.js";
import {
  ContentReset,
  DidCapture,
  NoFlags,
  PerformedWork,
  Ref,
  RefStatic,
} from "./ReactFiberFlags.js";
import { includesSomeLane, NoLanes } from "./ReactFiberLane.js";
import {
  REACT_ELEMENT_TYPE,
  REACT_FORWARD_REF_TYPE,
  REACT_MEMO_TYPE,
} from "../react/ReactSymbols.js";
import { cloneChildFibers, mountChildFibers, reconcileChildFibers } from "./ReactChildFiber.js";
import { bailoutHooks, renderWithHooks } from "./ReactFiberHooks.js";
import { pushProvider } from "./ReactFiberNewContext.js";
import { pushHostContainer, pushHostContext } from "./ReactFiberHostContext.js";
import {
  constructClassInstance,
  mountClassInstance,
  updateClassInstance,
} from "./ReactFiberClassComponent.js";
import { createFiberFromElement } from "./ReactFiber.js";
import shallowEqual from "../shared/shallowEqual.js";

function reconcileChildren(
  current: Fiber | null,
  workInProgress: Fiber,
  nextChildren: unknown,
  renderLanes: Lanes,
): void {
  if (current === null) {
    workInProgress.child = mountChildFibers(workInProgress, null, nextChildren, renderLanes);
  } else {
    workInProgress.child = reconcileChildFibers(
      workInProgress,
      current.child,
      nextChildren,
      renderLanes,
    );
  }
}

function markRef(current: Fiber | null, workInProgress: Fiber): void {
  const ref = workInProgress.ref;
  if ((current === null && ref !== null) || (current !== null && current.ref !== ref)) {
    workInProgress.flags |= Ref;
    workInProgress.flags |= RefStatic;
  }
}

function updateFunctionComponent(
  current: Fiber | null,
  workInProgress: Fiber,
  Component: (...args: unknown[]) => unknown,
  nextProps: unknown,
  renderLanes: Lanes,
): Fiber | null {
  const nextChildren = renderWithHooks(
    current,
    workInProgress,
    Component,
    nextProps,
    null,
    renderLanes,
  );

  if (current !== null && !didReceiveUpdate) {
    bailoutHooks(current, workInProgress, renderLanes);
    return bailoutOnAlreadyFinishedWork(current, workInProgress, renderLanes);
  }

  workInProgress.flags |= PerformedWork;
  reconcileChildren(current, workInProgress, nextChildren, renderLanes);
  return workInProgress.child;
}

function updateClassComponent(
  current: Fiber | null,
  workInProgress: Fiber,
  Component: unknown,
  nextProps: unknown,
  renderLanes: Lanes,
): Fiber | null {
  const Ctor = Component as ComponentClass;
  let instance = workInProgress.stateNode as ComponentInstance | null;

  if (instance === null) {
    instance = constructClassInstance(workInProgress, Ctor, nextProps);
    mountClassInstance(workInProgress, Ctor, nextProps, renderLanes);
  } else if (current === null) {
    // Re-mount (component was previously deleted but fiber is being reused)
    mountClassInstance(workInProgress, Ctor, nextProps, renderLanes);
  } else {
    const shouldUpdate = updateClassInstance(current, workInProgress, Ctor, nextProps, renderLanes);
    if (!shouldUpdate) {
      return bailoutOnAlreadyFinishedWork(current, workInProgress, renderLanes);
    }
  }

  const nextChildren = instance!.render();
  workInProgress.flags |= PerformedWork;
  reconcileChildren(current, workInProgress, nextChildren, renderLanes);
  return workInProgress.child;
}

function updateHostRoot(current: Fiber, workInProgress: Fiber, renderLanes: Lanes): Fiber | null {
  pushHostContainer(workInProgress);

  const nextChildren =
    (workInProgress.memoizedState as Record<string, unknown> | null)?.["element"] ?? null;
  reconcileChildren(current, workInProgress, nextChildren, renderLanes);
  return workInProgress.child;
}

function updateHostComponent(
  current: Fiber | null,
  workInProgress: Fiber,
  renderLanes: Lanes,
): Fiber | null {
  pushHostContext(workInProgress);

  const nextProps = workInProgress.pendingProps as Record<string, unknown>;
  const prevProps =
    current !== null ? (current.memoizedProps as Record<string, unknown> | null) : null;

  let nextChildren = nextProps["children"];

  // Check if the host config says this component should set text content
  const isDirectTextChild = typeof nextChildren === "string" || typeof nextChildren === "number";

  if (isDirectTextChild) {
    nextChildren = null;
  } else if (prevProps !== null) {
    const prevIsDirectTextChild =
      typeof prevProps["children"] === "string" || typeof prevProps["children"] === "number";
    if (prevIsDirectTextChild) {
      workInProgress.flags |= ContentReset;
    }
  }

  markRef(current, workInProgress);
  reconcileChildren(current, workInProgress, nextChildren, renderLanes);
  return workInProgress.child;
}

function updateHostText(_current: Fiber | null, _workInProgress: Fiber): null {
  // Nothing to do for text nodes in beginWork
  return null;
}

function updateFragment(
  current: Fiber | null,
  workInProgress: Fiber,
  renderLanes: Lanes,
): Fiber | null {
  const nextChildren = workInProgress.pendingProps;
  reconcileChildren(current, workInProgress, nextChildren, renderLanes);
  return workInProgress.child;
}

function updateContextProvider(
  current: Fiber | null,
  workInProgress: Fiber,
  renderLanes: Lanes,
): Fiber | null {
  const context: ReactContext<unknown> = workInProgress.type as ReactContext<unknown>;
  const newProps = workInProgress.pendingProps as Record<string, unknown>;
  const newValue = newProps["value"];

  pushProvider(workInProgress, context, newValue);

  const newChildren = newProps["children"];
  reconcileChildren(current, workInProgress, newChildren, renderLanes);
  return workInProgress.child;
}

function updateForwardRef(
  current: Fiber | null,
  workInProgress: Fiber,
  Component: unknown,
  nextProps: unknown,
  renderLanes: Lanes,
): Fiber | null {
  const render = (Component as Record<string, unknown>)["render"] as (
    props: unknown,
    secondArg?: unknown,
  ) => unknown;
  const ref = workInProgress.ref;

  const nextChildren = renderWithHooks(
    current,
    workInProgress,
    render,
    nextProps,
    ref,
    renderLanes,
  );

  if (current !== null && !didReceiveUpdate) {
    bailoutHooks(current, workInProgress, renderLanes);
    return bailoutOnAlreadyFinishedWork(current, workInProgress, renderLanes);
  }

  workInProgress.flags |= PerformedWork;
  reconcileChildren(current, workInProgress, nextChildren, renderLanes);
  return workInProgress.child;
}

function updateMemoComponent(
  current: Fiber | null,
  workInProgress: Fiber,
  Component: unknown,
  nextProps: unknown,
  renderLanes: Lanes,
): Fiber | null {
  const comp = Component as Record<string, unknown>;
  if (current === null) {
    const innerType = comp["type"];
    if (
      typeof innerType === "function" &&
      comp["compare"] === null &&
      comp["defaultProps"] === undefined
    ) {
      // Simple memo shortcut
      workInProgress.tag = SimpleMemoComponent;
      workInProgress.type = innerType;
      return updateSimpleMemoComponent(current, workInProgress, innerType, nextProps, renderLanes);
    }

    const child = createFiberFromElement(
      {
        $$typeof: REACT_ELEMENT_TYPE,
        type: innerType as string | ((...args: unknown[]) => unknown),
        key: null,
        ref: null,
        props: nextProps,
        _owner: null,
      },
      renderLanes,
    );
    child.ref = workInProgress.ref;
    child.return = workInProgress;
    workInProgress.child = child;
    return child;
  }

  // Update path
  const currentChild = current.child!;
  const prevProps = currentChild.memoizedProps;
  const compare = (comp["compare"] || shallowEqual) as (a: unknown, b: unknown) => boolean;

  if (compare(prevProps, nextProps) && current.ref === workInProgress.ref) {
    return bailoutOnAlreadyFinishedWork(current, workInProgress, renderLanes);
  }

  workInProgress.flags |= PerformedWork;
  const newChild = createFiberFromElement(
    {
      $$typeof: REACT_ELEMENT_TYPE,
      type: comp["type"] as string | ((...args: unknown[]) => unknown),
      key: null,
      ref: null,
      props: nextProps,
      _owner: null,
    },
    renderLanes,
  );
  newChild.ref = workInProgress.ref;
  newChild.return = workInProgress;
  workInProgress.child = newChild;
  return newChild;
}

function updateSimpleMemoComponent(
  current: Fiber | null,
  workInProgress: Fiber,
  Component: unknown,
  nextProps: unknown,
  renderLanes: Lanes,
): Fiber | null {
  if (current !== null) {
    const prevProps = current.memoizedProps;
    if (shallowEqual(prevProps, nextProps) && current.ref === workInProgress.ref) {
      didReceiveUpdate = false;
      workInProgress.pendingProps = nextProps = prevProps;
      return bailoutOnAlreadyFinishedWork(current, workInProgress, renderLanes);
    }
  }
  return updateFunctionComponent(
    current,
    workInProgress,
    Component as (...args: unknown[]) => unknown,
    nextProps,
    renderLanes,
  );
}

function updateSuspenseComponent(
  current: Fiber | null,
  workInProgress: Fiber,
  renderLanes: Lanes,
): Fiber | null {
  const nextProps = workInProgress.pendingProps as Record<string, unknown>;

  const showFallback = (workInProgress.flags & DidCapture) !== NoFlags;

  if (showFallback) {
    workInProgress.flags &= ~DidCapture;
    const fallback = nextProps["fallback"];
    // Render fallback
    reconcileChildren(current, workInProgress, fallback, renderLanes);
    return workInProgress.child;
  }

  // Normal render - show primary content
  const primaryChildren = nextProps["children"];
  reconcileChildren(current, workInProgress, primaryChildren, renderLanes);
  return workInProgress.child;
}

function updateLazyComponent(
  current: Fiber | null,
  workInProgress: Fiber,
  lazyComponent: unknown,
  nextProps: unknown,
  renderLanes: Lanes,
): Fiber | null {
  const payload = (lazyComponent as Record<string, unknown>)["_payload"];
  const init = (lazyComponent as Record<string, unknown>)["_init"] as (payload: unknown) => unknown;
  const Component = init(payload);

  workInProgress.type = Component;

  if (typeof Component === "function") {
    if (isClassComponent(Component)) {
      workInProgress.tag = ClassComponent;
      return updateClassComponent(current, workInProgress, Component, nextProps, renderLanes);
    }
    workInProgress.tag = FunctionComponent;
    return updateFunctionComponent(
      current,
      workInProgress,
      Component as (...args: unknown[]) => unknown,
      nextProps,
      renderLanes,
    );
  }

  if (typeof Component === "object" && Component !== null) {
    if ((Component as Record<string, unknown>)["$$typeof"] === REACT_FORWARD_REF_TYPE) {
      workInProgress.tag = ForwardRef;
      return updateForwardRef(current, workInProgress, Component, nextProps, renderLanes);
    }
    if ((Component as Record<string, unknown>)["$$typeof"] === REACT_MEMO_TYPE) {
      workInProgress.tag = MemoComponent;
      return updateMemoComponent(current, workInProgress, Component, nextProps, renderLanes);
    }
  }

  throw new Error(
    `Element type is invalid. Received a promise that resolves to: ${Component}. ` +
      "Lazy element type must resolve to a class or function.",
  );
}

function isClassComponent(Component: unknown): boolean {
  const proto = (Component as Record<string, unknown>)["prototype"] as
    | Record<string, unknown>
    | undefined;
  return !!(proto && proto["isReactComponent"]);
}

// Track whether we received an update during this beginWork
let didReceiveUpdate = false;

export function markWorkInProgressReceivedUpdate(): void {
  didReceiveUpdate = true;
}

function bailoutOnAlreadyFinishedWork(
  current: Fiber | null,
  workInProgress: Fiber,
  renderLanes: Lanes,
): Fiber | null {
  if (!includesSomeLane(workInProgress.childLanes, renderLanes)) {
    // No pending work in children
    return null;
  }

  // Clone children - this fiber doesn't need work but children might
  cloneChildFibers(current, workInProgress);
  return workInProgress.child;
}

export function beginWork(
  current: Fiber | null,
  workInProgress: Fiber,
  renderLanes: Lanes,
): Fiber | null {
  didReceiveUpdate = false;

  // Check if we can bail out
  if (current !== null) {
    const oldProps = current.memoizedProps;
    const newProps = workInProgress.pendingProps;

    if (oldProps !== newProps) {
      didReceiveUpdate = true;
    } else if (!includesSomeLane(renderLanes, workInProgress.lanes)) {
      didReceiveUpdate = false;
      // Push contexts as needed even during bailout
      switch (workInProgress.tag) {
        case HostRoot:
          pushHostContainer(workInProgress);
          break;
        case HostComponent:
          pushHostContext(workInProgress);
          break;
        case ContextProvider: {
          const context: ReactContext<unknown> = workInProgress.type as ReactContext<unknown>;
          pushProvider(
            workInProgress,
            context,
            (workInProgress.memoizedProps as Record<string, unknown>)["value"],
          );
          break;
        }
      }
      return bailoutOnAlreadyFinishedWork(current, workInProgress, renderLanes);
    }
  }

  // Clear lanes before processing - they'll be set again if needed
  workInProgress.lanes = NoLanes;

  switch (workInProgress.tag) {
    case FunctionComponent: {
      const Component = workInProgress.type as (...args: unknown[]) => unknown;
      const unresolvedProps = workInProgress.pendingProps;
      return updateFunctionComponent(
        current,
        workInProgress,
        Component,
        unresolvedProps,
        renderLanes,
      );
    }
    case ClassComponent: {
      const Component = workInProgress.type;
      const unresolvedProps = workInProgress.pendingProps;
      return updateClassComponent(current, workInProgress, Component, unresolvedProps, renderLanes);
    }
    case HostRoot:
      return updateHostRoot(current!, workInProgress, renderLanes);
    case HostComponent:
      return updateHostComponent(current, workInProgress, renderLanes);
    case HostText:
      return updateHostText(current, workInProgress);
    case Fragment:
      return updateFragment(current, workInProgress, renderLanes);
    case ContextProvider:
      return updateContextProvider(current, workInProgress, renderLanes);
    case ForwardRef: {
      const type = workInProgress.type;
      const unresolvedProps = workInProgress.pendingProps;
      return updateForwardRef(current, workInProgress, type, unresolvedProps, renderLanes);
    }
    case MemoComponent: {
      const type = workInProgress.type;
      const unresolvedProps = workInProgress.pendingProps;
      return updateMemoComponent(current, workInProgress, type, unresolvedProps, renderLanes);
    }
    case SimpleMemoComponent:
      return updateSimpleMemoComponent(
        current,
        workInProgress,
        workInProgress.type,
        workInProgress.pendingProps,
        renderLanes,
      );
    case SuspenseComponent:
      return updateSuspenseComponent(current, workInProgress, renderLanes);
    case LazyComponent: {
      const elementType = workInProgress.elementType;
      return updateLazyComponent(
        current,
        workInProgress,
        elementType,
        workInProgress.pendingProps,
        renderLanes,
      );
    }
    default:
      throw new Error(`Unknown work tag: ${workInProgress.tag}`);
  }
}

// Class Component Lifecycle Management

import type { ClassUpdate, ClassUpdateQueue, Fiber } from "./ReactFiberTypes.js";
import type { Lane, Lanes } from "./ReactFiberLane.js";
import type { ComponentClass, ComponentInstance } from "../react/ReactTypes.js";
import { Callback, Snapshot, Update } from "./ReactFiberFlags.js";
import { SyncLane } from "./ReactFiberLane.js";
import assign from "../shared/assign.js";

// Update tags
const UpdateState = 0;
const ReplaceState = 1;
const ForceUpdate = 2;
// CaptureUpdate = 3 (reserved for error boundary handling)

export function initializeClassUpdateQueue<S>(fiber: Fiber): void {
  const queue: ClassUpdateQueue<S> = {
    baseState: fiber.memoizedState as S,
    firstBaseUpdate: null,
    lastBaseUpdate: null,
    shared: {
      pending: null,
    },
    callbacks: null,
  };
  fiber.updateQueue = queue;
}

export function createClassUpdate(lane: Lane): ClassUpdate {
  return {
    lane,
    tag: UpdateState,
    payload: null,
    callback: null,
    next: null,
  };
}

export function enqueueClassUpdate(fiber: Fiber, update: ClassUpdate): void {
  const updateQueue = fiber.updateQueue as ClassUpdateQueue;
  if (updateQueue === null) return;

  const sharedQueue = updateQueue.shared;
  const pending = sharedQueue.pending;
  if (pending === null) {
    update.next = update;
  } else {
    update.next = pending.next;
    pending.next = update;
  }
  sharedQueue.pending = update;
}

export function processClassUpdateQueue<S>(
  fiber: Fiber,
  props: unknown,
  instance: unknown,
  _renderLanes: Lanes,
): void {
  const queue = fiber.updateQueue as ClassUpdateQueue<S>;
  if (!queue) return;

  let firstBaseUpdate = queue.firstBaseUpdate;
  let lastBaseUpdate = queue.lastBaseUpdate;

  // Move pending updates to base queue
  const pendingQueue = queue.shared.pending;
  if (pendingQueue !== null) {
    queue.shared.pending = null;

    const lastPendingUpdate = pendingQueue;
    const firstPendingUpdate = lastPendingUpdate.next!;
    lastPendingUpdate.next = null;

    if (lastBaseUpdate === null) {
      firstBaseUpdate = firstPendingUpdate;
    } else {
      lastBaseUpdate.next = firstPendingUpdate;
    }
    lastBaseUpdate = lastPendingUpdate;
  }

  if (firstBaseUpdate !== null) {
    let newState: S = queue.baseState;
    const newBaseState: S = newState;
    let update: ClassUpdate<S> | null = firstBaseUpdate;

    do {
      // Process update
      if (update!.tag === UpdateState) {
        const payload = update!.payload;
        if (typeof payload === "function") {
          newState = payload.call(instance, newState, props);
        } else {
          newState = assign({}, newState, payload);
        }
      } else if (update!.tag === ReplaceState) {
        newState = update!.payload as S;
      } else if (update!.tag === ForceUpdate) {
        // Force update doesn't change state
      }

      if (update!.callback !== null) {
        fiber.flags |= Callback;
        if (queue.callbacks === null) {
          queue.callbacks = [];
        }
        queue.callbacks.push(update!.callback);
      }

      update = update!.next;
      if (update === null) break;
    } while (true);

    queue.baseState = newBaseState;
    queue.firstBaseUpdate = null;
    queue.lastBaseUpdate = null;
    fiber.memoizedState = newState;
  }
}

export function constructClassInstance(
  fiber: Fiber,
  Component: ComponentClass,
  props: unknown,
): ComponentInstance {
  const context = {};

  const instance = new Component(props as Record<string, unknown>, context);
  const state = instance.state !== undefined ? instance.state : null;
  fiber.memoizedState = state;

  instance.props = props as Readonly<Record<string, unknown>>;
  instance.state = state as Readonly<Record<string, unknown>>;
  instance.refs = {};
  instance.context = context;

  // Set up updater
  (instance as unknown as Record<string, unknown>)["updater"] = {
    isMounted: () => true,
    enqueueSetState: (_inst: unknown, payload: unknown, callback: unknown) => {
      const update = createClassUpdate(SyncLane);
      update.payload = payload;
      if (callback) update.callback = callback as () => void;
      enqueueClassUpdate(fiber, update);
    },
    enqueueReplaceState: (_inst: unknown, payload: unknown, callback: unknown) => {
      const update = createClassUpdate(SyncLane);
      update.tag = ReplaceState;
      update.payload = payload;
      if (callback) update.callback = callback as () => void;
      enqueueClassUpdate(fiber, update);
    },
    enqueueForceUpdate: (_inst: unknown, callback: unknown) => {
      const update = createClassUpdate(SyncLane);
      update.tag = ForceUpdate;
      if (callback) update.callback = callback as () => void;
      enqueueClassUpdate(fiber, update);
    },
  };

  fiber.stateNode = instance;
  // Store fiber reference on instance for setState
  (instance as unknown as Record<string, unknown>)["_reactInternals"] = fiber;

  return instance;
}

export function mountClassInstance(
  fiber: Fiber,
  Component: ComponentClass,
  nextProps: unknown,
  renderLanes: Lanes,
): void {
  const instance = fiber.stateNode as ComponentInstance;

  instance.props = nextProps as Readonly<Record<string, unknown>>;
  instance.state = fiber.memoizedState as Readonly<Record<string, unknown>>;
  instance.refs = {};

  initializeClassUpdateQueue(fiber);
  processClassUpdateQueue(fiber, nextProps, instance, renderLanes);
  instance.state = fiber.memoizedState as Readonly<Record<string, unknown>>;

  // Call getDerivedStateFromProps
  const getDerivedStateFromProps = (Component as unknown as Record<string, unknown>)[
    "getDerivedStateFromProps"
  ];
  if (typeof getDerivedStateFromProps === "function") {
    const partialState = getDerivedStateFromProps(nextProps, instance.state);
    if (partialState != null) {
      instance.state = assign({}, instance.state, partialState);
      fiber.memoizedState = instance.state;
    }
  }

  // Mark for lifecycle effects
  if (typeof instance.componentDidMount === "function") {
    fiber.flags |= Update;
  }
}

export function updateClassInstance(
  _current: Fiber,
  fiber: Fiber,
  Component: ComponentClass,
  nextProps: unknown,
  renderLanes: Lanes,
): boolean {
  const instance = fiber.stateNode as ComponentInstance;
  const oldProps = fiber.memoizedProps;
  const oldState = fiber.memoizedState;

  instance.props = oldProps as Readonly<Record<string, unknown>>;

  // Call getDerivedStateFromProps
  let newState = oldState;
  const getDerivedStateFromProps = (Component as unknown as Record<string, unknown>)[
    "getDerivedStateFromProps"
  ];
  if (typeof getDerivedStateFromProps === "function") {
    const partialState = getDerivedStateFromProps(nextProps, oldState);
    if (partialState != null) {
      newState = assign({}, oldState, partialState);
    }
  }

  processClassUpdateQueue(fiber, nextProps, instance, renderLanes);
  const processedState = fiber.memoizedState;
  if (processedState !== oldState) {
    newState = assign({}, newState, processedState);
  }

  // shouldComponentUpdate check
  const shouldUpdate =
    typeof instance.shouldComponentUpdate === "function"
      ? instance.shouldComponentUpdate(
          nextProps as Readonly<Record<string, unknown>>,
          newState as Readonly<Record<string, unknown>>,
          {},
        )
      : true;

  if (shouldUpdate) {
    if (typeof instance.componentDidUpdate === "function") {
      fiber.flags |= Update;
    }
    if (typeof instance.getSnapshotBeforeUpdate === "function") {
      fiber.flags |= Snapshot;
    }
  }

  instance.props = nextProps as Readonly<Record<string, unknown>>;
  instance.state = newState as Readonly<Record<string, unknown>>;
  fiber.memoizedState = newState;
  fiber.memoizedProps = nextProps;

  return shouldUpdate;
}

// CommitWork - Commit phase: apply fiber effects to the host tree
// Three sub-phases: before mutation, mutation, layout

import type { Effect, Fiber, FiberRoot, FunctionComponentUpdateQueue } from "./ReactFiberTypes.js";
import type { HostConfig } from "../host-config/HostConfigInterface.js";
import {
  ClassComponent,
  ForwardRef,
  FunctionComponent,
  HostComponent,
  HostRoot,
  HostText,
  MemoComponent,
  SimpleMemoComponent,
} from "./ReactWorkTags.js";
import {
  BeforeMutationMask,
  ChildDeletion,
  ContentReset,
  LayoutMask,
  MutationMask,
  NoFlags,
  Passive,
  PassiveMask,
  Placement,
  Ref,
  Snapshot,
  Update,
} from "./ReactFiberFlags.js";
import type { ComponentInstance } from "../react/ReactTypes.js";
import { HookHasEffect, HookInsertion, HookLayout, HookPassive } from "./ReactFiberHooks.js";

function getHostParent(fiber: Fiber): { parent: unknown; isContainer: boolean } {
  let node: Fiber | null = fiber.return;
  while (node !== null) {
    if (node.tag === HostComponent) {
      return { parent: node.stateNode, isContainer: false };
    }
    if (node.tag === HostRoot) {
      return {
        parent: (node.stateNode as FiberRoot).containerInfo,
        isContainer: true,
      };
    }
    node = node.return;
  }
  throw new Error("Could not find host parent");
}

function getHostSibling(fiber: Fiber): unknown {
  let node: Fiber = fiber;

  siblings: while (true) {
    while (node.sibling === null) {
      if (node.return === null || isHostParent(node.return)) {
        return null;
      }
      node = node.return;
    }
    node.sibling.return = node.return;
    node = node.sibling;

    while (node.tag !== HostComponent && node.tag !== HostText) {
      if (node.flags & Placement) {
        continue siblings;
      }
      if (node.child === null) {
        continue siblings;
      }
      node.child.return = node;
      node = node.child;
    }

    if (!(node.flags & Placement)) {
      return node.stateNode;
    }
  }
}

function isHostParent(fiber: Fiber): boolean {
  return fiber.tag === HostComponent || fiber.tag === HostRoot;
}

// ─── Before Mutation Phase ───────────────────────────────────────────────

export function commitBeforeMutationEffects(_root: FiberRoot, finishedWork: Fiber): void {
  commitBeforeMutationEffectsOnFiber(finishedWork);
}

function commitBeforeMutationEffectsOnFiber(fiber: Fiber): void {
  // Process children first
  let child = fiber.child;
  if ((fiber.subtreeFlags & BeforeMutationMask) !== NoFlags && child !== null) {
    while (child !== null) {
      commitBeforeMutationEffectsOnFiber(child);
      child = child.sibling;
    }
  }

  if ((fiber.flags & Snapshot) !== NoFlags) {
    if (fiber.tag === ClassComponent) {
      const instance = fiber.stateNode as ComponentInstance;
      const current = fiber.alternate;
      if (current !== null && typeof instance.getSnapshotBeforeUpdate === "function") {
        instance.getSnapshotBeforeUpdate(
          current.memoizedProps as Readonly<Record<string, unknown>>,
          current.memoizedState as Readonly<Record<string, unknown>>,
        );
      }
    }
  }
}

// ─── Mutation Phase ─────────────────────────────────────────────────────

export function commitMutationEffects(root: FiberRoot, finishedWork: Fiber): void {
  commitMutationEffectsOnFiber(finishedWork, root);
}

function commitMutationEffectsOnFiber(fiber: Fiber, root: FiberRoot): void {
  const hostConfig = root.hostConfig;

  // Process children first
  let child = fiber.child;
  if ((fiber.subtreeFlags & MutationMask) !== NoFlags && child !== null) {
    while (child !== null) {
      commitMutationEffectsOnFiber(child, root);
      child = child.sibling;
    }
  }

  const flags = fiber.flags;

  // Handle deletions
  if (flags & ChildDeletion) {
    const deletions = fiber.deletions;
    if (deletions !== null) {
      for (let i = 0; i < deletions.length; i++) {
        commitDeletion(root, deletions[i]!, fiber, hostConfig);
      }
    }
  }

  // Handle placement (insertion)
  if (flags & Placement) {
    commitPlacement(fiber, hostConfig);
    fiber.flags &= ~Placement;
  }

  // Handle updates
  if (flags & Update) {
    switch (fiber.tag) {
      case FunctionComponent:
      case ForwardRef:
      case MemoComponent:
      case SimpleMemoComponent: {
        // Commit insertion effects
        commitHookEffectListUnmount(HookInsertion | HookHasEffect, fiber);
        commitHookEffectListMount(HookInsertion | HookHasEffect, fiber);
        break;
      }
      case HostComponent: {
        const instance = fiber.stateNode;
        if (instance !== null) {
          const newProps = fiber.memoizedProps;
          const oldProps = fiber.alternate !== null ? fiber.alternate.memoizedProps : newProps;
          hostConfig.commitUpdate(
            instance,
            fiber.type as string,
            oldProps as Record<string, unknown>,
            newProps as Record<string, unknown>,
          );
        }
        break;
      }
      case HostText: {
        const textInstance = fiber.stateNode;
        const newText = fiber.memoizedProps;
        const oldText = fiber.alternate !== null ? fiber.alternate.memoizedProps : newText;
        if (textInstance !== null) {
          hostConfig.commitTextUpdate(textInstance, oldText as string, newText as string);
        }
        break;
      }
    }
  }

  // Handle content reset
  if (flags & ContentReset) {
    if (fiber.tag === HostComponent) {
      hostConfig.resetTextContent(fiber.stateNode);
    }
  }

  // Handle ref
  if (flags & Ref) {
    const current = fiber.alternate;
    if (current !== null) {
      commitDetachRef(current);
    }
  }
}

function commitPlacement(finishedWork: Fiber, hostConfig: HostConfig): void {
  const { parent, isContainer } = getHostParent(finishedWork);
  const before = getHostSibling(finishedWork);

  if (finishedWork.tag === HostComponent || finishedWork.tag === HostText) {
    const stateNode = finishedWork.stateNode;
    if (before !== null) {
      if (isContainer) {
        hostConfig.insertInContainerBefore(parent, stateNode, before);
      } else {
        hostConfig.insertBefore(parent, stateNode, before);
      }
    } else {
      if (isContainer) {
        hostConfig.appendChildToContainer(parent, stateNode);
      } else {
        hostConfig.appendChild(parent, stateNode);
      }
    }
  } else {
    // Composite component - traverse to find host children
    let child = finishedWork.child;
    while (child !== null) {
      commitPlacement(child, hostConfig);
      child = child.sibling;
    }
  }
}

function commitDeletion(
  root: FiberRoot,
  childToDelete: Fiber,
  hostParentFiber: Fiber,
  hostConfig: HostConfig,
): void {
  // Find host parent
  const { parent, isContainer } = getHostParent(hostParentFiber);

  // Unmount the subtree
  commitNestedUnmounts(childToDelete, root);

  // Remove from host tree
  removeHostChildren(childToDelete, parent, isContainer, hostConfig);
}

function removeHostChildren(
  fiber: Fiber,
  parent: unknown,
  isContainer: boolean,
  hostConfig: HostConfig,
): void {
  if (fiber.tag === HostComponent || fiber.tag === HostText) {
    if (isContainer) {
      hostConfig.removeChildFromContainer(parent, fiber.stateNode);
    } else {
      hostConfig.removeChild(parent, fiber.stateNode);
    }
  } else {
    let child = fiber.child;
    while (child !== null) {
      removeHostChildren(child, parent, isContainer, hostConfig);
      child = child.sibling;
    }
  }
}

function commitNestedUnmounts(fiber: Fiber, root: FiberRoot): void {
  let node: Fiber = fiber;
  while (true) {
    commitUnmount(node, root);
    if (node.child !== null) {
      node.child.return = node;
      node = node.child;
      continue;
    }
    if (node === fiber) return;
    while (node.sibling === null) {
      if (node.return === null || node.return === fiber) return;
      node = node.return;
    }
    node.sibling.return = node.return;
    node = node.sibling;
  }
}

function commitUnmount(fiber: Fiber, _root: FiberRoot): void {
  switch (fiber.tag) {
    case FunctionComponent:
    case ForwardRef:
    case MemoComponent:
    case SimpleMemoComponent: {
      // Unmount layout effects synchronously
      commitHookEffectListUnmount(HookLayout | HookHasEffect, fiber);
      // Schedule passive effect cleanup
      break;
    }
    case ClassComponent: {
      const instance = fiber.stateNode as ComponentInstance | null;
      if (instance !== null && typeof instance.componentWillUnmount === "function") {
        instance.componentWillUnmount();
      }
      break;
    }
  }

  // Detach ref
  commitDetachRef(fiber);
}

function commitDetachRef(fiber: Fiber): void {
  const ref = fiber.ref;
  if (ref !== null) {
    if (typeof ref === "function") {
      ref(null);
    } else if (typeof ref === "object") {
      (ref as { current: unknown }).current = null;
    }
  }
}

// ─── Layout Phase ───────────────────────────────────────────────────────

export function commitLayoutEffects(root: FiberRoot, finishedWork: Fiber): void {
  commitLayoutEffectsOnFiber(finishedWork, root);
}

function commitLayoutEffectsOnFiber(fiber: Fiber, root: FiberRoot): void {
  // Process children first
  let child = fiber.child;
  if ((fiber.subtreeFlags & LayoutMask) !== NoFlags && child !== null) {
    while (child !== null) {
      commitLayoutEffectsOnFiber(child, root);
      child = child.sibling;
    }
  }

  const flags = fiber.flags;

  if (flags & (Update | Ref)) {
    const current = fiber.alternate;

    switch (fiber.tag) {
      case FunctionComponent:
      case ForwardRef:
      case SimpleMemoComponent: {
        if (flags & Update) {
          commitHookEffectListMount(HookLayout | HookHasEffect, fiber);
        }
        break;
      }
      case ClassComponent: {
        if (flags & Update) {
          const instance = fiber.stateNode as ComponentInstance;
          if (current === null) {
            if (typeof instance.componentDidMount === "function") {
              instance.componentDidMount();
            }
          } else {
            if (typeof instance.componentDidUpdate === "function") {
              instance.componentDidUpdate(
                current.memoizedProps as Readonly<Record<string, unknown>>,
                current.memoizedState as Readonly<Record<string, unknown>>,
                (instance as unknown as Record<string, unknown>)["__snapshot"],
              );
            }
          }
        }
        break;
      }
      case HostComponent: {
        // Auto-focus if needed
        if (current === null && flags & Update) {
          const instance = fiber.stateNode as Element;
          if (
            (fiber.memoizedProps as Record<string, unknown> | null)?.["autoFocus"] &&
            typeof (instance as unknown as Record<string, unknown>)["focus"] === "function"
          ) {
            (
              instance as unknown as Record<string, unknown> & {
                focus: () => void;
              }
            ).focus();
          }
        }
        break;
      }
    }

    // Attach ref
    if (flags & Ref) {
      commitAttachRef(fiber);
    }
  }
}

function commitAttachRef(fiber: Fiber): void {
  const ref = fiber.ref;
  if (ref === null) return;

  const instance = fiber.stateNode;
  if (typeof ref === "function") {
    const cleanup = ref(instance);
    if (typeof cleanup === "function") {
      fiber.refCleanup = cleanup;
    }
  } else if (typeof ref === "object") {
    (ref as { current: unknown }).current = instance;
  }
}

// ─── Passive Effects ─────────────────────────────────────────────────────

export function commitPassiveUnmountEffects(fiber: Fiber): void {
  commitPassiveUnmountOnFiber(fiber);
}

function commitPassiveUnmountOnFiber(fiber: Fiber): void {
  let child = fiber.child;
  if ((fiber.subtreeFlags & PassiveMask) !== NoFlags && child !== null) {
    while (child !== null) {
      commitPassiveUnmountOnFiber(child);
      child = child.sibling;
    }
  }

  if ((fiber.flags & Passive) !== NoFlags) {
    switch (fiber.tag) {
      case FunctionComponent:
      case ForwardRef:
      case SimpleMemoComponent: {
        commitHookEffectListUnmount(HookPassive | HookHasEffect, fiber);
        break;
      }
    }
  }
}

export function commitPassiveMountEffects(root: FiberRoot, fiber: Fiber): void {
  commitPassiveMountOnFiber(root, fiber);
}

function commitPassiveMountOnFiber(root: FiberRoot, fiber: Fiber): void {
  let child = fiber.child;
  if ((fiber.subtreeFlags & PassiveMask) !== NoFlags && child !== null) {
    while (child !== null) {
      commitPassiveMountOnFiber(root, child);
      child = child.sibling;
    }
  }

  if ((fiber.flags & Passive) !== NoFlags) {
    switch (fiber.tag) {
      case FunctionComponent:
      case ForwardRef:
      case SimpleMemoComponent: {
        commitHookEffectListMount(HookPassive | HookHasEffect, fiber);
        break;
      }
    }
  }
}

// ─── Hook Effect Helpers ─────────────────────────────────────────────────

function commitHookEffectListMount(flags: number, fiber: Fiber): void {
  const updateQueue = fiber.updateQueue as FunctionComponentUpdateQueue | null;
  if (updateQueue === null) return;

  const lastEffect = updateQueue.lastEffect;
  if (lastEffect === null) return;

  const firstEffect = lastEffect.next;
  let effect: Effect | null = firstEffect;
  do {
    if (effect === null) break;
    if ((effect.tag & flags) === flags) {
      const create = effect.create;
      const destroy = create();
      effect.destroy = destroy;
    }
    effect = effect.next;
  } while (effect !== firstEffect);
}

function commitHookEffectListUnmount(flags: number, fiber: Fiber): void {
  const updateQueue = fiber.updateQueue as FunctionComponentUpdateQueue | null;
  if (updateQueue === null) return;

  const lastEffect = updateQueue.lastEffect;
  if (lastEffect === null) return;

  const firstEffect = lastEffect.next;
  let effect: Effect | null = firstEffect;
  do {
    if (effect === null) break;
    if ((effect.tag & flags) === flags) {
      const destroy = effect.destroy;
      effect.destroy = null;
      if (typeof destroy === "function") {
        destroy();
      }
    }
    effect = effect.next;
  } while (effect !== firstEffect);
}

// CompleteWork - Render phase up-traversal
// Creates host instances, appends children, bubbles subtreeFlags

import type { Fiber, FiberRoot } from "./ReactFiberTypes.js";
import type { Lanes } from "./ReactFiberLane.js";
import type { HostConfig } from "../host-config/HostConfigInterface.js";
import type { ReactContext } from "../react/ReactTypes.js";
import {
  ClassComponent,
  ContextProvider,
  ForwardRef,
  Fragment,
  FunctionComponent,
  HostComponent,
  HostRoot,
  HostText,
  LazyComponent,
  MemoComponent,
  SimpleMemoComponent,
  SuspenseComponent,
} from "./ReactWorkTags.js";
import { NoFlags, Ref, RefStatic, Update } from "./ReactFiberFlags.js";
import { popProvider } from "./ReactFiberNewContext.js";
import { getHostContext, popHostContainer, popHostContext } from "./ReactFiberHostContext.js";

function bubbleProperties(completedWork: Fiber): void {
  let subtreeFlags = NoFlags;
  let child = completedWork.child;

  while (child !== null) {
    subtreeFlags |= child.subtreeFlags;
    subtreeFlags |= child.flags;
    child.return = completedWork;
    child = child.sibling;
  }

  completedWork.subtreeFlags |= subtreeFlags;
}

function appendAllChildren(parent: unknown, workInProgress: Fiber, hostConfig: HostConfig): void {
  let node = workInProgress.child;
  while (node !== null) {
    if (node.tag === HostComponent || node.tag === HostText) {
      hostConfig.appendInitialChild(parent, node.stateNode);
    } else if (node.child !== null) {
      // Traverse down into composite components
      node.child.return = node;
      node = node.child;
      continue;
    }

    if (node === workInProgress) return;

    while (node.sibling === null) {
      if (node.return === null || node.return === workInProgress) return;
      node = node.return;
    }

    node.sibling.return = node.return;
    node = node.sibling;
  }
}

function markUpdate(workInProgress: Fiber): void {
  workInProgress.flags |= Update;
}

function markRef(workInProgress: Fiber): void {
  workInProgress.flags |= Ref | RefStatic;
}

export function completeWork(
  current: Fiber | null,
  workInProgress: Fiber,
  _renderLanes: Lanes,
): Fiber | null {
  const newProps = workInProgress.pendingProps;

  switch (workInProgress.tag) {
    case FunctionComponent:
    case ClassComponent:
    case Fragment:
    case ForwardRef:
    case MemoComponent:
    case SimpleMemoComponent:
    case LazyComponent:
      bubbleProperties(workInProgress);
      return null;

    case HostRoot: {
      popHostContainer(workInProgress);
      bubbleProperties(workInProgress);
      return null;
    }

    case HostComponent: {
      popHostContext(workInProgress);
      const hostContext = getHostContext();
      const type = workInProgress.type;

      // Get host config from root
      let root: Fiber | null = workInProgress;
      while (root !== null && root.tag !== HostRoot) {
        root = root.return;
      }
      const fiberRoot = root!.stateNode as FiberRoot;
      const hostConfig = fiberRoot.hostConfig;

      if (current !== null && workInProgress.stateNode != null) {
        // Update
        const oldProps = current.memoizedProps;
        if (oldProps !== newProps) {
          markUpdate(workInProgress);
        }
        if (current.ref !== workInProgress.ref) {
          markRef(workInProgress);
        }
      } else {
        // Mount - create the DOM instance
        const instance = hostConfig.createInstance(
          type as string,
          newProps as Record<string, unknown>,
          fiberRoot.containerInfo,
          hostContext,
        );

        appendAllChildren(instance, workInProgress, hostConfig);
        workInProgress.stateNode = instance;

        if (
          hostConfig.finalizeInitialChildren(
            instance,
            type as string,
            newProps as Record<string, unknown>,
            hostContext,
          )
        ) {
          markUpdate(workInProgress);
        }

        if (workInProgress.ref !== null) {
          markRef(workInProgress);
        }
      }

      bubbleProperties(workInProgress);
      return null;
    }

    case HostText: {
      const newText = newProps;

      let root: Fiber | null = workInProgress;
      while (root !== null && root.tag !== HostRoot) {
        root = root.return;
      }
      const fiberRoot = root!.stateNode as FiberRoot;
      const hostConfig = fiberRoot.hostConfig;

      if (current !== null && workInProgress.stateNode != null) {
        // Update
        const oldText = current.memoizedProps;
        if (oldText !== newText) {
          markUpdate(workInProgress);
        }
      } else {
        // Mount
        const textInstance = hostConfig.createTextInstance(
          newText as string,
          fiberRoot.containerInfo,
          getHostContext(),
        );
        workInProgress.stateNode = textInstance;
      }

      bubbleProperties(workInProgress);
      return null;
    }

    case ContextProvider: {
      const context = workInProgress.type;
      popProvider(context as ReactContext<unknown>);
      bubbleProperties(workInProgress);
      return null;
    }

    case SuspenseComponent: {
      bubbleProperties(workInProgress);
      return null;
    }

    default:
      bubbleProperties(workInProgress);
      return null;
  }
}

import type {
  Effect,
  Fiber,
  FiberRoot,
  FunctionComponentUpdateQueue,
  Hook,
  Update,
  UpdateQueue,
} from "./ReactFiberTypes.js";
import type { Lane, Lanes } from "./ReactFiberLane.js";
import type { Dispatcher, ReactContext } from "../react/ReactTypes.js";
import type { Flags } from "./ReactFiberFlags.js";
import {
  includesOnlyNonUrgentLanes,
  isSubsetOfLanes,
  mergeLanes,
  NoLane,
  NoLanes,
  removeLanes,
  SyncLane,
} from "./ReactFiberLane.js";
import {
  LayoutStatic as LayoutStaticEffect,
  Passive as PassiveEffect,
  PassiveStatic as PassiveStaticEffect,
  Update as UpdateEffect,
} from "./ReactFiberFlags.js";
import ReactSharedInternals from "../react/ReactSharedInternals.js";
import { REACT_CONTEXT_TYPE } from "../react/ReactSymbols.js";
import { prepareToReadContext, readContext } from "./ReactFiberNewContext.js";
import objectIs from "../shared/objectIs.js";
import { HostRoot } from "./ReactWorkTags.js";

// --- Hook Effect Tags ---
export const HookHasEffect = /*  */ 0b0001;
export const HookInsertion = /*  */ 0b0010;
export const HookLayout = /*  */ 0b0100;
export const HookPassive = /*  */ 0b1000;

// --- Effect Instance ---
interface EffectInstance {
  destroy: void | (() => void);
}

// --- Module-level state ---
let renderLanes: Lanes = NoLanes;
let currentlyRenderingFiber: Fiber = null as unknown as Fiber;
let currentHook: Hook | null = null;
let workInProgressHook: Hook | null = null;
let didScheduleRenderPhaseUpdateDuringThisPass: boolean = false;
let globalClientIdCounter: number = 0;

const RE_RENDER_LIMIT = 25;

// --- Exported functions for work loop interaction ---
// These will be set by the work loop to avoid circular dependencies
let scheduleUpdateOnFiberFn: ((root: FiberRoot, fiber: Fiber, lane: Lane) => void) | null = null;
let requestUpdateLaneFn: (() => Lane) | null = null;
let workInProgressRoot: FiberRoot | null = null;
let markWorkInProgressReceivedUpdateFn: (() => void) | null = null;

export function setHooksExternals(externals: {
  scheduleUpdateOnFiber: (root: FiberRoot, fiber: Fiber, lane: Lane) => void;
  requestUpdateLane: () => Lane;
  markWorkInProgressReceivedUpdate: () => void;
}): void {
  scheduleUpdateOnFiberFn = externals.scheduleUpdateOnFiber;
  requestUpdateLaneFn = externals.requestUpdateLane;
  markWorkInProgressReceivedUpdateFn = externals.markWorkInProgressReceivedUpdate;
}

export function setWorkInProgressRoot(root: FiberRoot | null, _lanes: Lanes): void {
  workInProgressRoot = root;
}

// --- Helper functions ---

function basicStateReducer<S>(state: S, action: S | ((s: S) => S)): S {
  return typeof action === "function" ? (action as (s: S) => S)(state) : action;
}

function areHookInputsEqual(nextDeps: Array<unknown>, prevDeps: Array<unknown> | null): boolean {
  if (prevDeps === null) {
    return false;
  }
  if (prevDeps.length !== nextDeps.length) {
    return false;
  }
  for (let i = 0; i < prevDeps.length && i < nextDeps.length; i++) {
    if (objectIs(nextDeps[i], prevDeps[i])) {
      continue;
    }
    return false;
  }
  return true;
}

function createEffectInstance(): EffectInstance {
  return { destroy: undefined };
}

function createFunctionComponentUpdateQueue(): FunctionComponentUpdateQueue {
  return {
    lastEffect: null,
    events: null,
    stores: null,
  };
}

// --- Hook infrastructure ---

function mountWorkInProgressHook(): Hook {
  const hook: Hook = {
    memoizedState: null,
    baseState: null,
    baseQueue: null,
    queue: null,
    next: null,
  };

  if (workInProgressHook === null) {
    currentlyRenderingFiber.memoizedState = workInProgressHook = hook;
  } else {
    workInProgressHook = workInProgressHook.next = hook;
  }
  return workInProgressHook;
}

function updateWorkInProgressHook(): Hook {
  let nextCurrentHook: Hook | null;
  if (currentHook === null) {
    const current = currentlyRenderingFiber.alternate;
    if (current !== null) {
      nextCurrentHook = current.memoizedState as Hook | null;
    } else {
      nextCurrentHook = null;
    }
  } else {
    nextCurrentHook = currentHook.next;
  }

  let nextWorkInProgressHook: Hook | null;
  if (workInProgressHook === null) {
    nextWorkInProgressHook = currentlyRenderingFiber.memoizedState as Hook | null;
  } else {
    nextWorkInProgressHook = workInProgressHook.next;
  }

  if (nextWorkInProgressHook !== null) {
    // Reuse existing work-in-progress hook
    workInProgressHook = nextWorkInProgressHook;
    nextWorkInProgressHook = workInProgressHook.next;
    currentHook = nextCurrentHook;
  } else {
    // Clone from current hook
    if (nextCurrentHook === null) {
      throw new Error("Rendered more hooks than during the previous render.");
    }

    currentHook = nextCurrentHook;

    const newHook: Hook = {
      memoizedState: currentHook.memoizedState,
      baseState: currentHook.baseState,
      baseQueue: currentHook.baseQueue,
      queue: currentHook.queue,
      next: null,
    };

    if (workInProgressHook === null) {
      currentlyRenderingFiber.memoizedState = workInProgressHook = newHook;
    } else {
      workInProgressHook = workInProgressHook.next = newHook;
    }
  }
  return workInProgressHook;
}

// --- Effect push ---

function pushSimpleEffect(
  tag: number,
  inst: EffectInstance,
  create: () => (() => void) | void,
  deps: Array<unknown> | null,
): Effect {
  const effect: Effect = {
    tag,
    create,
    destroy: inst.destroy ?? null,
    deps,
    next: null,
  };
  return pushEffectImpl(effect);
}

function pushEffectImpl(effect: Effect): Effect {
  let componentUpdateQueue: FunctionComponentUpdateQueue | null =
    currentlyRenderingFiber.updateQueue as unknown as FunctionComponentUpdateQueue | null;
  if (componentUpdateQueue === null) {
    componentUpdateQueue = createFunctionComponentUpdateQueue();
    currentlyRenderingFiber.updateQueue = componentUpdateQueue;
  }
  const lastEffect = componentUpdateQueue.lastEffect;
  if (lastEffect === null) {
    componentUpdateQueue.lastEffect = effect.next = effect;
  } else {
    const firstEffect = lastEffect.next;
    lastEffect.next = effect;
    effect.next = firstEffect;
    componentUpdateQueue.lastEffect = effect;
  }
  return effect;
}

// --- Update queue helpers ---

function isRenderPhaseUpdate(fiber: Fiber): boolean {
  const alternate = fiber.alternate;
  return (
    fiber === currentlyRenderingFiber ||
    (alternate !== null && alternate === currentlyRenderingFiber)
  );
}

function enqueueRenderPhaseUpdate<S, A>(queue: UpdateQueue<S, A>, update: Update<S, A>): void {
  didScheduleRenderPhaseUpdateDuringThisPass = true;
  const pending = queue.pending;
  if (pending === null) {
    update.next = update;
  } else {
    update.next = pending.next;
    pending.next = update;
  }
  queue.pending = update;
}

function enqueueUpdate<S, A>(
  fiber: Fiber,
  queue: UpdateQueue<S, A>,
  update: Update<S, A>,
  lane: Lane,
): FiberRoot | null {
  // Concurrent update: append to the queue
  const pending = queue.pending;
  if (pending === null) {
    update.next = update;
  } else {
    update.next = pending.next;
    pending.next = update;
  }
  queue.pending = update;

  // Mark the fiber and its return path with lanes
  return markUpdateLaneFromFiberToRoot(fiber, lane);
}

function markUpdateLaneFromFiberToRoot(fiber: Fiber, lane: Lane): FiberRoot | null {
  fiber.lanes = mergeLanes(fiber.lanes, lane);
  const alternate = fiber.alternate;
  if (alternate !== null) {
    alternate.lanes = mergeLanes(alternate.lanes, lane);
  }

  // Walk to root
  let node = fiber.return;
  let root: FiberRoot | null = null;
  if (node === null && fiber.tag === HostRoot) {
    root = fiber.stateNode as FiberRoot;
  } else {
    while (node !== null) {
      node.childLanes = mergeLanes(node.childLanes, lane);
      const nodeAlternate = node.alternate;
      if (nodeAlternate !== null) {
        nodeAlternate.childLanes = mergeLanes(nodeAlternate.childLanes, lane);
      }
      if (node.return === null && node.tag === HostRoot) {
        root = node.stateNode as FiberRoot;
        break;
      }
      node = node.return;
    }
  }
  return root;
}

// --- State hooks ---

function mountStateImpl<S>(initialState: (() => S) | S): Hook {
  const hook = mountWorkInProgressHook();
  if (typeof initialState === "function") {
    initialState = (initialState as () => S)();
  }
  hook.memoizedState = hook.baseState = initialState;
  const queue: UpdateQueue<S, S | ((s: S) => S)> = {
    pending: null,
    lanes: NoLanes,
    dispatch: null,
    lastRenderedReducer: basicStateReducer,
    lastRenderedState: initialState,
  };
  hook.queue = queue as unknown as UpdateQueue<unknown, unknown>;
  return hook;
}

function mountState<S>(initialState: (() => S) | S): [S, (action: S | ((s: S) => S)) => void] {
  const hook = mountStateImpl(initialState);
  const queue = hook.queue!;
  const dispatch = dispatchSetState.bind(null, currentlyRenderingFiber, queue) as unknown as (
    action: S | ((s: S) => S),
  ) => void;
  queue.dispatch = dispatch as unknown as ((action: unknown) => void) | null;
  return [hook.memoizedState as S, dispatch];
}

function updateState<S>(_initialState: (() => S) | S): [S, (action: S | ((s: S) => S)) => void] {
  return updateReducer(
    basicStateReducer as unknown as (state: S, action: S | ((s: S) => S)) => S,
    _initialState as unknown as S,
  );
}

function mountReducer<S, I, A>(
  reducer: (state: S, action: A) => S,
  initialArg: I,
  init?: (arg: I) => S,
): [S, (action: A) => void] {
  const hook = mountWorkInProgressHook();
  let initialState: S;
  if (init !== undefined) {
    initialState = init(initialArg);
  } else {
    initialState = initialArg as unknown as S;
  }
  hook.memoizedState = hook.baseState = initialState;
  const queue: UpdateQueue<S, A> = {
    pending: null,
    lanes: NoLanes,
    dispatch: null,
    lastRenderedReducer: reducer,
    lastRenderedState: initialState,
  };
  hook.queue = queue as unknown as UpdateQueue<unknown, unknown>;
  const dispatch = dispatchReducerAction.bind(
    null,
    currentlyRenderingFiber,
    queue as unknown as UpdateQueue<unknown, unknown>,
  ) as unknown as (action: A) => void;
  queue.dispatch = dispatch as unknown as ((action: A) => void) | null;
  return [hook.memoizedState as S, dispatch];
}

function updateReducer<S, I, A>(
  reducer: (state: S, action: A) => S,
  _initialArg: I,
  _init?: (arg: I) => S,
): [S, (action: A) => void] {
  const hook = updateWorkInProgressHook();
  return updateReducerImpl(hook, currentHook as Hook, reducer);
}

function updateReducerImpl<S, A>(
  hook: Hook,
  current: Hook,
  reducer: (state: S, action: A) => S,
): [S, (action: A) => void] {
  const queue = hook.queue! as unknown as UpdateQueue<S, A>;
  queue.lastRenderedReducer = reducer;

  let baseQueue = hook.baseQueue as Update<S, A> | null;
  const pendingQueue = queue.pending;

  if (pendingQueue !== null) {
    // Merge pending queue and base queue
    if (baseQueue !== null) {
      const baseFirst = baseQueue.next;
      const pendingFirst = pendingQueue.next;
      baseQueue.next = pendingFirst;
      pendingQueue.next = baseFirst;
    }
    current.baseQueue = baseQueue = pendingQueue;
    queue.pending = null;
  }

  const baseState = hook.baseState as S;
  if (baseQueue === null) {
    hook.memoizedState = baseState;
  } else {
    const first = baseQueue.next;
    let newState: S = baseState;

    let newBaseState: S | null = null;
    let newBaseQueueFirst: Update<S, A> | null = null;
    let newBaseQueueLast: Update<S, A> | null = null;
    let update = first;

    do {
      const updateLane = update!.lane;

      if (!isSubsetOfLanes(renderLanes, updateLane)) {
        // Priority is insufficient. Skip this update.
        const clone: Update<S, A> = {
          lane: updateLane,
          action: update!.action,
          hasEagerState: update!.hasEagerState,
          eagerState: update!.eagerState,
          next: null,
        };
        if (newBaseQueueLast === null) {
          newBaseQueueFirst = newBaseQueueLast = clone;
          newBaseState = newState;
        } else {
          newBaseQueueLast.next = clone;
          newBaseQueueLast = clone;
        }
        currentlyRenderingFiber.lanes = mergeLanes(currentlyRenderingFiber.lanes, updateLane);
      } else {
        // This update has sufficient priority.
        if (newBaseQueueLast !== null) {
          const clone: Update<S, A> = {
            lane: NoLane,
            action: update!.action,
            hasEagerState: update!.hasEagerState,
            eagerState: update!.eagerState,
            next: null,
          };
          newBaseQueueLast.next = clone;
          newBaseQueueLast = clone;
        }

        // Process the update
        const action = update!.action;
        if (update!.hasEagerState) {
          newState = update!.eagerState as S;
        } else {
          newState = reducer(newState, action);
        }
      }
      update = update!.next;
    } while (update !== null && update !== first);

    if (newBaseQueueLast === null) {
      newBaseState = newState;
    } else {
      newBaseQueueLast.next = newBaseQueueFirst!;
    }

    if (!objectIs(newState, hook.memoizedState)) {
      markWorkInProgressReceivedUpdateFn?.();
    }

    hook.memoizedState = newState;
    hook.baseState = newBaseState as S;
    hook.baseQueue = newBaseQueueLast;
    queue.lastRenderedState = newState;
  }

  const dispatch = queue.dispatch!;
  return [hook.memoizedState as S, dispatch];
}

// --- Ref hooks ---

function mountRef<T>(initialValue: T): { current: T } {
  const hook = mountWorkInProgressHook();
  const ref = { current: initialValue };
  hook.memoizedState = ref;
  return ref;
}

function updateRef<T>(_initialValue: T): { current: T } {
  const hook = updateWorkInProgressHook();
  return hook.memoizedState as { current: T };
}

// --- Effect hooks ---

function mountEffectImpl(
  fiberFlags: Flags,
  hookFlags: number,
  create: () => (() => void) | void,
  deps: Array<unknown> | void | null,
): void {
  const hook = mountWorkInProgressHook();
  const nextDeps = (deps === undefined ? null : deps) as Array<unknown> | null;
  currentlyRenderingFiber.flags |= fiberFlags;
  hook.memoizedState = pushSimpleEffect(
    HookHasEffect | hookFlags,
    createEffectInstance(),
    create,
    nextDeps as Array<unknown> | null,
  );
}

function updateEffectImpl(
  fiberFlags: Flags,
  hookFlags: number,
  create: () => (() => void) | void,
  deps: Array<unknown> | void | null,
): void {
  const hook = updateWorkInProgressHook();
  const nextDeps = (deps === undefined ? null : deps) as Array<unknown> | null;
  const effect: Effect = hook.memoizedState as Effect;
  const inst = createEffectInstance();
  inst.destroy = effect.destroy as unknown as void | (() => void);

  if (currentHook !== null) {
    if (nextDeps !== null) {
      const prevEffect: Effect = currentHook.memoizedState as Effect;
      const prevDeps = prevEffect.deps;
      if (areHookInputsEqual(nextDeps as Array<unknown>, prevDeps)) {
        hook.memoizedState = pushSimpleEffect(
          hookFlags,
          inst,
          create,
          nextDeps as Array<unknown> | null,
        );
        return;
      }
    }
  }

  currentlyRenderingFiber.flags |= fiberFlags;
  hook.memoizedState = pushSimpleEffect(
    HookHasEffect | hookFlags,
    inst,
    create,
    nextDeps as Array<unknown> | null,
  );
}

function mountEffect(create: () => (() => void) | void, deps?: Array<unknown> | null): void {
  mountEffectImpl(PassiveEffect | PassiveStaticEffect, HookPassive, create, deps);
}

function updateEffect(create: () => (() => void) | void, deps?: Array<unknown> | null): void {
  updateEffectImpl(PassiveEffect, HookPassive, create, deps);
}

function mountLayoutEffect(create: () => (() => void) | void, deps?: Array<unknown> | null): void {
  mountEffectImpl(UpdateEffect | LayoutStaticEffect, HookLayout, create, deps);
}

function updateLayoutEffect(create: () => (() => void) | void, deps?: Array<unknown> | null): void {
  updateEffectImpl(UpdateEffect, HookLayout, create, deps);
}

function mountInsertionEffect(
  create: () => (() => void) | void,
  deps?: Array<unknown> | null,
): void {
  mountEffectImpl(UpdateEffect, HookInsertion, create, deps);
}

function updateInsertionEffect(
  create: () => (() => void) | void,
  deps?: Array<unknown> | null,
): void {
  updateEffectImpl(UpdateEffect, HookInsertion, create, deps);
}

// --- Imperative Handle ---

function imperativeHandleEffect<T>(
  create: () => T,
  ref: { current: T | null } | ((inst: T | null) => void) | null | undefined,
): void | (() => void) {
  if (typeof ref === "function") {
    const refCallback = ref;
    const inst = create();
    refCallback(inst);
    return () => {
      refCallback(null);
    };
  } else if (ref !== null && ref !== undefined) {
    const refObject = ref;
    const inst = create();
    refObject.current = inst;
    return () => {
      refObject.current = null;
    };
  }
}

function mountImperativeHandle<T>(
  ref: { current: T | null } | ((inst: T | null) => void) | null | undefined,
  create: () => T,
  deps?: Array<unknown> | null,
): void {
  const effectDeps = deps !== null && deps !== undefined ? deps.concat([ref]) : null;
  mountEffectImpl(
    UpdateEffect | LayoutStaticEffect,
    HookLayout,
    (imperativeHandleEffect<T>).bind(null, create, ref) as unknown as () => (() => void) | void,
    effectDeps as Array<unknown> | null,
  );
}

function updateImperativeHandle<T>(
  ref: { current: T | null } | ((inst: T | null) => void) | null | undefined,
  create: () => T,
  deps?: Array<unknown> | null,
): void {
  const effectDeps = deps !== null && deps !== undefined ? deps.concat([ref]) : null;
  updateEffectImpl(
    UpdateEffect,
    HookLayout,
    (imperativeHandleEffect<T>).bind(null, create, ref) as unknown as () => (() => void) | void,
    effectDeps as Array<unknown> | null,
  );
}

// --- Callback and Memo hooks ---

function mountCallback<T>(callback: T, deps: Array<unknown> | void | null): T {
  const hook = mountWorkInProgressHook();
  const nextDeps = (deps === undefined ? null : deps) as Array<unknown> | null;
  hook.memoizedState = [callback, nextDeps];
  return callback;
}

function updateCallback<T>(callback: T, deps: Array<unknown> | void | null): T {
  const hook = updateWorkInProgressHook();
  const nextDeps = (deps === undefined ? null : deps) as Array<unknown> | null;
  const prevState = hook.memoizedState as [T, Array<unknown> | null];
  if (nextDeps !== null) {
    const prevDeps: Array<unknown> | null = prevState[1];
    if (areHookInputsEqual(nextDeps as Array<unknown>, prevDeps)) {
      return prevState[0];
    }
  }
  hook.memoizedState = [callback, nextDeps];
  return callback;
}

function mountMemo<T>(nextCreate: () => T, deps: Array<unknown> | void | null): T {
  const hook = mountWorkInProgressHook();
  const nextDeps = (deps === undefined ? null : deps) as Array<unknown> | null;
  const nextValue = nextCreate();
  hook.memoizedState = [nextValue, nextDeps];
  return nextValue;
}

function updateMemo<T>(nextCreate: () => T, deps: Array<unknown> | void | null): T {
  const hook = updateWorkInProgressHook();
  const nextDeps = (deps === undefined ? null : deps) as Array<unknown> | null;
  const prevState = hook.memoizedState as [T, Array<unknown> | null];
  if (nextDeps !== null) {
    const prevDeps: Array<unknown> | null = prevState[1];
    if (areHookInputsEqual(nextDeps as Array<unknown>, prevDeps)) {
      return prevState[0];
    }
  }
  const nextValue = nextCreate();
  hook.memoizedState = [nextValue, nextDeps];
  return nextValue;
}

// --- Context hook ---

function mountContext<T>(context: ReactContext<T>): T {
  return readContext(context);
}

function updateContext<T>(context: ReactContext<T>): T {
  return readContext(context);
}

// --- Deferred Value hook ---

function mountDeferredValue<T>(value: T, _initialValue?: T): T {
  const hook = mountWorkInProgressHook();
  hook.memoizedState = value;
  return value;
}

function updateDeferredValue<T>(value: T, _initialValue?: T): T {
  const hook = updateWorkInProgressHook();
  const prevValue: T = (currentHook as Hook).memoizedState as T;
  if (objectIs(value, prevValue)) {
    return value;
  }
  // Check if this is a non-urgent update; if so, defer
  if (!includesOnlyNonUrgentLanes(renderLanes)) {
    // Urgent update - keep previous value
    hook.memoizedState = prevValue;
    return prevValue;
  }
  // Non-urgent update - use new value
  markWorkInProgressReceivedUpdateFn?.();
  hook.memoizedState = value;
  return value;
}

// --- Transition hook ---

function mountTransition(): [boolean, (callback: () => void) => void] {
  const stateHook = mountStateImpl(false as boolean);
  const start = startTransition.bind(null, currentlyRenderingFiber, stateHook.queue!, true, false);
  const hook = mountWorkInProgressHook();
  hook.memoizedState = start;
  return [false, start];
}

function updateTransition(): [boolean, (callback: () => void) => void] {
  const [booleanOrThenable] = updateState(false);
  const hook = updateWorkInProgressHook();
  const start = hook.memoizedState as (callback: () => void) => void;
  const isPending = typeof booleanOrThenable === "boolean" ? booleanOrThenable : false;
  return [isPending, start];
}

function startTransition(
  fiber: Fiber,
  queue: UpdateQueue<unknown, unknown>,
  pendingState: unknown,
  finishedState: unknown,
  callback: () => void,
): void {
  const lane = requestUpdateLaneFn?.() ?? SyncLane;

  // Set pending state
  const pendingUpdate: Update<unknown, unknown> = {
    lane,
    action: pendingState,
    hasEagerState: false,
    eagerState: null,
    next: null,
  };

  if (isRenderPhaseUpdate(fiber)) {
    enqueueRenderPhaseUpdate(queue, pendingUpdate);
  } else {
    const root = enqueueUpdate(fiber, queue, pendingUpdate, lane);
    if (root !== null) {
      if (!scheduleUpdateOnFiberFn) {
        throw new Error(
          "ReactFiberHooks: scheduleUpdateOnFiberFn not initialized. Call setHooksExternals() first.",
        );
      }
      scheduleUpdateOnFiberFn(root, fiber, lane);
    }
  }

  try {
    callback();
  } finally {
    // Set finished state
    const finishedUpdate: Update<unknown, unknown> = {
      lane,
      action: finishedState,
      hasEagerState: false,
      eagerState: null,
      next: null,
    };

    if (isRenderPhaseUpdate(fiber)) {
      enqueueRenderPhaseUpdate(queue, finishedUpdate);
    } else {
      const root = enqueueUpdate(fiber, queue, finishedUpdate, lane);
      if (root !== null) {
        if (!scheduleUpdateOnFiberFn) {
          throw new Error(
            "ReactFiberHooks: scheduleUpdateOnFiberFn not initialized. Call setHooksExternals() first.",
          );
        }
        scheduleUpdateOnFiberFn(root, fiber, lane);
      }
    }
  }
}

// --- SyncExternalStore hook ---

function subscribeToStore<T>(
  fiber: Fiber,
  inst: { value: T; getSnapshot: () => T },
  subscribe: (onStoreChange: () => void) => () => void,
): () => void {
  const handleStoreChange = () => {
    // Check if the value changed
    if (checkIfSnapshotChanged(inst)) {
      // Force a re-render
      const lane = SyncLane;
      const root = markUpdateLaneFromFiberToRoot(fiber, lane);
      if (root !== null) {
        if (!scheduleUpdateOnFiberFn) {
          throw new Error(
            "ReactFiberHooks: scheduleUpdateOnFiberFn not initialized. Call setHooksExternals() first.",
          );
        }
        scheduleUpdateOnFiberFn(root, fiber, lane);
      }
    }
  };
  return subscribe(handleStoreChange);
}

function checkIfSnapshotChanged<T>(inst: { value: T; getSnapshot: () => T }): boolean {
  const latestGetSnapshot = inst.getSnapshot;
  const prevValue = inst.value;
  try {
    const nextValue = latestGetSnapshot();
    return !objectIs(prevValue, nextValue);
  } catch {
    return true;
  }
}

function mountSyncExternalStore<T>(
  subscribe: (onStoreChange: () => void) => () => void,
  getSnapshot: () => T,
  _getServerSnapshot?: () => T,
): T {
  const fiber = currentlyRenderingFiber;
  const hook = mountWorkInProgressHook();

  const nextSnapshot = getSnapshot();
  hook.memoizedState = nextSnapshot;

  const inst = {
    value: nextSnapshot,
    getSnapshot,
  };
  hook.queue = inst as unknown as UpdateQueue<unknown, unknown>;

  // Subscribe effect
  mountEffect(
    subscribeToStore.bind(null, fiber, inst, subscribe) as unknown as () => (() => void) | void,
    [subscribe],
  );

  // Update store instance effect
  fiber.flags |= PassiveEffect;
  pushSimpleEffect(
    HookHasEffect | HookPassive,
    createEffectInstance(),
    updateStoreInstance.bind(null, fiber, inst, nextSnapshot, getSnapshot),
    null,
  );

  return nextSnapshot;
}

function updateStoreInstance<T>(
  _fiber: Fiber,
  inst: { value: T; getSnapshot: () => T },
  nextSnapshot: T,
  getSnapshot: () => T,
): void {
  inst.value = nextSnapshot;
  inst.getSnapshot = getSnapshot;
}

function updateSyncExternalStore<T>(
  subscribe: (onStoreChange: () => void) => () => void,
  getSnapshot: () => T,
  _getServerSnapshot?: () => T,
): T {
  const fiber = currentlyRenderingFiber;
  const hook = updateWorkInProgressHook();

  const nextSnapshot = getSnapshot();
  const prevSnapshot = (currentHook || hook).memoizedState;
  const snapshotChanged = !objectIs(prevSnapshot, nextSnapshot);

  if (snapshotChanged) {
    hook.memoizedState = nextSnapshot;
    markWorkInProgressReceivedUpdateFn?.();
  }

  const inst = hook.queue as unknown as { value: T; getSnapshot: () => T };
  updateEffect(
    subscribeToStore.bind(null, fiber, inst, subscribe) as unknown as () => (() => void) | void,
    [subscribe],
  );

  if (inst.getSnapshot !== getSnapshot || snapshotChanged) {
    fiber.flags |= PassiveEffect;
    pushSimpleEffect(
      HookHasEffect | HookPassive,
      createEffectInstance(),
      updateStoreInstance.bind(null, fiber, inst, nextSnapshot, getSnapshot),
      null,
    );
  }

  return nextSnapshot;
}

// --- Id hook ---

function mountId(): string {
  const hook = mountWorkInProgressHook();

  const root = workInProgressRoot;
  const identifierPrefix = root ? root.identifierPrefix : "";
  const globalClientId = globalClientIdCounter++;
  const id = "_" + identifierPrefix + "r_" + globalClientId.toString(32) + "_";

  hook.memoizedState = id;
  return id;
}

function updateId(): string {
  const hook = updateWorkInProgressHook();
  return hook.memoizedState as string;
}

// --- Debug Value ---

function mountDebugValue<T>(_value: T, _formatterFn?: (value: T) => unknown): void {
  // No-op
}

const updateDebugValue = mountDebugValue;

// --- use hook ---

function use<T>(usable: unknown): T {
  if (usable !== null && typeof usable === "object") {
    const obj = usable as Record<string, unknown>;
    if (typeof obj["then"] === "function") {
      throw usable; // Suspend (throw the thenable)
    } else if (obj["$$typeof"] === REACT_CONTEXT_TYPE) {
      return readContext(usable as ReactContext<T>);
    }
  }
  throw new Error("An unsupported type was passed to use(): " + String(usable));
}

// --- Optimistic hook (simplified) ---

function mountOptimistic<S, A>(
  passthrough: S,
  _reducer?: (state: S, action: A) => S,
): [S, (action: A) => void] {
  const hook = mountWorkInProgressHook();
  hook.memoizedState = hook.baseState = passthrough;
  const queue: UpdateQueue<S, A> = {
    pending: null,
    lanes: NoLanes,
    dispatch: null,
    lastRenderedReducer: null,
    lastRenderedState: null,
  };
  hook.queue = queue as unknown as UpdateQueue<unknown, unknown>;
  const dispatch = ((action: A) => {
    // Simplified: dispatch optimistic update
    dispatchSetState(currentlyRenderingFiber, queue, action);
  }) as (action: A) => void;
  queue.dispatch = dispatch as unknown as ((action: A) => void) | null;
  return [passthrough, dispatch];
}

function updateOptimistic<S, A>(
  passthrough: S,
  reducer?: (state: S, action: A) => S,
): [S, (action: A) => void] {
  const hook = updateWorkInProgressHook();
  hook.baseState = passthrough;
  const resolvedReducer =
    typeof reducer === "function"
      ? reducer
      : (basicStateReducer as unknown as (state: S, action: A) => S);
  return updateReducerImpl(hook, currentHook as Hook, resolvedReducer);
}

// --- Action State (simplified) ---

function mountActionState<S, P>(
  _action: (state: Awaited<S>, payload: P) => S,
  initialState: Awaited<S>,
  _permalink?: string,
): [Awaited<S>, (payload: P) => void, boolean] {
  const stateHook = mountWorkInProgressHook();
  stateHook.memoizedState = stateHook.baseState = initialState;

  const stateQueue: UpdateQueue<unknown, unknown> = {
    pending: null,
    lanes: NoLanes,
    dispatch: null,
    lastRenderedReducer: basicStateReducer,
    lastRenderedState: initialState,
  };
  stateHook.queue = stateQueue;
  const dispatch = dispatchSetState.bind(null, currentlyRenderingFiber, stateQueue) as unknown as (
    payload: P,
  ) => void;
  stateQueue.dispatch = dispatch as unknown as (action: unknown) => void;

  // pending hook
  const pendingHook = mountWorkInProgressHook();
  pendingHook.memoizedState = false;

  // action hook
  const actionHook = mountWorkInProgressHook();
  actionHook.memoizedState = _action;

  return [initialState, dispatch, false];
}

function updateActionState<S, P>(
  _action: (state: Awaited<S>, payload: P) => S,
  _initialState: Awaited<S>,
  _permalink?: string,
): [Awaited<S>, (payload: P) => void, boolean] {
  const [state, dispatch] = updateReducer(
    basicStateReducer as unknown as (state: Awaited<S>, action: unknown) => Awaited<S>,
    null,
  );
  // pending
  const [isPending] = updateReducer(
    basicStateReducer as unknown as (state: boolean, action: unknown) => boolean,
    null,
  );
  // action
  const actionHook = updateWorkInProgressHook();
  actionHook.memoizedState = _action;

  return [state as Awaited<S>, dispatch, !!isPending];
}

// --- Dispatch functions ---

function dispatchSetState<S, A>(fiber: Fiber, queue: UpdateQueue<S, A>, action: A): void {
  const lane = requestUpdateLaneFn?.() ?? SyncLane;

  const update: Update<S, A> = {
    lane,
    action,
    hasEagerState: false,
    eagerState: null,
    next: null,
  };

  if (isRenderPhaseUpdate(fiber)) {
    enqueueRenderPhaseUpdate(queue, update);
  } else {
    // Try eager state computation
    const alternate = fiber.alternate;
    if (fiber.lanes === NoLanes && (alternate === null || alternate.lanes === NoLanes)) {
      const lastRenderedReducer = queue.lastRenderedReducer;
      if (lastRenderedReducer !== null) {
        try {
          const currentState: S = queue.lastRenderedState as S;
          const eagerState = lastRenderedReducer(currentState, action);
          update.hasEagerState = true;
          update.eagerState = eagerState;
          if (objectIs(eagerState, currentState)) {
            // Fast path: bail out without scheduling
            // Still enqueue the update in case we need to rebase later
            enqueueUpdate(fiber, queue, update, lane);
            return;
          }
        } catch {
          // Suppress the error, it will throw again in render
        }
      }
    }

    const root = enqueueUpdate(fiber, queue, update, lane);
    if (root !== null && scheduleUpdateOnFiberFn) {
      scheduleUpdateOnFiberFn(root, fiber, lane);
    }
  }
}

function dispatchReducerAction<S, A>(fiber: Fiber, queue: UpdateQueue<S, A>, action: A): void {
  const lane = requestUpdateLaneFn?.() ?? SyncLane;

  const update: Update<S, A> = {
    lane,
    action,
    hasEagerState: false,
    eagerState: null,
    next: null,
  };

  if (isRenderPhaseUpdate(fiber)) {
    enqueueRenderPhaseUpdate(queue, update);
  } else {
    const root = enqueueUpdate(fiber, queue, update, lane);
    if (root !== null && scheduleUpdateOnFiberFn) {
      scheduleUpdateOnFiberFn(root, fiber, lane);
    }
  }
}

// --- Dispatchers ---

const HooksDispatcherOnMount: Dispatcher = {
  useState: mountState,
  useReducer: mountReducer as unknown as Dispatcher["useReducer"],
  useEffect: mountEffect,
  useLayoutEffect: mountLayoutEffect,
  useInsertionEffect: mountInsertionEffect,
  useCallback: mountCallback as unknown as Dispatcher["useCallback"],
  useMemo: mountMemo as unknown as Dispatcher["useMemo"],
  useRef: mountRef,
  useContext: mountContext,
  useImperativeHandle: mountImperativeHandle as unknown as Dispatcher["useImperativeHandle"],
  useDebugValue: mountDebugValue,
  useDeferredValue: mountDeferredValue,
  useTransition: mountTransition,
  useSyncExternalStore: mountSyncExternalStore,
  useId: mountId,
  use,
  useOptimistic: mountOptimistic as unknown as Dispatcher["useOptimistic"],
  useActionState: mountActionState as unknown as Dispatcher["useActionState"],
};

const HooksDispatcherOnUpdate: Dispatcher = {
  useState: updateState,
  useReducer: updateReducer as unknown as Dispatcher["useReducer"],
  useEffect: updateEffect,
  useLayoutEffect: updateLayoutEffect,
  useInsertionEffect: updateInsertionEffect,
  useCallback: updateCallback as unknown as Dispatcher["useCallback"],
  useMemo: updateMemo as unknown as Dispatcher["useMemo"],
  useRef: updateRef,
  useContext: updateContext,
  useImperativeHandle: updateImperativeHandle as unknown as Dispatcher["useImperativeHandle"],
  useDebugValue: updateDebugValue,
  useDeferredValue: updateDeferredValue,
  useTransition: updateTransition,
  useSyncExternalStore: updateSyncExternalStore,
  useId: updateId,
  use,
  useOptimistic: updateOptimistic as unknown as Dispatcher["useOptimistic"],
  useActionState: updateActionState as unknown as Dispatcher["useActionState"],
};

const ContextOnlyDispatcher: Dispatcher = {
  useState: throwInvalidHookError as unknown as Dispatcher["useState"],
  useReducer: throwInvalidHookError as unknown as Dispatcher["useReducer"],
  useEffect: throwInvalidHookError as unknown as Dispatcher["useEffect"],
  useLayoutEffect: throwInvalidHookError as unknown as Dispatcher["useLayoutEffect"],
  useInsertionEffect: throwInvalidHookError as unknown as Dispatcher["useInsertionEffect"],
  useCallback: throwInvalidHookError as unknown as Dispatcher["useCallback"],
  useMemo: throwInvalidHookError as unknown as Dispatcher["useMemo"],
  useRef: throwInvalidHookError as unknown as Dispatcher["useRef"],
  useContext: throwInvalidHookError as unknown as Dispatcher["useContext"],
  useImperativeHandle: throwInvalidHookError as unknown as Dispatcher["useImperativeHandle"],
  useDebugValue: throwInvalidHookError as unknown as Dispatcher["useDebugValue"],
  useDeferredValue: throwInvalidHookError as unknown as Dispatcher["useDeferredValue"],
  useTransition: throwInvalidHookError as unknown as Dispatcher["useTransition"],
  useSyncExternalStore: throwInvalidHookError as unknown as Dispatcher["useSyncExternalStore"],
  useId: throwInvalidHookError as unknown as Dispatcher["useId"],
  use: throwInvalidHookError as unknown as Dispatcher["use"],
  useOptimistic: throwInvalidHookError as unknown as Dispatcher["useOptimistic"],
  useActionState: throwInvalidHookError as unknown as Dispatcher["useActionState"],
};

function throwInvalidHookError(): never {
  throw new Error(
    "Invalid hook call. Hooks can only be called inside of the body of a function component.",
  );
}

// --- renderWithHooks ---

export function renderWithHooks<Props>(
  current: Fiber | null,
  workInProgress: Fiber,
  Component: (props: Props, secondArg?: unknown) => unknown,
  props: Props,
  secondArg: unknown,
  nextRenderLanes: Lanes,
): unknown {
  renderLanes = nextRenderLanes;
  currentlyRenderingFiber = workInProgress;

  workInProgress.memoizedState = null;
  workInProgress.updateQueue = null;
  workInProgress.lanes = NoLanes;

  prepareToReadContext(workInProgress, nextRenderLanes);

  // Set dispatcher based on mount vs update
  ReactSharedInternals.H =
    current === null || current.memoizedState === null
      ? HooksDispatcherOnMount
      : HooksDispatcherOnUpdate;

  let children = Component(props, secondArg);

  // Check for render phase updates
  if (didScheduleRenderPhaseUpdateDuringThisPass) {
    children = renderWithHooksAgain(workInProgress, Component, props, secondArg);
  }

  finishRenderingHooks(current, workInProgress);

  return children;
}

function renderWithHooksAgain<Props>(
  workInProgress: Fiber,
  Component: (props: Props, secondArg?: unknown) => unknown,
  props: Props,
  secondArg: unknown,
): unknown {
  let children;
  let numberOfReRenders = 0;

  do {
    didScheduleRenderPhaseUpdateDuringThisPass = false;

    if (numberOfReRenders >= RE_RENDER_LIMIT) {
      throw new Error(
        "Too many re-renders. React limits the number of renders to prevent " + "an infinite loop.",
      );
    }

    numberOfReRenders += 1;

    // Start over from the beginning of the list
    currentHook = null;
    workInProgressHook = null;

    workInProgress.updateQueue = null;

    ReactSharedInternals.H = HooksDispatcherOnUpdate;

    children = Component(props, secondArg);
  } while (didScheduleRenderPhaseUpdateDuringThisPass);

  return children;
}

function finishRenderingHooks(_current: Fiber | null, _workInProgress: Fiber): void {
  ReactSharedInternals.H = ContextOnlyDispatcher;

  renderLanes = NoLanes;
  currentlyRenderingFiber = null as unknown as Fiber;

  currentHook = null;
  workInProgressHook = null;
}

// --- Bailout hooks ---

export function bailoutHooks(current: Fiber, workInProgress: Fiber, lanes: Lanes): void {
  workInProgress.updateQueue = current.updateQueue;
  workInProgress.flags &= ~(PassiveEffect | UpdateEffect);
  current.lanes = removeLanes(current.lanes, lanes);
}

// Export for use by work loop
export function resetHooksAfterThrow(): void {
  currentlyRenderingFiber = null as unknown as Fiber;
  currentHook = null;
  workInProgressHook = null;
  didScheduleRenderPhaseUpdateDuringThisPass = false;
  ReactSharedInternals.H = ContextOnlyDispatcher;
}

import type { ReactContext } from "../react/ReactTypes.js";
import type { ContextDependency, Fiber } from "./ReactFiberTypes.js";
import type { Lanes } from "./ReactFiberLane.js";
import { isSubsetOfLanes, mergeLanes, NoLanes } from "./ReactFiberLane.js";

// Simple value stack for context
interface StackCursor<T> {
  current: T;
}

function createCursor<T>(defaultValue: T): StackCursor<T> {
  return { current: defaultValue };
}

const valueStack: Array<unknown> = [];
let index = -1;

function push<T>(cursor: StackCursor<T>, value: T): void {
  index++;
  valueStack[index] = cursor.current;
  cursor.current = value;
}

function pop<T>(cursor: StackCursor<T>): void {
  if (index < 0) {
    return;
  }
  cursor.current = valueStack[index] as T;
  valueStack[index] = null;
  index--;
}

const valueCursor: StackCursor<unknown> = createCursor(null);

let currentlyRenderingFiber: Fiber | null = null;
let lastContextDependency: ContextDependency | null = null;

export function resetContextDependencies(): void {
  currentlyRenderingFiber = null;
  lastContextDependency = null;
}

export function pushProvider<T>(
  _providerFiber: Fiber,
  context: ReactContext<T>,
  nextValue: T,
): void {
  push(valueCursor, context._currentValue);
  context._currentValue = nextValue;
}

export function popProvider(context: ReactContext<unknown>, _providerFiber?: Fiber): void {
  const currentValue = valueCursor.current;
  context._currentValue = currentValue;
  pop(valueCursor);
}

export function readContext<T>(context: ReactContext<T>): T {
  return readContextForConsumer(currentlyRenderingFiber, context);
}

export function prepareToReadContext(workInProgress: Fiber, _renderLanes: Lanes): void {
  currentlyRenderingFiber = workInProgress;
  lastContextDependency = null;

  const dependencies = workInProgress.dependencies;
  if (dependencies !== null) {
    // Reset the context dependency list for this render pass so dependencies
    // are re-recorded. Context-changed detection for bail-out optimization is
    // not yet implemented (requires propagateContextChange integration).
    dependencies.firstContext = null;
  }
}

function readContextForConsumer<T>(consumer: Fiber | null, context: ReactContext<T>): T {
  const value: T = context._currentValue;

  if (consumer === null) {
    return value;
  }

  const contextItem: ContextDependency<T> = {
    context,
    memoizedValue: value,
    next: null,
  };

  if (lastContextDependency === null) {
    // This is the first dependency for this fiber
    if (consumer.dependencies === null) {
      consumer.dependencies = {
        lanes: NoLanes,
        firstContext: contextItem,
      };
    } else {
      consumer.dependencies.firstContext = contextItem;
    }
    lastContextDependency = contextItem;
  } else {
    // Append to the existing list
    lastContextDependency = lastContextDependency.next = contextItem;
  }

  return value;
}

// Check if context has changed since the last render
export function propagateContextChange(
  workInProgress: Fiber,
  context: ReactContext<unknown>,
  renderLanes: Lanes,
): void {
  let fiber: Fiber | null = workInProgress.child;
  if (fiber !== null) {
    fiber.return = workInProgress;
  }

  while (fiber !== null) {
    const dependencies = fiber.dependencies;
    if (dependencies !== null) {
      const nextFiber: Fiber | null = fiber.child;

      let dependency = dependencies.firstContext;
      while (dependency !== null) {
        if (dependency.context === context) {
          // Found a match. Schedule an update on this fiber.
          fiber.lanes = mergeLanes(fiber.lanes, renderLanes);
          const alternate = fiber.alternate;
          if (alternate !== null) {
            alternate.lanes = mergeLanes(alternate.lanes, renderLanes);
          }

          // Propagate the changed lanes up the return path
          scheduleContextWorkOnParentPath(fiber.return, renderLanes);

          // Mark that this dependency has changed
          dependencies.lanes = mergeLanes(dependencies.lanes, renderLanes);
          break;
        }
        dependency = dependency.next;
      }

      // Continue traversal from child or sibling
      if (nextFiber !== null) {
        nextFiber.return = fiber;
      }
      fiber = nextFiber;
      continue;
    }

    // Traverse children
    if (fiber.child !== null) {
      fiber.child.return = fiber;
      fiber = fiber.child;
      continue;
    }

    if (fiber === workInProgress) {
      return;
    }

    while (fiber!.sibling === null) {
      if (fiber!.return === null || fiber!.return === workInProgress) {
        return;
      }
      fiber = fiber!.return;
    }

    fiber!.sibling!.return = fiber!.return;
    fiber = fiber!.sibling;
  }
}

function scheduleContextWorkOnParentPath(parent: Fiber | null, renderLanes: Lanes): void {
  let node = parent;
  while (node !== null) {
    const alternate = node.alternate;
    if (!isSubsetOfLanes(node.childLanes, renderLanes)) {
      node.childLanes = mergeLanes(node.childLanes, renderLanes);
      if (alternate !== null) {
        alternate.childLanes = mergeLanes(alternate.childLanes, renderLanes);
      }
    } else if (alternate !== null && !isSubsetOfLanes(alternate.childLanes, renderLanes)) {
      alternate.childLanes = mergeLanes(alternate.childLanes, renderLanes);
    } else {
      // Already updated
      break;
    }
    node = node.return;
  }
}

// Work Loop - Scheduling and execution of React render and commit phases

import type { Fiber, FiberRoot } from "./ReactFiberTypes.js";
import type { Lane, Lanes } from "./ReactFiberLane.js";
import {
  getHighestPriorityLane,
  getNextLanes,
  markRootFinished,
  markRootUpdated,
  mergeLanes,
  NoLane,
  NoLanes,
  SyncLane,
} from "./ReactFiberLane.js";
import { LayoutMask, MutationMask, NoFlags, PassiveMask } from "./ReactFiberFlags.js";
import { createWorkInProgress } from "./ReactFiber.js";
import { beginWork } from "./ReactFiberBeginWork.js";
import { completeWork } from "./ReactFiberCompleteWork.js";
import {
  commitBeforeMutationEffects,
  commitLayoutEffects,
  commitMutationEffects,
  commitPassiveMountEffects,
  commitPassiveUnmountEffects,
} from "./ReactFiberCommitWork.js";
import {
  cancelCallback,
  ImmediatePriority,
  NormalPriority,
  scheduleCallback,
  shouldYield,
} from "../scheduler/Scheduler.js";
import type { PriorityLevel } from "../scheduler/SchedulerPriorities.js";
import type { Task } from "../scheduler/Scheduler.js";
import { setHooksExternals, setWorkInProgressRoot } from "./ReactFiberHooks.js";
import { markWorkInProgressReceivedUpdate } from "./ReactFiberBeginWork.js";

// Work-in-progress state
let workInProgressRoot: FiberRoot | null = null;
let workInProgress: Fiber | null = null;
let workInProgressRenderLanes: Lanes = NoLanes;

// Initialize hooks externals to break circular dependency
function requestUpdateLane(): Lane {
  return SyncLane;
}

setHooksExternals({
  scheduleUpdateOnFiber,
  requestUpdateLane,
  markWorkInProgressReceivedUpdate,
});

// Root-level scheduling state
let rootDoesHavePassiveEffects = false;
let rootWithPendingPassiveEffects: FiberRoot | null = null;

export function scheduleUpdateOnFiber(root: FiberRoot, _fiber: Fiber, lane: Lane): void {
  // Mark the fiber and root as having pending work
  markRootUpdated(root, lane);

  // Schedule work on the root
  ensureRootIsScheduled(root);
}

function ensureRootIsScheduled(root: FiberRoot): void {
  const nextLanes = getNextLanes(root, NoLanes);

  if (nextLanes === NoLanes) {
    // No pending work
    if (root.callbackNode !== null) {
      cancelCallback(root.callbackNode as Task);
      root.callbackNode = null;
    }
    root.callbackPriority = NoLane;
    return;
  }

  const newCallbackPriority = getHighestPriorityLane(nextLanes);

  // Check if there's already a scheduled callback with the same priority
  const existingCallbackPriority = root.callbackPriority;
  if (existingCallbackPriority === newCallbackPriority) {
    return; // Already scheduled
  }

  // Cancel existing callback if different priority
  if (root.callbackNode !== null) {
    cancelCallback(root.callbackNode as Task);
  }

  // Schedule new callback
  let newCallbackNode;

  if (newCallbackPriority === SyncLane) {
    // Sync work - schedule immediately
    scheduleSyncCallback(() => {
      performSyncWorkOnRoot(root);
    });
    newCallbackNode = null;
  } else {
    // Async work
    const priority = laneToPriority(newCallbackPriority);
    newCallbackNode = scheduleCallback(priority, () => {
      performConcurrentWorkOnRoot(root);
    });
  }

  root.callbackNode = newCallbackNode;
  root.callbackPriority = newCallbackPriority;
}

function laneToPriority(lane: Lane): PriorityLevel {
  if (lane === SyncLane) return ImmediatePriority;
  return NormalPriority;
}

// Sync callbacks queue
let syncQueue: Array<() => void> | null = null;
let isFlushingSyncQueue = false;

function scheduleSyncCallback(callback: () => void): void {
  if (syncQueue === null) {
    syncQueue = [callback];
    // Schedule a microtask to flush
    queueMicrotask(flushSyncCallbacks);
  } else {
    syncQueue.push(callback);
  }
}

function flushSyncCallbacks(): void {
  if (isFlushingSyncQueue) return;
  isFlushingSyncQueue = true;
  const queue = syncQueue;
  syncQueue = null;
  if (queue !== null) {
    for (let i = 0; i < queue.length; i++) {
      queue[i]!();
    }
  }
  isFlushingSyncQueue = false;
}

// ─── Sync Work ──────────────────────────────────────────────────────────

export function performSyncWorkOnRoot(root: FiberRoot): void {
  const lanes = getNextLanes(root, NoLanes);
  if (lanes === NoLanes) return;

  // Render phase
  renderRootSync(root, lanes);

  // Commit phase
  const finishedWork = root.current.alternate;
  if (finishedWork !== null) {
    root.finishedWork = finishedWork;
    commitRoot(root);
  }

  ensureRootIsScheduled(root);
}

// ─── Concurrent Work ────────────────────────────────────────────────────

function performConcurrentWorkOnRoot(root: FiberRoot): void {
  // Concurrent mode not yet implemented — falls back to synchronous rendering.
  // workLoopConcurrent (below) is ready but not wired in yet.
  performSyncWorkOnRoot(root);
}

// ─── Render Phase ───────────────────────────────────────────────────────

function renderRootSync(root: FiberRoot, lanes: Lanes): void {
  // Prepare fresh stack
  if (workInProgressRoot !== root || workInProgressRenderLanes !== lanes) {
    prepareFreshStack(root, lanes);
  }

  // Work loop
  workLoopSync();

  // Done rendering
  workInProgressRoot = null;
  workInProgressRenderLanes = NoLanes;
  setWorkInProgressRoot(null, NoLanes);
}

function prepareFreshStack(root: FiberRoot, lanes: Lanes): void {
  root.finishedWork = null;

  workInProgressRoot = root;
  const rootWorkInProgress = createWorkInProgress(root.current, null);
  workInProgress = rootWorkInProgress;
  workInProgressRenderLanes = lanes;

  // Sync hooks with current WIP root and lanes
  setWorkInProgressRoot(root, lanes);
}

function workLoopSync(): void {
  while (workInProgress !== null) {
    performUnitOfWork(workInProgress);
  }
}

/** Reserved for concurrent mode - used when shouldYield is available. */
export function workLoopConcurrent(): void {
  while (workInProgress !== null && !shouldYield()) {
    performUnitOfWork(workInProgress);
  }
}

function performUnitOfWork(unitOfWork: Fiber): void {
  const current = unitOfWork.alternate;

  // BeginWork returns the next child to work on, or null
  const next = beginWork(current, unitOfWork, workInProgressRenderLanes);
  unitOfWork.memoizedProps = unitOfWork.pendingProps;

  if (next === null) {
    // No more children - complete this unit
    completeUnitOfWork(unitOfWork);
  } else {
    workInProgress = next;
  }
}

function completeUnitOfWork(unitOfWork: Fiber): void {
  let completedWork: Fiber | null = unitOfWork;

  do {
    const current = completedWork.alternate;
    const returnFiber: Fiber | null = completedWork.return;

    // Complete the work for this fiber
    const next = completeWork(current, completedWork, workInProgressRenderLanes);

    if (next !== null) {
      // Completing this fiber spawned new work
      workInProgress = next;
      return;
    }

    // Move to sibling
    const siblingFiber = completedWork.sibling;
    if (siblingFiber !== null) {
      workInProgress = siblingFiber;
      return;
    }

    // No sibling - go up to parent
    completedWork = returnFiber;
    workInProgress = completedWork;
  } while (completedWork !== null);
}

// ─── Commit Phase ───────────────────────────────────────────────────────

function commitRoot(root: FiberRoot): void {
  const finishedWork = root.finishedWork;
  if (finishedWork === null) return;

  root.finishedWork = null;
  root.callbackNode = null;
  root.callbackPriority = NoLane;

  // Check for passive effects
  if (
    (finishedWork.subtreeFlags & PassiveMask) !== NoFlags ||
    (finishedWork.flags & PassiveMask) !== NoFlags
  ) {
    if (!rootDoesHavePassiveEffects) {
      rootDoesHavePassiveEffects = true;
      scheduleCallback(NormalPriority, () => {
        flushPassiveEffects();
      });
    }
  }

  // Check if there are any effects to commit
  const subtreeHasEffects =
    (finishedWork.subtreeFlags & (MutationMask | LayoutMask | PassiveMask)) !== NoFlags;
  const rootHasEffect =
    (finishedWork.flags & (MutationMask | LayoutMask | PassiveMask)) !== NoFlags;

  if (subtreeHasEffects || rootHasEffect) {
    const hostConfig = root.hostConfig;

    // Before mutation phase
    hostConfig.prepareForCommit(root.containerInfo);
    commitBeforeMutationEffects(root, finishedWork);

    // Mutation phase - modify the DOM
    commitMutationEffects(root, finishedWork);

    // Swap the current tree
    root.current = finishedWork;

    // Layout phase
    commitLayoutEffects(root, finishedWork);

    hostConfig.resetAfterCommit(root.containerInfo);
  } else {
    // No effects - just swap the tree
    root.current = finishedWork;
  }

  // Handle passive effects
  if (rootDoesHavePassiveEffects) {
    rootDoesHavePassiveEffects = false;
    rootWithPendingPassiveEffects = root;
  }

  // Mark lanes as finished
  const remainingLanes = mergeLanes(finishedWork.lanes, finishedWork.childLanes);
  markRootFinished(root, remainingLanes);

  // Schedule any remaining work
  ensureRootIsScheduled(root);
}

export function flushPassiveEffects(): void {
  if (rootWithPendingPassiveEffects === null) return;

  const root = rootWithPendingPassiveEffects;
  rootWithPendingPassiveEffects = null;

  const finishedWork = root.current;

  // Unmount old effects
  commitPassiveUnmountEffects(finishedWork);

  // Mount new effects
  commitPassiveMountEffects(root, finishedWork);

  // Flush any sync work scheduled by effects
  flushSyncCallbacks();
}

// ─── Public flush for testing ────────────────────────────────────────────

export function flushSync(fn?: () => void): void {
  if (fn) {
    fn();
  }
  flushSyncCallbacks();
}

import type { PriorityLevel } from "./SchedulerPriorities.js";
import {
  IDLE_PRIORITY_TIMEOUT,
  IdlePriority,
  IMMEDIATE_PRIORITY_TIMEOUT,
  ImmediatePriority,
  LOW_PRIORITY_TIMEOUT,
  LowPriority,
  NORMAL_PRIORITY_TIMEOUT,
  NormalPriority,
  USER_BLOCKING_PRIORITY_TIMEOUT,
  UserBlockingPriority,
} from "./SchedulerPriorities.js";
import { peek, pop, push } from "./SchedulerMinHeap.js";
import type { HeapNode } from "./SchedulerMinHeap.js";

export type Callback = (didTimeout: boolean) => Callback | null | undefined | boolean | void;

export interface Task extends HeapNode {
  id: number;
  callback: Callback | null;
  priorityLevel: PriorityLevel;
  startTime: number;
  expirationTime: number;
  sortIndex: number;
}

// Time utilities
let getCurrentTime: () => number;
const hasPerformanceNow = typeof performance === "object" && typeof performance.now === "function";

if (hasPerformanceNow) {
  const localPerformance = performance;
  getCurrentTime = () => localPerformance.now();
} else {
  const localDate = Date;
  const initialTime = localDate.now();
  getCurrentTime = () => localDate.now() - initialTime;
}

// Frame yield budget (5ms)
const frameYieldMs = 5;

// Task queues stored as min heaps
const taskQueue: Task[] = [];
const timerQueue: Task[] = [];

// Incrementing id counter. Used to maintain insertion order.
let taskIdCounter = 1;

let currentTask: Task | null = null;
let currentPriorityLevel: PriorityLevel = NormalPriority;

// This is set while performing work, to prevent re-entrance.
let isPerformingWork = false;

let isHostCallbackScheduled = false;
let isHostTimeoutScheduled = false;

// Capture local references to native APIs
const localSetTimeout = typeof setTimeout === "function" ? setTimeout : null;
const localClearTimeout = typeof clearTimeout === "function" ? clearTimeout : null;

function advanceTimers(currentTime: number): void {
  // Check for tasks that are no longer delayed and add them to the queue.
  let timer = peek(timerQueue);
  while (timer !== null) {
    if (timer.callback === null) {
      // Timer was cancelled.
      pop(timerQueue);
    } else if ((timer as Task).startTime <= currentTime) {
      // Timer fired. Transfer to the task queue.
      pop(timerQueue);
      timer.sortIndex = (timer as Task).expirationTime;
      push(taskQueue, timer as Task);
    } else {
      // Remaining timers are pending.
      return;
    }
    timer = peek(timerQueue);
  }
}

function handleTimeout(currentTime: number): void {
  isHostTimeoutScheduled = false;
  advanceTimers(currentTime);

  if (!isHostCallbackScheduled) {
    if (peek(taskQueue) !== null) {
      isHostCallbackScheduled = true;
      requestHostCallback();
    } else {
      const firstTimer = peek(timerQueue) as Task | null;
      if (firstTimer !== null) {
        requestHostTimeout(handleTimeout, firstTimer.startTime - currentTime);
      }
    }
  }
}

function flushWork(initialTime: number): boolean {
  // We'll need a host callback the next time work is scheduled.
  isHostCallbackScheduled = false;
  if (isHostTimeoutScheduled) {
    // We scheduled a timeout but it's no longer needed. Cancel it.
    isHostTimeoutScheduled = false;
    cancelHostTimeout();
  }

  isPerformingWork = true;
  const previousPriorityLevel = currentPriorityLevel;
  try {
    return workLoop(initialTime);
  } finally {
    currentTask = null;
    currentPriorityLevel = previousPriorityLevel;
    isPerformingWork = false;
  }
}

function workLoop(initialTime: number): boolean {
  let currentTime = initialTime;
  advanceTimers(currentTime);
  currentTask = peek(taskQueue) as Task | null;
  while (currentTask !== null) {
    if (currentTask.expirationTime > currentTime && shouldYieldToHost()) {
      // This currentTask hasn't expired, and we've reached the deadline.
      break;
    }
    const callback = currentTask.callback;
    if (typeof callback === "function") {
      currentTask.callback = null;
      currentPriorityLevel = currentTask.priorityLevel;
      const didUserCallbackTimeout = currentTask.expirationTime <= currentTime;
      const continuationCallback = callback(didUserCallbackTimeout);
      currentTime = getCurrentTime();
      if (typeof continuationCallback === "function") {
        // If a continuation is returned, immediately yield to the main thread
        currentTask.callback = continuationCallback as Callback;
        advanceTimers(currentTime);
        return true;
      } else {
        if (currentTask === peek(taskQueue)) {
          pop(taskQueue);
        }
        advanceTimers(currentTime);
      }
    } else {
      pop(taskQueue);
    }
    currentTask = peek(taskQueue) as Task | null;
  }
  // Return whether there's additional work
  if (currentTask !== null) {
    return true;
  } else {
    const firstTimer = peek(timerQueue) as Task | null;
    if (firstTimer !== null) {
      requestHostTimeout(handleTimeout, firstTimer.startTime - currentTime);
    }
    return false;
  }
}

// --- Host config: MessageChannel-based scheduling ---

let isMessageLoopRunning = false;
let taskTimeoutID: ReturnType<typeof setTimeout> | number = -1;
let frameInterval: number = frameYieldMs;
let startTime = -1;

function shouldYieldToHost(): boolean {
  const timeElapsed = getCurrentTime() - startTime;
  if (timeElapsed < frameInterval) {
    return false;
  }
  return true;
}

const performWorkUntilDeadline = (): void => {
  if (isMessageLoopRunning) {
    const currentTime = getCurrentTime();
    startTime = currentTime;

    let hasMoreWork = true;
    try {
      hasMoreWork = flushWork(currentTime);
    } finally {
      if (hasMoreWork) {
        schedulePerformWorkUntilDeadline();
      } else {
        isMessageLoopRunning = false;
      }
    }
  }
};

let schedulePerformWorkUntilDeadline: () => void;
if (typeof MessageChannel !== "undefined") {
  // DOM and Worker environments.
  // We prefer MessageChannel because of the 4ms setTimeout clamping.
  const channel = new MessageChannel();
  const port = channel.port2;
  channel.port1.onmessage = performWorkUntilDeadline;
  schedulePerformWorkUntilDeadline = () => {
    port.postMessage(null);
  };
} else {
  // Fallback to setTimeout in non-browser environments.
  schedulePerformWorkUntilDeadline = () => {
    localSetTimeout!(performWorkUntilDeadline, 0);
  };
}

function requestHostCallback(): void {
  if (!isMessageLoopRunning) {
    isMessageLoopRunning = true;
    schedulePerformWorkUntilDeadline();
  }
}

function requestHostTimeout(callback: (currentTime: number) => void, ms: number): void {
  taskTimeoutID = localSetTimeout!(() => {
    callback(getCurrentTime());
  }, ms);
}

function cancelHostTimeout(): void {
  localClearTimeout!(taskTimeoutID as ReturnType<typeof setTimeout>);
  taskTimeoutID = -1;
}

// --- Public API ---

export function scheduleCallback(
  priorityLevel: PriorityLevel,
  callback: Callback,
  options?: { delay: number },
): Task {
  const currentTime = getCurrentTime();

  let taskStartTime: number;
  if (typeof options === "object" && options !== null) {
    const delay = options.delay;
    if (typeof delay === "number" && delay > 0) {
      taskStartTime = currentTime + delay;
    } else {
      taskStartTime = currentTime;
    }
  } else {
    taskStartTime = currentTime;
  }

  let timeout: number;
  switch (priorityLevel) {
    case ImmediatePriority:
      timeout = IMMEDIATE_PRIORITY_TIMEOUT;
      break;
    case UserBlockingPriority:
      timeout = USER_BLOCKING_PRIORITY_TIMEOUT;
      break;
    case IdlePriority:
      timeout = IDLE_PRIORITY_TIMEOUT;
      break;
    case LowPriority:
      timeout = LOW_PRIORITY_TIMEOUT;
      break;
    case NormalPriority:
    default:
      timeout = NORMAL_PRIORITY_TIMEOUT;
      break;
  }

  const expirationTime = taskStartTime + timeout;

  const newTask: Task = {
    id: taskIdCounter++,
    callback,
    priorityLevel,
    startTime: taskStartTime,
    expirationTime,
    sortIndex: -1,
  };

  if (taskStartTime > currentTime) {
    // This is a delayed task.
    newTask.sortIndex = taskStartTime;
    push(timerQueue, newTask);
    if (peek(taskQueue) === null && newTask === peek(timerQueue)) {
      // All tasks are delayed, and this is the task with the earliest delay.
      if (isHostTimeoutScheduled) {
        cancelHostTimeout();
      } else {
        isHostTimeoutScheduled = true;
      }
      requestHostTimeout(handleTimeout, taskStartTime - currentTime);
    }
  } else {
    newTask.sortIndex = expirationTime;
    push(taskQueue, newTask);
    // Schedule a host callback, if needed.
    if (!isHostCallbackScheduled && !isPerformingWork) {
      isHostCallbackScheduled = true;
      requestHostCallback();
    }
  }

  return newTask;
}

export function cancelCallback(task: Task): void {
  task.callback = null;
}

export function shouldYield(): boolean {
  return shouldYieldToHost();
}

export function getCurrentPriorityLevel(): PriorityLevel {
  return currentPriorityLevel;
}

export function forceFrameRate(fps: number): void {
  if (fps < 0 || fps > 125) {
    return;
  }
  if (fps > 0) {
    frameInterval = Math.floor(1000 / fps);
  } else {
    frameInterval = frameYieldMs;
  }
}

export {
  getCurrentTime,
  IdlePriority,
  ImmediatePriority,
  LowPriority,
  NormalPriority,
  UserBlockingPriority,
};

export interface HeapNode {
  id: number;
  sortIndex: number;
}

type Heap<T extends HeapNode> = T[];

export function push<T extends HeapNode>(heap: Heap<T>, node: T): void {
  const index = heap.length;
  heap.push(node);
  siftUp(heap, node, index);
}

export function peek<T extends HeapNode>(heap: Heap<T>): T | null {
  return heap.length === 0 ? null : (heap[0] ?? null);
}

export function pop<T extends HeapNode>(heap: Heap<T>): T | null {
  if (heap.length === 0) {
    return null;
  }
  const first = heap[0]!;
  const last = heap.pop()!;
  if (last !== first) {
    heap[0] = last;
    siftDown(heap, last, 0);
  }
  return first;
}

function siftUp<T extends HeapNode>(heap: Heap<T>, node: T, i: number): void {
  let index = i;
  while (index > 0) {
    const parentIndex = (index - 1) >>> 1;
    const parent = heap[parentIndex]!;
    if (compare(parent, node) > 0) {
      // The parent is larger. Swap positions.
      heap[parentIndex] = node;
      heap[index] = parent;
      index = parentIndex;
    } else {
      // The parent is smaller. Exit.
      return;
    }
  }
}

function siftDown<T extends HeapNode>(heap: Heap<T>, node: T, i: number): void {
  let index = i;
  const length = heap.length;
  const halfLength = length >>> 1;
  while (index < halfLength) {
    const leftIndex = (index + 1) * 2 - 1;
    const left = heap[leftIndex];
    const rightIndex = leftIndex + 1;
    const right = heap[rightIndex];

    // If the left or right node is smaller, swap with the smaller of those.
    if (left !== undefined && compare(left, node) < 0) {
      if (rightIndex < length && right !== undefined && compare(right, left) < 0) {
        heap[index] = right;
        heap[rightIndex] = node;
        index = rightIndex;
      } else {
        heap[index] = left;
        heap[leftIndex] = node;
        index = leftIndex;
      }
    } else if (rightIndex < length && right !== undefined && compare(right, node) < 0) {
      heap[index] = right;
      heap[rightIndex] = node;
      index = rightIndex;
    } else {
      // Neither child is smaller. Exit.
      return;
    }
  }
}

function compare(a: HeapNode, b: HeapNode): number {
  // Compare sort index first, then task id.
  const diff = a.sortIndex - b.sortIndex;
  return diff !== 0 ? diff : a.id - b.id;
}

import objectIs from "./objectIs.js";

export default function shallowEqual(objA: unknown, objB: unknown): boolean {
  if (objectIs(objA, objB)) {
    return true;
  }

  if (typeof objA !== "object" || objA === null || typeof objB !== "object" || objB === null) {
    return false;
  }

  const keysA = Object.keys(objA as object);
  const keysB = Object.keys(objB as object);

  if (keysA.length !== keysB.length) {
    return false;
  }

  for (let i = 0; i < keysA.length; i++) {
    const currentKey = keysA[i]!;
    if (
      !Object.hasOwn(objB as object, currentKey) ||
      !objectIs(
        (objA as Record<string, unknown>)[currentKey],
        (objB as Record<string, unknown>)[currentKey],
      )
    ) {
      return false;
    }
  }

  return true;
}

declare const process:
  | { on(event: string, listener: (...args: unknown[]) => void): void }
  | undefined;

export interface ErrorEntry {
  service_name: string;
  error_code?: string | undefined;
  message: string;
  stack_trace?: string | undefined;
  severity?: "low" | "medium" | "high" | "critical" | undefined;
  metadata?: string | undefined;
}

export interface ErrorShipperOptions {
  baseUrl?: string | undefined;
  batchSize?: number | undefined;
  flushIntervalMs?: number | undefined;
}

export interface ErrorShipper {
  shipError(entry: ErrorEntry): void;
  flush(): Promise<void>;
}

export function createErrorShipper(options: ErrorShipperOptions = {}): ErrorShipper {
  const baseUrl = options.baseUrl ?? "https://spike.land/api";
  const batchSize = options.batchSize ?? 10;
  const flushIntervalMs = options.flushIntervalMs ?? 5000;

  let buffer: ErrorEntry[] = [];
  let timeoutId: ReturnType<typeof setTimeout> | null = null;

  const flush = async () => {
    if (buffer.length === 0) return;

    const entries = [...buffer];
    buffer = [];

    if (timeoutId) {
      clearTimeout(timeoutId);
      timeoutId = null;
    }

    try {
      await fetch(`${baseUrl}/errors/ingest`, {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(entries),
      });
    } catch {
      // Silently discard: error shipping is best-effort and must not throw
    }
  };

  const shipError = (entry: ErrorEntry) => {
    buffer.push(entry);

    if (buffer.length >= batchSize) {
      flush();
    } else if (!timeoutId) {
      timeoutId = setTimeout(flush, flushIntervalMs);
    }
  };

  if (typeof process !== "undefined" && typeof process.on === "function") {
    process.on("beforeExit", () => {
      flush();
    });
  }

  return { shipError, flush };
}

/**
 * Immutable Tool Builder
 *
 * tRPC-style immutable builder where each .use(), .tool(), .meta(), .output()
 * returns a genuinely new object with augmented generics. Zero `as unknown as` casts.
 */

import { z } from "zod";
import type {
  BuiltTool,
  CallToolResult,
  EmptyContext,
  HandlerParams,
  Middleware,
  MiddlewareParams,
  ToolExample,
  ToolMeta,
} from "./types.js";

// ─── Internal middleware representation ───

/** Erased middleware — loses generic info but can be stored in arrays */
interface ErasedMiddleware {
  fn: (params: MiddlewareParams<unknown, Record<string, unknown>>) => Promise<CallToolResult>;
}

// ─── Procedure (pre-tool: middleware chain, no schema yet) ───

export interface Procedure<TCtx> {
  /**
   * Add middleware to the procedure chain.
   *
   * Middleware can require a SUBSET of the current context.
   * The fn field is contravariant in TCtxIn, so a middleware requiring
   * { userId } can be used where the context has { userId, deps, ... }.
   *
   * The result is TCtx intersected with the middleware's output context.
   */
  use<TCtxIn extends Record<string, unknown>, TCtxOut extends TCtxIn>(
    mw: Middleware<TCtxIn, TCtxOut>,
  ): TCtx extends TCtxIn ? Procedure<TCtx & TCtxOut> : never;

  /**
   * Define a tool with name, description, and input schema.
   * Returns a ToolBuilder that can add meta, output schema, and handler.
   */
  tool<TFields extends z.ZodRawShape>(
    name: string,
    description: string,
    fields: TFields,
  ): ToolBuilder<z.infer<z.ZodObject<TFields>>, TCtx, CallToolResult>;
}

// ─── ToolBuilder (post-tool: has schema, needs handler) ───

export interface ToolBuilder<TInput, TCtx, TOutput> {
  /** Add metadata (category, tier, etc.) */
  meta(meta: ToolMeta): ToolBuilder<TInput, TCtx, TOutput>;

  /** Add few-shot examples for LLM tool selection */
  examples(examples: ToolExample[]): ToolBuilder<TInput, TCtx, TOutput>;

  /** Add output schema for runtime validation of handler return values */
  output<TNewOutput>(schema: z.ZodType<TNewOutput>): ToolBuilder<TInput, TCtx, TNewOutput>;

  /** Define the handler. Returns a BuiltTool ready for registration. */
  handler(
    fn: (params: HandlerParams<TInput, TCtx>) => Promise<CallToolResult> | CallToolResult,
  ): BuiltTool<TInput, TOutput>;
}

// ─── Internal middleware runner ───

async function runMiddlewareChain(
  middlewares: ErasedMiddleware[],
  input: unknown,
  initialCtx: Record<string, unknown>,
  finalHandler: (input: unknown, ctx: Record<string, unknown>) => Promise<CallToolResult>,
): Promise<CallToolResult> {
  let index = 0;

  const executeNext = async (ctx: Record<string, unknown>): Promise<CallToolResult> => {
    if (index >= middlewares.length) {
      return finalHandler(input, ctx);
    }
    const current = middlewares[index]!;
    index++;
    return current.fn({
      input,
      ctx,
      next: async <TNewCtx extends Record<string, unknown>>(newCtx: TNewCtx) => {
        return executeNext(newCtx);
      },
    });
  };

  return executeNext(initialCtx);
}

// ─── Procedure implementation ───

function createProcedureImpl<TCtx>(middlewares: ErasedMiddleware[]): Procedure<TCtx> {
  return {
    use(mw: Middleware<Record<string, unknown>, Record<string, unknown>>) {
      const erased: ErasedMiddleware = {
        fn: mw.fn as ErasedMiddleware["fn"],
      };
      return createProcedureImpl([...middlewares, erased]);
    },

    tool<TFields extends z.ZodRawShape>(
      name: string,
      description: string,
      fields: TFields,
    ): ToolBuilder<z.infer<z.ZodObject<TFields>>, TCtx, CallToolResult> {
      const schema = z.object(fields);
      return createToolBuilderImpl<z.infer<typeof schema>, TCtx, CallToolResult>(
        middlewares,
        name,
        description,
        fields,
        schema,
        {},
        undefined,
      );
    },
    // The implementation types are erased at runtime; the public
    // Procedure<TCtx> interface provides the correct generic types.
  } as Procedure<TCtx>;
}

// ─── ToolBuilder implementation ───

function createToolBuilderImpl<TInput, TCtx, TOutput>(
  middlewares: ErasedMiddleware[],
  name: string,
  description: string,
  fields: z.ZodRawShape,
  inputSchema: z.ZodType<TInput>,
  toolMeta: ToolMeta,
  outputSchema: z.ZodType<TOutput> | undefined,
): ToolBuilder<TInput, TCtx, TOutput> {
  return {
    meta(newMeta: ToolMeta): ToolBuilder<TInput, TCtx, TOutput> {
      return createToolBuilderImpl(
        middlewares,
        name,
        description,
        fields,
        inputSchema,
        { ...toolMeta, ...newMeta },
        outputSchema,
      );
    },

    examples(newExamples: ToolExample[]): ToolBuilder<TInput, TCtx, TOutput> {
      return createToolBuilderImpl(
        middlewares,
        name,
        description,
        fields,
        inputSchema,
        { ...toolMeta, examples: [...(toolMeta.examples ?? []), ...newExamples] },
        outputSchema,
      );
    },

    output<TNewOutput>(schema: z.ZodType<TNewOutput>): ToolBuilder<TInput, TCtx, TNewOutput> {
      return createToolBuilderImpl(
        middlewares,
        name,
        description,
        fields,
        inputSchema,
        toolMeta,
        schema,
      );
    },

    handler(
      fn: (params: HandlerParams<TInput, TCtx>) => Promise<CallToolResult> | CallToolResult,
    ): BuiltTool<TInput, TOutput> {
      const wrappedHandler = async (
        rawInput: TInput,
        initialCtx: Record<string, unknown> = {},
      ): Promise<CallToolResult> => {
        // 1. Validate input
        const parsed = inputSchema.safeParse(rawInput);
        if (!parsed.success) {
          return {
            content: [
              {
                type: "text",
                text: `**Validation Error**\n${parsed.error.message}`,
              },
            ],
            isError: true,
          };
        }

        const validInput = parsed.data;
        let result: CallToolResult;

        try {
          // 2. Run middleware chain -> handler
          result = await runMiddlewareChain(
            middlewares,
            validInput,
            initialCtx,
            async (input, ctx) =>
              fn({
                input: input as TInput,
                ctx: ctx as TCtx,
              }),
          );
        } catch (error: unknown) {
          if (error && typeof error === "object") {
            const errorObj = error as Record<string, unknown>;
            if (errorObj["name"] === "DomainError") {
              const domainError = errorObj as {
                code: string;
                message: string;
                retryable: boolean;
              };
              return {
                content: [
                  {
                    type: "text",
                    text: `**Error: ${domainError.code}**\n${domainError.message}\n**Retryable:** ${domainError.retryable}`,
                  },
                ],
                isError: true,
              };
            }
            // Handle McpError (has name === "McpError" and a code property)
            if (errorObj["name"] === "McpError" && "code" in errorObj) {
              const mcpError = errorObj as {
                code: string;
                message: string;
                retryable?: boolean;
              };
              return {
                content: [
                  {
                    type: "text",
                    text: `**Error: ${mcpError.code}**\n${mcpError.message}`,
                  },
                ],
                isError: true,
              };
            }
          }
          // Generic error fallback — convert to text instead of propagating
          const message = error instanceof Error ? error.message : String(error);
          return {
            content: [{ type: "text", text: `**Error**\n${message}` }],
            isError: true,
          };
        }

        if (outputSchema && !result.isError) {
          const textContent = result.content
            .filter((c) => c.type === "text" && c.text)
            .map((c) => c.text)
            .join("");
          try {
            const data = JSON.parse(textContent) as unknown;
            const outputParsed = outputSchema.safeParse(data);
            if (!outputParsed.success) {
              return {
                content: [
                  {
                    type: "text",
                    text: `**Output Validation Error**\n${outputParsed.error.message}`,
                  },
                ],
                isError: true,
              };
            }
          } catch {
            // Non-JSON output -- skip validation
          }
        }

        return result;
      };

      return {
        name,
        description,
        inputSchema: fields,
        outputSchema,
        meta: toolMeta,
        handler: wrappedHandler,
      };
    },
  };
}

