/**
 * Create a base procedure with no middleware.
 *
 * @example
 * ```ts
 * const baseProcedure = createProcedure();
 * const t = baseProcedure.use(withUserId("user-123"));
 *
 * const myTool = t.tool("my_tool", "Does something", {
 *   name: z.string(),
 * })
 * .meta({ category: "utils", tier: "free" })
 * .handler(async ({ input, ctx }) => {
 *   return { content: [{ type: "text", text: `Hello ${input.name}` }] };
 * });
 * ```
 */
export function createProcedure<TCtx = EmptyContext>(): Procedure<TCtx> {
  return createProcedureImpl<TCtx>([]);
}

/** Pre-built base procedure with no middleware */
export const baseProcedure = createProcedure();

/**
 * Minimal internal class-variance-authority (cva) implementation
 * for spike.land. Reduces bundle size and removes external dependency.
 */

export type ClassValue = string | number | boolean | null | undefined | ClassValue[];

export function clsx(...inputs: ClassValue[]): string {
  let str = "";
  for (let i = 0; i < inputs.length; i++) {
    const val = inputs[i];
    if (val) {
      if (typeof val === "string") {
        str += (str && " ") + val;
      } else if (Array.isArray(val)) {
        const inner = clsx(...val);
        if (inner) str += (str && " ") + inner;
      } else if (typeof val === "object") {
        for (const key in val as any) {
          if ((val as any)[key]) {
            str += (str && " ") + key;
          }
        }
      }
    }
  }
  return str;
}

export type VariantProps<T extends (...args: any) => any> = Parameters<T>[0];

export type ConfigVariants = Record<string, Record<string, string>>;

export function cva<T extends ConfigVariants>(
  base: string,
  config?: {
    variants?: T;
    defaultVariants?: { [K in keyof T]?: keyof T[K] };
    compoundVariants?: Array<
      { [K in keyof T]?: keyof T[K] | Array<keyof T[K]> } & { className: string }
    >;
  },
) {
  return (
    props?: { [K in keyof T]?: keyof T[K] | undefined | null } & {
      className?: string | undefined | null;
    },
  ) => {
    const { className, ...variants } = props || {};
    let result = base;

    if (config?.variants) {
      const variantsConfig = config.variants;
      for (const variant in variantsConfig) {
        const variantKey = variant as keyof T;
        const value = (variants as any)[variantKey] ?? config.defaultVariants?.[variantKey];
        const variantEntry = variantsConfig[variantKey];
        if (value && variantEntry && variantEntry[value as string]) {
          result = clsx(result, variantEntry[value as string]);
        }
      }
    }

    if (config?.compoundVariants) {
      for (const compound of config.compoundVariants) {
        const matches = Object.entries(compound).every(([key, value]) => {
          if (key === "className") return true;
          const propValue =
            (variants as any)[key as keyof T] ?? config.defaultVariants?.[key as keyof T];
          return Array.isArray(value) ? value.includes(propValue as any) : propValue === value;
        });
        if (matches) {
          result = clsx(result, compound.className);
        }
      }
    }

    return clsx(result, className);
  };
}

import * as React from "react";

/**
 * Minimal internal Slot component for spike.land.
 * Merges props and refs from the Slot to its first child.
 * Used for the "asChild" pattern in UI components.
 */

export interface SlotProps extends React.HTMLAttributes<HTMLElement> {
  children?: React.ReactNode;
}

export const Slot = React.forwardRef<HTMLElement, SlotProps>((props, forwardedRef) => {
  const { children, ...slotProps } = props;

  if (React.isValidElement(children)) {
    return React.cloneElement(children, {
      ...slotProps,
      ...(children.props as any),
      // @ts-ignore - cloning refs is tricky but needed here
      ref: (children as any).props?.ref ? mergeRefs(forwardedRef, (children as any).ref) : forwardedRef,
    } as any);
  }

  return React.Children.count(children) > 1 ? React.Children.only(null) : null;
});

Slot.displayName = "Slot";

function mergeRefs<T>(...refs: Array<React.ForwardedRef<T> | React.Ref<T>>) {
  return (node: T) => {
    for (const ref of refs) {
      if (typeof ref === "function") {
        ref(node);
      } else if (ref && typeof ref === "object") {
        (ref as any).current = node;
      }
    }
  };
}

/**
 * Guard Expression Parser
 *
 * Safe recursive-descent parser for guard expressions used by the statechart
 * engine. Supports arithmetic, comparison, logical operators, string/number
 * literals, boolean/null keywords, and context field access.
 */

// ---------------------------------------------------------------------------
// Parser types
// ---------------------------------------------------------------------------

interface Parser {
  input: string;
  pos: number;
  context: Record<string, unknown>;
}

// ---------------------------------------------------------------------------
// Tokenizer helpers
// ---------------------------------------------------------------------------

function createParser(expression: string, context: Record<string, unknown>): Parser {
  return { input: expression, pos: 0, context };
}

function skipWhitespace(p: Parser): void {
  while (p.pos < p.input.length && /\s/.test(p.input[p.pos]!)) {
    p.pos++;
  }
}

function peek(p: Parser, expected: string): boolean {
  skipWhitespace(p);
  return p.input.startsWith(expected, p.pos);
}

function consume(p: Parser, expected: string): void {
  skipWhitespace(p);
  if (!p.input.startsWith(expected, p.pos)) {
    throw new Error(
      `Guard parse error at position ${p.pos}: expected "${expected}", found "${p.input.slice(
        p.pos,
        p.pos + 10,
      )}"`,
    );
  }
  p.pos += expected.length;
}

// ---------------------------------------------------------------------------
// Recursive descent grammar
// ---------------------------------------------------------------------------

function parseExpr(p: Parser): unknown {
  return parseOrExpr(p);
}

function parseOrExpr(p: Parser): unknown {
  let left = parseAndExpr(p);
  while (peek(p, "||")) {
    consume(p, "||");
    const right = parseAndExpr(p);
    left = Boolean(left) || Boolean(right);
  }
  return left;
}

function parseAndExpr(p: Parser): unknown {
  let left = parseNotExpr(p);
  while (peek(p, "&&")) {
    consume(p, "&&");
    const right = parseNotExpr(p);
    left = Boolean(left) && Boolean(right);
  }
  return left;
}

function parseNotExpr(p: Parser): unknown {
  skipWhitespace(p);
  if (peek(p, "!") && !peek(p, "!=")) {
    consume(p, "!");
    const val = parseNotExpr(p);
    return !val;
  }
  return parseCompare(p);
}

function parseCompare(p: Parser): unknown {
  const left = parseAddSub(p);
  skipWhitespace(p);

  const ops = ["==", "!=", ">=", "<=", ">", "<"];
  for (const op of ops) {
    if (peek(p, op)) {
      consume(p, op);
      const right = parseAddSub(p);
      switch (op) {
        case "==":
          return left === right;
        case "!=":
          return left !== right;
        case ">":
          return (left as number) > (right as number);
        case "<":
          return (left as number) < (right as number);
        case ">=":
          return (left as number) >= (right as number);
        case "<=":
          return (left as number) <= (right as number);
      }
    }
  }

  return left;
}

function parseAddSub(p: Parser): unknown {
  let left = parseMulDiv(p);
  while (peek(p, "+") || peek(p, "-")) {
    if (peek(p, "+")) {
      consume(p, "+");
      const right = parseMulDiv(p);
      left = (left as number) + (right as number);
    } else {
      consume(p, "-");
      const right = parseMulDiv(p);
      left = (left as number) - (right as number);
    }
  }
  return left;
}

function parseMulDiv(p: Parser): unknown {
  let left = parsePow(p);
  while (peek(p, "*") || peek(p, "/")) {
    if (peek(p, "*")) {
      consume(p, "*");
      const right = parsePow(p);
      left = (left as number) * (right as number);
    } else {
      consume(p, "/");
      const right = parsePow(p);
      if (right === 0) {
        throw new Error("Division by zero in guard expression");
      }
      left = (left as number) / (right as number);
    }
  }
  return left;
}

function parsePow(p: Parser): unknown {
  let left = parsePrimary(p);
  while (peek(p, "**")) {
    consume(p, "**");
    const right = parsePrimary(p);
    left = Math.pow(left as number, right as number);
  }
  return left;
}

function resolvePath(obj: unknown, path: string[]): unknown {
  let value = obj;
  for (const key of path) {
    if (value === null || value === undefined) return undefined;
    if (typeof value === "object") {
      value = (value as Record<string, unknown>)[key];
    } else {
      return undefined;
    }
  }
  return value;
}

function parsePrimary(p: Parser): unknown {
  skipWhitespace(p);

  // Parenthesized expression
  if (peek(p, "(")) {
    consume(p, "(");
    const val = parseExpr(p);
    consume(p, ")");
    return val;
  }

  // String literal (double-quoted)
  if (p.pos < p.input.length && p.input[p.pos] === '"') {
    p.pos++; // skip opening quote
    let str = "";
    while (p.pos < p.input.length && p.input[p.pos] !== '"') {
      if (p.input[p.pos] === "\\") {
        p.pos++;
        if (p.pos >= p.input.length) {
          throw new Error("Guard parse error: unterminated string escape");
        }
      }
      str += p.input[p.pos];
      p.pos++;
    }
    if (p.pos >= p.input.length) {
      throw new Error("Guard parse error: unterminated string literal");
    }
    p.pos++; // skip closing quote
    return str;
  }

  // String literal (single-quoted)
  if (p.pos < p.input.length && p.input[p.pos] === "'") {
    p.pos++; // skip opening quote
    let str = "";
    while (p.pos < p.input.length && p.input[p.pos] !== "'") {
      if (p.input[p.pos] === "\\") {
        p.pos++;
        if (p.pos >= p.input.length) {
          throw new Error("Guard parse error: unterminated string escape");
        }
      }
      str += p.input[p.pos];
      p.pos++;
    }
    if (p.pos >= p.input.length) {
      throw new Error("Guard parse error: unterminated string literal");
    }
    p.pos++; // skip closing quote
    return str;
  }

  // Number literal
  if (
    p.pos < p.input.length &&
    (/\d/.test(p.input[p.pos]!) ||
      (p.input[p.pos] === "-" && p.pos + 1 < p.input.length && /\d/.test(p.input[p.pos + 1]!)))
  ) {
    let numStr = "";
    if (p.input[p.pos] === "-") {
      numStr += "-";
      p.pos++;
    }
    while (p.pos < p.input.length && /[\d.]/.test(p.input[p.pos]!)) {
      numStr += p.input[p.pos]!;
      p.pos++;
    }
    const num = Number(numStr);
    if (isNaN(num)) {
      throw new Error(`Guard parse error: invalid number "${numStr}"`);
    }
    return num;
  }

  // Boolean / null keywords and context access
  skipWhitespace(p);
  const identStart = p.pos;
  while (p.pos < p.input.length && /[a-zA-Z0-9_.]/.test(p.input[p.pos]!)) {
    p.pos++;
  }
  const ident = p.input.slice(identStart, p.pos);

  if (ident === "") {
    throw new Error(
      `Guard parse error at position ${p.pos}: unexpected character "${p.input[p.pos] ?? "EOF"}"`,
    );
  }

  if (ident === "true") return true;
  if (ident === "false") return false;
  if (ident === "null") return null;

  // Context access: context.field.subfield
  if (ident.startsWith("context.")) {
    const path = ident.slice("context.".length).split(".");
    return resolvePath(p.context, path);
  }

  // Event access: event.field.subfield (maps to context._event.field.subfield)
  if (ident.startsWith("event.")) {
    const path = ["_event", ...ident.slice("event.".length).split(".")];
    return resolvePath(p.context, path);
  }

  throw new Error(
    `Guard parse error: unknown identifier "${ident}". Use "context.fieldName" or "event.fieldName" for access.`,
  );
}

// ---------------------------------------------------------------------------
// Public API
// ---------------------------------------------------------------------------

/**
 * Evaluate a guard expression string against a context object.
 * Returns true if the expression evaluates to a truthy value.
 */
export function evaluateGuard(expression: string, context: Record<string, unknown>): boolean {
  return Boolean(evaluateExpression(expression, context));
}

/**
 * Evaluate an arbitrary expression string against a context object.
 * Returns the raw result value (may be string, number, boolean, null, etc.).
 */
export function evaluateExpression(expression: string, context: Record<string, unknown>): unknown {
  const p = createParser(expression, context);
  const result = parseExpr(p);
  skipWhitespace(p);
  if (p.pos < p.input.length) {
    throw new Error(
      `Expression parse error: unexpected trailing content at position ${p.pos}: "${p.input.slice(
        p.pos,
      )}"`,
    );
  }
  return result;
}

/**
 * Thin Gemini REST streaming client — replaces Vercel AI SDK (`ai` + `@ai-sdk/google`).
 *
 * Sends SSE events the frontend already understands:
 *   data: {"type":"text_delta","text":"…"}
 *   data: {"type":"tool_call_start","name":"…","toolCallId":"…","args":{…},"transport":"server"}
 *   data: {"type":"tool_call_end","toolCallId":"…","name":"…","result":…}
 *   data: [DONE]
 */

// ── Local types (replace AI SDK types) ──────────────────────────────────────

export interface ChatMessage {
  role: "user" | "assistant" | "system";
  content: string | ContentPart[];
}

export interface ContentPart {
  type: string;
  text?: string;
  image?: string;
}

export interface ToolDef {
  description?: string;
  parameters: JsonSchema;
  execute: (args: Record<string, unknown>) => Promise<unknown>;
}

interface JsonSchema {
  type: string;
  properties?: Record<string, unknown>;
  required?: string[];
  [key: string]: unknown;
}

// ── Gemini API types ────────────────────────────────────────────────────────

interface GeminiContent {
  role: "user" | "model";
  parts: GeminiPart[];
}

type GeminiPart =
  | { text: string }
  | { functionCall: { name: string; args: Record<string, unknown> } }
  | { functionResponse: { name: string; response: { result: unknown } } };

interface GeminiFunctionDeclaration {
  name: string;
  description?: string;
  parameters?: JsonSchema;
}

interface GeminiCandidate {
  content?: { parts?: GeminiPart[] };
  finishReason?: string;
}

interface GeminiStreamChunk {
  candidates?: GeminiCandidate[];
}

// ── Helpers ─────────────────────────────────────────────────────────────────

function contentToString(content: string | ContentPart[]): string {
  if (typeof content === "string") return content;
  return content
    .filter((p) => p.type === "text")
    .map((p) => p.text ?? "")
    .join("");
}

function toGeminiContents(messages: ChatMessage[]): {
  contents: GeminiContent[];
  systemInstruction?: { parts: { text: string }[] };
} {
  let systemInstruction: { parts: { text: string }[] } | undefined;
  const contents: GeminiContent[] = [];

  for (const msg of messages) {
    if (msg.role === "system") {
      systemInstruction = { parts: [{ text: contentToString(msg.content) }] };
      continue;
    }

    contents.push({
      role: msg.role === "assistant" ? "model" : "user",
      parts: [{ text: contentToString(msg.content) }],
    });
  }

  return { contents, ...(systemInstruction !== undefined && { systemInstruction }) };
}

function toFunctionDeclarations(tools: Record<string, ToolDef>): GeminiFunctionDeclaration[] {
  return Object.entries(tools).map(([name, def]) => ({
    name,
    ...(def.description !== undefined && { description: def.description }),
    parameters: def.parameters,
  }));
}

function sseEvent(data: unknown): string {
  return `data: ${JSON.stringify(data)}\n\n`;
}

// ── Core streaming function ─────────────────────────────────────────────────

export interface StreamGeminiOptions {
  apiKey: string;
  model: string;
  systemPrompt: string;
  messages: ChatMessage[];
  tools?: Record<string, ToolDef>;
  onToolResult?: (toolName: string, result: unknown) => Promise<void>;
}

export function streamGemini(opts: StreamGeminiOptions): ReadableStream<Uint8Array> {
  const encoder = new TextEncoder();
  const { apiKey, model, systemPrompt, messages, tools, onToolResult } = opts;

  return new ReadableStream<Uint8Array>({
    async start(controller) {
      try {
        await runStreamLoop(
          controller,
          encoder,
          apiKey,
          model,
          systemPrompt,
          messages,
          tools,
          onToolResult,
        );
        controller.enqueue(encoder.encode("data: [DONE]\n\n"));
      } catch (err) {
        const msg = err instanceof Error ? err.message : "Unknown error";
        controller.enqueue(encoder.encode(sseEvent({ type: "error", error: msg })));
      } finally {
        controller.close();
      }
    },
  });
}

async function runStreamLoop(
  controller: ReadableStreamDefaultController<Uint8Array>,
  encoder: TextEncoder,
  apiKey: string,
  model: string,
  systemPrompt: string,
  messages: ChatMessage[],
  tools: Record<string, ToolDef> | undefined,
  onToolResult: ((toolName: string, result: unknown) => Promise<void>) | undefined,
  depth = 0,
): Promise<void> {
  if (depth > 10) {
    controller.enqueue(
      encoder.encode(sseEvent({ type: "error", error: "Tool call loop limit reached" })),
    );
    return;
  }

  const { contents, systemInstruction } = toGeminiContents([
    { role: "system", content: systemPrompt },
    ...messages,
  ]);

  const body: Record<string, unknown> = { contents };
  if (systemInstruction) {
    body["systemInstruction"] = systemInstruction;
  }

  const declarations = tools ? toFunctionDeclarations(tools) : [];
  if (declarations.length > 0) {
    body["tools"] = [{ functionDeclarations: declarations }];
  }

  const url = `https://generativelanguage.googleapis.com/v1beta/models/${model}:streamGenerateContent?alt=sse&key=${apiKey}`;

  const response = await fetch(url, {
    method: "POST",
    headers: { "Content-Type": "application/json" },
    body: JSON.stringify(body),
  });

  if (!response.ok) {
    const errorText = await response.text();
    throw new Error(`Gemini API error ${response.status}: ${errorText}`);
  }

  const reader = response.body!.getReader();
  const decoder = new TextDecoder();
  let buffer = "";
  const functionCalls: { name: string; args: Record<string, unknown> }[] = [];

  for (;;) {
    const { done, value } = await reader.read();
    if (done) break;

    buffer += decoder.decode(value, { stream: true });

    // Process complete SSE lines
    const lines = buffer.split("\n");
    buffer = lines.pop()!; // keep incomplete line

    for (const line of lines) {
      if (!line.startsWith("data: ")) continue;
      const data = line.slice(6).trim();
      if (!data || data === "[DONE]") continue;

      let chunk: GeminiStreamChunk;
      try {
        chunk = JSON.parse(data);
      } catch {
        continue;
      }

      const parts = chunk.candidates?.[0]?.content?.parts;
      if (!parts) continue;

      for (const part of parts) {
        if ("text" in part) {
          controller.enqueue(encoder.encode(sseEvent({ type: "text_delta", text: part.text })));
        } else if ("functionCall" in part) {
          functionCalls.push({
            name: part.functionCall.name,
            args: part.functionCall.args,
          });
        }
      }
    }
  }

  // Process any function calls
  if (functionCalls.length > 0 && tools) {
    for (const fc of functionCalls) {
      const toolCallId = crypto.randomUUID();

      controller.enqueue(
        encoder.encode(
          sseEvent({
            type: "tool_call_start",
            toolCallId,
            name: fc.name,
            args: fc.args,
            transport: "server",
          }),
        ),
      );

      const toolDef = tools[fc.name];
      let result: unknown;
      if (toolDef) {
        try {
          result = await toolDef.execute(fc.args);
        } catch (err) {
          result = {
            error: err instanceof Error ? err.message : "Tool execution failed",
          };
        }
      } else {
        result = { error: `Unknown tool: ${fc.name}` };
      }

      controller.enqueue(
        encoder.encode(
          sseEvent({
            type: "tool_call_end",
            toolCallId,
            name: fc.name,
            result,
          }),
        ),
      );

      if (onToolResult) {
        try {
          await onToolResult(fc.name, result);
        } catch {
          // fire-and-forget
        }
      }

      // Append function call + response to messages and recurse
      messages.push({
        role: "assistant",
        content: `[Called tool ${fc.name}]`,
      });
      messages.push({
        role: "user",
        content: JSON.stringify({ toolResult: fc.name, result }),
      });
    }

    // Recurse for multi-turn tool calling
    await runStreamLoop(
      controller,
      encoder,
      apiKey,
      model,
      systemPrompt,
      messages,
      tools,
      onToolResult,
      depth + 1,
    );
  }
}

import { md5 } from "@spike-land-ai/code";
import Replicate from "replicate";
import type Env from "../core-logic/env";
import { getCacheDefault } from "../core-logic/utils/cache";

interface InputDefaults {
  cfg: number;
  steps: number;
  prompt: string;
  aspect_ratio: string;
  output_format: "webp" | "png" | "jpeg";
  output_quality: number;
  negative_prompt: string;
  prompt_strength: number;
}

const INPUT_DEFAULTS: InputDefaults = {
  cfg: 3.5,
  steps: 28,
  prompt: 'a photo of vibrant artistic graffiti on a wall saying "SD3 medium"',
  aspect_ratio: "16:9",
  output_format: "webp",
  output_quality: 90,
  negative_prompt: "",
  prompt_strength: 0.85,
};

const REPLICATE_MODEL = "black-forest-labs/flux-schnell";

export function parseInputFromUrl(urlString: string): InputDefaults {
  try {
    const url = new URL(urlString);
    const match = url.pathname.match(/^\/replicate\/([^.]+)\.(?:webp|png|jpeg)$/);

    if (!match || !match[1]) {
      return INPUT_DEFAULTS;
    }

    const base64Params = match[1];
    const decodedParams = atob(base64Params);
    const urlSearchParams = new URLSearchParams(decodedParams);

    const params: Partial<InputDefaults> = {};

    urlSearchParams.forEach((value, key) => {
      if (key in INPUT_DEFAULTS) {
        const typedKey = key as keyof InputDefaults;
        const defaultValue = INPUT_DEFAULTS[typedKey];

        if (value !== "" && value !== String(defaultValue)) {
          if (typeof defaultValue === "number") {
            const numValue = Number(value);
            if (!isNaN(numValue)) {
              Object.assign(params, { [typedKey]: numValue });
            }
          } else if (typedKey === "output_format") {
            if (value === "webp" || value === "png" || value === "jpeg") {
              Object.assign(params, { [typedKey]: value });
            }
          } else {
            Object.assign(params, { [typedKey]: value });
          }
        }
      }
    });

    return { ...INPUT_DEFAULTS, ...params };
  } catch (error) {
    console.error("Error parsing URL params:", error);
    return INPUT_DEFAULTS;
  }
}

/**
 * Fetches an image from a URL, saves it to R2 storage, and returns it as a response.
 * @param image_url - The URL of the image to fetch.
 * @param env - The environment object containing R2 storage.
 * @param md5Prompt - The MD5 hash of the prompt, used as the storage key.
 * @param outputFormat - The desired output format of the image.
 * @param ctx - The execution context for background tasks.
 * @returns A Promise that resolves to a Response object containing the image.
 * @throws Error if the image fetch fails.
 */
async function fetchAndSaveImage(
  image_url: string,
  env: Env,
  md5Prompt: string,
  outputFormat: string,
  ctx: ExecutionContext,
): Promise<Response> {
  try {
    console.warn(`Fetching image from: ${image_url}`);
    const response = await fetch(image_url);

    if (!response || !response.ok) {
      throw new Error(`Failed to fetch image: ${response.status} ${response.statusText}`);
    }

    // Clone the response for R2 storage
    const responseClone = response.clone();

    // Store the image in R2 as a background task
    ctx.waitUntil(
      (async () => {
        try {
          const arrayBuffer = await responseClone.arrayBuffer();
          await env.R2.put(md5Prompt, arrayBuffer);
        } catch (error) {
          if (error instanceof Error) {
            console.error(`Failed to store image in R2: ${error.message}`);
          }
        }
      })(),
    );

    // Prepare and return the response
    return new Response(await response.arrayBuffer(), {
      headers: {
        "Content-Type": `image/${outputFormat}`,
        "Cache-Control": "public, max-age=31536000, immutable",
        "Access-Control-Allow-Origin": "*",
      },
    });
  } catch (error) {
    if (error instanceof Error) {
      console.error(`Error in fetchAndSaveImage: ${error.message}`);
    }
    throw error;
  }
}

export async function handleReplicateRequest(
  request: Request,
  env: Env,
  ctx: ExecutionContext,
): Promise<Response> {
  // Removed origin restriction to allow direct MCP usage from anywhere.

  try {
    const input = parseInputFromUrl(request.url);
    const md5Prompt = md5("replicate salt " + JSON.stringify(input));

    const cacheKey = new Request(request.url, request);
    let resp = await getCacheDefault().match(cacheKey);
    if (resp) return resp;

    const saved = await env.R2.get(md5Prompt);
    if (saved) {
      return new Response(saved.body, {
        headers: {
          "Content-Type": `image/${input.output_format}`,
          "Access-Control-Allow-Origin": "*",
          "Cache-Control": "public, max-age=31536000, immutable",
        },
      });
    }

    const replicate = new Replicate({ auth: env.REPLICATE_API_TOKEN });
    const imageU = await replicate.run(REPLICATE_MODEL, { input });

    if (!imageU) {
      throw new Error("No response from Replicate API");
    }
    const imageArray = Array.isArray(imageU) ? imageU : [imageU];
    const image_url = imageArray[0]?.toString();
    if (!image_url) {
      throw new Error("Invalid image URL from Replicate API");
    }

    resp = await fetchAndSaveImage(image_url, env, md5Prompt, input.output_format, ctx)!;

    ctx.waitUntil(getCacheDefault().put(cacheKey, resp.clone()));
    return resp;
  } catch (e: unknown) {
    console.error("Error in handleReplicateRequest:", e);
    return new Response(`Error: ${e instanceof Error ? e.message : "Unknown error"}`, {
      status: 500,
    });
  }
}

