        {
          content: {
            parts: [
              {
                text:
                  "```json\n" +
                  JSON.stringify({
                    intent: "debugging",
                    task: "Fix login flow",
                    constraints: [],
                    acceptance: [],
                    context: "",
                    priority: "critical",
                  }) +
                  "\n```",
              },
            ],
          },
        },
      ],
    };

