      .all(),
    c.env.DB.prepare(countQ.sql)
      .bind(...countQ.params)
      .first<{ total: number }>(),
  ]);

  return c.json({
    bugs: result.results,
    total: countResult?.total ?? 0,
    limit,
    offset,
  });
});

