import { afterEach, beforeEach, describe, expect, it, vi } from "vitest";
import { clearEloCache, ensureUserElo, getUserElo, recordEloEvent } from "../elo-service.js";

// Mock D1Database
function createMockDb() {
  const store = new Map<string, Record<string, unknown>>();

  const mockPrepare = vi.fn().mockImplementation((sql: string) => {
    const bindValues: unknown[] = [];

    const statement = {
      bind: (...args: unknown[]) => {
        bindValues.push(...args);
        return statement;
      },
      first: vi.fn().mockImplementation(async () => {
        if (sql.includes("SELECT") && sql.includes("user_elo")) {
          const userId = bindValues[0] as string;
          const row = store.get(userId);
          return row ?? null;
        }
        return null;
      }),
      run: vi.fn().mockImplementation(async () => {
        if (sql.includes("INSERT INTO user_elo")) {
          const userId = bindValues[0] as string;
          store.set(userId, {
            user_id: userId,
            elo: bindValues[1] as number,
            event_count: 0,
            daily_gains: 0,
            daily_reset_at: bindValues[2] as number,
            tier: bindValues[3] as string,
          });
        }
        return { success: true };
      }),
    };
    return statement;
  });

  const mockBatch = vi.fn().mockImplementation(async (stmts: unknown[]) => {
    // Simulate batch: parse UPDATE + INSERT from the bind values
    // In tests, we just need to verify the batch was called
    return stmts.map(() => ({ success: true }));
  });

  return {
    prepare: mockPrepare,
    batch: mockBatch,
    _store: store,
  } as unknown as D1Database & { _store: Map<string, Record<string, unknown>> };
}

describe("elo-service", () => {
  let db: D1Database & { _store: Map<string, Record<string, unknown>> };

  beforeEach(() => {
    clearEloCache();
    db = createMockDb();
  });

  afterEach(() => {
    clearEloCache();
  });

  describe("ensureUserElo", () => {
    it("creates a new user with default ELO 1200", async () => {
      const result = await ensureUserElo(db, "user-1");
      expect(result.userId).toBe("user-1");
      expect(result.elo).toBe(1200);
      expect(result.tier).toBe("pro");
      expect(result.eventCount).toBe(0);
      expect(result.dailyGains).toBe(0);
    });

    it("returns existing user from DB", async () => {
      // Pre-populate the store
      db._store.set("user-2", {
        user_id: "user-2",
        elo: 1800,
        event_count: 50,
        daily_gains: 30,
        daily_reset_at: Date.now(),
        tier: "business",
      });

      const result = await ensureUserElo(db, "user-2");
      expect(result.elo).toBe(1800);
      expect(result.tier).toBe("business");
      expect(result.eventCount).toBe(50);
    });

    it("uses cache on second call", async () => {
      await ensureUserElo(db, "user-3");
      const callCount = (db.prepare as ReturnType<typeof vi.fn>).mock.calls.length;

      await ensureUserElo(db, "user-3");
      // Should not have made additional DB calls
      expect((db.prepare as ReturnType<typeof vi.fn>).mock.calls.length).toBe(callCount);
    });
  });

  describe("getUserElo", () => {
    it("returns null for unknown user", async () => {
      const result = await getUserElo(db, "nonexistent");
      expect(result).toBeNull();
    });

    it("returns user data when exists", async () => {
      db._store.set("user-4", {
        user_id: "user-4",
        elo: 900,
        event_count: 10,
        daily_gains: 5,
        daily_reset_at: Date.now(),
        tier: "free",
      });

      const result = await getUserElo(db, "user-4");
      expect(result).not.toBeNull();
      expect(result!.elo).toBe(900);
      expect(result!.tier).toBe("free");
    });
  });

  describe("recordEloEvent", () => {
    it("records a positive event and updates ELO", async () => {
      const result = await recordEloEvent(db, "user-5", "report_valid_bug", "bug-1");
      expect(result.delta).toBe(25);
      expect(result.newElo).toBe(1225);
      expect(result.tier).toBe("pro");
      expect(result.capped).toBe(false);
      expect(db.batch).toHaveBeenCalledTimes(1);
    });

    it("records a negative event", async () => {
      const result = await recordEloEvent(db, "user-6", "abuse_flag");
      expect(result.delta).toBe(-50);
      expect(result.newElo).toBe(1150);
    });

    it("caps daily gains at 100", async () => {
      // Pre-populate user with 90 daily gains
      db._store.set("user-7", {
        user_id: "user-7",
        elo: 1200,
        event_count: 10,
        daily_gains: 90,
        daily_reset_at: Date.now(),
        tier: "pro",
      });

      const result = await recordEloEvent(db, "user-7", "report_valid_bug");
      // Should cap at remaining 10 (100 - 90)
      expect(result.delta).toBe(10);
      expect(result.capped).toBe(true);
      expect(result.newElo).toBe(1210);
    });

    it("returns 0 delta when daily cap is fully used", async () => {
      db._store.set("user-8", {
        user_id: "user-8",
        elo: 1200,
        event_count: 50,
        daily_gains: 100,
        daily_reset_at: Date.now(),
        tier: "pro",
      });

      const result = await recordEloEvent(db, "user-8", "successful_tool_use");
      expect(result.delta).toBe(0);
      expect(result.capped).toBe(true);
      // No batch call since delta is 0
      expect(db.batch).not.toHaveBeenCalled();
    });

    it("negative events bypass daily cap", async () => {
      db._store.set("user-9", {
        user_id: "user-9",
        elo: 1200,
        event_count: 50,
        daily_gains: 100,
        daily_reset_at: Date.now(),
        tier: "pro",
      });

      const result = await recordEloEvent(db, "user-9", "rate_limit_hit");
      expect(result.delta).toBe(-5);
      expect(result.newElo).toBe(1195);
    });
  });
});

import { Hono } from "hono";
import type { Env } from "../../core-logic/env";
import type { Variables } from "../middleware";
import { createDb } from "../../db/db-index";
import { webhooks, messages } from "../../db/schema";
import { eq } from "drizzle-orm";
import { generateId } from "../../core-logic/id-gen";

export const webhooksRouter = new Hono<{ Bindings: Env; Variables: Variables }>();

/**
 * POST /webhooks/inbound/:token
 * Accepts a message from an external service (Slack, GitHub, etc.) and posts it
 * into the channel associated with the webhook token.
 */
webhooksRouter.post("/inbound/:token", async (c) => {
  const token = c.req.param("token");
  const db = createDb(c.env.DB);

  // Look up the webhook by token
  const [webhook] = await db.select().from(webhooks).where(eq(webhooks.token, token));

  if (!webhook) {
    return c.json({ error: "Invalid webhook token" }, 404);
  }

  const body = (await c.req.json().catch((): null => null)) as Record<string, unknown> | null;
  if (!body) {
    return c.json({ error: "Invalid JSON body" }, 400);
  }

  // Accept either { text } or { content } as the message body
  const content = String(body["text"] || body["content"] || JSON.stringify(body));

  const id = generateId();
  const now = Date.now();

  const msg: {
    id: string;
    channelId: string;
    userId: string;
    content: string;
    contentType: string;
    threadId: string | null;
    createdAt: number;
  } = {
    id,
    channelId: webhook.channelId,
    userId: `webhook-${webhook.id}`,
    content,
    contentType: String(body["contentType"] || "text"),
    threadId: null,
    createdAt: now,
  };

  await db.insert(messages).values(msg);

  // Broadcast via DO
  const doId = c.env.CHANNEL_DO.idFromName(webhook.channelId);
  const stub = c.env.CHANNEL_DO.get(doId);

  await stub.fetch(
    new Request("http://internal/broadcast", {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({ type: "message_new", message: msg }),
    }),
  );

  return c.json({ success: true, messageId: id }, 201);
});

/**
 * POST /webhooks/outbound/fire
 * Internal endpoint: called from message routes to fire outbound webhooks
 * when a message is posted in a channel that has outbound webhooks.
 *
 * This is not exposed publicly — it's called from the messages route.
 */
export async function fireOutboundWebhooks(
  db: ReturnType<typeof createDb>,
  channelId: string,
  message: Record<string, unknown>,
): Promise<void> {
  const outbound = await db.select().from(webhooks).where(eq(webhooks.channelId, channelId));

  const outboundHooks = outbound.filter((w) => w.type === "outbound" && w.url);

  await Promise.allSettled(
    outboundHooks.map(async (hook) => {
      try {
        await fetch(hook.url!, {
          method: "POST",
          headers: { "Content-Type": "application/json" },
          body: JSON.stringify({
            event: "message_new",
            channel_id: channelId,
            message,
            webhook_id: hook.id,
          }),
        });
      } catch {
        // Silently ignore failed webhook deliveries for now
      }
    }),
  );
}

export interface Mention {
  type: "user" | "channel" | "role" | "file";
  id: string;
  raw: string;
}

/**
 * Extracts mentions from text.
 * - @username -> user
 * - #channel-slug -> channel
 * - @role -> role
 * - @/path/to/file -> file
 */
export function extractMentions(text: string): Mention[] {
  const mentions: Mention[] = [];
  const regex = /(?:^|\s)(@|#)([a-zA-Z0-9_\-\/]+)(?=\s|$|[.,!?])/g;

  let match;
  while ((match = regex.exec(text)) !== null) {
    const raw = match[0].trim();
    const prefix = match[1];
    const id = match[2];

    if (prefix === "#") {
      mentions.push({ type: "channel", id: id!, raw });
    } else if (prefix === "@") {
      if (id!.startsWith("/")) {
        mentions.push({ type: "file", id: id!, raw });
      } else {
        // Just assuming user for now unless it's a known role like "here" or "channel"
        if (id === "here" || id === "channel" || id === "everyone") {
          mentions.push({ type: "role", id, raw });
        } else {
          mentions.push({ type: "user", id: id!, raw });
        }
      }
    }
  }

  return mentions;
}

import { DurableObject } from "cloudflare:workers";
import type { Env } from "../core-logic/env";
import type { WsAttachment } from "../core-logic/types";

// Messages sent from Client -> Server
type ClientMessage =
  | { type: "auth"; token?: string }
  | { type: "typing_start" }
  | { type: "typing_stop" }
  | { type: "ping" };

export class ChannelDurableObject extends DurableObject {
  private typingUsers: Set<string> = new Set();
  private typingTimeouts: Map<string, number> = new Map();

  constructor(ctx: DurableObjectState, env: Env) {
    super(ctx, env);
  }

  override async fetch(request: Request) {
    const url = new URL(request.url);
    if (request.headers.get("Upgrade") === "websocket") {
      // Create a WebSocket pair
      const pair = new WebSocketPair();
      const [client, server] = Object.values(pair);

      // Authenticate via attachment? We can pass userId in headers or URL during upgrade
      const userId =
        request.headers.get("x-user-id") || url.searchParams.get("userId") || "anonymous";
      const displayName =
        request.headers.get("x-display-name") || url.searchParams.get("displayName") || "Unknown";
      const channelId = url.searchParams.get("channelId") || "unknown";

      const attachment: WsAttachment = {
        userId,
        displayName,
        channelId,
        isBot: false,
      };

      // Accept the connection using Hibernation API
      this.ctx.acceptWebSocket(server!, [channelId]);

      // Store attachment
      server!.serializeAttachment(attachment);

      // Broadcast user_joined (optional, maybe too noisy for large channels)
      return new Response(null, { status: 101, webSocket: client || null });
    }

    // HTTP endpoint for internal broadcasts (from Hono API routes)
    if (request.method === "POST" && url.pathname === "/broadcast") {
      const body = await request.json();
      this.broadcast(JSON.stringify(body));
      return new Response("OK", { status: 200 });
    }

    return new Response("Not found", { status: 404 });
  }

  private broadcast(message: string, excludeWs?: WebSocket) {
    const sockets = this.ctx.getWebSockets();
    for (const ws of sockets) {
      if (ws !== excludeWs) {
        try {
          ws.send(message);
        } catch (_e) {
          // ignore
        }
      }
    }
  }

  // --- Hibernation API handlers ---
  override async webSocketMessage(ws: WebSocket, msg: string | ArrayBuffer) {
    if (typeof msg !== "string") return;

    try {
      const data = JSON.parse(msg) as ClientMessage;
      const attachment = ws.deserializeAttachment() as WsAttachment | null;
      if (!attachment) return;

      switch (data.type) {
        case "ping":
          ws.send(JSON.stringify({ type: "pong" }));
          break;
        case "typing_start":
          this.typingUsers.add(attachment.userId);
          // Clear any existing timeout
          const existing = this.typingTimeouts.get(attachment.userId);
          if (existing) clearTimeout(existing);

          this.typingTimeouts.set(
            attachment.userId,
            setTimeout(() => this.clearTyping(attachment.userId), 5000) as unknown as number,
          );

          this.broadcast(JSON.stringify({ type: "typing", users: Array.from(this.typingUsers) }));
          break;
        case "typing_stop":
          this.clearTyping(attachment.userId);
          break;
      }
    } catch (e) {
      console.error("Invalid WS message", e);
    }
  }

  private clearTyping(userId: string) {
    this.typingUsers.delete(userId);
    this.typingTimeouts.delete(userId);
    this.broadcast(JSON.stringify({ type: "typing", users: Array.from(this.typingUsers) }));
  }

  override async webSocketClose(ws: WebSocket, _code: number, _reason: string, _wasClean: boolean) {
    const attachment = ws.deserializeAttachment() as WsAttachment | null;
    if (attachment) {
      this.clearTyping(attachment.userId);
    }
  }

  override async webSocketError(ws: WebSocket, error: unknown) {
    console.error("[ChannelDurableObject] WebSocket error:", error);
    const attachment = ws.deserializeAttachment() as WsAttachment | null;
    if (attachment) {
      this.clearTyping(attachment.userId);
    }
  }
}

import { DurableObject } from "cloudflare:workers";
import type { Env } from "../core-logic/env";

interface PresenceData {
  status: "online" | "away" | "dnd" | "offline";
  lastSeen: number;
}

export class PresenceDurableObject extends DurableObject {
  private presence: Map<string, PresenceData> = new Map();
  private ALARM_INTERVAL = 30 * 1000; // 30s
  private TIMEOUT = 60 * 1000; // 60s

  constructor(ctx: DurableObjectState, env: Env) {
    super(ctx, env);
    this.ctx.blockConcurrencyWhile(async () => {
      // Ensure the alarm is set when the DO wakes up
      const currentAlarm = await this.ctx.storage.getAlarm();
      if (!currentAlarm) {
        await this.ctx.storage.setAlarm(Date.now() + this.ALARM_INTERVAL);
      }
    });
  }

  override async fetch(request: Request) {
    const url = new URL(request.url);

    if (request.headers.get("Upgrade") === "websocket") {
      const pair = new WebSocketPair();
      const [client, server] = Object.values(pair);

      const userId = request.headers.get("x-user-id") || url.searchParams.get("userId");
      if (!userId) {
        return new Response("Missing userId", { status: 400 });
      }

      this.ctx.acceptWebSocket(server!, [userId]);
      server!.serializeAttachment({ userId });

      // Mark user as online
      this.updatePresence(userId, "online");

      // Send current presence state of everyone to the new client
      const state = Object.fromEntries(this.presence.entries());
      server!.send(JSON.stringify({ type: "presence_state", state }));

      return new Response(null, { status: 101, webSocket: client || null });
    }

    if (request.method === "GET" && url.pathname === "/state") {
      const state = Object.fromEntries(this.presence.entries());
      return new Response(JSON.stringify(state), {
        headers: { "Content-Type": "application/json" },
      });
    }

    return new Response("Not found", { status: 404 });
  }

  private broadcast(message: string) {
    const sockets = this.ctx.getWebSockets();
    for (const ws of sockets) {
      try {
        ws.send(message);
      } catch (_e) {
        // ignore
      }
    }
  }

  private updatePresence(userId: string, status: "online" | "away" | "dnd" | "offline") {
    const now = Date.now();
    const existing = this.presence.get(userId);

    if (existing?.status !== status) {
      this.presence.set(userId, { status, lastSeen: now });
      this.broadcast(
        JSON.stringify({
          type: "presence_changed",
          userId,
          status,
          lastSeen: now,
        }),
      );
    } else {
      existing.lastSeen = now;
    }
  }

  override async webSocketMessage(ws: WebSocket, msg: string | ArrayBuffer) {
    if (typeof msg !== "string") return;

    try {
      const data = JSON.parse(msg);
      const attachment = ws.deserializeAttachment() as { userId: string } | null;
      if (!attachment) return;

      if (data.type === "heartbeat" || data.type === "ping") {
        this.updatePresence(attachment.userId, "online");
        if (data.type === "ping") {
          ws.send(JSON.stringify({ type: "pong" }));
        }
      } else if (
        data.type === "presence_set" &&
        ["online", "away", "dnd", "offline"].includes(data.status)
      ) {
        this.updatePresence(attachment.userId, data.status);
      }
    } catch (e) {
      console.error("Invalid WS message", e);
    }
  }

  override async webSocketClose(ws: WebSocket) {
    const attachment = ws.deserializeAttachment() as { userId: string } | null;
    if (attachment) {
      // Check if user has other active websockets
      const userSockets = this.ctx.getWebSockets(attachment.userId);
      if (userSockets.length === 0) {
        this.updatePresence(attachment.userId, "offline");
      }
    }
  }

  override async webSocketError(ws: WebSocket) {
    const attachment = ws.deserializeAttachment() as { userId: string } | null;
    if (attachment) {
      const userSockets = this.ctx.getWebSockets(attachment.userId);
      if (userSockets.length === 0) {
        this.updatePresence(attachment.userId, "offline");
      }
    }
  }

  override async alarm() {
    const now = Date.now();

    // Check timeouts
    for (const [userId, data] of this.presence.entries()) {
      if (data.status !== "offline" && now - data.lastSeen > this.TIMEOUT) {
        data.status = "offline";
        this.broadcast(
          JSON.stringify({
            type: "presence_changed",
            userId,
            status: "offline",
            lastSeen: data.lastSeen,
          }),
        );
      }
    }

    // Optional: cleanup completely offline/old entries to save memory
    for (const [userId, data] of this.presence.entries()) {
      if (data.status === "offline" && now - data.lastSeen > this.TIMEOUT * 2) {
        this.presence.delete(userId);
      }
    }

    // Schedule next alarm
    await this.ctx.storage.setAlarm(now + this.ALARM_INTERVAL);
  }
}

/**
 * Quiz Engine — Pure business logic for the learning quiz system.
 *
 * Verification-through-questions: content → article → quiz → badge.
 * Multiple-choice with reframing, conflict detection, consistency verification.
 *
 * Algorithm:
 * - 4 options per question, correct answer randomized
 * - 3 questions per round, each testing a different concept
 * - Each concept has 3+ variant questions (reframings of same idea)
 * - Concept mastery = 2+ correct answers across different variants
 * - Contradiction detection: if answer conflicts with previous correct answer
 *   on same concept, mastery resets to 0
 */

// ─── Types ───────────────────────────────────────────────────────────────────

export interface QuizQuestion {
  conceptIndex: number;
  variantIndex: number;
  question: string;
  options: [string, string, string, string];
  correctIndex: number; // 0-3
}

export interface QuizRound {
  roundNumber: number;
  questions: [QuizQuestion, QuizQuestion, QuizQuestion];
}

export interface ConceptState {
  name: string;
  correctCount: number;
  attempts: number;
  mastered: boolean;
  /** Track which option index was chosen for each variant to detect conflicts */
  answerHistory: Map<number, number>;
}

export interface QuizSession {
  id: string;
  userId: string;
  article: string;
  concepts: ConceptDefinition[];
  conceptStates: ConceptState[];
  currentRound: QuizRound;
  roundNumber: number;
  conflicts: ConflictRecord[];
  completed: boolean;
  score: number;
  createdAt: number;
  completedAt: number | null;
}

export interface ConceptDefinition {
  name: string;
  variants: QuizVariant[];
}

export interface QuizVariant {
  question: string;
  options: [string, string, string, string];
  correctIndex: number;
}

export interface ConflictRecord {
  concept: string;
  round: number;
  detail: string;
}

export interface AnswerResult {
  questionIndex: number;
  concept: string;
  correct: boolean;
  conflict: boolean;
}

export interface BadgePayload {
  sid: string;
  topic: string;
  score: number;
  ts: number;
}

// ─── Constants ───────────────────────────────────────────────────────────────

export const MASTERY_THRESHOLD = 2;
export const OPTIONS_PER_QUESTION = 4;
export const QUESTIONS_PER_ROUND = 3;

// ─── In-memory session storage ──────────────────────────────────────────────

const sessions = new Map<string, QuizSession>();

export function clearQuizSessions(): void {
  sessions.clear();
}

export function getSession(id: string): QuizSession | undefined {
  return sessions.get(id);
}

export function setSession(id: string, session: QuizSession): void {
  sessions.set(id, session);
}

// ─── Helpers ────────────────────────────────────────────────────────────────

/** Deterministic pseudo-random based on content hash */
function deterministicRandom(content: string, conceptIdx: number, variantIdx: number): number {
  let hash = 0;
  const seed = `${content.slice(0, 100)}:${conceptIdx}:${variantIdx}`;
  for (let i = 0; i < seed.length; i++) {
    const char = seed.charCodeAt(i);
    hash = ((hash << 5) - hash + char) | 0;
  }
  return Math.abs(hash % 1000) / 1000;
}

export function truncate(s: string, maxLen: number): string {
  return s.length <= maxLen ? s : s.slice(0, maxLen - 3) + "...";
}

function generateVariantQuestion(keySentence: string, variant: number): string {
  const prefix = truncate(keySentence, 40);
  switch (variant) {
    case 0:
      return `Which statement about "${prefix}" is correct?`;
    case 1:
      return `Regarding "${prefix}", which is true?`;
    case 2:
      return `What best describes "${prefix}"?`;
    default:
      return `About "${prefix}":`;
  }
}

function generateOptions(
  keySentence: string,
  _variant: number,
  correctIndex: number,
): [string, string, string, string] {
  const prefix = truncate(keySentence, 30);
  const correct = `This accurately reflects: ${prefix}`;
  const distractors = [
    `This contradicts: ${prefix}`,
    `This is unrelated to: ${prefix}`,
    `This oversimplifies: ${prefix}`,
  ];

  const options: string[] = [];
  let distractorIdx = 0;
  for (let i = 0; i < OPTIONS_PER_QUESTION; i++) {
    if (i === correctIndex) {
      options.push(correct);
    } else {
      options.push(distractors[distractorIdx++] ?? `Distractor ${i}`);
    }
  }
  return options as [string, string, string, string];
}

