          ],
          correctIndex: 1,
        },
        {
          question: "What metric best indicates a successful deployment?",
          options: [
            "Number of lines changed",
            "Speed of the deployment pipeline",
            "Error rate staying at or below pre-deploy levels",
            "Number of approvals on the PR",
          ],
          correctIndex: 2,
        },
      ],
    },
  ];
}

/**
 * Generate planning interview concepts using Gemini API with hardcoded fallback.
 * Unlike content-based quiz concepts, these are always structured around the
 * 6 BAZDMEG planning concepts, contextualized to the specific task.
 */
export async function generatePlanningConcepts(
  taskDescription: string,
  packageName: string | undefined,
  geminiApiKey: string | undefined,
): Promise<ConceptDefinition[]> {
  if (geminiApiKey) {
    try {
      const conceptList = PLANNING_CONCEPT_NAMES.join(", ");
      const pkgContext = packageName ? ` in package "${packageName}"` : "";
      const systemPrompt = `You are an expert software engineering interviewer. Given a task description, generate multiple-choice questions that test the developer's understanding across exactly 6 planning concepts: ${conceptList}.

For each concept, create 3 variant questions (different framings of the same concept). Each question must have exactly 4 options and exactly 1 correct answer. Questions should be specific to the task described, not generic.

Return strict JSON:
{
  "concepts": [
    {
      "name": "file_awareness",
      "variants": [
        { "question": "...", "options": ["A", "B", "C", "D"], "correctIndex": 0 }
      ]
    }
  ]
}`;
      const userPrompt = `Task${pkgContext}: ${taskDescription}`;

      const body = {
        contents: [{ role: "user", parts: [{ text: userPrompt }] }],
        generationConfig: {
          maxOutputTokens: 8192,
          temperature: 0.3,
          response_mime_type: "application/json",
        },
        systemInstruction: { parts: [{ text: systemPrompt }] },
      };

      const url = `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${geminiApiKey}`;
      const response = await fetch(url, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(body),
      });

      if (response.ok) {
        const data = (await response.json()) as {
          candidates?: Array<{ content?: { parts?: Array<{ text?: string }> } }>;
        };
        const text = data.candidates?.[0]?.content?.parts?.[0]?.text;
        if (text) {
          const parsed = JSON.parse(text) as { concepts?: ConceptDefinition[] };
          if (parsed.concepts && Array.isArray(parsed.concepts) && parsed.concepts.length === 6) {
            return parsed.concepts;
          }
        }
      }
    } catch (err) {
      console.error("[Planning] Gemini generation failed, falling back to defaults:", err);
    }
  }

  return getDefaultPlanningConcepts();
}

// ─── Round Generation ───────────────────────────────────────────────────────

/** Pick the next round of questions, choosing unmastered concepts and unused variants */
export function generateNextRound(session: QuizSession): QuizRound {
  const unmasteredConcepts = session.conceptStates
    .map((state, idx) => ({ state, idx }))
    .filter(({ state }) => !state.mastered);

  // Pick up to 3 unmastered concepts
  const selected: { state: ConceptState; idx: number }[] = [];
  const shuffled = [...unmasteredConcepts];
  // Fisher-Yates with deterministic seed
  for (let i = shuffled.length - 1; i > 0; i--) {
    const j = Math.abs((session.roundNumber * 31 + i * 17) % (i + 1));
    [shuffled[i], shuffled[j]] = [shuffled[j]!, shuffled[i]!];
  }
  for (const item of shuffled) {
    if (selected.length >= QUESTIONS_PER_ROUND) break;
    selected.push(item);
  }

  // If not enough unmastered, re-test mastered ones
  if (selected.length < QUESTIONS_PER_ROUND) {
    const mastered = session.conceptStates
      .map((state, idx) => ({ state, idx }))
      .filter(({ state }) => state.mastered);
    for (const item of mastered) {
      if (selected.length >= QUESTIONS_PER_ROUND) break;
      selected.push(item);
    }
  }

  // Pad with first concepts if still not enough
  while (selected.length < QUESTIONS_PER_ROUND) {
    const idx = selected.length % session.conceptStates.length;
    selected.push({
      state: session.conceptStates[idx]!,
      idx,
    });
  }

  const questions = selected.map(({ state, idx }) => {
    const concept = session.concepts[idx]!;
    // Pick a variant not yet answered
    const usedVariants = new Set(state.answerHistory.keys());
    let variantIdx = 0;
    for (let v = 0; v < concept.variants.length; v++) {
      if (!usedVariants.has(v)) {
        variantIdx = v;
        break;
      }
    }
    // If all used, cycle back
    if (usedVariants.size >= concept.variants.length) {
      variantIdx = state.attempts % concept.variants.length;
    }

    const variant = concept.variants[variantIdx]!;
    return {
      conceptIndex: idx,
      variantIndex: variantIdx,
      question: variant.question,
      options: variant.options,
      correctIndex: variant.correctIndex,
    } satisfies QuizQuestion;
  });

  return {
    roundNumber: session.roundNumber,
    questions: questions as [QuizQuestion, QuizQuestion, QuizQuestion],
  };
}

// ─── Answer Evaluation ──────────────────────────────────────────────────────

/** Evaluate answers for a round. Returns results, detects conflicts, updates mastery. */
export function evaluateAnswers(
  session: QuizSession,
  answers: [number, number, number],
): {
  results: AnswerResult[];
  conflicts: ConflictRecord[];
  allMastered: boolean;
} {
  const results: AnswerResult[] = [];
  const newConflicts: ConflictRecord[] = [];

  for (let i = 0; i < QUESTIONS_PER_ROUND; i++) {
    const question = session.currentRound.questions[i]!;
    const answer = answers[i]!;
    const conceptState = session.conceptStates[question.conceptIndex]!;
    const concept = session.concepts[question.conceptIndex]!;
    const isCorrect = answer === question.correctIndex;

    // Check for conflict: did user previously answer a different variant of this concept
    // correctly, but now answered incorrectly (or chose a conflicting answer)?
    let hasConflict = false;
    if (conceptState.answerHistory.size > 0) {
      for (const [prevVariant, prevAnswer] of conceptState.answerHistory) {
        const prevVariantDef = concept.variants[prevVariant];
        if (prevVariantDef && prevAnswer === prevVariantDef.correctIndex && !isCorrect) {
          hasConflict = true;
          const conflict: ConflictRecord = {
            concept: concept.name,
            round: session.roundNumber,
            detail: `Previously correct on variant ${prevVariant}, now incorrect on variant ${question.variantIndex}`,
          };
          newConflicts.push(conflict);
          session.conflicts.push(conflict);

          // Reset mastery for this concept
          conceptState.correctCount = 0;
          conceptState.mastered = false;
          break;
        }
      }
    }

    // Record this answer
    conceptState.answerHistory.set(question.variantIndex, answer);
    conceptState.attempts++;

    if (isCorrect && !hasConflict) {
      conceptState.correctCount++;
      if (conceptState.correctCount >= MASTERY_THRESHOLD) {
        conceptState.mastered = true;
      }
    }

    results.push({
      questionIndex: i,
      concept: concept.name,
      correct: isCorrect,
      conflict: hasConflict,
    });
  }

  const allMastered = session.conceptStates.every((s) => s.mastered);
  return { results, conflicts: newConflicts, allMastered };
}

// ─── Scoring ────────────────────────────────────────────────────────────────

/** Compute overall score as percentage */
export function computeScore(session: QuizSession): number {
  const totalCorrect = session.conceptStates.reduce((sum, s) => sum + s.correctCount, 0);
  const totalAttempts = session.conceptStates.reduce((sum, s) => sum + s.attempts, 0);
  if (totalAttempts === 0) return 0;
  return Math.round((totalCorrect / totalAttempts) * 100);
}

// ─── Badge Tokens ───────────────────────────────────────────────────────────

/** Generate a self-contained signed badge token */
export function generateBadgeToken(payload: BadgePayload, secret: string): string {
  const payloadStr = JSON.stringify(payload);
  const payloadB64 = btoa(payloadStr);

  let hash = 0;
  const signInput = payloadStr + secret;
  for (let i = 0; i < signInput.length; i++) {
    const char = signInput.charCodeAt(i);
    hash = ((hash << 5) - hash + char) | 0;
  }
  const sigB64 = btoa(String(Math.abs(hash)));

  return `${payloadB64}.${sigB64}`;
}

/** Verify a badge token */
export function verifyBadgeToken(token: string, secret: string): BadgePayload | null {
  const parts = token.split(".");
  if (parts.length !== 2) return null;

  const [payloadB64, sigB64] = parts;
  if (!payloadB64 || !sigB64) return null;

  try {
    const payloadStr = atob(payloadB64);
    const payload = JSON.parse(payloadStr) as BadgePayload;

    const expectedToken = generateBadgeToken(payload, secret);
    const expectedSig = expectedToken.split(".")[1];
    if (sigB64 !== expectedSig) return null;

    return payload;
  } catch {
    return null;
  }
}

// ─── Sanitization ───────────────────────────────────────────────────────────

/** Sanitize round data for client (strip correct answers) */
export function sanitizeRound(round: QuizRound): {
  roundNumber: number;
  questions: Array<{
    conceptIndex: number;
    question: string;
    options: [string, string, string, string];
  }>;
} {
  return {
    roundNumber: round.roundNumber,
    questions: round.questions.map((q) => ({
      conceptIndex: q.conceptIndex,
      question: q.question,
      options: q.options,
    })),
  };
}

// ─── Session Factory ────────────────────────────────────────────────────────

/** Create initial concept states from concept definitions */
export function createConceptStates(concepts: ConceptDefinition[]): ConceptState[] {
  return concepts.map((c) => ({
    name: c.name,
    correctCount: 0,
    attempts: 0,
    mastered: false,
    answerHistory: new Map(),
  }));
}

/** Create a new quiz session (without storing it) */
export function createQuizSession(
  id: string,
  userId: string,
  articleContent: string,
  concepts: ConceptDefinition[],
): QuizSession {
  const conceptStates = createConceptStates(concepts);

  const session: QuizSession = {
    id,
    userId,
    article: articleContent,
    concepts,
    conceptStates,
    currentRound: {
      roundNumber: 0,
      questions: [] as unknown as [QuizQuestion, QuizQuestion, QuizQuestion],
    },
    roundNumber: 1,
    conflicts: [],
    completed: false,
    score: 0,
    createdAt: Date.now(),
    completedAt: null,
  };

  session.currentRound = generateNextRound(session);
  return session;
}

/**
 * Tool Search Module
 *
 * Provides keyword and semantic search over registered tools.
 * Extracted from ToolRegistry for independent testability.
 *
 * Ported from spike.land — Gemini semantic search removed (keyword + TF-IDF only).
 */

import type { RegisteredTool } from "@modelcontextprotocol/sdk/server/mcp.js";
import { suggestParameters, ToolEmbeddingIndex } from "./embeddings";
import type {
  SearchResult,
  ToolComplexity,
  ToolDefinition,
  ToolStability,
} from "../../lazy-imports/registry";

interface TrackedToolRef {
  definition: ToolDefinition;
  registered: RegisteredTool;
}

export class ToolSearch {
  private embeddingIndex = new ToolEmbeddingIndex();

  /** Register a tool in the in-memory TF-IDF embedding index. */
  index(
    name: string,
    category: string,
    description: string,
    _version?: string,
    _stability?: ToolStability,
  ): void {
    // Embedding index just takes the string inputs for now
    this.embeddingIndex.embed(name, category, description);
  }

  /** Keyword search over registered tools. */
  search(
    tools: Map<string, TrackedToolRef>,
    query: string,
    limit = 10,
    includeDeprecated = false,
  ): SearchResult[] {
    const terms = query.toLowerCase().split(/\s+/).filter(Boolean);
    if (terms.length === 0) return [];

    const scored: Array<{ result: SearchResult; score: number }> = [];

    for (const [, { definition, registered }] of tools) {
      if (definition.category === "gateway-meta") continue;

      const stability = definition.stability ?? "stable";
      if (!includeDeprecated && stability === "deprecated") continue;

      const nameLC = definition.name.toLowerCase();
      const descLC = definition.description.toLowerCase();
      const catLC = definition.category.toLowerCase();

      let score = 0;
      for (const term of terms) {
        if (nameLC.includes(term)) score += 3;
        if (catLC.includes(term)) score += 2;
        if (descLC.includes(term)) score += 1;
      }

      scored.push({
        result: {
          name: definition.name,
          category: definition.category,
          description: (definition.description.split("\n")[0] ?? "").slice(0, 200),
          tier: definition.tier,
          ...(definition.complexity ? { complexity: definition.complexity } : {}),
          enabled: registered.enabled ?? false,
          version: definition.version ?? "1.0.0",
          stability,
        },
        score,
      });
    }

    const validScores = scored.filter((s) => s.score > 0);
    validScores.sort((a, b) => b.score - a.score);
    return validScores.slice(0, limit).map((s) => s.result);
  }

  /** In-memory TF-IDF semantic search (no external API). */
  searchSemantic(
    tools: Map<string, TrackedToolRef>,
    query: string,
    limit = 10,
    includeDeprecated = false,
  ): SearchResult[] {
    const results = this.embeddingIndex.search(query, limit);
    if (results.length === 0) return [];

    const suggested = suggestParameters(query);

    return results
      .filter((r) => {
        const tracked = tools.get(r.name);
        if (!tracked || tracked.definition.category === "gateway-meta") return false;

        const stability = tracked.definition.stability ?? "stable";
        if (!includeDeprecated && stability === "deprecated") return false;

        return true;
      })
      .map((r) => {
        const tracked = tools.get(r.name)!;
        const stability = tracked.definition.stability ?? "stable";

        return {
          name: tracked.definition.name,
          category: tracked.definition.category,
          description: (tracked.definition.description.split("\n")[0] ?? "").slice(0, 200),
          tier: tracked.definition.tier,
          ...(tracked.definition.complexity
            ? { complexity: tracked.definition.complexity as ToolComplexity }
            : {}),
          enabled: tracked.registered.enabled ?? false,
          score: Math.round(r.score * 100) / 100,
          ...(Object.keys(suggested).length > 0 ? { suggestedParams: suggested } : {}),
          version: tracked.definition.version ?? "1.0.0",
          stability,
        };
      });
  }
}

/**
 * My-Apps MCP Tools (CF Workers)
 *
 * Full lifecycle management for user apps: create, list, get, chat,
 * messages, status, bin, restore, permanent delete, versions, batch.
 *
 * Most operations delegate to the spike.land API for codespace
 * transpilation and AI agent features.
 */

import { z } from "zod";
import type { ToolRegistryAdapter } from "../../lazy-imports/types";
import { freeTool } from "../../lazy-imports/procedures-index.ts";
import { apiRequest, textResult } from "../lib/tool-helpers";
import type { DrizzleDB } from "../../db/db/db-index.ts";

export function registerAppsTools(
  registry: ToolRegistryAdapter,
  userId: string,
  db: DrizzleDB,
): void {
  const t = freeTool(userId, db);

  registry.registerBuilt(
    t
      .tool(
        "apps_create",
        "Use this when you have a workspace and want to create a personal app from a prompt. " +
          "Create a new app from a text prompt. This is the STARTING POINT for new apps. " +
          "The AI will generate code based on your prompt.",
        {
          prompt: z
            .string()
            .min(1)
            .max(5000)
            .describe("What the app should do. Be specific about features, layout, and behavior."),
          codespace_id: z
            .string()
            .min(1)
            .max(100)
            .regex(/^[a-zA-Z0-9_.-]+$/)
            .optional()
            .describe("Custom codespace ID (slug). Auto-generated if omitted."),
          image_ids: z
            .array(z.string())
            .max(5)
            .optional()
            .describe("Image IDs to attach as references."),
          template_id: z.string().optional().describe("Start from a template."),
        },
      )
      .meta({ category: "apps", tier: "free" })
      .examples([
        {
          name: "create_todo_app",
          input: { prompt: "Create a simple todo list app with local storage." },
          description: "Create a basic app",
        },
        {
          name: "create_with_template",
          input: { prompt: "Make it a dark theme analytics dashboard.", template_id: "dashboard" },
          description: "Start from a dashboard template",
        },
      ])
      .handler(async ({ input }) => {
        const { prompt, codespace_id, image_ids, template_id } = input;

        const body: Record<string, unknown> = { prompt };
        if (codespace_id) body["codespaceId"] = codespace_id;
        if (image_ids?.length) body["imageIds"] = image_ids;
        if (template_id) body["templateId"] = template_id;

        const app = await apiRequest<{
          id: string;
          name: string;
          slug: string;
          status: string;
          codespaceId: string;
          codespaceUrl: string;
        }>("/api/apps", { method: "POST", body: JSON.stringify(body) });

        return textResult(
          `**App Created!**\n\n` +
            `**Name:** ${app.name}\n` +
            `**ID:** ${app.id}\n` +
            `**Slug:** ${app.slug}\n` +
            `**Status:** ${app.status}\n` +
            `**Codespace:** ${app.codespaceId}\n\n` +
            `The AI is now generating your app. Use \`apps_get\` to check progress, ` +
            `or \`apps_chat\` to send follow-up instructions.`,
        );
      }),
  );

  registry.registerBuilt(
    t
      .tool(
        "apps_list",
        "List your apps. Call this FIRST to see what exists before making changes. " +
          "Returns app IDs needed for all other apps_* tools.",
        {
          status: z
            .enum([
              "PROMPTING",
              "WAITING",
              "DRAFTING",
              "BUILDING",
              "FINE_TUNING",
              "TEST",
              "LIVE",
              "FAILED",
            ])
            .optional()
            .describe("Filter by status. Omit to see all active apps."),
          limit: z
            .number()
            .int()
            .min(1)
            .max(50)
            .optional()
            .default(20)
            .describe("Max apps to return. Default: 20."),
        },
      )
      .meta({ category: "apps", tier: "free" })
      .examples([
        {
          name: "list_active",
          input: { limit: 10 },
          description: "List up to 10 active apps",
        },
        {
          name: "list_live_apps",
          input: { status: "LIVE" },
          description: "List only published apps",
        },
      ])
      .handler(async ({ input }) => {
        const { status, limit } = input;
        const params = new URLSearchParams();
        if (status) params.set("status", status);
        params.set("limit", String(limit));

        const apps = await apiRequest<
          Array<{
            id: string;
            name: string;
            slug: string;
            status: string;
            codespaceId: string | null;
            messageCount: number;
            versionCount: number;
          }>
        >(`/api/apps?${params.toString()}`);

        if (!Array.isArray(apps) || apps.length === 0) {
          return textResult(
            `**My Apps (0)**\n\nNo apps found. Use \`apps_create\` to create your first app.`,
          );
        }

        let text = `**My Apps (${apps.length})**\n\n`;
        for (const app of apps) {
          text += `- **${app.name}** (${app.status})`;
          text += ` -- ID: \`${app.codespaceId || app.slug || app.id}\``;
          if (app.messageCount !== undefined) {
            text += ` | Messages: ${app.messageCount}`;
          }
          if (app.versionCount !== undefined) {
            text += ` | Versions: ${app.versionCount}`;
          }
          text += `\n`;
        }

        return textResult(text);
      }),
  );

  registry.registerBuilt(
    t
      .tool(
        "apps_get",
        "Get full app details including current code and status. Read before editing.",
        {
          app_id: z.string().min(1).describe("App identifier: codespace ID, slug, or database ID."),
        },
      )
      .meta({ category: "apps", tier: "free" })
      .handler(async ({ input }) => {
        const { app_id } = input;

        const app = await apiRequest<{
          id: string;
          name: string;
          slug: string;
          description: string | null;
          status: string;
          codespaceId: string | null;
          codespaceUrl: string | null;
          agentWorking: boolean;
          lastAgentActivity: string | null;
          createdAt: string;
          updatedAt: string;
          _count?: { messages: number; images: number };
          statusHistory?: Array<{
            status: string;
            message: string | null;
            createdAt: string;
          }>;
        }>(`/api/apps/${encodeURIComponent(app_id)}`);

        let text = `**App: ${app.name}**\n\n`;
        text += `**ID:** ${app.id}\n`;
        text += `**Slug:** ${app.slug || "--"}\n`;
        text += `**Status:** ${app.status}\n`;
        text += `**Agent Working:** ${app.agentWorking ? "Yes" : "No"}\n`;
        if (app.description) text += `**Description:** ${app.description}\n`;
        if (app.codespaceId) text += `**Codespace:** ${app.codespaceId}\n`;
        if (app.codespaceUrl) {
          text += `**Preview:** https://testing.spike.land/live/${app.codespaceId}\n`;
        }
        text += `**Created:** ${app.createdAt}\n`;
        text += `**Updated:** ${app.updatedAt}\n`;

        if (app._count) {
          text += `**Messages:** ${app._count.messages} | **Images:** ${app._count.images}\n`;
        }

        if (app.statusHistory && app.statusHistory.length > 0) {
          text += `\n**Recent Status History:**\n`;
          for (const h of app.statusHistory.slice(0, 5)) {
            text += `- ${h.status}${h.message ? `: ${h.message}` : ""} (${h.createdAt})\n`;
          }
        }

        return textResult(text);
      }),
  );

  registry.registerBuilt(
    t
      .tool(
        "apps_preview",
        "Get the live preview URL for an app. Use this to quickly check your app in the browser.",
        {
          app_id: z.string().min(1).describe("App identifier: codespace ID, slug, or database ID."),
        },
      )
      .meta({ category: "apps", tier: "free" })
      .handler(async ({ input }) => {
        const { app_id } = input;

        const app = await apiRequest<{
          id: string;
          name: string;
          codespaceId: string | null;
          codespaceUrl: string | null;
          status: string;
        }>(`/api/apps/${encodeURIComponent(app_id)}`);

        if (!app.codespaceId) {
          return textResult(
            `**No Preview Available**\n\nApp "${app.name}" does not have a codespace yet. ` +
              `Current status: ${app.status}. The app may still be building.`,
          );
        }

        const previewUrl = `https://testing.spike.land/live/${app.codespaceId}`;

        return textResult(
          `**Live Preview**\n\n` +
            `**App:** ${app.name}\n` +
            `**Status:** ${app.status}\n` +
            `**Preview URL:** ${previewUrl}\n\n` +
            `Open this URL in a browser to see your app running live.`,
        );
      }),
  );

  registry.registerBuilt(
    t
      .tool(
        "apps_chat",
        "Send a message to iterate on an existing app. PREFERRED over direct code edits.",
        {
          app_id: z.string().min(1).describe("App identifier: codespace ID, slug, or database ID."),
          message: z.string().min(1).max(10000).describe("Your message to iterate on the app."),
          image_ids: z
            .array(z.string())
            .max(5)
            .optional()
            .describe("Image IDs to attach as references."),
        },
      )
      .meta({ category: "apps", tier: "free" })
      .handler(async ({ input }) => {
        const { app_id, message, image_ids } = input;

        const body: Record<string, unknown> = {
          content: message,
          role: "USER",
        };
        if (image_ids?.length) body["imageIds"] = image_ids;

        const result = await apiRequest<{
          id: string;
          content: string;
          role: string;
          createdAt: string;
        }>(`/api/apps/${encodeURIComponent(app_id)}/messages`, {
          method: "POST",
          body: JSON.stringify(body),
        });

        return textResult(
          `**Message Sent!**\n\n` +
            `**Message ID:** ${result.id}\n` +
            `**Status:** The AI is processing your request.\n\n` +
            `Use \`apps_get\` to check when the agent finishes, ` +
            `or \`apps_get_messages\` to see the conversation.`,
        );
      }),
  );

  registry.registerBuilt(
    t
      .tool(
        "apps_get_messages",
        "Get chat history for an app. Shows the conversation between user and AI agent.",
        {
          app_id: z.string().min(1).describe("App identifier."),
