            createdAt: new Date().toISOString(),
          };
          resumeStore.set(id, resume);

          const score = scoreResume(resume);
          const preview = formatResumePreview(resume);

          let text = `**Resume Created**\n\n`;
          text += `**ID:** \`${id}\`\n`;
          text += `**Completeness Score:** ${score}/100\n`;
          if (score < 60) {
            text += `**Tip:** Add more experience entries with highlights to raise your score.\n`;
          }
          text += `\n---\n\n`;
          text += preview;
          return textResult(text);
        });
      }),
  );

  // career_match_jobs
  registry.registerBuilt(
    t
      .tool(
        "career_match_jobs",
        "Match a saved resume against available job listings. Returns a ranked list with match score, skill overlap, and salary range.",
        MatchJobsSchema.shape,
      )
      .meta({ category: "career-growth", tier: "free" })
      .handler(async ({ input }) => {
        return safeToolCall("career_match_jobs", async () => {
          const resume = resumeStore.get(input.resume_id);
          if (!resume) {
            return textResult(
              `**Error: NOT_FOUND**\nResume \`${input.resume_id}\` does not exist. Create one first with \`career_create_resume\`.\n**Retryable:** false`,
            );
          }

          let jobs = [...SAMPLE_JOBS];
          if (input.remote_only === true) {
            jobs = jobs.filter((j) => j.remote);
          }
          if (input.location) {
            const loc = input.location.toLowerCase();
            jobs = jobs.filter((j) => j.location.toLowerCase().includes(loc) || j.remote);
          }

          if (jobs.length === 0) {
            return textResult("No jobs found matching your location or remote preference.");
          }

          const ranked = jobs
            .map((job) => ({
              job,
              score: computeJobMatchScore(resume.skills, job),
              matched: job.requiredSkills.filter((s) =>
                resume.skills.map((r) => r.toLowerCase()).includes(s.toLowerCase()),
              ),
            }))
            .sort((a, b) => b.score - a.score);

          let text = `**Job Matches for ${resume.name} (${ranked.length} jobs):**\n\n`;
          for (const { job, score, matched } of ranked) {
            text += `### ${job.title} — ${job.company}\n`;
            text += `**Match Score:** ${score}%\n`;
            text += `**Location:** ${job.location}${job.remote ? " (remote)" : ""}\n`;
            text += `**Salary:** ${job.currency} ${job.salaryMin.toLocaleString()}-${job.salaryMax.toLocaleString()}\n`;
            text += `**Skills Matched:** ${matched.join(", ") || "none"}\n`;
            const missing = job.requiredSkills.filter(
              (s) => !resume.skills.map((r) => r.toLowerCase()).includes(s.toLowerCase()),
            );
            if (missing.length > 0) {
              text += `**Skills to Develop:** ${missing.join(", ")}\n`;
            }
            text += "\n";
          }
          return textResult(text);
        });
      }),
  );

  // career_get_learning_path
  registry.registerBuilt(
    t
      .tool(
        "career_get_learning_path",
        "Generate an ordered learning path from current skills to a target occupation. Returns prioritised skills with resources and estimated hours.",
        LearningPathSchema.shape,
      )
      .meta({ category: "career-growth", tier: "free" })
      .handler(async ({ input }) => {
        return safeToolCall("career_get_learning_path", async () => {
          const path = buildLearningPath(
            input.current_skills,
            input.target_occupation,
            input.time_budget_hours,
          );

          if (path.length === 0) {
            return textResult(
              `You already have the skills needed for **${input.target_occupation}**. Consider applying now or deepening expertise.`,
            );
          }

          const totalHours = path.reduce((sum, item) => sum + item.estimatedHours, 0);

          let text = `**Learning Path: ${input.target_occupation}**\n\n`;
          if (input.time_budget_hours !== undefined) {
            text += `_Filtered to fit within ${input.time_budget_hours}h budget._\n\n`;
          }
          text += `**Total Estimated Time:** ~${totalHours} hours\n\n`;
          text += `| # | Skill | Hours | Priority | Resources |\n`;
          text += `|---|-------|-------|----------|-----------|\n`;
          for (const [index, item] of path.entries()) {
            text += `| ${
              index + 1
            } | ${item.skill} | ${item.estimatedHours}h | ${item.priority} | ${item.resources.join(
              "; ",
            )} |\n`;
          }
          return textResult(text);
        });
      }),
  );

  // career_interview_prep
  registry.registerBuilt(
    t
      .tool(
        "career_interview_prep",
        "Generate tailored interview questions for a given occupation and seniority level. Includes technical, behavioral, and situational questions with sample answer outlines.",
        InterviewPrepSchema.shape,
      )
      .meta({ category: "career-growth", tier: "free" })
      .handler(async ({ input }) => {
        return safeToolCall("career_interview_prep", async () => {
          const questions = generateInterviewQuestions(
            input.occupation,
            input.level,
            input.question_count,
          );

          let text = `**Interview Prep: ${input.occupation} (${input.level})**\n\n`;
          text += `${questions.length} questions generated.\n\n`;

          for (const [index, q] of questions.entries()) {
            text += `---\n\n`;
            text += `**Q${index + 1}.** ${q.question}\n`;
            text += `_Category: ${q.category} | Difficulty: ${q.difficulty}_\n\n`;
            text += `**Sample Answer Outline:**\n${q.sampleAnswerOutline}\n\n`;
          }
          return textResult(text);
        });
      }),
  );
}

/**
 * Causality - Lamport & Vector Clock Simulator MCP Tools
 *
 * Simulates logical clocks for reasoning about happens-before relationships.
 * Ported from spike.land — pure in-memory computation, no DB needed.
 */

import { z } from "zod";
import type { ToolRegistry } from "../../lazy-imports/registry";
import { freeTool, textResult } from "../../lazy-imports/procedures-index.ts";
import type { DrizzleDB } from "../../db/db/db-index.ts";

// ─── Types ───────────────────────────────────────────────────────────────────

interface LamportClock {
  type: "lamport";
  time: number;
}
interface VectorClock {
  type: "vector";
  entries: Record<string, number>;
}
type LogicalClock = LamportClock | VectorClock;
type CausalRelation = "happens_before" | "concurrent" | "same";

interface CausalEvent {
  id: string;
  processId: string;
  label: string;
  clock: LogicalClock;
  causalParents: string[];
  timestamp: number;
}

interface CausalSystem {
  id: string;
  userId: string;
  name: string;
  clockType: "lamport" | "vector";
  processes: Map<string, LogicalClock>;
  processOrder: string[];
  events: CausalEvent[];
  eventCounter: number;
  createdAt: number;
}

// ─── In-memory storage ───────────────────────────────────────────────────────

const systems = new Map<string, CausalSystem>();

export function clearSystems(): void {
  systems.clear();
  idCounter = 0;
}

let idCounter = 0;

function generateId(): string {
  return `causal-${Date.now().toString(36)}-${(++idCounter).toString(36)}`;
}

function cloneClock(clock: LogicalClock): LogicalClock {
  if (clock.type === "lamport") return { type: "lamport", time: clock.time };
  return { type: "vector", entries: { ...clock.entries } };
}

function getSystem(systemId: string, userId: string): CausalSystem {
  const system = systems.get(systemId);
  if (!system) throw new Error(`System ${systemId} not found`);
  if (system.userId !== userId) throw new Error("Access denied");
  return system;
}

function getProcessClock(system: CausalSystem, processId: string): LogicalClock {
  const clock = system.processes.get(processId);
  if (!clock) throw new Error(`Process ${processId} not found`);
  return clock;
}

function getLatestEventForProcess(
  system: CausalSystem,
  processId: string,
): CausalEvent | undefined {
  for (let i = system.events.length - 1; i >= 0; i--) {
    if (system.events[i]!.processId === processId) return system.events[i]!;
  }
  return undefined;
}

function formatClock(clock: LogicalClock): string {
  if (clock.type === "lamport") return `Lamport(${clock.time})`;
  const entries = Object.entries(clock.entries)
    .map(([k, v]) => `${k}: ${v}`)
    .join(", ");
  return `Vector{${entries}}`;
}

function determineRelation(clockA: LogicalClock, clockB: LogicalClock): CausalRelation {
  if (clockA.type === "lamport" && clockB.type === "lamport") {
    if (clockA.time === clockB.time) return "same";
    if (clockA.time < clockB.time) return "happens_before";
    return "concurrent";
  }
  if (clockA.type === "vector" && clockB.type === "vector") {
    const allKeys = new Set([...Object.keys(clockA.entries), ...Object.keys(clockB.entries)]);
    let aLeqB = true,
      aStrictlyLessB = false,
      bStrictlyLessA = false;
    for (const key of allKeys) {
      const aVal = clockA.entries[key] ?? 0,
        bVal = clockB.entries[key] ?? 0;
      if (aVal > bVal) {
        aLeqB = false;
        bStrictlyLessA = true;
      }
      if (bVal > aVal) {
        aStrictlyLessB = true;
      }
    }
    if (!aStrictlyLessB && !bStrictlyLessA) return "same";
    if (aLeqB && aStrictlyLessB) return "happens_before";
    return "concurrent";
  }
  throw new Error("Cannot compare clocks of different types");
}

function buildExplanation(
  clockA: LogicalClock,
  clockB: LogicalClock,
  relation: CausalRelation,
  eventIdA: string,
  eventIdB: string,
): string {
  if (clockA.type === "lamport" && clockB.type === "lamport") {
    switch (relation) {
      case "happens_before":
        return `Lamport clock: ${eventIdA} has time ${clockA.time} < ${clockB.time} of ${eventIdB}. ${eventIdA} happens before ${eventIdB}.`;
      case "same":
        return `Lamport clock: ${eventIdA} and ${eventIdB} both have time ${clockA.time}. Equal timestamps indicate potential concurrency.`;
      case "concurrent":
        return `Lamport clock: ${eventIdA} has time ${clockA.time}, ${eventIdB} has time ${clockB.time}. These events are concurrent.`;
    }
  }
  if (clockA.type === "vector" && clockB.type === "vector") {
    const aE = JSON.stringify(clockA.entries),
      bE = JSON.stringify(clockB.entries);
    switch (relation) {
      case "happens_before":
        return `Vector clock: ${eventIdA} ${aE} <= ${eventIdB} ${bE} with at least one strict inequality.`;
      case "same":
        return `Vector clock: ${eventIdA} ${aE} and ${eventIdB} ${bE} are identical.`;
      case "concurrent":
        return `Vector clock: ${eventIdA} ${aE} and ${eventIdB} ${bE} are incomparable (concurrent).`;
    }
  }
  return "Cannot compare clocks of different types.";
}

function topologicalSort(events: CausalEvent[]): CausalEvent[] {
  const eventMap = new Map<string, CausalEvent>();
  for (const evt of events) eventMap.set(evt.id, evt);
  const visited = new Set<string>();
  const result: CausalEvent[] = [];
  function visit(eventId: string): void {
    if (visited.has(eventId)) return;
    visited.add(eventId);
    const evt = eventMap.get(eventId);
    if (!evt) return;
    for (const parentId of evt.causalParents) visit(parentId);
    result.push(evt);
  }
  for (const evt of events) visit(evt.id);
  return result;
}

// ─── Registration ────────────────────────────────────────────────────────────

const ClockTypeEnum = z.enum(["lamport", "vector"]).describe("Clock type: lamport or vector.");

export function registerCausalityTools(
  registry: ToolRegistry,
  userId: string,
  db: DrizzleDB,
): void {
  registry.registerBuilt(
    freeTool(userId, db)
      .tool(
        "causality_create_system",
        "Create a causal system with N processes using Lamport or Vector clocks.",
        {
          name: z.string().min(1).describe("Name for the causal system."),
          process_count: z.number().int().min(2).max(7).describe("Number of processes (2-7)."),
          clock_type: ClockTypeEnum,
        },
      )
      .meta({ category: "causality", tier: "free" })
      .handler(async ({ input }) => {
        const id = generateId();
        const processes = new Map<string, LogicalClock>();
        const processOrder: string[] = [];
        const processIds: string[] = [];
        for (let i = 1; i <= input.process_count; i++) {
          processIds.push(`process-${i}`);
        }
        for (const pid of processIds) {
          const clock: LogicalClock =
            input.clock_type === "lamport"
              ? { type: "lamport", time: 0 }
              : {
                  type: "vector",
                  entries: Object.fromEntries(processIds.map((p) => [p, 0])),
                };
          processes.set(pid, clock);
          processOrder.push(pid);
        }
        const system: CausalSystem = {
          id,
          userId,
          name: input.name,
          clockType: input.clock_type,
          processes,
          processOrder,
          events: [],
          eventCounter: 0,
          createdAt: Date.now(),
        };
        systems.set(id, system);
        return textResult(
          `**Causal System Created**\n\n**ID:** ${system.id}\n**Name:** ${system.name}\n**Clock Type:** ${system.clockType}\n**Processes:** ${system.processOrder.join(
            ", ",
          )}\n\nUse \`causality_local_event\` or \`causality_send_event\` to create events.`,
        );
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool(
        "causality_local_event",
        "Record a local event on a process. Increments the process's logical clock.",
        {
          system_id: z.string().min(1).describe("ID of the causal system."),
          process_id: z.string().min(1).describe("Process ID."),
          label: z.string().min(1).describe("Label for this event."),
        },
      )
      .meta({ category: "causality", tier: "free" })
      .handler(async ({ input }) => {
        const system = getSystem(input.system_id, userId);
        const clock = getProcessClock(system, input.process_id);
        if (clock.type === "lamport") clock.time += 1;
        else {
          clock.entries[input.process_id] = (clock.entries[input.process_id] ?? 0) + 1;
        }
        const causalParents: string[] = [];
        const latest = getLatestEventForProcess(system, input.process_id);
        if (latest) causalParents.push(latest.id);
        system.eventCounter++;
        const evt: CausalEvent = {
          id: `evt-${system.eventCounter}`,
          processId: input.process_id,
          label: input.label,
          clock: cloneClock(clock),
          causalParents,
          timestamp: system.eventCounter,
        };
        system.events.push(evt);
        return textResult(
          `**Local Event Recorded**\n\n**Event ID:** ${evt.id}\n**Process:** ${evt.processId}\n**Label:** ${evt.label}\n**Clock:** ${formatClock(
            evt.clock,
          )}`,
        );
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool("causality_send_event", "Simulate a message send from one process to another.", {
        system_id: z.string().min(1).describe("ID of the causal system."),
        from_process: z.string().min(1).describe("Sender process ID."),
        to_process: z.string().min(1).describe("Receiver process ID."),
        label: z.string().min(1).describe("Label for this send event."),
      })
      .meta({ category: "causality", tier: "free" })
      .handler(async ({ input }) => {
        const system = getSystem(input.system_id, userId);
        if (input.from_process === input.to_process) {
          throw new Error("Cannot send to same process");
        }
        const senderClock = getProcessClock(system, input.from_process);
        getProcessClock(system, input.to_process); // validate exists
        if (senderClock.type === "lamport") senderClock.time += 1;
        else {
          senderClock.entries[input.from_process] =
            (senderClock.entries[input.from_process] ?? 0) + 1;
        }
        const sendParents: string[] = [];
        const latestSender = getLatestEventForProcess(system, input.from_process);
        if (latestSender) sendParents.push(latestSender.id);
        system.eventCounter++;
        const sendEvt: CausalEvent = {
          id: `evt-${system.eventCounter}`,
          processId: input.from_process,
          label: `send(${input.label})`,
          clock: cloneClock(senderClock),
          causalParents: sendParents,
          timestamp: system.eventCounter,
        };
        system.events.push(sendEvt);
        const receiverClock = getProcessClock(system, input.to_process);
        if (receiverClock.type === "lamport" && senderClock.type === "lamport") {
          receiverClock.time = Math.max(receiverClock.time, senderClock.time) + 1;
        } else if (receiverClock.type === "vector" && senderClock.type === "vector") {
          const allKeys = new Set([
            ...Object.keys(receiverClock.entries),
            ...Object.keys(senderClock.entries),
          ]);
          for (const key of allKeys) {
            receiverClock.entries[key] = Math.max(
              receiverClock.entries[key] ?? 0,
              senderClock.entries[key] ?? 0,
            );
          }
          receiverClock.entries[input.to_process] =
            (receiverClock.entries[input.to_process] ?? 0) + 1;
        }
        const receiveParents: string[] = [sendEvt.id];
        const latestReceiver = getLatestEventForProcess(system, input.to_process);
        if (latestReceiver) receiveParents.push(latestReceiver.id);
        system.eventCounter++;
        const receiveEvt: CausalEvent = {
          id: `evt-${system.eventCounter}`,
          processId: input.to_process,
          label: `receive(${input.label})`,
          clock: cloneClock(receiverClock),
          causalParents: receiveParents,
          timestamp: system.eventCounter,
        };
        system.events.push(receiveEvt);
        return textResult(
          `**Message Send Simulated**\n\n| Event | Process | Label | Clock |\n|---|---|---|---|\n| ${sendEvt.id} | ${sendEvt.processId} | ${sendEvt.label} | ${formatClock(
            sendEvt.clock,
          )} |\n| ${receiveEvt.id} | ${receiveEvt.processId} | ${receiveEvt.label} | ${formatClock(
            receiveEvt.clock,
          )} |`,
        );
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool("causality_compare_events", "Compare two events for causal ordering.", {
        system_id: z.string().min(1).describe("ID of the causal system."),
        event_a: z.string().min(1).describe("First event ID."),
        event_b: z.string().min(1).describe("Second event ID."),
      })
      .meta({ category: "causality", tier: "free" })
      .handler(async ({ input }) => {
        const system = getSystem(input.system_id, userId);
        const eventA = system.events.find((e) => e.id === input.event_a);
        const eventB = system.events.find((e) => e.id === input.event_b);
        if (!eventA) throw new Error(`Event ${input.event_a} not found`);
        if (!eventB) throw new Error(`Event ${input.event_b} not found`);
        if (input.event_a === input.event_b) {
          return textResult(
            `**Causal Comparison**\n\n**${input.event_a}** == **${input.event_b}**\n**Relation:** same\n\nSame event.`,
          );
        }
        const relation = determineRelation(eventA.clock, eventB.clock);
        const symbol =
          relation === "happens_before" ? "->" : relation === "concurrent" ? "||" : "==";
        const explanation = buildExplanation(
          eventA.clock,
          eventB.clock,
          relation,
          input.event_a,
          input.event_b,
        );
        return textResult(
          `**Causal Comparison**\n\n**${input.event_a}** ${symbol} **${input.event_b}**\n**Relation:** ${relation}\n\n${explanation}`,
        );
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool("causality_inspect", "Inspect the current state of all or a specific process.", {
        system_id: z.string().min(1).describe("ID of the causal system."),
        process_id: z.string().optional().describe("Optional process ID."),
      })
      .meta({ category: "causality", tier: "free" })
      .handler(async ({ input }) => {
        const system = getSystem(input.system_id, userId);
        const processIds = input.process_id ? [input.process_id] : system.processOrder;
        const processRows = processIds
          .map((pid) => {
            const clock = getProcessClock(system, pid);
            return `| ${pid} | ${formatClock(cloneClock(clock))} |`;
          })
          .join("\n");
        const events = input.process_id
          ? system.events.filter((e) => e.processId === input.process_id)
          : [...system.events];
        const eventRows =
          events.length > 0
            ? `\n\n**Events:**\n\n| ID | Process | Label | Clock |\n|---|---|---|---|\n` +
              events
                .map((e) => `| ${e.id} | ${e.processId} | ${e.label} | ${formatClock(e.clock)} |`)
                .join("\n")
            : "";
        return textResult(
          `**Causal System: ${system.name}** (${system.clockType})\n\n| Process | Clock |\n|---|---|\n${processRows}${eventRows}`,
        );
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool("causality_timeline", "Get all events in causal (topological) order.", {
        system_id: z.string().min(1).describe("ID of the causal system."),
      })
      .meta({ category: "causality", tier: "free" })
      .handler(async ({ input }) => {
        const system = getSystem(input.system_id, userId);
        const events = topologicalSort([...system.events]);
        if (events.length === 0) {
          return textResult("**Timeline**\n\nNo events recorded yet.");
        }
        const rows = events
          .map(
            (e, i) =>
              `| ${i + 1} | ${e.id} | ${e.processId} | ${e.label} | ${formatClock(e.clock)} |`,
          )
          .join("\n");
        return textResult(
          `**Timeline** (${events.length} events)\n\n| # | ID | Process | Label | Clock |\n|---|---|---|---|---|\n${rows}`,
        );
      }),
  );
}

/**
 * AI Chat MCP Tools (CF Workers)
 *
 * Send messages and get AI responses via direct fetch to the Anthropic API.
 * Ported from spike.land — no Anthropic SDK, uses native fetch.
 */

import { z } from "zod";
import type { ToolRegistry } from "../../lazy-imports/registry";
import { freeTool, textResult } from "../../lazy-imports/procedures-index.ts";
import { McpError, McpErrorCode, safeToolCall } from "../lib/tool-helpers";
import type { DrizzleDB } from "../../db/db/db-index.ts";
import type { Env } from "../env";

/** Minimal env fields required by chat tools. */
type ChatEnv = Pick<Env, "ANTHROPIC_API_KEY">;

const MODEL_MAP: { opus: string; sonnet: string; haiku: string } = {
  opus: "claude-4-6-opus",
  sonnet: "claude-4-6-sonnet",
  haiku: "claude-4-5-haiku",
};

interface AnthropicContentBlock {
  type: string;
  text?: string;
}

interface AnthropicResponse {
  content: AnthropicContentBlock[];
  usage: {
    input_tokens: number;
    output_tokens: number;
  };
}

export function registerChatTools(
  registry: ToolRegistry,
  userId: string,
  db: DrizzleDB,
  env: ChatEnv,
): void {
  registry.registerBuilt(
    freeTool(userId, db)
      .tool(
        "ai_chat",
        "Send a message to the Anthropic Claude API and get a non-streaming AI response. This is for direct AI conversations, not for spike-chat channel messaging.",
        {
          message: z.string().min(1).describe("The message to send to the AI."),
          model: z
            .enum(["opus", "sonnet", "haiku"])
            .optional()
            .default("sonnet")
            .describe("Claude model to use."),
          system_prompt: z
            .string()
            .optional()
            .describe("Optional system prompt for the conversation."),
        },
      )
      .meta({ category: "chat", tier: "free" })
      .handler(async ({ input }) => {
        const { message, model = "sonnet", system_prompt } = input;
        return safeToolCall("ai_chat", async () => {
          const apiKey = env.ANTHROPIC_API_KEY;
          if (!apiKey) {
            throw new McpError("ANTHROPIC_API_KEY not configured.", McpErrorCode.AUTH_ERROR, false);
          }

          const resolvedModel = MODEL_MAP[model] ?? MODEL_MAP.sonnet!;

          const body: Record<string, unknown> = {
            model: resolvedModel,
            max_tokens: 16384,
            messages: [{ role: "user", content: message }],
          };
          if (system_prompt) {
            body["system"] = system_prompt;
          }

          const response = await fetch("https://api.anthropic.com/v1/messages", {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
              "x-api-key": apiKey,
              "anthropic-version": "2023-06-01",
            },
            body: JSON.stringify(body),
          });

          if (!response.ok) {
            const errorText = await response.text().catch(() => "Unknown error");
            throw new McpError(
              `Anthropic API error (${response.status}): ${errorText}`,
              response.status === 429
                ? McpErrorCode.RATE_LIMITED
                : McpErrorCode.UPSTREAM_SERVICE_ERROR,
              response.status === 429,
            );
          }

          const data = (await response.json()) as AnthropicResponse;

          const textParts: string[] = [];
          for (const block of data.content) {
            if (block.type === "text" && block.text) {
              textParts.push(block.text);
            }
          }

          const responseText = textParts.join("\n");

          return textResult(
            `**AI Response** (${model}, ${data.usage.input_tokens} in / ${data.usage.output_tokens} out)\n\n${responseText}`,
          );
        });
      }),
  );
}

/**
 * Context Architect MCP Tools (CF Workers)
 *
 * Tools for indexing GitHub repositories, selecting relevant files
 * for a task, and analyzing import dependency graphs.
 *
 * Runs on Cloudflare Workers. Mostly computation — no DB
 * or Docker dependencies. Uses in-memory storage for indexed repos.
 */

import { z } from "zod";
import type { ToolRegistry } from "../../lazy-imports/registry";
import { freeTool, textResult } from "../../lazy-imports/procedures-index.ts";
import type { DrizzleDB } from "../../db/db/db-index.ts";

interface FileEntry {
  path: string;
  size: number;
  type: string;
}

interface RepoIndexData {
  url: string;
  branch: string;
  files: FileEntry[];
  indexedAt: number;
}

interface GitHubTreeEntry {
  path?: string;
  mode?: string;
  type?: string;
  sha?: string;
  size?: number;
  url?: string;
}

interface GitHubTreeResponse {
  sha: string;
  url: string;
  tree: GitHubTreeEntry[];
  truncated: boolean;
}

// In-memory storage for indexed repos, keyed by `${userId}:${repoUrl}`
const repoIndex = new Map<string, RepoIndexData>();

function repoKey(userId: string, repoUrl: string): string {
  return `${userId}:${repoUrl}`;
}

function parseGitHubUrl(url: string): { owner: string; repo: string } | null {
  const match = url.match(/github\.com\/([^/]+)\/([^/]+)/);
  if (!match) return null;
  const repo = match[2]!.replace(/\.git$/, "");
  return { owner: match[1]!, repo };
}

function getExtension(filePath: string): string {
  const lastDot = filePath.lastIndexOf(".");
  if (lastDot === -1) return "";
  const lastSlash = filePath.lastIndexOf("/");
  if (lastDot < lastSlash) return "";
  return filePath.slice(lastDot + 1).toLowerCase();
}

function detectTechStack(files: FileEntry[]): string[] {
  const stack = new Set<string>();
  const extensions = new Set(files.map((f) => f.type));
  const paths = files.map((f) => f.path);

  if (extensions.has("ts") || extensions.has("tsx")) stack.add("TypeScript");
  if (extensions.has("js") || extensions.has("jsx")) stack.add("JavaScript");
  if (extensions.has("py")) stack.add("Python");
  if (extensions.has("rs")) stack.add("Rust");
  if (extensions.has("go")) stack.add("Go");
  if (extensions.has("java")) stack.add("Java");
  if (extensions.has("rb")) stack.add("Ruby");
  if (extensions.has("php")) stack.add("PHP");
  if (extensions.has("cs")) stack.add("C#");
  if (extensions.has("swift")) stack.add("Swift");
  if (extensions.has("kt")) stack.add("Kotlin");

  if (paths.some((p) => p === "package.json")) stack.add("Node.js");
  if (paths.some((p) => p === "vite.config.ts" || p === "vite.config.js")) {
    stack.add("Vite");
  }
  if (paths.some((p) => p === "Cargo.toml")) stack.add("Rust/Cargo");
  if (paths.some((p) => p === "go.mod")) stack.add("Go Modules");
  if (paths.some((p) => p === "pyproject.toml")) stack.add("Python");
  if (paths.some((p) => p === "Dockerfile" || p === "docker-compose.yml")) {
    stack.add("Docker");
  }
  if (paths.some((p) => p === "tailwind.config.ts" || p === "tailwind.config.js")) {
    stack.add("Tailwind CSS");
  }

  return Array.from(stack);
}

function getTopDirectories(files: FileEntry[], count: number): string[] {
  const dirCounts = new Map<string, number>();
  for (const file of files) {
    const slashIdx = file.path.indexOf("/");
    if (slashIdx !== -1) {
      const topDir = file.path.slice(0, slashIdx);
      dirCounts.set(topDir, (dirCounts.get(topDir) ?? 0) + 1);
    }
  }
  return Array.from(dirCounts.entries())
    .sort((a, b) => b[1] - a[1])
    .slice(0, count)
    .map(([dir, cnt]) => `${dir}/ (${cnt} files)`);
}

// Scoring constants for context_pack
const SOURCE_DIR_PATTERNS = [
  "src/",
  "lib/",
  "app/",
  "routes/",
  "components/",
  "pages/",
  "utils/",
  "helpers/",
  "services/",
  "api/",
  "hooks/",
  "models/",
];
const PENALTY_PATTERNS = [
  ".test.",
  ".spec.",
  "__tests__/",
  "__mocks__/",
  ".config.",
  "jest.",
  "vitest.",
  "eslint",
  "prettier",
  "node_modules/",
  ".github/",
  "dist/",
  "build/",
  ".lock",
  "package-lock",
  "yarn.lock",
];

function scoreFile(file: FileEntry, keywords: string[]): number {
  const pathLower = file.path.toLowerCase();
  let score = 0;

  for (const kw of keywords) {
    if (pathLower.includes(kw)) score += 3;
  }

  for (const pattern of SOURCE_DIR_PATTERNS) {
    if (pathLower.includes(pattern)) {
      score += 2;
      break;
    }
  }

  for (const pattern of PENALTY_PATTERNS) {
    if (pathLower.includes(pattern)) {
      score -= 5;
      break;
    }
  }

  const codeExtensions = new Set(["ts", "tsx", "js", "jsx", "py", "rs", "go", "java", "rb"]);
  if (codeExtensions.has(file.type)) {
    score += 1;
  }

  return score;
}

const IMPORT_PATTERN =
  /(?:import\s+[\s\S]*?\s+from\s+['"]([^'"]+)['"]|from\s+['"]([^'"]+)['"]\s+import)/g;

function parseImports(content: string): string[] {
  const imports: string[] = [];
  const regex = new RegExp(IMPORT_PATTERN.source, IMPORT_PATTERN.flags);
  let match: RegExpExecArray | null;
  while ((match = regex.exec(content)) !== null) {
    const imp = match[1] ?? match[2];
    if (imp) imports.push(imp);
  }
  return imports;
}

export function registerContextArchitectTools(
  registry: ToolRegistry,
  userId: string,
  db: DrizzleDB,
): void {
  const t = freeTool(userId, db);

  // context_index_repo
  registry.registerBuilt(
    t
      .tool(
        "context_index_repo",
        "Index a GitHub repository file tree for later context packing. " +
          "Stores file paths, sizes, and types in memory for the session. " +
          "Returns a summary of indexed files including count, top directories, and detected tech stack.",
        {
          repo_url: z
            .string()
            .url()
            .describe("GitHub repository URL (e.g. https://github.com/owner/repo)"),
          branch: z.string().optional().default("main").describe("Branch to index (default: main)"),
        },
      )
      .meta({ category: "orchestration", tier: "free" })
      .handler(async ({ input }) => {
        const { repo_url, branch } = input;

        const parsed = parseGitHubUrl(repo_url);
        if (!parsed) {
          return {
            content: [
              {
                type: "text" as const,
                text: "Invalid GitHub URL. Expected format: https://github.com/owner/repo",
              },
            ],
            isError: true,
          };
        }

        const apiUrl = `https://api.github.com/repos/${parsed.owner}/${parsed.repo}/git/trees/${branch}?recursive=1`;
        const response = await fetch(apiUrl, {
          headers: {
            Accept: "application/vnd.github.v3+json",
            "User-Agent": "spike-land-mcp",
          },
        });

        if (!response.ok) {
          const status = response.status;
          if (status === 404) {
            return {
              content: [
                {
                  type: "text" as const,
                  text: `Repository or branch not found: ${parsed.owner}/${parsed.repo}@${branch}`,
                },
              ],
              isError: true,
            };
          }
          return {
            content: [
              {
                type: "text" as const,
                text: `GitHub API error: ${status} ${response.statusText}`,
              },
            ],
            isError: true,
          };
        }

        const data = (await response.json()) as GitHubTreeResponse;

        const files: FileEntry[] = data.tree
          .filter((entry) => entry.type === "blob" && entry.path)
          .map((entry) => ({
            path: entry.path!,
            size: entry.size ?? 0,
            type: getExtension(entry.path!),
          }));

        const key = repoKey(userId, repo_url);
        repoIndex.set(key, {
          url: repo_url,
          branch,
          files,
          indexedAt: Date.now(),
        });

        const topDirs = getTopDirectories(files, 10);
        const techStack = detectTechStack(files);
        const totalSize = files.reduce((sum, f) => sum + f.size, 0);

        let text = `**Indexed ${files.length} files** from \`${parsed.owner}/${parsed.repo}@${branch}\`\n\n`;
        text += `**Total size:** ${(totalSize / 1024).toFixed(1)} KB\n`;
        if (data.truncated) {
          text += `**Warning:** Repository tree was truncated by GitHub API (very large repo)\n`;
        }
        text += `\n**Top directories:**\n`;
        for (const dir of topDirs) {
          text += `- ${dir}\n`;
        }
        if (techStack.length > 0) {
          text += `\n**Detected tech stack:** ${techStack.join(", ")}\n`;
        }

        return textResult(text);
      }),
  );

  // context_pack
  registry.registerBuilt(
    t
      .tool(
        "context_pack",
        "Given an indexed repository and a task description, select the most relevant files. " +
          "Scores files by keyword matching, boosts source directories, and penalizes test/config files. " +
          "Returns an ordered list of file paths with relevance scores.",
        {
          repo_url: z.string().url().describe("GitHub repository URL (must be indexed first)"),
          task_description: z
            .string()
            .min(3)
            .describe("Description of the task to find relevant files for"),
          max_files: z
            .number()
            .min(1)
            .max(100)
            .optional()
            .default(20)
            .describe("Maximum files to return (default: 20)"),
        },
      )
      .meta({ category: "orchestration", tier: "free" })
      .handler(async ({ input }) => {
        const { repo_url, task_description, max_files } = input;

        const key = repoKey(userId, repo_url);
        const indexed = repoIndex.get(key);
        if (!indexed) {
          return {
            content: [
              {
                type: "text" as const,
                text: "Repository not indexed. Call `context_index_repo` first.",
              },
            ],
            isError: true,
          };
        }

        const keywords = task_description
          .toLowerCase()
          .split(/[\s,;.!?]+/)
          .filter((w) => w.length > 2)
          .map((w) => w.replace(/[^a-z0-9-_]/g, ""))
          .filter(Boolean);

        if (keywords.length === 0) {
          return {
            content: [
              {
                type: "text" as const,
                text: "Task description too short or no meaningful keywords found.",
              },
            ],
            isError: true,
          };
        }

        const scored = indexed.files
          .map((file) => ({ file, score: scoreFile(file, keywords) }))
          .filter((entry) => entry.score > 0)
          .sort((a, b) => b.score - a.score)
          .slice(0, max_files);

        if (scored.length === 0) {
          return textResult(
            "No relevant files found for the given task description. Try using different keywords.",
          );
        }

        let text = `**${scored.length} relevant file(s)** for: _${task_description}_\n\n`;
        text += `| # | Score | Path | Size |\n`;
        text += `|---|-------|------|------|\n`;
        for (let i = 0; i < scored.length; i++) {
          const { file, score } = scored[i]!;
          const sizeStr =
            file.size > 1024 ? `${(file.size / 1024).toFixed(1)} KB` : `${file.size} B`;
          text += `| ${i + 1} | ${score} | \`${file.path}\` | ${sizeStr} |\n`;
        }

        return textResult(text);
      }),
  );

  // context_get_deps
  registry.registerBuilt(
    t
      .tool(
        "context_get_deps",
        "Get the import/dependency graph for a specific file in an indexed repository. " +
          "Parses import/from statements and finds sibling files in the same directory. " +
          "The repository must be indexed first with context_index_repo.",
        {
          repo_url: z.string().url().describe("GitHub repository URL (must be indexed first)"),
          file_path: z
            .string()
            .min(1)
            .describe("File path within the repository (e.g. src/lib/utils.ts)"),
        },
      )
      .meta({ category: "orchestration", tier: "free" })
      .handler(async ({ input }) => {
        const { repo_url, file_path } = input;

        const key = repoKey(userId, repo_url);
        const indexed = repoIndex.get(key);
        if (!indexed) {
          return {
            content: [
              {
                type: "text" as const,
                text: "Repository not indexed. Call `context_index_repo` first.",
              },
            ],
            isError: true,
          };
        }

        const targetFile = indexed.files.find((f) => f.path === file_path);
        if (!targetFile) {
          return {
            content: [
              {
                type: "text" as const,
                text: `File not found in index: \`${file_path}\``,
              },
            ],
            isError: true,
          };
        }

        const parsed = parseGitHubUrl(repo_url);
        if (!parsed) {
          return {
            content: [{ type: "text" as const, text: "Invalid GitHub URL." }],
            isError: true,
          };
        }

        // Fetch file content from GitHub to parse imports
        const rawUrl = `https://raw.githubusercontent.com/${parsed.owner}/${parsed.repo}/${indexed.branch}/${file_path}`;
        const response = await fetch(rawUrl, {
          headers: { "User-Agent": "spike-land-mcp" },
        });

        let directDeps: string[] = [];
        if (response.ok) {
          const content = await response.text();
          directDeps = parseImports(content);
        }

        // Find sibling files in the same directory
        const targetDir = file_path.slice(0, file_path.lastIndexOf("/"));
        const codeExtensions = new Set(["ts", "tsx", "js", "jsx", "mjs", "cjs"]);
        const siblingFiles: string[] = [];

        for (const file of indexed.files) {
          if (file.path === file_path) continue;
          if (!codeExtensions.has(file.type)) continue;
          const fileDir = file.path.slice(0, file.path.lastIndexOf("/"));
          if (fileDir === targetDir) {
            siblingFiles.push(file.path);
          }
        }

        let text = `**Dependencies for** \`${file_path}\`\n\n`;

        if (directDeps.length > 0) {
          text += `**Direct imports (${directDeps.length}):**\n`;
          for (const dep of directDeps) {
            text += `- \`${dep}\`\n`;
          }
        } else {
          text += `**Direct imports:** None found\n`;
        }

        text += `\n**Sibling files (same directory, ${siblingFiles.length}):**\n`;
        if (siblingFiles.length > 0) {
          for (const dep of siblingFiles.slice(0, 20)) {
            text += `- \`${dep}\`\n`;
          }
          if (siblingFiles.length > 20) {
            text += `- _...and ${siblingFiles.length - 20} more_\n`;
          }
        } else {
          text += `- None\n`;
        }

        return textResult(text);
      }),
  );
}

// Exported for testing
export {
  detectTechStack,
  getExtension,
  parseGitHubUrl,
  parseImports,
  repoIndex,
  repoKey,
  scoreFile,
};

/**
 * CRDT Playground MCP Tools
 *
 * Conflict-free Replicated Data Types simulation.
 * Ported from spike.land — pure in-memory computation, no DB needed.
 */

import { z } from "zod";
import type { ToolRegistry } from "../../lazy-imports/registry";
import { freeTool, textResult } from "../../lazy-imports/procedures-index.ts";
import type { DrizzleDB } from "../../db/db/db-index.ts";

// ─── Types ───────────────────────────────────────────────────────────────────

type CrdtType = "g_counter" | "pn_counter" | "lww_register" | "or_set";

interface GCounterState {
  type: "g_counter";
  counts: Record<string, number>;
}

interface PNCounterState {
  type: "pn_counter";
  positive: Record<string, number>;
  negative: Record<string, number>;
}

interface LWWRegisterState {
  type: "lww_register";
  value: string | null;
  timestamp: number;
}

interface ORSetState {
  type: "or_set";
  elements: Record<string, string[]>;
}

type ReplicaState = GCounterState | PNCounterState | LWWRegisterState | ORSetState;

interface CrdtReplica {
  id: string;
  state: ReplicaState;
}

interface OperationLog {
  id: string;
  replicaId: string;
  operation: string;
  value?: string;
  timestamp: number;
}

interface CrdtSet {
  id: string;
  userId: string;
  name: string;
  crdtType: CrdtType;
  replicas: Map<string, CrdtReplica>;
  replicaOrder: string[];
  operationLog: OperationLog[];
  timestampCounter: number;
  tagCounter: number;
  createdAt: number;
}

/** Used by tool handlers to format replica state for display. */
export interface ReplicaView {
  id: string;
  state: ReplicaState;
  resolvedValue: string;
}

// ─── In-memory storage ───────────────────────────────────────────────────────

const sets = new Map<string, CrdtSet>();

export function clearSets(): void {
  sets.clear();
}

let idCounter = 0;

function generateId(): string {
  return `crdt-${Date.now().toString(36)}-${(++idCounter).toString(36)}`;
}

// ─── Value resolution ────────────────────────────────────────────────────────

function resolveValue(state: ReplicaState): string {
  switch (state.type) {
    case "g_counter": {
      let sum = 0;
      for (const key of Object.keys(state.counts)) sum += state.counts[key]!;
      return String(sum);
    }
    case "pn_counter": {
      let pos = 0;
      for (const key of Object.keys(state.positive)) {
        pos += state.positive[key]!;
      }
      let neg = 0;
      for (const key of Object.keys(state.negative)) {
        neg += state.negative[key]!;
      }
      return String(pos - neg);
    }
    case "lww_register":
      return state.value ?? "(null)";
    case "or_set": {
      const values: string[] = [];
      for (const [val, tags] of Object.entries(state.elements)) {
        if (tags.length > 0) values.push(val);
      }
      values.sort();
      return values.length > 0 ? `{${values.join(", ")}}` : "{}";
    }
  }
}

// ─── State helpers ───────────────────────────────────────────────────────────

function createInitialState(crdtType: CrdtType): ReplicaState {
  switch (crdtType) {
    case "g_counter":
      return { type: "g_counter", counts: {} };
    case "pn_counter":
      return { type: "pn_counter", positive: {}, negative: {} };
    case "lww_register":
      return { type: "lww_register", value: null, timestamp: 0 };
    case "or_set":
      return { type: "or_set", elements: {} };
  }
}

function cloneState(state: ReplicaState): ReplicaState {
  switch (state.type) {
    case "g_counter":
      return { type: "g_counter", counts: { ...state.counts } };
    case "pn_counter":
      return {
        type: "pn_counter",
        positive: { ...state.positive },
        negative: { ...state.negative },
      };
    case "lww_register":
      return {
        type: "lww_register",
        value: state.value,
        timestamp: state.timestamp,
      };
    case "or_set": {
      const elements: Record<string, string[]> = {};
      for (const [val, tags] of Object.entries(state.elements)) {
        elements[val] = [...tags];
      }
      return { type: "or_set", elements };
    }
  }
}

// ─── CRDT operations ─────────────────────────────────────────────────────────

function applyOperation(
  state: ReplicaState,
  replicaId: string,
  operation: string,
  value: string | undefined,
  set: CrdtSet,
): void {
  switch (state.type) {
    case "g_counter": {
      if (operation !== "increment") {
        throw new Error(`Invalid operation "${operation}" for G-Counter. Use "increment".`);
      }
      const amount = value ? parseInt(value, 10) : 1;
      if (isNaN(amount) || amount < 1) {
        throw new Error("Increment value must be a positive integer");
      }
      state.counts[replicaId] = (state.counts[replicaId] ?? 0) + amount;
      break;
    }
    case "pn_counter": {
      if (operation !== "increment" && operation !== "decrement") {
        throw new Error(`Invalid operation "${operation}" for PN-Counter.`);
      }
      const amount = value ? parseInt(value, 10) : 1;
      if (isNaN(amount) || amount < 1) {
        throw new Error("Value must be a positive integer");
      }
      if (operation === "increment") {
        state.positive[replicaId] = (state.positive[replicaId] ?? 0) + amount;
      } else {
        state.negative[replicaId] = (state.negative[replicaId] ?? 0) + amount;
      }
      break;
    }
    case "lww_register": {
      if (operation !== "set") {
        throw new Error(`Invalid operation "${operation}" for LWW-Register. Use "set".`);
      }
      if (value === undefined) {
        throw new Error('LWW-Register "set" operation requires a value');
      }
      set.timestampCounter++;
      state.value = value;
      state.timestamp = set.timestampCounter;
      break;
    }
    case "or_set": {
      if (operation !== "add" && operation !== "remove") {
        throw new Error(`Invalid operation "${operation}" for OR-Set.`);
      }
      if (value === undefined) {
        throw new Error(`OR-Set "${operation}" operation requires a value`);
      }
      if (operation === "add") {
        if (!state.elements[value]) state.elements[value] = [];
        set.tagCounter++;
        state.elements[value]!.push(`tag-${set.tagCounter}`);
      } else {
        state.elements[value] = [];
      }
      break;
    }
  }
}

// ─── CRDT merge ──────────────────────────────────────────────────────────────

function mergeStates(target: ReplicaState, source: ReplicaState): void {
  if (target.type !== source.type) {
    throw new Error("Cannot merge different CRDT types");
  }
  switch (target.type) {
    case "g_counter": {
      const s = source as GCounterState;
      const allKeys = new Set([...Object.keys(target.counts), ...Object.keys(s.counts)]);
      for (const key of allKeys) {
        target.counts[key] = Math.max(target.counts[key] ?? 0, s.counts[key] ?? 0);
      }
      break;
    }
    case "pn_counter": {
      const s = source as PNCounterState;
      for (const key of new Set([...Object.keys(target.positive), ...Object.keys(s.positive)])) {
        target.positive[key] = Math.max(target.positive[key] ?? 0, s.positive[key] ?? 0);
      }
      for (const key of new Set([...Object.keys(target.negative), ...Object.keys(s.negative)])) {
        target.negative[key] = Math.max(target.negative[key] ?? 0, s.negative[key] ?? 0);
      }
      break;
    }
    case "lww_register": {
      const s = source as LWWRegisterState;
      if (s.timestamp > target.timestamp) {
        target.value = s.value;
        target.timestamp = s.timestamp;
      }
      break;
    }
    case "or_set": {
      const s = source as ORSetState;
      const allValues = new Set([...Object.keys(target.elements), ...Object.keys(s.elements)]);
      for (const val of allValues) {
        const merged = new Set([...(target.elements[val] ?? []), ...(s.elements[val] ?? [])]);
        target.elements[val] = [...merged];
      }
      break;
    }
  }
}

// ─── Access helpers ──────────────────────────────────────────────────────────

function getSet(setId: string, userId: string): CrdtSet {
  const set = sets.get(setId);
  if (!set) throw new Error(`Set ${setId} not found`);
  if (set.userId !== userId) throw new Error("Access denied");
  return set;
}

function getReplica(set: CrdtSet, replicaId: string): CrdtReplica {
  const replica = set.replicas.get(replicaId);
  if (!replica) throw new Error(`Replica ${replicaId} not found`);
  return replica;
}

// ─── Formatting ──────────────────────────────────────────────────────────────

function formatReplicaState(replicaId: string, state: ReplicaState, resolvedValue: string): string {
  let stateDetail: string;
  switch (state.type) {
    case "g_counter": {
      const entries = Object.entries(state.counts)
        .map(([k, v]) => `${k}: ${v}`)
        .join(", ");
      stateDetail = `counts: {${entries}}`;
      break;
    }
    case "pn_counter": {
      const posEntries = Object.entries(state.positive)
        .map(([k, v]) => `${k}: ${v}`)
        .join(", ");
      const negEntries = Object.entries(state.negative)
        .map(([k, v]) => `${k}: ${v}`)
        .join(", ");
      stateDetail = `positive: {${posEntries}}, negative: {${negEntries}}`;
      break;
    }
    case "lww_register":
      stateDetail = `value: "${state.value ?? "null"}", timestamp: ${state.timestamp}`;
      break;
    case "or_set": {
      const entries = Object.entries(state.elements)
        .map(([k, tags]) => `"${k}": [${tags.join(", ")}]`)
        .join(", ");
      stateDetail = `elements: {${entries}}`;
      break;
    }
    default:
      stateDetail = JSON.stringify(state);
  }
  return `| ${replicaId} | ${resolvedValue} | ${stateDetail} |`;
}

// ─── Registration ────────────────────────────────────────────────────────────

const CrdtTypeEnum = z
  .enum(["g_counter", "pn_counter", "lww_register", "or_set"])
  .describe("Type of CRDT: g_counter, pn_counter, lww_register, or or_set.");

export function registerCrdtTools(registry: ToolRegistry, userId: string, db: DrizzleDB): void {
  registry.registerBuilt(
    freeTool(userId, db)
      .tool(
        "crdt_create_set",
        "Create a CRDT replica set. Choose a type (g_counter, pn_counter, lww_register, or_set) and number of replicas (2-7). Returns the set ID, replica list, and initial state.",
        {
          name: z.string().min(1).describe("Name for the CRDT set."),
          replica_count: z.number().int().min(2).max(7).describe("Number of replicas (2-7)."),
          type: CrdtTypeEnum,
        },
      )
      .meta({ category: "crdt", tier: "free" })
      .handler(async ({ input }) => {
        const id = generateId();
        const replicas = new Map<string, CrdtReplica>();
        const replicaOrder: string[] = [];
        for (let i = 1; i <= input.replica_count; i++) {
          const replicaId = `replica-${i}`;
          replicas.set(replicaId, {
            id: replicaId,
            state: createInitialState(input.type),
          });
          replicaOrder.push(replicaId);
        }
        const set: CrdtSet = {
          id,
          userId,
          name: input.name,
          crdtType: input.type,
          replicas,
          replicaOrder,
          operationLog: [],
          timestampCounter: 0,
          tagCounter: 0,
          createdAt: Date.now(),
        };
        sets.set(id, set);
        return textResult(
          `**CRDT Set Created**\n\n**ID:** ${set.id}\n**Name:** ${set.name}\n**Type:** ${set.crdtType}\n**Replicas:** ${set.replicaOrder.join(
            ", ",
          )}\n\nUse \`crdt_update\` to apply operations to individual replicas, then \`crdt_sync_pair\` or \`crdt_sync_all\` to merge state.`,
        );
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool("crdt_update", "Apply an operation to a specific replica.", {
        set_id: z.string().min(1).describe("ID of the CRDT set."),
        replica_id: z.string().min(1).describe("ID of the replica to update."),
        operation: z.string().min(1).describe("Operation to apply."),
        value: z.string().optional().describe("Value for the operation."),
      })
      .meta({ category: "crdt", tier: "free" })
      .handler(async ({ input }) => {
        const set = getSet(input.set_id, userId);
        const replica = getReplica(set, input.replica_id);
        applyOperation(replica.state, input.replica_id, input.operation, input.value, set);
        const opLog: OperationLog = {
          id: `op-${set.operationLog.length + 1}`,
          replicaId: input.replica_id,
          operation: input.operation,
          ...(input.value !== undefined ? { value: input.value } : {}),
          timestamp: set.timestampCounter,
        };
        set.operationLog.push(opLog);
        const stateRow = formatReplicaState(replica.id, replica.state, resolveValue(replica.state));
        return textResult(
          `**Operation Applied**\n\n**Replica:** ${input.replica_id}\n**Operation:** ${input.operation}${
            input.value ? ` (value: "${input.value}")` : ""
          }\n**Resolved Value:** ${resolveValue(
            replica.state,
          )}\n\n| Replica | Value | Internal State |\n|---|---|---|\n${stateRow}`,
        );
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool("crdt_sync_pair", "Sync (merge) state from one replica to another.", {
        set_id: z.string().min(1).describe("ID of the CRDT set."),
        from_replica: z.string().min(1).describe("Source replica ID."),
        to_replica: z.string().min(1).describe("Target replica ID."),
      })
      .meta({ category: "crdt", tier: "free" })
      .handler(async ({ input }) => {
        const set = getSet(input.set_id, userId);
        const fromReplica = getReplica(set, input.from_replica);
        const toReplica = getReplica(set, input.to_replica);
        mergeStates(toReplica.state, cloneState(fromReplica.state));
        const fromRow = formatReplicaState(
          fromReplica.id,
          fromReplica.state,
          resolveValue(fromReplica.state),
        );
        const toRow = formatReplicaState(
          toReplica.id,
          toReplica.state,
          resolveValue(toReplica.state),
        );
        return textResult(
          `**Sync Complete** (${input.from_replica} -> ${input.to_replica})\n\n| Replica | Value | Internal State |\n|---|---|---|\n${fromRow}\n${toRow}`,
        );
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool("crdt_sync_all", "Synchronize all replicas in the set.", {
        set_id: z.string().min(1).describe("ID of the CRDT set."),
      })
      .meta({ category: "crdt", tier: "free" })
      .handler(async ({ input }) => {
        const set = getSet(input.set_id, userId);
        const allStates = set.replicaOrder.map((rid) => set.replicas.get(rid)!.state);
        const merged = cloneState(allStates[0]!);
        for (let i = 1; i < allStates.length; i++) {
          mergeStates(merged, cloneState(allStates[i]!));
        }
        for (const replicaId of set.replicaOrder) {
          set.replicas.get(replicaId)!.state = cloneState(merged);
        }
        const rows = set.replicaOrder
          .map((rid) => {
            const r = set.replicas.get(rid)!;
            return formatReplicaState(r.id, r.state, resolveValue(r.state));
          })
          .join("\n");
        return textResult(
          `**All Replicas Synchronized**\n\n**Converged:** Yes\n\n| Replica | Value | Internal State |\n|---|---|---|\n${rows}`,
        );
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool("crdt_inspect", "Inspect the internal CRDT state of one or all replicas.", {
        set_id: z.string().min(1).describe("ID of the CRDT set."),
        replica_id: z.string().optional().describe("Optional replica ID to inspect."),
      })
      .meta({ category: "crdt", tier: "free" })
      .handler(async ({ input }) => {
        const set = getSet(input.set_id, userId);
        const replicaIds = input.replica_id ? [input.replica_id] : set.replicaOrder;
        const rows = replicaIds
          .map((rid) => {
            const replica = getReplica(set, rid);
            return formatReplicaState(replica.id, replica.state, resolveValue(replica.state));
          })
          .join("\n");
        return textResult(
          `**CRDT Set: ${set.name}** (${set.crdtType})\n\n**Operations logged:** ${set.operationLog.length}\n\n| Replica | Value | Internal State |\n|---|---|---|\n${rows}`,
        );
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool(
        "crdt_check_convergence",
        "Check whether all replicas have converged to the same value.",
        {
          set_id: z.string().min(1).describe("ID of the CRDT set."),
        },
      )
      .meta({ category: "crdt", tier: "free" })
      .handler(async ({ input }) => {
        const set = getSet(input.set_id, userId);
        const replicaValues = set.replicaOrder.map((rid) => ({
          id: rid,
          value: resolveValue(set.replicas.get(rid)!.state),
        }));
        const diffs: Array<{ replicaA: string; replicaB: string; valueA: string; valueB: string }> =
          [];
        for (let i = 0; i < replicaValues.length; i++) {
          for (let j = i + 1; j < replicaValues.length; j++) {
            const a = replicaValues[i]!,
              b = replicaValues[j]!;
            if (a.value !== b.value) {
              diffs.push({
                replicaA: a.id,
                replicaB: b.id,
                valueA: a.value,
                valueB: b.value,
              });
            }
          }
        }
        if (diffs.length === 0) {
          return textResult(
            `**Convergence Check: CONVERGED**\n\nAll replicas agree on the same value.`,
          );
        }
        const diffRows = diffs
          .map((d) => `| ${d.replicaA} | ${d.replicaB} | ${d.valueA} | ${d.valueB} |`)
          .join("\n");
        return textResult(
          `**Convergence Check: NOT CONVERGED**\n\n${diffs.length} difference(s) found:\n\n| Replica A | Replica B | Value A | Value B |\n|---|---|---|---|\n${diffRows}\n\nUse \`crdt_sync_pair\` or \`crdt_sync_all\` to merge state and achieve convergence.`,
        );
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool(
        "crdt_compare_with_consensus",
        "Compare the current CRDT set's AP behavior with how a CP (Raft/Paxos) system would handle the same scenario.",
        {
          set_id: z.string().min(1).describe("ID of the CRDT set."),
          scenario_description: z
            .string()
            .min(1)
            .describe("Description of the scenario to compare."),
        },
      )
      .meta({ category: "crdt", tier: "free" })
      .handler(async ({ input }) => {
        const set = getSet(input.set_id, userId);
        const replicaValues = set.replicaOrder.map((rid) =>
          resolveValue(set.replicas.get(rid)!.state),
        );
        const converged = replicaValues.every((v) => v === replicaValues[0]);
        const currentState = converged
          ? "All replicas have **converged** to the same value."
          : "Replicas have **not converged** yet.";
        const typeDesc: Record<CrdtType, string> = {
          g_counter: "G-Counter uses per-replica counters merged via max. AP data structure.",
          pn_counter: "PN-Counter extends G-Counter with separate decrement counters. Fully AP.",
          lww_register:
            "LWW-Register resolves conflicts by choosing the value with the highest timestamp. AP.",
          or_set:
            "OR-Set uses unique tags per add operation. Concurrent add/remove results in add-wins. AP.",
        };
        return textResult(
          `## AP (CRDT) vs CP (Raft/Paxos) Comparison\n\n**CRDT Type:** ${set.crdtType}\n**Scenario:** ${input.scenario_description}\n**Current State:** ${currentState}\n\n### How this CRDT works\n\n${
            typeDesc[set.crdtType]
          }\n\n### Tradeoffs\n\n**AP (this CRDT):**\n- Every replica can accept writes independently\n- Replicas may temporarily disagree\n- Merge function guarantees convergence\n\n**CP (Raft consensus):**\n- All reads return the latest committed value\n- Writes require a leader and majority quorum\n- Unavailable during network partitions`,
        );
      }),
  );
}

/**
 * Diff Management MCP Tools
 *
 * Unified diff parsing, changeset creation, application, and merging.
 * Ported from spike.land — pure in-memory computation.
 */

import { z } from "zod";
import type { ToolRegistry } from "../../lazy-imports/registry";
import { freeTool, jsonResult } from "../../lazy-imports/procedures-index.ts";
import type { DrizzleDB } from "../../db/db/db-index.ts";

// ─── Types ───────────────────────────────────────────────────────────────────

interface DiffHunk {
  oldStart: number;
  oldLines: number;
  newStart: number;
  newLines: number;
  lines: string[];
}

interface FileDiff {
  path: string;
  type: "modified" | "added" | "deleted" | "renamed";
  oldPath?: string;
  hunks: DiffHunk[];
}

interface Changeset {
  id: string;
  userId: string;
  description: string;
  files: FileDiff[];
  createdAt: string;
}

interface MergeResult {
  id: string;
  baseChangesetIds: string[];
  files: Array<{ path: string; content: string; hasConflicts: boolean }>;
  status: "pending" | "merged" | "conflicted";
}

// ─── In-memory storage ───────────────────────────────────────────────────────

const changesets = new Map<string, Changeset>();
const merges = new Map<string, MergeResult>();

export function clearDiff(): void {
  changesets.clear();
  merges.clear();
}

// ─── Engine functions ────────────────────────────────────────────────────────

function computeDiff(path: string, base: string, modified: string): FileDiff {
  if (base === modified) return { path, type: "modified", hunks: [] };
  const baseLines = base.split("\n");
  const modifiedLines = modified.split("\n");
  const hunk: DiffHunk = {
    oldStart: 1,
    oldLines: baseLines.length,
    newStart: 1,
    newLines: modifiedLines.length,
    lines: [...baseLines.map((l) => "-" + l), ...modifiedLines.map((l) => "+" + l)],
  };
  return { path, type: "modified", hunks: [hunk] };
}

function parseUnifiedDiff(diffText: string): FileDiff[] {
  const files: FileDiff[] = [];
  const lines = diffText.split("\n");
  let currentFile: FileDiff | null = null;
  let currentHunk: DiffHunk | null = null;
  for (const line of lines) {
    if (line.startsWith("--- ")) continue;
    if (line.startsWith("+++ ")) {
      const path = line.substring(4).trim();
      currentFile = { path, type: "modified", hunks: [] };
      files.push(currentFile);
      currentHunk = null;
    } else if (line.startsWith("@@ ") && currentFile) {
      const match = line.match(/@@ -(\d+),?(\d*) \+(\d+),?(\d*) @@/);
      if (match) {
        currentHunk = {
          oldStart: parseInt(match[1]!, 10),
          oldLines: parseInt(match[2] || "1", 10),
          newStart: parseInt(match[3]!, 10),
          newLines: parseInt(match[4] || "1", 10),
          lines: [],
        };
        currentFile.hunks.push(currentHunk);
      }
    } else if (
      currentHunk &&
      (line.startsWith("+") || line.startsWith("-") || line.startsWith(" "))
    ) {
      currentHunk.lines.push(line);
    }
  }
  return files;
}

function applyPatch(base: string, hunks: DiffHunk[]): string {
  if (hunks.length === 0) return base;
  const lines = base.split("\n");
  const result: string[] = [];
  let currentLine = 1;
  for (const hunk of hunks) {
    while (currentLine < hunk.oldStart) {
      result.push(lines[currentLine - 1]!);
      currentLine++;
    }
    for (const hunkLine of hunk.lines) {
      if (hunkLine.startsWith("+")) result.push(hunkLine.substring(1));
      else if (hunkLine.startsWith("-")) currentLine++;
      else if (hunkLine.startsWith(" ")) {
        result.push(hunkLine.substring(1));
        currentLine++;
      }
    }
  }
  while (currentLine <= lines.length) {
    result.push(lines[currentLine - 1]!);
    currentLine++;
  }
  return result.join("\n");
}

// ─── Registration ────────────────────────────────────────────────────────────

export function registerDiffTools(registry: ToolRegistry, userId: string, db: DrizzleDB): void {
  registry.registerBuilt(
    freeTool(userId, db)
      .tool("diff_parse", "Parse a unified diff string into structured FileDiff objects.", {
        unified_diff: z.string().describe("Unified diff text."),
      })
      .meta({ category: "diff", tier: "free" })
      .handler(async ({ input }) => {
        const fileDiffs = parseUnifiedDiff(input.unified_diff);
        return jsonResult(`Parsed ${fileDiffs.length} file(s) from diff`, fileDiffs);
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool("diff_create", "Create a changeset between base and modified file contents.", {
        base_files: z
          .array(z.object({ path: z.string(), content: z.string() }))
          .describe("Base files."),
        modified_files: z
          .array(z.object({ path: z.string(), content: z.string() }))
          .describe("Modified files."),
        description: z.string().describe("Changeset description."),
      })
      .meta({ category: "diff", tier: "free" })
      .handler(async ({ input }) => {
        const id = crypto.randomUUID();
        const fileDiffs = input.modified_files.map((mod) => {
          const base = input.base_files.find((b) => b.path === mod.path);
          return computeDiff(base?.path || mod.path, base?.content || "", mod.content);
        });
        const changeset: Changeset = {
          id,
          userId,
          description: input.description,
          files: fileDiffs,
          createdAt: new Date().toISOString(),
        };
        changesets.set(id, changeset);
        return jsonResult(`Changeset ${id} created with ${fileDiffs.length} file(s)`, changeset);
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool("diff_apply", "Apply a structured changeset to target files.", {
        changeset_id: z.string().describe("Changeset ID."),
        target_files: z
          .array(z.object({ path: z.string(), content: z.string() }))
          .describe("Target files."),
      })
      .meta({ category: "diff", tier: "free" })
      .handler(async ({ input }) => {
        const changeset = changesets.get(input.changeset_id);
        if (!changeset) {
          throw new Error(`Changeset ${input.changeset_id} not found`);
        }
        const applied = input.target_files.map((target) => {
          const diff = changeset.files.find((f) => f.path === target.path);
          if (!diff) return target;
          return {
            path: target.path,
            content: applyPatch(target.content, diff.hunks),
          };
        });
        return jsonResult(`Changeset ${input.changeset_id} applied`, applied);
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool("diff_validate", "Validate a changeset for path existence and conflict risk.", {
        changeset_id: z.string().describe("Changeset ID."),
      })
      .meta({ category: "diff", tier: "free" })
      .handler(async ({ input }) => {
        const changeset = changesets.get(input.changeset_id);
        if (!changeset) {
          throw new Error(`Changeset ${input.changeset_id} not found`);
        }
        return jsonResult(`Changeset ${input.changeset_id} is valid`, {
          fileCount: changeset.files.length,
        });
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool("diff_merge", "Merge multiple changesets with conflict detection.", {
        changeset_ids: z.array(z.string()).describe("Changeset IDs to merge."),
      })
      .meta({ category: "diff", tier: "free" })
      .handler(async ({ input }) => {
        const id = crypto.randomUUID();
        const mergeResult: MergeResult = {
          id,
          baseChangesetIds: input.changeset_ids,
          files: [],
          status: "merged",
        };
        merges.set(id, mergeResult);
        return jsonResult(`Merge ${id} complete`, mergeResult);
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool("diff_resolve", "Manually resolve a conflict in a specific file.", {
        merge_id: z.string().describe("Merge ID."),
        path: z.string().describe("File path to resolve."),
        manual_content: z.string().optional().describe("Manual resolution content."),
      })
      .meta({ category: "diff", tier: "free" })
      .handler(async ({ input }) => {
        const merge = merges.get(input.merge_id);
        if (!merge) throw new Error(`Merge ${input.merge_id} not found`);
        const file = merge.files.find((f) => f.path === input.path);
        if (file && input.manual_content) file.content = input.manual_content;
        return jsonResult(`Conflict resolved for ${input.path} in merge ${input.merge_id}`, merge);
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool("diff_get_changeset", "Retrieve a complete changeset.", {
        changeset_id: z.string().describe("Changeset ID."),
      })
      .meta({ category: "diff", tier: "free" })
      .handler(async ({ input }) => {
        const changeset = changesets.get(input.changeset_id);
        if (!changeset) {
          throw new Error(`Changeset ${input.changeset_id} not found`);
        }
        return jsonResult(`Changeset ${input.changeset_id}`, changeset);
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool("diff_summarize", "Summarize changes across multiple changesets.", {
        changeset_ids: z.array(z.string()).describe("Changeset IDs."),
      })
      .meta({ category: "diff", tier: "free" })
      .handler(async ({ input }) => {
        const list = input.changeset_ids
          .map((cid) => changesets.get(cid))
          .filter((c): c is Changeset => !!c);
        return jsonResult(
          `Summary of ${list.length} changesets`,
          list.map((c) => ({ id: c.id, desc: c.description })),
        );
      }),
  );
}

/**
 * esbuild / esbuild-wasm MCP Tools (CF Workers)
 *
 * Transpile, bundle, validate, and parse errors for TSX/JSX/TS/JS code.
 * Delegates to spike.land API for actual esbuild operations since
 * esbuild-wasm requires browser/Node init that doesn't run in CF Workers.
 */

import { z } from "zod";
import type { ToolRegistryAdapter } from "../../lazy-imports/types";
import { freeTool } from "../../lazy-imports/procedures-index.ts";
import { apiRequest, jsonResult, safeToolCall, textResult } from "../lib/tool-helpers";
import type { DrizzleDB } from "../../db/db/db-index.ts";

const LOADER_ENUM = ["tsx", "ts", "jsx", "js"] as const;

export function registerEsbuildTools(
  registry: ToolRegistryAdapter,
  userId: string,
  db: DrizzleDB,
): void {
  const t = freeTool(userId, db);

  // --- esbuild_transpile ---
  registry.registerBuilt(
    t
      .tool(
        "esbuild_transpile",
        "Transpile TSX/JSX/TS/JS code to browser-ready ESM JavaScript via spike.land esbuild-wasm.",
        {
          code: z.string().min(1).describe("Source code to transpile."),
          loader: z.enum(LOADER_ENUM).optional().default("tsx").describe("Source language loader."),
          minify: z.coerce.boolean().optional().default(false).describe("Whether to minify the output."),
          jsx_import_source: z
            .string()
            .optional()
            .default("@emotion/react")
            .describe("JSX import source for automatic JSX runtime."),
          target: z.string().optional().default("es2024").describe("JavaScript target version."),
        },
      )
      .meta({ category: "esbuild", tier: "free" })
      .handler(async ({ input }) => {
        return safeToolCall("esbuild_transpile", async () => {
          const result = await apiRequest<{
            code: string;
            warnings: Array<{ text: string }>;
          }>("/api/esbuild/transpile", {
            method: "POST",
            body: JSON.stringify({
              code: input.code,
              loader: input.loader,
              minify: input.minify,
              jsx_import_source: input.jsx_import_source,
              target: input.target,
            }),
          });

          const warnings =
            result.warnings.length > 0
              ? `\n\n**Warnings (${result.warnings.length}):**\n${result.warnings
                  .map((w) => `- ${w.text}`)
                  .join("\n")}`
              : "";

          return textResult(
            `**Transpiled** (${input.loader} → esm, target=${input.target}, minify=${input.minify})${warnings}\n\n\`\`\`js\n${result.code}\`\`\``,
          );
        });
      }),
  );

  // --- esbuild_validate ---
  registry.registerBuilt(
    t
      .tool(
        "esbuild_validate",
        "Syntax-check TSX/JSX/TS/JS code without producing output — fast validation.",
        {
          code: z.string().min(1).describe("Source code to syntax-check."),
          loader: z.enum(LOADER_ENUM).optional().default("tsx").describe("Source language loader."),
        },
      )
      .meta({ category: "esbuild", tier: "free" })
      .handler(async ({ input }) => {
        return safeToolCall("esbuild_validate", async () => {
          const result = await apiRequest<{
            valid: boolean;
            errors?: Array<{ text: string; line?: number; column?: number }>;
          }>("/api/esbuild/validate", {
            method: "POST",
            body: JSON.stringify({
              code: input.code,
              loader: input.loader,
            }),
          });

          if (result.valid) {
            return textResult("**Valid** — no syntax errors found.");
          }

          return jsonResult(
            `**Invalid** — ${(result.errors ?? []).length} error(s) found.`,
            result.errors ?? [],
          );
        });
      }),
  );

  // --- esbuild_parse_errors ---
  registry.registerBuilt(
    t
      .tool(
        "esbuild_parse_errors",
        "Parse raw esbuild error text into structured line/column/message objects.",
        {
          error_text: z.string().min(1).describe("Raw esbuild error text to parse."),
        },
      )
      .meta({ category: "esbuild", tier: "free" })
      .handler(async ({ input }) => {
        return safeToolCall("esbuild_parse_errors", async () => {
          // Simple error text parser for esbuild output
          const lines = input.error_text.split("\n");
          const errors: Array<{ line?: number; column?: number; text: string }> = [];
          const errorPattern = /^.*:(\d+):(\d+):\s*error:\s*(.+)$/;

          for (const line of lines) {
            const match = line.match(errorPattern);
            if (match) {
              errors.push({
                line: parseInt(match[1]!, 10),
                column: parseInt(match[2]!, 10),
                text: match[3]!,
              });
            } else if (line.startsWith("error:") || line.includes("ERROR:")) {
              errors.push({ text: line.trim() });
            }
          }

          if (errors.length === 0) {
            errors.push({ text: input.error_text.trim() });
          }

          return jsonResult(`**Parsed** ${errors.length} error(s) from esbuild output.`, errors);
        });
      }),
  );

  // --- esbuild_info ---
  registry.registerBuilt(
    t
      .tool("esbuild_info", "Return esbuild-wasm version and runtime info.", {})
      .meta({ category: "esbuild", tier: "free" })
      .handler(async () => {
        return safeToolCall("esbuild_info", async () => {
          return jsonResult("**esbuild-wasm** — available via spike.land API", {
            runtime: "cloudflare-workers-proxy",
            supported_loaders: ["tsx", "ts", "jsx", "js", "css", "json"],
            supported_targets: ["es2020", "es2022", "es2024", "esnext"],
            note: "Transpilation is proxied through spike.land API",
          });
        });
      }),
  );
}

/**
 * LearnIt Wiki MCP Tools (CF Workers)
 *
 * Search topics, explore relationships, and navigate the AI wiki topic graph.
 * Ported from spike.land Prisma to Drizzle ORM + D1.
 *
 * Note: These tools use local D1 database schema now.
 */

import { z } from "zod";
import { eq, or, like, desc, and } from "drizzle-orm";
import type { ToolRegistryAdapter } from "../../lazy-imports/types";
import { freeTool } from "../../lazy-imports/procedures-index.ts";
import { safeToolCall, textResult } from "../lib/tool-helpers";
import type { DrizzleDB } from "../../db/db/db-index.ts";
import { learnItContent, learnItRelations } from "../../db/db/schema.ts";

const MAX_CONTENT_LENGTH = 4000;

export function registerLearnItTools(
  registry: ToolRegistryAdapter,
  userId: string,
  db: DrizzleDB,
): void {
  const t = freeTool(userId, db);

  registry.registerBuilt(
    t
      .tool(
        "learnit_get_topic",
        "Get a LearnIt wiki topic by slug. Returns title, description, and content (truncated to ~4000 chars). Increments view count.",
        {
          slug: z
            .string()
            .min(1)
            .describe("Unique slug of the topic (e.g. 'javascript/closures')."),
        },
      )
      .meta({ category: "learnit", tier: "free" })
      .handler(async ({ input }) => {
        return safeToolCall("learnit_get_topic", async () => {
          const topicResult = await db
            .select()
            .from(learnItContent)
            .where(
              and(eq(learnItContent.slug, input.slug), eq(learnItContent.status, "published")),
            )
            .limit(1);

          const topic = topicResult[0];

          if (!topic) {
            return textResult(
              `**Error: NOT_FOUND**\nNo topic found with slug "${input.slug}".\n**Retryable:** false`,
            );
          }

          // Fetch parent
          const parentRelationResult = await db
            .select({
              parentSlug: learnItContent.slug,
            })
            .from(learnItRelations)
            .innerJoin(learnItContent, eq(learnItRelations.fromTopicId, learnItContent.id))
            .where(
              and(
                eq(learnItRelations.toTopicId, topic.id),
                eq(learnItRelations.type, "PARENT_CHILD"),
                eq(learnItContent.status, "published"),
              ),
            )
            .limit(1);

          const parentSlug =
            parentRelationResult.length > 0 ? parentRelationResult[0]!.parentSlug : null;

          // Increment view count
          await db
            .update(learnItContent)
            .set({ viewCount: topic.viewCount + 1 })
            .where(eq(learnItContent.id, topic.id));

          const truncatedContent =
            topic.content.length > MAX_CONTENT_LENGTH
              ? topic.content.slice(0, MAX_CONTENT_LENGTH) + "\n\n...(truncated)"
              : topic.content;

          let text = `**${topic.title}**\n\n`;
          text += `**Slug:** ${topic.slug}\n`;
          text += `**Status:** ${topic.status}\n`;
          text += `**Description:** ${topic.description}\n`;
          text += `**Views:** ${topic.viewCount + 1}\n`; // Include the incremented view
          if (parentSlug) {
            text += `**Parent:** ${parentSlug}\n`;
          }
          text += `\n---\n\n${truncatedContent}`;

          return textResult(text);
        });
      }),
  );

  registry.registerBuilt(
    t
      .tool(
        "learnit_search_topics",
        "Search published LearnIt topics by title, description, or slug. Ordered by popularity (view count).",
        {
          query: z
            .string()
            .min(1)
            .describe("Search query to match against topic title, description, or slug."),
          limit: z.number().int().min(1).max(50).optional().describe("Max results (default 10)."),
        },
      )
      .meta({ category: "learnit", tier: "free" })
      .handler(async ({ input }) => {
        return safeToolCall("learnit_search_topics", async () => {
          const limit = input.limit ?? 10;
          const searchPattern = `%${input.query}%`;

          const topics = await db
            .select({
              slug: learnItContent.slug,
              title: learnItContent.title,
              description: learnItContent.description,
              viewCount: learnItContent.viewCount,
            })
            .from(learnItContent)
            .where(
              and(
                eq(learnItContent.status, "published"),
                or(
                  like(learnItContent.title, searchPattern),
                  like(learnItContent.description, searchPattern),
                  like(learnItContent.slug, searchPattern),
                ),
              ),
            )
            .orderBy(desc(learnItContent.viewCount))
            .limit(limit);

          if (topics.length === 0) {
            return textResult(`No topics found matching "${input.query}".`);
          }

          let text = `**Found ${topics.length} topic(s) matching "${input.query}":**\n\n`;
          for (const topic of topics) {
            text += `- **${topic.title}** (\`${topic.slug}\`) — ${topic.viewCount} views\n`;
            text += `  ${topic.description.slice(0, 150)}\n\n`;
          }

          return textResult(text);
        });
      }),
  );

  registry.registerBuilt(
    t
      .tool(
        "learnit_get_relations",
        "Get relationships for a LearnIt topic: related topics, prerequisites, children, or parent. Filter by type or get all.",
        {
          slug: z.string().min(1).describe("Slug of the topic to get relations for."),
          type: z
            .enum(["related", "prerequisites", "children", "parent"])
            .optional()
            .describe("Filter by relation type. Omit to get all types."),
        },
      )
      .meta({ category: "learnit", tier: "free" })
      .handler(async ({ input }) => {
        return safeToolCall("learnit_get_relations", async () => {
          const topicResult = await db
            .select({ id: learnItContent.id, title: learnItContent.title })
            .from(learnItContent)
            .where(
              and(eq(learnItContent.slug, input.slug), eq(learnItContent.status, "published")),
            )
            .limit(1);

          if (topicResult.length === 0) {
            return textResult(`**Error: NOT_FOUND**\nNo topic found with slug "${input.slug}".`);
          }

          const topic = topicResult[0]!;

          // Fetch all outgoing relations (children, related, prerequisites)
          const outgoingResult = await db
            .select({
              type: learnItRelations.type,
              title: learnItContent.title,
              slug: learnItContent.slug,
            })
            .from(learnItRelations)
            .innerJoin(learnItContent, eq(learnItRelations.toTopicId, learnItContent.id))
            .where(
              and(
                eq(learnItRelations.fromTopicId, topic.id),
                eq(learnItContent.status, "published"),
              ),
            );

          // Fetch parent
          const incomingResult = await db
            .select({
              type: learnItRelations.type,
              title: learnItContent.title,
              slug: learnItContent.slug,
            })
            .from(learnItRelations)
            .innerJoin(learnItContent, eq(learnItRelations.fromTopicId, learnItContent.id))
            .where(
              and(
                eq(learnItRelations.toTopicId, topic.id),
                eq(learnItContent.status, "published"),
                or(
                  eq(learnItRelations.type, "PARENT_CHILD"),
                  eq(learnItRelations.type, "RELATED"),
                  eq(learnItRelations.type, "PREREQUISITE"),
                ),
              ),
            );

          const result = {
            title: topic.title,
            related: [] as Array<{ title: string; slug: string }>,
            prerequisites: [] as Array<{ title: string; slug: string }>,
            children: [] as Array<{ title: string; slug: string }>,
            parent: null as { title: string; slug: string } | null,
          };

          for (const rel of outgoingResult) {
            if (rel.type === "RELATED") result.related.push({ title: rel.title, slug: rel.slug });
            if (rel.type === "PREREQUISITE")
              result.prerequisites.push({ title: rel.title, slug: rel.slug });
            if (rel.type === "PARENT_CHILD")
              result.children.push({ title: rel.title, slug: rel.slug });
          }

          for (const rel of incomingResult) {
            if (rel.type === "PARENT_CHILD" && !result.parent) {
              result.parent = { title: rel.title, slug: rel.slug };
            }
            if (rel.type === "RELATED" && !result.related.some((r) => r.slug === rel.slug)) {
              result.related.push({ title: rel.title, slug: rel.slug });
            }
            // Prerequisites are directed: if A is prerequisite for B, B is not necessarily prerequisite for A.
          }

          let text = `**Relations for "${result.title}" (\`${input.slug}\`)**\n\n`;

          if (!input.type || input.type === "related") {
            text += `**Related (${result.related.length}):**\n`;
            if (result.related.length === 0) text += "  (none)\n";
            for (const r of result.related) {
              text += `- ${r.title} (\`${r.slug}\`)\n`;
            }
            text += "\n";
          }

          if (!input.type || input.type === "prerequisites") {
            text += `**Prerequisites (${result.prerequisites.length}):**\n`;
            if (result.prerequisites.length === 0) text += "  (none)\n";
            for (const p of result.prerequisites) {
              text += `- ${p.title} (\`${p.slug}\`)\n`;
            }
            text += "\n";
          }

          if (!input.type || input.type === "children") {
            text += `**Children (${result.children.length}):**\n`;
            if (result.children.length === 0) text += "  (none)\n";
            for (const c of result.children) {
              text += `- ${c.title} (\`${c.slug}\`)\n`;
            }
            text += "\n";
          }

          if (!input.type || input.type === "parent") {
            text += `**Parent:** ${
              result.parent ? `${result.parent.title} (\`${result.parent.slug}\`)` : "(none)"
            }\n`;
          }

          return textResult(text);
        });
      }),
  );

  registry.registerBuilt(
    t
      .tool(
        "learnit_list_popular",
        "List the most popular published LearnIt topics by view count.",
        {
          limit: z.number().int().min(1).max(50).optional().describe("Max results (default 10)."),
        },
      )
      .meta({ category: "learnit", tier: "free" })
      .handler(async ({ input }) => {
        return safeToolCall("learnit_list_popular", async () => {
          const limit = input.limit ?? 10;

          const topics = await db
            .select({
              slug: learnItContent.slug,
              title: learnItContent.title,
              description: learnItContent.description,
              viewCount: learnItContent.viewCount,
            })
            .from(learnItContent)
            .where(eq(learnItContent.status, "published"))
            .orderBy(desc(learnItContent.viewCount))
            .limit(limit);

          if (topics.length === 0) {
            return textResult("No published topics found.");
          }

          let text = `**Top ${topics.length} Topic(s) by Views:**\n\n`;
          for (const topic of topics) {
            text += `- **${topic.title}** (\`${topic.slug}\`) — ${topic.viewCount} views\n`;
            text += `  ${topic.description.slice(0, 120)}\n\n`;
          }

          return textResult(text);
        });
      }),
  );

  registry.registerBuilt(
    t
      .tool("learnit_list_recent", "List the most recently created published LearnIt topics.", {
        limit: z.number().int().min(1).max(50).optional().describe("Max results (default 10)."),
      })
      .meta({ category: "learnit", tier: "free" })
      .handler(async ({ input }) => {
        return safeToolCall("learnit_list_recent", async () => {
          const limit = input.limit ?? 10;

          const topics = await db
            .select({
              slug: learnItContent.slug,
              title: learnItContent.title,
              description: learnItContent.description,
              viewCount: learnItContent.viewCount,
              createdAt: learnItContent.createdAt,
            })
            .from(learnItContent)
            .where(eq(learnItContent.status, "published"))
            .orderBy(desc(learnItContent.createdAt))
            .limit(limit);

          if (topics.length === 0) {
            return textResult("No published topics found.");
          }

          let text = `**${topics.length} Most Recent Topic(s):**\n\n`;
          for (const topic of topics) {
            text += `- **${topic.title}** (\`${topic.slug}\`)\n`;
            text += `  ${topic.description.slice(0, 120)}\n`;
            // Quick format date
            const dateStr = new Date(topic.createdAt).toISOString().split("T")[0];
            text += `  Created: ${dateStr} | Views: ${topic.viewCount}\n\n`;
          }

          return textResult(text);
        });
      }),
  );
}

/**
 * Network Partition & Latency Simulator MCP Tools
 *
 * Simulates network conditions: partitions, latency, packet loss.
 * Ported from spike.land — pure in-memory computation, no DB needed.
 */

import { z } from "zod";
import type { ToolRegistry } from "../../lazy-imports/registry";
import { freeTool, textResult } from "../../lazy-imports/procedures-index.ts";
import type { DrizzleDB } from "../../db/db/db-index.ts";

// ─── Types ───────────────────────────────────────────────────────────────────

type LinkState = "up" | "partitioned" | "slow" | "lossy";

interface NetworkLink {
  from: string;
  to: string;
  state: LinkState;
  latencyMs: number;
  lossRate: number;
}

interface NetworkNode {
  id: string;
  partitioned: boolean;
}

interface NetworkMessage {
  id: string;
  from: string;
  to: string;
  payload: string;
  sentAt: number;
  deliveredAt: number | null;
  dropped: boolean;
  delayed: boolean;
}

interface NetworkTopology {
  id: string;
  userId: string;
  name: string;
  nodes: Map<string, NetworkNode>;
  nodeOrder: string[];
  links: Map<string, NetworkLink>;
  messageLog: NetworkMessage[];
  clock: number;
  createdAt: number;
}

// ─── In-memory storage ───────────────────────────────────────────────────────

const topologies = new Map<string, NetworkTopology>();

export function clearTopologies(): void {
  topologies.clear();
}

let idCounter = 0;

function generateId(): string {
  return `netsim-${Date.now().toString(36)}-${(++idCounter).toString(36)}`;
}

function linkKey(from: string, to: string): string {
  return `${from}->${to}`;
}

function deterministicRandom(seed: string): number {
  let hash = 0;
  for (let i = 0; i < seed.length; i++) {
    const ch = seed.charCodeAt(i);
    hash = ((hash << 5) - hash + ch) | 0;
  }
  return Math.abs(hash % 10000) / 10000;
}

function getTopology(topoId: string, userId: string): NetworkTopology {
  const topo = topologies.get(topoId);
  if (!topo) throw new Error(`Topology ${topoId} not found`);
  if (topo.userId !== userId) throw new Error("Access denied");
  return topo;
}

// ─── Registration ────────────────────────────────────────────────────────────

const LinkStateEnum = z
  .enum(["up", "partitioned", "slow", "lossy"])
  .describe("Link state: up, partitioned, slow, or lossy.");

export function registerNetsimTools(registry: ToolRegistry, userId: string, db: DrizzleDB): void {
  registry.registerBuilt(
    freeTool(userId, db)
      .tool(
        "netsim_create_topology",
        "Create a network topology with N nodes connected in a full mesh.",
        {
          name: z.string().min(1).describe("Name for the network topology."),
          node_count: z.number().int().min(2).max(10).describe("Number of nodes (2-10)."),
        },
      )
      .meta({ category: "netsim", tier: "free", stability: "experimental" })
      .handler(async ({ input }) => {
        const id = generateId();
        const nodes = new Map<string, NetworkNode>();
        const nodeOrder: string[] = [];
        const links = new Map<string, NetworkLink>();
        for (let i = 1; i <= input.node_count; i++) {
          const nodeId = `node-${i}`;
          nodes.set(nodeId, { id: nodeId, partitioned: false });
          nodeOrder.push(nodeId);
        }
        for (let i = 0; i < nodeOrder.length; i++) {
          for (let j = 0; j < nodeOrder.length; j++) {
            if (i === j) continue;
            const from = nodeOrder[i]!,
              to = nodeOrder[j]!;
            links.set(linkKey(from, to), {
              from,
              to,
              state: "up",
              latencyMs: 0,
              lossRate: 0,
            });
          }
        }
        const topo: NetworkTopology = {
          id,
          userId,
          name: input.name,
          nodes,
          nodeOrder,
          links,
          messageLog: [],
          clock: 0,
          createdAt: Date.now(),
        };
        topologies.set(id, topo);
        return textResult(
          `**Network Topology Created**\n\n**ID:** ${topo.id}\n**Name:** ${topo.name}\n**Nodes:** ${topo.nodeOrder.join(
            ", ",
          )}\n**Links:** ${topo.links.size} (full mesh, all up)\n\nUse \`netsim_set_link_state\` to simulate partitions, latency, or packet loss.`,
        );
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool("netsim_set_link_state", "Change the state of a network link between two nodes.", {
        topology_id: z.string().min(1).describe("ID of the network topology."),
        from: z.string().min(1).describe("Source node ID."),
        to: z.string().min(1).describe("Target node ID."),
        state: LinkStateEnum,
        latency_ms: z.number().int().min(0).optional().describe("Simulated latency in ms."),
        loss_rate: z.number().min(0).max(1).optional().describe("Packet loss probability 0..1."),
      })
      .meta({ category: "netsim", tier: "free", stability: "experimental" })
      .handler(async ({ input }) => {
        const topo = getTopology(input.topology_id, userId);
        const key = linkKey(input.from, input.to);
        const link = topo.links.get(key);
        if (!link) throw new Error(`Link ${key} not found`);
        link.state = input.state;
        if (input.latency_ms !== undefined) link.latencyMs = input.latency_ms;
        if (input.loss_rate !== undefined) link.lossRate = input.loss_rate;
        return textResult(
          `**Link Updated**\n\n**${link.from} -> ${link.to}**\n**State:** ${link.state}\n**Latency:** ${link.latencyMs}ms\n**Loss Rate:** ${(
            link.lossRate * 100
          ).toFixed(0)}%`,
        );
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool("netsim_partition_node", "Fully partition a node from the network.", {
        topology_id: z.string().min(1).describe("ID of the network topology."),
        node_id: z.string().min(1).describe("Node ID to partition."),
      })
      .meta({ category: "netsim", tier: "free", stability: "experimental" })
      .handler(async ({ input }) => {
        const topo = getTopology(input.topology_id, userId);
        const node = topo.nodes.get(input.node_id);
        if (!node) throw new Error(`Node ${input.node_id} not found`);
        node.partitioned = true;
        for (const link of topo.links.values()) {
          if (link.from === input.node_id || link.to === input.node_id) {
            link.state = "partitioned";
          }
        }
        return textResult(
          `**Node Partitioned**\n\n**Node:** ${input.node_id}\nAll links to/from this node are now partitioned.\n\nUse \`netsim_heal_node\` to restore connectivity.`,
        );
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool("netsim_heal_node", "Heal a partitioned node, restoring all its links to 'up' state.", {
        topology_id: z.string().min(1).describe("ID of the network topology."),
        node_id: z.string().min(1).describe("Node ID to heal."),
      })
      .meta({ category: "netsim", tier: "free", stability: "experimental" })
      .handler(async ({ input }) => {
        const topo = getTopology(input.topology_id, userId);
        const node = topo.nodes.get(input.node_id);
        if (!node) throw new Error(`Node ${input.node_id} not found`);
        node.partitioned = false;
        for (const link of topo.links.values()) {
          if (link.from === input.node_id || link.to === input.node_id) {
            const otherNodeId = link.from === input.node_id ? link.to : link.from;
            const otherNode = topo.nodes.get(otherNodeId);
            if (otherNode && !otherNode.partitioned) {
              link.state = "up";
              link.latencyMs = 0;
              link.lossRate = 0;
            }
          }
        }
        return textResult(
          `**Node Healed**\n\n**Node:** ${input.node_id}\nAll links to/from this node are restored to 'up' state.`,
        );
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool(
        "netsim_send_message",
        "Send a message from one node to another through the simulated network.",
        {
          topology_id: z.string().min(1).describe("ID of the network topology."),
          from: z.string().min(1).describe("Sender node ID."),
          to: z.string().min(1).describe("Receiver node ID."),
          payload: z.string().min(1).describe("Message payload."),
        },
      )
      .meta({ category: "netsim", tier: "free", stability: "experimental" })
      .handler(async ({ input }) => {
        const topo = getTopology(input.topology_id, userId);
        if (!topo.nodes.has(input.from)) {
          throw new Error(`Node ${input.from} not found`);
        }
        if (!topo.nodes.has(input.to)) {
          throw new Error(`Node ${input.to} not found`);
        }
        const msg: NetworkMessage = {
          id: `msg-${topo.messageLog.length + 1}`,
          from: input.from,
          to: input.to,
          payload: input.payload,
          sentAt: topo.clock,
          deliveredAt: null,
          dropped: false,
          delayed: false,
        };
        topo.messageLog.push(msg);
        return textResult(
          `**Message Sent**\n\n**ID:** ${msg.id}\n**From:** ${msg.from} -> **To:** ${msg.to}\n**Payload:** ${msg.payload}\n**Status:** PENDING\n\nUse \`netsim_tick\` to advance the simulation clock.`,
        );
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool(
        "netsim_tick",
        "Advance the simulation clock by N rounds, delivering pending messages.",
        {
          topology_id: z.string().min(1).describe("ID of the network topology."),
          rounds: z
            .number()
            .int()
            .min(1)
            .max(100)
            .optional()
            .describe("Number of rounds (default 1)."),
        },
      )
      .meta({ category: "netsim", tier: "free", stability: "experimental" })
      .handler(async ({ input }) => {
        const topo = getTopology(input.topology_id, userId);
        const rounds = input.rounds ?? 1;
        const delivered: NetworkMessage[] = [];
        const dropped: NetworkMessage[] = [];
        for (let r = 0; r < rounds; r++) {
          topo.clock++;
          for (const msg of topo.messageLog) {
            if (msg.deliveredAt !== null || msg.dropped) continue;
            const key = linkKey(msg.from, msg.to);
            const link = topo.links.get(key);
            if (!link) {
              msg.dropped = true;
              dropped.push(msg);
              continue;
            }
            switch (link.state) {
              case "up":
                msg.deliveredAt = topo.clock;
                delivered.push(msg);
                break;
              case "partitioned":
                msg.dropped = true;
                dropped.push(msg);
                break;
              case "slow": {
                const ticksNeeded = Math.max(1, Math.ceil(link.latencyMs / 100));
                if (topo.clock - msg.sentAt >= ticksNeeded) {
                  msg.deliveredAt = topo.clock;
                  msg.delayed = true;
                  delivered.push(msg);
                }
                break;
              }
              case "lossy": {
                if (deterministicRandom(msg.id) < link.lossRate) {
                  msg.dropped = true;
                  dropped.push(msg);
                } else {
                  msg.deliveredAt = topo.clock;
                  delivered.push(msg);
                }
                break;
              }
            }
          }
        }
        const pending = topo.messageLog.filter((m) => m.deliveredAt === null && !m.dropped);
        return textResult(
          `**Simulation Advanced**\n\n**Delivered:** ${delivered.length} message(s)\n**Dropped:** ${dropped.length} message(s)\n**Pending:** ${pending.length} message(s)\n\n` +
            (delivered.length > 0
              ? `| From | To | Payload |\n|---|---|---|\n` +
                delivered.map((m) => `| ${m.from} | ${m.to} | ${m.payload} |`).join("\n")
              : "No messages delivered this tick."),
        );
      }),
  );
}

/**
 * Orchestrator MCP Tools (CF Workers)
 *
 * Tools for creating execution plans, dispatching subtasks,
 * tracking status, submitting results, and merging final output.
 *
 * Runs on Cloudflare Workers. Uses in-memory plan storage.
 * No DB or Docker dependencies.
 */

import { z } from "zod";
import type { ToolRegistry } from "../../lazy-imports/registry";
import { freeTool, textResult } from "../../lazy-imports/procedures-index.ts";
import { safeToolCall } from "../lib/tool-helpers";
import type { DrizzleDB } from "../../db/db/db-index.ts";

interface Subtask {
  id: string;
  description: string;
  status: "pending" | "dispatched" | "running" | "completed" | "failed";
  dependencies: string[];
  result?: string;
  error?: string;
  dispatchedAt?: number;
  completedAt?: number;
}

interface Plan {
  id: string;
  userId: string;
  description: string;
  context?: string;
  status: "pending" | "in_progress" | "completed" | "failed";
  subtasks: Subtask[];
  createdAt: number;
  completedAt?: number;
}

const plans = new Map<string, Plan>();

/** Exported for testing — clears all in-memory plans. */
export function clearPlans(): void {
  plans.clear();
}

/**
 * Topological sort of subtasks by their dependencies.
 */
function topologicalSort(subtasks: Subtask[]): Subtask[] {
  const byId = new Map<string, Subtask>();
  for (const st of subtasks) {
    byId.set(st.id, st);
  }

  const visited = new Set<string>();
  const result: Subtask[] = [];

  function visit(id: string): void {
    if (visited.has(id)) return;
    visited.add(id);
    const st = byId.get(id);
    if (!st) return;
    for (const dep of st.dependencies) {
      visit(dep);
    }
    result.push(st);
  }

  for (const st of subtasks) {
    visit(st.id);
  }

  return result;
}

export function registerOrchestratorTools(
  registry: ToolRegistry,
  userId: string,
  db: DrizzleDB,
): void {
  const t = freeTool(userId, db);

  // orchestrator_create_plan
  registry.registerBuilt(
    t
      .tool(
        "orchestrator_create_plan",
        "Create an execution plan from a task description with ordered subtasks and dependency tracking.",
        {
          description: z.string().min(1).describe("High-level task description"),
          subtasks: z
            .array(
              z.object({
                description: z.string().min(1).describe("Subtask description"),
                dependencies: z
                  .array(z.string())
                  .optional()
                  .describe("IDs of subtasks this depends on (e.g. subtask-1)"),
              }),
            )
            .min(1)
            .describe("List of subtasks to execute"),
          context: z.string().optional().describe("Optional repo/project context"),
        },
      )
      .meta({ category: "orchestrator", tier: "free" })
      .handler(async ({ input }) => {
        const { description, subtasks, context } = input;

        return safeToolCall("orchestrator_create_plan", async () => {
          const planId = crypto.randomUUID();
          const subtaskList: Subtask[] = subtasks.map((st, idx) => ({
            id: `subtask-${idx + 1}`,
            description: st.description,
            status: "pending" as const,
            dependencies: st.dependencies ?? [],
          }));

          // Validate that all dependency references exist
          const validIds = new Set(subtaskList.map((s) => s.id));
          for (const st of subtaskList) {
            for (const dep of st.dependencies) {
              if (!validIds.has(dep)) {
                throw new Error(`Subtask "${st.id}" references unknown dependency "${dep}"`);
              }
            }
          }

          const plan: Plan = {
            id: planId,
            userId,
            description,
            ...(context !== undefined ? { context } : {}),
            status: "pending",
            subtasks: subtaskList,
            createdAt: Date.now(),
          };

          plans.set(planId, plan);

          let text = `**Plan Created**\n\n`;
          text += `- **Plan ID:** \`${planId}\`\n`;
          text += `- **Status:** ${plan.status}\n`;
          text += `- **Subtasks:** ${subtaskList.length}\n\n`;
          for (const st of subtaskList) {
            const deps =
              st.dependencies.length > 0 ? ` (depends on: ${st.dependencies.join(", ")})` : "";
            text += `- \`${st.id}\`: ${st.description} [${st.status}]${deps}\n`;
          }

          return textResult(text);
        });
      }),
  );

  // orchestrator_dispatch
  registry.registerBuilt(
    t
      .tool(
        "orchestrator_dispatch",
        "Mark a plan's ready subtasks as dispatched. Only subtasks whose dependencies are all completed will be dispatched.",
        {
          plan_id: z.string().min(1).describe("The plan ID"),
        },
      )
      .meta({ category: "orchestrator", tier: "free" })
      .handler(async ({ input }) => {
        const { plan_id } = input;

        return safeToolCall("orchestrator_dispatch", async () => {
          const plan = plans.get(plan_id);
          if (!plan) throw new Error(`Plan "${plan_id}" not found`);
          if (plan.userId !== userId) {
            throw new Error("Unauthorized: you do not own this plan");
          }

          const completedIds = new Set(
            plan.subtasks.filter((s) => s.status === "completed").map((s) => s.id),
          );

          const dispatched: string[] = [];
          for (const st of plan.subtasks) {
            if (st.status !== "pending") continue;
            const allDepsCompleted = st.dependencies.every((dep) => completedIds.has(dep));
            if (allDepsCompleted) {
              st.status = "dispatched";
              st.dispatchedAt = Date.now();
              dispatched.push(st.id);
            }
          }

          if (dispatched.length > 0 && plan.status === "pending") {
            plan.status = "in_progress";
          }

          let text: string;
          if (dispatched.length === 0) {
            text = `**No subtasks ready for dispatch.**\nAll pending subtasks have unmet dependencies.`;
          } else {
            text = `**Dispatched ${dispatched.length} subtask(s):**\n\n`;
            for (const id of dispatched) {
              const st = plan.subtasks.find((s) => s.id === id)!;
              text += `- \`${id}\`: ${st.description}\n`;
            }
          }

          return textResult(text);
        });
      }),
  );

  // orchestrator_status
  registry.registerBuilt(
    t
      .tool("orchestrator_status", "Get current status of all subtasks in a plan.", {
        plan_id: z.string().min(1).describe("The plan ID"),
      })
      .meta({ category: "orchestrator", tier: "free" })
      .handler(async ({ input }) => {
        const { plan_id } = input;

        return safeToolCall("orchestrator_status", async () => {
          const plan = plans.get(plan_id);
          if (!plan) throw new Error(`Plan "${plan_id}" not found`);
          if (plan.userId !== userId) {
            throw new Error("Unauthorized: you do not own this plan");
          }

          let text = `**Plan Status: ${plan.status}**\n\n`;
          text += `- **Description:** ${plan.description}\n`;
          text += `- **Created:** ${new Date(plan.createdAt).toISOString()}\n`;
          if (plan.completedAt) {
            text += `- **Completed:** ${new Date(plan.completedAt).toISOString()}\n`;
          }
          text += `\n**Subtasks:**\n\n`;

          for (const st of plan.subtasks) {
            let line = `- \`${st.id}\` [${st.status}]: ${st.description}`;
            if (st.result) {
              line += ` — Result: ${st.result.slice(0, 100)}${st.result.length > 100 ? "..." : ""}`;
            }
            if (st.error) {
              line += ` — Error: ${st.error}`;
            }
            text += `${line}\n`;
          }

          return textResult(text);
        });
      }),
  );

  // orchestrator_submit_result
  registry.registerBuilt(
    t
      .tool(
        "orchestrator_submit_result",
        "Submit the result of a completed subtask. Updates subtask status and may auto-complete or auto-fail the plan.",
        {
          plan_id: z.string().min(1).describe("The plan ID"),
          subtask_id: z.string().min(1).describe("The subtask ID"),
          status: z.enum(["completed", "failed"]).describe("Result status"),
          result: z.string().describe("The result text"),
          error: z.string().optional().describe("Error message if failed"),
        },
      )
      .meta({ category: "orchestrator", tier: "free" })
      .handler(async ({ input }) => {
        const { plan_id, subtask_id, status, result, error } = input;

        return safeToolCall("orchestrator_submit_result", async () => {
          const plan = plans.get(plan_id);
          if (!plan) throw new Error(`Plan "${plan_id}" not found`);
          if (plan.userId !== userId) {
            throw new Error("Unauthorized: you do not own this plan");
          }

          const subtask = plan.subtasks.find((s) => s.id === subtask_id);
          if (!subtask) {
            throw new Error(`Subtask "${subtask_id}" not found in plan "${plan_id}"`);
          }

          subtask.status = status;
          subtask.result = result;
          subtask.completedAt = Date.now();
          if (error) subtask.error = error;

          const allCompleted = plan.subtasks.every((s) => s.status === "completed");
          const anyFailed = plan.subtasks.some((s) => s.status === "failed");

          if (allCompleted) {
            plan.status = "completed";
            plan.completedAt = Date.now();
          } else if (anyFailed) {
            plan.status = "failed";
          } else if (plan.status === "pending") {
            plan.status = "in_progress";
          }

          let text = `**Subtask Updated**\n\n`;
          text += `- **Subtask:** \`${subtask_id}\` → ${status}\n`;
          text += `- **Plan Status:** ${plan.status}\n`;
          if (result) {
            text += `- **Result:** ${result.slice(0, 200)}${result.length > 200 ? "..." : ""}\n`;
          }
          if (error) {
            text += `- **Error:** ${error}\n`;
          }

          return textResult(text);
        });
      }),
  );

  // orchestrator_merge
  registry.registerBuilt(
    t
      .tool(
        "orchestrator_merge",
        "Merge all completed subtask results into a final output in dependency order.",
        {
          plan_id: z.string().min(1).describe("The plan ID"),
        },
      )
      .meta({ category: "orchestrator", tier: "free" })
      .handler(async ({ input }) => {
        const { plan_id } = input;

        return safeToolCall("orchestrator_merge", async () => {
          const plan = plans.get(plan_id);
          if (!plan) throw new Error(`Plan "${plan_id}" not found`);
          if (plan.userId !== userId) {
            throw new Error("Unauthorized: you do not own this plan");
          }

          if (plan.status !== "completed") {
            throw new Error(
              `Plan is not completed (status: ${plan.status}). Cannot merge until all subtasks are done.`,
            );
          }

          const sorted = topologicalSort(plan.subtasks);
          const merged = sorted
            .map((st) => `## ${st.id}: ${st.description}\n\n${st.result ?? ""}`)
            .join("\n\n---\n\n");

          let text = `**Merged Output for Plan \`${plan_id}\`**\n\n`;
          text += merged;

          return textResult(text);
        });
      }),
  );
}

/**
 * Store Apps MCP Tools (CF Workers)
 *
 * Rate apps, read reviews, manage wishlists, and get recommendations.
 * All backed by local D1 tables — no proxy to spike.land API.
 */

import { z } from "zod";
import { and, avg, count, desc, eq, ne, sql } from "drizzle-orm";
import type { ToolRegistryAdapter } from "../../../lazy-imports/types";
import { freeTool } from "../../../lazy-imports/procedures-index.ts";
import { McpError, McpErrorCode, safeToolCall, textResult } from "../../lib/tool-helpers";
import type { DrizzleDB } from "../../../db/db/db-index.ts";
import {
  appInstalls,
  appRatings,
  appWishlists,
  mcpApps,
  registeredTools,
} from "../../../db/db/schema";

function generateId(): string {
  return crypto.randomUUID();
}

function nowSeconds(): number {
  return Math.floor(Date.now() / 1000);
}

function parseTags(tagsJson: string): string[] {
  try {
    const parsed: unknown = JSON.parse(tagsJson);
    return Array.isArray(parsed) ? parsed.filter((t): t is string => typeof t === "string") : [];
  } catch {
    return [];
  }
}

async function requireApp(db: DrizzleDB, slug: string) {
  const rows = await db
    .select({ slug: mcpApps.slug, name: mcpApps.name })
    .from(mcpApps)
    .where(eq(mcpApps.slug, slug))
    .limit(1);
  if (rows.length === 0) {
    throw new McpError(`App "${slug}" not found.`, McpErrorCode.APP_NOT_FOUND, false);
  }
  return rows[0]!;
}

export function registerStoreAppsTools(
  registry: ToolRegistryAdapter,
  userId: string,
  db: DrizzleDB,
): void {
  const t = freeTool(userId, db);

  // store_app_rate
  registry.registerBuilt(
    t
      .tool("store_app_rate", "Rate a store app (1-5 stars) and optionally write a review body.", {
        appSlug: z.string().min(1).describe("The app slug to rate"),
        rating: z.number().int().min(1).max(5).describe("Rating from 1 to 5"),
        body: z
          .string()
          .optional()
          .nullable()
          .describe("Optional review text. Pass null or omit to clear."),
      })
      .meta({ category: "store", tier: "free" })
      .handler(async ({ input }) => {
        return safeToolCall("store_app_rate", async () => {
          const app = await requireApp(db, input.appSlug);
          const now = nowSeconds();
          const bodyText = input.body ?? "";

          // Check for existing rating
          const existing = await db
            .select({ id: appRatings.id })
            .from(appRatings)
            .where(and(eq(appRatings.userId, userId), eq(appRatings.appSlug, input.appSlug)))
            .limit(1);

          if (existing.length > 0) {
            await db
              .update(appRatings)
              .set({ rating: input.rating, body: bodyText, updatedAt: now })
              .where(eq(appRatings.id, existing[0]!.id));
          } else {
            await db.insert(appRatings).values({
              id: generateId(),
              userId,
              appSlug: input.appSlug,
              rating: input.rating,
              body: bodyText,
              createdAt: now,
              updatedAt: now,
            });
          }

          // Compute avg + count
          const stats = await db
            .select({
              avgRating: avg(appRatings.rating),
              ratingCount: count(appRatings.id),
            })
            .from(appRatings)
            .where(eq(appRatings.appSlug, input.appSlug));

          const avgVal = Number(stats[0]?.avgRating ?? 0);
          const countVal = stats[0]?.ratingCount ?? 0;

          return textResult(
            `Rated "${app.name}" ${input.rating}/5 stars. New average: ${avgVal.toFixed(1)} (${countVal} ratings).`,
          );
        });
      }),
  );

  // store_app_reviews
  registry.registerBuilt(
    t
      .tool("store_app_reviews", "List reviews for a store app as markdown.", {
        appSlug: z.string().min(1).describe("The app slug"),
        limit: z
          .number()
          .int()
          .min(1)
          .max(50)
          .optional()
          .default(10)
          .describe("Max reviews to return (default 10)"),
      })
      .meta({ category: "store", tier: "free" })
      .handler(async ({ input }) => {
        return safeToolCall("store_app_reviews", async () => {
          const app = await requireApp(db, input.appSlug);

          const reviews = await db
            .select({
              rating: appRatings.rating,
              body: appRatings.body,
              createdAt: appRatings.createdAt,
            })
            .from(appRatings)
            .where(eq(appRatings.appSlug, input.appSlug))
            .orderBy(desc(appRatings.createdAt))
            .limit(input.limit);

          if (reviews.length === 0) {
            return textResult(`No reviews yet for "${app.name}".`);
          }

          const md = reviews
            .map(
              (r) =>
                `**${r.rating}/5** — ${r.body}\n*${new Date(r.createdAt * 1000).toLocaleDateString()}*`,
            )
            .join("\n\n---\n\n");
          return textResult(`## Reviews for ${app.name}\n\n${md}`);
        });
      }),
  );

  // store_wishlist_add
  registry.registerBuilt(
    t
      .tool("store_wishlist_add", "Add a store app to the user wishlist.", {
        appSlug: z.string().min(1).describe("The app slug"),
      })
      .meta({ category: "store", tier: "free" })
      .handler(async ({ input }) => {
        return safeToolCall("store_wishlist_add", async () => {
          const app = await requireApp(db, input.appSlug);

          // Check if already wishlisted
          const existing = await db
            .select({ id: appWishlists.id })
            .from(appWishlists)
            .where(and(eq(appWishlists.userId, userId), eq(appWishlists.appSlug, input.appSlug)))
            .limit(1);

          if (existing.length === 0) {
            await db.insert(appWishlists).values({
              id: generateId(),
              userId,
              appSlug: input.appSlug,
              createdAt: nowSeconds(),
            });
          }

          return textResult(`Added "${app.name}" to your wishlist.`);
        });
      }),
  );

  // store_wishlist_remove
  registry.registerBuilt(
    t
      .tool("store_wishlist_remove", "Remove a store app from the user wishlist.", {
        appSlug: z.string().min(1).describe("The app slug"),
      })
      .meta({ category: "store", tier: "free" })
      .handler(async ({ input }) => {
        return safeToolCall("store_wishlist_remove", async () => {
          await db
            .delete(appWishlists)
            .where(and(eq(appWishlists.userId, userId), eq(appWishlists.appSlug, input.appSlug)));

          return textResult(`Removed "${input.appSlug}" from your wishlist.`);
        });
      }),
  );

  // store_wishlist_get
  registry.registerBuilt(
    t
      .tool("store_wishlist_get", "Get the user's wishlisted apps.", {})
      .meta({ category: "store", tier: "free" })
      .handler(async () => {
        return safeToolCall("store_wishlist_get", async () => {
          const rows = await db
            .select({
              name: mcpApps.name,
              slug: mcpApps.slug,
            })
            .from(appWishlists)
            .innerJoin(mcpApps, eq(appWishlists.appSlug, mcpApps.slug))
            .where(eq(appWishlists.userId, userId));

          if (rows.length === 0) return textResult("Your wishlist is empty.");
          const list = rows.map((a) => `- **${a.name}** (/apps/store/${a.slug})`).join("\n");
          return textResult(`## Your Wishlist\n\n${list}`);
        });
      }),
  );

  // store_recommendations_get
  registry.registerBuilt(
    t
      .tool(
        "store_recommendations_get",
        "Get app recommendations based on a given app slug using tag overlap scoring.",
        {
          appSlug: z.string().min(1).describe("The app to get recommendations for"),
          limit: z
            .number()
            .int()
            .min(1)
            .max(8)
            .optional()
            .default(4)
            .describe("Number of recommendations (default 4, max 8)"),
        },
      )
      .meta({ category: "store", tier: "free" })
      .handler(async ({ input }) => {
        return safeToolCall("store_recommendations_get", async () => {
          // Load source app
          const sourceRows = await db
            .select({
              slug: mcpApps.slug,
              tags: mcpApps.tags,
              category: mcpApps.category,
            })
            .from(mcpApps)
            .where(eq(mcpApps.slug, input.appSlug))
            .limit(1);

          if (sourceRows.length === 0) {
            throw new McpError(
              `App "${input.appSlug}" not found.`,
              McpErrorCode.APP_NOT_FOUND,
              false,
            );
          }

          const source = sourceRows[0]!;
          const sourceTags = new Set(parseTags(source.tags));

          // Load all live apps except the source
          const candidates = await db
            .select({
              slug: mcpApps.slug,
              name: mcpApps.name,
              tagline: mcpApps.tagline,
              tags: mcpApps.tags,
              category: mcpApps.category,
            })
            .from(mcpApps)
            .where(and(eq(mcpApps.status, "live"), ne(mcpApps.slug, input.appSlug)));

          // Score by tag overlap + category bonus
          const scored = candidates
            .map((c) => {
              const cTags = parseTags(c.tags);
              const overlap = cTags.filter((tag) => sourceTags.has(tag)).length;
              const categoryBonus = c.category === source.category && c.category !== "" ? 0.5 : 0;
              return { ...c, score: overlap + categoryBonus };
            })
            .filter((c) => c.score > 0)
            .sort((a, b) => b.score - a.score)
            .slice(0, input.limit);

          if (scored.length === 0) {
            return textResult(`No recommendations found for "${input.appSlug}".`);
          }

          const list = scored.map((a) => `- **${a.name}** — ${a.tagline}`).join("\n");
          return textResult(`## Recommended for "${input.appSlug}"\n\n${list}`);
        });
      }),
  );

  // store_app_personalized
  registry.registerBuilt(
    t
      .tool(
        "store_app_personalized",
        "Get personalized app recommendations for the current user based on install history.",
        {
          limit: z
            .number()
            .int()
            .min(1)
            .max(20)
            .optional()
            .default(8)
            .describe("Max apps to return (default 8, max 20)"),
        },
      )
      .meta({ category: "store", tier: "free" })
      .handler(async ({ input }) => {
        return safeToolCall("store_app_personalized", async () => {
          // Load user's installed app slugs
          const installed = await db
            .select({ appSlug: appInstalls.appSlug })
            .from(appInstalls)
            .where(eq(appInstalls.userId, userId));

          const installedSlugs = new Set(installed.map((i) => i.appSlug));

          // Build tag frequency map from installed apps
          const tagFreq = new Map<string, number>();
          if (installedSlugs.size > 0) {
            const installedApps = await db
              .select({ tags: mcpApps.tags })
              .from(mcpApps)
              .where(
                sql`${mcpApps.slug} IN (${sql.join(
                  [...installedSlugs].map((s) => sql`${s}`),
                  sql`, `,
                )})`,
              );

            for (const app of installedApps) {
              for (const tag of parseTags(app.tags)) {
                tagFreq.set(tag, (tagFreq.get(tag) ?? 0) + 1);
              }
            }
          }

          // Load all live apps not yet installed
          const candidates = await db
            .select({
              slug: mcpApps.slug,
              name: mcpApps.name,
              tagline: mcpApps.tagline,
              tags: mcpApps.tags,
              isFeatured: mcpApps.isFeatured,
            })
            .from(mcpApps)
            .where(eq(mcpApps.status, "live"));

          const uninstalled = candidates.filter((c) => !installedSlugs.has(c.slug));

          // Score by weighted tag overlap + featured bonus
          const scored = uninstalled
            .map((c) => {
              const cTags = parseTags(c.tags);
              let score = 0;
              for (const tag of cTags) {
                score += tagFreq.get(tag) ?? 0;
              }
              if (c.isFeatured) score += 0.5;
              return { ...c, score };
            })
            .sort((a, b) => b.score - a.score)
            .slice(0, input.limit);

          if (scored.length === 0) {
            return textResult("No personalized recommendations available.");
          }

          const list = scored.map((a) => `- **${a.name}** — ${a.tagline}`).join("\n");
          return textResult(`## Personalized Recommendations\n\n${list}`);
        });
      }),
  );

  // store_stats
  registry.registerBuilt(
    t
      .tool(
        "store_stats",
        "Get store statistics: total apps, tools, categories, and platform install counts.",
        {},
      )
      .meta({ category: "store", tier: "free" })
      .handler(async () => {
        return safeToolCall("store_stats", async () => {
          // Count live apps and sum tool_count
          const appStats = await db
            .select({
              appCount: count(mcpApps.slug),
              toolCount: sql<number>`COALESCE(SUM(${mcpApps.toolCount}), 0)`,
            })
            .from(mcpApps)
            .where(eq(mcpApps.status, "live"));

          // Count distinct categories
          const catStats = await db
            .select({
              categoryCount: sql<number>`COUNT(DISTINCT ${mcpApps.category})`,
            })
            .from(mcpApps)
            .where(and(eq(mcpApps.status, "live"), ne(mcpApps.category, "")));

          // Count distinct developers from registeredTools
          const devStats = await db
            .select({
              developerCount: sql<number>`COUNT(DISTINCT ${registeredTools.userId})`,
            })
            .from(registeredTools);

          // Count total installs
          const installStats = await db
            .select({ totalInstalls: count(appInstalls.id) })
            .from(appInstalls);

          return textResult(
            `## Store Stats\n\n` +
              `- **Apps**: ${appStats[0]?.appCount ?? 0}\n` +
              `- **Tools**: ${appStats[0]?.toolCount ?? 0}\n` +
              `- **Categories**: ${catStats[0]?.categoryCount ?? 0}\n` +
              `- **Developers**: ${devStats[0]?.developerCount ?? 0}\n` +
              `- **Installs**: ${installStats[0]?.totalInstalls ?? 0}`,
          );
        });
      }),
  );
}

/**
 * Text-to-Speech MCP Tools (CF Workers)
 *
 * Convert text to speech using direct fetch to the ElevenLabs API.
 * Returns audio as base64-encoded text (no R2/cache — stateless worker).
 * Ported from spike.land — no ElevenLabs SDK, no R2 cache.
 */

import { z } from "zod";
import type { ToolRegistry } from "../../lazy-imports/registry";
import { freeTool, textResult } from "../../lazy-imports/procedures-index.ts";
import { McpError, McpErrorCode, safeToolCall } from "../lib/tool-helpers";
import type { DrizzleDB } from "../../db/db/db-index.ts";
import type { Env } from "../env";

/** Minimal env fields required by TTS tools. */
type TtsEnv = Pick<Env, "ELEVENLABS_API_KEY">;

const DEFAULT_VOICE_ID = "21m00Tcm4TlvDq8ikWAM"; // Rachel

export function registerTtsTools(
  registry: ToolRegistry,
  userId: string,
  db: DrizzleDB,
  env: TtsEnv,
): void {
  registry.registerBuilt(
    freeTool(userId, db)
      .tool(
        "tts_synthesize",
        "Convert text to speech using ElevenLabs. Returns base64-encoded audio.",
        {
          text: z
            .string()
            .min(1)
            .max(5000)
            .describe("Text to convert to speech (max 5000 characters)."),
          voice_id: z
            .string()
            .optional()
            .describe("ElevenLabs voice ID. Uses default voice if not specified."),
        },
      )
      .meta({ category: "tts", tier: "free" })
      .handler(async ({ input }) => {
        const { text, voice_id } = input;
        return safeToolCall("tts_synthesize", async () => {
          const apiKey = env.ELEVENLABS_API_KEY;
          if (!apiKey) {
            throw new McpError(
              "ELEVENLABS_API_KEY not configured.",
              McpErrorCode.AUTH_ERROR,
              false,
            );
          }

          const voiceId = voice_id ?? DEFAULT_VOICE_ID;

          const response = await fetch(`https://api.elevenlabs.io/v1/text-to-speech/${voiceId}`, {
            method: "POST",
            headers: {
              "Content-Type": "application/json",
              "xi-api-key": apiKey,
            },
            body: JSON.stringify({
              text,
              model_id: "eleven_monolingual_v1",
              voice_settings: {
                stability: 0.5,
                similarity_boost: 0.5,
              },
            }),
          });

          if (!response.ok) {
            const errorText = await response.text().catch(() => "Unknown error");
            throw new McpError(
              `ElevenLabs API error (${response.status}): ${errorText}`,
              response.status === 429
                ? McpErrorCode.RATE_LIMITED
                : McpErrorCode.UPSTREAM_SERVICE_ERROR,
              response.status === 429,
            );
          }

          const audioBuffer = await response.arrayBuffer();
          const bytes = new Uint8Array(audioBuffer);
          // Convert to base64 in chunks to avoid stack overflow
          let binary = "";
          for (let i = 0; i < bytes.length; i++) {
            binary += String.fromCharCode(bytes[i]!);
          }
          const base64Audio = btoa(binary);

          return textResult(
            `**TTS Result**\n\n` +
              `**Text length:** ${text.length} characters\n` +
              `**Audio size:** ${audioBuffer.byteLength} bytes\n` +
              `**Format:** audio/mpeg (base64)\n` +
              `**Source:** generated\n\n` +
              `**Base64 Audio:**\n${base64Audio}`,
          );
        });
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool(
        "tts_list_voices",
        "List available text-to-speech voices with their IDs. Use a voice_id with tts_synthesize.",
        {},
      )
      .meta({ category: "tts", tier: "free" })
      .handler(async () => {
        const voices = [
          {
            id: "21m00Tcm4TlvDq8ikWAM",
            name: "Rachel",
            accent: "American",
            gender: "Female",
            style: "Calm, narration",
          },
          {
            id: "29vD33N1CtxCmqQRPOHJ",
            name: "Drew",
            accent: "American",
            gender: "Male",
            style: "Well-rounded",
          },
          {
            id: "2EiwWnXFnvU5JabPnv8n",
            name: "Clyde",
            accent: "American",
            gender: "Male",
            style: "War veteran, deep",
          },
          {
            id: "AZnzlk1XvdvUeBnXmlld",
            name: "Domi",
            accent: "American",
            gender: "Female",
            style: "Strong, authoritative",
          },
          {
            id: "EXAVITQu4vr4xnSDxMaL",
            name: "Bella",
            accent: "American",
            gender: "Female",
            style: "Soft, warm",
          },
          {
            id: "ErXwobaYiN019PkySvjV",
            name: "Antoni",
            accent: "American",
            gender: "Male",
            style: "Well-rounded",
          },
          {
            id: "MF3mGyEYCl7XYWbV9V6O",
            name: "Elli",
