/**
 * Agent Inbox MCP Tools
 *
 * Bidirectional chat bridge for external agents (e.g., Claude Code via MCP).
 * Allows an external agent to poll for messages, read full context, and respond.
 *
 * Runs on Cloudflare Workers with Drizzle ORM.
 * Uses agentMessages + claudeCodeAgents
 * tables and delegates app-specific operations to the spike.land API.
 */

import { z } from "zod";
import { and, asc, desc, eq } from "drizzle-orm";
import type { ToolRegistry } from "../../lazy-imports/registry";
import { freeTool, textResult } from "../../lazy-imports/procedures-index.ts";
import { agentMessages, claudeCodeAgents } from "../db/schema";
import type { DrizzleDB } from "../db/db-index.ts";

export function registerAgentInboxTools(
  registry: ToolRegistry,
  userId: string,
  db: DrizzleDB,
): void {
  registry.registerBuilt(
    freeTool(userId, db)
      .tool(
        "agent_inbox_poll",
        "Poll for new messages across your agents. " +
          "Returns agents with message counts and latest message preview.",
        {
          since: z
            .string()
            .optional()
            .describe("ISO timestamp. Only return messages created after this time. Omit for all."),
          agent_id: z
            .string()
            .optional()
            .describe("Filter to a specific agent. Omit to poll all agents."),
        },
      )
      .meta({ category: "agent-inbox", tier: "free" })
      .handler(async ({ input, ctx }) => {
        const { since, agent_id } = input;

        // Get agents owned by this user
        const agentFilter = agent_id
          ? and(eq(claudeCodeAgents.id, agent_id), eq(claudeCodeAgents.userId, ctx.userId))
          : eq(claudeCodeAgents.userId, ctx.userId);

        const agents = await ctx.db
          .select({ id: claudeCodeAgents.id, name: claudeCodeAgents.name })
          .from(claudeCodeAgents)
          .where(agentFilter);

        if (agents.length === 0) {
          const serverTime = new Date().toISOString();
          return textResult(`**No agents found.**\n\nserverTime: ${serverTime}`);
        }

        // Fetch messages for each agent
        const agentMap = new Map<
          string,
          {
            agentId: string;
            agentName: string;
            messageCount: number;
            latestMessage: {
              id: string;
              content: string;
              role: string;
              createdAt: number;
            };
          }
        >();

        for (const agent of agents) {
          const sinceTs = since ? new Date(since).getTime() : 0;

          // Get recent messages for this agent
          const msgs = await ctx.db
            .select({
              id: agentMessages.id,
              content: agentMessages.content,
              role: agentMessages.role,
              createdAt: agentMessages.createdAt,
            })
            .from(agentMessages)
            .where(eq(agentMessages.agentId, agent.id))
            .orderBy(desc(agentMessages.createdAt))
            .limit(50);

          const filtered = sinceTs > 0 ? msgs.filter((m) => m.createdAt > sinceTs) : msgs;

          if (filtered.length > 0) {
            const latest = filtered[0]!;
            agentMap.set(agent.id, {
              agentId: agent.id,
              agentName: agent.name,
              messageCount: filtered.length,
              latestMessage: {
                id: latest.id,
                content: latest.content.slice(0, 200),
                role: latest.role,
                createdAt: latest.createdAt,
              },
            });
          }
        }

        const serverTime = new Date().toISOString();

        if (agentMap.size === 0) {
          return textResult(
            `**No messages found.**\n\nserverTime: ${serverTime}\n\nCall again to continue polling.`,
          );
        }

        let text = `**Messages (across ${agentMap.size} agent(s)):**\n\n`;
        for (const a of agentMap.values()) {
          text += `### ${a.agentName}\n`;
          text += `- **Agent ID:** ${a.agentId}\n`;
          text += `- **Messages:** ${a.messageCount}\n`;
          text += `- **Latest [${a.latestMessage.role}]:** ${a.latestMessage.content}${
            a.latestMessage.content.length >= 200 ? "..." : ""
          }\n`;
          text += `- **At:** ${new Date(a.latestMessage.createdAt).toISOString()}\n\n`;
        }
        text += `serverTime: ${serverTime}`;

        return textResult(text);
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool(
        "agent_inbox_read",
        "Get full messages for an agent. Returns chronological messages with full content.",
        {
          agent_id: z.string().min(1).describe("Agent ID to read messages from."),
          limit: z
            .number()
            .int()
            .min(1)
            .max(50)
            .optional()
            .describe("Max messages to return. Default: 20."),
          since: z
            .string()
            .optional()
            .describe("ISO timestamp. Only return messages created after this time."),
        },
      )
      .meta({ category: "agent-inbox", tier: "free" })
      .handler(async ({ input, ctx }) => {
        const { agent_id, limit, since } = input;

        // Verify agent ownership
        const agentRows = await ctx.db
          .select({
            id: claudeCodeAgents.id,
            name: claudeCodeAgents.name,
            userId: claudeCodeAgents.userId,
          })
          .from(claudeCodeAgents)
          .where(eq(claudeCodeAgents.id, agent_id))
          .limit(1);

        const agent = agentRows[0];
        if (!agent || agent.userId !== ctx.userId) {
          return textResult(`**Error:** Agent not found or you don't own it (ID: ${agent_id}).`);
        }

        const messages = await ctx.db
          .select({
            id: agentMessages.id,
            role: agentMessages.role,
            content: agentMessages.content,
            createdAt: agentMessages.createdAt,
          })
          .from(agentMessages)
          .where(eq(agentMessages.agentId, agent_id))
          .orderBy(asc(agentMessages.createdAt))
          .limit(limit || 20);

        const sinceTs = since ? new Date(since).getTime() : 0;
        const filtered = sinceTs > 0 ? messages.filter((m) => m.createdAt > sinceTs) : messages;

        if (filtered.length === 0) {
          return textResult(`**No messages found** for agent "${agent.name}".`);
        }

        let text = `**Messages for "${agent.name}" (${filtered.length}):**\n\n`;
        for (const msg of filtered) {
          const role = msg.role === "user" ? "User" : msg.role === "assistant" ? "Agent" : "System";
          text += `**[${role}]** (${new Date(msg.createdAt).toISOString()}) ID: ${msg.id}\n`;
          text += `${msg.content}\n\n`;
        }

        return textResult(text);
      }),
  );

  registry.registerBuilt(
    freeTool(userId, db)
      .tool(
        "agent_inbox_respond",
        "Send an agent response. Creates an assistant message for the agent.",
        {
          agent_id: z.string().min(1).describe("Agent ID to respond to."),
          content: z.string().min(1).describe("The agent's response content."),
        },
      )
      .meta({ category: "agent-inbox", tier: "free" })
      .handler(async ({ input, ctx }) => {
        const { agent_id, content } = input;

        // Verify agent ownership
        const agentRows = await ctx.db
          .select({
            id: claudeCodeAgents.id,
            name: claudeCodeAgents.name,
            userId: claudeCodeAgents.userId,
          })
          .from(claudeCodeAgents)
          .where(eq(claudeCodeAgents.id, agent_id))
          .limit(1);

        const agent = agentRows[0];
        if (!agent || agent.userId !== ctx.userId) {
          return textResult(`**Error:** Agent not found or you don't own it (ID: ${agent_id}).`);
        }

        const id = crypto.randomUUID();
        await ctx.db.insert(agentMessages).values({
          id,
          agentId: agent_id,
          role: "assistant",
          content,
          createdAt: Date.now(),
        });

        return textResult(
          `**Response sent.**\n\n` + `**Message ID:** ${id}\n` + `**Agent:** ${agent.name}`,
        );
      }),
  );
}

/**
 * Bootstrap Protocol Tools (CF Workers)
 *
 * One-session workspace onboarding — create workspaces,
 * store integration credentials, and deploy apps.
 *
 * DB operations use Drizzle ORM + D1.
 * Codespace creation and transpilation features
 * delegate to the spike.land API.
 */

import { z } from "zod";
import { and, eq, sql } from "drizzle-orm";
import type { ToolRegistryAdapter } from "../../lazy-imports/types";
import { freeTool } from "../../lazy-imports/procedures-index.ts";
import { apiRequest, SPIKE_LAND_BASE_URL, textResult } from "../../core-logic/lib/tool-helpers";
import type { DrizzleDB } from "../db/db-index.ts";
import { registeredTools, vaultSecrets, workspaceMembers, workspaces } from "../db/schema";

export function registerBootstrapTools(
  registry: ToolRegistryAdapter,
  userId: string,
  db: DrizzleDB,
): void {
  const t = freeTool(userId, db);

  registry.registerBuilt(
    t
      .tool(
        "bootstrap_workspace",
        "Create or update a workspace configuration for the user. " +
          "A workspace is the container for secrets, tools, and apps.",
        {
          name: z.string().min(1).max(100),
          settings: z.record(z.string(), z.unknown()).optional().default({}),
        },
      )
      .meta({ category: "bootstrap", tier: "free" })
      .handler(async ({ input, ctx }) => {
        const { name, settings } = input;
        const now = Date.now();
        const slug = name
          .toLowerCase()
          .replace(/[^a-z0-9]+/g, "-")
          .replace(/^-|-$/g, "");

        // Check if user already has a workspace
        const existing = await ctx.db
          .select({ id: workspaces.id })
          .from(workspaces)
          .where(eq(workspaces.ownerId, ctx.userId))
          .limit(1);

        let workspaceId: string;

        if (existing.length > 0) {
          workspaceId = existing[0]!.id;
          await ctx.db
            .update(workspaces)
            .set({
              name,
              settings: JSON.stringify(settings),
              updatedAt: now,
            })
            .where(eq(workspaces.id, workspaceId));
        } else {
          workspaceId = crypto.randomUUID();
          await ctx.db.insert(workspaces).values({
            id: workspaceId,
            ownerId: ctx.userId,
            name,
            slug: `${slug}-${workspaceId.slice(0, 8)}`,
            description: `Workspace for ${name}`,
            plan: "free",
            settings: JSON.stringify(settings),
            createdAt: now,
            updatedAt: now,
          });

          // Add owner as member
          await ctx.db.insert(workspaceMembers).values({
            id: crypto.randomUUID(),
            workspaceId,
            userId: ctx.userId,
            role: "owner",
            createdAt: now,
          });
        }

        return textResult(
          `**Workspace Ready!**\n\n` +
            `**ID:** ${workspaceId}\n` +
            `**Name:** ${name}\n\n` +
            `Next steps:\n` +
            `- Use \`bootstrap_connect_integration\` to add API credentials\n` +
            `- Use \`bootstrap_create_app\` to deploy a live app`,
        );
      }),
  );

  registry.registerBuilt(
    t
      .tool(
        "bootstrap_connect_integration",
        "Connect an integration by storing its credentials in the encrypted vault. " +
          "Each credential key/value pair is stored separately.",
        {
          integration_name: z
            .string()
            .min(1)
            .max(100)
            .regex(/^[a-zA-Z][a-zA-Z0-9_]*$/),
          credentials: z.record(z.string(), z.string()),
        },
      )
      .meta({ category: "bootstrap", tier: "free" })
      .handler(async ({ input, ctx }) => {
        const { integration_name, credentials } = input;
        const now = Date.now();

        // Find workspace for this user
        const ws = await ctx.db
          .select({ id: workspaces.id })
          .from(workspaces)
          .where(eq(workspaces.ownerId, ctx.userId))
          .limit(1);

        const workspaceId = ws[0]?.id ?? null;

        const storedSecrets: Array<{ name: string; id: string }> = [];

        for (const [key, value] of Object.entries(credentials)) {
          const secretName = `${integration_name}_${key}`;
          const secretId = crypto.randomUUID();

          // Encrypt using WebCrypto AES-GCM
          const encoder = new TextEncoder();
          const iv = crypto.getRandomValues(new Uint8Array(12));
          const keyMaterial = await crypto.subtle.importKey(
            "raw",
            encoder.encode(ctx.userId),
            "PBKDF2",
            false,
            ["deriveKey"],
          );
          const cryptoKey = await crypto.subtle.deriveKey(
            {
              name: "PBKDF2",
              salt: encoder.encode("spike-land-vault"),
              iterations: 100000,
              hash: "SHA-256",
            },
            keyMaterial,
            { name: "AES-GCM", length: 256 },
            false,
            ["encrypt"],
          );
          const encrypted = await crypto.subtle.encrypt(
            { name: "AES-GCM", iv },
            cryptoKey,
            encoder.encode(value),
          );

          const encryptedValue = JSON.stringify({
            iv: btoa(String.fromCharCode(...iv)),
            data: btoa(String.fromCharCode(...new Uint8Array(encrypted))),
          });

          // Upsert: delete then insert (D1 doesn't support ON CONFLICT well)
          await ctx.db
            .delete(vaultSecrets)
            .where(and(eq(vaultSecrets.userId, ctx.userId), eq(vaultSecrets.key, secretName)));

          await ctx.db.insert(vaultSecrets).values({
            id: secretId,
            userId: ctx.userId,
            workspaceId,
            key: secretName,
            encryptedValue,
            createdAt: now,
            updatedAt: now,
          });

          storedSecrets.push({ name: secretName, id: secretId });
        }

        let text = `**Integration Connected: ${integration_name}**\n\n`;
        text += `**Secrets Stored:**\n`;
        for (const s of storedSecrets) {
          text += `- ${s.name} (ID: ${s.id})\n`;
        }

        return textResult(text);
      }),
  );

  registry.registerBuilt(
    t
      .tool(
        "bootstrap_create_app",
        "Use this for first-time setup — creates workspace + secrets + app in one flow. " +
          "Create a live app. Delegates codespace creation and app linking to the spike.land API.",
        {
          app_name: z.string().min(3).max(50),
          description: z.string().min(10).max(500).optional(),
          code: z.string().min(1).optional(),
          codespace_id: z
            .string()
            .min(1)
            .max(100)
            .regex(/^[a-zA-Z0-9_.-]+$/)
            .optional(),
        },
      )
      .meta({ category: "bootstrap", tier: "free" })
      .handler(async ({ input }) => {
        const { app_name, description, code, codespace_id } = input;

        const effectiveCodespaceId =
          codespace_id ||
          app_name
            .toLowerCase()
            .replace(/[^a-z0-9]+/g, "-")
            .replace(/^-|-$/g, "");

        // Delegate to spike.land API for codespace + app creation
        const body: Record<string, unknown> = {
          name: app_name,
          description: description || `App from codespace ${effectiveCodespaceId}`,
          requirements: "Bootstrap-created app",
          monetizationModel: "free",
          codespaceId: effectiveCodespaceId,
        };
        if (code) body["code"] = code;

        try {
          const appData = await apiRequest<{
            id: string;
            name: string;
          }>("/api/apps", {
            method: "POST",
            body: JSON.stringify(body),
          });

          const liveUrl = `${SPIKE_LAND_BASE_URL}/api/codespace/${effectiveCodespaceId}/embed`;
          const dashboardUrl = `${SPIKE_LAND_BASE_URL}/create`;

          return textResult(
            `**App Created!**\n\n` +
              `**App:** ${appData.name} (ID: ${appData.id})\n` +
              `**Codespace:** ${effectiveCodespaceId}\n` +
              `**Live URL:** ${liveUrl}\n` +
              `**Dashboard:** ${dashboardUrl}`,
          );
        } catch (error) {
          const msg = error instanceof Error ? error.message : "Unknown error";
          return textResult(`**Error creating app:** ${msg}`);
        }
      }),
  );

  registry.registerBuilt(
    t
      .tool(
        "bootstrap_status",
        "Get the current workspace setup status: workspace config, secrets, tools.",
        {},
      )
      .meta({ category: "bootstrap", tier: "free" })
      .handler(async ({ ctx }) => {
        const [ws, secretCount, toolCount] = await Promise.all([
          ctx.db
            .select({
              id: workspaces.id,
              name: workspaces.name,
              settings: workspaces.settings,
            })
            .from(workspaces)
            .where(eq(workspaces.ownerId, ctx.userId))
            .limit(1),
          ctx.db
            .select({ count: sql<number>`count(*)` })
            .from(vaultSecrets)
            .where(eq(vaultSecrets.userId, ctx.userId)),
          ctx.db
            .select({ count: sql<number>`count(*)` })
            .from(registeredTools)
            .where(eq(registeredTools.userId, ctx.userId)),
        ]);

        const workspace = ws[0];
        const secrets = secretCount[0]?.count ?? 0;
        const tools = toolCount[0]?.count ?? 0;

        let text = `**Workspace Status**\n\n`;

        if (workspace) {
          text += `**Workspace:** ${workspace.name}\n`;
          text += `**ID:** ${workspace.id}\n`;
        } else {
          text += `**Workspace:** Not configured\n`;
        }

        text += `**Vault Secrets:** ${secrets}\n`;
        text += `**Registered Tools:** ${tools}\n`;

        if (!workspace) {
          text += `\nUse \`bootstrap_workspace\` to get started.`;
        }

        return textResult(text);
      }),
  );
}

/**
 * Gateway Meta Tools (CF Workers)
 *
 * 5 always-on discovery tools for Progressive Context Disclosure.
 * Ported from spike.land — uses KV instead of Redis for category persistence,
 * Drizzle instead of Prisma for marketplace search.
 */

import { z } from "zod";
import { and, desc, eq, like, or } from "drizzle-orm";
import type { ToolRegistry } from "../../lazy-imports/registry";
import { CATEGORY_AUDIENCES } from "../../core-logic/mcp/categories";
import type { DrizzleDB } from "../db/db-index.ts";
import { registeredTools, users } from "../db/schema";
import { saveEnabledCategories } from "../../core-logic/kv/categories";
import { freeTool } from "../../lazy-imports/procedures-index.ts";

interface CreditInfo {
  balance: number;
  dailyLimit: number;
  tier: string;
  usedToday: number;
}

async function fetchCreditInfo(
  spikeEdge: Fetcher,
  mcpInternalSecret: string,
  userId: string,
): Promise<CreditInfo | null> {
  try {
    const res = await spikeEdge.fetch(
      `https://edge.spike.land/internal/credits/balance/${userId}`,
      { headers: { "x-internal-secret": mcpInternalSecret } },
    );
    if (!res.ok) {
      console.error("[mcp] fetchCreditInfo failed:", res.status, await res.text().catch(() => ""));
      return null;
    }
    return (await res.json()) as CreditInfo;
  } catch (err) {
    console.error("[mcp] fetchCreditInfo error:", err);
    return null;
  }
}

export function registerGatewayMetaTools(
  registry: ToolRegistry,
  userId: string,
  db: DrizzleDB,
  kv?: KVNamespace,
  spikeEdge?: Fetcher,
  mcpInternalSecret?: string,
): void {
  const t = freeTool(userId, db);

  // search_tools
  registry.registerBuilt(
    t
      .tool(
        "search_tools",
        "Search all available spike.land tools by keyword or description. Also searches the marketplace for community-published tools.",
        {
          query: z.string().min(1).max(200).describe("Search query"),
          limit: z.number().min(1).max(50).optional().default(10).describe("Maximum results"),
          semantic: z
            .boolean()
            .optional()
            .default(false)
            .describe("Use AI-powered semantic search with synonym expansion"),
          stability: z
            .enum(["stable", "beta", "experimental", "deprecated"])
            .optional()
            .describe("Filter results by stability tag"),
        },
      )
      .meta({ category: "gateway-meta", tier: "free" })
      .examples([
        {
          name: "keyword_search",
          input: { query: "code generation", limit: 5 },
          description: "Search for code generation tools by keyword",
        },
        {
          name: "semantic_search",
          input: { query: "help me write tests", semantic: true },
          description: "Find test-related tools using semantic search",
        },
        {
          name: "stable_only",
          input: { query: "storage", stability: "stable" },
          description: "Search for stable storage tools only",
        },
      ])
      .handler(async ({ input }) => {
        const { query, limit, semantic, stability } = input;

        if (semantic) {
          const rawSemanticResults = registry.searchToolsSemantic(query, limit);
          const semanticResults = stability
            ? rawSemanticResults.filter((r) => r.stability === stability)
            : rawSemanticResults;

          if (semanticResults.length === 0) {
            return {
              content: [
                {
                  type: "text",
                  text: `No tools found matching "${query}"${stability ? ` with stability: ${stability}` : ""} (semantic). Try different keywords or use list_categories.`,
                },
              ],
            };
          }

          const names = semanticResults.map((r) => r.name);
          const newlyEnabled = registry.enableTools(names);

          if (newlyEnabled.length > 0) {
            if (kv) void saveEnabledCategories(userId, registry.getEnabledCategories(), kv);
          }

          let text = `**Found ${semanticResults.length} tool(s) matching "${query}" (semantic):**\n\n`;
          for (const result of semanticResults) {
            const status = newlyEnabled.includes(result.name)
              ? " (now activated)"
              : result.enabled
                ? ""
                : " (inactive)";
            text += `- **${result.name}**${status}\n  ${result.description}\n  Category: ${result.category} | Tier: ${result.tier} | v${result.version ?? "1.0.0"} (${result.stability ?? "stable"}) | Similarity: ${result.score}\n`;
            if (result.suggestedParams && Object.keys(result.suggestedParams).length > 0) {
              text += `  Suggested params: ${JSON.stringify(result.suggestedParams)}\n`;
            }
            const examples = registry.getToolExamples(result.name);
            if (examples && examples.length > 0) {
              text += `  Examples: ${examples.length} available (use get_tool_help for details)\n`;
            }
            text += "\n";
          }

          if (newlyEnabled.length > 0) {
            text += `\n${newlyEnabled.length} tool(s) activated and ready to use.\n`;
          }

          return { content: [{ type: "text", text }] };
        }

        const rawResults = await registry.searchTools(query, limit);
        const results = stability
          ? rawResults.filter((r) => r.stability === stability)
          : rawResults;

        // Also search published tools in the DB (marketplace)
        let marketplaceTools: Array<{
          id: string;
          name: string;
          description: string;
          installCount: number;
          userName: string | null;
        }> = [];
        try {
          // SQLite LIKE is case-insensitive for ASCII — push filter into SQL
          const searchPattern = `%${query}%`;
          marketplaceTools = await db
            .select({
              id: registeredTools.id,
              name: registeredTools.name,
              description: registeredTools.description,
              installCount: registeredTools.installCount,
              userName: users.name,
            })
            .from(registeredTools)
            .leftJoin(users, eq(users.id, registeredTools.userId))
            .where(
              and(
                eq(registeredTools.status, "published"),
                or(
                  like(registeredTools.name, searchPattern),
                  like(registeredTools.description, searchPattern),
                ),
              ),
            )
            .orderBy(desc(registeredTools.installCount))
            .limit(limit);
        } catch (err) {
          console.error("[mcp] search_tools marketplace query error:", err);
          // DB query failure should not break platform tool search
        }

        if (results.length === 0 && marketplaceTools.length === 0) {
          return {
            content: [
              {
                type: "text",
                text: `No tools found matching "${query}"${stability ? ` with stability: ${stability}` : ""}. Try different keywords or use list_categories.`,
              },
            ],
          };
        }

        let text = "";

        if (results.length > 0) {
          const names = results.map((r) => r.name);
          const newlyEnabled = registry.enableTools(names);

          if (newlyEnabled.length > 0) {
            if (kv) void saveEnabledCategories(userId, registry.getEnabledCategories(), kv);
          }

          text += `**Found ${results.length} platform tool(s) matching "${query}"${stability ? ` (${stability})` : ""}:**\n\n`;
          for (const result of results) {
            const status = newlyEnabled.includes(result.name)
              ? " (now activated)"
              : result.enabled
                ? ""
                : " (inactive)";
            text += `- **${result.name}**${status}\n  ${result.description}\n  Category: ${result.category} | Tier: ${result.tier} | v${result.version ?? "1.0.0"} (${result.stability ?? "stable"})\n`;
            const examples = registry.getToolExamples(result.name);
            if (examples && examples.length > 0) {
              text += `  Examples: ${examples.length} available (use get_tool_help for details)\n`;
            }
            text += "\n";
          }

          if (newlyEnabled.length > 0) {
            text += `\n${newlyEnabled.length} tool(s) activated and ready to use.\n\n`;
          }
        }

        if (marketplaceTools.length > 0) {
          text += `**Marketplace (${marketplaceTools.length} community tool(s)):**\n\n`;
          for (const tool of marketplaceTools) {
            const author = tool.userName ?? "Unknown";
            text += `- **${tool.name}** — ${tool.description}\n  Author: ${author} | Installs: ${tool.installCount} | ID: ${tool.id}\n\n`;
          }
          text += `Use \`marketplace_install\` to install community tools.\n`;
        }

        return { content: [{ type: "text", text }] };
      }),
  );

  // list_categories
  registry.registerBuilt(
    t
      .tool(
        "list_categories",
        "List all available tool categories with descriptions and tool counts.",
        {},
      )
      .meta({ category: "gateway-meta", tier: "free" })
      .handler(async () => {
        const categories = registry.listCategories();

        let text = `**spike.land Tool Categories (${registry.getToolCount()} total tools)**\n\n`;
        text += `_Tip: The "Labs" group is for distributed systems simulation — skip if building apps._\n\n`;

        // Group by audience
        const audienceLabels: Record<string, string> = {
          "app-building": "App Building",
          "ai-automation": "AI & Automation",
          labs: "Labs (Distributed Systems)",
          learning: "Learning",
          platform: "Platform",
          domain: "Domain",
          infrastructure: "Infrastructure",
        };

        const grouped = new Map<string, typeof categories>();
        const ungrouped: typeof categories = [];

        for (const cat of categories) {
          if (cat.name === "gateway-meta") continue;
          const audience = CATEGORY_AUDIENCES[cat.name];
          if (audience) {
            if (!grouped.has(audience)) grouped.set(audience, []);
            grouped.get(audience)!.push(cat);
          } else {
            ungrouped.push(cat);
          }
        }

        for (const [audience, cats] of grouped) {
          const label = audienceLabels[audience] ?? audience;
          text += `### ${label}\n\n`;
          for (const cat of cats) {
            const status =
              cat.enabledCount > 0 ? ` (${cat.enabledCount}/${cat.toolCount} active)` : "";
            text += `- **${cat.name}** (${cat.toolCount} tools)${status}\n  ${cat.description}\n\n`;
          }
        }

        if (ungrouped.length > 0) {
          text += `### Other\n\n`;
          for (const cat of ungrouped) {
            const status =
              cat.enabledCount > 0 ? ` (${cat.enabledCount}/${cat.toolCount} active)` : "";
            text += `- **${cat.name}** (${cat.toolCount} tools)${status}\n  ${cat.description}\n\n`;
          }
        }

        text += "\nUse `search_tools` or `enable_category` to activate tools.";
        return { content: [{ type: "text", text }] };
      }),
  );

  // enable_category
  registry.registerBuilt(
    t
      .tool("enable_category", "Activate all tools in a specific category.", {
        category: z.string().min(1).describe("Category name to activate"),
      })
      .meta({ category: "gateway-meta", tier: "free" })
      .examples([
        {
          name: "enable_codegen",
          input: { category: "codegen" },
          description: "Activate all code generation tools",
        },
      ])
      .handler(async ({ input }) => {
        const { category } = input;

        const enabled = registry.enableCategory(category);

        if (enabled.length === 0) {
          if (!registry.hasCategory(category)) {
            const categories = registry.listCategories();
            const available = categories
              .map((c) => c.name)
              .filter((n) => n !== "gateway-meta")
              .join(", ");
            return {
              content: [
                {
                  type: "text",
                  text: `Category "${category}" not found. Available: ${available}`,
                },
              ],
              isError: true,
            };
          }
          return {
            content: [
              {
                type: "text",
                text: `All tools in "${category}" are already active.`,
              },
            ],
          };
        }

        // Persist enabled categories to KV (fire & forget)
        if (kv) void saveEnabledCategories(userId, registry.getEnabledCategories(), kv);

        let text = `**Activated ${enabled.length} tool(s) in "${category}":**\n\n`;
        for (const name of enabled) text += `- ${name}\n`;
        text += `\nThese tools are now available for use.`;
        return { content: [{ type: "text", text }] };
      }),
  );

  // get_balance
  registry.registerBuilt(
    t
      .tool(
        "get_balance",
        "Get current AI credit balance. Returns balance in credits with USD approximation.",
        {},
      )
      .meta({ category: "gateway-meta", tier: "free" })
      .examples([
        {
          name: "check_credits",
          input: {},
          description: "Check your current AI credit balance",
          expected_output: "Balance in credits with USD approximation",
        },
      ])
      .handler(async () => {
        const creditInfo =
          spikeEdge && mcpInternalSecret
            ? await fetchCreditInfo(spikeEdge, mcpInternalSecret, userId)
            : null;

        if (!creditInfo) {
          return {
            content: [
              {
                type: "text",
                text:
                  `**AI Credit Balance**\n\n` +
                  `**Amount:** N/A (edge mode)\n` +
                  `**Currency:** credits\n` +
                  `**Approximate USD:** N/A\n\n` +
                  `Balance details are available at https://spike.land/settings?tab=billing\n` +
                  `Use \`billing_status\` to check your subscription tier.`,
              },
            ],
          };
        }

        const usd = (creditInfo.balance * 0.01).toFixed(2);
        const remaining = creditInfo.dailyLimit - creditInfo.usedToday;
        return {
          content: [
            {
              type: "text",
              text:
                `**AI Credit Balance**\n\n` +
                `**Balance:** ${creditInfo.balance} credits (~$${usd} USD)\n` +
                `**Tier:** ${creditInfo.tier}\n` +
                `**Daily Limit:** ${creditInfo.dailyLimit}\n` +
                `**Used Today:** ${creditInfo.usedToday}\n` +
                `**Remaining Today:** ${remaining}\n\n` +
                `Manage billing at https://spike.land/settings?tab=billing`,
            },
          ],
        };
      }),
  );

  // get_status
  registry.registerBuilt(
    t
      .tool(
        "get_status",
        "START HERE. Get a guided overview of spike.land capabilities, active tools, and recommended next steps.",
        {},
      )
      .meta({ category: "gateway-meta", tier: "free" })
      .examples([
        {
          name: "check_platform",
          input: {},
          description: "Get an overview of available tools and categories",
          expected_output: "Platform status with tool counts and categories",
        },
      ])
      .handler(async () => {
        const categories = registry.listCategories();
        const totalTools = registry.getToolCount();
        const enabledTools = registry.getEnabledCount();

        // Fetch user name and credit info in parallel
        const [userRow, creditInfo] = await Promise.all([
          db
            .select({ name: users.name })
            .from(users)
            .where(eq(users.id, userId))
            .limit(1)
            .then((rows) => rows[0] ?? null)
            .catch((err): null => {
              console.error("[mcp] get_status user lookup error:", err);
              return null;
            }),
          spikeEdge && mcpInternalSecret
            ? fetchCreditInfo(spikeEdge, mcpInternalSecret, userId)
            : null,
        ]);

        const name = userRow?.name;
        let text = name ? `**Welcome back, ${name}!**` : `**Welcome to spike.land!**`;

        if (creditInfo) {
          text += ` You're on the **${creditInfo.tier}** tier.\n\n`;
          text += `**Credits:** ${creditInfo.balance} available | ${creditInfo.usedToday}/${creditInfo.dailyLimit} used today\n\n`;
          if (creditInfo.tier === "free" && creditInfo.balance < 10) {
            text += `> Low credits! Consider upgrading at https://spike.land/settings?tab=billing\n\n`;
          }
        } else {
          text += `\n\n`;
        }

        text += `**Platform:** ${totalTools} tools | ${enabledTools} active | ${categories.length} categories\n`;
        const stabilityBreakdown = registry.getStabilityBreakdown();
        if (Object.keys(stabilityBreakdown).length > 0) {
          text += `**Stability:** `;
          text += Object.entries(stabilityBreakdown)
            .map(([tag, count]) => `${tag}: ${count}`)
            .join(", ");
          text += `\n`;
        }
        text += `\n`;

        const activeCategories = categories.filter((c) => c.enabledCount > 0);
        const inactiveCategories = categories.filter(
          (c) => c.enabledCount === 0 && c.name !== "gateway-meta",
        );

        if (activeCategories.length > 0) {
          text += `**Active:**\n`;
          for (const cat of activeCategories) {
            text += `- ${cat.name}: ${cat.enabledCount}/${cat.toolCount} active\n`;
          }
          text += "\n";
        }

        if (inactiveCategories.length > 0) {
          text += `**Available:**\n`;
          for (const cat of inactiveCategories) {
            text += `- ${cat.name}: ${cat.toolCount} tools\n`;
          }
          text += "\n";
        }

        text += `**Getting Started:**\n`;
        text += `1. Use \`search_tools\` to find tools by keyword (e.g., "create app", "image generation")\n`;
        text += `2. Use \`list_categories\` to browse all tool categories grouped by audience\n`;
        text += `3. Use \`enable_category\` to activate a whole category at once\n\n`;
        text += `**Quick Start Paths:**\n`;
        text += `- **Build an app →** \`apps_create\` (or \`bootstrap_create_app\` for first-time setup)\n`;
        text += `- **Generate images →** enable "image" category\n`;
        text += `- **AI chat →** enable "ai-gateway" category\n`;
        text += `- **Manage secrets →** enable "vault" category\n`;

        if (creditInfo && (creditInfo.tier === "pro" || creditInfo.tier === "business")) {
          text += `- **Code review →** enable "codegen" category\n`;
          text += `- **Advanced AI →** enable "ai-gateway" category for multi-model access\n`;
        }

        return { content: [{ type: "text", text }] };
      }),
  );

  // get_tool_help
  registry.registerBuilt(
    t
      .tool(
        "get_tool_help",
        "Get detailed help for a specific tool, including descriptions, examples, and version information.",
        {
          tool_name: z.string().describe("The name of the tool to get help for"),
        },
      )
      .meta({ category: "gateway-meta", tier: "free" })
      .handler(async ({ input }) => {
        const { tool_name } = input;
        const definitions = registry.getToolDefinitions();
        const def = definitions.find((d) => d.name === tool_name);

        if (!def) {
          return {
            content: [{ type: "text", text: `Tool not found: ${tool_name}` }],
            isError: true,
          };
        }

        let text = `**Tool:** ${def.name}\n`;
        text += `**Description:** ${def.description}\n`;
        text += `**Category:** ${def.category}\n`;
        text += `**Version:** ${def.version}\n`;
        text += `**Stability:** ${def.stability}\n\n`;

        if (def.inputSchema) {
          text += `**Input Schema:**\n`;
          for (const [key, field] of Object.entries(def.inputSchema)) {
            const zField = field as z.ZodTypeAny;
            const desc = zField.description || "No description";
            const isOptional = zField instanceof z.ZodOptional ? true : false;
            text += `- \`${key}\`${isOptional ? " (optional)" : ""}: ${desc}\n`;
          }
          text += "\n";
        }

        if (def.examples && def.examples.length > 0) {
          text += `**Examples:**\n`;
          for (const ex of def.examples) {
            text += `- **${ex.name}**: ${ex.description}\n  \`\`\`json\n  ${JSON.stringify(ex.input, null, 2)}\n  \`\`\`\n`;
            if (ex.expected_output) {
              text += `  Expected output: ${ex.expected_output}\n`;
            }
          }
        } else {
          text += `*No examples provided for this tool.*\n`;
        }

        return { content: [{ type: "text", text }] };
      }),
  );

  // search_tools_by_stability
  registry.registerBuilt(
    t
      .tool(
        "search_tools_by_stability",
        "Find and automatically enable tools matching a specific stability tag (e.g., beta, experimental).",
        {
          stability: z
            .enum(["stable", "beta", "experimental", "deprecated", "not-implemented"])
            .describe("The stability level to search for"),
          limit: z.number().optional().describe("Max results to show"),
        },
      )
      .meta({ category: "gateway-meta", tier: "free" })
      .handler(async ({ input }) => {
        const { stability, limit } = input;
        const matching = registry.filterByStability(stability);

        if (matching.length === 0) {
          return {
            content: [{ type: "text", text: `No tools found with stability: ${stability}` }],
          };
        }

        registry.enableByStability(stability);
        if (kv) void saveEnabledCategories(userId, registry.getEnabledCategories(), kv);

        let text = `**Found and activated ${matching.length} tool(s) with stability: ${stability}**\n\n`;

        const displayLimit = limit || 20;
        const displayTools = matching.slice(0, displayLimit);

        for (const def of displayTools) {
          text += `- **${def.name}** (v${def.version ?? "1.0.0"})\n  ${def.description}\n`;
        }

        if (matching.length > displayLimit) {
          text += `\n... and ${matching.length - displayLimit} more.`;
        }

        return { content: [{ type: "text", text }] };
      }),
  );

  // list_tool_versions
  registry.registerBuilt(
    t
      .tool("list_tool_versions", "List all registered versions of a specific tool.", {
        tool_name: z.string().describe("The name of the tool"),
      })
      .meta({ category: "gateway-meta", tier: "free" })
      .handler(async ({ input }) => {
        const { tool_name } = input;
        const versions = registry.listVersions(tool_name);

        if (versions.length === 0) {
          return {
            content: [{ type: "text", text: `No versions found for tool: ${tool_name}` }],
            isError: true,
          };
        }

        let text = `**Versions for ${tool_name}:**\n\n`;
        for (const v of versions) {
          text += `- v${v.version} (${v.stability})\n`;
        }

        return { content: [{ type: "text", text }] };
      }),
  );
}

/**
 * Audit Questionnaire MCP Tools (CF Workers)
 *
 * Tools for submitting persona audit evaluations, viewing results,
 * and comparing personas across segments.
 */

import { z } from "zod";
import { eq, sql } from "drizzle-orm";
import type { ToolRegistry } from "../../../lazy-imports/registry";
import { freeTool, jsonResult } from "../../../lazy-imports/procedures-index.ts";
import type { DrizzleDB } from "../../db/db-index.ts";
import { personaAuditBatches, personaAuditResults } from "../../db/schema";
import { PERSONAS } from "../../../core-logic/lib/persona-data";

const SEGMENTS: Record<string, string[]> = {
  Developer: [
    "ai-indie",
    "classic-indie",
    "agency-dev",
    "in-house-dev",
    "ml-engineer",
    "ai-hobbyist",
    "enterprise-devops",
    "startup-devops",
  ],
  Business: ["technical-founder", "nontechnical-founder", "growth-leader", "ops-leader"],
  Creator: ["content-creator", "hobbyist-creator", "social-gamer", "solo-explorer"],
};

function getSegment(slug: string): string {
  for (const [segment, slugs] of Object.entries(SEGMENTS)) {
    if (slugs.includes(slug)) return segment;
  }
  return "Unknown";
}

export function registerAuditQuestionnaireTools(
  registry: ToolRegistry,
  userId: string,
  db: DrizzleDB,
): void {
  const t = freeTool(userId, db);

  // audit_submit_evaluation
  registry.registerBuilt(
    t
      .tool(
        "audit_submit_evaluation",
        "Submit an audit evaluation for a single persona within a batch.",
        {
          persona_slug: z.string().describe("Slug of the persona being evaluated"),
          batch_id: z.string().describe("Batch this evaluation belongs to"),
          ux_score: z.number().int().min(1).max(5).describe("UX quality score (1-5)"),
          content_relevance: z
            .number()
            .int()
            .min(1)
            .max(5)
            .describe("Content relevance score (1-5)"),
          cta_compelling: z.number().int().min(1).max(5).describe("CTA effectiveness score (1-5)"),
          recommended_apps_relevant: z
            .number()
            .int()
            .min(1)
            .max(5)
            .describe("App recommendations score (1-5)"),
          would_sign_up: z.coerce.boolean().describe("Would this persona sign up?"),
          blockers: z.string().optional().describe("Blocking issues found"),
          highlights: z.string().optional().describe("Positive highlights"),
          accessibility_issues: z.array(z.string()).optional().describe("A11y issues found"),
          broken_links: z.array(z.string()).optional().describe("Broken links found"),
          performance_notes: z.string().optional().describe("Performance observations"),
        },
      )
      .meta({ category: "persona", tier: "free" })
      .handler(async ({ input }) => {
        const resultId = crypto.randomUUID();

        await db.insert(personaAuditResults).values({
          id: resultId,
          batchId: input.batch_id,
          personaSlug: input.persona_slug,
          uxScore: input.ux_score,
          contentRelevance: input.content_relevance,
          ctaCompelling: input.cta_compelling,
          recommendedAppsRelevant: input.recommended_apps_relevant,
          wouldSignUp: input.would_sign_up ? 1 : 0,
          blockers: input.blockers ?? "",
          highlights: input.highlights ?? "",
          accessibilityIssues: JSON.stringify(input.accessibility_issues ?? []),
          brokenLinks: JSON.stringify(input.broken_links ?? []),
          performanceNotes: input.performance_notes ?? "",
          createdAt: Date.now(),
        });

        await db.run(
          sql`UPDATE persona_audit_batches SET completed_count = completed_count + 1, status = CASE WHEN completed_count + 1 >= total_personas THEN 'completed' ELSE 'in_progress' END, completed_at = CASE WHEN completed_count + 1 >= total_personas THEN ${Date.now()} ELSE completed_at END WHERE id = ${input.batch_id}`,
        );

        return jsonResult(
          `Evaluation submitted for persona "${input.persona_slug}" in batch ${input.batch_id}.`,
          { resultId, personaSlug: input.persona_slug, batchId: input.batch_id },
        );
      }),
  );

  // audit_get_results
  registry.registerBuilt(
    t
      .tool(
        "audit_get_results",
        "Get all audit results for a batch, formatted as a markdown table.",
        {
          batch_id: z.string().describe("Batch ID to retrieve results for"),
        },
      )
      .meta({ category: "persona", tier: "free" })
      .handler(async ({ input }) => {
        const batches = await db
          .select()
          .from(personaAuditBatches)
          .where(eq(personaAuditBatches.id, input.batch_id));

        const batch = batches[0];
        if (!batch) {
          return jsonResult(`Batch "${input.batch_id}" not found.`, { error: "not_found" });
        }

        const results = await db
          .select()
          .from(personaAuditResults)
          .where(eq(personaAuditResults.batchId, input.batch_id));

        if (results.length === 0) {
          return jsonResult(`Batch "${input.batch_id}" exists but has no results yet.`, {
            batch,
            results: [],
          });
        }

        const header = "| Persona | UX | Content | CTA | Apps | Sign Up | Blockers |";
        const divider = "|---------|----|---------| ----|------|---------|----------|";
        const rows = results.map((r) => {
          const persona = PERSONAS.find((p) => p.slug === r.personaSlug);
          const name = persona ? persona.name : r.personaSlug;
          const signUp = r.wouldSignUp ? "Yes" : "No";
          const blockers = r.blockers || "-";
          return `| ${name} | ${r.uxScore} | ${r.contentRelevance} | ${r.ctaCompelling} | ${r.recommendedAppsRelevant} | ${signUp} | ${blockers} |`;
        });

        const table = [header, divider, ...rows].join("\n");
        const status = `**Batch status**: ${batch.status} (${batch.completedCount}/${batch.totalPersonas})`;

        return jsonResult(`${status}\n\n${table}`, { batch, resultCount: results.length });
      }),
  );

  // audit_compare_personas
  registry.registerBuilt(
    t
      .tool(
        "audit_compare_personas",
        "Compare persona audit results across segments (Developer, Business, Creator).",
        {
          batch_id: z.string().describe("Batch ID to compare results for"),
        },
      )
      .meta({ category: "persona", tier: "free" })
      .handler(async ({ input }) => {
        const results = await db
          .select()
          .from(personaAuditResults)
          .where(eq(personaAuditResults.batchId, input.batch_id));

        if (results.length === 0) {
          return jsonResult(`No results found for batch "${input.batch_id}".`, {
            error: "no_results",
          });
        }

        // Group by segment
        const segmentScores: Record<
          string,
          { total: number; ux: number; content: number; cta: number; apps: number; signups: number }
        > = {};

        for (const r of results) {
          const seg = getSegment(r.personaSlug);
          if (!segmentScores[seg]) {
            segmentScores[seg] = { total: 0, ux: 0, content: 0, cta: 0, apps: 0, signups: 0 };
          }
          const s = segmentScores[seg];
          s.total++;
          s.ux += r.uxScore;
          s.content += r.contentRelevance;
          s.cta += r.ctaCompelling;
          s.apps += r.recommendedAppsRelevant;
          s.signups += r.wouldSignUp;
        }

        // Segment averages table
        const header = "| Segment | Avg UX | Avg Content | Avg CTA | Avg Apps | Signup % |";
        const divider = "|---------|--------|-------------|---------|----------|----------|";
        const rows = Object.entries(segmentScores).map(([seg, s]) => {
          const avgUx = (s.ux / s.total).toFixed(1);
          const avgContent = (s.content / s.total).toFixed(1);
          const avgCta = (s.cta / s.total).toFixed(1);
          const avgApps = (s.apps / s.total).toFixed(1);
          const signupPct = ((s.signups / s.total) * 100).toFixed(0);
          return `| ${seg} | ${avgUx} | ${avgContent} | ${avgCta} | ${avgApps} | ${signupPct}% |`;
        });

        const segmentTable = [header, divider, ...rows].join("\n");

        // Best/worst personas by average score
        const scored = results.map((r) => {
          const avg =
            (r.uxScore + r.contentRelevance + r.ctaCompelling + r.recommendedAppsRelevant) / 4;
          const persona = PERSONAS.find((p) => p.slug === r.personaSlug);
          return { slug: r.personaSlug, name: persona ? persona.name : r.personaSlug, avg };
        });
        scored.sort((a, b) => b.avg - a.avg);

        const best = scored[0]!;
        const worst = scored[scored.length - 1]!;

        const insights = [
          `**Best performing**: ${best.name} (avg ${best.avg.toFixed(1)})`,
          `**Worst performing**: ${worst.name} (avg ${worst.avg.toFixed(1)})`,
        ].join("\n");

        return jsonResult(
          `## Segment Comparison\n\n${segmentTable}\n\n## Insights\n\n${insights}`,
          { segmentScores, best: best.slug, worst: worst.slug },
        );
      }),
  );
}

/**
 * Reminders Tools (CF Workers)
 *
 * CRUD for user reminders using Drizzle ORM + D1.
 * Simplified from spike.land's workspace-scoped connectionReminder model
 * to a flat per-user reminders table.
 */

import { z } from "zod";
import { and, eq, isNotNull, isNull } from "drizzle-orm";
import type { ToolRegistryAdapter } from "../../lazy-imports/types";
import { freeTool } from "../../lazy-imports/procedures-index.ts";
import { textResult } from "../../core-logic/lib/tool-helpers";
import type { DrizzleDB } from "../db/db-index.ts";
import { reminders } from "../db/schema";

export function registerRemindersTools(
  registry: ToolRegistryAdapter,
  userId: string,
  db: DrizzleDB,
): void {
  const t = freeTool(userId, db);

  registry.registerBuilt(
    t
      .tool("reminders_list", "List your reminders.", {
        status: z
          .enum(["ACTIVE", "COMPLETED", "ALL"])
          .optional()
          .default("ACTIVE")
          .describe("Filter by status."),
      })
      .meta({ category: "reminders", tier: "free" })
      .handler(async ({ input, ctx }) => {
        const conditions = [eq(reminders.userId, ctx.userId)];

        if (input.status === "ACTIVE") {
          conditions.push(isNull(reminders.completedAt));
        } else if (input.status === "COMPLETED") {
          conditions.push(isNotNull(reminders.completedAt));
        }

        const rows = await ctx.db
          .select()
          .from(reminders)
          .where(and(...conditions))
          .orderBy(reminders.dueAt);

        if (rows.length === 0) return textResult("No reminders found.");

        let text = `**Your Reminders (${rows.length})**\n\n`;
        for (const r of rows) {
          const status = r.completedAt ? "COMPLETED" : "ACTIVE";
          const dueStr = r.dueAt ? new Date(r.dueAt).toISOString() : "No due date";
          text += `- **${r.text}** [${status}]\n  Due: ${dueStr}\n  ID: \`${r.id}\`\n\n`;
        }
        return textResult(text);
      }),
  );

  registry.registerBuilt(
    t
      .tool("reminders_create", "Create a new reminder.", {
        text: z.string().min(1).describe("Reminder text."),
        due_date: z.string().datetime().optional().describe("ISO 8601 due date."),
      })
      .meta({ category: "reminders", tier: "free" })
      .handler(async ({ input, ctx }) => {
        const id = crypto.randomUUID();
        const now = Date.now();

        await ctx.db.insert(reminders).values({
          id,
          userId: ctx.userId,
          text: input.text,
          dueAt: input.due_date ? new Date(input.due_date).getTime() : null,
          completedAt: null,
          createdAt: now,
        });

        return textResult(`**Reminder Created!**\n\nID: \`${id}\`\nText: ${input.text}`);
      }),
  );

  registry.registerBuilt(
    t
      .tool("reminders_complete", "Mark a reminder as completed.", {
        reminder_id: z.string().min(1).describe("Reminder ID."),
      })
      .meta({ category: "reminders", tier: "free" })
      .handler(async ({ input, ctx }) => {
        const now = Date.now();

        const updated = await ctx.db
          .update(reminders)
          .set({ completedAt: now })
          .where(and(eq(reminders.id, input.reminder_id), eq(reminders.userId, ctx.userId)))
          .returning({ id: reminders.id, text: reminders.text });

        if (updated.length === 0) {
          return textResult(
            "**Error: NOT_FOUND**\nReminder not found or not owned by you.\n**Retryable:** false",
          );
        }

        return textResult(
          `**Reminder Completed!**\n\nID: \`${updated[0]!.id}\`\nText: ${updated[0]!.text}`,
        );
      }),
  );
}

/**
 * Swarm Monitoring MCP Tools (CF Workers)
 *
 * Tools for monitoring AI agent swarm performance, costs, and health status.
 * Runs on Cloudflare Workers with Drizzle ORM.
 *
 * The D1 schema has a simplified claudeCodeAgents table without audit logs,
 * so metrics/replay tools work with available data (agent status + metadata).
 * Docker-based metrics are stubbed.
 */

import { z } from "zod";
import { desc, eq } from "drizzle-orm";
import type { ToolRegistry } from "../../lazy-imports/registry";
import { freeTool, textResult } from "../../lazy-imports/procedures-index.ts";
import { agentMessages, claudeCodeAgents } from "../db/schema";
import type { DrizzleDB } from "../db/db-index.ts";

export function registerSwarmMonitoringTools(
  registry: ToolRegistry,
  userId: string,
  db: DrizzleDB,
): void {
  const t = freeTool(userId, db);

  // swarm_get_metrics
  registry.registerBuilt(
    t
      .tool(
        "swarm_get_metrics",
        "Get swarm performance metrics: agent count, status breakdown, and activity summary for a given time period.",
        {
          period: z
            .enum(["1h", "24h", "7d", "30d"])
            .optional()
            .default("24h")
            .describe("Time period to aggregate metrics over."),
        },
      )
      .meta({ category: "swarm-monitoring", tier: "free" })
      .handler(async ({ input, ctx }) => {
        const { period = "24h" } = input;

        const periodMs: Record<string, number> = {
          "1h": 60 * 60 * 1000,
          "24h": 24 * 60 * 60 * 1000,
          "7d": 7 * 24 * 60 * 60 * 1000,
          "30d": 30 * 24 * 60 * 60 * 1000,
        };
        const since = Date.now() - (periodMs[period] ?? periodMs["24h"]!);

        const agents = await ctx.db
          .select({
            id: claudeCodeAgents.id,
            name: claudeCodeAgents.name,
            status: claudeCodeAgents.status,
            lastActiveAt: claudeCodeAgents.lastActiveAt,
            metadata: claudeCodeAgents.metadata,
            createdAt: claudeCodeAgents.createdAt,
          })
          .from(claudeCodeAgents)
          .where(eq(claudeCodeAgents.userId, ctx.userId));

        const agentsSpawned = agents.filter((a) => a.createdAt >= since).length;
        const running = agents.filter((a) => a.status === "running").length;
        const idle = agents.filter((a) => a.status === "idle").length;
        const stopped = agents.filter((a) => a.status === "stopped").length;

        const text =
          `**Swarm Metrics (${period})**\n\n` +
          `- Total agents: ${agents.length}\n` +
          `- Agents spawned in period: ${agentsSpawned}\n` +
          `- Running: ${running}\n` +
          `- Idle: ${idle}\n` +
          `- Stopped: ${stopped}\n\n` +
          `_Note: Detailed audit log metrics (task duration, success rate, token usage) ` +
          `require the spike.land platform. This edge worker provides agent status metrics only._`;

        return textResult(text);
      }),
  );

  // swarm_get_cost
  registry.registerBuilt(
    t
      .tool(
        "swarm_get_cost",
        "Get token usage and cost breakdown for the swarm. Reads usage data from agent metadata.",
        {
          agent_id: z
            .string()
            .optional()
            .describe("Filter by a specific agent ID. Omit for swarm-wide totals."),
        },
      )
      .meta({ category: "swarm-monitoring", tier: "free" })
      .handler(async ({ input, ctx }) => {
        const { agent_id } = input;

        const agents = agent_id
          ? await ctx.db
              .select()
              .from(claudeCodeAgents)
              .where(eq(claudeCodeAgents.id, agent_id))
              .limit(1)
          : await ctx.db
              .select()
              .from(claudeCodeAgents)
              .where(eq(claudeCodeAgents.userId, ctx.userId));

        if (agents.length === 0) {
          return textResult(agent_id ? `Agent ${agent_id} not found.` : "No agents found.");
        }

        const TOKEN_COST_USD = 0.000003;
        let totalTokens = 0;

        let text = `**Swarm Token Cost${agent_id ? ` (agent: ${agent_id})` : ""}**\n\n`;
        text += `**Breakdown by agent:**\n\n`;

        for (const a of agents) {
          const meta = JSON.parse(a.metadata || "{}") as Record<string, unknown>;
          const tokens = typeof meta["totalTokensUsed"] === "number" ? meta["totalTokensUsed"] : 0;
          totalTokens += tokens;
          const agentCost = (tokens * TOKEN_COST_USD).toFixed(4);
          text += `- **${a.name}** — ${tokens.toLocaleString()} tokens ($${agentCost})\n`;
          text += `  ID: ${a.id}\n`;
        }

        const totalCostUsd = (totalTokens * TOKEN_COST_USD).toFixed(4);
        text =
          `**Swarm Token Cost${agent_id ? ` (agent: ${agent_id})` : ""}**\n\n` +
          `- Total tokens: ${totalTokens.toLocaleString()}\n` +
          `- Estimated cost: $${totalCostUsd}\n\n` +
          `**Breakdown by agent:**\n\n`;

        for (const a of agents) {
          const meta = JSON.parse(a.metadata || "{}") as Record<string, unknown>;
          const tokens = typeof meta["totalTokensUsed"] === "number" ? meta["totalTokensUsed"] : 0;
          const agentCost = (tokens * TOKEN_COST_USD).toFixed(4);
          text += `- **${a.name}** — ${tokens.toLocaleString()} tokens ($${agentCost})\n`;
          text += `  ID: ${a.id}\n`;
        }

        return textResult(text);
      }),
  );

  // swarm_replay
  registry.registerBuilt(
    t
      .tool(
        "swarm_replay",
        "Replay an agent's message history step-by-step. Returns timestamped messages with optional range filtering.",
        {
          agent_id: z.string().min(1).describe("ID of the agent to replay."),
          from_step: z
            .number()
            .int()
            .min(0)
            .optional()
            .describe("Start from this step index (inclusive, 0-based)."),
          to_step: z
            .number()
            .int()
            .min(0)
            .optional()
            .describe("Stop at this step index (inclusive, 0-based)."),
        },
      )
      .meta({ category: "swarm-monitoring", tier: "free" })
      .handler(async ({ input, ctx }) => {
        const { agent_id, from_step, to_step } = input;

        // Verify ownership
        const agentRows = await ctx.db
          .select({
            userId: claudeCodeAgents.userId,
            name: claudeCodeAgents.name,
          })
          .from(claudeCodeAgents)
          .where(eq(claudeCodeAgents.id, agent_id))
          .limit(1);

        const agent = agentRows[0];
        if (!agent) return textResult(`Agent ${agent_id} not found.`);
        if (agent.userId !== ctx.userId) {
          return textResult(`Agent ${agent_id} not found.`);
        }

        const allMessages = await ctx.db
          .select({
            id: agentMessages.id,
            role: agentMessages.role,
            content: agentMessages.content,
            createdAt: agentMessages.createdAt,
          })
          .from(agentMessages)
          .where(eq(agentMessages.agentId, agent_id))
          .orderBy(agentMessages.createdAt);

        if (allMessages.length === 0) {
          return textResult(`No message history found for agent ${agent_id}.`);
        }

        const startIdx = from_step ?? 0;
        const endIdx = to_step !== undefined ? to_step + 1 : allMessages.length;
        const sliced = allMessages.slice(startIdx, endIdx);

        if (sliced.length === 0) {
          return textResult(
            `No steps in range [${startIdx}, ${
              to_step ?? allMessages.length - 1
            }] for agent ${agent_id}.`,
          );
        }

        let text = `**Replay: ${agent.name}** (steps ${startIdx}–${
          startIdx + sliced.length - 1
        } of ${allMessages.length} total)\n\n`;

        sliced.forEach((msg, i) => {
          const stepNum = startIdx + i;
          text += `**Step ${stepNum}**\n`;
          text += `  Role: ${msg.role}\n`;
          text += `  Time: ${new Date(msg.createdAt).toISOString()}\n`;
          text += `  Content: ${msg.content.slice(0, 120)}${
            msg.content.length > 120 ? "..." : ""
          }\n`;
          text += "\n";
        });

        return textResult(text);
      }),
  );

  // swarm_health
  registry.registerBuilt(
    t
      .tool(
        "swarm_health",
        "Get health status of all agents: alive/stuck/errored state, last activity time, and current status.",
        {},
      )
      .meta({ category: "swarm-monitoring", tier: "free" })
      .handler(async ({ ctx }) => {
        const now = Date.now();
        const fiveMinAgo = now - 5 * 60 * 1000;
        const thirtyMinAgo = now - 30 * 60 * 1000;

        const agents = await ctx.db
          .select({
            id: claudeCodeAgents.id,
            name: claudeCodeAgents.name,
            status: claudeCodeAgents.status,
            lastActiveAt: claudeCodeAgents.lastActiveAt,
            metadata: claudeCodeAgents.metadata,
          })
          .from(claudeCodeAgents)
          .where(eq(claudeCodeAgents.userId, ctx.userId))
          .orderBy(desc(claudeCodeAgents.lastActiveAt));

        if (agents.length === 0) return textResult("No agents found.");

        let aliveCount = 0;
        let stuckCount = 0;
        let erroredCount = 0;

        let text = `**Swarm Health (${agents.length} agents)**\n\n`;

        for (const a of agents) {
          let health: string;
          if (a.status === "stopped") {
            health = "STOPPED";
            erroredCount++;
          } else if (!a.lastActiveAt) {
            health = "ERRORED";
            erroredCount++;
          } else if (a.lastActiveAt >= fiveMinAgo) {
            health = "ALIVE";
            aliveCount++;
          } else if (a.lastActiveAt >= thirtyMinAgo) {
            health = "STUCK";
            stuckCount++;
          } else {
            health = "ERRORED";
            erroredCount++;
          }

          const lastActivity = a.lastActiveAt ? new Date(a.lastActiveAt).toISOString() : "never";

          const meta = JSON.parse(a.metadata || "{}") as Record<string, unknown>;
          const currentTask = meta["projectPath"]
            ? `Working on: ${meta["projectPath"]}`
            : "No active task";

          text += `- **${a.name}** [${health}]\n`;
          text += `  Last activity: ${lastActivity}\n`;
          text += `  ${currentTask}\n`;
          text += `  ID: ${a.id}\n\n`;
        }

        text += `**Summary:** ${aliveCount} alive, ${stuckCount} stuck, ${erroredCount} errored/stopped`;
        return textResult(text);
      }),
  );
}

import { describe, expect, it, vi, afterEach } from "vitest";
import app from "../api/app";
import { STATUS_PROBE_HEADER } from "../../common/core-logic/service-metrics";
import type { Env } from "../core-logic/env";
import {
  createStatusSnapshot,
  probeAll,
  probeService,
  SERVICES,
  type ServiceProbe,
} from "../core-logic/monitor";

function createFetcher(handler: (request: Request) => Response | Promise<Response>): Fetcher {
  return {
    fetch: vi.fn(handler),
  };
}

function createStatusDb(
  rowsByService: Record<
    string,
    Array<{
      minute_bucket: number;
      request_count: number;
      latency_min_ms: number;
      latency_max_ms: number;
      latency_sum_ms: number;
      latency_sum_sq_ms: number;
    }>
  > = {},
): D1Database {
  return {
    batch: vi.fn(async () => []),
    exec: vi.fn(async () => undefined),
    prepare: vi.fn(() => ({
      bind: (...params: unknown[]) => {
        const [serviceName, cutoff] = params;
        const rows =
          typeof serviceName === "string"
            ? (rowsByService[serviceName] ?? []).filter(
                (row) => row.minute_bucket >= Number(cutoff ?? 0),
              )
            : [];

        return {
          all: vi.fn(async () => ({ results: rows })),
          run: vi.fn(async () => ({ success: true })),
          first: vi.fn(async () => rows[0] ?? null),
        };
      },
    })),
  } as unknown as D1Database;
}

function createEnv(overrides: Partial<Env> = {}): Env {
  const okFetcher = createFetcher(
    () => new Response(JSON.stringify({ status: "ok" }), { status: 200 }),
  );

  return {
    STATUS_DB: createStatusDb(),
    SPIKE_EDGE: okFetcher,
    TRANSPILE: okFetcher,
    MCP_REGISTRY: okFetcher,
    AUTH_MCP: okFetcher,
    IMAGE_STUDIO: okFetcher,
    ...overrides,
  };
}

afterEach(() => {
  vi.restoreAllMocks();
});

describe("probeService", () => {
  it("uses the service binding health endpoint and marks fast successes as up", async () => {
    const service: ServiceProbe = {
      label: "Edge API",
      url: "https://api.spike.land/health",
      binding: "SPIKE_EDGE",
      path: "/api/health",
    };
    const fetcher = createFetcher((request) => {
      expect(new URL(request.url).pathname).toBe("/api/health");
      expect(request.headers.get(STATUS_PROBE_HEADER)).toBe("1");
      return new Response(JSON.stringify({ status: "ok" }), { status: 200 });
    });
    const env = createEnv({ SPIKE_EDGE: fetcher });

    vi.spyOn(Date, "now").mockReturnValueOnce(100).mockReturnValueOnce(250);

    await expect(probeService(service, env)).resolves.toEqual({
      label: "Edge API",
      url: "https://api.spike.land/health",
      status: "up",
      httpStatus: 200,
      latencyMs: 150,
      error: null,
    });
  });

  it("marks slow successes as degraded", async () => {
    const env = createEnv();

    vi.spyOn(Date, "now").mockReturnValueOnce(0).mockReturnValueOnce(1500);

    await expect(probeService(SERVICES[0]!, env)).resolves.toMatchObject({
      status: "degraded",
      httpStatus: 200,
      latencyMs: 1500,
    });
  });

  it("marks failed binding fetches as down", async () => {
    const env = createEnv({
      AUTH_MCP: createFetcher(() => {
        throw new Error("boom");
      }),
    });

    vi.spyOn(Date, "now").mockReturnValueOnce(10).mockReturnValueOnce(25);

    await expect(probeService(SERVICES[4]!, env)).resolves.toMatchObject({
      status: "down",
      httpStatus: null,
      latencyMs: 15,
      error: "boom",
    });
  });
});

