let mutex: Mutex;

export const transpile = async ({
  code,
  originToUse,
  wasmModule,
}: {
  code: string;
  originToUse: string;
  wasmModule?: WebAssembly.Module;
}): Promise<string> => {
  if (!mutex) {
    mutex = new Mutex();
  }
  return mutex.runExclusive(async () => {
    const tp = (
      globalThis as unknown as {
        transpile?: typeof transpile;
      }
    ).transpile;

    if (tp) {
      const params: {
        code: string;
        originToUse: string;
        wasmModule?: WebAssembly.Module;
      } = {
        code,
        originToUse,
      };
      if (wasmModule) {
        params.wasmModule = wasmModule;
      }
      return tp(params);
    }
    const worker = (await init()).getWorker("esbuild");
    try {
      const { data, error } = await tryCatch(
        worker.rpc.rpc("transpile", {
          code,
          originToUse,
          wasmModule,
        }) as Promise<string>,
      );
      if (error) {
        console.error(error);
        throw error;
      }
      return data!;
    } finally {
      (await init()).releaseWorker(worker);
    }
  });
};

export const build = async ({
  codeSpace,
  origin,
  format = "esm",
  splitting = false,
  entryPoints,
  external = [],
}: MyBuildOptions): Promise<string> => {
  const worker = (await init()).getWorker("esbuild");
  try {
    const { data, error } = await tryCatch(
      worker.rpc.rpc("build", {
        codeSpace,
        origin,
        splitting,
        external,
        entryPoints,
        format,
      }) as Promise<string>,
    );
    if (error) throw error;
    return data!;
  } finally {
    (await init()).releaseWorker(worker);
  }
};

export const connect = async ({
  signal,
  sess,
}: {
  signal: string;
  sess: ICodeSession;
}): Promise<() => void> => {
  const worker = (await init()).getWorker("connect");
  try {
    // rpc.signal does not return a promise, so tryCatch is not directly applicable here
    // If it could error, it would need a synchronous try/catch or a different pattern
    worker.rpc.signal("connect", { signal, sess });

    return async () => {
      (await init()).releaseWorker(worker);
    };
  } catch (e) {
    console.error(e);
    (await init()).releaseWorker(worker);
    throw e; // Re-throw after logging and releasing worker
  }
};

import { getWasmModule, setWasmModule } from "../core-logic/lib/idb-cache";
import { importMap } from "../core-logic/lib/importmap-utils";
import { tryCatch } from "../lazy-imports/try-catch";
import { Mutex } from "async-mutex";
import type { BuildOptions } from "esbuild-wasm";
import esbuildWasm from "esbuild-wasm";
import type * as esbuild from "esbuild-wasm";
import { wasmFile } from "../lazy-imports/esbuildWASM";
import { fetchPlugin } from "../lazy-imports/esbuild-fetch-plugin";
import { makeEnv } from "../core-logic/lib/esbuild-make-env";

export { wasmFile };

const { build: esmBuild, initialize, transform } = esbuildWasm as typeof import("esbuild-wasm");

export type MyBuildOptions = BuildOptions & {
  codeSpace: string;
  origin: string;
  wasmModule?: WebAssembly.Module;
};

interface ModuleInitializer {
  init: boolean | Promise<boolean>;
  initialize: (wasmModule: WebAssembly.Module) => Promise<boolean> | boolean;
}

const mod: ModuleInitializer = {
  init: false,
  initialize: async (wasmModule: WebAssembly.Module) => {
    if (mod.init === true) return true;
    await initialize({ wasmModule, worker: false });
    return (mod.init = true);
  },
};

const mutex = new Mutex();

const initializeModule = async (wasmModule?: WebAssembly.Module, origin?: string) => {
  if (mod.init) return;

  if (wasmModule) {
    await mod.initialize(wasmModule);
  } else if (origin) {
    // Try IDB-cached WASM first
    const cachedWasm = await getWasmModule("esbuild-wasm");
    if (cachedWasm) {
      const compiled = await WebAssembly.compile(cachedWasm);
      await mod.initialize(compiled);
    } else {
      const wasmURL = new URL(`${origin}/${wasmFile}`).toString();
      const response = await fetch(wasmURL);
      const buffer = await response.arrayBuffer();
      await setWasmModule("esbuild-wasm", buffer);
      const compiled = await WebAssembly.compile(buffer);
      await mod.initialize(compiled);
    }
  } else {
    throw new Error("Either wasmModule or origin must be provided");
  }
};

export const transpile = async ({
  code,
  originToUse,
  wasmModule,
}: {
  code: string;
  originToUse: string;
  wasmModule?: WebAssembly.Module;
}): Promise<string> => {
  return mutex.runExclusive(async () => {
    const transpilePromise = async () => {
      await initializeModule(wasmModule, originToUse);
      const transformedCode = await transform(code, {
        loader: "tsx",
        format: "esm",
        treeShaking: true,
        platform: "browser",
        minify: false,
        charset: "utf8",
        keepNames: true,
        tsconfigRaw: {
          compilerOptions: {
            jsx: "react-jsx",
            jsxFragmentFactory: "Fragment",
            jsxImportSource: "@emotion/react",
          },
        },
        target: "es2024",
      });
      return transformedCode.code;
    };

    const { data, error } = await tryCatch<string>(transpilePromise());

    if (error) {
      if (error instanceof Error) {
        console.error("Error during transpile:", error.message);
      }
      throw error; // Re-throw the original error
    }
    if (data === null || data === undefined) {
      throw new Error("Transpilation returned null or undefined.");
    }
    return data;
  });
};

