  },
  format,
  platform: "browser",
  outExtension: { ".js": ".mjs", ".css": ".css" },
  entryPoints: entryPoints ? [entryPoints] : [`${origin}/live/${codeSpace}/wrapper.js`],
  plugins: [fetchPlugin(origin)],
  assetNames: "assets/[name]-[hash]",
  publicPath: "/",
});

export const build = async ({
  codeSpace,
  origin,
  entryPoints,
  external = [],
  splitting = false,
  wasmModule = undefined,
  metafile = false,
  format = "esm",
}: MyBuildOptions): Promise<string | esbuild.OutputFile[] | { error: unknown }> => {
  return mutex.runExclusive(async () => {
    const buildPromise = async () => {
      await initializeModule(wasmModule, origin);
      const defaultOpts = getDefaultBuildOptions({
        codeSpace,
        origin,
        external,
        metafile,
        splitting,
        format,
      });

      const currentBuildOptions = {
        // Renamed to avoid conflict
        ...defaultOpts,
        external: [...Object.keys(importMap.imports)],
        entryPoints: entryPoints ? entryPoints : [`${origin}/live/${codeSpace}/index.tsx`],
      } as BuildOptions;

      const result = await esmBuild(currentBuildOptions);
      if (!result.outputFiles || result.outputFiles.length === 0) {
        throw new Error("Build failed, no output files produced.");
      }
      if (splitting) {
        return result.outputFiles;
      } else {
        return result.outputFiles[0]!.text;
      }
    };

    const { data, error } = await tryCatch<string | esbuild.OutputFile[]>(buildPromise());

    if (error) {
      console.error("Error during build:", error);
      return { error };
    }
    if (data === null || data === undefined) {
      throw new Error("Build returned null or undefined.");
    }
    return data;
  });
};

Object.assign(globalThis, { transpile, build });

import { md5 } from "../../../../crypto-data-structures/md5";
import { wait } from "../../../lib/wait";
import { editor, Range, typescript, Uri } from "../../../../editor/monaco-editor.worker";
import { getEditorOptions } from "../../../../editor/config";
import { originToUse } from "../../../../editor/config";
import { configureJsxSupport, registerLanguages } from "./language";
import type {
  EditorConfig,
  EditorModel,
  MonacoEditorInternalState,
} from "../../../../editor/types";
import {
  checkTypeScriptErrors,
  fetchAndCreateExtraModels,
  getImports,
  loadMonacoCss,
  refreshAta,
  setupResponsiveEditor,
} from "./utils";
import { ensureSpikeLandMonacoTheme } from "../../../../editor/theme";

// Global API interface for agent control
interface SpikeEditorAPI {
  getValue: () => string;
  setValue: (value: string) => void;
  getSelection: () => string;
  insertText: (text: string) => void;
  replace: (search: string, replacement: string) => void;
  replaceAll: (search: string, replacement: string) => void;
  focus: () => void;
  setPosition: (line: number, column: number) => void;
  revealLine: (line: number) => void;
  triggerAction: (actionId: string) => void;
  format: () => void;
  undo: () => void;
  redo: () => void;
  getLineCount: () => number;
  getPosition: () => { line: number; column: number };
}

declare global {
  interface Window {
    __spikeEditor?: SpikeEditorAPI;
  }
}

// Store for editor models
const modelStore: Record<string, EditorModel> = {};

/**
 * Initialize Monaco editor with the given configuration
 * @param config Editor configuration
 * @param ata Auto Type Acquisition function
 */
export async function startMonaco(
  { code, container, codeSpace, onChange }: EditorConfig,
  ata: (options: {
    code: string;
    originToUse: string;
  }) => Promise<Array<{ filePath: string; content: string }>>,
): Promise<EditorModel> {
  // If we already have a model for this codeSpace, check if it's still valid
  if (modelStore[codeSpace]) {
    try {
      // Check if the container is still in the DOM
      if (container && document.body.contains(container)) {
        return modelStore[codeSpace];
      } else {
        // Container is no longer in the DOM, clean up the old model
        console.debug(`Container for ${codeSpace} is no longer in the DOM, creating new model`);
        // Use requestAnimationFrame to ensure we're not unmounting during render
        requestAnimationFrame(() => {
          delete modelStore[codeSpace];
        });
      }
    } catch (error) {
      console.error(`Error checking model for ${codeSpace}:`, error);
      // Use requestAnimationFrame to ensure we're not unmounting during render
      requestAnimationFrame(() => {
        delete modelStore[codeSpace];
      });
    }
  }

  // Create a new model
  modelStore[codeSpace] = await createEditorModel(
    {
      code,
      container,
      codeSpace,
      onChange,
    },
    ata,
  );

  return modelStore[codeSpace];
}

/**
 * Create a new editor model
 * @param config Editor configuration
 * @param ata Auto Type Acquisition function
 */
async function createEditorModel(
  { code, container, codeSpace, onChange }: EditorConfig,
  ata: (options: {
    code: string;
    originToUse: string;
  }) => Promise<Array<{ filePath: string; content: string }>>,
): Promise<EditorModel> {
  // Initialize languages and compiler options
  registerLanguages();

  ensureSpikeLandMonacoTheme();

  // Process code and prepare for editor

  fetchAndCreateExtraModels(code, originToUse)
    .then(() => refreshAta(code, ata))
    .catch((error) => {
      console.error("Error fetching extra models:", error);
    });
  // Create URI for the model
  const uri = Uri.parse(`${originToUse}/live/${codeSpace}.tsx`);
  let model = editor.getModel(uri);

  if (model) {
    model.setValue(code);
  } else {
    // Create a new model
    model = editor.createModel(code, "typescript", uri);

    // Configure JSX support for TSX files
    configureJsxSupport(uri.toString());
  }

  // Load Monaco CSS
  await loadMonacoCss();

  // Create editor with responsive options
  const editorOptions = getEditorOptions();
  const myEditor = editor.create(container, {
    ...editorOptions,
    model: model,
  });

  // Set up responsive behavior
  const cleanupResponsive = setupResponsiveEditor(myEditor);

  // Initialize state for tracking changes
  let abortController = new AbortController();
  const ttt = { checking: 0 };
  const recentlyChanged = new Set<string>();

  // Create editor model interface
  const editorModel: EditorModel = {
    getValue: () => model.getValue(),
    silent: false,
    getErrors: async () => {
      try {
        const worker = await typescript.getTypeScriptWorker();
        const typeScriptWorker = await worker(uri);
        const diagnostics = await typeScriptWorker.getSuggestionDiagnostics(uri.toString());
        const extractMessageText = (message: string | { messageText: string }): string => {
          if (typeof message === "string") {
            return message;
          } else if (message && typeof message.messageText !== "undefined") {
            return extractMessageText(message.messageText);
          } else {
            return "Unknown diagnostic message";
          }
        };
        return diagnostics.map((d: { messageText: string | { messageText: string } }) =>
          extractMessageText(d.messageText),
        );
      } catch (error) {
        console.error("Error getting diagnostics:", error);
        return ["Error fetching diagnostics"];
      }
    },
    isEdit: false,
    lastValueHashToBeSet: "",
    setValue: async (newCode: string) => {
      const lastHash = md5(newCode);

      // Prevent recursive updates
      if (editorModel.silent) {
        console.debug("Skipping setValue while silent");
        return;
      }

      // Check if this update is necessary
      const currentCode = model.getValue();
      if (currentCode === newCode) {
        console.debug("Skipping identical content update");
        return;
      }

      editorModel.lastValueHashToBeSet = lastHash;

      // Handle recently changed content
      if (recentlyChanged.has(lastHash)) {
        console.debug("Content was recently changed, debouncing update");
        await wait(1000);
        if (editorModel.lastValueHashToBeSet !== lastHash) {
          console.debug("Newer update pending, skipping this one");
          return;
        }
      }

      // Save editor state before update
      const viewState = myEditor.saveViewState();
      editorModel.silent = true;

      try {
        // Update in a single atomic operation
        await wait(0); // Break potential call stack
        model.pushEditOperations(
          [],
          [
            {
              range: model.getFullModelRange(),
              text: newCode,
            },
          ],
          () => null,
        );

        // Restore view state if available
        if (viewState) {
          await wait(0); // Ensure DOM has updated
          myEditor.restoreViewState(viewState);
        }

        // Mark this content as recently changed
        recentlyChanged.add(lastHash);
        setTimeout(() => recentlyChanged.delete(lastHash), 1000);
      } catch (error) {
        console.error("Error updating editor value:", error);
      } finally {
        await wait(0); // Ensure all updates are processed
        editorModel.silent = false;
      }
    },
  };

  // Expose global API for agent control
  const spikeEditorAPI: SpikeEditorAPI = {
    getValue: () => model.getValue(),
    setValue: (value: string) => editorModel.setValue(value),
    getSelection: () => myEditor.getModel()?.getValueInRange(myEditor.getSelection()!) || "",
    insertText: (text: string) => {
      const selection = myEditor.getSelection();
      if (selection) {
        myEditor.executeEdits("api", [
          {
            range: selection,
            text,
            forceMoveMarkers: true,
          },
        ]);
      }
    },
    replace: (search: string, replacement: string) => {
      const content = model.getValue();
      const idx = content.indexOf(search);
      if (idx !== -1) {
        const startPos = model.getPositionAt(idx);
        const endPos = model.getPositionAt(idx + search.length);
        myEditor.executeEdits("api", [
          {
            range: new Range(
              startPos.lineNumber,
              startPos.column,
              endPos.lineNumber,
              endPos.column,
            ),
            text: replacement,
            forceMoveMarkers: true,
          },
        ]);
      }
    },
    replaceAll: (search: string, replacement: string) => {
      const content = model.getValue();
      const edits: { range: Range; text: string; forceMoveMarkers: boolean }[] = [];
      let idx = 0;
      while ((idx = content.indexOf(search, idx)) !== -1) {
        const startPos = model.getPositionAt(idx);
        const endPos = model.getPositionAt(idx + search.length);
        edits.push({
          range: new Range(startPos.lineNumber, startPos.column, endPos.lineNumber, endPos.column),
          text: replacement,
          forceMoveMarkers: true,
        });
        idx += search.length;
      }
      if (edits.length > 0) {
        myEditor.executeEdits("api", edits);
      }
    },
    focus: () => myEditor.focus(),
    setPosition: (line: number, column: number) =>
      myEditor.setPosition({ lineNumber: line, column }),
    revealLine: (line: number) => myEditor.revealLineInCenter(line),
    triggerAction: (actionId: string) => myEditor.trigger("api", actionId, null),
    format: () => myEditor.trigger("api", "editor.action.formatDocument", null),
    undo: () => myEditor.trigger("api", "undo", null),
    redo: () => myEditor.trigger("api", "redo", null),
    getLineCount: () => model.getLineCount(),
    getPosition: () => {
      const pos = myEditor.getPosition();
      return { line: pos?.lineNumber || 1, column: pos?.column || 1 };
    },
  };

  window.__spikeEditor = spikeEditorAPI;

  // Set up focus/blur handlers
  myEditor.getDomNode()?.blur();

  myEditor.onDidFocusEditorText(() => {
    editorModel.isEdit = true;
    abortController.abort();
    abortController = new AbortController();
    setTimeout(() => {
      if (abortController.signal.aborted) return;
      editorModel.isEdit = false;
    }, 50);
  });

  myEditor.onDidBlurEditorText(() => {
    editorModel.isEdit = false;
  });

  // Function to handle content changes and formatting
  const onChangeAddRecentlyChanged = async () => {
    const code = model.getValue();
    const hashOfCode = md5(code);
    recentlyChanged.add(hashOfCode);

    onChange(code);
    setTimeout(() => {
      recentlyChanged.delete(hashOfCode);
    }, 1000);
  };

  // Set up state for tracking content updates
  const editorState: MonacoEditorInternalState = {
    isUpdating: { current: false },
    pendingUpdate: { current: null },
    previousContent: { current: model.getValue() },
    previousImports: { current: getImports(model.getValue()) },
  };

  // Handle content changes
  model.onDidChangeContent(() => {
    if (editorModel.silent) return;

    // Handle concurrent updates
    if (editorState.isUpdating.current) {
      editorState.pendingUpdate.current = model.getValue();
      return;
    }

    const processUpdate = async () => {
      editorState.isUpdating.current = true;
      try {
        const content = editorState.pendingUpdate.current || model.getValue();
        editorState.pendingUpdate.current = null;

        // Check if imports have changed
        const currentImports = getImports(content);
        const importsChanged =
          JSON.stringify(currentImports) !== JSON.stringify(editorState.previousImports.current);

        // Check if the user has finished editing or if imports have changed
        if (!editorModel.isEdit || importsChanged) {
          console.warn("User finished editing or imports changed, saving changes");
          editorState.previousImports.current = currentImports;

          // Save changes
          await onChangeAddRecentlyChanged();
        }

        // Always run type checking after changes
        if (ttt.checking === 0) {
          ttt.checking = 1;
          try {
            await checkTypeScriptErrors(model, uri);
          } finally {
            ttt.checking = 0;
          }
        }

        editorState.previousContent.current = content;

        // Handle any updates that came in while processing
        if (editorState.pendingUpdate.current) {
          editorState.pendingUpdate.current = null;
          await processUpdate();
        }
      } finally {
        editorState.isUpdating.current = false;
      }
    };

    processUpdate().catch((error) => console.error("Error processing content update:", error));
  });

  // Add cleanup method to the model
  return {
    ...editorModel,
    dispose: () => {
      delete window.__spikeEditor;
      cleanupResponsive();
      myEditor.dispose();
      model.dispose();
      delete modelStore[codeSpace];
    },
  };
}

import { wait } from "../../../lib/wait";
import { editor, typescript, Uri } from "../../../../editor/monaco-editor.worker";
import { modelCache, originToUse } from "../../../../editor/config";
import type { ExtraLib } from "../../../../editor/types";

/**
 * Fetch and create extra models for imports
 * @param code The code to analyze for imports
 * @param originToUse The origin URL
 */
export async function fetchAndCreateExtraModels(code: string, originToUse: string): Promise<void> {
  const patterns = [
    new RegExp(` from "(${originToUse})/live/[a-zA-Z0-9\\-_]+`, "gm"),
    new RegExp(` from "\\./(?!@/)[a-zA-Z0-9\\-_]+`, "gm"),
    new RegExp(` from "/live/[a-zA-Z0-9\\-_]+`, "gm"),
  ];

  const matches = patterns.flatMap((pattern) => [...code.matchAll(pattern)]);

  try {
    await Promise.all(
      matches.map(async (match) => {
        const codeSpace = match[0]!.split("/").pop();
        const extraModel = new URL(`/live/${codeSpace}/index.tsx`, originToUse).toString();
        const mUri = Uri.parse(`${originToUse}/live/${codeSpace}.tsx`);

        if (!modelCache[mUri.toString()]) {
          const res = await fetch(extraModel);
          if (!res.ok) {
            throw new Error(`Failed to fetch model: ${res.statusText}`);
          }
          const content = await res.text();
          modelCache[mUri.toString()] = editor.createModel(content, "typescript", mUri);
        }
      }),
    );
  } catch (error) {
    console.error("Error fetching extra models:", error);
    throw error;
  }
}

/**
 * Refresh ATA (Auto Type Acquisition) for TypeScript
 * @param code The code to analyze
 * @param ata The ATA function
 */
export async function refreshAta(
  code: string,
  ata: (options: {
    code: string;
    originToUse: string;
  }) => Promise<Array<{ filePath: string; content: string }>>,
): Promise<void> {
  try {
    const extraLibs: ExtraLib[] = (await ata({ code, originToUse })).map(
      ({ filePath, content }) => ({
        filePath: originToUse + filePath,
        content,
      }),
    );

    console.warn("Setting extra libraries:", { extraLibs });
    typescript.typescriptDefaults.setExtraLibs(extraLibs);

    const mjsFiles = extraLibs.filter((lib) => lib.filePath.endsWith(".mjs"));
    for (const lib of mjsFiles) {
      const myUri = Uri.parse(lib.filePath);
      const existingModel = editor.getModel(myUri);

      if (existingModel) {
        existingModel.setValue(lib.content);
      } else {
        editor.createModel(lib.content, "typescript", myUri);
      }
    }

    typescript.typescriptDefaults.setDiagnosticsOptions({
      noSuggestionDiagnostics: false,
      noSemanticValidation: false,
      noSyntaxValidation: false,
      diagnosticCodesToIgnore: [2691],
    });
    typescript.typescriptDefaults.setEagerModelSync(true);
  } catch (error) {
    console.error("Error refreshing ATA:", error);
    throw new Error(
      `Failed to refresh ATA: ${error instanceof Error ? error.message : "Unknown error"}`,
    );
  }
}

/**
 * Extract imports from code
 * @param code The code to analyze
 */
export function getImports(code: string): string[] {
  const importRegex = /import\s+(?:{[^}]*}|\*\s+as\s+[^;]+|[^;]+)\s+from\s+['"]([^'"]+)['"]/g;
  return [...code.matchAll(importRegex)].map((match) => match[1]!);
}

/**
 * Load CSS for Monaco editor
 * @param version The Monaco editor version (defaults to the imported version)
 */
export async function loadMonacoCss(): Promise<void> {
  const link = document.createElement("link");
  const promiseIsResolved = new Promise<void>((resolve) => {
    link.onload = () => resolve();
  });

  link.rel = "stylesheet";
  link.href = `${originToUse}/start.css`;
  document.head.appendChild(link);

  await promiseIsResolved;
}

/**
 * Handle window resize for responsive editor
 * @param editorInstance The Monaco editor instance
 */
export function setupResponsiveEditor(editorInstance: editor.IStandaloneCodeEditor): () => void {
  const resizeHandler = () => {
    // Debounce resize events
    if (resizeHandler.timeout) {
      clearTimeout(resizeHandler.timeout);
    }

    resizeHandler.timeout = setTimeout(() => {
      editorInstance.layout();

      // Apply different settings based on screen size
      const width = window.innerWidth;

      if (width < 768) {
        // Mobile settings
        editorInstance.updateOptions({
          minimap: { enabled: false },
          wordWrap: "on",
          folding: false,
        });
      } else if (width < 1024) {
        // Tablet settings
        editorInstance.updateOptions({
          minimap: { enabled: true, maxColumn: 60 },
          wordWrap: "on",
          folding: true,
        });
      } else {
        // Desktop settings
        editorInstance.updateOptions({
          minimap: { enabled: true },
          wordWrap: "off",
          folding: true,
        });
      }
    }, 100);
  };

  // Initialize with current size
  resizeHandler();

  // Add event listener
  window.addEventListener("resize", resizeHandler);

  // Return cleanup function
  return () => {
    window.removeEventListener("resize", resizeHandler);
    if (resizeHandler.timeout) {
      clearTimeout(resizeHandler.timeout);
    }
  };
}

// Add timeout property to resizeHandler function
declare global {
  interface Function {
    timeout?: ReturnType<typeof setTimeout>;
  }
}

/**
 * Helper function to extract message text from diagnostic objects
 * @param diagnostic The diagnostic object that may have nested messageText
 */
function getMessageText(diagnostic: { messageText: string | { messageText: string } }): string {
  return typeof diagnostic.messageText === "string"
    ? diagnostic.messageText
    : diagnostic.messageText.messageText;
}

/**
 * Check for TypeScript errors
 * @param model The Monaco editor model
 * @param uri The URI of the file
 */
export async function checkTypeScriptErrors(model: editor.ITextModel, uri: Uri): Promise<void> {
  try {
    console.warn("Running TypeScript check");
    const currentCode = model.getValue();

    // First, check for import statements that might need type definitions
    const imports = getImports(currentCode);

    if (imports.length > 0) {
      console.warn("Detected imports:", imports);
      // Wait a moment for types to be loaded
      await wait(100);
    }

    // Now check for errors
    const typeScriptWorker = await (await typescript.getTypeScriptWorker())(uri);

    const [syntacticDiagnostics, semanticDiagnostics, suggestionDiagnostics] = await Promise.all([
      typeScriptWorker.getSyntacticDiagnostics(uri.toString()),
      typeScriptWorker.getSemanticDiagnostics(uri.toString()),
      typeScriptWorker.getSuggestionDiagnostics(uri.toString()),
    ]);

    // Log syntactic errors
    if (syntacticDiagnostics.length > 0) {
      console.error("Syntactic diagnostics:", syntacticDiagnostics);
    }

    // Check for missing modules and try to resolve them
    const missingModuleErrors = semanticDiagnostics.filter(
      (d: { messageText: string | { messageText: string } }) =>
        getMessageText(d).includes("Cannot find module"),
    );

    if (missingModuleErrors.length > 0) {
      console.warn("Missing module errors detected:", missingModuleErrors);

      // Try another refresh with more aggressive settings
      typescript.typescriptDefaults.setDiagnosticsOptions({
        noSuggestionDiagnostics: false,
        noSemanticValidation: false,
        noSyntaxValidation: false,
      });

      // Re-check after refreshing types
      const updatedSemanticDiagnostics = await typeScriptWorker.getSemanticDiagnostics(
        uri.toString(),
      );

      if (updatedSemanticDiagnostics.length < semanticDiagnostics.length) {
        console.warn("Successfully resolved some type errors");
      } else {
        console.warn(
          "Some modules still missing types:",
          updatedSemanticDiagnostics.filter(
            (d: { messageText: string | { messageText: string } }) =>
              getMessageText(d).includes("Cannot find module"),
          ),
        );
      }
    }

    // Log suggestion diagnostics for debugging
    if (suggestionDiagnostics.length > 0) {
      console.warn("Suggestion diagnostics:", suggestionDiagnostics);
    }
  } catch (error) {
    console.error("Error during TypeScript check:", error);
  }
}

import { replacePreservingWhitespace } from "./diff-utils";
import type { Message, MessageContent, TextPart } from "../../ui/@/lib/interfaces";

interface CodeModification {
  search: string;
  replace: string;
}

const CODE_MODIFICATION_REGEX = /<<<<<<< SEARCH[\s\S]*?=======[\s\S]*?>>>>>>> REPLACE/g;
export const SEARCH_REPLACE_MARKERS = {
  SEARCH_START: "<<<<<<< SEARCH",
  SEPARATOR: "=======",
  REPLACE_END: ">>>>>>> REPLACE",
} as const;

function getTextFromMessageContent(content: MessageContent): string {
  if (typeof content === "string") {
    return content;
  }
  if (Array.isArray(content)) {
    return content
      .filter((part): part is TextPart => part.type === "text")
      .map((part) => part.text)
      .join("");
  }
  return "";
}
/**
 * Adds or updates a message in the messages array
 * @param messages - The current array of messages
 * @param newMessage - The message to add or update
 * @returns A new array of messages with the new message added or updated
 */
export function messagesPush(messages: Message[], newMessage: Message): Message[] {
  if (!newMessage.role) {
    throw new Error("Message must have a role");
  }

  const messagesCopy = JSON.parse(JSON.stringify(messages)) as Message[];
  const newId = newMessage.id || Date.now().toString();

  if (!messagesCopy.length) {
    return [{ ...newMessage, id: newId }];
  }

  const lastMessage = messagesCopy[messagesCopy.length - 1];

  if (lastMessage!.role === newMessage.role && newMessage.role === "assistant") {
    const newMessageText = getTextFromMessageContent(newMessage.content);
    const lastMessageText = getTextFromMessageContent(lastMessage!.content);
    messagesCopy[messagesCopy.length - 1] = {
      ...lastMessage!,
      id: newMessage.id,
      role: lastMessage!.role,
      content: newMessageText.startsWith(lastMessageText)
        ? newMessageText
        : lastMessageText + newMessageText,
    };
    return messagesCopy;
  }

  return [...messagesCopy, { ...newMessage, id: newId }];
}

/**
 * Formats a code modification into the standard format
 */
function formatCodeModification(mod: CodeModification): string {
  return `<<<<<<< SEARCH
${mod.search}
=======
${mod.replace}
>>>>>>> REPLACE`;
}

/**
 * Parses a string that might represent a diff block into a CodeModification object.
 * Handles fully formed diff blocks or content extracted from other contexts (e.g., markdown).
 */
function parseSingleDiffBlock(blockText: string): CodeModification | null {
  const searchMarker = SEARCH_REPLACE_MARKERS.SEARCH_START;
  const separatorMarker = SEARCH_REPLACE_MARKERS.SEPARATOR;
  const replaceMarker = SEARCH_REPLACE_MARKERS.REPLACE_END;

  let searchText = "";
  let replaceText = "";

  // Regex to capture content within a standard diff block
  const fullBlockRegex = new RegExp(
    // Using non-capturing group for optional newline after SEARCH marker
    // Allowing for optional newline before SEPARATOR and REPLACE_END
    `^${searchMarker}(?:\\n)?([\\s\\S]*?)(?:\\n)?${separatorMarker}(?:\\n)?([\\s\\S]*?)(?:\\n)?${replaceMarker}$`,
  );
  const fullBlockMatch = blockText.match(fullBlockRegex);

  if (fullBlockMatch) {
    const searchContent = fullBlockMatch[1];
    const replaceContentRaw = fullBlockMatch[2];

    // If the raw replace content itself contains more separators,
    // take only the part before the first such internal separator.
    const replaceParts = replaceContentRaw?.split(separatorMarker);
    const finalReplaceContent = replaceParts?.[0];

    const searchText = searchContent?.trim() ?? "";
    const replaceText = finalReplaceContent?.trim() ?? "";

    // Search text cannot be empty, replace text can be empty (for deletions)
    if (searchText) {
      return { search: searchText, replace: replaceText };
    }
  } else {
    // Fallback for content that might be just the inner parts of a diff,
    // or a malformed block. This is more lenient.
    // This handles cases where the content is like "SEARCH_CONTENT ======= REPLACE_CONTENT"
    // potentially with extra "=======" and content afterwards, which should be ignored.
    const parts = blockText.split(separatorMarker);
    if (parts.length >= 2) {
      // We need at least one separator to define search and replace parts
      // Trim the part first, then check for and remove markers.
      let tempSearch = parts[0]!.trim();
      if (tempSearch.startsWith(searchMarker)) {
        // Remove marker and then trim any leading whitespace from the actual search content.
        tempSearch = tempSearch.substring(searchMarker.length).trimStart();
      }
      searchText = tempSearch;

      // Replace text is the content of the second part (parts[1])
      // Any subsequent parts (from further separators) are ignored.
      // Trim the part first, then check for and remove markers.
      let tempReplace = parts[1]?.trim() ?? "";
      if (tempReplace.endsWith(replaceMarker)) {
        // Remove marker and then trim any trailing whitespace from the actual replace content.
        tempReplace = tempReplace.substring(0, tempReplace.length - replaceMarker.length).trimEnd();
      }
      replaceText = tempReplace;

      // Only return a valid object if searchText is not empty. Replace text can be empty (for deletions).
      if (searchText) {
        return { search: searchText, replace: replaceText };
      }
    }
  }
  return null;
}

/**
 * Extracts code modifications from a response string.
 * AI responses might contain modifications in two primary ways:
 * 1. Standard diff format: Directly embedded `<<<<<<< SEARCH ... ======= ... >>>>>>> REPLACE` blocks.
 * 2. Markdown code blocks: Diff content wrapped within triple backticks (e.g., ```diff ... ```).
 * This function tries to find and parse both, prioritizing direct matches and then
 * attempting to parse content within markdown code blocks.
 * It uses a Set to ensure that identical modification blocks are not added multiple times
 * if they happen to appear in both formats or are repeated.
 */
export const extractCodeModification = (response: string): string[] => {
  const modifications: string[] = [];
  const seenModifications = new Set<string>(); // To avoid duplicates

  // Strategy 1: Find standard diff blocks directly in the response
  const directMatches = response.match(CODE_MODIFICATION_REGEX) || [];
  for (const match of directMatches) {
    // Parse the direct match to get a canonical form for the 'seen' set
    const parsedDirectMatch = parseSingleDiffBlock(match);
    if (parsedDirectMatch) {
      const canonicalDirectMatch = formatCodeModification(parsedDirectMatch);
      if (!seenModifications.has(canonicalDirectMatch)) {
        modifications.push(match); // Push the original match
        seenModifications.add(canonicalDirectMatch); // Add canonical form to seen set
      }
    } else {
      // Fallback: if parsing fails (shouldn't happen for valid CODE_MODIFICATION_REGEX match),
      // add the raw match to avoid missing it, though de-duplication might be imperfect.
      if (!seenModifications.has(match)) {
        modifications.push(match);
        seenModifications.add(match);
      }
    }
  }

  // Strategy 2: Find markdown code blocks and try to parse their content
  // Regex to capture content within ``` ```, optionally with a language tag.
  // Allows for optional whitespace before the closing ``` via \s*
  const codeBlockRegex = /```(?:[a-zA-Z0-9\-_]+)?\n([\s\S]*?)\n\s*```/g;
  let markdownMatch;
  while ((markdownMatch = codeBlockRegex.exec(response)) !== null) {
    const blockContent = markdownMatch[1]?.trim(); // Content within the backticks
    if (typeof blockContent === "string") {
      const parsedDiffObject = parseSingleDiffBlock(blockContent);
      if (parsedDiffObject) {
        const formattedModString = formatCodeModification(parsedDiffObject);
        if (!seenModifications.has(formattedModString)) {
          modifications.push(formattedModString);
          seenModifications.add(formattedModString);
        }
      }
    }
  }

  return modifications.sort();
};

/**
 * Parses a single, well-formed code modification string (e.g., one complete SEARCH/REPLACE block)
 * into its constituent search and replace parts.
 * This function expects the input `mod` to be a string that starts with `<<<<<<< SEARCH`
 * and ends with `>>>>>>> REPLACE`, containing one `=======` separator.
 * It trims whitespace from the extracted search and replace contents.
 */
function parseModification(mod: string): CodeModification | null {
  const parts = mod
    .replace(/<<<<<<< SEARCH|>>>>>>> REPLACE/g, "")
    .split(SEARCH_REPLACE_MARKERS.SEPARATOR);

  if (parts.length === 2) {
    const search = parts[0]!.trim();
    const replace = parts[1]?.trim() ?? "";

    return {
      search,
      replace,
    };
  }

  if (process.env.NODE_ENV !== "test") {
    console.warn("parseModification - Failed to parse modification, parts count:", parts.length);
  }
  return null;
}

/**
 * Loads messages from localStorage for a given code space
 */
export const loadMessages = (codeSpace: string): Message[] => {
  if (!codeSpace) {
    throw new Error("Code space must be provided");
  }

  const key = `chatMessages-${codeSpace}`;
  let rawMessages: Message[] = [];

  try {
    rawMessages = JSON.parse(localStorage.getItem(key) || "[]");
  } catch (error) {
    console.error("Error loading messages:", error);
    return [];
  }

  const validMessages = rawMessages.filter((m) => !!m.role);

  return validMessages.reduce((acc, current, index) => {
    if (index === 0 || current.role !== validMessages[index - 1]!.role) {
      acc.push(current);
    }
    return acc;
  }, [] as Message[]);
};

/**
 * Applies code modifications to the current code
 */
function applyCodeModifications(code: string, modifications: string[], applyAll = true): string {
  // This function iterates through a list of modification strings (each being a
  // complete SEARCH/REPLACE block). For each block, it parses it into
  // search/replace parts and then applies the replacement to the `code`.
  // The `replacePreservingWhitespace` utility is used for the actual replacement,
  // which attempts to be smart about whitespace.
  // If `applyAll` is false, only the first modification in the list is applied.
  // This is useful if the AI provides multiple alternative modifications and only one should be tried.

  try {
    let result = code;
    const modsToApply = applyAll ? modifications : modifications.slice(0, 1);

    modsToApply.forEach((mod, index) => {
      const parsed = parseModification(mod);

      if (parsed) {
        result = replacePreservingWhitespace(result, parsed.search, parsed.replace);
      } else {
        if (process.env.NODE_ENV !== "test") {
          console.warn(
            `applyCodeModifications - Failed to parse modification ${
              index + 1
            }. Modification string: "${mod.substring(0, 100)}..."`,
          );
        }
      }
    });

    return result;
  } catch (error) {
    // This catch block is a safety net. Errors during parsing or replacement
    // should ideally be handled more gracefully, but if an unexpected error occurs,
    // we log it and return the original code to prevent corruption.
    console.error("Error applying code modifications:", error);
    console.error("Error details:", error instanceof Error ? error.message : String(error));
    console.error("Error stack:", error instanceof Error ? error.stack : "No stack trace");
    return code;
  }
}

/**
 * Updates code by applying all search/replace modifications
 */
export const updateSearchReplace = (instructions: string, codeNow: string): string => {
  const modifications = extractCodeModification(instructions);

  if (modifications.length === 0) {
    if (process.env.NODE_ENV !== "test") {
      console.warn("updateSearchReplace - No modifications extracted from instructions");
    }
    return codeNow;
  }

  // Validate each modification can be parsed
  modifications.forEach((mod, index) => {
    const parsed = parseModification(mod);
    if (!parsed) {
      if (process.env.NODE_ENV !== "test") {
        console.warn(`updateSearchReplace - Failed to parse modification ${index + 1}`);
      }
    }
  });

  return applyCodeModifications(codeNow, modifications, true);
};

/**
 * Updates code by applying only the first search/replace modification
 */
export const replaceFirstCodeMod = (instructions: string, codeNow: string): string => {
  const modifications = extractCodeModification(instructions);
  return applyCodeModifications(codeNow, modifications, false);
};

