// Utility Functions
function hasKnownExtension(path: string): boolean {
  const lastDotIndex = path.lastIndexOf(".");
  return lastDotIndex !== -1 && FILE_EXTENSIONS.has(path.slice(lastDotIndex));
}

function isWorkerFile(path: string): boolean {
  return WORKER_PATTERNS.some((pattern) => path.includes(pattern));
}

function isComponentFile(path: string): boolean {
  return COMPONENT_PATTERNS.some((pattern) => path.includes(pattern));
}

function processQueryAndHash(path: string): {
  basePath: string;
  query: string;
  hash: string;
} {
  const [pathPart, hash] = path.split("#");
  const [basePath, query] = (pathPart || "").split("?");

  return {
    basePath: basePath || "",
    query: query ? `?${query}` : "",
    hash: hash ? `#${hash}` : "",
  };
}

function shouldTransformPath(path: string): boolean {
  return (
    !path.includes("?bundle=true") &&
    !path.startsWith("data:") &&
    !path.startsWith("http://") &&
    !path.startsWith("https://") &&
    !path.startsWith("/live/")
  );
}

function getExportsString(match: string): string {
  const namedImports = match.match(/\{([^}]*)\}/s)?.[1];
  return (
    namedImports
      ?.split(",")
      .map((s) => s.trim().split(" as ")[0])
      .filter(Boolean)
      .join(",") || ""
  );
}

function sortExports(param: string): string {
  return param.split(",").filter(Boolean).sort().join(",");
}

function parseNamedExports(match: string): Array<{ name: string; alias?: string }> {
  const namedImports = match.match(/\{([^}]*)\}/s)?.[1];
  if (!namedImports) return [];
  return namedImports
    .split(",")
    .map((s) => s.trim())
    .filter(Boolean)
    .map((s) => {
      const parts = s.split(/\s+as\s+/);
      return parts.length > 1 ? { name: parts[0]!, alias: parts[1]! } : { name: parts[0]! };
    });
}

function splitLargeImport(
  match: string,
  importPath: string,
  keyword: "import" | "export",
  importMapImports: ImportMap["imports"] = importMap.imports,
): string | null {
  const exports = parseNamedExports(match);
  if (exports.length <= MAX_EXPORTS_PER_URL) return null;

  // Detect default import (only for import statements)
  let defaultImport: string | undefined;
  if (keyword === "import") {
    const defaultMatch = match.match(/import\s+([A-Za-z_$][\w$]*)\s*,\s*\{/);
    if (defaultMatch) defaultImport = defaultMatch[1];
  }

  // Detect indentation from the original match
  const indentMatch = match.match(/^(\s*)/);
  const indent = indentMatch ? indentMatch[1] : "";

  const chunks: Array<{ name: string; alias?: string }>[] = [];
  for (let i = 0; i < exports.length; i += MAX_EXPORTS_PER_URL) {
    chunks.push(exports.slice(i, i + MAX_EXPORTS_PER_URL));
  }

  return chunks
    .map((chunk, idx) => {
      const specifiers = chunk
        .map((e) => (e.alias ? `${e.name} as ${e.alias}` : e.name))
        .join(", ");
      const exportsParam = sortExports(chunk.map((e) => e.name).join(","));
      const mappedPath = getMappedPath(importPath, exportsParam, true, importMapImports);

      if (keyword === "export") {
        return `${indent}export { ${specifiers} } from "${mappedPath}";`;
      }

      // First chunk gets default import if present
      if (idx === 0 && defaultImport) {
        return `${indent}import ${defaultImport}, { ${specifiers} } from "${mappedPath}";`;
      }
      return `${indent}import { ${specifiers} } from "${mappedPath}";`;
    })
    .join("\n");
}

function getMappedPath(
  path: string,
  exportsParam = "",
  hasFromClause = false,
  importMapImports: ImportMap["imports"] = importMap.imports,
): string {
  const { basePath, query, hash } = processQueryAndHash(path);

  // Early returns for complex or special paths
  if (path.includes("${") || path.includes("+")) return path;

  // Exact match in import map
  if (importMapImports[basePath]) return path;

  // Check for prefix matches in import map (e.g., @/components/ui/)
  for (const [prefix, mappedPrefix] of Object.entries(importMapImports)) {
    if (basePath.startsWith(prefix) && prefix.endsWith("/")) {
      const restPath = basePath.slice(prefix.length);
      return mappedPrefix + restPath + query + hash;
    }
  }

  // Handle worker files
  if (isWorkerFile(basePath)) {
    const baseWithoutExt = hasKnownExtension(basePath)
      ? basePath.substring(0, basePath.lastIndexOf("."))
      : basePath;
    const extension = hasFromClause ? ".mjs" : ".js";
    const resultPath = baseWithoutExt + extension;

    return !resultPath.startsWith(".") && !resultPath.startsWith("/")
      ? `/${resultPath}`
      : resultPath;
  }

  // Handle component and special files
  if (isComponentFile(basePath)) {
    const baseWithoutExt = hasKnownExtension(basePath)
      ? basePath.substring(0, basePath.lastIndexOf("."))
      : basePath;
    const extension = ".mjs";
    const resultPath = baseWithoutExt + extension;

    return !resultPath.startsWith(".") && !resultPath.startsWith("/")
      ? `/${resultPath}`
      : resultPath;
  }

  // Handle directory imports and paths without extension
  if (!hasKnownExtension(basePath) && (basePath.startsWith(".") || basePath.startsWith("/"))) {
    const extension = basePath.endsWith("/") ? "index.mjs" : ".mjs";
    return `${basePath}${extension}${query}${hash}`;
  }

  // Preserve live and absolute URLs
  if (basePath.startsWith("/live/") || /^https?:\/\//.test(basePath)) {
    return path;
  }

  // Handle non-relative paths — resolve directly to ESM CDN
  if (!basePath.startsWith(".") && !basePath.startsWith("/")) {
    const params = ["bundle=true", `external=${EXTERNAL_DEPENDENCIES.join(",")}`, DEPS_PARAM];

    if (exportsParam) params.push(`exports=${sortExports(exportsParam)}`);

    return `${ESM_CDN}/${basePath}?${params.join("&")}${query}${hash}`;
  }

  return `${basePath}${query}${hash}`;
}

export function importMapReplace(code: string): string {
  // Prevent double processing
  if (code.includes("/** importMapReplace */") || code.includes("/* esm.sh")) {
    return code;
  }

  // Normalize line endings
  code = code.replace(/\r\n/g, "\n");

  // Helper function for replacing imports
  const replaceImport = (match: string, pre: string, q1: string, path: string, q2: string) => {
    if (!shouldTransformPath(path)) return match;
    const fullPath = getMappedPath(path, "", false);
    return `${pre}${q1}${fullPath}${q2}`;
  };

  // Replace simple imports
  code = code.replace(/^(\s*import\s+)(['"])([^'"]+)(['"];\s*$)/gm, replaceImport);

  // Replace imports with from clause
  code = code.replace(/^(\s*import\s+[\s\S]*?from\s+['"])([^'"]+)(['"];?)/gm, (match) => {
    if (match.includes("/** importMapReplace */")) return match;

    const pathMatch = match.match(/['"]([^'"]+)['"]/);
    if (!pathMatch) return match;

    const importPath = pathMatch[1];
    if (!importPath || !shouldTransformPath(importPath)) return match;

    // Try splitting large imports
    const split = splitLargeImport(match, importPath, "import");
    if (split) return split;

    const exportsParam = getExportsString(match);
    const mappedPath = getMappedPath(importPath!, exportsParam, true);
    return match.replace(/['"][^'"]+['"]/, `"${mappedPath}"`);
  });

  // Replace export from clauses
  code = code.replace(/^(\s*export\s+[\s\S]*?from\s+['"])([^'"]+)(['"];?)/gm, (match) => {
    if (match.includes("/** importMapReplace */")) return match;

    const pathMatch = match.match(/['"]([^'"]+)['"]/);
    if (!pathMatch) return match;

    const exportPath = pathMatch[1];
    if (!exportPath || !shouldTransformPath(exportPath)) return match;

    // Try splitting large exports
    const split = splitLargeImport(match, exportPath, "export");
    if (split) return split;

    const exportsParam = getExportsString(match);
    const mappedPath = getMappedPath(exportPath!, exportsParam, true);
    return match.replace(/['"][^'"]+['"]/, `"${mappedPath}"`);
  });

  // Replace dynamic imports
  code = code.replace(/(\bimport\s*\(\s*['"])([^'"]+)(['"]\s*\))/g, (match) => {
    const pathMatch = match.match(/['"]([^'"]+)['"]/);
    if (!pathMatch) return match;

    const importPath = pathMatch[1];
    if (!importPath || !shouldTransformPath(importPath)) return match;

    const mappedPath = getMappedPath(importPath!, "", true);
    return match.replace(/['"][^'"]+['"]/, `"${mappedPath}"`);
  });

  return `/** importMapReplace */\n${code}`;
}

export default importMap;

/**
 * LRU Cache Core Implementation
 * A high-performance, feature-rich LRU (Least Recently Used) cache.
 */

import { AC } from "./polyfills";
import { getUintArray, isPosInt, Stack, type StackLike, ZeroArray } from "./stack";
import type {
  BackgroundFetch,
  DisposeTask,
  Index,
  LRUCacheCount,
  LRUCacheDisposer,
  LRUCacheDisposeReason,
  LRUCacheEntry,
  LRUCacheFetcher,
  LRUCacheFetchOptions,
  LRUCacheGetOptions,
  LRUCacheHasOptions,
  LRUCacheInserter,
  LRUCacheMemoizer,
  LRUCacheMemoizerOptions,
  LRUCacheMemoOptions,
  LRUCacheMilliseconds,
  LRUCacheOptions,
  LRUCachePeekOptions,
  LRUCacheSetOptions,
  LRUCacheSize,
  LRUCacheSizeCalculator,
  LRUCacheStatus,
  NumberArray,
} from "./types";
import { emitSimplifiedWarning, perf } from "./utils";

export class LRUCache<K extends object | string | number, V extends object, FC = unknown> {
  readonly #max: LRUCacheCount;
  readonly #maxSize: LRUCacheSize;
  readonly #dispose?: LRUCacheDisposer<K, V>;
  readonly #onInsert?: LRUCacheInserter<K, V>;
  readonly #disposeAfter: LRUCacheDisposer<K, V> | undefined;
  readonly #fetchMethod: LRUCacheFetcher<K, V, FC> | undefined;
  readonly #memoMethod: LRUCacheMemoizer<K, V, FC> | undefined;

  ttl: LRUCacheMilliseconds;
  ttlResolution: LRUCacheMilliseconds;
  ttlAutopurge: boolean;
  updateAgeOnGet: boolean;
  updateAgeOnHas: boolean;
  allowStale: boolean;
  noDisposeOnSet: boolean;
  noUpdateTTL: boolean;
  maxEntrySize: LRUCacheSize;
  sizeCalculation: LRUCacheSizeCalculator<K, V> | undefined;
  noDeleteOnFetchRejection: boolean;
  noDeleteOnStaleGet: boolean;
  allowStaleOnFetchAbort: boolean;
  allowStaleOnFetchRejection: boolean;
  ignoreFetchAbort: boolean;

  #size: LRUCacheCount;
  #calculatedSize: LRUCacheSize;
  #keyMap: Map<K, Index>;
  #keyList: Array<K | undefined>;
  #valList: Array<V | BackgroundFetch<V> | undefined>;
  #next: NumberArray;
  #prev: NumberArray;
  #head: Index;
  #tail: Index;
  #free: StackLike;
  #disposed: Array<DisposeTask<K, V>> | undefined;
  #sizes?: ZeroArray;
  #starts?: ZeroArray;
  #ttls?: ZeroArray;

  #hasDispose: boolean;
  #hasFetchMethod: boolean;
  #hasDisposeAfter: boolean;
  #hasOnInsert: boolean;

  static unsafeExposeInternals<Ki extends object, Vi extends object, FCi = unknown>(
    c: LRUCache<Ki, Vi, FCi>,
  ) {
    return {
      starts: c.#starts,
      ttls: c.#ttls,
      sizes: c.#sizes,
      keyMap: c.#keyMap as Map<Ki, number>,
      keyList: c.#keyList,
      valList: c.#valList,
      next: c.#next,
      prev: c.#prev,
      get head() {
        return c.#head;
      },
      get tail() {
        return c.#tail;
      },
      free: c.#free,
      isBackgroundFetch: (p: unknown) => c.#isBackgroundFetch(p),
      backgroundFetch: (
        k: Ki,
        index: number | undefined,
        options: LRUCacheFetchOptions<Ki, Vi, FCi>,
        context: unknown,
      ): BackgroundFetch<Vi> =>
        c.#backgroundFetch(k, index as Index | undefined, options, context as FCi),
      moveToTail: (index: number): void => c.#moveToTail(index as Index),
      indexes: (options?: { allowStale: boolean }) => c.#indexes(options),
      rindexes: (options?: { allowStale: boolean }) => c.#rindexes(options),
      isStale: (index: number | undefined) => c.#isStale(index as Index),
    };
  }

  get max(): LRUCacheCount {
    return this.#max;
  }
  get maxSize(): LRUCacheCount {
    return this.#maxSize;
  }
  get calculatedSize(): LRUCacheSize {
    return this.#calculatedSize;
  }
  get size(): LRUCacheCount {
    return this.#size;
  }
  get fetchMethod(): LRUCacheFetcher<K, V, FC> | undefined {
    return this.#fetchMethod;
  }
  get memoMethod(): LRUCacheMemoizer<K, V, FC> | undefined {
    return this.#memoMethod;
  }
  get dispose() {
    return this.#dispose;
  }
  get onInsert() {
    return this.#onInsert;
  }
  get disposeAfter() {
    return this.#disposeAfter;
  }

  constructor(options: LRUCacheOptions<K, V, FC> | LRUCache<K, V, FC>) {
    const {
      max = 0,
      ttl,
      ttlResolution = 1,
      ttlAutopurge,
      updateAgeOnGet,
      updateAgeOnHas,
      allowStale,
      dispose,
      onInsert,
      disposeAfter,
      noDisposeOnSet,
      noUpdateTTL,
      maxSize = 0,
      maxEntrySize = 0,
      sizeCalculation,
      fetchMethod,
      memoMethod,
      noDeleteOnFetchRejection,
      noDeleteOnStaleGet,
      allowStaleOnFetchRejection,
      allowStaleOnFetchAbort,
      ignoreFetchAbort,
    } = options;

    if (max !== 0 && !isPosInt(max)) {
      throw new TypeError("max option must be a nonnegative integer");
    }

    const ResolvedUintArray = max ? getUintArray(max) : Array;
    if (!ResolvedUintArray) {
      throw new Error("invalid max value: " + max);
    }

    this.#max = max;
    this.#maxSize = maxSize;
    this.maxEntrySize = maxEntrySize || this.#maxSize;
    this.sizeCalculation = sizeCalculation || undefined;
    if (this.sizeCalculation) {
      if (!this.#maxSize && !this.maxEntrySize) {
        throw new TypeError("cannot set sizeCalculation without setting maxSize or maxEntrySize");
      }
      if (typeof this.sizeCalculation !== "function") {
        throw new TypeError("sizeCalculation set to non-function");
      }
    }

    if (memoMethod !== undefined && typeof memoMethod !== "function") {
      throw new TypeError("memoMethod must be a function if defined");
    }
    this.#memoMethod = memoMethod || undefined;

    if (fetchMethod !== undefined && typeof fetchMethod !== "function") {
      throw new TypeError("fetchMethod must be a function if specified");
    }
    this.#fetchMethod = fetchMethod || undefined;
    this.#hasFetchMethod = !!fetchMethod;

    this.#keyMap = new Map();
    this.#keyList = new Array(max).fill(undefined);
    this.#valList = new Array(max).fill(undefined);
    this.#next = new ResolvedUintArray(max);
    this.#prev = new ResolvedUintArray(max);
    this.#head = 0 as Index;
    this.#tail = 0 as Index;
    this.#free = Stack.create(max);
    this.#size = 0;
    this.#calculatedSize = 0;

    if (typeof dispose === "function") {
      this.#dispose = dispose;
    }
    if (typeof onInsert === "function") {
      this.#onInsert = onInsert;
    }
    if (typeof disposeAfter === "function") {
      this.#disposeAfter = disposeAfter;
      this.#disposed = [];
    } else {
      this.#disposeAfter = undefined;
      this.#disposed = undefined;
    }
    this.#hasDispose = !!this.#dispose;
    this.#hasOnInsert = !!this.#onInsert;
    this.#hasDisposeAfter = !!this.#disposeAfter;

    this.noDisposeOnSet = !!noDisposeOnSet;
    this.noUpdateTTL = !!noUpdateTTL;
    this.noDeleteOnFetchRejection = !!noDeleteOnFetchRejection;
    this.allowStaleOnFetchRejection = !!allowStaleOnFetchRejection;
    this.allowStaleOnFetchAbort = !!allowStaleOnFetchAbort;
    this.ignoreFetchAbort = !!ignoreFetchAbort;

    if (this.maxEntrySize !== 0) {
      if (this.#maxSize !== 0) {
        if (!isPosInt(this.#maxSize)) {
          throw new TypeError("maxSize must be a positive integer if specified");
        }
      }
      if (!isPosInt(this.maxEntrySize)) {
        throw new TypeError("maxEntrySize must be a positive integer if specified");
      }
      this.#initializeSizeTracking();
    }

    this.allowStale = !!allowStale;
    this.noDeleteOnStaleGet = !!noDeleteOnStaleGet;
    this.updateAgeOnGet = !!updateAgeOnGet;
    this.updateAgeOnHas = !!updateAgeOnHas;
    this.ttlResolution = isPosInt(ttlResolution) || ttlResolution === 0 ? ttlResolution : 1;
    this.ttlAutopurge = !!ttlAutopurge;
    this.ttl = ttl || 0;
    if (this.ttl) {
      if (!isPosInt(this.ttl)) {
        throw new TypeError("ttl must be a positive integer if specified");
      }
      this.#initializeTTLTracking();
    }

    if (this.#max === 0 && this.ttl === 0 && this.#maxSize === 0) {
      throw new TypeError("At least one of max, maxSize, or ttl is required");
    }
    if (!this.ttlAutopurge && !this.#max && !this.#maxSize) {
      emitSimplifiedWarning(
        "TTL caching without ttlAutopurge, max, or maxSize can " +
          "result in unbounded memory consumption.",
        "UNBOUNDED_CACHE",
      );
    }
  }

  getRemainingTTL(key: K) {
    return this.#keyMap.has(key) ? Infinity : 0;
  }

  #initializeTTLTracking() {
    const ttls = new ZeroArray(this.#max);
    const starts = new ZeroArray(this.#max);
    this.#ttls = ttls;
    this.#starts = starts;

    this.#setItemTTL = (index, ttl, start = perf.now()) => {
      starts[index] = ttl !== 0 ? start : 0;
      ttls[index] = ttl;
      if (ttl !== 0 && this.ttlAutopurge) {
        const t = setTimeout(() => {
          if (this.#isStale(index)) {
            this.#delete(this.#keyList[index] as K, "expire");
          }
        }, ttl + 1);
        /* c8 ignore start */
        if (t.unref) {
          t.unref();
        }
        /* c8 ignore stop */
      }
    };

    this.#updateItemAge = (index) => {
      starts[index] = ttls[index] !== 0 ? perf.now() : 0;
    };

    this.#statusTTL = (status, index) => {
      if (ttls[index]) {
        const ttl = ttls[index];
        const start = starts[index];
        /* c8 ignore next */
        if (!ttl || !start) return;
        status.ttl = ttl;
        status.start = start;
        status.now = cachedNow || getNow();
        const age = status.now - start;
        status.remainingTTL = ttl - age;
      }
    };

    let cachedNow = 0;
    const getNow = () => {
      const n = perf.now();
      if (this.ttlResolution > 0) {
        cachedNow = n;
        const t = setTimeout(() => (cachedNow = 0), this.ttlResolution);
        /* c8 ignore start */
        if (t.unref) {
          t.unref();
        }
        /* c8 ignore stop */
      }
      return n;
    };

    this.getRemainingTTL = (key) => {
      const index = this.#keyMap.get(key);
      if (index === undefined) {
        return 0;
      }
      const ttl = ttls[index];
      const start = starts[index];
      if (!ttl || !start) {
        return Infinity;
      }
      const age = (cachedNow || getNow()) - start;
      return ttl - age;
    };

    this.#isStale = (index) => {
      const s = starts[index];
      const t = ttls[index];
      return !!t && !!s && (cachedNow || getNow()) - s > t;
    };
  }

  #updateItemAge: (index: Index) => void = () => {};
  #statusTTL: (status: LRUCacheStatus<V>, index: Index) => void = () => {};
  #setItemTTL: (index: Index, ttl: LRUCacheMilliseconds, start?: LRUCacheMilliseconds) => void =
    () => {};

  #isStale: (index: Index) => boolean = () => false;

  #initializeSizeTracking() {
    const sizes = new ZeroArray(this.#max);
    this.#calculatedSize = 0;
    this.#sizes = sizes;
    this.#removeItemSize = (index) => {
      this.#calculatedSize -= sizes[index] as number;
      sizes[index] = 0;
    };
    this.#requireSize = (k, v, size, sizeCalculation) => {
      if (this.#isBackgroundFetch(v)) {
        return 0;
      }
      if (!isPosInt(size)) {
        if (sizeCalculation) {
          if (typeof sizeCalculation !== "function") {
            throw new TypeError("sizeCalculation must be a function");
          }
          size = sizeCalculation(v, k);
          if (!isPosInt(size)) {
            throw new TypeError("sizeCalculation return invalid (expect positive integer)");
          }
        } else {
          throw new TypeError(
            "invalid size value (must be positive integer). " +
              "When maxSize or maxEntrySize is used, sizeCalculation " +
              "or size must be set.",
          );
        }
      }
      return size;
    };
    this.#addItemSize = (index: Index, size: LRUCacheSize, status?: LRUCacheStatus<V>) => {
      sizes[index] = size;
      if (this.#maxSize) {
        const maxSize = this.#maxSize - (sizes[index] as number);
        while (this.#calculatedSize > maxSize) {
          this.#evict(true);
        }
      }
      this.#calculatedSize += sizes[index] as number;
      if (status) {
        status.entrySize = size;
        status.totalCalculatedSize = this.#calculatedSize;
      }
    };
  }

  #removeItemSize: (index: Index) => void = (_i) => {};
  #addItemSize: (index: Index, size: LRUCacheSize, status?: LRUCacheStatus<V>) => void = (
    _i,
    _s,
    _st,
  ) => {};
  #requireSize: (
    k: K,
    v: V | BackgroundFetch<V>,
    size?: LRUCacheSize,
    sizeCalculation?: LRUCacheSizeCalculator<K, V>,
  ) => LRUCacheSize = (
    _k: K,
    _v: V | BackgroundFetch<V>,
    size?: LRUCacheSize,
    sizeCalculation?: LRUCacheSizeCalculator<K, V>,
  ) => {
    if (size || sizeCalculation) {
      throw new TypeError("cannot set size without setting maxSize or maxEntrySize on cache");
    }
    return 0;
  };

  *#indexes({ allowStale = this.allowStale } = {}) {
    if (this.#size) {
      for (let i = this.#tail; true; ) {
        if (!this.#isValidIndex(i)) {
          break;
        }
        if (allowStale || !this.#isStale(i)) {
          yield i;
        }
        if (i === this.#head) {
          break;
        } else {
          i = this.#prev[i] as Index;
        }
      }
    }
  }

  *#rindexes({ allowStale = this.allowStale } = {}) {
    if (this.#size) {
      for (let i = this.#head; true; ) {
        if (!this.#isValidIndex(i)) {
          break;
        }
        if (allowStale || !this.#isStale(i)) {
          yield i;
        }
        if (i === this.#tail) {
          break;
        } else {
          i = this.#next[i] as Index;
        }
      }
    }
  }

  #isValidIndex(index: Index) {
    return index !== undefined && this.#keyMap.get(this.#keyList[index] as K) === index;
  }

  *entries() {
    for (const i of this.#indexes()) {
      if (
        this.#valList[i] !== undefined &&
        this.#keyList[i] !== undefined &&
        !this.#isBackgroundFetch(this.#valList[i])
      ) {
        yield [this.#keyList[i], this.#valList[i]] as [K, V];
      }
    }
  }

  *rentries() {
    for (const i of this.#rindexes()) {
      if (
        this.#valList[i] !== undefined &&
        this.#keyList[i] !== undefined &&
        !this.#isBackgroundFetch(this.#valList[i])
      ) {
        yield [this.#keyList[i], this.#valList[i]] as [K, V];
      }
    }
  }

  *keys() {
    for (const i of this.#indexes()) {
      const k = this.#keyList[i];
      if (k !== undefined && !this.#isBackgroundFetch(this.#valList[i])) {
        yield k;
      }
    }
  }

  *rkeys() {
    for (const i of this.#rindexes()) {
      const k = this.#keyList[i];
      if (k !== undefined && !this.#isBackgroundFetch(this.#valList[i])) {
        yield k;
      }
    }
  }

  *values() {
    for (const i of this.#indexes()) {
      const v = this.#valList[i];
      if (v !== undefined && !this.#isBackgroundFetch(this.#valList[i])) {
        yield this.#valList[i] as V;
      }
    }
  }

  *rvalues() {
    for (const i of this.#rindexes()) {
      const v = this.#valList[i];
      if (v !== undefined && !this.#isBackgroundFetch(this.#valList[i])) {
        yield this.#valList[i] as V;
      }
    }
  }

  [Symbol.iterator]() {
    return this.entries();
  }

  [Symbol.toStringTag] = "LRUCache";

  find(
    fn: (v: V, k: K, self: LRUCache<K, V, FC>) => boolean,
    getOptions: LRUCacheGetOptions<K, V, FC> = {},
  ): V | undefined {
    for (const i of this.#indexes()) {
      const v = this.#valList[i];
      const value = this.#isBackgroundFetch(v) ? v.__staleWhileFetching : v;
      if (value === undefined) continue;
      if (fn(value, this.#keyList[i] as K, this)) {
        return this.get(this.#keyList[i] as K, getOptions);
      }
    }
    return undefined;
  }

  forEach(fn: (v: V, k: K, self: LRUCache<K, V, FC>) => void, thisp: object = this) {
    for (const i of this.#indexes()) {
      const v = this.#valList[i];
      const value = this.#isBackgroundFetch(v) ? v.__staleWhileFetching : v;
      if (value === undefined) continue;
      fn.call(thisp, value, this.#keyList[i] as K, this);
    }
  }

  rforEach(fn: (v: V, k: K, self: LRUCache<K, V, FC>) => void, thisp: object = this) {
    for (const i of this.#rindexes()) {
      const v = this.#valList[i];
      const value = this.#isBackgroundFetch(v) ? v.__staleWhileFetching : v;
      if (value === undefined) continue;
      fn.call(thisp, value, this.#keyList[i] as K, this);
    }
  }

  purgeStale() {
    let deleted = false;
    for (const i of this.#rindexes({ allowStale: true })) {
      if (this.#isStale(i)) {
        this.#delete(this.#keyList[i] as K, "expire");
        deleted = true;
      }
    }
    return deleted;
  }

  info(key: K): LRUCacheEntry<V> | undefined {
    const i = this.#keyMap.get(key);
    if (i === undefined) return undefined;
    const v = this.#valList[i];
    const value: V | undefined = this.#isBackgroundFetch(v) ? v.__staleWhileFetching : (v as V);
    if (value === undefined) return undefined;
    const entry: LRUCacheEntry<V> = { value };
    if (this.#ttls && this.#starts) {
      const ttl = this.#ttls[i];
      const start = this.#starts[i];
      if (ttl && start) {
        const remain = ttl - (perf.now() - start);
        entry.ttl = remain;
        entry.start = Date.now();
      }
    }
    if (this.#sizes) {
      entry.size = this.#sizes[i] || 0;
    }
    return entry;
  }

  dump() {
    const arr: Array<[K, LRUCacheEntry<V>]> = [];
    for (const i of this.#indexes({ allowStale: true })) {
      const key = this.#keyList[i];
      const v = this.#valList[i];
      const value: V | undefined = this.#isBackgroundFetch(v) ? v.__staleWhileFetching : (v as V);
      if (value === undefined || key === undefined) continue;
      const entry: LRUCacheEntry<V> = { value };
      if (this.#ttls && this.#starts) {
        entry.ttl = this.#ttls[i] || 0;
        const age = perf.now() - (this.#starts[i] || 0);
        entry.start = Math.floor(Date.now() - age);
      }
      if (this.#sizes) {
        entry.size = this.#sizes[i] || 0;
      }
      arr.unshift([key, entry]);
    }
    return arr;
  }

  load(arr: Array<[K, LRUCacheEntry<V>]>) {
    this.clear();
    for (const [key, entry] of arr) {
      if (entry.start) {
        const age = Date.now() - entry.start;
        entry.start = perf.now() - age;
      }
      this.set(key, entry.value, entry);
    }
  }

  set(k: K, v: V | BackgroundFetch<V> | undefined, setOptions: LRUCacheSetOptions<K, V, FC> = {}) {
    if (v === undefined) {
      this.delete(k);
      return this;
    }
    const {
      ttl = this.ttl,
      start,
      noDisposeOnSet = this.noDisposeOnSet,
      sizeCalculation = this.sizeCalculation,
      status,
    } = setOptions;
    let { noUpdateTTL = this.noUpdateTTL } = setOptions;

    const size = this.#requireSize(k, v, setOptions.size || 0, sizeCalculation);
    if (this.maxEntrySize && size > this.maxEntrySize) {
      if (status) {
        status.set = "miss";
        status.maxEntrySizeExceeded = true;
      }
      this.#delete(k, "set");
      return this;
    }
    let index = this.#size === 0 ? undefined : this.#keyMap.get(k);
    if (index === undefined) {
      const newIndex = (
        this.#size === 0
          ? this.#tail
          : this.#free.length !== 0
            ? this.#free.pop()
            : this.#size === this.#max
              ? this.#evict(false)
              : this.#size
      ) as Index;

      this.#keyList[newIndex] = k;
      this.#valList[newIndex] = v;
      this.#keyMap.set(k, newIndex);
      this.#next[this.#tail as Index] = newIndex;
      this.#prev[newIndex] = this.#tail as Index;
      this.#tail = newIndex;
      this.#size++;
      this.#addItemSize(newIndex, size, status);
      if (status) status.set = "add";
      noUpdateTTL = false;
      index = newIndex;
      if (this.#hasOnInsert) {
        this.#onInsert?.(v as V, k, "add");
      }
    } else {
      this.#moveToTail(index);
      const oldVal = this.#valList[index] as V | BackgroundFetch<V>;
      if (v !== oldVal) {
        if (this.#hasFetchMethod && this.#isBackgroundFetch(oldVal)) {
          oldVal.__abortController.abort(new Error("replaced"));
          const { __staleWhileFetching: s } = oldVal;
          if (s !== undefined && !noDisposeOnSet) {
            if (this.#hasDispose) {
              this.#dispose?.(s as V, k, "set");
            }
            if (this.#hasDisposeAfter) {
              this.#disposed?.push([s as V, k, "set"]);
            }
          }
        } else if (!noDisposeOnSet) {
          if (this.#hasDispose) {
            this.#dispose?.(oldVal as V, k, "set");
          }
          if (this.#hasDisposeAfter) {
            this.#disposed?.push([oldVal as V, k, "set"]);
          }
        }
        this.#removeItemSize(index);
        this.#addItemSize(index, size, status);
        this.#valList[index] = v;
        if (status) {
          status.set = "replace";
          const oldValue =
            oldVal && this.#isBackgroundFetch(oldVal) ? oldVal.__staleWhileFetching : oldVal;
          if (oldValue !== undefined) status.oldValue = oldValue as V;
        }
      } else if (status) {
        status.set = "update";
      }

      if (this.#hasOnInsert) {
        this.onInsert?.(v as V, k, v === oldVal ? "update" : "replace");
      }
    }
    if (ttl !== 0 && !this.#ttls) {
      this.#initializeTTLTracking();
    }
    if (this.#ttls) {
      if (!noUpdateTTL) {
        this.#setItemTTL(index, ttl, start);
      }
      if (status) this.#statusTTL(status, index);
    }
    if (!noDisposeOnSet && this.#hasDisposeAfter && this.#disposed) {
      const dt = this.#disposed;
      let task: DisposeTask<K, V> | undefined;
      while ((task = dt?.shift())) {
        this.#disposeAfter?.(...task);
      }
    }
    return this;
  }

  pop(): V | undefined {
    try {
      while (this.#size) {
        const val = this.#valList[this.#head];
        this.#evict(true);
        if (this.#isBackgroundFetch(val)) {
          if (val.__staleWhileFetching) {
            return val.__staleWhileFetching;
          }
        } else if (val !== undefined) {
          return val as V;
        }
      }
    } finally {
      if (this.#hasDisposeAfter && this.#disposed) {
        const dt = this.#disposed;
        let task: DisposeTask<K, V> | undefined;
        while ((task = dt?.shift())) {
          this.#disposeAfter?.(...task);
        }
      }
    }
    return undefined;
  }

  #evict(free: boolean) {
    const head = this.#head;
    const k = this.#keyList[head] as K;
    const v = this.#valList[head] as V | BackgroundFetch<V>;
    if (this.#hasFetchMethod && this.#isBackgroundFetch(v)) {
      v.__abortController.abort(new Error("evicted"));
    } else if (this.#hasDispose || this.#hasDisposeAfter) {
      if (this.#hasDispose) {
        this.#dispose?.(v as V, k, "evict");
      }
      if (this.#hasDisposeAfter) {
        this.#disposed?.push([v as V, k, "evict"]);
      }
    }
    this.#removeItemSize(head);
    if (free) {
      this.#keyList[head] = undefined;
      this.#valList[head] = undefined;
      this.#free.push(head);
    }
    if (this.#size === 1) {
      this.#head = this.#tail = 0 as Index;
      this.#free.length = 0;
    } else {
      this.#head = this.#next[head] as Index;
    }
    this.#keyMap.delete(k);
    this.#size--;
    return head;
  }

  has(k: K, hasOptions: LRUCacheHasOptions<K, V, FC> = {}) {
    const { updateAgeOnHas = this.updateAgeOnHas, status } = hasOptions;
    const index = this.#keyMap.get(k);
    if (index !== undefined) {
      const v = this.#valList[index];
      if (this.#isBackgroundFetch(v) && v.__staleWhileFetching === undefined) {
        if (status) status.has = "miss";
        return false;
      }
      if (!this.#isStale(index)) {
        if (updateAgeOnHas) {
          this.#updateItemAge(index);
        }
        if (status) {
          status.has = "hit";
          this.#statusTTL(status, index);
        }
        return true;
      } else if (status) {
        status.has = "stale";
        this.#statusTTL(status, index);
      }
    } else if (status) {
      status.has = "miss";
    }
    return false;
  }

  peek(k: K, peekOptions: LRUCachePeekOptions<K, V, FC> = {}) {
    const { allowStale = this.allowStale } = peekOptions;
    const index = this.#keyMap.get(k);
    if (index === undefined || (!allowStale && this.#isStale(index))) {
      return undefined;
    }
    const v = this.#valList[index];
    return this.#isBackgroundFetch(v) ? v.__staleWhileFetching : (v as V);
  }

  #backgroundFetch(
    k: K,
    index: Index | undefined,
    options: LRUCacheFetchOptions<K, V, FC>,
    context: FC | undefined,
  ): BackgroundFetch<V> {
    const v = index === undefined ? undefined : (this.#valList[index] as V | undefined);
    if (this.#isBackgroundFetch(this.#valList[index!])) {
      return this.#valList[index!] as BackgroundFetch<V>;
    }

    const ac = new AC() as AbortController;
    const { signal: userSignal } = options;
    userSignal?.addEventListener("abort", () => ac.abort(userSignal.reason), {
      signal: ac.signal,
    });

    const fetchOpts = {
      signal: ac.signal,
      options,
      context: context as FC,
    };

    const cb = (fetchedValue: V | undefined, updateCache = false): V | undefined => {
      const { aborted } = ac.signal;
      const ignoreAbort = options.ignoreFetchAbort && fetchedValue !== undefined;
      if (options.status) {
        if (aborted && !updateCache) {
          options.status.fetchAborted = true;
          options.status.fetchError = ac.signal.reason;
          if (ignoreAbort) options.status.fetchAbortIgnored = true;
        } else {
          options.status.fetchResolved = true;
        }
      }
      if (aborted && !ignoreAbort && !updateCache) {
        return fetchFail(ac.signal.reason);
      }

      if (index === undefined) {
        return fetchedValue;
      }
      if (typeof index === "number") {
        const currentValInMap: V | BackgroundFetch<V> | undefined = this.#valList[index];
        if (currentValInMap === p) {
          if (fetchedValue === undefined) {
            if (p.__staleWhileFetching) {
              this.#valList[index] = p.__staleWhileFetching;
            } else {
              this.#delete(k, "fetch");
            }
          } else {
            if (options.status) options.status.fetchUpdated = true;
            this.set(k, fetchedValue, fetchOpts.options);
          }
        }
      }
      return fetchedValue;
    };

    const eb = (er: Error) => {
      if (options.status) {
        options.status.fetchRejected = true;
        options.status.fetchError = er;
      }
      return fetchFail(er);
    };

    const fetchFail = (er: Error): V | undefined => {
      const { aborted } = ac.signal;
      const allowStaleAborted = aborted && options.allowStaleOnFetchAbort;
      const allowStale = allowStaleAborted || options.allowStaleOnFetchRejection;
      const noDelete = allowStale || options.noDeleteOnFetchRejection;

      let currentValInMap: V | BackgroundFetch<V> | undefined;
      if (typeof index === "number") {
        currentValInMap = this.#valList[index];
      } else {
        const idx = this.#keyMap.get(k);
        currentValInMap = idx !== undefined ? this.#valList[idx] : undefined;
      }
      if (currentValInMap === p) {
        const del = !noDelete || p.__staleWhileFetching === undefined;
        if (del) {
          this.#delete(k, "fetch");
        } else if (!allowStaleAborted && typeof index === "number") {
          this.#valList[index] = p.__staleWhileFetching;
        }
      }
      if (allowStale) {
        if (options.status && p.__staleWhileFetching !== undefined) {
          options.status.returnedStale = true;
        }
        return p.__staleWhileFetching;
      } else if (p.__returned === p) {
        throw er;
      }
      return undefined;
    };

    const pcall = (res: (v: V | undefined) => void, rej: (e: Error) => void) => {
      const fmp = this.#fetchMethod?.(k, v, fetchOpts);
      if (fmp && fmp instanceof Promise) {
        fmp.then((val) => {
          if (typeof val === "undefined") {
            res(undefined);
          } else {
            res(val as V | undefined);
          }
        }, rej);
      } else {
        res(fmp as V | undefined);
      }

      ac.signal.addEventListener("abort", () => {
        if (!options.ignoreFetchAbort || options.allowStaleOnFetchAbort) {
          res(undefined);
          if (options.allowStaleOnFetchAbort && fmp && fmp instanceof Promise) {
            fmp
              .then((val) => {
                if (typeof val === "undefined") {
                  cb(undefined, true);
                } else {
                  cb(val as V | undefined, true);
                }
              })
              .catch(() => {});
          }
        }
      });
    };

    if (options.status) options.status.fetchDispatched = true;
    const prom = new Promise(pcall).then(cb, eb);
    const p: BackgroundFetch<V> = Object.assign(prom, {
      __abortController: ac,
      __staleWhileFetching: v,
      __returned: undefined,
    });

    if (index === undefined) {
      const setOptions: LRUCacheSetOptions<K, V, FC> = { ...fetchOpts.options };
      this.set(k, p, setOptions);
      index = this.#keyMap.get(k)!;
    } else {
      this.#valList[index] = p;
    }
    return p;
  }

  #isBackgroundFetch(p: unknown): p is BackgroundFetch<V> {
    if (!this.#hasFetchMethod) return false;
    const b = p as BackgroundFetch<V>;
    return (
      !!b &&
      b instanceof Promise &&
      Object.prototype.hasOwnProperty.call(b, "__staleWhileFetching") &&
      b.__abortController instanceof AC
    );
  }

  fetch(k: K, fetchOptions?: LRUCacheFetchOptions<K, V, FC>): Promise<undefined | V>;

  async fetch(k: K, fetchOptions: LRUCacheFetchOptions<K, V, FC> = {}): Promise<undefined | V> {
    const {
      allowStale = this.allowStale,
      updateAgeOnGet = this.updateAgeOnGet,
      noDeleteOnStaleGet = this.noDeleteOnStaleGet,
      ttl = this.ttl,
      noDisposeOnSet = this.noDisposeOnSet,
      size = 0,
      sizeCalculation = this.sizeCalculation,
      noUpdateTTL = this.noUpdateTTL,
      noDeleteOnFetchRejection = this.noDeleteOnFetchRejection,
      allowStaleOnFetchRejection = this.allowStaleOnFetchRejection,
      ignoreFetchAbort = this.ignoreFetchAbort,
      allowStaleOnFetchAbort = this.allowStaleOnFetchAbort,
      context,
      forceRefresh = false,
      status,
      signal,
    } = fetchOptions;

    if (!this.#hasFetchMethod) {
      if (status) status.fetch = "get";
      const getOptions: LRUCacheGetOptions<K, V, FC> = {
        allowStale,
        updateAgeOnGet,
        noDeleteOnStaleGet,
      };
      if (status !== undefined) {
        getOptions.status = status;
      }
      return this.get(k, getOptions);
    }

    const options: LRUCacheFetchOptions<K, V, FC> = {
      allowStale,
      updateAgeOnGet,
      noDeleteOnStaleGet,
      ttl,
      noDisposeOnSet,
      size,
      noUpdateTTL,
      noDeleteOnFetchRejection,
      allowStaleOnFetchRejection,
      allowStaleOnFetchAbort,
      ignoreFetchAbort,
    };
    if (sizeCalculation !== undefined) {
      options.sizeCalculation = sizeCalculation;
    }
    if (status !== undefined) {
      options.status = status;
    }
    if (signal !== undefined) {
      options.signal = signal;
    }

    const index = this.#keyMap.get(k);
    if (index === undefined) {
      if (status) status.fetch = "miss";
      const p = this.#backgroundFetch(k, index, options, context);
      return (p.__returned = p);
    } else {
      const v = this.#valList[index];
      if (this.#isBackgroundFetch(v)) {
        const staleReturn = allowStale && v.__staleWhileFetching !== undefined;
        if (status) {
          status.fetch = "inflight";
          if (staleReturn) status.returnedStale = true;
        }
        return staleReturn ? v.__staleWhileFetching : (v.__returned = v);
      }

      const isStale = this.#isStale(index);
      if (!forceRefresh && !isStale) {
        if (status) status.fetch = "hit";
        this.#moveToTail(index);
        if (updateAgeOnGet) {
          this.#updateItemAge(index);
        }
        if (status) this.#statusTTL(status, index);
        return v as V;
      }

      const p = this.#backgroundFetch(k, index, options, context);
      const hasStaleData = p.__staleWhileFetching !== undefined;
      const staleReturn = hasStaleData && allowStale;
      if (status) {
        status.fetch = isStale ? "stale" : "refresh";
        if (staleReturn && isStale) status.returnedStale = true;
      }
      return staleReturn ? p.__staleWhileFetching : (p.__returned = p);
    }
  }

  forceFetch(k: K, fetchOptions?: LRUCacheFetchOptions<K, V, FC>): Promise<V>;
  async forceFetch(k: K, fetchOptions: LRUCacheFetchOptions<K, V, FC> = {}): Promise<V> {
    const v = await this.fetch(k, fetchOptions as unknown as Parameters<typeof this.fetch>[1]);
    if (v === undefined) throw new Error("fetch() returned undefined");
    return v;
  }

  memo(k: K, memoOptions?: LRUCacheMemoOptions<K, V, FC>): V;
  memo(k: K, memoOptions: LRUCacheMemoOptions<K, V, FC> = {}): V {
    const memoMethod = this.#memoMethod;
    if (!memoMethod) {
      throw new Error("no memoMethod provided to constructor");
    }
    const { context, forceRefresh, ...options } = memoOptions;
    const v = this.get(k, options);
    if (!forceRefresh && v !== undefined) return v;
    const vv = memoMethod(k, v, {
      options,
      context,
    } as LRUCacheMemoizerOptions<K, V, FC>);
    this.set(k, vv, options);
    return vv;
  }

  get(k: K, getOptions: LRUCacheGetOptions<K, V, FC> = {}) {
    const {
      allowStale = this.allowStale,
      updateAgeOnGet = this.updateAgeOnGet,
      noDeleteOnStaleGet = this.noDeleteOnStaleGet,
      status,
    } = getOptions;
    const index = this.#keyMap.get(k);
    if (index !== undefined) {
      const value = this.#valList[index];
      const fetching = this.#isBackgroundFetch(value);
      if (status) this.#statusTTL(status, index);
      if (this.#isStale(index)) {
        if (status) status.get = "stale";
        if (!fetching) {
          if (!noDeleteOnStaleGet) {
            this.#delete(k, "expire");
          }
          if (status && allowStale) status.returnedStale = true;
          return allowStale ? (value as V) : undefined;
        } else {
          if (status && allowStale && value.__staleWhileFetching !== undefined) {
            status.returnedStale = true;
          }
          return allowStale ? value.__staleWhileFetching : undefined;
        }
      } else {
        if (status) status.get = "hit";
        if (fetching) {
          return value.__staleWhileFetching;
        }
        this.#moveToTail(index);
        if (updateAgeOnGet) {
          this.#updateItemAge(index);
        }
        return value as V;
      }
    } else if (status) {
      status.get = "miss";
    }
    return undefined;
  }

  #connect(p: Index, n: Index) {
    this.#prev[n] = p;
    this.#next[p] = n;
  }

  #moveToTail(index: Index): void {
    if (index !== this.#tail) {
      if (index === this.#head) {
        this.#head = this.#next[index] as Index;
      } else {
        this.#connect(this.#prev[index] as Index, this.#next[index] as Index);
      }
      this.#connect(this.#tail, index);
      this.#tail = index;
    }
  }

  delete(k: K) {
    return this.#delete(k, "delete");
  }

  #delete(k: K, reason: LRUCacheDisposeReason) {
    let deleted = false;
    if (this.#size !== 0) {
      const index = this.#keyMap.get(k);
      if (index !== undefined) {
        deleted = true;
        if (this.#size === 1) {
          this.#clear(reason);
        } else {
          this.#removeItemSize(index);
          const v = this.#valList[index];
          if (this.#isBackgroundFetch(v)) {
            v.__abortController.abort(new Error(reason));
          } else if (this.#hasDispose || this.#hasDisposeAfter) {
            if (this.#hasDispose) {
              this.#dispose?.(v as V, k, reason);
            }
            if (this.#hasDisposeAfter) {
              this.#disposed?.push([v as V, k, reason]);
            }
          }
          this.#keyMap.delete(k);
          this.#keyList[index] = undefined;
          this.#valList[index] = undefined;
          if (index === this.#tail) {
            this.#tail = this.#prev[index] as Index;
          } else if (index === this.#head) {
            this.#head = this.#next[index] as Index;
          } else {
            const pi = this.#prev[index] as Index;
            this.#next[pi] = this.#next[index] as Index;
            const ni = this.#next[index] as Index;
            this.#prev[ni] = this.#prev[index] as Index;
          }
          this.#size--;
          this.#free.push(index);
        }
      }
    }
    if (this.#hasDisposeAfter && this.#disposed?.length) {
      const dt = this.#disposed;
      let task: DisposeTask<K, V> | undefined;
      while ((task = dt?.shift())) {
        this.#disposeAfter?.(...task);
      }
    }
    return deleted;
  }

  clear() {
    return this.#clear("delete");
  }

  #clear(reason: LRUCacheDisposeReason) {
    for (const index of this.#rindexes({ allowStale: true })) {
      const v = this.#valList[index];
      const k = this.#keyList[index];
      if (this.#isBackgroundFetch(v)) {
        v.__abortController.abort(new Error(reason));
      } else if (k !== undefined && v !== undefined) {
        if (this.#hasDispose) {
          this.#dispose?.(v as V, k as K, reason);
        }
        if (this.#hasDisposeAfter) {
          this.#disposed?.push([v as V, k as K, reason]);
        }
      }
    }

    this.#keyMap.clear();
    this.#valList.fill(undefined);
    this.#keyList.fill(undefined);
    if (this.#ttls && this.#starts) {
      this.#ttls.fill(0);
      this.#starts.fill(0);
    }
    if (this.#sizes) {
      this.#sizes.fill(0);
    }
    this.#head = 0 as Index;
    this.#tail = 0 as Index;
    this.#free.length = 0;
    this.#calculatedSize = 0;
    this.#size = 0;
    if (this.#hasDisposeAfter && this.#disposed) {
      const dt = this.#disposed;
      let task: DisposeTask<K, V> | undefined;
      while ((task = dt?.shift())) {
        this.#disposeAfter?.(...task);
      }
    }
  }
}

import type { ImageData } from "../../ui/@/lib/interfaces";
import { md5 } from "../../crypto-data-structures/md5";
import { tryCatch } from "../../lazy-imports/try-catch"; // Added import

const MAX_FILE_SIZE = 600 * 1024; // 600 KB

export const processImage = (file: File): Promise<ImageData> => {
  const blobToBase64 = (blob: Blob): Promise<string> => {
    return new Promise((resolve, reject) => {
      const reader = new FileReader();
      reader.onload = () => resolve(reader.result as string);
      reader.onerror = reject;
      reader.readAsDataURL(blob);
    });
  };

  const resizeImage = (img: HTMLImageElement, maxSize: number): Promise<Blob> => {
    return new Promise((resolve) => {
      const canvas = document.createElement("canvas");
      let width = img.width;
      let height = img.height;

      // Calculate the width and height, constraining the proportions
      if (width > height) {
        if (width > maxSize) {
          height = Math.round((height * maxSize) / width);
          width = maxSize;
        }
      } else {
        if (height > maxSize) {
          width = Math.round((width * maxSize) / height);
          height = maxSize;
        }
      }

      canvas.width = width;
      canvas.height = height;

      const ctx = canvas.getContext("2d");
      ctx!.drawImage(img, 0, 0, width, height);

      canvas.toBlob((blob) => {
        resolve(blob!);
      }, file.type);
    });
  };

  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.onload = async (e) => {
      const processLogic = async () => {
        if (!e.target?.result) {
          throw new Error("FileReader did not load content.");
        }
        let arrayBuffer = e.target.result as ArrayBuffer;
        let blob = new Blob([arrayBuffer], { type: file.type });

        let size = 1600;
        while (blob.size > MAX_FILE_SIZE) {
          const img = new Image();
          // Wrapping the image loading and resizing in a promise for tryCatch
          const resizeStepPromise = new Promise<Blob>((res, rej) => {
            img.onload = () => {
              // Self-invoking async function to handle awaits
              (async () => {
                try {
                  console.warn("Resizing image to", size);
                  const resized = await resizeImage(img, size);
                  res(resized);
                } catch (resizeError) {
                  rej(resizeError);
                }
              })();
            };
            img.onerror = () => rej(new Error("Image loading failed for resizing."));
            img.src = URL.createObjectURL(blob);
          });

          const { data: resizedBlobData, error: resizeError } = await tryCatch(resizeStepPromise);
          if (resizeError || !resizedBlobData) {
            throw new Error(
              `Image resizing failed: ${resizeError?.message || "Unknown resize error"}`,
            );
          }
          blob = resizedBlobData;

          const { data: newArrayBuffer, error: blobToArrayBufferError } = await tryCatch(
            blob.arrayBuffer(),
          );
          if (blobToArrayBufferError || !newArrayBuffer) {
            throw new Error(
              `Failed to get arrayBuffer from resized blob: ${
                blobToArrayBufferError?.message || "Unknown error"
              }`,
            );
          }
          arrayBuffer = newArrayBuffer;
          size -= 300;
        }

        const base64Data = await blobToBase64(blob); // This returns a Promise, can be awaited directly
        const md5Body = md5(base64Data);
        const imageName = file.name;
        const url = location.origin + `/my-cms/${md5Body}/${imageName}`;

        const { error: putError } = await tryCatch(
          fetch(url, { method: "PUT", body: arrayBuffer }),
        );
        if (putError) {
          throw new Error(`Failed to upload image: ${putError.message}`);
        }

        return {
          imageName,
          url,
          src: url,
          mediaType: file.type,
          data: url,
        } as ImageData;
      };

      const { data: imageData, error } = await tryCatch(processLogic());
      if (error) {
        console.error("Error in processImage onload:", error);
        reject(new Error(`Failed to process image: ${error.message}`));
      } else if (imageData) {
        resolve(imageData);
      } else {
        reject(new Error("Image processing did not return data."));
      }
    };
    reader.onerror = () => reject(new Error("Failed to read file"));
    reader.readAsArrayBuffer(file);
  });
};

const sharedWorkerSupported = typeof SharedWorker !== "undefined";

import { tryCatch as _tryCatch } from "../../lazy-imports/try-catch"; // Added import

class SharedWorkerPolyfill {
  private worker: Worker | null = null; // Can be null if construction fails
  public port: MessagePort = null!; // Will be initialized if worker is created

  constructor(url: string, opts?: WorkerOptions) {
    if (process.env.VI_TEST) {
      // Mock worker for tests
      this.worker = {
        postMessage: () => {},
        terminate: () => {},
        onmessage: null,
        onmessageerror: null,
        onerror: null,
        addEventListener: () => {},
        removeEventListener: () => {},
        dispatchEvent: () => true,
      } as unknown as Worker;
      this.initializeWorker();
    } else {
      // Attempt to create the real worker
      try {
        // Synchronous new Worker() can throw, so wrap it.
        // However, tryCatch is for Promises. For synchronous errors, a standard try/catch is fine.
        // Let's assume for now that new Worker() itself doesn't throw in a way that needs tryCatch,
        // but rather errors might occur during its lifecycle (onerror).
        // If new Worker() itself can throw and we want to use tryCatch, we'd need to wrap its instantiation
        // in a Promise, which is a bit artificial for a constructor.
        // Sticking to standard try/catch for constructor-level errors.
        this.worker = new Worker(url, opts);
        this.initializeWorker();
      } catch (error) {
        console.error("Failed to construct Worker:", error);
        // Worker remains null, port will not be initialized.
        // Consumers of this class should check if `this.worker` or `this.port` is null.
        // Or, we could re-throw or set an error state.
        // For now, let's allow it to proceed with worker as null.
      }
    }
  }

  private initializeWorker() {
    if (!this.worker) {
      // Guard against null worker
      console.warn("Worker not initialized, cannot initialize port.");
      // Initialize port to a mock or throw, to avoid errors if accessed later
      this.port = {
        onmessage: null,
        onmessageerror: null,
        close: () => {},
        postMessage: () => {},
        start: () => {},
        addEventListener: () => {},
        removeEventListener: () => {},
        dispatchEvent: () => false,
      } as unknown as MessagePort;
      return;
    }
    if (process.env.VI_TEST) {
      // Create a mock MessagePort for tests
      this.port = {
        onmessage: null,
        onmessageerror: null,
        close: () => {},
        postMessage: () => {},
        start: () => {},
        addEventListener: () => {},
        removeEventListener: () => {},
        dispatchEvent: () => true,
      } as unknown as MessagePort;
    } else {
      this.port = this.worker as unknown as MessagePort; // Safe now due to the guard
      // Send port2 to the worker
      const message = { type: "init" };
      this.worker.postMessage(message);

      // Forward error events from the worker to the port
      // The `this.worker &&` check is redundant due to the guard above
      if ("onerror" in this.worker) {
        this.worker.onerror = (event: ErrorEvent) => {
          const errorEvent = new ErrorEvent("error", {
            message: event.message,
            filename: event.filename,
            lineno: event.lineno,
            colno: event.colno,
            error: event.error,
          });
          this.port.dispatchEvent(errorEvent);
        };
      }
    }
  }

  /**
   * An EventListener called when MessageEvent of type 'message' is fired on the port—that is, when the port receives a message.
   */
  get onmessage(): ((this: MessagePort, ev: MessageEvent) => void) | null {
    return this.port.onmessage;
  }

  set onmessage(value: ((this: MessagePort, ev: MessageEvent) => void) | null) {
    this.port.onmessage = value;
  }

  /**
   * An EventListener called when a MessageEvent of type 'messageerror' is fired—that is, when it receives a message that cannot be deserialized.
   */
  get onmessageerror(): ((this: MessagePort, ev: MessageEvent) => void) | null {
    return this.port.onmessageerror;
  }

  set onmessageerror(value: ((this: MessagePort, ev: MessageEvent) => void) | null,) {
    this.port.onmessageerror = value;
  }

  /**
   * Clones message and transmits it to worker's global environment.
   */
  postMessage = (message: unknown, transfer?: Transferable[]) =>
    transfer ? this.port.postMessage(message, transfer) : this.port.postMessage(message);

  /**
   * Immediately terminates the worker.
   */
  terminate(): void {
    if (this.worker) {
      this.worker.terminate();
    }
    // port.close() should be safe even if port is a mock,
    // but good practice to check if it's truly initialized if worker failed.
    if (this.port && typeof this.port.close === "function") {
      this.port.close();
    }
  }

  /**
   * Disconnects the port, so it is no longer active.
   */
  close(): void {
    this.port.close();
  }

  /**
   * Is an EventListener that is called whenever an ErrorEvent of type 'error' occurs.
   */
  get onerror(): ((this: AbstractWorker, ev: ErrorEvent) => void) | null {
    if (this.worker && "onerror" in this.worker) {
      return this.worker.onerror;
    }
    return null;
  }

  set onerror(value: ((this: AbstractWorker, ev: ErrorEvent) => void) | null) {
    if (this.worker && "onerror" in this.worker) {
      this.worker.onerror = value;
    }
  }

  addEventListener(
    type: string,
    listener: EventListenerOrEventListenerObject,
    options?: boolean | AddEventListenerOptions,
  ): void {
    this.port.addEventListener(type, listener, options);
  }

  removeEventListener(
    type: string,
    listener: EventListenerOrEventListenerObject,
    options?: boolean | EventListenerOptions,
  ): void {
    this.port.removeEventListener(type, listener, options);
  }

  /**
   * Dispatches an event to this EventTarget.
   */
  dispatchEvent(event: Event): boolean {
    return this.port.dispatchEvent(event);
  }
}

const WorkerToExport = sharedWorkerSupported ? SharedWorker : SharedWorkerPolyfill;

export default WorkerToExport;

