export const useSpeedy = async (codeSpace: string) => {
  const attemptBuild = async (entryPoint = "") =>
    build({
      codeSpace,
      splitting: true,
      entryPoints: entryPoint ? [entryPoint] : [],
      origin: location.origin,
      format: "esm",
    });

  const buildWithRetry = async (entryPoint = "") => {
    let { data, error } = await tryCatch(attemptBuild(entryPoint));
    if (error) {
      console.error("Build failed, retrying after 1 second:", error);
      await wait(1000);
      ({ data, error } = await tryCatch(attemptBuild(entryPoint))); // Re-assign
      if (error) {
        console.error("Build failed on retry:", error);
        throw error;
      }
    }
    if (data === null || data === undefined) {
      throw new Error("Build returned null or undefined.");
    }
    return data;
  };

  const indexMjs = (await buildWithRetry()) as unknown as Array<{
    contents: Uint8Array;
    path: string;
    text: string;
  }>;

  const getMimeType = (extension: string) => {
    const mimeTypes: Record<string, string> = {
      woff: "font/woff",
      woff2: "font/woff2",
      ttf: "font/ttf",
      otf: "font/otf",
      eot: "application/vnd.ms-fontobject",
      svg: "image/svg+xml",
    };
    return mimeTypes[extension] || `font/${extension}`;
  };

  // 2. Proper error handling and logging
  indexMjs
    .filter((f) => !f.path.endsWith(".css") && !f.path.endsWith(".mjs"))
    .forEach(async (f) => {
      const uploadFont = async () => {
        const body = f.contents;
        const extension = f.path.split(".").pop() as string;
        const mimeType = getMimeType(extension);

        const response = await fetch(f.path.slice(1), {
          method: "PUT",
          body: body as BodyInit,
          headers: { "Content-Type": mimeType },
        });

        if (!response || !response.ok) {
          throw new Error(`Failed to upload font: ${f.path}, Status: ${response.status}`);
        }
      };
      const { error } = await tryCatch(uploadFont());
      if (error) {
        console.error(`Error processing font: ${f.path}`, error);
      }
    });

  // 4. Update CSS to use correct paths
  const updateCssPaths = (css: string, codeSpace: string) => {
    return css.replace(
      /url\((["']?)\/assets\//g,
      `url($1https://testing.spike.land/live/${codeSpace}/api/my-cms/assets/`,
    );
  };
  let updatedCss = "";
  // Usage in your main function:
  const css = indexMjs.find((f) => f.path.endsWith("/api/my-cms/index.css"))?.text;
  if (css) {
    updatedCss = updateCssPaths(css, codeSpace);
    // Use updatedCss in your HTML template
  }

  // await fetch(f.path.slice(1), {method: "PUT", body, headers: {"Content-Type": `font/${extension}`}});

  const htm = await fetch(`/live/${codeSpace}/htm`).then((res) => res.text());

  const html = `<!DOCTYPE html>
<html lang="en">
<head profile="http://www.w3.org/2005/10/profile">
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1.0, user-scalable=no, interactive-widget=resizes-content">
  <meta name="theme-color" content="#ffffff" media="(prefers-color-scheme: light)">
  <meta name="theme-color" content="#000000" media="(prefers-color-scheme: dark)">
  <base href="/">
  <style type="text/css">  
    ${updatedCss}
  </style>
</head>
<body>
  <div id="embed">${htm}</div>
  <script type="module">
  ${indexMjs[0]!.text.split("@import url(").join("//@import url(")}
  </script>
</body>
</html>`;

  const md = md5(html);

  await fetch(`/my-cms/${md}/${codeSpace}.html`, {
    method: "PUT",
    headers: {
      "Content-Type": "text/html",
    },
    body: html,
  });
};

import type { ICodeSession } from "../../ui/@/lib/interfaces";
import {
  applySessionDelta,
  computeSessionHash,
  sanitizeSession,
  type SessionDelta,
} from "../lib/make-sess";
import { tryCatch } from "../../lazy-imports/try-catch";
import type { ISessionSynchronizer } from "./types";

const REFRESH_INTERVAL_MS = 15000;
const RECONNECT_DELAY_MS = 1500;

interface IncomingSocketMessage extends Partial<SessionDelta> {
  type?: string;
  hash?: string;
}

/**
 * SessionSynchronizer enables communication for code sessions.
 */
export class SessionSynchronizer implements ISessionSynchronizer {
  private session: ICodeSession | null = null;
  private subscribers: Array<(session: ICodeSession & { sender: string }) => void> = [];
  private socket: WebSocket | null = null;
  private refreshInterval: ReturnType<typeof setInterval> | null = null;
  private reconnectTimeout: ReturnType<typeof setTimeout> | null = null;
  private isClosed = false;
  private codeSpace: string;

  constructor(codeSpace: string, session?: ICodeSession) {
    this.codeSpace = codeSpace;
    if (session) {
      this.session = sanitizeSession(session);
    }
    this.registerLifecycleListeners();
    this.startRefreshLoop();
  }

  private notifySubscribers(session: ICodeSession & { sender: string }): void {
    this.subscribers.forEach((cb) => {
      try {
        cb(session);
      } catch (error) {
        console.error("Error notifying subscriber:", error);
      }
    });
  }

  async getCode(): Promise<string> {
    if (!this.session) {
      this.session = await this.init();
    }
    return this.session!.code;
  }

  getSession(): ICodeSession | null {
    return this.session;
  }

  async init(session?: ICodeSession): Promise<ICodeSession> {
    if (session) {
      this.setSession(sanitizeSession(session), "INIT");
      this.ensureRealtimeConnection();
      return this.session!;
    }

    if (this.session) {
      this.ensureRealtimeConnection();
      return this.session;
    }

    const fetchSessionPromise = async () => {
      const response = await fetch(this.getSessionUrl());
      if (!response.ok) {
        throw new Error(`Failed to fetch session: ${response.status}`);
      }
      return response.json();
    };

    const { data, error } = await tryCatch(fetchSessionPromise());

    if (error) {
      console.error("Error initializing session:", error);
      this.setSession(
        sanitizeSession({
          codeSpace: this.codeSpace,
          code: "",
          html: "",
          css: "",
          transpiled: "",
        }),
        "INIT_FALLBACK",
      );
    } else {
      this.setSession(data as ICodeSession, "INIT");
    }

    this.ensureRealtimeConnection();
    return this.session!;
  }

  subscribe(callback: (session: ICodeSession & { sender: string }) => void): () => void {
    this.subscribers.push(callback);
    return () => {
      this.subscribers = this.subscribers.filter((cb) => cb !== callback);
    };
  }

  broadcastSession(session: ICodeSession & { sender: string }): void {
    try {
      this.setSession(session, session.sender);
    } catch (error) {
      console.error("Error in SessionSynchronizer.broadcastSession", error);
    }
  }

  close(): void {
    this.isClosed = true;
    this.subscribers = [];
    this.unregisterLifecycleListeners();
    if (this.refreshInterval) {
      clearInterval(this.refreshInterval);
      this.refreshInterval = null;
    }
    if (this.reconnectTimeout) {
      clearTimeout(this.reconnectTimeout);
      this.reconnectTimeout = null;
    }
    if (this.socket) {
      const socket = this.socket;
      this.socket = null;
      try {
        socket.close();
      } catch {
        // Socket may already be closed.
      }
    }
  }

  private setSession(session: Partial<ICodeSession>, sender: string): void {
    const nextSession = sanitizeSession(session);
    const currentHash = this.session ? computeSessionHash(this.session) : null;
    const nextHash = computeSessionHash(nextSession);
    if (currentHash === nextHash) {
      return;
    }

    this.session = nextSession;
    this.notifySubscribers({
      ...nextSession,
      sender,
    });
  }

  private getSessionUrl(): string {
    return `/live/${encodeURIComponent(this.codeSpace)}/session.json`;
  }

  private getWebSocketUrl(): string | null {
    if (typeof window === "undefined") {
      return null;
    }

    const url = new URL(this.getSessionUrl(), window.location.origin);
    url.protocol = url.protocol === "https:" ? "wss:" : "ws:";
    url.pathname = `/live/${encodeURIComponent(this.codeSpace)}/websocket`;
    url.search = "";
    return url.toString();
  }

  private ensureRealtimeConnection(): void {
    if (this.isClosed || typeof WebSocket === "undefined") {
      return;
    }
    if (this.socket && this.socket.readyState !== WebSocket.CLOSED) {
      return;
    }

    const websocketUrl = this.getWebSocketUrl();
    if (!websocketUrl) {
      return;
    }

    const socket = new WebSocket(websocketUrl);
    this.socket = socket;

    socket.onmessage = (event) => {
      void this.handleSocketMessage(event.data);
    };

    socket.onclose = () => {
      if (this.socket === socket) {
        this.socket = null;
      }
      if (!this.isClosed) {
        this.scheduleReconnect();
      }
    };

    socket.onerror = () => {
      try {
        socket.close();
      } catch {
        // Ignore close errors from already-closed sockets.
      }
    };
  }

  private scheduleReconnect(): void {
    if (this.reconnectTimeout || this.isClosed) {
      return;
    }

    this.reconnectTimeout = setTimeout(() => {
      this.reconnectTimeout = null;
      void this.refreshFromServer("SOCKET_RECONNECT");
      this.ensureRealtimeConnection();
    }, RECONNECT_DELAY_MS);
  }

  private async handleSocketMessage(rawMessage: unknown): Promise<void> {
    if (typeof rawMessage !== "string") {
      return;
    }

    let message: IncomingSocketMessage;
    try {
      const parsed: unknown = JSON.parse(rawMessage);
      if (typeof parsed !== "object" || parsed === null || Array.isArray(parsed)) {
        return;
      }
      message = parsed as IncomingSocketMessage;
    } catch {
      return;
    }

    if (message.type === "handshake") {
      if (this.session && typeof message.hash === "string") {
        const currentHash = computeSessionHash(this.session);
        if (currentHash !== message.hash) {
          await this.refreshFromServer("SOCKET_HANDSHAKE");
        }
      }
      return;
    }

    if (message.type) {
      return;
    }

    if (
      typeof message.oldHash !== "string" ||
      typeof message.hashCode !== "string" ||
      typeof message.delta === "undefined"
    ) {
      return;
    }

    if (!this.session) {
      await this.refreshFromServer("REMOTE_PATCH_MISS");
      return;
    }

    try {
      const patchedSession = applySessionDelta(this.session, message as SessionDelta);
      this.setSession(patchedSession, "REMOTE_PATCH");
    } catch (error) {
      console.error("Failed to apply live session patch:", error);
      await this.refreshFromServer("REMOTE_PATCH_REFRESH");
    }
  }

  private async refreshFromServer(sender: string): Promise<void> {
    if (this.isClosed) {
      return;
    }

    const fetchSessionPromise = async () => {
      const response = await fetch(this.getSessionUrl());
      if (!response.ok) {
        throw new Error(`Failed to fetch session: ${response.status}`);
      }
      return response.json() as Promise<ICodeSession>;
    };

    const { data, error } = await tryCatch(fetchSessionPromise());
    if (error || !data) {
      if (error) {
        console.error("Error refreshing session:", error);
      }
      return;
    }

    this.setSession(data, sender);
  }

  private startRefreshLoop(): void {
    if (this.refreshInterval || typeof window === "undefined") {
      return;
    }

    this.refreshInterval = setInterval(() => {
      if (!this.socket || this.socket.readyState !== WebSocket.OPEN) {
        void this.refreshFromServer("REFRESH_INTERVAL");
      }
    }, REFRESH_INTERVAL_MS);
  }

  private readonly handleLifecycleRefresh = (): void => {
    void this.refreshFromServer("WINDOW_FOCUS");
  };

  private readonly handleVisibilityRefresh = (): void => {
    if (typeof document !== "undefined" && document.visibilityState === "visible") {
      void this.refreshFromServer("VISIBILITY_REFRESH");
    }
  };

  private registerLifecycleListeners(): void {
    if (typeof window === "undefined" || typeof document === "undefined") {
      return;
    }

    window.addEventListener("focus", this.handleLifecycleRefresh);
    window.addEventListener("online", this.handleLifecycleRefresh);
    document.addEventListener("visibilitychange", this.handleVisibilityRefresh);
  }

  private unregisterLifecycleListeners(): void {
    if (typeof window === "undefined" || typeof document === "undefined") {
      return;
    }

    window.removeEventListener("focus", this.handleLifecycleRefresh);
    window.removeEventListener("online", this.handleLifecycleRefresh);
    document.removeEventListener("visibilitychange", this.handleVisibilityRefresh);
  }
}

import type { ImageData } from "../../ui/@/lib/interfaces";
import { md5 } from "../../crypto-data-structures/md5";
import { transpile } from "../../concurrency/shared";
import { tryCatch } from "../../lazy-imports/try-catch";
import type { RunMessageResult } from "./types";

export interface EditorState {
  started: boolean;
  sub: boolean;
  code: string;
  setValue: (code: string) => void;
}

/**
 * Generic function type that preserves argument and return types.
 * Use this instead of `(...args: any[]) => any` for better type safety.
 * @template TArgs - Tuple type representing function arguments
 * @template TReturn - Return type of the function
 */
type GenericFunction<TArgs extends unknown[] = unknown[], TReturn = unknown> = (
  ...args: TArgs
) => TReturn;

/**
 * Type constraint for async functions returning a Promise.
 * @template TArgs - Tuple type representing function arguments
 * @template TReturn - The unwrapped return type (what the Promise resolves to)
 */
type AsyncFunction<TArgs extends unknown[] = unknown[], TReturn = unknown> = (
  ...args: TArgs
) => Promise<TReturn>;

function memoize<TArgs extends unknown[], TReturn>(
  fn: GenericFunction<TArgs, TReturn>,
  keyResolver?: (...args: TArgs) => string,
): GenericFunction<TArgs, TReturn> {
  const cache = new Map<string, TReturn>();

  return (...args: TArgs): TReturn => {
    const key = keyResolver ? keyResolver(...args) : JSON.stringify(args);

    if (cache.has(key)) {
      return cache.get(key) as TReturn;
    }

    const result = fn(...args);
    cache.set(key, result);

    if (result instanceof Promise) {
      result.catch(() => {
        cache.delete(key);
      });
    }

    return result;
  };
}

/**
 * Type for a memoized function that accepts an AbortSignal as the last parameter.
 * @template TArgs - Tuple type representing the original function arguments
 * @template TReturn - The unwrapped return type (what the Promise resolves to)
 */
type MemoizedFunctionWithAbort<TArgs extends unknown[], TReturn> = (
  ...args: [...TArgs, AbortSignal]
) => Promise<TReturn>;

/**
 * Callback interface for managing promise resolution with abort signals.
 * @template TReturn - The type of value the promise resolves to
 */
interface MemoizeCallbacks<TReturn> {
  resolve: (value: TReturn) => void;
  reject: (reason?: unknown) => void;
  signal: AbortSignal;
}

/**
 * Memoizes an async function with support for AbortSignal cancellation.
 * Multiple concurrent calls with the same arguments share the same underlying promise.
 * @template TArgs - Tuple type representing the original function arguments
 * @template TReturn - The unwrapped return type (what the Promise resolves to)
 * @param fn - The async function to memoize
 * @param keyResolver - Optional function to generate cache keys from arguments
 * @returns A memoized version of the function that accepts an AbortSignal as the last argument
 */
export function memoizeWithAbort<TArgs extends unknown[], TReturn>(
  fn: AsyncFunction<TArgs, TReturn>,
  keyResolver?: (...args: TArgs) => string,
): MemoizedFunctionWithAbort<TArgs, TReturn> {
  const cache = new Map<
    string,
    { promise: Promise<TReturn>; callbacks: MemoizeCallbacks<TReturn>[] }
  >();

  return (...args: [...TArgs, AbortSignal]): Promise<TReturn> => {
    const signal = args.pop() as AbortSignal;
    const fnArgs = args as unknown as TArgs;
    const key = keyResolver ? keyResolver(...fnArgs) : JSON.stringify(fnArgs);

    if (cache.has(key)) {
      const entry = cache.get(key)!;
      const { promise, callbacks } = entry;

      if (signal.aborted) {
        return Promise.reject(new DOMException("Aborted", "AbortError"));
      }

      const newPromise = new Promise<TReturn>((resolve, reject) => {
        callbacks.push({ resolve, reject, signal });
        signal.addEventListener("abort", () => {
          reject(new DOMException("Aborted", "AbortError"));
        });
      });

      promise.then(
        (value: TReturn) => {
          callbacks.forEach((cb) => cb.resolve(value));
        },
        (error: unknown) => {
          callbacks.forEach((cb) => cb.reject(error));
        },
      );

      return newPromise;
    } else {
      if (signal.aborted) {
        return Promise.reject(new DOMException("Aborted", "AbortError"));
      }

      const callbacks: MemoizeCallbacks<TReturn>[] = [];
      const promise = fn(...fnArgs).then(
        (value: TReturn) => {
          cache.delete(key);
          return value;
        },
        (error: unknown) => {
          cache.delete(key);
          throw error;
        },
      );

      cache.set(key, { promise, callbacks });

      const newPromise = new Promise<TReturn>((resolve, reject) => {
        callbacks.push({ resolve, reject, signal });
        signal.addEventListener("abort", () => {
          reject(new DOMException("Aborted", "AbortError"));
        });
      });

      promise.then(
        (value: TReturn) => {
          callbacks.forEach((cb) => cb.resolve(value));
        },
        (error: unknown) => {
          callbacks.forEach((cb) => cb.reject(error));
        },
      );

      return newPromise;
    }
  };
}

export const transpileCode = memoize(
  async (code: string): Promise<string> => {
    const { data, error } = await tryCatch(transpile({ code, originToUse: location.origin }));
    if (error) {
      throw new Error(
        `Transpilation failed: ${error instanceof Error ? error.message : String(error)}`,
      );
    }
    if (data === null || data === undefined) {
      throw new Error("Transpilation returned null or undefined.");
    }
    return data;
  },
  (code: string) => md5(code),
);

/**
 * Message data structure for screenshot responses from the iframe.
 */
interface ScreenshotMessageData {
  type: "screenshot";
  imageData: ImageData;
}

/**
 * Type guard to check if message data is a screenshot response.
 * @param data - The message data to check
 * @returns True if the data is a valid screenshot response
 */
function isScreenshotMessage(data: unknown): data is ScreenshotMessageData {
  return (
    typeof data === "object" &&
    data !== null &&
    "type" in data &&
    (data as ScreenshotMessageData).type === "screenshot" &&
    "imageData" in data
  );
}

/**
 * Captures a screenshot from the iframe content.
 * @returns A promise that resolves with the screenshot image data
 */
export const screenshot = (): Promise<ImageData> => {
  return new Promise<ImageData>((resolve) => {
    const iframe = document.querySelector("iframe");

    const messageHandler = (event: MessageEvent<unknown>): void => {
      if (iframe && event.source === iframe.contentWindow && isScreenshotMessage(event.data)) {
        window.removeEventListener("message", messageHandler);
        resolve(event.data.imageData);
      }
    };

    window.addEventListener("message", messageHandler);

    iframe?.contentWindow?.postMessage(
      {
        type: "screenshot",
        sender: "Runner / Editor",
      },
      "*",
    );
  });
};

/**
 * Message data structure for code execution results from the iframe.
 */
interface CodeExecutionResultMessageData {
  type: "code-execution-result";
  result: RunMessageResult;
}

/**
 * Type guard to check if message data is a code execution result.
 * @param data - The message data to check
 * @returns True if the data is a valid code execution result
 */
function isCodeExecutionResultMessage(data: unknown): data is CodeExecutionResultMessageData {
  return (
    typeof data === "object" &&
    data !== null &&
    "type" in data &&
    (data as CodeExecutionResultMessageData).type === "code-execution-result" &&
    "result" in data
  );
}

/**
 * Executes transpiled code in the iframe and returns the result.
 * @param transpiled - The transpiled JavaScript code to execute
 * @returns A promise that resolves with the execution result or false on failure
 */
export const runCode = async (transpiled: string): Promise<RunMessageResult | false> => {
  return new Promise((resolve) => {
    const iframe = document.querySelector("iframe");
    if (!iframe || !iframe.contentWindow) {
      console.error("No iframe found for code execution");
      return resolve(false);
    }

    const messageHandler = (event: MessageEvent<unknown>): void => {
      if (
        iframe &&
        event.source === iframe.contentWindow &&
        isCodeExecutionResultMessage(event.data)
      ) {
        window.removeEventListener("message", messageHandler);
        resolve(event.data.result);
      }
    };

    window.addEventListener("message", messageHandler);

    iframe.contentWindow.postMessage(
      {
        type: "execute-code",
        code: transpiled,
      },
      "*",
    );

    // Add timeout to prevent hanging
    setTimeout(() => {
      window.removeEventListener("message", messageHandler);
      console.error("Code execution timed out");
      resolve(false);
    }, 5000);
  });
};

export interface EditorInitOptions {
  container: HTMLDivElement;
  codeSpace: string;
  code: string;
  onChange: (newCode: string) => void;
}

export interface EditorInstance {
  getValue: () => string;
  silent: boolean;
  getErrors: () => Promise<string[]>;
  isEdit: boolean;
  setValue: (_newCode: string) => void;
}

export async function initializeMonaco(options: EditorInitOptions): Promise<EditorInstance> {
  const { startMonacoEditor } = await import("../components/app/monaco-edi");
  const { data, error } = await tryCatch(startMonacoEditor(options));
  if (error) {
    throw new Error(`Monaco initialization failed: ${String(error)}`);
  }
  if (!data) {
    throw new Error("Monaco initialization failed: No data returned");
  }
  const { getValue, silent, getErrors, isEdit, setValue } = data;
  return {
    getValue,
    silent,
    getErrors,
    isEdit,
    setValue,
  };
}

import { getCodeSpace } from "./hooks/use-code-space.ts";
import { importMap, importMapReplace } from "./lib/importmap-utils";
import { routes } from "./lib/routes";
import { SessionSynchronizer } from "./services/SessionSynchronizer";
import { tryCatch } from "../lazy-imports/try-catch";
import HTML from "../index.html";

import type { ICodeSession } from "../ui/@/lib/interfaces";
import { sanitizeSession, sessionToJSON } from "./lib/make-sess";

const cSessions: Record<string, SessionSynchronizer> = {};

interface RouteContext {
  request: Request;
  session: ICodeSession;
  codeSpace: string;
  pathname: string;
}

type RouteHandler = (context: RouteContext) => Promise<Response> | Response;
type RouteCondition = (context: RouteContext) => boolean;

interface RouteConfig {
  condition: RouteCondition;
  handler: RouteHandler;
}

// Define route handlers (keeping existing functions, but they might need slight adjustments for context)
async function handleEditorResponseInternal(context: RouteContext): Promise<Response> {
  return handleEditorResponse(context.codeSpace);
}
async function handleHtmlResponseInternal(context: RouteContext): Promise<Response> {
  return handleHtmlResponse(context.session);
}
function handleIndexCssInternal(context: RouteContext): Response {
  return handleIndexCss(context.request, context.session);
}
async function handleIndexJsInternal(context: RouteContext): Promise<Response> {
  return handleIndexJs(context.request, context.session);
}
function handleIndexTsxInternal(context: RouteContext): Response {
  return handleIndexTsx(context.request, context.session);
}
async function handleSessionJsonInternal(context: RouteContext): Promise<Response> {
  return handleSessionJson(context.request, context.session);
}

function isGeneralHtmlRoute({ request, pathname, codeSpace }: RouteContext): boolean {
  const url = request.url;
  // Check if pathname is a key in the routes object
  const isListedRoute = Object.prototype.hasOwnProperty.call(routes, pathname);

  return (
    isListedRoute ||
    url.includes("/hydrated") ||
    url.includes("/worker") ||
    url.includes("/dehydrated") ||
    url.endsWith("/") ||
    (!url.includes("/live/") && !url.startsWith(location.origin + "/api/")) || // Exclude /api/ routes as well
    url.includes("/embed") ||
    url.includes("/public") ||
    url.endsWith(`/live/${codeSpace}/xxx`) ||
    url.endsWith(`/live/${codeSpace}/`)
  );
}

const routeConfigs: RouteConfig[] = [
  {
    condition: ({ request }) => request.url.includes("/session.json"),
    handler: handleSessionJsonInternal,
  },
  {
    condition: ({ request }) => request.url.includes("/index.tsx"),
    handler: handleIndexTsxInternal,
  },
  {
    condition: ({ request }) => request.url.includes("/index.js"),
    handler: handleIndexJsInternal,
  },
  {
    condition: ({ request }) => request.url.includes("/index.css"),
    handler: handleIndexCssInternal,
  },
  {
    condition: isGeneralHtmlRoute,
    handler: handleHtmlResponseInternal,
  },
  {
    condition: ({ request, codeSpace }) => request.url.endsWith(`/live/${codeSpace}`), // This should likely be more specific if it's for the editor view itself
    handler: handleEditorResponseInternal,
  },
];

export async function fakeServer(request: Request) {
  const { pathname: rawPathname } = new URL(request.url);
  const pathname = rawPathname;
  const codeSpace = getCodeSpace(pathname);
  console.warn(
    "CodeSpace:",
    codeSpace,
    "Request URL:",
    request.url,
    "Normalized Pathname:",
    pathname,
  );

  if (!cSessions[codeSpace]) {
    const sessionFetchPromise = fetch(`/live/${codeSpace}/session.json`).then((r) => {
      if (!r.ok) {
        throw new Error(`Failed to fetch initial session for ${codeSpace}: ${r.status}`);
      }
      return r.json() as Promise<ICodeSession>;
    });
    const { data: initialSessionData, error: fetchError } =
      await tryCatch<ICodeSession>(sessionFetchPromise);

    if (fetchError || !initialSessionData) {
      console.error(`Failed to initialize session for ${codeSpace}:`, fetchError);
      return new Response(`Error initializing session: ${fetchError?.message || "Unknown error"}`, {
        status: 500,
      });
    }
    cSessions[codeSpace] = new SessionSynchronizer(codeSpace, initialSessionData);
    initialisedSessions.add(codeSpace); // Mark as initialized after the first successful fetch
  }

  const session = await cSessions[codeSpace]!.init();
  if (!session) {
    console.error(`Session is null after init for ${codeSpace}`);
    return new Response(`Error initializing session: Session is null`, {
      status: 500,
    });
  }

  const context: RouteContext = { request, session, codeSpace, pathname };

  for (const config of routeConfigs) {
    if (config.condition(context)) {
      return config.handler(context);
    }
  }

  console.warn("Default request (no route matched):", request.url);
  return fetch(request);
}

async function handleEditorResponse(codeSpace: string) {
  const { data: htmlResponse, error: fetchHtmlError } = await tryCatch(fetch("/index.html"));

  if (fetchHtmlError || !htmlResponse || !htmlResponse.ok) {
    console.error("Failed to fetch base HTML for editor:", fetchHtmlError || htmlResponse?.status);
    return new Response("Failed to fetch base HTML", { status: 500 });
  }

  const { data: baseHtml, error: textError } = await tryCatch(htmlResponse.text());

  if (textError || baseHtml === null) {
    console.error("Failed to get text from base HTML for editor:", textError);
    return new Response("Failed to read base HTML", { status: 500 });
  }

  const respText = baseHtml
    .replace("// IMPORTMAP", JSON.stringify(importMap))
    .replace(
      '<div id="embed"></div>',
      `<div id="embed"><iframe title="Live preview" src="/live/${codeSpace}/"></iframe></div>`,
    );

  const headers = createHtmlResponseHeaders();
  return new Response(respText, { status: 200, headers });
}

