async function handleSessionJson(
  request: Request,
  currentSession: ICodeSession, // Renamed to avoid confusion
) {
  console.warn("Session request:", request.url);
  const codeSpace = getCodeSpace(request.url);
  let sessionToReturn = currentSession;

  // This condition seems to intend to re-fetch if it's NOT the first time for this codeSpace.
  // However, `initialisedSessions` is populated when `!cSessions[codeSpace]` is true in `fakeServer`.
  // If the goal is to always return the latest from the server for /session.json:
  const sessionFetchPromise = fetch(request.url).then((r) => {
    if (!r.ok) {
      throw new Error(`Failed to fetch session for ${codeSpace} in handleSessionJson: ${r.status}`);
    }
    return r.json() as Promise<ICodeSession>;
  });
  const { data: newSessionData, error: fetchError } =
    await tryCatch<ICodeSession>(sessionFetchPromise);

  if (fetchError) {
    console.error(`Failed to fetch session for ${codeSpace} in handleSessionJson:`, fetchError);
    // Fallback to currentSession if fetch fails
  } else if (newSessionData) {
    sessionToReturn = sanitizeSession(newSessionData);
    // Update the central SessionSynchronizer if it exists, or create it.
    // This ensures cSessions[codeSpace] is always up-to-date after a /session.json call.
    if (cSessions[codeSpace]) {
      // It's tricky if cSessions[codeSpace] is already being used by other parts.
      // A full re-initialization might be too disruptive.
      // For now, let's assume the SessionSynchronizer handles internal updates if its session changes.
      // Or, we might need a method on SessionSynchronizer to update its internal session.
      // This part of the logic might need further review based on SessionSynchronizer's capabilities.
      // For simplicity, we'll re-assign if it's different.
      const currentSyncSession = await cSessions[codeSpace]!.getSession();
      if (JSON.stringify(currentSyncSession) !== JSON.stringify(sessionToReturn)) {
        cSessions[codeSpace] = new SessionSynchronizer(codeSpace, sessionToReturn);
      }
    } else {
      cSessions[codeSpace] = new SessionSynchronizer(codeSpace, sessionToReturn);
    }
  }

  return new Response(sessionToJSON(sessionToReturn), {
    headers: {
      "Content-Type": "application/json",
      ...request.headers,
    },
  });
}

import { hash } from "immutable";
import { Md5 } from "ts-md5";

const shortHashCache = new Map<string, string>();

export function md5(input: object | string): string {
  if (!input) input = "empty";

  const strInput = typeof input === "string" ? input : JSON.stringify(input);

  // Check cache
  if (shortHashCache.has(strInput)) {
    return shortHashCache.get(strInput)!;
  }

  // Compute numeric hash
  const hashedValue = hash(Md5.hashStr(strInput));
  let shortKey = intToString(hashedValue);

  // Ensure minimum length of 8
  while (shortKey.length < 8) {
    shortKey += shortKey;
  }
  shortKey = shortKey.slice(0, 8);

  // Store in cache
  shortHashCache.set(strInput, shortKey);

  return shortKey;
}

function intToString(n: number): string {
  // Adjust negative
  if (n < 0) {
    n += 2 ** 31;
  }

  if (n > 2 ** 31) {
    throw new Error("Input must be a 32-bit unsigned integer");
  }

  let num = n;
  const alpha = "abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ";
  const alphanumeric = alpha + "0123456789";

  let base62 = "";
  do {
    base62 = alphanumeric[num % 62] + base62;
    num = Math.floor(num / 62);
  } while (num > 0);

  if (base62.length === 0 || !alpha.includes(base62[0] || "")) {
    base62 = "a" + base62;
  }

  let alphaPart = "";
  let alphanumericPart = "";
  for (const char of base62) {
    if (alphaPart.length === 0 || alpha.includes(char)) {
      alphaPart += char;
    } else {
      alphanumericPart += char;
    }
  }

  return alphaPart + alphanumericPart;
}

import { md5 } from "../crypto-data-structures/md5";
import { routes } from "../core-logic/lib/routes";
const MIME_TYPES: Record<string, string> = {
  ".html": "text/html",
  ".htm": "text/html",
  ".css": "text/css",
  ".js": "application/javascript",
  ".mjs": "application/javascript",
  ".cjs": "application/javascript",
  ".json": "application/json",
  ".ts": "application/typescript",
  ".tsx": "application/typescript",
  ".jsx": "application/javascript",
  ".wasm": "application/wasm",
  ".svg": "image/svg+xml",
  ".png": "image/png",
  ".jpg": "image/jpeg",
  ".jpeg": "image/jpeg",
  ".gif": "image/gif",
  ".webp": "image/webp",
  ".ico": "image/x-icon",
  ".txt": "text/plain",
  ".xml": "text/xml",
  ".pdf": "application/pdf",
  ".zip": "application/zip",
  ".map": "application/json",
  ".woff": "font/woff",
  ".woff2": "font/woff2",
  ".ttf": "font/ttf",
  ".otf": "font/otf",
  ".eot": "application/vnd.ms-fontobject",
  ".mp4": "video/mp4",
  ".webm": "video/webm",
  ".mp3": "audio/mpeg",
  ".wav": "audio/wav",
};

function lookup(path: string): string | false {
  const ext = path.slice(path.lastIndexOf(".")).toLowerCase();
  return MIME_TYPES[ext] || false;
}

// Simplified getContentType function
function getContentType(path: string) {
  return lookup(path) || "application/octet-stream";
}

function getHashHeaderValue(filePath: string, assetHash: string): string {
  const fileParts = filePath.split(".");
  if (fileParts.length < 3) {
    return assetHash;
  }
  return fileParts.at(-2) || assetHash;
}

export const serveWithCache = (files: Record<string, string>, cacheToUse: () => Promise<Cache>) => {
  const ASSET_HASH = files["ASSET_HASH"] || md5(JSON.stringify(files));

  let _fileCache: Cache | null | undefined;
  const fileCachePromise = cacheToUse()
    .then((cache) => {
      _fileCache = cache;
      return cache;
    })
    .catch((error) => {
      console.error("Cache creation failed:", error);
      _fileCache = null; // Indicate that cache is unavailable
    });

  const isAsset = (request: Request) => {
    const url = new URL(request.url);
    const pathname = decodeURIComponent(
      url.pathname.startsWith("/") ? url.pathname.slice(1) : url.pathname,
    );
    const assetPath = pathname.startsWith(ASSET_HASH + "/")
      ? pathname.slice(ASSET_HASH.length + 1)
      : pathname;
    return assetPath in files || pathname in files;
  };

  // Instance-specific in-flight requests map
  const inFlightRequests = new Map<string, Promise<Response>>();

  return {
    isAsset,
    shouldBeCached: (request: Request) => {
      if (isAsset(request)) {
        return true;
      }
      const url = new URL(request.url);
      if (
        url.pathname.startsWith("/live/") ||
        url.pathname.startsWith("/my-cms/") ||
        url.pathname.startsWith("/api/")
      ) {
        return false;
      }
      return !Object.hasOwn(routes, url.pathname);
    },

    serve: async (
      request: Request,
      assetFetcher: (req: Request, waitUntil: (p: Promise<unknown>) => void) => Promise<Response>,
      waitUntil: (p: Promise<unknown>) => void,
    ) => {
      if (request.method !== "GET") {
        return new Response("Method Not Allowed", { status: 405 });
      }

      if (!isAsset(request)) {
        return new Response("Not Found", { status: 404 });
      }

      const url = new URL(request.url);
      const pathname = decodeURIComponent(
        url.pathname.startsWith("/") ? url.pathname.slice(1) : url.pathname,
      );
      const filePath = pathname.startsWith(ASSET_HASH + "/")
        ? pathname.slice(ASSET_HASH.length + 1)
        : pathname;

      if (!(filePath in files)) {
        return new Response("Not Found", { status: 404 });
      }

      if (_fileCache === undefined) {
        await fileCachePromise;
      }

      const cacheUrl = new URL(request.url);
      cacheUrl.pathname = files[filePath] || filePath;
      cacheUrl.search = "";
      cacheUrl.hash = "";

      const cacheKey = new Request(cacheUrl.toString());

      if (_fileCache) {
        // Attempt to find the response in the cache
        const cachedResp = await _fileCache.match(cacheKey);
        if (cachedResp) return cachedResp.clone();

        if (inFlightRequests.has(request.url)) {
          // Wait for the in-flight fetch to complete
          const inFlightResponse = await inFlightRequests.get(request.url)!;
          return inFlightResponse.clone();
        }

        // Construct the new URL based on the files mapping
        const newUrl = new URL(request.url);
        newUrl.pathname = "/" + (files[filePath] || filePath);
        newUrl.pathname = newUrl.pathname.replace(ASSET_HASH + "/", "");

        const req = new Request(newUrl.toString(), {
          method: request.method,
          headers: request.headers,
          redirect: request.redirect,
        });

        // Create a promise to represent the in-flight fetch
        const inFlightPromise = (async (req: Request) => {
          const resolvedFilePath = files[filePath] ? files[filePath] : filePath;
          const hash = getHashHeaderValue(resolvedFilePath, ASSET_HASH);

          let kvResp: Response;
          try {
            kvResp = await assetFetcher(req, waitUntil);
          } catch (error) {
            console.error("Asset fetch error:", error);
            inFlightRequests.delete(request.url);
            return new Response("Internal Server Error", { status: 500 });
          }

          if (!kvResp.ok) {
            inFlightRequests.delete(request.url);
            return kvResp;
          }

          // Clone the body before consuming it
          const bodyClone = await kvResp.clone().arrayBuffer();

          // Clone headers and set appropriate Content-Type
          const headers = new Headers(kvResp.headers);
          const contentType = getContentType(filePath);
          headers.set("Content-Type", contentType);
          headers.set("x-hash", hash);

          // Content-type-aware cache control
          const isHtml = contentType.includes("text/html") || !filePath.includes(".");
          const isHashed = /\.[0-9a-f]{8,}\./.test(filePath);
          if (isHtml) {
            headers.set("Cache-Control", "public, no-cache, must-revalidate");
          } else if (isHashed) {
            headers.set("Cache-Control", "public, max-age=604800, immutable");
          } else {
            headers.set("Cache-Control", "public, max-age=14400, stale-while-revalidate=86400");
          }
          headers.set("Access-Control-Allow-Origin", "*");
          // Access-Control-Allow-Credentials: true
          headers.set("Access-Control-Allow-Credentials", "true");
          // Set security headers
          headers.set("Cross-Origin-Embedder-Policy", "require-corp");

          const response = new Response(bodyClone, {
            status: kvResp.status,
            statusText: kvResp.statusText,
            headers,
          });

          if (response.status === 200) {
            // Cache the response asynchronously if cache is available
            waitUntil(
              _fileCache.put(cacheKey, response.clone()).catch((error) => {
                console.error("Cache put error:", error);
              }),
            );
          }

          // Remove the in-flight request from the map
          inFlightRequests.delete(request.url);

          return response.clone();
        })(req);

        // Store the in-flight promise
        inFlightRequests.set(request.url, inFlightPromise);

        // Await the in-flight fetch and ensure we return a cloned response
        const response = await inFlightPromise;
        return response.clone();
      }

      // If we reach here, it means the cache is not available
      return new Response("Service Unavailable", { status: 503 });
    },
  };
};

import { getAtaCache, setAtaCache } from "../core-logic/lib/idb-cache";
import { QueuedFetch } from "../http-client/queued-fetch";
import { tryCatch } from "./try-catch";
import { setupTypeAcquisition } from "@typescript/ata";
import ts from "typescript";

// Keep the globalThis reference style for shared worker compatibility

interface ExtraLib {
  filePath: string;
  content: string;
}

// Consolidated path cleaning logic
export function cleanFilePath(filePath: string, originToUse: string): string {
  // Remove potential origins and CDN prefixes
  let cleaned = filePath
    .replace(originToUse, "")
    .replace("https://spike.land", "")
    .replace("https://esm.spike.land", "");

  // Remove node_modules, @types, version paths (e.g., /v18/)
  cleaned = cleaned
    .replace(/\/node_modules\//g, "/")
    .replace(/@types\//g, "")
    .replace(/dist\//g, "")
    .replace(/types\//g, "")
    .replace(/src\//g, "")
    .replace(/declarations\//g, "")
    .replace(/\/v\d+\//g, "/");
  // Remove specific TS version paths if they appear
  cleaned = cleaned.replace(/ts\d+\.\d+\//g, "");

  // Remove version numbers like @1.2.3
  cleaned = cleaned.replace(/@(\^)?\d+(\.)?\d+(\.)?\d+/g, "");

  // Normalize paths starting with /
  if (!cleaned.startsWith("/")) {
    cleaned = `/${cleaned}`;
  }

  // Remove any double slashes that might have been introduced
  cleaned = cleaned.replace(/\/\//g, "/");

  // Ensure it doesn't end with .d.ts/ - this shouldn't happen with ATA VFS keys but good practice
  cleaned = cleaned.replace(/\.d\.ts\//g, "/");

  return cleaned;
}

// Consolidated content cleaning logic
export function cleanFileContent(content: string, originToUse: string): string {
  // Perform similar cleaning on content, focusing on import/reference paths
  let cleaned = content
    .replace(new RegExp(originToUse, "g"), "")
    .replace(/https:\/\/spike\.land/g, "")
    .replace(/https:\/\/esm\.sh/g, "");

  // Clean paths within the content
  cleaned = cleaned
    .replace(/\/node_modules\//g, "/")
    .replace(/@types\//g, "")
    .replace(/dist\//g, "")
    .replace(/types\//g, "")
    .replace(/src\//g, "")
    .replace(/declarations\//g, "");

  // Remove version numbers like @1.2.3
  cleaned = cleaned.replace(/@(\^)?\d+(\.)?\d+(\.)?\d+/g, "");

  // Remove specific TS version paths if they appear
  cleaned = cleaned.replace(/ts\d+\.\d+\//g, "");

  // Fix potentially broken import paths if origin was stripped
  cleaned = cleaned.replace(/from "\//g, 'from "').replace(/path="\//g, 'path="');

  // Ensure it doesn't end with .d.ts/
  cleaned = cleaned.replace(/\.d\.ts\//g, "/");

  return cleaned;
}

// Helper to extract import specifiers from code
export function extractImportSpecifiers(code: string): string[] {
  const sourceFile = ts.createSourceFile(
    "temp.tsx", // Temporary filename, doesn't matter
    code,
    ts.ScriptTarget.Latest,
    true, // setParentNodes
    ts.ScriptKind.TSX, // Assume TSX for flexibility
  );

  const imports: string[] = [];

  function visit(node: ts.Node) {
    // Check for import declarations: import ... from "specifier";
    if (ts.isImportDeclaration(node) && ts.isStringLiteral(node.moduleSpecifier)) {
      imports.push(node.moduleSpecifier.text);
    } // Check for dynamic imports: import("specifier")
    else if (ts.isCallExpression(node) && node.expression.kind === ts.SyntaxKind.ImportKeyword) {
      const arg = node.arguments[0];
      if (arg && ts.isStringLiteral(arg)) {
        imports.push(arg.text);
      }
    } // Check for require calls: require("specifier") - less common in ESM workers but good to have
    else if (
      ts.isCallExpression(node) &&
      ts.isIdentifier(node.expression) &&
      node.expression.text === "require"
    ) {
      const arg = node.arguments[0];
      if (arg && ts.isStringLiteral(arg)) {
        imports.push(arg.text);
      }
    }
    // Triple-slash directives are handled via comment parsing below

    ts.forEachChild(node, visit);
  }

  // Also check for triple-slash references in comments
  ts.forEachLeadingCommentRange(sourceFile.text, sourceFile.getFullStart(), (pos, end, kind) => {
    if (
      kind === ts.SyntaxKind.MultiLineCommentTrivia ||
      kind === ts.SyntaxKind.SingleLineCommentTrivia
    ) {
      const commentText = sourceFile.text.substring(pos, end);
      const match = commentText.match(/<reference\s+path=["']([^"']+)["']\s*\/>/);
      if (match && match[1]!) {
        imports.push(match[1]!);
      }
    }
  });

  visit(sourceFile);
  return [...new Set(imports)]; // Return unique specifiers
}

// Main refactored ATA function
export async function ata({
  code,
  originToUse,
}: {
  code: string;
  originToUse: string;
}): Promise<ExtraLib[]> {
  const queuedFetch = new QueuedFetch(4, 10000, 100); // Keep adjusted settings

  // Wrap fetch with IDB cache for type definition responses
  const cachedFetch: typeof fetch = async (input, init?) => {
    const url =
      typeof input === "string" ? input : input instanceof URL ? input.toString() : input.url;
    const cached = await getAtaCache(url);
    if (cached !== null) {
      return new Response(cached, {
        status: 200,
        headers: { "x-idb-cache": "hit" },
      });
    }
    const fetchInput = input instanceof URL ? input.toString() : input;
    const response = await queuedFetch.fetch(fetchInput, init);
    if (response.ok) {
      const text = await response.text();
      await setAtaCache(url, text);
      return new Response(text, {
        status: response.status,
        headers: response.headers,
      });
    }
    return response;
  };

  // 1. Extract imports from the original code first
  const extCode = `${code}
import "react";
import "@emotion/react";
import * as JSXruntime from "@emotion/react/jsx-runtime";
import "react/jsx-runtime";
import "react/jsx-dev-runtime";
import "react/jsx-runtime/jsx-dev-runtime";
import "react/jsx-runtime/jsx-dev-runtime.d.ts";
import "react/jsx-dev-runtime/jsx-dev-runtime.d.ts";
import "react/jsx-dev-runtime/jsx-dev-runtime";
import "react/jsx-dev-runtime/jsx-dev-runtime.d.ts";
// Add other common implicit dependencies if necessary
`;
  const importSpecifiers = extractImportSpecifiers(extCode);

  // 2. Run ATA
  const { data: vfs, error: vfsError } = await tryCatch(
    new Promise<Map<string, string>>((resolve) =>
      setupTypeAcquisition({
        projectName: "MonacoEditorTypes",
        typescript: ts,
        logger: console, // Keep console for ATA's internal logger, or create a more complex adapter
        fetcher: cachedFetch as typeof fetch,
        delegate: {
          started: () => {},
          progress: () => {},
          receivedFile: () => {},
          errorMessage: (userFacingMessage, error) =>
            console.error(`[ATA] Error: ${userFacingMessage}`, error),
          finished: (vfsMap) => {
            resolve(vfsMap);
          },
        },
      })(extCode),
    ),
  );

  if (vfsError) {
    console.error("[ATA] Failed to acquire types:", vfsError);
    return [];
  }

  // 3. Process ATA VFS
  const processedLibs: Record<string, string> = {};
  for (const [filePath, content] of vfs.entries()) {
    const cleanedPath = cleanFilePath(filePath, originToUse);
    const cleanedContent = cleanFileContent(content, originToUse);
    if (!processedLibs[cleanedPath]) {
      processedLibs[cleanedPath] = cleanedContent;
    }
  }

  // 4. Identify & Fetch Missing Aliased Imports and /live/ Imports
  const aliasPrefix = "@/";
  const livePrefix = "/live/";
  const extraFetchPromises: Array<Promise<void>> = [];

  for (const specifier of importSpecifiers) {
    if (specifier.startsWith(aliasPrefix)) {
      const mappedPath = specifier;
      // Construct the expected final path *after* cleaning
      const expectedCleanedPath = cleanFilePath(`/${mappedPath}.d.ts`, originToUse); // Assume .d.ts extension

      if (!processedLibs[expectedCleanedPath]) {
        const fetchUrl = `${originToUse}/${mappedPath}.d.ts`;

        extraFetchPromises.push(
          cachedFetch(fetchUrl)
            .then(async (response) => {
              if (response.ok) {
                const content = await response.text();
                const finalFilePath = cleanFilePath(fetchUrl, originToUse);
                const cleanedContent = cleanFileContent(content, originToUse);

                if (!processedLibs[finalFilePath]) {
                  processedLibs[finalFilePath] = cleanedContent;
                }
              }
            })
            .catch((error) => {
              console.error(
                `[ATA] Error fetching aliased import ${specifier} from ${fetchUrl}:`,
                error,
              );
            }),
        );
      }
    }

    // Handle /live/ cross-codespace imports
    if (specifier.startsWith(livePrefix)) {
      const codeSpaceName = specifier.slice(livePrefix.length).split("/")[0];
      if (!codeSpaceName) continue;

      const fetchUrl = `${originToUse}/live/${codeSpaceName}/index.tsx`;
      const dtsPath = `/live/${codeSpaceName}.d.ts`;
      const barePath = `/live/${codeSpaceName}`;

      if (!processedLibs[dtsPath]) {
        extraFetchPromises.push(
          cachedFetch(fetchUrl)
            .then(async (response) => {
              if (response.ok) {
                const content = await response.text();
                if (!processedLibs[dtsPath]) {
                  processedLibs[dtsPath] = content;
                }
                if (!processedLibs[barePath]) {
                  processedLibs[barePath] = content;
                }
              }
            })
            .catch((error) => {
              console.error(`[ATA] Error fetching /live/ import ${specifier}:`, error);
            }),
        );
      }
    }
  }

  // Wait for all extra fetches to complete
  const { error: extraFetchError } = await tryCatch(Promise.all(extraFetchPromises));
  if (extraFetchError) {
    console.error("[ATA] Error during extra fetches:", extraFetchError);
  }

  // 5. Finalize
  const extraLibs: ExtraLib[] = Object.entries(processedLibs)
    .map(([filePath, content]) => ({ filePath, content }))
    .sort((a, b) => a.filePath.localeCompare(b.filePath));

  // Optimized package.json filtering
  const filePaths = new Set(extraLibs.map((lib) => lib.filePath));
  const filteredLibs = extraLibs.filter((lib) => {
    if (lib.filePath.endsWith("/package.json")) {
      const indexDts = lib.filePath.replace("/package.json", "/index.d.ts");
      return !filePaths.has(indexDts);
    }
    if (lib.filePath.endsWith(".mts")) {
      const mts = lib.filePath.replace(".mts", ".d.ts").replace(".d.d", ".d");
      return !filePaths.has(mts);
    }
    return true;
  });

  return filteredLibs;
}

