        </CardTitle>
      </CardHeader>
      <CardContent className={cardContentClasses}>
        {suggestions.map((suggestion, index) => (
          <Button
            key={index}
            variant="outline"
            className={cn(
              buttonClasses,
              isDarkMode
                ? "hover:bg-gray-700/50 active:bg-gray-600/50 border-gray-700"
                : "hover:bg-gray-50 active:bg-gray-100 border-gray-200",
