}

export function definePlatformMonacoTheme(
  monaco: {
    editor: {
      defineTheme: (name: string, data: MonacoEditor.IStandaloneThemeData) => void;
    };
  },
  isDark: boolean,
): string {
  const tokens = readThemeTokens(isDark);
  monaco.editor.defineTheme(SPIKE_PLATFORM_MONACO_THEME, createMonacoThemeData(tokens, isDark));
  return SPIKE_PLATFORM_MONACO_THEME;
}

export function getTheme(isDark: boolean): MonacoThemeColors {
  return createThemeColors(readThemeTokens(isDark), isDark);
}

export function getGutterWidth(lineCount: number): number {
  const digits = Math.max(1, String(lineCount).length);
  return Math.ceil(digits * CHAR_WIDTH + GUTTER_PADDING);
}

export interface HighlightSegment {
  startOffset: number;
  endOffset: number;
  className: string;
}

const JSX_EXTENSIONS = new Set(["tsx", "jsx"]);
const TAILWIND_ATTRS = new Set(["class", "className", "tw"]);
const TAILWIND_HELPERS = /\b(?:cn|clsx|twMerge)\s*\(/g;
const TAG_NAME = /[A-Za-z][\w.-]*/y;
const ATTR_NAME = /[A-Za-z_:][\w:.-]*/y;
const WHITESPACE = /\s*/y;

type TailwindTokenKind =
  | "spike-tailwind-layout"
  | "spike-tailwind-spacing"
  | "spike-tailwind-color"
  | "spike-tailwind-utility";

export function isJsxLikeFile(fileName?: string): boolean {
  const ext = fileName?.split(".").pop()?.toLowerCase();
  return ext !== undefined && JSX_EXTENSIONS.has(ext);
}

export function collectEditorHighlightSegments(code: string, fileName?: string): HighlightSegment[] {
  const segments: HighlightSegment[] = [];

  if (isJsxLikeFile(fileName)) {
    segments.push(...collectJsxSegments(code));
    segments.push(...collectHelperTailwindSegments(code));
  }

  return segments;
}

function collectJsxSegments(code: string): HighlightSegment[] {
  const segments: HighlightSegment[] = [];
  let index = 0;

  while (index < code.length) {
    if (startsWith(code, index, "//")) {
      index = skipLineComment(code, index);
      continue;
    }

    if (startsWith(code, index, "/*")) {
      index = skipBlockComment(code, index);
      continue;
    }

    if (isQuote(code[index])) {
      index = skipString(code, index);
      continue;
    }

    if (code[index] === "<") {
      const parsed = parseJsxTag(code, index);
      if (parsed !== null) {
        segments.push(...parsed.segments);
        index = parsed.endOffset;
        continue;
      }
    }

    index += 1;
  }

  return segments;
}

function collectHelperTailwindSegments(code: string): HighlightSegment[] {
  const segments: HighlightSegment[] = [];

  for (const match of code.matchAll(TAILWIND_HELPERS)) {
    const openParenIndex = match.index! + match[0].length - 1;
    const expressionEnd = findMatchingBracket(code, openParenIndex, "(", ")");
    if (expressionEnd === -1) continue;

    const expression = code.slice(openParenIndex + 1, expressionEnd);
    segments.push(...collectTailwindStringSegments(expression, openParenIndex + 1));
  }

  return segments;
}

function parseJsxTag(
  code: string,
  startOffset: number,
): { endOffset: number; segments: HighlightSegment[] } | null {
  let index = startOffset + 1;
  const segments: HighlightSegment[] = [];

  if (code[index] === "/") {
    index += 1;
  }

  TAG_NAME.lastIndex = index;
  const tagMatch = TAG_NAME.exec(code);
  if (tagMatch === null) return null;

  const tagNameStart = index;
  const tagNameEnd = index + tagMatch[0].length;

  if (!looksLikeJsxTag(code, startOffset, tagNameEnd)) {
    return null;
  }

  segments.push({
    startOffset: tagNameStart,
    endOffset: tagNameEnd,
    className: "spike-jsx-tag",
  });

  index = tagNameEnd;

  while (index < code.length) {
    WHITESPACE.lastIndex = index;
    const whitespaceMatch = WHITESPACE.exec(code);
    index = whitespaceMatch?.index === index ? whitespaceMatch[0].length + index : index;

    if (startsWith(code, index, "/>")) {
      return { endOffset: index + 2, segments };
    }

    if (code[index] === ">") {
      return { endOffset: index + 1, segments };
    }

    ATTR_NAME.lastIndex = index;
    const attrMatch = ATTR_NAME.exec(code);

    if (attrMatch === null) {
      index += 1;
      continue;
    }

    const attrName = attrMatch[0];
    const attrStart = index;
    const attrEnd = index + attrName.length;
    segments.push({
      startOffset: attrStart,
      endOffset: attrEnd,
      className: "spike-jsx-attr",
    });

    index = attrEnd;
    WHITESPACE.lastIndex = index;
    const postAttrWhitespace = WHITESPACE.exec(code);
    index = postAttrWhitespace?.index === index ? postAttrWhitespace[0].length + index : index;

    if (code[index] !== "=") {
      continue;
    }

    index += 1;
    WHITESPACE.lastIndex = index;
    const postEqualsWhitespace = WHITESPACE.exec(code);
    index =
      postEqualsWhitespace?.index === index ? postEqualsWhitespace[0].length + index : index;

    const current = code[index];
    if (current === undefined) break;

    if (isQuote(current)) {
      const stringEnd = findStringEnd(code, index);
      if (stringEnd === -1) break;

      if (TAILWIND_ATTRS.has(attrName)) {
        segments.push(...collectTailwindSegmentsFromLiteral(code.slice(index + 1, stringEnd), index + 1));
      } else {
        segments.push({
          startOffset: index + 1,
          endOffset: stringEnd,
          className: "spike-jsx-attr-value",
        });
      }

      index = stringEnd + 1;
      continue;
    }

    if (current === "{") {
      const expressionEnd = findMatchingBracket(code, index, "{", "}");
      if (expressionEnd === -1) break;

      if (TAILWIND_ATTRS.has(attrName)) {
        const expression = code.slice(index + 1, expressionEnd);
        segments.push(...collectTailwindStringSegments(expression, index + 1));
      }

      index = expressionEnd + 1;
      continue;
    }
  }

  return null;
}

function looksLikeJsxTag(code: string, tagStart: number, tagNameEnd: number): boolean {
  const next = code[tagNameEnd];
  if (next === ">" || next === "/" || next === " " || next === "\n" || next === "\t") {
    return true;
  }

  if (next === "=") {
    return false;
  }

  if (code[tagStart + 1] === "/") {
    return true;
  }

  return false;
}

function collectTailwindStringSegments(expression: string, offsetBase: number): HighlightSegment[] {
  const segments: HighlightSegment[] = [];
  let index = 0;

  while (index < expression.length) {
    const char = expression[index];

    if (char === "/" && expression[index + 1] === "/") {
      index = skipLineComment(expression, index);
      continue;
    }

    if (char === "/" && expression[index + 1] === "*") {
      index = skipBlockComment(expression, index);
      continue;
    }

    if (!isQuote(char)) {
      index += 1;
      continue;
    }

    const end = findStringEnd(expression, index);
    if (end === -1) break;

    segments.push(...collectTailwindSegmentsFromLiteral(expression.slice(index + 1, end), offsetBase + index + 1));
    index = end + 1;
  }

  return segments;
}

function collectTailwindSegmentsFromLiteral(value: string, startOffset: number): HighlightSegment[] {
  const segments: HighlightSegment[] = [];
  const tokenRegex = /\S+/g;

  for (const match of value.matchAll(tokenRegex)) {
    const token = match[0];
    const tokenStart = startOffset + match.index!;
    const tokenParts = splitTailwindToken(token);

    if (tokenParts.length === 0) continue;

    let cursor = tokenStart;
    for (const prefix of tokenParts.slice(0, -1)) {
      segments.push({
        startOffset: cursor,
        endOffset: cursor + prefix.length + 1,
        className: "spike-tailwind-variant",
      });
      cursor += prefix.length + 1;
    }

    const utility = tokenParts[tokenParts.length - 1]!;
    segments.push({
      startOffset: cursor,
      endOffset: cursor + utility.length,
      className: classifyTailwindToken(utility),
    });
  }

  return segments;
}

function splitTailwindToken(token: string): string[] {
  const parts: string[] = [];
  let bracketDepth = 0;
  let current = "";

  for (const char of token) {
    if (char === "[" || char === "(" || char === "{") bracketDepth += 1;
    if (char === "]" || char === ")" || char === "}") bracketDepth = Math.max(0, bracketDepth - 1);

    if (char === ":" && bracketDepth === 0) {
      parts.push(current);
      current = "";
      continue;
    }

    current += char;
  }

  if (current.length > 0) {
    parts.push(current);
  }

  return parts.filter(Boolean);
}

function classifyTailwindToken(token: string): TailwindTokenKind {
  if (
    /^(?:absolute|relative|fixed|sticky|block|inline|inline-block|inline-flex|flex|grid|hidden|contents|table|justify-|items-|content-|place-|self-|overflow-|object-|z-|basis-|grow|shrink|order-)/.test(
      token,
    )
  ) {
    return "spike-tailwind-layout";
  }

  if (
    /^(?:p|px|py|pt|pr|pb|pl|m|mx|my|mt|mr|mb|ml|space-x|space-y|gap|w|h|min-w|min-h|max-w|max-h|size|inset|top|right|bottom|left)-/.test(
      token,
    )
  ) {
    return "spike-tailwind-spacing";
  }

  if (
    /^(?:bg|text|border|ring|outline|shadow|from|via|to|decoration|caret|fill|stroke|placeholder)-/.test(
      token,
    )
  ) {
    return "spike-tailwind-color";
  }

  return "spike-tailwind-utility";
}

function findMatchingBracket(
  value: string,
  openIndex: number,
  openChar: string,
  closeChar: string,
): number {
  let depth = 0;
  let index = openIndex;

  while (index < value.length) {
    if (startsWith(value, index, "//")) {
      index = skipLineComment(value, index);
      continue;
    }

    if (startsWith(value, index, "/*")) {
      index = skipBlockComment(value, index);
      continue;
    }

    if (isQuote(value[index])) {
      index = skipString(value, index);
      continue;
    }

    if (value[index] === openChar) depth += 1;
    if (value[index] === closeChar) {
      depth -= 1;
      if (depth === 0) return index;
    }

    index += 1;
  }

  return -1;
}

function skipLineComment(value: string, start: number): number {
  const end = value.indexOf("\n", start);
  return end === -1 ? value.length : end + 1;
}

function skipBlockComment(value: string, start: number): number {
  const end = value.indexOf("*/", start + 2);
  return end === -1 ? value.length : end + 2;
}

function skipString(value: string, start: number): number {
  const end = findStringEnd(value, start);
  return end === -1 ? value.length : end + 1;
}

function findStringEnd(value: string, start: number): number {
  const quote = value[start];
  let index = start + 1;

  while (index < value.length) {
    if (value[index] === "\\") {
      index += 2;
      continue;
    }

    if (value[index] === quote) {
      return index;
    }

    index += 1;
  }

  return -1;
}

function isQuote(value: string | undefined): value is '"' | "'" | "`" {
  return value === '"' || value === "'" || value === "`";
}

function startsWith(value: string, index: number, needle: string): boolean {
  return value.slice(index, index + needle.length) === needle;
}

import { useRef, useState, useEffect, useCallback } from "react";
import { useSpikeChat, type AppUpdatedEvent } from "../hooks/useSpikeChat";
import { Send, Wifi, WifiOff, Loader2 } from "lucide-react";

interface SpikeChatPanelProps {
  channelId: string;
  onAppUpdated?: (event: AppUpdatedEvent) => void;
  className?: string;
}

export function SpikeChatPanel({ channelId, onAppUpdated, className = "" }: SpikeChatPanelProps) {
  const { messages, isConnected, isLoading, typingUsers, sendMessage, startTyping, stopTyping } =
    useSpikeChat({ channelId, onAppUpdated });

  const [input, setInput] = useState("");
  const [isSending, setIsSending] = useState(false);
  const messagesEndRef = useRef<HTMLDivElement>(null);
  const scrollContainerRef = useRef<HTMLDivElement>(null);
  const isAtBottomRef = useRef(true);
  const initialScrollDoneRef = useRef(false);

  // Track if user is at bottom
  const handleScroll = useCallback(() => {
    const el = scrollContainerRef.current;
    if (!el) return;
    isAtBottomRef.current = el.scrollHeight - el.scrollTop - el.clientHeight < 50;
  }, []);

  // Auto-scroll only if user was at the bottom
  useEffect(() => {
    if (isAtBottomRef.current) {
      messagesEndRef.current?.scrollIntoView({ behavior: "smooth" });
    }
  }, [messages]);

  // Scroll to bottom on initial load — runs once when loading finishes and messages are available
  useEffect(() => {
    if (!isLoading && messages.length > 0 && !initialScrollDoneRef.current) {
      initialScrollDoneRef.current = true;
      messagesEndRef.current?.scrollIntoView();
    }
  }, [isLoading, messages.length]);

  const handleSend = async () => {
    const text = input.trim();
    if (!text || isSending) return;
    setIsSending(true);
    setInput("");
    stopTyping();
    try {
      await sendMessage(text);
    } catch {
      setInput(text); // restore on error
    } finally {
      setIsSending(false);
    }
  };

  const handleKeyDown = (e: React.KeyboardEvent<HTMLTextAreaElement>) => {
    if (e.key === "Enter" && !e.shiftKey) {
      e.preventDefault();
      handleSend();
    }
  };

  const handleInputChange = (e: React.ChangeEvent<HTMLTextAreaElement>) => {
    setInput(e.target.value);
    if (e.target.value.trim()) startTyping();
    else stopTyping();
  };

  const formatTime = (ts: number) => {
    const d = new Date(ts);
    return d.toLocaleTimeString(undefined, { hour: "2-digit", minute: "2-digit" });
  };

  // Avatar background color derived from userId using CSS variable palette tokens
  const avatarBgColor = (uid: string): string => {
    const vars = [
      "var(--color-blue-500)",
      "var(--color-emerald-500)",
      "var(--color-amber-500)",
      "var(--color-purple-500)",
      "var(--color-pink-500)",
      "var(--color-cyan-500)",
      "var(--color-red-500)",
      "var(--color-indigo-500)",
    ];
    let hash = 0;
    for (let i = 0; i < uid.length; i++) hash = (hash * 31 + uid.charCodeAt(i)) | 0;
    return vars[Math.abs(hash) % vars.length] ?? vars[0]!;
  };

  const isBot = (uid: string) => uid.startsWith("agent-") || uid === "system";

  return (
    <div className={`flex flex-col h-full ${className}`}>
      {/* Header */}
      <div className="flex items-center gap-2 px-4 py-2 border-b border-border bg-muted/30">
        <span className="font-semibold text-sm text-foreground">
          # {channelId.replace(/^app-/, "")}
        </span>
        <span className="ml-auto flex items-center gap-1 text-xs text-muted-foreground">
          {isConnected ? (
            <>
              <Wifi className="w-3 h-3 text-[var(--success-color)]" />
              Connected
            </>
          ) : (
            <>
              <WifiOff className="w-3 h-3 text-destructive" />
              Reconnecting...
            </>
          )}
        </span>
      </div>

      {/* Messages */}
      <div
        ref={scrollContainerRef}
        onScroll={handleScroll}
        className="flex-1 overflow-y-auto p-4 space-y-3"
        role="log"
        aria-label="Chat messages"
      >
        {isLoading ? (
          <div className="flex items-center justify-center py-8">
            <Loader2 className="w-5 h-5 animate-spin text-muted-foreground" />
          </div>
        ) : messages.length === 0 ? (
          <p className="text-center text-sm text-muted-foreground py-8">
            No messages yet. Start the conversation!
          </p>
        ) : (
          messages.map((msg) => (
            <div
              key={msg.id}
              className="flex gap-2.5 animate-in fade-in slide-in-from-bottom-1 duration-200"
            >
              <div
                className="w-7 h-7 rounded-full shrink-0 flex items-center justify-center text-xs font-bold text-white"
                style={{ backgroundColor: avatarBgColor(msg.userId) }}
              >
                {msg.userId.charAt(0).toUpperCase()}
              </div>
              <div className="min-w-0 flex-1">
                <div className="flex items-baseline gap-2">
                  <span
                    className={`text-sm font-semibold ${isBot(msg.userId) ? "text-primary" : "text-foreground"}`}
                  >
                    {isBot(msg.userId) ? "Bot" : msg.userId.split("-")[0]}
                  </span>
                  <span className="text-[10px] text-muted-foreground">
                    {formatTime(msg.createdAt)}
                  </span>
                  {msg.contentType === "app_updated" && (
                    <span className="text-[10px] font-medium text-primary bg-primary/10 px-1.5 py-0.5 rounded-full">
                      update
                    </span>
                  )}
                </div>
                <p className="text-sm text-foreground/90 whitespace-pre-wrap break-words mt-0.5">
                  {msg.content}
                </p>
              </div>
            </div>
          ))
        )}

        {typingUsers.length > 0 && (
          <div className="text-xs text-muted-foreground italic animate-pulse">
            {typingUsers.join(", ")} {typingUsers.length === 1 ? "is" : "are"} typing...
          </div>
        )}
        <div ref={messagesEndRef} />
      </div>

      {/* Input */}
      <div className="border-t border-border p-3 bg-card">
        <div className="flex gap-2">
          <textarea
            value={input}
            onChange={handleInputChange}
            onKeyDown={handleKeyDown}
            placeholder="Type a message..."
            rows={1}
            aria-label="Chat message input"
            className="flex-1 resize-none rounded-lg border border-border bg-muted/30 px-3 py-2 text-sm
                       placeholder:text-muted-foreground focus:outline-none focus:ring-1 focus:ring-primary
                       max-h-32"
            disabled={isSending}
          />
          <button
            onClick={handleSend}
            disabled={!input.trim() || isSending || !isConnected}
            className="shrink-0 rounded-lg bg-primary px-3 py-2 text-primary-foreground
                       disabled:opacity-50 disabled:cursor-not-allowed hover:bg-primary/90 transition-colors"
            aria-label="Send message"
          >
            {isSending ? (
              <Loader2 className="w-4 h-4 animate-spin" />
            ) : (
              <Send className="w-4 h-4" />
            )}
          </button>
        </div>
        <p className="text-[10px] text-muted-foreground mt-1">
          Press Enter to send, Shift+Enter for new line
        </p>
      </div>
    </div>
  );
}

import { useState, useEffect, useCallback, useMemo } from "react";
import { Play, Loader2, Zap } from "lucide-react";
import { useMcpTools, useMcpToolCall } from "../../src/hooks/useMcp";
import { deriveSurface } from "../../../core-logic/derive-surface";
import type { SurfaceSpec } from "../../../core-logic/derive-surface";
import { FieldGroup } from "./FieldGroup";
import { ResultRenderer } from "./ResultRenderer";
import { formatIdentifier } from "./formatting";

interface ToolSurfaceProps {
  toolName: string;
  appSlug?: string;
  graph?: Record<string, unknown>;
  session?: { outputs: Record<string, unknown> };
  recordToolResult?: (tool: string, input: Record<string, unknown>, result: unknown) => void;
  isAvailable?: boolean;
  defaultExpanded?: boolean;
  initialData?: Record<string, unknown>;
}

export function ToolSurface({
  toolName,
  graph,
  session,
  recordToolResult,
  isAvailable = true,
  defaultExpanded = false,
  initialData,
}: ToolSurfaceProps) {
  const [expanded, setExpanded] = useState(defaultExpanded);
  const [formData, setFormData] = useState<Record<string, unknown>>(initialData ?? {});
  const [lastResult, setLastResult] = useState<unknown>(null);

  const { data: toolsData, isLoading: toolsLoading } = useMcpTools();
  const { mutate: callTool, isPending, data: result, error } = useMcpToolCall();

  const toolDef = toolsData?.tools?.find((t) => t.name === toolName);

  const surface: SurfaceSpec | null = useMemo(() => {
    if (!toolDef) return null;
    return deriveSurface({
      name: toolDef.name,
      description: toolDef.description,
      inputSchema: toolDef.inputSchema as {
        type: "object";
        properties?: Record<
          string,
          {
            type: string;
            description?: string;
            enum?: string[];
            default?: unknown;
            items?: unknown;
            properties?: unknown;
            required?: string[];
          }
        >;
        required?: string[];
      },
      examples: (toolDef as Record<string, unknown>).examples as
        | Array<{ label?: string; args?: Record<string, unknown> }>
        | undefined,
    });
  }, [toolDef]);

  // Initialize form defaults from surface spec
  useEffect(() => {
    if (!surface || Object.keys(formData).length > 0) return;
    const defaults: Record<string, unknown> = {};
    const allFields = [
      ...surface.fieldGroups.flatMap((g) => g.fields),
      ...(surface.advancedGroup?.fields ?? []),
    ];
    for (const field of allFields) {
      if (field.defaultValue !== undefined) {
        defaults[field.name] = field.defaultValue;
      } else if (field.inputType === "boolean") {
        defaults[field.name] = false;
      } else if (field.inputType === "number") {
        defaults[field.name] = 0;
      } else if (field.inputType === "enum" && field.enumValues?.length) {
        defaults[field.name] = field.enumValues[0];
      } else if (field.inputType === "array") {
        defaults[field.name] = [];
      } else if (field.inputType === "object") {
        defaults[field.name] = {};
      } else {
        defaults[field.name] = "";
      }
    }
    setFormData({ ...defaults, ...(initialData ?? {}) });
  }, [surface, initialData, formData]);

  // Pre-fill from session graph
  useEffect(() => {
    if (!graph || !session) return;
    const toolGraph = graph[toolName] as { inputs?: Record<string, unknown> } | undefined;
    if (!toolGraph?.inputs) return;

    const prefill: Record<string, unknown> = {};
    for (const [key, val] of Object.entries(toolGraph.inputs)) {
      if (typeof val === "string" && val.startsWith("from:")) {
        const path = val.slice(5);
        if (session.outputs[path] !== undefined) {
          prefill[key] = session.outputs[path];
        }
      }
    }
    if (Object.keys(prefill).length > 0) {
      setFormData((prev) => ({ ...prev, ...prefill }));
    }
  }, [session?.outputs, graph, toolName, setFormData]);

  // Record result to session
  useEffect(() => {
    if (result) {
      setLastResult(result);
      recordToolResult?.(toolName, formData, result);
    }
  }, [result, toolName, formData, recordToolResult]);

  const handleFieldChange = useCallback((key: string, value: unknown) => {
    setFormData((prev) => ({ ...prev, [key]: value }));
  }, []);

  const handleExecute = useCallback(() => {
    callTool({ name: toolName, args: formData });
  }, [callTool, toolName, formData]);

  const handleExampleClick = useCallback((data: Record<string, unknown>) => {
    setFormData((prev) => ({ ...prev, ...data }));
  }, []);

  if (toolsLoading) {
    return (
      <div className="rubik-panel p-4 flex items-center gap-2 text-muted-foreground">
        <Loader2 className="w-4 h-4 animate-spin" />
        <span className="text-sm">Loading tool...</span>
      </div>
    );
  }

  if (!surface) {
    return (
      <div className="rubik-panel p-4 text-sm text-muted-foreground">
        Tool <code className="font-mono text-primary">{toolName}</code> not found.
      </div>
    );
  }

  return (
    <div className="rubik-panel overflow-hidden">
      <button
        type="button"
        onClick={() => setExpanded(!expanded)}
        className="w-full flex items-center justify-between gap-4 px-5 py-4 text-left transition-colors hover:bg-muted/20"
      >
        <div className="flex items-center gap-3 min-w-0">
          <div className="flex h-12 w-12 shrink-0 items-center justify-center rounded-2xl bg-primary/10 text-primary ring-1 ring-primary/10">
            <Zap className="w-5 h-5" />
          </div>
          <div className="min-w-0">
            <div className="flex flex-wrap items-center gap-2">
              <span className="block text-lg font-semibold tracking-[-0.04em] text-foreground">
                {formatIdentifier(surface.toolName)}
              </span>
              <span className="rounded-md border border-border/70 bg-background/80 px-2 py-0.5 font-mono text-[11px] text-muted-foreground">
                {surface.toolName}
              </span>
            </div>
            <span className="mt-1 block text-sm leading-6 text-muted-foreground line-clamp-2">
              {surface.description}
            </span>
          </div>
        </div>
        <div className="flex items-center gap-2 shrink-0 ml-3">
          {isAvailable && (
            <span className="rubik-chip px-2 py-0.5 text-[10px] bg-success/10 text-success-foreground">
              Ready
            </span>
          )}
        </div>
      </button>

      {expanded && (
        <div className="border-t border-border">
          {surface.examples.length > 0 && (
            <div className="flex flex-wrap gap-1.5 px-5 pt-4 pb-1">
              {surface.examples.map((ex) => (
                <button
                  key={ex.label}
                  type="button"
                  onClick={() => handleExampleClick(ex.data)}
                  className="rubik-chip px-2.5 py-1 text-[10px] hover:bg-primary/10 hover:text-primary transition-colors cursor-pointer"
                >
                  {ex.label}
                </button>
              ))}
            </div>
          )}

          <form
            onSubmit={(e) => {
              e.preventDefault();
              handleExecute();
            }}
            className="space-y-6 p-5 sm:p-6"
          >
            {surface.fieldGroups.map((group) => (
              <FieldGroup
                key={group.label}
                label={group.label}
                fields={group.fields}
                formData={formData}
                onChange={handleFieldChange}
              />
            ))}

            {surface.advancedGroup && (
              <FieldGroup
                label={surface.advancedGroup.label}
                fields={surface.advancedGroup.fields}
                formData={formData}
                onChange={handleFieldChange}
                defaultCollapsed
              />
            )}

            <button
              type="submit"
              disabled={isPending || !isAvailable}
              className="inline-flex w-full items-center justify-center gap-2 rounded-xl bg-primary px-5 py-3 text-sm font-semibold text-primary-foreground shadow-sm transition-colors hover:bg-primary/90 focus:outline-none focus:ring-4 focus:ring-primary/10 disabled:opacity-50 sm:w-auto"
            >
              {isPending ? (
                <Loader2 className="w-4 h-4 animate-spin" />
              ) : (
                <Play className="w-4 h-4" />
              )}
              {isPending ? "Running..." : "Execute"}
            </button>
          </form>

          {(lastResult || error) && (
            <output
              htmlFor={toolName}
              aria-label={`Result for ${toolName}`}
              className="block px-5 pb-5"
            >
              <ResultRenderer result={lastResult} error={error} />
            </output>
          )}
        </div>
      )}
    </div>
  );
}

import { describe, it, expect, beforeEach, vi } from "vitest";
import { renderHook, act } from "@testing-library/react";
import { useDarkMode } from "../useDarkMode";

describe("useDarkMode", () => {
  beforeEach(() => {
    localStorage.clear();
    document.documentElement.classList.remove("dark", "light");
    // Reset matchMedia to return light mode by default
    Object.defineProperty(window, "matchMedia", {
      writable: true,
      value: (query: string) => ({
        matches: false,
        media: query,
        onchange: null,
        addListener: () => {},
        removeListener: () => {},
        addEventListener: () => {},
        removeEventListener: () => {},
        dispatchEvent: () => false,
      }),
    });
  });

  it("defaults to light theme when no preference stored", () => {
    const { result } = renderHook(() => useDarkMode());
    expect(result.current.theme).toBe("light");
  });

  it("loads stored dark preference", () => {
    localStorage.setItem("theme-preference", "dark");
    const { result } = renderHook(() => useDarkMode());
    expect(result.current.theme).toBe("dark");
    expect(result.current.isDarkMode).toBe(true);
  });

  it("loads stored light preference", () => {
    localStorage.setItem("theme-preference", "light");
    const { result } = renderHook(() => useDarkMode());
    expect(result.current.theme).toBe("light");
    expect(result.current.isDarkMode).toBe(false);
  });

  it("setTheme('dark') updates state and localStorage", async () => {
    const { result } = renderHook(() => useDarkMode());

    await act(async () => {
      result.current.setTheme("dark");
    });

    expect(result.current.theme).toBe("dark");
    expect(result.current.isDarkMode).toBe(true);
    expect(localStorage.getItem("theme-preference")).toBe("dark");
    expect(document.documentElement.classList.contains("dark")).toBe(true);
  });

  it("setTheme('light') updates state and removes dark class", async () => {
    localStorage.setItem("theme-preference", "dark");
    const { result } = renderHook(() => useDarkMode());

    await act(async () => {
      result.current.setTheme("light");
    });

    expect(result.current.theme).toBe("light");
    expect(result.current.isDarkMode).toBe(false);
    expect(document.documentElement.classList.contains("dark")).toBe(false);
    expect(document.documentElement.classList.contains("light")).toBe(true);
  });

  it("isDarkMode is false when theme is light", () => {
    const { result } = renderHook(() => useDarkMode());
    expect(result.current.isDarkMode).toBe(false);
  });

  it("isDarkMode is true when theme is dark", () => {
    localStorage.setItem("theme-preference", "dark");
    const { result } = renderHook(() => useDarkMode());
    expect(result.current.isDarkMode).toBe(true);
  });

  it("toggleTheme switches between light and dark", async () => {
    const { result } = renderHook(() => useDarkMode());
    expect(result.current.theme).toBe("light");

    await act(async () => {
      result.current.toggleTheme();
    });

    expect(result.current.theme).toBe("dark");
    expect(result.current.isDarkMode).toBe(true);
  });

  it("responds to storage events from other tabs", async () => {
    const { result } = renderHook(() => useDarkMode());
    expect(result.current.theme).toBe("light");

    await act(async () => {
      window.dispatchEvent(
        new StorageEvent("storage", {
          key: "theme-preference",
          newValue: "dark",
        }),
      );
    });

    expect(result.current.theme).toBe("dark");
  });
});

import { describe, it, expect, vi, beforeEach } from "vitest";
import { renderHook, act } from "@testing-library/react";
import { useFocusTrap } from "../useFocusTrap";

// ---------------------------------------------------------------------------
// Helpers to build a real DOM container with focusable elements
// ---------------------------------------------------------------------------

function buildContainer(buttonCount = 2): HTMLDivElement {
  const container = document.createElement("div");
  for (let i = 0; i < buttonCount; i++) {
    const btn = document.createElement("button");
    btn.textContent = `Button ${i + 1}`;
    btn.setAttribute("data-testid", `btn-${i}`);
    container.appendChild(btn);
  }
  document.body.appendChild(container);
  return container;
}

function cleanup(container: HTMLDivElement) {
  document.body.removeChild(container);
}

describe("useFocusTrap", () => {
  beforeEach(() => {
    vi.clearAllMocks();
  });

  it("returns a ref object", () => {
    const { result } = renderHook(() => useFocusTrap(false));
    expect(result.current).toHaveProperty("current");
  });

  it("does not focus anything when active=false", () => {
    const container = buildContainer(2);
    const { result } = renderHook(() => useFocusTrap(false));
    // Attach ref manually
    (result.current as React.MutableRefObject<HTMLDivElement>).current = container;

    const btn0 = container.querySelector<HTMLButtonElement>("[data-testid='btn-0']")!;
    expect(document.activeElement).not.toBe(btn0);
    cleanup(container);
  });

  it("focuses the first focusable element when activated", () => {
    const container = buildContainer(2);
    const btn0 = container.querySelector<HTMLButtonElement>("[data-testid='btn-0']")!;

    const { result, rerender } = renderHook(({ active }) => useFocusTrap(active), {
      initialProps: { active: false },
    });

    (result.current as React.MutableRefObject<HTMLDivElement>).current = container;

    act(() => {
      rerender({ active: true });
    });

    expect(document.activeElement).toBe(btn0);
    cleanup(container);
  });

  it("calls onClose when Escape is pressed while active", () => {
    const container = buildContainer(2);
    const onClose = vi.fn();

    const { result, rerender } = renderHook(({ active }) => useFocusTrap(active, onClose), {
      initialProps: { active: false },
    });

    (result.current as React.MutableRefObject<HTMLDivElement>).current = container;

    act(() => {
      rerender({ active: true });
    });

    act(() => {
      container.dispatchEvent(new KeyboardEvent("keydown", { key: "Escape", bubbles: true }));
    });

    expect(onClose).toHaveBeenCalledOnce();
    cleanup(container);
  });

  it("does not call onClose when Escape is pressed while inactive", () => {
    const container = buildContainer(2);
    const onClose = vi.fn();

    renderHook(() => useFocusTrap(false, onClose));

    act(() => {
      container.dispatchEvent(new KeyboardEvent("keydown", { key: "Escape", bubbles: true }));
    });

    expect(onClose).not.toHaveBeenCalled();
    cleanup(container);
  });

  it("traps Tab forward: wraps focus from last to first element", () => {
    const container = buildContainer(2);
    const btn0 = container.querySelector<HTMLButtonElement>("[data-testid='btn-0']")!;
    const btn1 = container.querySelector<HTMLButtonElement>("[data-testid='btn-1']")!;

    const { result, rerender } = renderHook(({ active }) => useFocusTrap(active), {
      initialProps: { active: false },
    });

    (result.current as React.MutableRefObject<HTMLDivElement>).current = container;

    act(() => {
      rerender({ active: true });
    });

    // Manually move focus to last button
    act(() => {
      btn1.focus();
    });
    expect(document.activeElement).toBe(btn1);

    // Dispatch Tab on container (last element focused → should wrap to first)
    act(() => {
      container.dispatchEvent(
        new KeyboardEvent("keydown", { key: "Tab", shiftKey: false, bubbles: true }),
      );
    });

    expect(document.activeElement).toBe(btn0);
    cleanup(container);
  });

  it("traps Shift+Tab backward: wraps focus from first to last element", () => {
    const container = buildContainer(2);
    const btn0 = container.querySelector<HTMLButtonElement>("[data-testid='btn-0']")!;
    const btn1 = container.querySelector<HTMLButtonElement>("[data-testid='btn-1']")!;

    const { result, rerender } = renderHook(({ active }) => useFocusTrap(active), {
      initialProps: { active: false },
    });

    (result.current as React.MutableRefObject<HTMLDivElement>).current = container;

    act(() => {
      rerender({ active: true });
    });

    // First element should have focus (from activation)
    expect(document.activeElement).toBe(btn0);

    // Dispatch Shift+Tab — should wrap to last element
    act(() => {
      container.dispatchEvent(
        new KeyboardEvent("keydown", { key: "Tab", shiftKey: true, bubbles: true }),
      );
    });

    expect(document.activeElement).toBe(btn1);
    cleanup(container);
  });

  it("does not wrap Tab when focus is not on the last element", () => {
    const container = buildContainer(2);
    const btn0 = container.querySelector<HTMLButtonElement>("[data-testid='btn-0']")!;
    const btn1 = container.querySelector<HTMLButtonElement>("[data-testid='btn-1']")!;

    const { result, rerender } = renderHook(({ active }) => useFocusTrap(active), {
      initialProps: { active: false },
    });

    (result.current as React.MutableRefObject<HTMLDivElement>).current = container;

    act(() => {
      rerender({ active: true });
    });

    // Focus is on btn0 (first), pressing Tab forward should do nothing special
    expect(document.activeElement).toBe(btn0);

    act(() => {
      container.dispatchEvent(
        new KeyboardEvent("keydown", { key: "Tab", shiftKey: false, bubbles: true }),
      );
    });

    // Focus should NOT have jumped to btn0 (it was already btn0 and not at last)
    expect(document.activeElement).not.toBe(btn1);
    cleanup(container);
  });

  it("handles empty focusable list gracefully", () => {
    const container = document.createElement("div");
    document.body.appendChild(container);

    const { result, rerender } = renderHook(({ active }) => useFocusTrap(active), {
      initialProps: { active: false },
    });

    (result.current as React.MutableRefObject<HTMLDivElement>).current = container;

    // Should not throw when there are no focusable elements
    expect(() => {
      act(() => {
        rerender({ active: true });
      });
    }).not.toThrow();

    document.body.removeChild(container);
  });

  it("restores focus to the triggering element on deactivation", () => {
    const container = buildContainer(2);
    // Create a trigger button outside the trap
    const trigger = document.createElement("button");
    trigger.textContent = "Open";
    document.body.appendChild(trigger);
    trigger.focus();
    expect(document.activeElement).toBe(trigger);

    const { result, rerender } = renderHook(({ active }) => useFocusTrap(active), {
      initialProps: { active: false },
    });

    (result.current as React.MutableRefObject<HTMLDivElement>).current = container;

    act(() => {
      rerender({ active: true });
    });

    // Focus moved into trap
    const btn0 = container.querySelector<HTMLButtonElement>("[data-testid='btn-0']")!;
    expect(document.activeElement).toBe(btn0);

    // Deactivate: focus should return to trigger
    act(() => {
      rerender({ active: false });
    });

    expect(document.activeElement).toBe(trigger);

    cleanup(container);
    document.body.removeChild(trigger);
  });

  it("ignores non-Tab and non-Escape key events", () => {
    const container = buildContainer(2);
    const onClose = vi.fn();

    const { result, rerender } = renderHook(({ active }) => useFocusTrap(active, onClose), {
      initialProps: { active: false },
    });

    (result.current as React.MutableRefObject<HTMLDivElement>).current = container;

    act(() => {
      rerender({ active: true });
    });

    act(() => {
      container.dispatchEvent(new KeyboardEvent("keydown", { key: "Enter", bubbles: true }));
      container.dispatchEvent(new KeyboardEvent("keydown", { key: "ArrowDown", bubbles: true }));
    });

    // onClose should not be called; no errors thrown
    expect(onClose).not.toHaveBeenCalled();
    cleanup(container);
  });

  it("works without an onClose callback (no error on Escape)", () => {
    const container = buildContainer(1);

    const { result, rerender } = renderHook(({ active }) => useFocusTrap(active), {
      initialProps: { active: false },
    });

    (result.current as React.MutableRefObject<HTMLDivElement>).current = container;

    act(() => {
      rerender({ active: true });
    });

    expect(() => {
      act(() => {
        container.dispatchEvent(new KeyboardEvent("keydown", { key: "Escape", bubbles: true }));
      });
    }).not.toThrow();

    cleanup(container);
  });
});

// Need React import for MutableRefObject type annotation
import type React from "react";

import { describe, it, expect, vi, beforeEach, afterEach } from "vitest";
import { renderHook, act, waitFor } from "@testing-library/react";
import { useSpikeChat, type ChatMessage, type AppUpdatedEvent } from "../useSpikeChat";

// ---------------------------------------------------------------------------
// Mock API module
// ---------------------------------------------------------------------------

vi.mock("../../core-logic/api", () => ({
  CHAT_ENABLED: true,
  chatUrl: (path: string) => `https://chat.spike.land${path}`,
  chatWsUrl: (path: string) => `wss://chat.spike.land${path}`,
}));

// ---------------------------------------------------------------------------
// WebSocket mock
// ---------------------------------------------------------------------------

type WsMockInstance = {
  readyState: number;
  onopen: (() => void) | null;
  onmessage: ((ev: { data: string }) => void) | null;
  onclose: (() => void) | null;
  onerror: (() => void) | null;
  send: ReturnType<typeof vi.fn>;
  close: ReturnType<typeof vi.fn>;
  _triggerOpen: () => void;
  _triggerMessage: (data: unknown) => void;
  _triggerClose: () => void;
  _triggerError: () => void;
};

let wsMockInstance: WsMockInstance | null = null;

const WsMock = vi.fn().mockImplementation(() => {
  const instance: WsMockInstance = {
    readyState: WebSocket.CONNECTING,
    onopen: null,
    onmessage: null,
    onclose: null,
    onerror: null,
    send: vi.fn(),
    close: vi.fn().mockImplementation(() => {
      instance.readyState = WebSocket.CLOSED;
      instance.onclose?.();
    }),
    _triggerOpen: () => {
      instance.readyState = WebSocket.OPEN;
      instance.onopen?.();
    },
    _triggerMessage: (data: unknown) => {
      instance.onmessage?.({ data: JSON.stringify(data) });
    },
    _triggerClose: () => {
      instance.readyState = WebSocket.CLOSED;
      instance.onclose?.();
    },
    _triggerError: () => {
      instance.onerror?.();
    },
  };
  wsMockInstance = instance;
  return instance;
});

// Replace global WebSocket with mock
Object.defineProperty(globalThis, "WebSocket", {
  value: WsMock,
  writable: true,
});

// ---------------------------------------------------------------------------
// fetch mock
// ---------------------------------------------------------------------------

const mockFetch = vi.fn();
Object.defineProperty(globalThis, "fetch", { value: mockFetch, writable: true });

const sampleMessages: ChatMessage[] = [
  {
    id: "msg-1",
    channelId: "ch-1",
    userId: "user-a",
    content: "Hello",
    contentType: "text",
    threadId: null,
    createdAt: 1_700_000_000_000,
  },
];

describe("useSpikeChat", () => {
  beforeEach(() => {
    vi.clearAllMocks();
    vi.useFakeTimers();
    wsMockInstance = null;
    // Default fetch returns empty message list
    mockFetch.mockResolvedValue({
      ok: true,
      json: () => Promise.resolve([]),
    });
  });

  afterEach(() => {
    vi.useRealTimers();
  });

  it("initializes with isLoading=true, isConnected=false, empty messages", () => {
    const { result } = renderHook(() => useSpikeChat({ channelId: "ch-1" }));
    expect(result.current.isLoading).toBe(true);
    expect(result.current.isConnected).toBe(false);
    expect(result.current.messages).toEqual([]);
    expect(result.current.typingUsers).toEqual([]);
  });

  it("fetches message history on mount", async () => {
    mockFetch.mockResolvedValue({
      ok: true,
      json: () => Promise.resolve(sampleMessages),
    });

    const { result } = renderHook(() => useSpikeChat({ channelId: "ch-1" }));

    await waitFor(() => {
      expect(result.current.isLoading).toBe(false);
    });

    expect(result.current.messages).toEqual(sampleMessages);
    expect(mockFetch).toHaveBeenCalledWith(
      expect.stringContaining("channelId=ch-1"),
      expect.objectContaining({ credentials: "include" }),
    );
  });

  it("sets isLoading=false even on failed fetch", async () => {
    mockFetch.mockRejectedValue(new Error("Network error"));
    const { result } = renderHook(() => useSpikeChat({ channelId: "ch-1" }));

    await waitFor(() => {
      expect(result.current.isLoading).toBe(false);
    });

    expect(result.current.messages).toEqual([]);
  });

  it("sets isLoading=false when fetch returns non-ok response", async () => {
    mockFetch.mockResolvedValue({ ok: false, json: () => Promise.resolve([]) });
    const { result } = renderHook(() => useSpikeChat({ channelId: "ch-1" }));

    await waitFor(() => {
      expect(result.current.isLoading).toBe(false);
    });
  });

  it("opens a WebSocket connection on mount", () => {
    renderHook(() => useSpikeChat({ channelId: "ch-1" }));
    expect(WsMock).toHaveBeenCalledWith(expect.stringContaining("ch-1"));
  });

  it("sets isConnected=true when WebSocket opens", async () => {
    const { result } = renderHook(() => useSpikeChat({ channelId: "ch-1" }));

    act(() => {
      wsMockInstance!._triggerOpen();
    });

    expect(result.current.isConnected).toBe(true);
  });

  it("sets isConnected=false when WebSocket closes", async () => {
    const { result } = renderHook(() => useSpikeChat({ channelId: "ch-1" }));

    act(() => {
      wsMockInstance!._triggerOpen();
    });
    expect(result.current.isConnected).toBe(true);

    act(() => {
      // Prevent reconnect timer from firing
      wsMockInstance!.close.mockImplementation(() => {
        wsMockInstance!.readyState = WebSocket.CLOSED;
        wsMockInstance!.onclose?.();
      });
      wsMockInstance!._triggerClose();
    });

    expect(result.current.isConnected).toBe(false);
  });

  it("appends new message on 'message_new' WebSocket event", async () => {
    const { result } = renderHook(() => useSpikeChat({ channelId: "ch-1" }));

    act(() => {
      wsMockInstance!._triggerOpen();
    });

    act(() => {
      wsMockInstance!._triggerMessage({
        type: "message_new",
        message: sampleMessages[0],
      });
    });

    expect(result.current.messages).toHaveLength(1);
    expect(result.current.messages[0].id).toBe("msg-1");
  });

  it("removes message on 'message_deleted' WebSocket event", async () => {
    mockFetch.mockResolvedValue({
      ok: true,
      json: () => Promise.resolve(sampleMessages),
    });

    const { result } = renderHook(() => useSpikeChat({ channelId: "ch-1" }));
    await waitFor(() => expect(result.current.messages).toHaveLength(1));

    act(() => {
      wsMockInstance!._triggerOpen();
      wsMockInstance!._triggerMessage({ type: "message_deleted", id: "msg-1" });
    });

    expect(result.current.messages).toHaveLength(0);
  });

  it("updates typingUsers on 'typing' WebSocket event", () => {
    const { result } = renderHook(() => useSpikeChat({ channelId: "ch-1" }));

    act(() => {
      wsMockInstance!._triggerOpen();
      wsMockInstance!._triggerMessage({ type: "typing", users: ["alice", "bob"] });
    });

    expect(result.current.typingUsers).toEqual(["alice", "bob"]);
  });

  it("calls onAppUpdated callback on 'app_updated' WebSocket event", () => {
    const onAppUpdated = vi.fn();
    renderHook(() => useSpikeChat({ channelId: "ch-1", onAppUpdated }));

    const event: AppUpdatedEvent = {
      type: "app_updated",
      appSlug: "my-app",
      version: "1.2.3",
      messageId: "msg-upd",
    };

    act(() => {
      wsMockInstance!._triggerOpen();
      wsMockInstance!._triggerMessage(event);
    });

    expect(onAppUpdated).toHaveBeenCalledWith(event);
  });

  it("ignores malformed JSON WebSocket messages without throwing", () => {
    const { result } = renderHook(() => useSpikeChat({ channelId: "ch-1" }));

    act(() => {
      wsMockInstance!._triggerOpen();
      wsMockInstance!.onmessage?.({ data: "not-valid-json{{" });
    });

    expect(result.current.messages).toEqual([]);
  });

  it("sendMessage posts to the chat API", async () => {
    mockFetch
      .mockResolvedValueOnce({ ok: true, json: () => Promise.resolve([]) }) // history
      .mockResolvedValueOnce({ ok: true }); // send

    const { result } = renderHook(() => useSpikeChat({ channelId: "ch-1" }));

    await act(async () => {
      await result.current.sendMessage("Hello world");
    });

    expect(mockFetch).toHaveBeenCalledWith(
      expect.stringContaining("/api/v1/messages"),
      expect.objectContaining({
        method: "POST",
        body: expect.stringContaining("Hello world"),
      }),
    );
  });

  it("sendMessage includes channelId in request body", async () => {
    mockFetch.mockResolvedValue({ ok: true });

    const { result } = renderHook(() => useSpikeChat({ channelId: "ch-abc" }));

    await act(async () => {
      await result.current.sendMessage("Hi");
    });

    const lastCall = mockFetch.mock.calls[mockFetch.mock.calls.length - 1];
    const body = JSON.parse(lastCall[1].body);
    expect(body.channelId).toBe("ch-abc");
    expect(body.content).toBe("Hi");
  });

  it("startTyping sends typing_start message when WebSocket is open", () => {
    const { result } = renderHook(() => useSpikeChat({ channelId: "ch-1" }));

    act(() => {
      wsMockInstance!._triggerOpen();
      result.current.startTyping();
    });

    expect(wsMockInstance!.send).toHaveBeenCalledWith(JSON.stringify({ type: "typing_start" }));
  });

  it("stopTyping sends typing_stop message when WebSocket is open", () => {
    const { result } = renderHook(() => useSpikeChat({ channelId: "ch-1" }));

    act(() => {
      wsMockInstance!._triggerOpen();
      result.current.stopTyping();
    });

    expect(wsMockInstance!.send).toHaveBeenCalledWith(JSON.stringify({ type: "typing_stop" }));
  });

  it("startTyping does not send when WebSocket is not open", () => {
    const { result } = renderHook(() => useSpikeChat({ channelId: "ch-1" }));
    // WebSocket is in CONNECTING state, not OPEN
    result.current.startTyping();
    expect(wsMockInstance!.send).not.toHaveBeenCalled();
  });

  it("closes WebSocket on unmount", () => {
    const { unmount } = renderHook(() => useSpikeChat({ channelId: "ch-1" }));
    const ws = wsMockInstance!;
    unmount();
    expect(ws.close).toHaveBeenCalled();
  });

  it("does not fetch or connect when enabled=false", () => {
    renderHook(() => useSpikeChat({ channelId: "ch-1", enabled: false }));
    expect(mockFetch).not.toHaveBeenCalled();
    expect(WsMock).not.toHaveBeenCalled();
  });

  it("sets isLoading=false immediately when enabled=false", () => {
    const { result } = renderHook(() => useSpikeChat({ channelId: "ch-1", enabled: false }));
    expect(result.current.isLoading).toBe(false);
  });

  it("schedules reconnect with exponential backoff on WebSocket close", async () => {
    renderHook(() => useSpikeChat({ channelId: "ch-1" }));
    const firstWs = wsMockInstance!;

    // Prevent the mock close from triggering onclose automatically so we can control it
    act(() => {
      firstWs._triggerOpen();
      firstWs.close.mockImplementation(() => {
        firstWs.readyState = WebSocket.CLOSED;
      });
      firstWs._triggerClose();
    });

    // After close, a reconnect timer should be scheduled (1s for first attempt)
    const callCountBefore = WsMock.mock.calls.length;
    act(() => {
      vi.advanceTimersByTime(1100);
    });

    expect(WsMock.mock.calls.length).toBeGreaterThan(callCountBefore);
  });
});

// @vitest-environment happy-dom
import { renderHook, waitFor } from "@testing-library/react";
import { describe, it, expect, vi, beforeEach } from "vitest";

let useTranspiler: typeof import("../useTranspiler").useTranspiler;
const fetchMock = vi.fn<typeof fetch>();

beforeEach(async () => {
  vi.resetModules();
  fetchMock.mockReset();
  vi.stubGlobal("fetch", fetchMock);

  const mod = await import("../useTranspiler");
  useTranspiler = mod.useTranspiler;
});

describe("useTranspiler", () => {
  it("returns null html for empty source", () => {
    const { result } = renderHook(() => useTranspiler("", 50));
    expect(result.current.html).toBeNull();
    expect(result.current.error).toBeNull();
    expect(result.current.isTranspiling).toBe(false);
  });

  it("returns null html for whitespace-only source", () => {
    const { result } = renderHook(() => useTranspiler("   \n  ", 50));
    expect(result.current.html).toBeNull();
    expect(result.current.isTranspiling).toBe(false);
  });

  it("transpiles valid TSX to preview HTML", async () => {
    fetchMock.mockResolvedValue(
      new Response('const App = () => "hello";export default App;', { status: 200 }),
    );

    const { result } = renderHook(() =>
      useTranspiler('export default function App() { return "hi"; }', 10),
    );

    await waitFor(() => {
      expect(result.current.isTranspiling).toBe(false);
      expect(result.current.html).toBeTruthy();
    });

    expect(result.current.html).toContain("<!DOCTYPE html>");
    expect(result.current.html).toContain("createRoot");
    expect(result.current.html).toContain("https://js.spike.land/react@19.2.4?bundle");
    expect(result.current.html).toContain("@theme inline");
    expect(result.current.html).not.toContain("fonts.googleapis.com");
    expect(result.current.html).toContain("globalThis.process ??= { env: {} };");
    expect(result.current.error).toBeNull();
  });

  it("shows isTranspiling during debounce", () => {
    fetchMock.mockResolvedValue(new Response("const x = 1;", { status: 200 }));

    const { result } = renderHook(() => useTranspiler("const x = 1;", 5000));

    // Should be transpiling while debounce is pending
    expect(result.current.isTranspiling).toBe(true);
  });

  it("handles transpilation errors gracefully", async () => {
    fetchMock.mockRejectedValue(new Error("Syntax error in source"));

    const { result } = renderHook(() => useTranspiler("invalid {{{", 10));

    await waitFor(() => {
      expect(result.current.isTranspiling).toBe(false);
    });

    expect(result.current.error).toBe("Transpiler failed: Syntax error in source");
    expect(result.current.html).toBeNull();
  });

  it("handles non-200 transpiler responses with error message", async () => {
    fetchMock.mockResolvedValue(new Response("Module not found", { status: 500 }));

    const { result } = renderHook(() => useTranspiler("const x = 1;", 10));

    await waitFor(() => {
      expect(result.current.isTranspiling).toBe(false);
    });

    expect(result.current.error).toBe("Transpiler failed: Module not found");
  });

  it("clears html when source becomes empty", async () => {
    fetchMock.mockResolvedValue(new Response('const App = () => "hello";', { status: 200 }));

    const { result, rerender } = renderHook(
      ({ source }: { source: string }) => useTranspiler(source, 10),
      { initialProps: { source: "const x = 1;" } },
    );

    await waitFor(() => {
      expect(result.current.isTranspiling).toBe(false);
      expect(result.current.html).toBeTruthy();
    });

    rerender({ source: "" });

    expect(result.current.html).toBeNull();
    expect(result.current.error).toBeNull();
    expect(result.current.isTranspiling).toBe(false);
  });

  it("debounces rapid code changes", async () => {
    fetchMock.mockResolvedValue(new Response("const x = 1;", { status: 200 }));

    const { rerender } = renderHook(({ source }: { source: string }) => useTranspiler(source, 50), {
      initialProps: { source: "v1" },
    });

    // Rapid changes — each should cancel the previous debounce
    rerender({ source: "v2" });
    rerender({ source: "v3" });
    rerender({ source: "v4" });

    await waitFor(() => {
      expect(fetchMock).toHaveBeenCalledTimes(1);
    });

    // Only the last value should have been transpiled
    expect(fetchMock.mock.calls[0]![0]).toBe("https://js.spike.land");
    expect(fetchMock.mock.calls[0]![1]).toMatchObject({
      method: "POST",
      body: "v4",
      headers: {
        "Content-Type": "text/plain",
        TR_ORIGIN: "http://localhost:3000",
      },
    });
  });

  it("rebuilds preview HTML for dark mode without re-fetching source", async () => {
    fetchMock.mockResolvedValue(new Response('const App = () => "hello";export default App;', { status: 200 }));

    const { result, rerender } = renderHook(
      ({ isDark }: { isDark: boolean }) =>
        useTranspiler('export default function App() { return "hi"; }', 10, isDark),
      { initialProps: { isDark: false } },
    );

    await waitFor(() => {
      expect(result.current.isTranspiling).toBe(false);
      expect(result.current.html).toContain('data-theme="light"');
    });

    rerender({ isDark: true });

    await waitFor(() => {
      expect(result.current.html).toContain('data-theme="dark"');
    });

    expect(fetchMock).toHaveBeenCalledTimes(1);
  });
});

