      </div>

      <div className="p-4">
        <h4 className="text-xs font-semibold text-muted-foreground uppercase tracking-wider mb-3">
          Stored Outputs
        </h4>
        {Object.keys(session.outputs).length === 0 ? (
          <p className="text-sm text-muted-foreground italic">No outputs stored yet.</p>
