  mirror?: string;
  vite?: boolean;
  worker?: ManifestWorkerConfig;
}

export interface ManifestDefaults {
  scope: string;
  registry: string;
  license: string;
  type: string;
}

export interface Manifest {
  defaults: ManifestDefaults;
  packages: Record<string, ManifestPackage>;
}

// ── Simple YAML Parser ──────────────────────────────────────────────────────

/**
 * Minimal YAML parser for the packages.yaml format.
 * Handles the subset of YAML used in the manifest (maps, lists, scalars).
 * Does NOT handle all YAML features — only what's needed for the manifest.
 */
function parseSimpleYaml(text: string): Record<string, unknown> {
  const lines = text.split("\n");
  return parseObject(lines, 0, 0).value as Record<string, unknown>;
}

interface ParseResult {
  value: unknown;
  consumed: number;
}

function getIndent(line: string): number {
  const match = line.match(/^(\s*)/);
  return match?.[1]?.length ?? 0;
}

function isComment(line: string): boolean {
  return line.trim().startsWith("#") || line.trim() === "";
}

function parseObject(lines: string[], start: number, baseIndent: number): ParseResult {
  const obj: Record<string, unknown> = {};
  let i = start;

  while (i < lines.length) {
    if (isComment(lines[i]!)) {
      i++;
      continue;
    }

    const indent = getIndent(lines[i]!);
    if (indent < baseIndent) break;
    if (indent > baseIndent) break;

    const line = lines[i]!.trim();
    const keyMatch = line.match(/^([^:]+?):\s*(.*)/);
    if (!keyMatch) {
      i++;
      continue;
    }

    const key = keyMatch[1]!.trim();
    const inlineValue = keyMatch[2]!.trim();

    if (inlineValue && !inlineValue.startsWith("#")) {
      // Inline scalar value
      obj[key] = parseScalar(inlineValue);
      i++;
    } else {
      // Check next non-empty line for indent
      let nextLine = i + 1;
      while (nextLine < lines.length && isComment(lines[nextLine]!)) {
        nextLine++;
      }

      if (nextLine >= lines.length) {
        obj[key] = null;
        i++;
        continue;
      }

      const nextIndent = getIndent(lines[nextLine]!);
      if (nextIndent <= baseIndent) {
        obj[key] = null;
        i++;
        continue;
      }

      // Check if it's a list or nested object
      const nextTrimmed = lines[nextLine]!.trim();
      if (nextTrimmed.startsWith("- ")) {
        const listResult = parseList(lines, nextLine, nextIndent);
        obj[key] = listResult.value;
        i = nextLine + listResult.consumed;
      } else {
        const nested = parseObject(lines, nextLine, nextIndent);
        obj[key] = nested.value;
        i = nextLine + nested.consumed;
      }
    }
  }

  return { value: obj, consumed: i - start };
}

function parseList(lines: string[], start: number, baseIndent: number): ParseResult {
  const arr: unknown[] = [];
  let i = start;

  while (i < lines.length) {
    if (isComment(lines[i]!)) {
      i++;
      continue;
    }

    const indent = getIndent(lines[i]!);
    if (indent < baseIndent) break;

    const line = lines[i]!.trim();
    if (!line.startsWith("- ")) break;

    const itemContent = line.slice(2).trim();

    // Check if it's an inline map (e.g., "- binding: FOO")
    if (itemContent.includes(":")) {
      // Collect the inline map + any continuation lines
      const mapObj: Record<string, unknown> = {};
      const firstPair = itemContent.match(/^([^:]+?):\s*(.*)/)!;
      mapObj[firstPair[1]!.trim()] = parseScalar(firstPair[2]!.trim());
      // Check for continuation lines at deeper indent
      let j = i + 1;
      const itemIndent = indent + 2;
      while (j < lines.length) {
        if (isComment(lines[j]!)) {
          j++;
          continue;
        }
        const jIndent = getIndent(lines[j]!);
        if (jIndent < itemIndent) break;
        const jLine = lines[j]!.trim();
        const jPair = jLine.match(/^([^:]+?):\s*(.*)/);
        if (jPair) {
          mapObj[jPair[1]!.trim()] = parseScalar(jPair[2]!.trim());
        }
        j++;
      }

      arr.push(mapObj);
      i = j;
    } else {
      arr.push(parseScalar(itemContent));
      i++;
    }
  }

  return { value: arr, consumed: i - start };
}

function parseScalar(value: string): string | number | boolean | null | unknown[] {
  if (value === "true") return true;
  if (value === "false") return false;
  if (value === "null" || value === "~" || value === "") return null;

  // Strip inline comments
  const commentIdx = value.indexOf(" #");
  const clean = commentIdx >= 0 ? value.slice(0, commentIdx).trim() : value;

  // Remove quotes
  if (
    (clean.startsWith('"') && clean.endsWith('"')) ||
    (clean.startsWith("'") && clean.endsWith("'"))
  ) {
    return clean.slice(1, -1);
  }

  if (clean.startsWith("[") && clean.endsWith("]")) {
    const body = clean.slice(1, -1).trim();
    if (!body) return [];

    const items: string[] = [];
    let current = "";
    let quote: '"' | "'" | null = null;

    for (const char of body) {
      if ((char === '"' || char === "'") && quote === null) {
        quote = char;
        current += char;
        continue;
      }

      if (quote !== null && char === quote) {
        quote = null;
        current += char;
        continue;
      }

      if (char === "," && quote === null) {
        items.push(current.trim());
        current = "";
        continue;
      }

      current += char;
    }

    if (current.trim()) {
      items.push(current.trim());
    }

    return items.map((item) => parseScalar(item));
  }

  // Try number
  const num = Number(clean);
  if (!isNaN(num)) return num;

  return clean;
}

// ── Public API ──────────────────────────────────────────────────────────────

let cachedManifest: Manifest | null = null;
let cachedPath: string | null = null;

/**
 * Read and parse the packages.yaml manifest file.
 * Results are cached per path.
 */
export async function readManifest(monorepoRoot?: string): Promise<Manifest> {
  const root = monorepoRoot ?? process.cwd();
  const manifestPath = join(root, "packages.yaml");

  if (cachedManifest && cachedPath === manifestPath) {
    return cachedManifest;
  }

  const raw = await readFile(manifestPath, "utf-8");
  const parsed = parseSimpleYaml(raw) as unknown as Manifest;

  if (!parsed.defaults || !parsed.packages) {
    throw new Error("Invalid packages.yaml: missing 'defaults' or 'packages' top-level keys");
  }

  cachedManifest = parsed;
  cachedPath = manifestPath;
  return parsed;
}

/**
 * Get a single package entry from the manifest.
 */
export async function getManifestPackage(
  packageName: string,
  monorepoRoot?: string,
): Promise<ManifestPackage | null> {
  const manifest = await readManifest(monorepoRoot);
  return manifest.packages[packageName] ?? null;
}

/**
 * Clear the manifest cache (useful for tests).
 */
export function clearManifestCache(): void {
  cachedManifest = null;
  cachedPath = null;
}

/**
 * Build a topological sort of packages based on deps.
 * Returns packages in build order (dependencies first).
 */
export function topologicalSort(packages: Record<string, ManifestPackage>): string[] {
  const visited = new Set<string>();
  const visiting = new Set<string>();
  const order: string[] = [];

  function visit(name: string): void {
    if (visited.has(name)) return;
    if (visiting.has(name)) {
      throw new Error(`Circular dependency detected involving: ${name}`);
    }

    visiting.add(name);
    const pkg = packages[name];
    if (pkg?.deps) {
      for (const dep of pkg.deps) {
        if (packages[dep]) {
          visit(dep);
        }
      }
    }
    visiting.delete(name);
    visited.add(name);
    order.push(name);
  }

  for (const name of Object.keys(packages)) {
    visit(name);
  }

  return order;
}

import type { SubdomainMapping } from "./types.js";

interface CaddyRoute {
  match?: Array<{ host?: string[] }>;
  handle?: Array<{ handler: string; upstreams?: Array<{ dial: string }>; [key: string]: unknown }>;
  [key: string]: unknown;
}

export class CaddyAdminClient {
  private readonly baseUrl: string;

  constructor(baseUrl?: string) {
    this.baseUrl = baseUrl ?? process.env["CADDY_ADMIN_URL"] ?? "http://caddy:2019";
  }

  async getConfig(): Promise<unknown> {
    const res = await fetch(`${this.baseUrl}/config/`);
    if (!res.ok) {
      throw new Error(`Caddy admin API error: ${res.status} ${await res.text()}`);
    }
    return res.json();
  }

  async addRoute(subdomain: string, upstream: string, port: number): Promise<void> {
    const route: CaddyRoute = {
      match: [{ host: [`${subdomain}.spike.local`] }],
      handle: [
        {
          handler: "reverse_proxy",
          upstreams: [{ dial: `${upstream}:${port}` }],
        },
      ],
    };

    const res = await fetch(`${this.baseUrl}/config/apps/http/servers/srv0/routes`, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify(route),
    });

    if (!res.ok) {
      throw new Error(`Failed to add Caddy route: ${res.status} ${await res.text()}`);
    }
  }

  async listRoutes(): Promise<SubdomainMapping[]> {
    const res = await fetch(`${this.baseUrl}/config/apps/http/servers/srv0/routes`);

    if (!res.ok) {
      if (res.status === 404) return [];
      throw new Error(`Failed to list Caddy routes: ${res.status} ${await res.text()}`);
    }

    const routes = (await res.json()) as CaddyRoute[];
    const mappings: SubdomainMapping[] = [];

    for (const route of routes) {
      const host = route.match?.[0]?.host?.[0];
      const dial = route.handle?.[0]?.upstreams?.[0]?.dial;

      if (!host || !dial) continue;

      const subdomain = host.replace(".spike.local", "");
      const [upstream, portStr] = dial.split(":");
      const port = parseInt(portStr!, 10);

      if (upstream && !isNaN(port)) {
        mappings.push({ subdomain, upstream, port });
      }
    }

    return mappings;
  }
}

/**
 * HN Write Client — Web scraping for login, submit, vote, comment.
 * All methods accept injected fetch + session cookie for testability.
 */

import type { FetchFn, HNErrorCode } from "../mcp/types.js";
import { HN_WEB_BASE } from "../mcp/types.js";
import type { SessionManager } from "./session-manager.js";

export type WriteResult =
  | { success: true; error?: undefined; message?: undefined }
  | { success: false; error: HNErrorCode; message: string };

export class HNWriteClient {
  private readonly fetchFn: FetchFn;
  private readonly session: SessionManager;

  constructor(session: SessionManager, fetchFn: FetchFn = globalThis.fetch) {
    this.fetchFn = fetchFn;
    this.session = session;
  }

  async login(username: string, password: string): Promise<WriteResult> {
    const body = new URLSearchParams({
      acct: username,
      pw: password,
      goto: "news",
    });

    const resp = await this.fetchFn(`${HN_WEB_BASE}/login`, {
      method: "POST",
      headers: { "Content-Type": "application/x-www-form-urlencoded" },
      body: body.toString(),
      redirect: "manual",
    });

    const setCookie = resp.headers.get("set-cookie");
    const html = await resp.text();

    // Successful login: redirect or cookie set
    if (setCookie && setCookie.includes("user=")) {
      this.session.login(username, setCookie);
      return { success: true };
    }

    // Check for redirect meta tag (success indicator)
    if (html.includes("URL=news")) {
      // Even without set-cookie header, some environments handle cookies differently
      this.session.login(username, `user=${username}`);
      return { success: true };
    }

    if (html.includes("Bad login")) {
      return {
        success: false,
        error: "AUTH_FAILED",
        message: "Invalid username or password",
      };
    }

    return { success: false, error: "AUTH_FAILED", message: "Login failed" };
  }

  async submitStory(title: string, url?: string, text?: string): Promise<WriteResult> {
    const authCheck = this.requireAuth();
    if (authCheck) return authCheck;

    // Step 1: GET /submit to extract fnid CSRF token
    const fnid = await this.extractFnid();
    if (!fnid.success) return fnid;

    // Step 2: POST /r with fnid + story data
    const body = new URLSearchParams({ fnid: fnid.token, title });
    if (url) body.set("url", url);
    if (text) body.set("text", text);

    const resp = await this.fetchFn(`${HN_WEB_BASE}/r`, {
      method: "POST",
      headers: {
        "Content-Type": "application/x-www-form-urlencoded",
        Cookie: this.session.getCookie()!,
      },
      body: body.toString(),
      redirect: "manual",
    });

    const html = await resp.text();

    if (this.isRateLimited(html)) {
      return {
        success: false,
        error: "RATE_LIMITED",
        message: "Rate limited — wait before retrying",
      };
    }

    if (html.includes("URL=newest") || html.includes("URL=new") || resp.status === 302) {
      return { success: true };
    }

    // CSRF expired — retry once
    if (html.includes("Unknown") || html.includes("expired")) {
      const retryFnid = await this.extractFnid();
      if (!retryFnid.success) {
        return {
          success: false,
          error: "CSRF_EXPIRED",
          message: "CSRF token expired and retry failed",
        };
      }

      const retryBody = new URLSearchParams({ fnid: retryFnid.token, title });
      if (url) retryBody.set("url", url);
      if (text) retryBody.set("text", text);

      const retryResp = await this.fetchFn(`${HN_WEB_BASE}/r`, {
        method: "POST",
        headers: {
          "Content-Type": "application/x-www-form-urlencoded",
          Cookie: this.session.getCookie()!,
        },
        body: retryBody.toString(),
        redirect: "manual",
      });

      const retryHtml = await retryResp.text();
      if (
        retryHtml.includes("URL=newest") ||
        retryHtml.includes("URL=new") ||
        retryResp.status === 302
      ) {
        return { success: true };
      }
      return {
        success: false,
        error: "SUBMIT_FAILED",
        message: "Submit failed after CSRF retry",
      };
    }

    return { success: false, error: "SUBMIT_FAILED", message: "Submit failed" };
  }

  async upvote(itemId: number): Promise<WriteResult> {
    const authCheck = this.requireAuth();
    if (authCheck) return authCheck;

    // Step 1: GET item page to extract vote auth token
    const resp = await this.fetchFn(`${HN_WEB_BASE}/item?id=${itemId}`, {
      headers: { Cookie: this.session.getCookie()! },
    });

    if (!resp.ok) {
      return {
        success: false,
        error: "NOT_FOUND",
        message: `Item ${itemId} not found`,
      };
    }

    const html = await resp.text();
    const voteMatch = html.match(/id="up_\d+"\s+href="([^"]+)"/);
    if (!voteMatch) {
      return {
        success: false,
        error: "VOTE_FAILED",
        message: "Could not find vote link — may have already voted",
      };
    }

    // Step 2: GET the vote URL
    const voteUrl = (voteMatch[1] as string).replace(/&amp;/g, "&");
    const voteResp = await this.fetchFn(`${HN_WEB_BASE}/${voteUrl}`, {
      headers: { Cookie: this.session.getCookie()! },
      redirect: "manual",
    });

    const voteHtml = await voteResp.text();

    if (this.isRateLimited(voteHtml)) {
      return {
        success: false,
        error: "RATE_LIMITED",
        message: "Rate limited — wait before retrying",
      };
    }

    // Success: redirect back to item or 302
    if (voteResp.status === 302 || voteHtml.includes("URL=") || voteResp.ok) {
      return { success: true };
    }

    return { success: false, error: "VOTE_FAILED", message: "Vote failed" };
  }

  async postComment(parentId: number, text: string): Promise<WriteResult> {
    const authCheck = this.requireAuth();
    if (authCheck) return authCheck;

    // Step 1: GET item page to extract hmac CSRF token
    const resp = await this.fetchFn(`${HN_WEB_BASE}/item?id=${parentId}`, {
      headers: { Cookie: this.session.getCookie()! },
    });

    if (!resp.ok) {
      return {
        success: false,
        error: "NOT_FOUND",
        message: `Item ${parentId} not found`,
      };
    }

    const html = await resp.text();
    const hmacMatch = html.match(/name="hmac"\s+value="([^"]+)"/);
    if (!hmacMatch) {
      return {
        success: false,
        error: "COMMENT_FAILED",
        message: "Could not find comment form CSRF token",
      };
    }

    // Step 2: POST /comment with hmac + text
    const body = new URLSearchParams({
      parent: String(parentId),
      text,
      hmac: hmacMatch[1] as string,
      goto: `item?id=${parentId}`,
    });

    const commentResp = await this.fetchFn(`${HN_WEB_BASE}/comment`, {
      method: "POST",
      headers: {
        "Content-Type": "application/x-www-form-urlencoded",
        Cookie: this.session.getCookie()!,
      },
      body: body.toString(),
      redirect: "manual",
    });

    const commentHtml = await commentResp.text();

    if (this.isRateLimited(commentHtml)) {
      return {
        success: false,
        error: "RATE_LIMITED",
        message: "Rate limited — wait before retrying",
      };
    }

    if (
      commentResp.status === 302 ||
      commentHtml.includes("URL=") ||
      commentHtml.includes(`item?id=${parentId}`)
    ) {
      return { success: true };
    }

    // CSRF expired — retry once
    if (commentHtml.includes("Unknown") || commentHtml.includes("expired")) {
      const retryResp = await this.fetchFn(`${HN_WEB_BASE}/item?id=${parentId}`, {
        headers: { Cookie: this.session.getCookie()! },
      });
      const retryPageHtml = await retryResp.text();
      const retryHmac = retryPageHtml.match(/name="hmac"\s+value="([^"]+)"/);
      if (!retryHmac) {
        return {
          success: false,
          error: "CSRF_EXPIRED",
          message: "CSRF token expired and retry failed",
        };
      }

      const retryBody = new URLSearchParams({
        parent: String(parentId),
        text,
        hmac: retryHmac[1] as string,
        goto: `item?id=${parentId}`,
      });

      const retryCommentResp = await this.fetchFn(`${HN_WEB_BASE}/comment`, {
        method: "POST",
        headers: {
          "Content-Type": "application/x-www-form-urlencoded",
          Cookie: this.session.getCookie()!,
        },
        body: retryBody.toString(),
        redirect: "manual",
      });

      const retryCommentHtml = await retryCommentResp.text();
      if (retryCommentResp.status === 302 || retryCommentHtml.includes("URL=")) {
        return { success: true };
      }
      return {
        success: false,
        error: "COMMENT_FAILED",
        message: "Comment failed after CSRF retry",
      };
    }

    return {
      success: false,
      error: "COMMENT_FAILED",
      message: "Comment failed",
    };
  }

  private requireAuth(): WriteResult | null {
    if (!this.session.isLoggedIn()) {
      return {
        success: false,
        error: "AUTH_REQUIRED",
        message: "Call hn_login first",
      };
    }
    return null;
  }

  private async extractFnid(): Promise<
    | { success: true; token: string }
    | {
        success: false;
        error: HNErrorCode;
        message: string;
      }
  > {
    const resp = await this.fetchFn(`${HN_WEB_BASE}/submit`, {
      headers: { Cookie: this.session.getCookie()! },
    });

    const html = await resp.text();
    const fnidMatch = html.match(/name="fnid"\s+value="([^"]+)"/);
    if (!fnidMatch) {
      return {
        success: false,
        error: "CSRF_EXPIRED",
        message: "Could not extract CSRF token from submit page",
      };
    }

    return { success: true, token: fnidMatch[1] as string };
  }

  private isRateLimited(html: string): boolean {
    return (
      html.includes("too fast") || html.includes("slow down") || html.includes("limit submissions")
    );
  }
}

import { z } from "zod";
import { AVATAR_STYLE_VALUES, errorResult, jsonResult, toolEvent } from "../../mcp/types.js";
import { tryCatch } from "../../mcp/try-catch.js";
import { imageProcedure } from "../../lazy-imports/image-middleware.js";
import { consumeCreditsOrError } from "../define-tool.js";

export const avatarTool = imageProcedure
  .tool(
    "avatar",
    "Generates a customized profile avatar image for a user based on a prompt and visual style.",
    {
      prompt: z.string().describe("Description of the desired avatar"),
      style: z
        .enum(AVATAR_STYLE_VALUES)
        .describe("Avatar style: photo, cartoon, abstract, or pixel")
        .optional(),
      tier: z
        .enum(["FREE", "TIER_0_5K", "TIER_1K", "TIER_2K", "TIER_4K"])
        .describe("Enhancement tier for generation quality")
        .optional(),
    },
  )
  .handler(async ({ input: input, ctx: ctx }) => {
    const { userId, deps } = ctx;
    const tier = input.tier ?? "TIER_1K";
    const style = input.style ?? "photo";
    const cost = deps.credits.calculateGenerationCost({ tier });

    const fullPrompt = `A profile avatar, face-centered composition. Style: ${style}. ${input.prompt}`;

    const jobRes = await tryCatch(
      deps.generation.createGenerationJob({
        userId,
        prompt: fullPrompt,
        tier,
        aspectRatio: "1:1",
      }),
    );

    if (!jobRes.ok) {
      return errorResult("GENERATION_FAILED", jobRes.error.message, true);
    }
    /* v8 ignore next */
    if (!jobRes.data?.success) {
      return errorResult(
        "GENERATION_FAILED",
        jobRes.data?.error ?? "Failed to create avatar job",
        true,
      );
    }

    const { error } = await consumeCreditsOrError(
      deps,
      userId,
      cost,
      "avatar",
      jobRes.data.jobId,
      ctx,
    );
    if (error) return error;

    ctx.notify?.(toolEvent("job:created", jobRes.data.jobId!, { tier, status: "PENDING" }));
    return jsonResult({
      jobId: jobRes.data.jobId,
      creditsCost: jobRes.data.creditsCost ?? cost,
      aspect_ratio: "1:1",
    });
  });

export const avatar = avatarTool.handler;
export const AvatarInputSchema = z.object(avatarTool.inputSchema);
export type AvatarInput = Parameters<typeof avatar>[0];

import { z } from "zod";
import type { AspectRatio } from "../../mcp/types.js";
import { errorResult, IMG_DEFAULTS, jsonResult, toolEvent } from "../../mcp/types.js";
import { tryCatch } from "../../mcp/try-catch.js";
import { imageProcedure } from "../../lazy-imports/image-middleware.js";
import { consumeCreditsOrError } from "../define-tool.js";

const PRESET_ASPECT_RATIOS: Record<
  string,
  { aspectRatio: AspectRatio; recommended_size?: string }
> = {
  github_readme: { aspectRatio: "16:9" },
  twitter_header: { aspectRatio: "4:1" },
  youtube_thumbnail: { aspectRatio: "16:9" },
  linkedin_cover: { aspectRatio: "4:1" },
  og: { aspectRatio: "16:9", recommended_size: "1200x630" },
};

function buildOgPrompt(title: string, subtitle?: string, prompt?: string): string {
  const parts = [IMG_DEFAULTS.promptBannerOg, `Title: "${title}".`];
  if (subtitle) parts.push(`Subtitle: "${subtitle}".`);
  if (prompt) parts.push(prompt);
  return parts.join(" ");
}

export const bannerTool = imageProcedure
  .tool(
    "banner",
    "Generates a banner or social media header image based on a prompt, preset platform size, and optional text.",
    {
      prompt: z.string().describe("Description of the desired banner"),
      preset: z
        .enum([
          "github_readme",
          "twitter_header",
          "youtube_thumbnail",
          "linkedin_cover",
          "og",
          "custom",
        ])
        .describe(
          "Platform preset: github_readme, twitter_header, youtube_thumbnail, linkedin_cover, og, or custom",
        ),
      custom_aspect_ratio: z
        .string()
        .describe("Custom aspect ratio (only used with preset=custom)")
        .optional(),
      tier: z
        .enum(["FREE", "TIER_0_5K", "TIER_1K", "TIER_2K", "TIER_4K"])
        .describe("Enhancement tier for generation quality")
        .optional(),
      title: z.string().describe("Title text to overlay on the banner").optional(),
      subtitle: z.string().describe("Subtitle text to overlay on the banner").optional(),
    },
  )
  .handler(async ({ input: input, ctx: ctx }) => {
    if (input.preset === "custom" && !input.custom_aspect_ratio) {
      return errorResult(
        "INVALID_INPUT",
        "custom_aspect_ratio is required when preset is 'custom'",
      );
    }
    const { userId, deps } = ctx;
    const tier = input.tier ?? "TIER_1K";
    const cost = deps.credits.calculateGenerationCost({
      tier,
      hasTextRender: !!input.title,
    });

    let aspectRatio: AspectRatio;
    let recommendedSize: string | undefined;
    if (input.preset === "custom") {
      aspectRatio = input.custom_aspect_ratio as AspectRatio;
    } else {
      const presetInfo = PRESET_ASPECT_RATIOS[input.preset];
      if (!presetInfo) throw new Error(`Unknown preset: ${input.preset}`);
      aspectRatio = presetInfo.aspectRatio;
      recommendedSize = presetInfo.recommended_size;
    }
    const fullPrompt = input.title
      ? buildOgPrompt(input.title, input.subtitle, input.prompt)
      : `A banner image for ${input.preset.replace(/_/g, " ")}. ${input.prompt}`;

    // Use advanced generation when title is provided and the capability exists
    if (input.title && deps.generation.createAdvancedGenerationJob) {
      const jobRes = await tryCatch(
        deps.generation.createAdvancedGenerationJob({
          userId,
          prompt: fullPrompt,
          tier,
          options: { textToRender: input.title },
        }),
      );

      if (!jobRes.ok) {
        return errorResult("GENERATION_FAILED", jobRes.error.message, true);
      }
      if (!jobRes.data?.success) {
        return errorResult(
          "GENERATION_FAILED",
          jobRes.data?.error ?? "Failed to create banner job",
          true,
        );
      }

      const { error } = await consumeCreditsOrError(
        deps,
        userId,
        cost,
        "banner",
        jobRes.data.jobId,
        ctx,
      );
      if (error) return error;

      ctx.notify?.(
        toolEvent("job:created", jobRes.data.jobId!, {
          tier,
          preset: input.preset,
          status: "PENDING",
        }),
      );

      return jsonResult({
        jobId: jobRes.data.jobId,
        creditsCost: jobRes.data.creditsCost ?? cost,
        preset: input.preset,
        aspect_ratio: aspectRatio,
        ...(recommendedSize ? { recommended_size: recommendedSize } : {}),
      });
    }

    const jobRes = await tryCatch(
      deps.generation.createGenerationJob({
        userId,
        prompt: fullPrompt,
        tier,
        aspectRatio,
      }),
    );

    if (!jobRes.ok) {
      return errorResult("GENERATION_FAILED", jobRes.error.message, true);
    }
    if (!jobRes.data?.success) {
      return errorResult(
        "GENERATION_FAILED",
        jobRes.data?.error ?? "Failed to create banner job",
        true,
      );
    }

    const { error } = await consumeCreditsOrError(
      deps,
      userId,
      cost,
      "banner",
      jobRes.data.jobId,
      ctx,
    );
    if (error) return error;

    ctx.notify?.(
      toolEvent("job:created", jobRes.data.jobId!, {
        tier,
        preset: input.preset,
        status: "PENDING",
      }),
    );

    return jsonResult({
      jobId: jobRes.data.jobId,
      creditsCost: jobRes.data.creditsCost ?? cost,
      preset: input.preset,
      aspect_ratio: aspectRatio,
      ...(recommendedSize ? { recommended_size: recommendedSize } : {}),
    });
  });

export const banner = bannerTool.handler;
export const BannerInputSchema = z.object(bannerTool.inputSchema);
export type BannerInput = Parameters<typeof banner>[0];

import { z } from "zod";
import { IMG_DEFAULTS, jsonResult } from "../../mcp/types.js";
import {
  imageProcedure,
  withCredits,
  withJob,
  withResolves,
} from "../../lazy-imports/image-middleware.js";

const PRESET_DIMENSIONS: Record<string, { width: number; height: number; label: string }> = {
  instagram_square: {
    width: 1080,
    height: 1080,
    label: "Instagram Square (1:1)",
  },
  instagram_story: {
    width: 1080,
    height: 1920,
    label: "Instagram Story (9:16)",
  },
  twitter_header: { width: 1500, height: 500, label: "Twitter Header (3:1)" },
  facebook_cover: { width: 820, height: 312, label: "Facebook Cover" },
  youtube_thumbnail: {
    width: 1280,
    height: 720,
    label: "YouTube Thumbnail (16:9)",
  },
  linkedin_banner: { width: 1584, height: 396, label: "LinkedIn Banner (4:1)" },
};

export const cropTool = imageProcedure
  .use(withResolves({ image_id: "image" }))
  .use(
    withCredits({
      cost: () => 1,
      source: "crop",
      sourceIdField: "image_id",
    }),
  )
  .use(withJob({ imageIdField: "image_id" }))
  .tool("crop", "Intelligently crop an image for social media or custom dimensions.", {
    image_id: z.string().describe("ID of the image to crop"),
    preset: z
      .enum([
        "instagram_square",
        "instagram_story",
        "twitter_header",
        "facebook_cover",
        "youtube_thumbnail",
        "linkedin_banner",
        "custom",
      ])
      .describe("Crop preset (e.g. instagram_square, twitter_header) or custom")
      .optional(),
    custom_width: z
      .number()
      .describe("Custom width in pixels (only with preset=custom)")
      .optional(),
    custom_height: z
      .number()
      .describe("Custom height in pixels (only with preset=custom)")
      .optional(),
  })
  .handler(async ({ input: input, ctx: ctx }) => {
    const preset = input.preset ?? IMG_DEFAULTS.smartCropPreset;
    const customWidth = input.custom_width ?? 1080;
    const customHeight = input.custom_height ?? 1080;

    let targetWidth: number;
    let targetHeight: number;

    if (preset === "custom") {
      targetWidth = customWidth;
      targetHeight = customHeight;
    } else {
      const dims = PRESET_DIMENSIONS[preset];
      targetWidth = dims!.width;
      targetHeight = dims!.height;
    }

    return jsonResult({
      jobId: ctx.jobs.currentJob.id,
      type: "smart_crop",
      preset,
      targetWidth,
      targetHeight,
      creditsCost: ctx.billing.creditsCost,
      status: ctx.jobs.currentJob.status,
    });
  });

export const crop = cropTool.handler;
export const CropInputSchema = z.object(cropTool.inputSchema);
export type CropInput = Parameters<typeof crop>[0];

import { z } from "zod";
import type { AspectRatio, EnhancementTier } from "../../mcp/types.js";
import {
  DIAGRAM_STYLE_VALUES,
  DIAGRAM_TYPE_VALUES,
  errorResult,
  jsonResult,
  toolEvent,
} from "../../mcp/types.js";
import { tryCatch } from "../../mcp/try-catch.js";
import { imageProcedure, withCredits } from "../../lazy-imports/image-middleware.js";

export const diagramTool = imageProcedure
  .use(
    withCredits({
      cost: (input, deps) =>
        deps.credits.calculateGenerationCost({
          tier: ((input as Record<string, unknown>)["tier"] as EnhancementTier) ?? "TIER_1K",
        }),
      source: "diagram",
    }),
  )
  .tool("diagram", "Description of the diagram to generate", {
    prompt: z.string().describe("Description of the diagram to generate"),
    type: z
      .enum(DIAGRAM_TYPE_VALUES)
      .describe("Diagram type: architecture, flowchart, sequence, er, or network")
      .optional(),
    style: z
      .enum(DIAGRAM_STYLE_VALUES)
      .describe("Visual style: technical, hand_drawn, or minimal")
      .optional(),
    tier: z
      .enum(["FREE", "TIER_0_5K", "TIER_1K", "TIER_2K", "TIER_4K"])
      .describe("Enhancement tier for output quality")
      .optional(),
  })
  .handler(async ({ input: input, ctx: ctx }) => {
    const { userId, deps } = ctx;
    const tier = input.tier ?? "TIER_1K";
    const diagramType = input.type ?? "architecture";
    const style = input.style ?? "technical";
    const cost = ctx.billing.creditsCost;
    const aspectRatio: AspectRatio = diagramType === "sequence" ? "3:4" : "16:9";

    const fullPrompt = `A clear, readable ${diagramType} diagram. Style: ${style}. ${input.prompt}`;

    if (deps.generation.createAdvancedGenerationJob) {
      const jobRes = await tryCatch(
        deps.generation.createAdvancedGenerationJob({
          userId,
          prompt: fullPrompt,
          tier,
          options: { thinkingMode: true },
        }),
      );

      if (!jobRes.ok) {
        return errorResult("GENERATION_FAILED", jobRes.error.message, true);
      }
      if (!jobRes.data?.success) {
        return errorResult(
          "GENERATION_FAILED",
          jobRes.data?.error ?? "Failed to create diagram job",
          true,
        );
      }

      ctx.notify?.(
        toolEvent("job:created", jobRes.data.jobId!, {
          tier,
          diagram_type: diagramType,
          status: "PENDING",
        }),
      );
      return jsonResult({
        jobId: jobRes.data.jobId,
        creditsCost: jobRes.data.creditsCost ?? cost,
        diagram_type: diagramType,
        aspect_ratio: aspectRatio,
      });
    }

    const jobRes = await tryCatch(
      deps.generation.createGenerationJob({
        userId,
        prompt: fullPrompt,
        tier,
        aspectRatio,
      }),
    );

    if (!jobRes.ok) {
      return errorResult("GENERATION_FAILED", jobRes.error.message, true);
    }
    if (!jobRes.data?.success) {
      return errorResult(
        "GENERATION_FAILED",
        jobRes.data?.error ?? "Failed to create diagram job",
        true,
      );
    }

    ctx.notify?.(
      toolEvent("job:created", jobRes.data.jobId!, {
        tier,
        diagram_type: diagramType,
        status: "PENDING",
      }),
    );
    return jsonResult({
      jobId: jobRes.data.jobId,
      creditsCost: jobRes.data.creditsCost ?? cost,
      diagram_type: diagramType,
      aspect_ratio: aspectRatio,
    });
  });

export const diagram = diagramTool.handler;
export const DiagramInputSchema = z.object(diagramTool.inputSchema);
