import { z } from "zod";
import type { EnhancementTier } from "../../mcp/types.js";
import {
  errorResult,
  IMG_DEFAULTS,
  jsonResult,
  MODEL_PREFERENCE_VALUES,
  toolEvent,
} from "../../mcp/types.js";
import { tryCatch } from "../../mcp/try-catch.js";
import { imageProcedure, withResolves } from "../../lazy-imports/image-middleware.js";

export const editTool = imageProcedure
  .use(withResolves({ source_image_id: "image" }))
  .tool(
    "edit",
    "Modify an existing image with a text prompt (merges image-modify + style-transfer).",
    {
      prompt: z.string().describe("Text prompt describing the desired modifications").optional(),
      image_url: z.string().describe("URL of an external image to modify").optional(),
      image_base64: z.string().describe("Base64-encoded image data to modify").optional(),
      source_image_id: z.string().describe("Library image ID to use as source").optional(),
      mime_type: z
        .string()
        .describe("MIME type of the image (e.g. image/jpeg). Defaults to image/jpeg")
        .optional(),
      tier: z
        .enum(["FREE", "TIER_0_5K", "TIER_1K", "TIER_2K", "TIER_4K"])
        .describe("Enhancement tier — higher tiers produce better quality")
        .optional(),
      model_preference: z
        .enum(MODEL_PREFERENCE_VALUES)
        .describe("Model preference: default, quality, speed, or latest")
        .optional(),
    },
  )
  .handler(async ({ input: input, ctx: ctx }) => {
    const { userId, deps } = ctx;
    const prompt = input.prompt ?? IMG_DEFAULTS.promptModify;
    const tier = (input.tier ?? IMG_DEFAULTS.tier) as EnhancementTier;
    const mimeType = input.mime_type ?? "image/jpeg";

    let imageData: string;

    if (input.source_image_id) {
      const image = ctx.entities.source_image_id;

      const downloadResult = await tryCatch(deps.storage.download(image.originalR2Key));
      /* v8 ignore next */
      if (!downloadResult.ok || !downloadResult.data) {
        return errorResult("DOWNLOAD_FAILED", "Failed to download source image data", true);
      }
      imageData = Buffer.from(downloadResult.data).toString("base64");
    } else if (input.image_base64) {
      imageData = input.image_base64;
    } else if (input.image_url) {
      const responseResult = await tryCatch(fetch(input.image_url));
      if (!responseResult.ok) {
        return errorResult("FETCH_FAILED", responseResult.error.message, true);
      }
      if (!responseResult.data || !responseResult.data.ok) {
        return errorResult(
          "FETCH_FAILED",
          `Failed to fetch image: ${responseResult.data?.status ?? "Network error"}`,
          true,
        );
      }
      const bufferResult = await tryCatch(responseResult.data.arrayBuffer());
      if (!bufferResult.ok || !bufferResult.data) {
        return errorResult("FETCH_FAILED", "Failed to read image data", true);
      }
      imageData = Buffer.from(bufferResult.data).toString("base64");
    } else {
      return errorResult("MISSING_IMAGE", "Provide source_image_id, image_url, or image_base64");
    }

    const result = await tryCatch(
      deps.generation.createModificationJob({
        userId,
        prompt,
        imageData,
        mimeType,
        tier,
      }),
    );

    if (!result.ok) {
      return errorResult("MODIFICATION_FAILED", result.error.message, true);
    }
    if (!result.data || !result.data.success) {
      return errorResult(
        "MODIFICATION_FAILED",
        result.data?.error ?? "Failed to create modification job",
        true,
      );
    }

    ctx.notify?.(toolEvent("job:created", result.data.jobId!, { tier, status: "PENDING" }));
    return jsonResult({
      jobId: result.data.jobId,
      creditsCost: result.data.creditsCost,
      tier,
      status: "PENDING",
    });
  });

export const edit = editTool.handler;
export const EditInputSchema = z.object(editTool.inputSchema);
export type EditInput = Parameters<typeof edit>[0];

import { z } from "zod";
import type { SubjectReference } from "../../mcp/types.js";
import {
  asImageId,
  errorResult,
  GENERATION_OUTPUT_FORMAT_VALUES,
  GENERATION_RESOLUTION_VALUES,
  IMG_DEFAULTS,
  jsonResult,
  MODEL_PREFERENCE_VALUES,
  REFERENCE_ROLE_VALUES,
  SUPPORTED_ASPECT_RATIOS,
  toolEvent,
} from "../../mcp/types.js";
import { tryCatch } from "../../mcp/try-catch.js";
import { imageProcedure } from "../../lazy-imports/image-middleware.js";

export const generateTool = imageProcedure
  .tool(
    "generate",
    "Generate images from text prompts with optional reference images, subjects, and advanced options",
    {
      prompt: z.string().describe("Text prompt for image generation").optional(),
      negative_prompt: z.string().describe("What to avoid in the generated image").optional(),
      aspect_ratio: z
        .enum(SUPPORTED_ASPECT_RATIOS)
        .describe("Aspect ratio (default 1:1)")
        .optional(),
      tier: z
        .enum(["FREE", "TIER_0_5K", "TIER_1K", "TIER_2K", "TIER_4K"])
        .describe("Quality tier — higher tiers cost more credits")
        .optional(),
      model_preference: z
        .enum(MODEL_PREFERENCE_VALUES)
        .describe("Model routing hint: default, quality, speed, latest")
        .optional(),
      resolution: z
        .enum(GENERATION_RESOLUTION_VALUES)
        .describe("Output resolution (advanced)")
        .optional(),
      thinking_mode: z
        .boolean()
        .describe("Enable thinking mode for better prompt interpretation")
        .optional(),
      google_search_grounding: z
        .boolean()
        .describe("Ground generation in current web knowledge")
        .optional(),
      text_to_render: z.string().describe("Text to render inside the image").optional(),
      subject_refs: z
        .array(z.string().describe("Subject ID or label"))
        .describe("Subject labels or IDs to include")
        .optional(),
      reference_images: z
        .array(
          z.object({
            url: z.string().describe("External URL of reference image").optional(),
            image_id: z
              .string()
              .describe("ID of a user-owned image to use as reference")
              .optional(),
            role: z
              .enum(REFERENCE_ROLE_VALUES)
              .describe("Role: style, subject, composition, color")
              .optional(),
          }),
        )
        .describe("Reference images for style/subject transfer")
        .optional(),
      seed: z.number().describe("Random seed for reproducibility").optional(),
      output_format: z
        .enum(GENERATION_OUTPUT_FORMAT_VALUES)
        .describe("Output format: png, jpeg, webp")
        .optional(),
      num_images: z
        .number()
        .min(1)
        .max(4)
        .describe("Number of images to generate (1-4)")
        .optional(),
    },
  )
  .handler(async ({ input: input, ctx: ctx }) => {
    const { userId, deps } = ctx;
    const {
      negative_prompt,
      thinking_mode,
      google_search_grounding,
      text_to_render,
      subject_refs,
      reference_images,
      seed,
      num_images,
    } = input;
    const prompt = input.prompt ?? IMG_DEFAULTS.promptGenerate;
    const tier = input.tier ?? IMG_DEFAULTS.tier;
    const aspectRatio = input.aspect_ratio ?? IMG_DEFAULTS.aspectRatio;
    const modelPreference = input.model_preference ?? IMG_DEFAULTS.modelPreference;
    const resolution = input.resolution;
    const outputFormat = input.output_format;

    const creditsCost = deps.credits.calculateGenerationCost({
      tier,
      numImages: num_images,
      hasGrounding: google_search_grounding,
      hasTextRender: !!text_to_render,
      numSubjects: subject_refs?.length,
      numReferences: reference_images?.length,
    });

    const hasEnough = await deps.credits.hasEnough(userId, creditsCost);
    if (!hasEnough) {
      return errorResult("BALANCE_ERROR", `Insufficient credits. Required: ${creditsCost}`);
    }

    // ── Reference generation path ──
    if (reference_images && reference_images.length > 0) {
      if (!deps.generation.createReferenceGenerationJob) {
        return errorResult("NOT_SUPPORTED", "Reference generation is not available", true);
      }

      const refs: Array<{
        imageId?: string;
        url?: string;
        role: (typeof REFERENCE_ROLE_VALUES)[number];
      }> = [];
      for (const ref of reference_images) {
        if (ref.image_id) {
          const imgRes = await tryCatch(deps.resolvers.resolveImage(asImageId(ref.image_id)));
          if (!imgRes.ok || !imgRes.data || imgRes.data.userId !== userId) {
            return errorResult("IMAGE_NOT_FOUND", `Reference image ${ref.image_id} not found`);
          }
          refs.push({ imageId: imgRes.data.id, role: ref.role ?? "style" });
        } else if (ref.url) {
          refs.push({ url: ref.url, role: ref.role ?? "style" });
        }
      }

      const resp = await tryCatch(
        deps.generation.createReferenceGenerationJob({
          userId,
          prompt,
          tier,
          referenceImages: refs,
          seed,
          outputFormat,
          numImages: num_images,
        }),
      );

      if (!resp.ok) {
        return errorResult("GENERATION_FAILED", resp.error.message, true);
      }
      /* v8 ignore next */
      if (!resp.data.success) {
        return errorResult("GENERATION_FAILED", resp.data.error ?? "Reference generation failed");
      }
      ctx.notify?.(toolEvent("job:created", resp.data.jobId!, { tier, status: "PENDING" }));
      return jsonResult({
        jobId: resp.data.jobId,
        status: "PENDING",
        tier,
        creditsCost: resp.data.creditsCost,
      });
    }

    // ── Advanced generation path ──
    const hasAdvancedParams =
      resolution !== undefined ||
      thinking_mode !== undefined ||
      google_search_grounding !== undefined ||
      text_to_render !== undefined ||
      (subject_refs !== undefined && subject_refs.length > 0);

    if (hasAdvancedParams) {
      if (!deps.generation.createAdvancedGenerationJob) {
        return errorResult("NOT_SUPPORTED", "Advanced generation is not available", true);
      }

      let subjects: SubjectReference[] | undefined;
      if (subject_refs && subject_refs.length > 0 && deps.db.subjectFindMany) {
        const subRes = await tryCatch(deps.db.subjectFindMany({ userId }));
        if (!subRes.ok || !subRes.data) {
          return errorResult("SUBJECT_LIST_FAILED", "Failed to fetch subjects", true);
        }
        subjects = [];
        for (const ref of subject_refs) {
          const sub = subRes.data.find((s) => s.id === ref || s.label === ref);
          if (!sub) {
            return errorResult("SUBJECT_NOT_FOUND", `Subject "${ref}" not found`);
          }
          subjects.push({
            label: sub.label,
            type: sub.type,
            sourceImageId: sub.imageId,
          });
        }
      }

      const resp = await tryCatch(
        deps.generation.createAdvancedGenerationJob({
          userId,
          prompt,
          tier,
          options: {
            modelPreference,
            resolution,
            thinkingMode: thinking_mode,
            googleSearchGrounding: google_search_grounding,
            textToRender: text_to_render,
            subjects,
            seed,
            outputFormat,
            numImages: num_images,
            negativePrompt: negative_prompt,
            aspectRatio,
          },
        }),
      );

      if (!resp.ok) {
        return errorResult("GENERATION_FAILED", resp.error.message, true);
      }
      if (!resp.data.success) {
        return errorResult("GENERATION_FAILED", resp.data.error ?? "Advanced generation failed");
      }
      ctx.notify?.(toolEvent("job:created", resp.data.jobId!, { tier, status: "PENDING" }));
      return jsonResult({
        jobId: resp.data.jobId,
        status: "PENDING",
        tier,
        creditsCost: resp.data.creditsCost,
      });
    }

    // ── Basic generation path ──
    const resp = await tryCatch(
      deps.generation.createGenerationJob({
        userId,
        prompt,
        tier,
        negativePrompt: negative_prompt,
        aspectRatio,
        seed,
        outputFormat,
        numImages: num_images,
      }),
    );

    if (!resp.ok) {
      return errorResult("GENERATION_FAILED", resp.error.message, true);
    }
    if (!resp.data.success) {
      return errorResult("GENERATION_FAILED", resp.data.error ?? "Generation failed");
    }
    ctx.notify?.(toolEvent("job:created", resp.data.jobId!, { tier, status: "PENDING" }));
    return jsonResult({
      jobId: resp.data.jobId,
      status: "PENDING",
      tier,
      creditsCost: resp.data.creditsCost,
    });
  });

export const generate = generateTool.handler;
export const GenerateInputSchema = z.object(generateTool.inputSchema);
export type GenerateInput = Parameters<typeof generate>[0];

import { z } from "zod";
import type { EnhancementTier } from "../../mcp/types.js";
import {
  errorResult,
  ICON_STYLE_VALUES,
  ICON_TARGET_VALUES,
  IMG_DEFAULTS,
  jsonResult,
  toolEvent,
} from "../../mcp/types.js";
import { tryCatch } from "../../mcp/try-catch.js";
import {
  imageProcedure,
  withCredits,
  withOwnership,
  withResolves,
} from "../../lazy-imports/image-middleware.js";

const PLATFORM_SIZES = {
  ios: [20, 29, 40, 58, 60, 76, 80, 87, 120, 152, 167, 180, 1024],
  android: [48, 72, 96, 144, 192, 512],
  favicon: [16, 32, 48],
} as const;

export const iconTool = imageProcedure
  .use(withResolves({ source_image_id: "image" }))
  .use(withOwnership(["source_image_id"]))
  .use(
    withCredits({
      cost: (input, deps) =>
        deps.credits.calculateGenerationCost({
          tier: ((input as Record<string, unknown>)["tier"] as EnhancementTier) ?? "TIER_1K",
        }),
      source: "icon",
    }),
  )
  .tool(
    "icon",
    "Generates an app icon or favicon based on a prompt, target platform, and visual style.",
    {
      prompt: z.string().describe("Description of the desired icon").optional(),
      source_image_id: z.string().describe("Source image to use").optional(),
      target: z
        .enum(ICON_TARGET_VALUES)
        .describe("Target platform: favicon, ios, android, or both")
        .optional(),
      tier: z
        .enum(["FREE", "TIER_0_5K", "TIER_1K", "TIER_2K", "TIER_4K"])
        .describe("Enhancement tier for generation quality")
        .optional(),
      style: z
        .enum(ICON_STYLE_VALUES)
        .describe("Icon style: flat, gradient, outlined, 3d, or pixel")
        .optional(),
    },
  )
  .handler(async ({ input, ctx }) => {
    if (!input.prompt && !input.source_image_id) {
      return errorResult("INVALID_INPUT", "Either prompt or source_image_id is required");
    }
    const { userId, deps } = ctx;
    const tier = input.tier ?? "TIER_1K";
    const target = input.target ?? "both";
    const style = input.style ?? "flat";

    const isFavicon = target === "favicon";
    const promptPrefix = isFavicon ? IMG_DEFAULTS.promptIconFavicon : IMG_DEFAULTS.promptIconApp;
    const fullPrompt = `${promptPrefix} Style: ${style}. ${input.prompt ?? ""}`.trim();

    // Reference image path
    if (input.source_image_id && deps.generation.createReferenceGenerationJob) {
      const jobRes = await tryCatch(
        deps.generation.createReferenceGenerationJob({
          userId,
          prompt: fullPrompt,
          tier,
          referenceImages: [
            {
              imageId: input.source_image_id,
              role: "subject",
            },
          ],
        }),
      );

      if (!jobRes.ok) {
        return errorResult("GENERATION_FAILED", jobRes.error.message, true);
      }
      /* v8 ignore next */
      if (!jobRes.data?.success) {
        return errorResult(
          "GENERATION_FAILED",
          jobRes.data?.error ?? "Failed to create icon job",
          true,
        );
      }

      ctx.notify?.(
        toolEvent("job:created", jobRes.data.jobId!, {
          tier,
          target,
          status: "PENDING",
        }),
      );
      return jsonResult({
        jobId: jobRes.data.jobId,
        creditsCost: jobRes.data.creditsCost ?? ctx.billing.creditsCost,
        aspect_ratio: "1:1",
        target,
        output_sizes: buildOutputSizes(target),
      });
    }

    // Prompt-only path
    const jobRes = await tryCatch(
      deps.generation.createGenerationJob({
        userId,
        prompt: fullPrompt,
        tier,
        aspectRatio: "1:1",
      }),
    );

    if (!jobRes.ok) {
      return errorResult("GENERATION_FAILED", jobRes.error.message, true);
    }
    if (!jobRes.data?.success) {
      return errorResult(
        "GENERATION_FAILED",
        jobRes.data?.error ?? "Failed to create icon job",
        true,
      );
    }

    ctx.notify?.(
      toolEvent("job:created", jobRes.data.jobId!, {
        tier,
        target,
        status: "PENDING",
      }),
    );
    return jsonResult({
      jobId: jobRes.data.jobId,
      creditsCost: jobRes.data.creditsCost ?? ctx.billing.creditsCost,
      aspect_ratio: "1:1",
      target,
      output_sizes: buildOutputSizes(target),
    });
  });

function buildOutputSizes(
  target: "favicon" | "ios" | "android" | "both",
): Record<string, readonly number[]> {
  if (target === "favicon") {
    return { favicon: PLATFORM_SIZES.favicon };
  }
  if (target === "both") {
    return { ios: PLATFORM_SIZES.ios, android: PLATFORM_SIZES.android };
  }
  return { [target]: PLATFORM_SIZES[target] };
}

export const icon = iconTool.handler;
export const IconInputSchema = z.object(iconTool.inputSchema);
export type IconInput = Parameters<typeof icon>[0];

import { z } from "zod";
import type { EnhancementTier } from "../../mcp/types.js";
import {
  errorResult,
  jsonResult,
  SCREENSHOT_BACKGROUND_VALUES,
  SCREENSHOT_DEVICE_VALUES,
  toolEvent,
} from "../../mcp/types.js";
import { tryCatch } from "../../mcp/try-catch.js";
import {
  imageProcedure,
  withCredits,
  withOwnership,
  withResolves,
} from "../../lazy-imports/image-middleware.js";

export const screenshotTool = imageProcedure
  .use(withResolves({ source_image_id: "image" }))
  .use(withOwnership(["source_image_id"]))
  .use(
    withCredits({
      cost: (input, deps) =>
        deps.credits.calculateGenerationCost({
          tier: ((input as Record<string, unknown>)["tier"] as EnhancementTier) ?? "TIER_1K",
        }),
      source: "screenshot",
      sourceIdField: "source_image_id",
    }),
  )
  .tool("screenshot", "Place a screenshot into a device mockup", {
    source_image_id: z.string().describe("ID of the source image"),
    device: z.enum(SCREENSHOT_DEVICE_VALUES).describe("Device mockup type").optional(),
    background: z.enum(SCREENSHOT_BACKGROUND_VALUES).describe("Background type").optional(),
    tier: z
      .enum(["FREE", "TIER_0_5K", "TIER_1K", "TIER_2K", "TIER_4K"])
      .describe("Enhancement tier for output quality")
      .optional(),
  })
  .handler(async ({ input: input, ctx: ctx }) => {
    const { userId, deps } = ctx;
    const tier = input.tier ?? "TIER_1K";
    const device = input.device ?? "iphone";
    const background = input.background ?? "gradient";

    const image = ctx.entities.source_image_id;

    const downloadRes = await tryCatch(deps.storage.download(image.originalR2Key));
    if (!downloadRes.ok || !downloadRes.data) {
      return errorResult("DOWNLOAD_FAILED", "Failed to download source image", true);
    }

    const fullPrompt = `Place this screenshot into a ${device} device mockup with a ${background} background.`;

    const jobRes = await tryCatch(
      deps.generation.createModificationJob({
        userId,
        prompt: fullPrompt,
        imageData: downloadRes.data.toString("base64"),
        mimeType: `image/${image.originalFormat}`,
        tier,
      }),
    );

    if (!jobRes.ok) {
      return errorResult("GENERATION_FAILED", jobRes.error.message, true);
    }
    if (!jobRes.data?.success) {
      return errorResult(
        "GENERATION_FAILED",
        jobRes.data?.error ?? "Failed to create screenshot mockup job",
        true,
      );
    }

    ctx.notify?.(
      toolEvent("job:created", jobRes.data.jobId!, {
        tier,
        device,
        background,
        status: "PENDING",
      }),
    );

    return jsonResult({
      jobId: jobRes.data.jobId,
      creditsCost: ctx.billing.creditsCost,
      device,
      background,
      source_image_id: input.source_image_id,
    });
  });

export const screenshot = screenshotTool.handler;
export const ScreenshotInputSchema = z.object(screenshotTool.inputSchema);
export type ScreenshotInput = Parameters<typeof screenshot>[0];

/**
 * iwd_story_album + iwd_timeline
 */

import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { z } from "zod";
import { createZodTool, jsonResult } from "@spike-land-ai/mcp-server-base";
import type { ToolClient } from "../mcp/types.js";
import { IWD_MILESTONES, IWD_BRAND, timelinePrompt } from "../mcp/types.js";

const ALBUM_THEMES = ["pioneers", "leaders", "innovators", "future_vision", "community"] as const;

export function registerStorytellingTools(server: McpServer, client: ToolClient): void {
  createZodTool(server, {
    name: "iwd_story_album",
    description:
      "Create a themed image album celebrating women in tech. Generates multiple images around a theme (pioneers, leaders, innovators, future_vision, community).",
    schema: {
      theme: z.enum(ALBUM_THEMES).describe("Album theme"),
      image_count: z.number().int().min(1).max(8).default(4).describe("Number of images to generate"),
      title: z.string().optional().describe("Custom album title"),
    },
    async handler({ theme, image_count, title }) {
      const albumTitle = title ?? `${IWD_BRAND.tagline} — ${theme.charAt(0).toUpperCase() + theme.slice(1)}`;

      const themePrompts: Record<string, string[]> = {
        pioneers: [
          "Ada Lovelace writing the first algorithm, Victorian era with modern tech overlay",
          "Grace Hopper at a computer console, pioneering compiler technology",
          "Katherine Johnson calculating orbital trajectories at NASA",
          "Hedy Lamarr inventing frequency-hopping spread spectrum",
          "Radia Perlman designing network protocols on a whiteboard",
          "Margaret Hamilton standing next to Apollo guidance code printouts",
          "Annie Easley working on rocket propulsion at NASA",
          "Sister Mary Kenneth Keller receiving first CS PhD in America",
        ],
        leaders: [
          "Woman CEO presenting at a tech conference, commanding stage presence",
          "Diverse women board meeting in a modern tech office",
          "Woman CTO leading an architecture design review",
          "Female venture capitalist reviewing startup pitches",
          "Woman engineering director mentoring junior developers",
          "Tech executive speaking at a product launch event",
          "Woman leading a hackathon team to victory",
          "Female founder ringing the stock exchange bell",
        ],
        innovators: [
          "Woman engineer building a robot in a modern lab",
          "Female data scientist visualizing breakthrough patterns",
          "Woman designing next-generation AI interface",
          "Female blockchain developer creating decentralized systems",
          "Woman biotech researcher making a discovery",
          "Female game developer creating immersive worlds",
          "Woman cybersecurity expert protecting digital infrastructure",
          "Female quantum computing researcher at the frontier",
        ],
        future_vision: [
          "Diverse women shaping AI ethics policy of the future",
          "Woman astronaut leading Mars colony establishment",
          "Female robotics engineer with humanoid AI companion",
          "Woman architect designing sustainable smart cities",
          "Girls coding in a futuristic classroom",
          "Woman scientist achieving fusion energy breakthrough",
          "Female tech leader at a global innovation summit",
          "Women collaborating on open source in a virtual workspace",
        ],
        community: [
          "Women at a coding bootcamp supporting each other",
          "Girls Who Code workshop with enthusiastic participants",
          "Women's tech meetup with diverse speakers and audience",
          "Female mentorship circle in a modern co-working space",
          "Women hackathon team celebrating their project",
          "Online women-in-tech community virtual meetup",
          "Women-led open source contributors collaborating",
          "Intergenerational women in tech sharing knowledge",
        ],
      };

      const prompts = themePrompts[theme]!.slice(0, image_count);
      const albumResult = await client.callTool("img_album_create", {
        name: albumTitle,
        description: `IWD 2026 album: ${theme}`,
      });

      const imageResults = await Promise.all(
        prompts.map((prompt) =>
          client.callTool("img_generate", {
            prompt: `${prompt}. Style: ${IWD_BRAND.tagline} celebration, purple (#A020F0) and green (#44B78B) accents, empowering, modern art.`,
            aspect_ratio: "16:9",
          })
        ),
      );

      return jsonResult({
        album: extractContent(albumResult),
        theme,
        title: albumTitle,
        images: imageResults.map((r, i) => ({
          prompt: prompts[i],
          result: extractContent(r),
        })),
      });
    },
  });

  createZodTool(server, {
    name: "iwd_timeline",
    description:
      "Generate a visual timeline of women-in-tech milestones as a diagram image. Uses curated historical data from 1843 to present.",
    schema: {
      start_year: z.number().int().optional().describe("Filter: start year (default: show all)"),
      end_year: z.number().int().optional().describe("Filter: end year (default: show all)"),
    },
    async handler({ start_year, end_year }) {
      const milestones = IWD_MILESTONES.filter((m) => {
        if (start_year && m.year < start_year) return false;
        if (end_year && m.year > end_year) return false;
        return true;
      });

      const mermaidDiagram = [
        "timeline",
        `    title ${IWD_BRAND.tagline} — Women in Tech Milestones`,
        ...milestones.map((m) => `    ${m.year} : ${m.title} : ${m.description}`),
      ].join("\n");

      const diagramResult = await client.callTool("img_diagram", {
        diagram: mermaidDiagram,
        format: "png",
      });

      return jsonResult({
        milestones,
        diagram: extractContent(diagramResult),
        prompt_used: timelinePrompt(),
      });
    },
  });
}

function extractContent(result: { content: Array<{ text: string }> }): string {
  return result.content[0]?.text ?? "";
}

#!/usr/bin/env node
/**
 * IWD Spotlight MCP Server — Orchestrator for International Women's Day 2026.
 *
 * Composes existing MCP tools (Image Studio, HackerNews, Stripe, GA4, Code Review)
 * into a celebration-themed toolkit. Pure orchestrator — no database, no state.
 */

import { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";
import { wrapServerWithLogging, registerFeedbackTool } from "@spike-land-ai/mcp-server-base";
import type { ToolClient } from "./types.js";

import { registerSpotlightTools } from "../core-logic/spotlight.js";
import { registerCampaignTools } from "../core-logic/campaign.js";
import { registerAmplifierTools } from "../core-logic/amplifier.js";
import { registerStorytellingTools } from "../core-logic/storytelling.js";
import { registerDashboardTools } from "../core-logic/dashboard.js";
import { registerContributorTools } from "../core-logic/contributors.js";

const SERVER_NAME = "iwd-spotlight";
const SERVER_VERSION = "0.1.0";

const server = new McpServer({
  name: SERVER_NAME,
  version: SERVER_VERSION,
});

wrapServerWithLogging(server, SERVER_NAME);

// ToolClient that delegates to the MCP server's own tool call mechanism.
// In production, this would be wired to a multiplexer like spike-cli.
// For now, it provides the interface; callers configure their own client.
const toolClient: ToolClient = {
  async callTool(name: string, args: Record<string, unknown>) {
    // In a composed MCP setup, the host (e.g. spike-cli) routes these calls
    // to the appropriate downstream MCP server. This stub logs the intent.
    process.stderr.write(`[iwd-spotlight] Delegating to tool: ${name}\n`);
    return {
      content: [{ type: "text" as const, text: JSON.stringify({ tool: name, args }) }],
    };
  },
};

// Register all tool groups
registerSpotlightTools(server, toolClient);
registerCampaignTools(server, toolClient);
registerAmplifierTools(server, toolClient);
registerStorytellingTools(server, toolClient);
registerDashboardTools(server, toolClient);
registerContributorTools(server, toolClient);
registerFeedbackTool(server, { serviceName: SERVER_NAME, toolName: "iwd_feedback" });

// Start server on stdio
async function main() {
  const transport = new StdioServerTransport();
  await server.connect(transport);
  process.stderr.write(`${SERVER_NAME} MCP Server v${SERVER_VERSION} running on stdio.\n`);
}

main();

import path from "node:path";
import type { McpServer } from "@modelcontextprotocol/sdk/server/mcp.js";
import { z } from "zod";
import { createZodTool, jsonResult } from "@spike-land-ai/mcp-server-base";
import { runPipeline } from "./pipeline.js";

export function registerAnalyzeTool(server: McpServer): void {
  createZodTool(server, {
    name: "reorganize_analyze",
    description:
      "Compute move plans for file reorganization. " +
      "In 'summary' mode, returns category breakdown and top directories. " +
      "In 'diff' mode, returns the full old-path → new-path mapping.",
    schema: {
      src: z.string().optional().describe("Source directory (default: 'src')"),
      mode: z
        .enum(["summary", "diff"])
        .optional()
        .describe("Output mode: 'summary' (default) or 'diff' for full path mapping"),
    },
    handler: async ({ src, mode }) => {
      const { plans } = await runPipeline(src);
      const outputMode = mode ?? "summary";

      if (outputMode === "diff") {
        const mappings = plans.map((p) => ({
          oldPath: p.fileNode.relPath,
          newPath: p.targetRelPath,
        }));
        return jsonResult({ total: plans.length, plans: mappings });
      }

      // Summary mode
      const catStats = new Map<string, number>();
      const dirStats = new Map<string, number>();

      for (const p of plans) {
        const cat = p.targetDir.split(path.sep)[0];
        catStats.set(cat!, (catStats.get(cat!) || 0) + 1);
        dirStats.set(p.targetDir, (dirStats.get(p.targetDir) || 0) + 1);
      }

      const categories = [...catStats.entries()]
        .sort((a, b) => b[1] - a[1])
        .map(([name, count]) => ({
          name,
          count,
          pct: Number(((count / plans.length) * 100).toFixed(1)),
        }));

      const topDirs = [...dirStats.entries()]
        .sort((a, b) => b[1] - a[1])
        .slice(0, 15)
        .map(([dir, count]) => ({ dir, count }));

      return jsonResult({
        totalFiles: plans.length,
        categories,
        topDirs,
      });
    },
  });
}

import { type FC, Fragment } from "react";
import { interpolate, spring, useCurrentFrame, useVideoConfig } from "remotion";
import { COLORS, SPRING_CONFIGS, VERITASIUM_COLORS } from "../../../core-logic/constants";

type NoteLifecycleProps = {
  /** 0-2: which stage to highlight (0=candidate, 1=active, 2=deprecated) */
  activeStage?: number;
  /** Number of stages to show (1-3) */
  revealCount?: number;
  delay?: number;
};

const STAGES = [
  {
    label: "CANDIDATE",
    color: VERITASIUM_COLORS.candidate,
    desc: "New & unproven",
    icon: "🌱",
  },
  {
    label: "ACTIVE",
    color: VERITASIUM_COLORS.active,
    desc: "3+ helps, >60% confidence",
    icon: "✅",
  },
  {
    label: "DEPRECATED",
    color: VERITASIUM_COLORS.deprecated,
    desc: "<30% confidence",
    icon: "📦",
  },
];

export const NoteLifecycle: FC<NoteLifecycleProps> = ({
  activeStage = -1,
  revealCount = 3,
  delay = 0,
}) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  return (
    <div
      style={{
        display: "flex",
        alignItems: "center",
        gap: 0,
        justifyContent: "center",
      }}
    >
      {STAGES.map((stage, i) => {
        if (i >= revealCount) return null;
        const stageDelay = delay + i * 20;
        const progress = spring({
          frame: frame - stageDelay,
          fps,
          config: SPRING_CONFIGS.snappy,
        });
        const isActive = i === activeStage;
        const glowAmount = isActive ? 16 + Math.sin(frame / 8) * 8 : 0;

        return (
          <Fragment key={stage.label}>
            {/* Node */}
            <div
              style={{
                display: "flex",
                flexDirection: "column",
                alignItems: "center",
                gap: 12,
                transform: `scale(${progress})`,
                opacity: interpolate(progress, [0, 1], [0, 1]),
              }}
            >
              <div
                style={{
                  width: 120,
                  height: 120,
                  borderRadius: 60,
                  background: isActive ? `${stage.color}25` : `${stage.color}10`,
                  border: `3px solid ${stage.color}${isActive ? "ff" : "50"}`,
                  display: "flex",
                  flexDirection: "column",
                  alignItems: "center",
                  justifyContent: "center",
                  boxShadow: isActive
                    ? `0 0 ${glowAmount}px ${stage.color}50`
                    : "0 4px 20px rgba(0,0,0,0.3)",
                }}
              >
                <span style={{ fontSize: 32 }}>{stage.icon}</span>
              </div>
              <div
                style={{
                  fontSize: 16,
                  fontWeight: 700,
                  color: stage.color,
                  fontFamily: "JetBrains Mono, monospace",
                  letterSpacing: "0.05em",
                }}
              >
                {stage.label}
              </div>
              <div
                style={{
                  fontSize: 13,
                  color: COLORS.textMuted,
                  fontFamily: "Inter, sans-serif",
                  textAlign: "center",
                  maxWidth: 140,
                }}
              >
                {stage.desc}
              </div>
            </div>

            {/* Arrow between nodes */}
            {i < revealCount - 1 && i < 2 && (
              <div
                style={{
                  display: "flex",
                  alignItems: "center",
                  margin: "0 24px",
                  marginBottom: 60,
                  opacity: spring({
                    frame: frame - stageDelay - 15,
                    fps,
                    config: SPRING_CONFIGS.smooth,
                  }),
                }}
              >
                <div
                  style={{
                    width: 60,
                    height: 2,
                    background: `linear-gradient(90deg, ${
                      STAGES[i]!.color
                    }60, ${STAGES[i + 1]!.color}60)`,
                  }}
                />
                <div
                  style={{
                    width: 0,
                    height: 0,
                    borderTop: "8px solid transparent",
                    borderBottom: "8px solid transparent",
                    borderLeft: `12px solid ${STAGES[i + 1]!.color}60`,
                  }}
                />
              </div>
            )}
          </Fragment>
        );
      })}
    </div>
  );
};

import { type FC } from "react";
import { interpolate, spring, useCurrentFrame, useVideoConfig } from "remotion";
import { COLORS, SPRING_CONFIGS, VERITASIUM_COLORS } from "../../../core-logic/constants";
import { bezierPath, fadeIn } from "../../lib/animations";

type SkillMatchingDiagramProps = {
  url?: string;
  delay?: number;
};

type Skill = {
  name: string;
  keywords: string[];
  color: string;
};

const SKILLS: Skill[] = [
  {
    name: "React Editor",
    keywords: ["code", "edit"],
    color: VERITASIUM_COLORS.transpiling,
  },
  {
    name: "AI Chat",
    keywords: ["chat", "ai"],
    color: VERITASIUM_COLORS.generating,
  },
  {
    name: "Deploy",
    keywords: ["deploy", "build"],
    color: VERITASIUM_COLORS.published,
  },
  {
    name: "Auth",
    keywords: ["login", "auth"],
    color: VERITASIUM_COLORS.planning,
  },
  {
    name: "Database",
    keywords: ["data", "db"],
    color: VERITASIUM_COLORS.fixing,
  },
  {
    name: "Testing",
    keywords: ["test", "spec"],
    color: VERITASIUM_COLORS.learning,
  },
  {
    name: "Docs",
    keywords: ["doc", "help"],
    color: VERITASIUM_COLORS.bayesian,
  },
  {
    name: "Analytics",
    keywords: ["metric", "log"],
    color: VERITASIUM_COLORS.candidate,
  },
];

const GRID_COLS = 4;
const GRID_START_X = 160;
const GRID_START_Y = 280;
const CELL_W = 180;
const CELL_H = 70;
const CELL_GAP_X = 20;
const CELL_GAP_Y = 20;

function extractKeywords(url: string): string[] {
  return url
    .toLowerCase()
    .replace(/https?:\/\//, "")
    .split(/[/\-_.?&=#+]/)
    .filter((k) => k.length > 2);
}

export const SkillMatchingDiagram: FC<SkillMatchingDiagramProps> = ({
  url = "https://spike.land/code/edit/ai-chat",
  delay = 0,
}) => {
  const frame = useCurrentFrame();
  const { fps } = useVideoConfig();

  const urlKeywords = extractKeywords(url);

  // Determine which skills match
  const matchingIndices = SKILLS.map((skill, i) => ({
    index: i,
    matched: skill.keywords.some((kw) =>
      urlKeywords.some((uk) => uk.includes(kw) || kw.includes(uk)),
    ),
  }));

  // URL bar animation
  const urlOpacity = fadeIn(frame, fps, 0.4, delay);

  // Keywords split animation
  const keywordDelay = delay + 15;
  const keywordProgress = spring({
    frame: frame - keywordDelay,
    fps,
    config: SPRING_CONFIGS.snappy,
  });

  // Unique matched keywords for display
  const displayTokens = urlKeywords.filter((kw) =>
    SKILLS.some((s) => s.keywords.some((sk) => kw.includes(sk) || sk.includes(kw))),
  );

  return (
    <div style={{ position: "relative", width: 960, height: 500 }}>
      {/* URL bar */}
      <div
        style={{
          position: "absolute",
          top: 0,
          left: 80,
          right: 80,
          height: 52,
          borderRadius: 26,
          background: "rgba(255,255,255,0.06)",
          border: `1px solid ${COLORS.darkBorder}`,
          display: "flex",
          alignItems: "center",
          padding: "0 24px",
          gap: 10,
          opacity: urlOpacity,
        }}
      >
        {/* Lock icon */}
        <div
          style={{
            width: 14,
            height: 14,
            borderRadius: 3,
            border: `2px solid ${COLORS.success}`,
            position: "relative",
          }}
        >
          <div
            style={{
              position: "absolute",
              top: -6,
              left: 1,
              width: 8,
              height: 6,
              borderRadius: "4px 4px 0 0",
              border: `2px solid ${COLORS.success}`,
              borderBottom: "none",
            }}
          />
        </div>
        <span
          style={{
            fontSize: 16,
            color: COLORS.textSecondary,
            fontFamily: "JetBrains Mono, monospace",
            overflow: "hidden",
            whiteSpace: "nowrap",
          }}
        >
          {url}
        </span>
      </div>

      {/* Keyword tokens */}
      <div
        style={{
          position: "absolute",
          top: 70,
          left: 80,
          right: 80,
          display: "flex",
          gap: 10,
          flexWrap: "wrap",
          justifyContent: "center",
          opacity: keywordProgress,
          transform: `translateY(${(1 - keywordProgress) * 10}px)`,
        }}
      >
        {urlKeywords.map((kw, i) => {
          const isMatch = displayTokens.includes(kw);
          const matchedSkill = isMatch
            ? SKILLS.find((s) => s.keywords.some((sk) => kw.includes(sk) || sk.includes(kw)))
            : null;
          const color = matchedSkill ? matchedSkill.color : COLORS.textMuted;

          return (
            <div
              key={`${kw}-${i}`}
              style={{
                padding: "4px 14px",
                borderRadius: 8,
                background: isMatch ? `${color}20` : "rgba(255,255,255,0.04)",
                border: `1px solid ${isMatch ? `${color}60` : COLORS.darkBorder}`,
                fontSize: 14,
                fontWeight: 600,
                color: isMatch ? color : COLORS.textMuted,
                fontFamily: "JetBrains Mono, monospace",
              }}
            >
              {kw}
            </div>
          );
        })}
      </div>

      {/* SVG connection paths */}
      <svg
        style={{
          position: "absolute",
          top: 0,
          left: 0,
          width: "100%",
          height: "100%",
          pointerEvents: "none",
        }}
      >
        <defs>
          <filter id="pathGlow" x="-50%" y="-50%" width="200%" height="200%">
            <feGaussianBlur stdDeviation="4" result="blur" />
            <feMerge>
              <feMergeNode in="blur" />
              <feMergeNode in="SourceGraphic" />
            </feMerge>
          </filter>
        </defs>
        {matchingIndices
          .filter((m) => m.matched)
          .map(({ index }) => {
            const col = index % GRID_COLS;
            const row = Math.floor(index / GRID_COLS);
            const targetX = GRID_START_X + col * (CELL_W + CELL_GAP_X) + CELL_W / 2;
            const targetY = GRID_START_Y + row * (CELL_H + CELL_GAP_Y);
            const sourceX = 480;
            const sourceY = 130;

            const pathDelay = delay + 25 + index * 4;
            const pathProgress = interpolate(frame, [pathDelay, pathDelay + 20], [0, 1], {
              extrapolateLeft: "clamp",
              extrapolateRight: "clamp",
            });

            // Sample points along the bezier
            const p0 = { x: sourceX, y: sourceY };
            const p1 = { x: sourceX, y: sourceY + 60 };
            const p2 = { x: targetX, y: targetY - 60 };
            const p3 = { x: targetX, y: targetY };

            const points: string[] = [];
            const steps = Math.floor(pathProgress * 30);
            for (let s = 0; s <= steps; s++) {
              const t = s / 30;
              const pt = bezierPath(t, p0, p1, p2, p3);
              points.push(`${pt.x},${pt.y}`);
            }

            if (points.length < 2) return null;

            return (
              <polyline
                key={`path-${index}`}
                points={points.join(" ")}
                fill="none"
                stroke={SKILLS[index]!.color}
                strokeWidth={2}
                opacity={pathProgress * 0.7}
                filter="url(#pathGlow)"
              />
            );
          })}
      </svg>

      {/* Skill cards grid */}
      {SKILLS.map((skill, i) => {
        const col = i % GRID_COLS;
        const row = Math.floor(i / GRID_COLS);
        const cardDelay = delay + 15 + i * 3;
        const cardProgress = spring({
          frame: frame - cardDelay,
          fps,
          config: SPRING_CONFIGS.snappy,
        });

        const isMatched = matchingIndices[i]!.matched;
        const matchFadeDelay = delay + 35;
        const matchFade = interpolate(
          frame,
          [matchFadeDelay, matchFadeDelay + 15],
          [1, isMatched ? 1 : 0.3],
          { extrapolateLeft: "clamp", extrapolateRight: "clamp" },
        );

        return (
          <div
            key={skill.name}
            style={{
              position: "absolute",
              left: GRID_START_X + col * (CELL_W + CELL_GAP_X),
              top: GRID_START_Y + row * (CELL_H + CELL_GAP_Y),
              width: CELL_W,
              height: CELL_H,
              borderRadius: 14,
              background: isMatched ? `${skill.color}15` : "rgba(255,255,255,0.03)",
              border: `1px solid ${isMatched ? `${skill.color}60` : COLORS.darkBorder}`,
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              fontSize: 15,
              fontWeight: 600,
              color: isMatched ? skill.color : COLORS.textSecondary,
              fontFamily: "Inter, sans-serif",
              transform: `scale(${cardProgress})`,
              opacity: matchFade,
              boxShadow: isMatched ? `0 0 20px ${skill.color}25` : "none",
            }}
          >
            {skill.name}
          </div>
        );
      })}
    </div>
  );
};

